# ============================================================
# FOCUS Strategy Manager
# ------------------------------------------------------------
# Independent manager (NOT a StrategyPlugin) that implements
# concentrated trading using GreenPen analysis on Bybit Futures.
#
# 6-State Machine (v2 — ADX/Conviction refactor 2026-04-07):
#   DORMANT → ALERT → HUNT → POSITIONED → CAUTION → COOLDOWN
#
# Key changes from v1:
#   - ADX filter: no entry when ADX < 20 (sideways = no trade)
#   - Conviction score (0-10) determines budget allocation
#   - DCA (SCOUT/REINFORCED/ALLIN) cycle removed entirely
#   - Same-direction re-entry blocked until market cycles
#   - Anti-Martingale and Time Volatility adjustments removed
#
# Features:
#   - Long + Short (linear perpetual)
#   - Isolated margin, configurable leverage
#   - GreenPen PA patterns + Market Structure + Zone + Cycle TP
#   - 3M discipline (max daily plans, max SL count)
#   - Budget physically isolated from other strategies
#   - Dynamic Trailing SL (preserved from v1)
# ============================================================
from __future__ import annotations

import json
import logging
import os
import threading
import time
from collections import deque
from dataclasses import asdict, dataclass, field
from enum import Enum
from typing import Any, Dict, List, Optional, Tuple

logger = logging.getLogger(__name__)

# ── State Machine ───────────────────────────────────────────

class FocusState(str, Enum):
    DORMANT = "DORMANT"       # ADX<15, 추세 없음, 4시간마다 체크
    ALERT = "ALERT"           # 횡보 끝 징조, 30분마다 체크
    HUNT = "HUNT"             # ADX>20, 추세 확정, 5분마다 스캔
    POSITIONED = "POSITIONED" # 포지션 보유 중 (DT가 trailing 담당)
    CAUTION = "CAUTION"       # 보유 중 + 횡보 시작 징조
    COOLDOWN = "COOLDOWN"     # 청산 후 쿨다운

# ── Legacy State Migration Map (기존 JSON 파일 호환) ───────
_STATE_MIGRATION = {
    "IDLE": "DORMANT",
    "SELECTING": "HUNT",
    "ZONE_WAIT": "ALERT",
    "WATCHING": "HUNT",
    "TRAILING": "POSITIONED",
}


@dataclass
class FocusPosition:
    market: str = ""
    direction: str = ""          # "LONG" or "SHORT"
    entry_price: float = 0.0
    qty: float = 0.0
    leverage: int = 1
    tp1: float = 0.0
    tp2: float = 0.0
    sl: float = 0.0
    atr_used: float = 0.0
    partial_done: bool = False   # TP1 partial exit completed
    trailing_high: float = 0.0  # for LONG trailing
    trailing_low: float = 0.0   # for SHORT trailing
    entry_ts: float = 0.0
    # ★ H9 FIX: 청산 실패 재시도 횟수 (영속화)
    close_retry_count: int = 0
    # ── Conviction (v2) ──
    conviction_score: float = 0.0     # [2026-05-17 100점 체계] 0~100 확신 점수 (옛 0~10 → 100점 환산. legacy_to_100pt 호환 로직)
    entry_source: str = "primary"   # "primary" or "scanner"
    # ── Dynamic Trailing SL 필드 ──
    peak_profit_price: float = 0.0    # 최고 수익 가격 (LONG: 최고가, SHORT: 최저가)
    breakeven_locked: bool = False    # SL이 손익분기점으로 이동됨
    original_sl: float = 0.0         # 최초 SL (동적 이동 전 원본)
    original_tp1: float = 0.0        # 최초 TP1 (Decay 전 원본)
    # ── SL Dodge (고래 전략: SL 근접 시 후퇴) ──
    sl_dodge_count: int = 0           # 후퇴 횟수 (max 3)
    # ── Morning Shield (아침 방패) ──
    morning_shield_date: str = ""     # "YYYY-MM-DD" KST — 하루 1회 제한
    # ── Event Shield (경제이벤트 방패, 2026-06-08) ──
    event_shield_done: str = ""       # 적용한 이벤트 라벨 ("YYYY-MM-DD HH:MM") — 이벤트별 1회 제한
    # ── BE Stall Exit (2026-04-19, 사용자 직관) ──
    # BE 락 이후 N분 내 새 피크 못 찍으면 5분봉 관찰자들이 관망→반납 시작한다는 관찰.
    # 반납 median 40% 방어용.
    be_locked_ts: float = 0.0          # BE 락 발동 시각
    last_peak_update_ts: float = 0.0   # 피크 갱신 시각 (peak_profit_price 업데이트마다 now())
    # ── ★ [2026-05-21 Phase 6 Stage 8 재재설계] 점수 회복 자동 청산 baseline ──
    # 부모님 진짜 룰 (5-21):
    #   "이윤이 나야 청산이고 BE까지 못가더라도 캔들의 흐름이...즉 점수가 회복되는 기미가 보이면 탈출".
    # 조건: pnl > min_pnl_pct (이윤 중) + conv 회복 (baseline + N 증가) → 소액 청산.
    # 기존 가드 (BE/SL/multi_be_lock) 그대로 작동. 손실 중에는 트리거 X (인내).
    entry_baseline_conv: float = 0.0           # 진입 시 conv (Scanner 산출, 회복 추적용)
    entry_baseline_trend: str = ""             # 진입 시 GreenPen trend 라벨 (보조 정보)
    # ── ★ Conviction Override Slot 마커 (2026-05-10 부모님 결정) ──
    is_override: bool = False          # True 시 별도 룰 적용 (작은 사이즈/가까운 SL/-10% Hard ROE 컷)
    # ── ★ Entry Expectation (2026-05-14 부모 — 진입 기대치 메커니즘) ──
    reward_target: float = 0.0         # H4 구조 기반 도달 목표가 (0 = 미산정)
    risk_invalidation: float = 0.0     # H4 swing 기반 무효화 가격 (0 = 미산정)
    rr_ratio: float = 0.0              # reward / risk
    expectation_source: str = ""       # 산정 출처 (예: "primary_zone/primary_swing")
    # ── ★ [2026-05-28 부모] guard_score 100점 체계로 진입한 포지션 마커 ──
    # True 면 옛 EXIT 가드들(fast_reject/reverse_drift/pre_be_stall/long_hold_timeout/
    # trend_reversal/quick_tp/bb_macd_sw/thesis_invalidation 등) 모두 우회.
    # 새 체계는 SL/TP/BE 와 새 5M 긴급 탈출만으로 청산을 관리한다.
    guard_score_entry: bool = False
    # ── [2026-05-29 부모] Slot Auto Expand — 강신호 시 임시 +1 슬롯 진입 마커 ──
    # 옛 단순 시간 기반 (롤백됨) → 강신호+묶임+제한적+자본보호 재설계.
    # True 시: 사이즈 축소 (slot_auto_expand_size_ratio), 청산까지 임시 슬롯 점유.
    is_slot_expand: bool = False


@dataclass
class FocusConfig:
    enabled: bool = True  # 기본 ON — 부팅 시 자동 활성화
    budget_usdt: float = 0.0       # 0 = 자동 배분
    leverage: int = 3                     # [2026-04-25 default 승격] $1/min 목표, 카테고리2 (3→7)
    direction_mode: str = "both"   # "long_only", "short_only", "both"
    max_positions: int = 3         # [2026-04-25 default 승격] multi-slot 분산 (3→4)
    risk_pct: float = 5.0                 # 04/15 최적 성능 기준 복원 (8→5)
    rr_ratio: float = 3.0
    max_daily_plans: int = 999    # [2026-04-25 default 승격] DM Hard Block + Consec Pause 가 대체 (3→999)
    max_daily_sl: int = 999        # [2026-04-25 부모님 결정] SL 10회 시 정지 (자본 50% 한도, 더 관대)
    primary_tf: str = "240"        # [2026-05-21 부모] H4 = "240" — 출구 가드 충분 판단으로 H4 재전환. 깊은 자리만 입학 (5/15 H1 전환 결정 재검토 — 1주간 raw_body/momentum_deriv/reverse_drift/BE_stall/expectation_progress 등 출구 가드 강화 누적). primary=H1 으로 돌리려면 "60".
    entry_tf: str = "5"            # M5 = "5"
    cooldown_sec: float = 600.0
    scan_interval_sec: float = 30.0
    cycle_tp1_mult: float = 1.8     # Safe 기준: TP1:SL=1.64:1 (기존 0.5=1:1 → 수수료에 잠식)
    cycle_tp2_mult: float = 3.0     # Safe 기준: TP2:SL=2.73:1 (러너 목표)
    cycle_sl_mult: float = 1.1      # [2026-04-25 Long Hold System] SL 멀리 (1.1→2.5, 자본 5% risk per trade)
    partial_exit_pct: float = 50.0
    trailing_pct: float = 1.5
    # ── ADX / Conviction 필터 (v2 2026-04-07) ──
    adx_filter_enabled: bool = True        # ADX 기반 진입 필터
    min_adx_entry: int = 22               # 최소 ADX: 이 이하면 진입 금지
    dormant_adx_threshold: int = 15       # DORMANT 기준: 이 이하면 추세 없음
    min_conviction: float = 35.0          # 2026-05-19 Phase 6 Step 1: 50→70 (옛 10점 7점 = 명문대 입학기준, 1823건 분석 결과 옛 conv 7+ 가 큰 이윤 80%)
    phase3_context_bonus_enabled: bool = True  # Phase 3 시간대(±4) + 코인(+2) 가산점 ON/OFF
    # ── Scanner Multi-Slot ──
    scanner_entry: bool = True            # [2026-04-25 default 승격] multi-slot 스캐너 진입 표준화 (False→True)
    scanner_min_adx: int = 25             # [2026-04-18 저녁] 25→18 ($1/min 목표, Anti-Knife+H4가 품질 보장)
    scanner_min_conviction: float = 50.0  # 2026-05-19 Phase 6 Step 1: 30→70 (옛 7점 = 명문대 입학)
    scanner_max_exposure_pct: float = 70.0  # max % of balance used
    # ★ [2026-05-20 부모] 30M 충돌 conviction 배수 — UI 노출 (옛 hardcoded 0.5 → dataclass 화)
    # PRI(H1) vs 30M 추세 충돌 시 conviction × 이 배수. 둘 다 발동시 ×둘 곱 (1/4 까지).
    # 1.0 = OFF / 0.7 = -30% (default) / 0.5 = -50% (옛값) / 0.8 = -20%
    # [2026-05-27 부모] H4/H1 PA 펄스 정신과 충돌 → 1.0 (사실상 비활성). 30M=타이밍 TF, 본체 방향 X
    scanner_m30_primary_conflict_penalty: float = 1.0   # PRI(H1) vs 30M 추세 충돌 시 conviction 배수 (1.0 = 페널티 없음)
    scanner_m30_direction_conflict_penalty: float = 1.0 # direction(LONG/SHORT) vs 30M 추세 충돌 시 conviction 배수
    # ── ★ [2026-05-20 Phase 6 — 부모님 재설계] Entry Mode 2가지 선택형 ──
    #   부모님 결정 (5/20): "Score 모드와 봇과 반대방향 진입 두가지로 선택"
    #   - "score" (default): conviction 100점 기반 (기존, conv ≥ 70 같은 방향 진입)
    #   - "reverse": 봇 신호 + 낮은 conv + 낮은 ADX → 반대 자동 진입 (부모님 1차 룰)
    #     조건: conv ≤ reverse_conv_threshold + ADX ≤ reverse_adx_max
    #     RSI/MACD/BB 보강 = Combo E 자동 결합 (필수 X, 낙관적)
    entry_mode: str = 'reverse'                # "score" | "reverse"
    # Reverse 모드 트리거 임계
    reverse_conv_threshold: float = 35.0     # conv 이 값 이하 → 반대 진입 트리거
    reverse_adx_max: float = 20.0            # ADX 이 값 이하 → 반대 진입 트리거 (낮은 ADX = 럭비공 = 부모님 직감 자리)
    # ★ [2026-04-25 universe 확장] 부모님 "준비된 코인 보이지? 확장하자"
    scanner_min_turnover_24h: float = 1_000_000.0   # 유동성 임계 (24h $1M)
    scanner_min_price_usdt: float = 0.2            # 짜잘이 필터 (5.0 → 0.10, APE/CHIP 같은 강신호 진입 가능)
    scanner_top_n: int = 20                         # 추적 코인 수 (10 → 20)
    scanner_blacklist: list = field(default_factory=lambda: ['CLUSDT', 'XAGUSDT', 'XAUTUSDT', 'XAUUSDT'])  # 영구 차단 코인 (예: ["CLUSDT"] — Bybit 약관 미동의 등)
    max_same_direction: int = 2            # 같은 방향 최대 포지션 수 (나머지는 반대 방향 강제) — Auto 기본값
    # ── 방향별 슬롯 제한 (2026-04-20 형 지시) ──
    #   LONG/SHORT 슬롯을 분리 제어 → 포트폴리오 레벨 방향 락.
    #   -1(Auto) = max_same_direction 사용(기존 동작 유지). 0 = 해당 방향 완전 차단.
    #   예: LONG=Auto, SHORT=0 → SHORT 완전 봉쇄 (BULL 시장 강제).
    #       LONG=max_positions, SHORT=max_positions → 양쪽 최대치(현재 구조).
    max_long_positions: int = -1           # LONG 슬롯 상한 (-1=Auto, 0=차단, N=명시)
    max_short_positions: int = -1          # SHORT 슬롯 상한 (-1=Auto, 0=차단, N=명시)
    auto_first_dir_lock: bool = False       # [2026-04-26 부모님 결정] Auto 모드 첫 발 방향 잠금
    # True (초단타 정신): 첫 발 방향 잠금 + 손실 cap 4줄 보호 (4-25)
    # False (롱홀드 정신): 양방향 자유 + same_dir cap 자동 편중 보호 (4-26)
    # ── 똑똑하게 #2,#4,#5,#6,#7 (2026-04-26 부모님 1단계 결정) ──
    # #7 Regime Reversal Pause — 전환점 자동 감지 + 신규 진입 일시 중단
    # [2026-05-27 부모] H4/H1 PA 펄스 정신과 충돌 (BTC 추세 반전 시 15분 전체 pause = 펄스 자리 놓침)
    regime_reversal_pause_enabled: bool = False      # 옛 "전환점=학비 비싼 구간" → 펄스 가드가 대체
    regime_reversal_ema_gap_threshold_pct: float = 0.3  # BTC EMA gap < 0.3% (수렴)
    regime_reversal_adx_threshold: float = 20.0      # ADX < 20 (추세 약화)
    regime_reversal_pause_min: float = 15.0          # 진입 중단 시간 (분)
    # #2 Conviction-Weighted Sizing — 시그널 강도에 따라 budget 가중
    conv_sizing_enabled: bool = True
    conv_sizing_low_threshold: float = 35.0  # [2026-05-17 100점 ×10] 5→50. conv≤50 → budget × 0.5
    conv_sizing_high_threshold: float = 65.0 # [2026-05-17 100점 ×10] 9→90. conv≥90 → budget × 1.5
    # ── ★ [2026-06-13 부모 "진입점수=확신"] Conviction→Risk 스케일 (역U자, 진입임계 anchor) ──
    #   근거: 저널분석 65-80=sweet(+9.04)/80+=끝물(-5.65,승41%). 진입임계(guard_score_threshold)=확신 기준선(1.0x),
    #   sweet 키우고 끝물 컷. risk_pct에 곱해 *cap 안 막히고 qty에 직접* 닿음 (budget×conv는 cap이 다 먹음). default OFF.
    #   ★ 50 못박지 않음 — anchor=guard_score_threshold (임계 바꾸면 확신 기준선도 따라감).
    conv_risk_scale_enabled: bool = True    # ON/OFF (켜야 발동)
    conv_risk_peak_conv: float = 60.0        # sweet spot 시작(역U 정점) — 진입임계~여기 선형↑
    conv_risk_peak_mult: float = 1.5         # sweet spot risk 배수
    conv_risk_chop_conv: float = 80.0        # 끝물 라인 (이 이상 = 후행/끝물)
    conv_risk_chop_mult: float = 0.6         # 끝물 risk 컷 배수
    conv_risk_floor_mult: float = 0.5        # 진입임계 미만(이례) 안전 배수
    conv_risk_max_mult: float = 2.0          # factor 안전 상한 (폭주 방지)
    # #4 BTC Trend-Aligned Conviction — BTC UPTREND 시 LONG +N / DOWNTREND 시 SHORT +N
    btc_trend_conv_bonus_enabled: bool = True
    btc_trend_conv_bonus: float = 20.0       # [2026-05-17 100점 ×10] 2→20
    # #5 Winners Add Strength — 수익 코인이 +X% 도달 시 추가 진입 (capital_threshold 외 트리거)
    winners_add_self_growth_enabled: bool = True
    winners_add_self_growth_pct: float = 1.5      # 코인 자체 +1.5% 도달 시 트리거
    winners_add_self_growth_ratio_pct: float = 50.0  # [2026-04-26 형 #1 fix] 추가 매수 비율 (기존 margin × N%) — 부모님 dashboard 조정 가능
    # #6 Multi-Stage BE Lock — peak 도달별 SL 자동 강화
    multi_be_lock_enabled: bool = True
    multi_be_lock_stage1_pct: float = 0.25      # [2026-06-04 부모] 0.4→0.25 (BE 조기 발동, Home 서버 검증: 38건 중 34승 +$30.27)
    multi_be_lock_stage2_pct: float = 1.0       # (고정모드) peak ≥ 1.0% → SL=entry+0.3%
    multi_be_lock_stage3_pct: float = 2.0       # (고정모드) peak ≥ 2.0% → SL=entry+1.0%
    multi_be_lock_stage4_pct: float = 3.0       # (고정모드) peak ≥ 3.0% → SL=entry+2.0%
    # [2026-05-16 부모] stage1 fee-aware — SL=entry+cushion 으로 fee 보호 (수수료 0.11% + buffer)
    multi_be_lock_fee_cushion_pct: float = 0.05  # [2026-06-04 부모] 검증값 (BE 후 손실 건당 -$0.12, 무시 가능)
    # [2026-05-21 부모] BE Lock ATR 적응 — 변동성 큰 코인은 더 멀리 가야 BE (일찍 컷 방지)
    multi_be_lock_atr_adaptive_enabled: bool = True   # True=ATR 배수 모드 / False=고정 % 모드 (위 stage_pct 사용)
    multi_be_lock_atr_tf: str = "60"                  # ATR 계산 TF (H1)
    multi_be_lock_atr_period: int = 14                # ATR 기간
    multi_be_lock_stage1_atr_mult: float = 0.3        # (적응모드) stage1 trigger = ATR% × 0.3 (BTC~0.3%, HYPE~0.9%)
    multi_be_lock_stage2_atr_mult: float = 0.7        # (적응모드) stage2 trigger = ATR% × 0.7
    multi_be_lock_stage3_atr_mult: float = 1.4        # (적응모드) stage3 trigger = ATR% × 1.4
    multi_be_lock_stage4_atr_mult: float = 2.2        # (적응모드) stage4 trigger = ATR% × 2.2
    # [2026-05-29 부모 5번째→6번째 fix] ATR adaptive 하한선 — 저변동 코인 (HYPE peak 0.094% 노이즈 컷 사고) 보호
    # ATR×0.3 이 너무 작으면 진입 직후 노이즈로 BE lock 발동 → SL 진입가 바로 위로 끌어올림 → 70초 컷
    # stage1 trigger 최소 0.3% 보장 (peak 0.3% 미달 시 BE lock 발동 X)
