    # 사고: pre_be_stall_146886s_peak+0.40%_atr1.7% (40시간 묵은 peak 강제청산)
    # 30분 넘은 peak는 stale → 미발동
    pre_be_stall_max_since_peak_sec: float = 1800.0    # peak 후 최대 시간 (default 30분)

    # ── 🐢 ★ Pre-BE 손실방지선 (2026-06-09 부모 "지금 나우") ──
    # pre_be_stall(정체)·reverse_drift(역행)의 사각: peak<0.1 못 띄운 헤맴(🐢)이 entry 기준 손실로 밀림.
    # 실증(2026-06-09): peak<0.1 SL직행 10건 -21.87, BElock 전부 False. entry 기준 손실%로 재기(peak 분모 회피).
    pre_be_loss_guard_enabled: bool = True            # default OFF — 부모 켜야 발동 (paper 관찰 후 실전)
    pre_be_loss_guard_peak_max_pct: float = 0.10       # peak ≤ 이 값 = 헤맴(못 띄움) 대상
    pre_be_loss_guard_trigger_loss_pct: float = 0.5    # entry 대비 -이 값(%) 밀리면 작은 컷 (SL -1~2%의 절반)
    pre_be_loss_guard_min_hold_sec: float = 60.0       # 진입 후 최소 보유 (그레이스 외 추가 안전)
    pre_be_loss_guard_max_age_sec: float = 7200.0      # [2026-06-09 부모] 1800→7200(2h) — 헤맴 -63(30분초과)이 stale룰에 미발동, entry기준이라 묵은peak 사고없이 안전

    # ── ★ Reverse Drift Exit (2026-05-16 부모 직접 요청) ──
    # pre_be_stall 약점 보완: AUTO 모드가 ATR 높을 때 미발동 → 추세가 우리 반대로 천천히 흐르면 손실.
    # 차별점: pre_be_stall = "정체 (peak update 안 됨)" / reverse_drift = "역행 (peak에서 멀어짐)"
    # 즉 ATR 높아도 그 추세가 entry 쪽으로 흐르면 컷.
    # BTC SHORT peak 0.19%→-0.09%, SOL SHORT peak 0.28%→-0.23% 같은 케이스 보호.
    # [2026-05-16 사고 후 수정] FARTCOIN 3일 묵은 peak(0.395)+drift 17% 강제청산 -$120.
    #   결함1: since_peak 상한 없음 → max_since_peak_sec 신설
    #   결함2: peak_max(0.4) == BE_trigger(0.4) → BE 락 미달 peak 사각지대 → 0.4→0.35 갭 확보
    reverse_drift_exit_enabled: bool = True            # [2026-05-16] 부모 ON 바로 (관찰 건너뛰고 실전)
    reverse_drift_peak_min_pct: float = 0.10           # [2026-05-20 부모] 0.05→0.10 (noise floor 상향, 잔여 잡음 컷 방지)
    reverse_drift_peak_max_pct: float = 0.35           # [2026-05-16 0.4→0.35] BE_trigger(0.4)와 0.05 갭, 사각지대 회피
    reverse_drift_min_since_peak_sec: float = 180.0    # peak 찍은 후 정체 최소 시간 (3분)
    reverse_drift_max_since_peak_sec: float = 1800.0   # [2026-05-16 신설] peak 30분 넘으면 stale → 미발동 (FARTCOIN 사고 방지)
    # ── ATR 적응 (tight_trail 명세서 계승) ──
    reverse_drift_atr_adaptive_enabled: bool = True
    reverse_drift_atr_tf: str = "5"                     # 5m
    reverse_drift_atr_period: int = 14
    reverse_drift_atr_multiplier: float = 0.2           # atr_pct × 0.2 = adaptive drift threshold
    reverse_drift_atr_cap_pct: float = 0.4              # 상한 (변동성 큰 자리 보호)
    reverse_drift_pct: float = 0.26                     # [2026-05-20 부모] 0.10→0.26 base drift floor 상향 (단기 컷 누적 방지)

    # ── ★★★ 끝물 추격 차단 (Overextension) — 2026-06-07 부모 지시 (라이브 ON) ──
    # 사례: TON +15%/24H 고점(범위 94.9%)에서 봇이 LONG 추격 → peak 0.82% 후 SL −2.23.
    #   부모님 "두고 볼 수밖에" 하며 안 산 그 자리를 봇이 천장에서 질렀음.
    # 구멍: DayBox 천장-LONG 차단은 박스 lock(횡보) 때만 작동 → 추세 급등 중엔 무방비.
    # 신호: 24H 범위 내 위치(pos) + 24H 이동폭(move). LONG=상단+급등 / SHORT=하단+급락 → 감점.
    # ★ 비대칭(BB 벽타기 철학): ADX≥exempt = 강한 돌파 → 감점 면제 ('강하면 벽 타고 흐름').
    #   하드차단 X, conviction soft 감점 (강한 신호면 넘어 진입). 코인 차단 아님(상황 감점).
    overextension_enabled: bool = True                 # 라이브 ON (부모 2026-06-07 "페이퍼 아닌 라이브")
    overextension_range_pos_pct: float = 0.85          # LONG: 24H 범위 상단 이 비율↑ / SHORT: 하단 (1-이값)↓
    overextension_min_move_pct: float = 8.0            # 24H 변동 |%| 이 이상이어야 '끝물' 판정 (작은 변동 제외)
    overextension_penalty: float = 20.0                # conviction 감점 점수
    overextension_adx_exempt: float = 30.0             # ADX 이 이상 = 강한 돌파 → 감점 면제 (0=면제 없음)
    # ── ★ [2026-06-13 부모 "#1 끝물필터 지금 만들어"] Blow-off 24h 급등/급락 추격 차단 ──
    #   overextension 의 ADX 면제 구멍 보완 — 펌프는 ADX 폭발→면제됨. 이건 *24h 이동폭 크기* 기반 +
    #   추격방향(같은 방향)만 감점 + ★ADX 면제 *없음*. ESPORTS+55% 류 잡코 펌프 추격 차단. default OFF.
    #   (티커는 _get_24h_ticker 캐시 공유 — overextension 과 중복 fetch 방지, rate-limit 보호.)
    blowoff_filter_enabled: bool = True               # ON/OFF (켜야 발동)
    blowoff_move_pct: float = 30.0                     # 24h |변동| ≥ 이 % = blow-off 후보 (추격 감점 시작)
    blowoff_penalty: float = 20.0                      # 기본 감점 (move_pct 지점)
    blowoff_extreme_pct: float = 80.0                  # 24h |변동| ≥ 이 % = 극단 (최대 감점)
    blowoff_max_penalty: float = 40.0                  # 극단에서 최대 감점
    blowoff_chase_only: bool = True                    # True = 같은방향(추격)만 감점 / fade(반대)는 면제

    # ── ★ 이윤 여력 페널티 (Headroom) — 2026-06-09 부모 "방향 맞아도 갈 곳 없으면 감점" ──
    #   부모님 통찰: 점수표가 후행 정렬엔 48점, '어디까지 갈지(여력)'엔 페널티 없는 보너스뿐 → 고점수=끝물.
    #   여력 없는 자리(저항/지지 코앞·RSI 극단·BB 밴드 끝)를 conviction 에서 음수로 깎아 끝물 진입 거름.
    #   기존 점수함수(S/R·RSI·BB) 무수정 — 격리된 _compute_headroom_penalty 로만 추가. default OFF.
    headroom_penalty_enabled: bool = True              # [2026-06-10 부모 "네가 입력하고 켜라"] 함대 기본 ON
    headroom_sr_penalty: float = 6.0                   # LONG 저항 코앞 / SHORT 지지 코앞 진입 감점
    headroom_sr_near_pct: float = 1.5                  # 저항/지지까지 이 % 이내 = 여력 없음
    headroom_rsi_penalty: float = 6.0                  # LONG 과매수 / SHORT 과매도 진입 감점
    headroom_rsi_overbought: float = 70.0              # LONG: RSI 이 이상 = 갈 곳 없음
    headroom_rsi_oversold: float = 30.0                # SHORT: RSI 이 이하 = 갈 곳 없음
    headroom_bb_penalty: float = 4.0                   # LONG BB 상단 / SHORT BB 하단 진입 감점
    headroom_bb_hi_pctb: float = 0.80                  # %b 이 이상 = 밴드 상단 (LONG 여력 없음)
    headroom_bb_lo_pctb: float = 0.20                  # %b 이 이하 = 밴드 하단 (SHORT 여력 없음)

    # ── 🎯 변곡 setup 점수 (Inflection Setup) — 2026-06-12 부모 "점수가 차트를 배신" ──
    #   봇은 캔들을 안 봄 — 점수만 봄. 점수가 "이동폭 내 위치 × 모멘텀 방향"을 인코딩해야
    #   천장 stall(롱 늦음/숏 좋음)·바닥 변곡(롱 좋음)·벽타기(모멘텀 살아있으면 면제)를 구분.
    #   부모님 모델: 오르다 멈춤=숏 최고점/롱 위험, 내리다 멈춤=롱 바닥/숏 위험. 방향 대칭.
    #   ★ 위치(높이)만으론 천장의 '벽타기'와 '끝물'을 못 가림 → 모멘텀 방향으로 가감.
    #   5m 288봉: pos(24h 범위 내 위치) × up(=0.75·tanh(slope15m/scale)+0.25·sign(MACD히스토Δ)).
    #   L=W·(at_high·(up-base)+at_low·(base+up)) / S=거울. 트리거(microtiming)는 별개 = 점수 밖.
    #   guard_eval 시뮬 검증 완료 (XRP/SOL/HYPE 천장 stall→SHORT, VELVET 벽타기→면제). default OFF.
    inflection_setup_enabled: bool = True             # 켜면 guard 점수에 ㉒ Inflect 항목 추가
    inflection_setup_weight: float = 20.0              # W: 변곡 modifier 최대 크기 스케일
    inflection_setup_cap: float = 20.0                 # 출력 클램프 ±cap
    inflection_setup_base: float = 0.45                # base: 위치만으로 주는 기본 가감(모멘텀 0일 때)
    inflection_setup_slope_scale: float = 0.40         # slope15m tanh 정규화 스케일(%)

    # ── 🎣 Retest setup 점수 — 2026-06-12 부모(옆마실 동생 의견) "돌파→눌림→지지=좋은 자리" ──
    #   변곡 축(끝물 거르기, ± 양쪽)의 짝 = '좋은 진입 잡기'(가점 위주). 부모님 "눌림 받고 다시 가는 자리".
    #   3박자: ①돌파(직전 swing high 넘음/low 깸) ②되돌림(돌파 후 고점에서 눌림, 천장추격 아님)
    #          ③지지확인(돌파 레벨 위/아래 유지 + 방향대로 turning). 셋 다 = 가점. 돌파만(천장)·실패=0.
    #   변곡과 상호작용: retest=눌림에 가점 / 변곡=모멘텀↓ 감점 → 이상적진입(눌림끝+turn)에선 둘 다 정렬.
    #   5m 피벗(±width) 돌파+되돌림. guard_eval 시뮬 검증(ETH/ZEC/XRP retest, 천장·실패 0). default OFF.
    retest_setup_enabled: bool = True                 # 켜면 guard 점수에 ㉓ Retest 항목 추가
    retest_setup_weight: float = 12.0                  # retest 가점 최대 크기(되돌림 품질 ×)
    retest_setup_turn_bonus: float = 4.0               # 되돌림 후 방향대로 turning 시 추가 가점
    retest_retr_lo: float = 0.30                       # 최소 되돌림 비율(이하=천장 추격, 신호 X)
    retest_retr_hi: float = 0.90                       # 이상적 되돌림 상한(+0.3 초과=too-deep 실패)
    retest_pivot_width: int = 2                        # 피벗 high/low 좌우 폭
    retest_fail_pct: float = 0.005                     # 돌파 레벨 이 % 이탈 시 retest 실패

    # ── 🌊 거시하락 능동 SHORT 진입 2단계 (Macro Short Timing) — 2026-06-11 부모 "물길 완성" ──
    #   1단계(breadth 방향게이트:8088)는 SHORT 순행에 가점만 = 반응형(좋은 자리 기다림). 여기선 거시 RISK_OFF +
    #   개별 코인 5m '반등(데드캣) 후 꺾임' 상태를 *능동 신호*로 SHORT conviction 가점 → guard_score(65) 게이트
    #   통과 = 능동 진입 실현 (focus_manager:8087 [2단계] 구현). ★ 끝물 추격 방지: '반등 있었고 꺾였다'가 전제 —
    #   쭉 하락만(반등無)이면 0. SHORT 전용(LONG은 1단계 -25 차단 보존). default OFF — 부모님 v3 Guards 탭서 ON.
    macro_short_timing_enabled: bool = True           # 2단계 ON/OFF (켜는 순간 실거래 작동)
    macro_short_timing_delta: float = 12.0             # SHORT conviction 가점 크기 (실값)
    macro_short_timing_min_signals: int = 2            # 꺾임 3신호(음전환/MACD<0/PA bearish) 중 최소 충족 수
    macro_short_timing_bounce_pct: float = 0.3         # '반등 존재' 전제 — 5m 저점 후 고점 반등 최소 %
    macro_short_timing_lookback: int = 12              # 5m 반등 탐색 봉 수

    # ── 🌋 변동성 각성 SL 적응 (Volatility Awakening) — 2026-06-11 부모 "멀게 두고 따라붙기" ──
    #   지지부진하던 코인 각성(변동성 확장) + Day 순행 진입 시 SL을 새 변동성에 맞춰 *넓게* →
    #   risk-based sizing(qty=risk/sl_distance) 이 size 자동 축소 = 리스크($) 고정. 노이즈 컷 회피하며 추세 탑승.
    #   ★ 멀게는 변동성이·견딜지는 Day 정렬이·SL은 %아닌 '각성의 발'(구조점). default OFF.
    awaken_sl_enabled: bool = True                    # 각성 SL 적응 ON/OFF (켜야 작동)
    awaken_sl_mode: str = 'atr'                       # atr / structure / both (SL 거리 기준, 부모님 3모드)
    awaken_atr_ratio: float = 1.3                      # 각성 판정 — 현재 ATR / 과거 ATR 비율
    awaken_atr_lookback: int = 20                      # 과거 ATR 평균 봉수(primary_tf=H4)
    awaken_max_sl_mult: float = 2.5                    # SL 최대 배수 (무한 확장 방지)
    awaken_require_day_align: bool = True              # Day(코인 D1) 순행만 견딤 자격 (역행/미정 제외)
    awaken_swing_lookback: int = 10                    # 구조점(각성의 발) swing 탐색 봉수
    awaken_atr_buffer: float = 0.5                     # 구조점에 ATR 여유 배수

    # ── ② ★ 끝물 상한 감점 (Conviction Ceiling) — 2026-06-09 부모 "90+=끝물=50↓, 벽타기 예외" ──
    # conviction 90+ = 모든 지표 정렬 = 후행/끝물(신호완성=5분봉1~2개 늦음). 데이터: 75-80 sweet(62%)/90+ worst(39%).
    # 끝물을 target(50)으로 cap → 65 게이트 미달 = 진입 차단. 단 벽타기(ADX≥exempt)는 면제(강한 돌파=계속 감).
    conviction_ceiling_enabled: bool = True           # default OFF — 부모 켜야 발동 (도구로 적정값 확인 후)
    conviction_ceiling_start: float = 65.0             # 이 이상 conviction = 끝물 후보
    conviction_ceiling_target: float = 50.0            # 끝물을 이 점수로 cap (65 게이트 미달 유도)
    conviction_ceiling_adx_exempt: float = 30.0        # ADX 이 이상 = 벽타기 → 면제 (0=면제 없음)

    # ── ★ [2026-06-13 점수 체계 패치 v1] 가산 캡 / ceiling 순서 / bypass 기준 ──
    #   근거: 점수 실측 50~159 (설계 0~100) — 가산 무제한 합산이 척도·ceiling·bypass 전부 잠식.
    #   전부 default OFF/기존값 — 부모님이 켜야 발동. 사고 시 토글 OFF = 즉시 원복.
    guard_score_total_cap_enabled: bool = False        # 가드 가산점 총합 클램프 ON/OFF
    guard_score_total_cap: float = 30.0                # 총합 클램프 ±N (가산도 감점도 이 한도)
    conviction_ceiling_post_guards: bool = True       # True = 끝물 상한을 base+가드 합산 *후* 적용 (가산 부활 차단)
    final_bypass_use_base: bool = False                # True = 점수흡수 bypass 비교를 base conviction 으로 (인플레 무관)

    # ── ★★★ Entry Grace Period (2026-05-18 부모 비전 #6) — 진입 후 분위기 파악 시간 ──
    # 부모님 원문: "진입 후 분위기 파악을 위한 시간이 더 필요해"
    # 사례: 사무실 1 BTC SHORT 15:20→15:23 reverse_drift_peak+0.10% 3분만에 컷 — 너무 빠름.
    # A/B 확률 게임 (메모리 feedback_exit_guard_A_B_probability_game_2026-05-18):
    #   A = 장기 물림 → 빨리 컷이 답
    #   B = 작은 계곡 후 언덕 → 조금 견디면 수익
    #   진입 시점에 어디인지 모름 → 그레이스 기간으로 판별 시간 벌기
    # 적용 가드: pre_be_stall_exit + reverse_drift_exit (너무 빠른 컷 가드 2개만)
    # 영향 X: be_stall_exit (유일한 수익 가드), long_hold_timeout (시간 단위 가드), SL, Hard ROE
    # default 0 = OFF — 부모님 명시적으로 켜야 발동 (검증 단계 자연 보장)
    entry_grace_period_sec: float = 0.0                 # 진입 후 N초 동안 빠른 컷 가드 비활성. 0=OFF, 300=5분 권장.
