    # 진입 전: 선택 TF(5/15/30/60M) × N봉 고가(LONG)/저가(SHORT)까지 거리 < min_pct → 진입 거부.
    # 진입 후: 동일 TF 천장/바닥 접근 시 선제 청산.
    gap_check_enabled: bool = True             # 진입 전 갭 체크 (default ON)
