    gap_check_min_pct: float = 0.3             # 최소 갭 % (0=OFF, 기본 0.3% — 2026-06-04 부모 결정)
    # ★ [2026-06-07 부모] 갭 ATR 적응 — 고정 0.3%가 등락 큰 코인엔 꼭대기. 등락폭(ATR)에 맞춰 필요 갭 동적화.
    #   XLM 사례: 2% 등락폭인데 0.3% 갭으로 통과 → 꼭대기 진입 → SL 반복. ATR 적응이면 등락 큰 코인=필요 갭 큼=꼭대기 차단.
    #   필요 갭 = max(gap_check_min_pct, ATR% × gap_check_atr_mult), 상한 gap_check_atr_cap_pct. 코인 자체 ATR 재사용.
    gap_check_atr_adaptive_enabled: bool = True    # 등락폭 적응 ON (등락장 꼭대기 추격 차단)
    gap_check_atr_mult: float = 0.7                # 필요 갭 = ATR% × 이값 (클수록 더 아래에서만 진입)
    gap_check_atr_cap_pct: float = 1.5             # ATR 적응 필요갭 상한 (변동성 폭발 코인 과차단 방지)
    gap_proximity_exit_enabled: bool = False   # 천장/바닥 접근 청산 (default OFF)
