    # ── Profit-Exit Coin Block (B10, 2026-04-19 형 직접 지시) ─────
    #   수익으로 빠진 코인은 N시간 동안 양방향 전부 차단.
    #   [배경] 2026-04-19 실측: +$2.88 LINK SHORT 수익 후 같은 방향 3연속 진입 → -$8.53.
    #          B9(profit 300s) + B8(2회 연속) 모두 12시간 단위 보호엔 부족.
    #   [원칙] "먹고 나갔다 = 진입 논리 실현 = 같은 코인 그 자체 판단 보류"
    #          반대 방향 플립도 차단 — 4시간 이내 플립은 대부분 whipsaw.
    #   [효과 시뮬레이션] 오늘 -$37 → -$23 (구조적 +$14 개선).
    #   직관: 형 "12시간 진입금지..어느 방향이든"
    profit_exit_block_enabled: bool = True
    profit_exit_block_hours: float = 1.0               # [2026-04-25 default 승격] 기회 재포착 빠르게 (12→1)
    profit_exit_block_min_pnl: float = 0.5             # 이 이하 수익은 노이즈로 제외 (수수료 간신히 넘긴 케이스)
    # ★ Phase F (2026-04-20 형 의도 복원): 3-tuple 조건 — 코인+방향+연속N회 모두 충족 시만 차단
    profit_exit_block_min_consecutive: int = 3         # [2026-04-25 Long Hold System] 연승 4회로 완화 (3→4)
    profit_exit_block_block_opposite: bool = True     # 반대 방향은 기본 허용 (FLIP 기회 보존)
    # ★ Phase J v2 (2026-04-21 사용자 의도 명확화 + 형 letter #6 통합):
    # "시장 식어가는 끝자락" 감지 → 방향 무관 진입 skip
    # (regime 전환 임박 = 어느 방향이든 진입 후 1-10분 동안 위험)
    adx_slope_check_enabled: bool = False   # [2026-04-25 default 승격] 4-21 거래 사망 범인 (True→False) ★
    adx_slope_lookback_bars: int = 3                   # 몇 H4 봉 전 대비 (3봉 = 12시간)
    adx_slope_decline_threshold_pct: float = 2.0       # 3봉 전 ADX 대비 N% 이상 하락 시 skip (노이즈 흡수)
    # ★ Phase K (2026-04-21) — Regime Transition Preemptive Entry ★
    # 개념: "레짐 전환 기미" 감지 → scanner 방향 반대로 선점 진입
    # 이중 검증: 형 서버 88.2%, 동생 서버 94.4% (peak<0 손실의 역방향 승률)
    #            + BTC H4 500봉 분석: |EMA gap|<0.3% + ADX 하락 = 12h내 전환 72% 적중 (9.17x lift)
    # 7대 AND 조건 + paper_mode 단계적 활성화
    # J v2 와 동시 ON 금지 (같은 ADX 하락 신호에 J=skip / K=flip — 충돌)
    regime_transition_enabled: bool = False             # ★ 2026-05-11 부모님 결정 — Phase K 활성화 ("뿌리 튼튼하게")
    regime_transition_paper_mode: bool = False         # ★ 2026-05-11 부모님 결정 — 실거래 (paper 검증 완료, 형 88%/동생 94.4%)
    regime_transition_size_mult: float = 0.3           # 1주차 floor 0.3 → 2주차 cap 0.5 (형 Q4 FIXED CAP 권장)
    # ★ 절대 금지 (부모 "연속 수익 = 곱배기 리스크" 원칙):
    #   - size_mult >= 0.7 어떤 값도 금지
