    #     factor <1 = runner(완화·태움) / >1 = chopper(강화·스캘프) / 1 = 중립(현행). default OFF.
    trend_adaptive_exit_enabled: bool = True         # 켜면 출구 트레일을 코인 ADX에 적응 (실거래 작동)
