class FocusManager:
    """Standalone FOCUS strategy manager."""

    def __init__(self, system: Any = None):
        self.system = system
        self._lock = threading.RLock()
        # ── [2026-05-15 Tick 락 분리] config 전용 락 ──
        #   문제: update_config 가 self._lock 을 tick(16코인 스캔·MTF·네트워크 I/O) 과 공유
        #         → 대시보드 config 저장이 무거운 tick 1회를 통째로 기다림 (체감 30~60초).
        #   해법: update_config 는 _config_lock 만 잡고 즉시 반환 + _config_dirty 플래그.
        #         실제 파일 저장(_save_config)은 다음 tick 시작 시 _lock 보유 상태에서 flush.
        #         → config 는 메모리에 즉시 반영, 파일 영속화는 ≤5초 지연 (튜닝 노브라 허용 가능).
        self._config_lock = threading.Lock()
        self._config_dirty = False

        # Config
        self.config = FocusConfig()

        # 점수 합격인데 막판 차단된 near-miss 링버퍼 (peer brief 노출용, 2026-06-07 부모)
