    # ── Trade Client ────────────────────────────────────────

    @staticmethod
    def _is_live_mode() -> bool:
        """실거래 모드 여부 — 단일 진실 소스.

        [2026-05-25 부모] LIVE = TRADING_MODE=LIVE AND AUTOBOT_LIVE=1 둘 다 충족 (안전 측).
        그 외(PAPER 또는 AUTOBOT_LIVE=0) = paper/dry. 이 한 곳에서만 판정해
        _get_client / SYNC / 진입검증 의 paper 판정이 서로 어긋나지 않게 함.
        """
        import os
        return (os.getenv("TRADING_MODE", "PAPER").upper() == "LIVE"
                and os.getenv("AUTOBOT_LIVE", "0") == "1")

    def _get_client(self):
        """Lazy-init separate BybitTradeClient for linear perpetual.

        [2026-05-25 부모] paper/dry 모드 (TRADING_MODE=PAPER 또는 AUTOBOT_LIVE=0) 시
        FocusDryClient 로 감쌈 — 시세는 실제 Bybit, 주문/잔고는 가상.
        LIVE 는 TRADING_MODE=LIVE AND AUTOBOT_LIVE=1 둘 다 충족해야 함 (안전 측).
        """
        if self._client is None:
            import os
            from app.integrations.bybit_trade import BybitTradeClient
            _real = BybitTradeClient(category="linear")
            logger.info("[FOCUS] Linear perpetual client initialized")
            if self._is_live_mode():
                self._client = _real
            else:
                from app.integrations.focus_dry_client import FocusDryClient
                _vusdt = float(os.getenv("DRY_INITIAL_USDT", "1000") or "1000")
                self._client = FocusDryClient(_real, virtual_usdt=_vusdt)
        return self._client

    # ── [2026-05-26 부모] TF 라운드 앵커 TP/SL + 견딤 (교재 충실) ──
    def _tf_round_active(self) -> bool:
        """TF 라운드 TP/SL 활성 여부 — enabled 만 검사 (부모 2026-05-28 단순화)."""
        return bool(getattr(self.config, "tf_round_tpsl_enabled", False))

    def _hold_mode_active(self) -> bool:
        """견딤 모드 — 진짜 TP2/SL 까지 단기컷 없이 견딤 (TF라운드 활성 + hold ON)."""
        return bool(self._tf_round_active()
                    and getattr(self.config, "tf_round_hold_enabled", True))

    def _compute_tf_round_targets(self, market: str, direction: str, tf_override: str = None):
        """교재(내부메모/GreenPen) TP/SL: 앵커=거래TF 최근 최고점, TP=ATR×배수(100% 라운드), SL=⅓ (RR 1:3).
        Returns (tp1, tp2, sl, atr) 또는 None (실패 시 cycle_tp 로 fallback).
        ★ [2026-05-27 부모] tf_override 추가 — entry["_pa_via"] 따라 H4/H1 anchor 분리.
           "각 H4, H1 캔들에서 알려주는 저항선 기준" 부모님 정신.
        """
        cfg = self.config
        # tf_override 있으면 사용, 없으면 config default ("240")
        tf = str(tf_override) if tf_override else str(getattr(cfg, "tf_round_anchor_tf", "240") or "240")
        period = max(2, int(getattr(cfg, "tf_round_atr_period", 14)))
        tp_mult = float(getattr(cfg, "tf_round_tp_atr_mult", 1.0))
        tp2_mult = float(getattr(cfg, "tf_round_tp2_atr_mult", 2.0))
        sl_ratio = float(getattr(cfg, "tf_round_sl_ratio", 1.0 / 3.0)) or (1.0 / 3.0)
        anchor_lb = max(1, int(getattr(cfg, "tf_round_anchor_lookback", 2)))
        raw = self._get_client().get_kline(market, interval=tf, limit=period + anchor_lb + 6)
        if not raw or len(raw) < period + 2:
            return None
        ordered = list(raw)  # oldest-first; [start,open,high,low,close,...]
        trs = []
        for i in range(1, len(ordered)):
            h = float(ordered[i][2]); l = float(ordered[i][3]); pc = float(ordered[i - 1][4])
            trs.append(max(h - l, abs(h - pc), abs(l - pc)))
        if len(trs) < period:
            return None
        atr = sum(trs[-period:]) / period
        if atr <= 0:
            return None
        round1 = atr * tp_mult
        round2 = atr * tp2_mult
        sl_dist = round1 * sl_ratio
        # ★ 부모님 규칙(2026-05-26 정정): 앵커 = "PA 다음 H4 캔들"의 극점 (=교재 ไส้หลัง Sig 사후꼬리).
        #   롱 = 그 캔들 최하단(Low)이 시작점 → TP=Low+round, SL=Low−⅓round
        #   숏 = 그 캔들 최고점(High)이 시작점 → TP=High−round, SL=High+⅓round
        #   offset = forming(ordered[-1])에서 몇 칸 뒤 캔들을 앵커로 쓸지.
        #   ※ 교재 정밀: Pat1/2/3 → PA후 2/3/4번째 캔들. 현재는 offset 근사(PA캔들 추적은 후속) — paper 튜닝.
        offset = max(0, int(getattr(cfg, "tf_round_anchor_offset", 0)))
        idx = -1 - offset
        if len(ordered) < abs(idx):
            return None
        a_high = float(ordered[idx][2]); a_low = float(ordered[idx][3])
        if direction == "LONG":
            anchor = a_low
            tp1 = anchor + round1; tp2 = anchor + round2; sl = anchor - sl_dist
        else:
            anchor = a_high
            tp1 = anchor - round1; tp2 = anchor - round2; sl = anchor + sl_dist
        logger.info("[FOCUS] TF-round %s %s: anchor=%.4f ATR(%s,%d)=%.4f round1=%.4f → TP1=%.4f TP2=%.4f SL=%.4f RR=%.1f",
                    market, direction, anchor, tf, period, atr, round1, tp1, tp2, sl,
                    (1.0 / sl_ratio) if sl_ratio > 0 else 0.0)
        return (tp1, tp2, sl, atr)

    def _frame_guard_option_b_active(self) -> bool:
        """Frame Guard 옵션 B 활성 여부 — enabled 만 검사 (부모 2026-05-28 단순화)."""
        return bool(getattr(self.config, "frame_guard_option_b_enabled", False))

    def _check_frame_guard(self, market: str, direction: str) -> tuple:
        """프레임 가드 — 24h 레인지 위치. 부모님 2026-05-26 진단.
        교재 "트렌드 > 프레임(S/R) > Sig" 의 "프레임" 강제.
        ★ 옵션 B (2026-05-27, paper only): 기본 50→60%/40% + 강추세 정렬 시 70%/30%.
        LIVE 는 기존 50%/50% 유지 (사무실 보호).
        Returns (blocked: bool, reason: str)"""
        cfg = self.config
        if not getattr(cfg, "frame_guard_enabled", True):
            return (False, "")
        tf = str(getattr(cfg, "frame_guard_range_tf", "240") or "240")
        n = max(1, int(getattr(cfg, "frame_guard_range_bars", 6)))
        option_b = self._frame_guard_option_b_active()
        if option_b:
            # 옵션 B (paper): 기본 cutoff 60%/40% + 강추세 정렬 시 70%/30%
            short_min = float(getattr(cfg, "frame_guard_short_min_pos_b", 0.40))
            long_max = float(getattr(cfg, "frame_guard_long_max_pos_b", 0.60))
        else:
            # LIVE: 기존 50%/50% (부모님 5/26 검증값)
            short_min = float(getattr(cfg, "frame_guard_short_min_pos", 0.50))
            long_max = float(getattr(cfg, "frame_guard_long_max_pos", 0.50))
        # 강추세 정렬 cutoff (옵션 B 활성 시에만 사용)
        short_min_aligned = float(getattr(cfg, "frame_guard_trend_aligned_short_min_pos", 0.30))
        long_max_aligned = float(getattr(cfg, "frame_guard_trend_aligned_long_max_pos", 0.70))
        slope_thr = float(getattr(cfg, "frame_guard_trend_slope_pct", 1.5))
        try:
            raw = self._get_client().get_kline(market, interval=tf, limit=n + 2)
            if not raw or len(raw) < 2:
                return (False, "")  # 데이터 부족 = 안전하게 통과
            ordered = list(raw)  # oldest-first
            win = ordered[-(n + 1):]  # 최근 (n+1) 봉 (forming 포함)
            hi = max(float(c[2]) for c in win)
            lo = min(float(c[3]) for c in win)
            if hi <= lo:
                return (False, "")  # flat = skip
            first_close = float(win[0][4])
            last_close = float(win[-1][4])
            pos = (last_close - lo) / (hi - lo)
            mid = (hi + lo) / 2.0
            slope_pct = ((last_close - first_close) / first_close * 100.0) if first_close > 0 else 0.0
            d = (direction or "").upper()
            # 추세 정렬 판정 (옵션 B 활성 시에만 — 강추세 + 진입 방향 일치 + 박스 중간 넘음)
            long_aligned = option_b and (d == "LONG" and slope_pct >= slope_thr and last_close > mid)
            short_aligned = option_b and (d == "SHORT" and slope_pct <= -slope_thr and last_close < mid)
            # cutoff 결정
            if long_aligned:
                cutoff = long_max_aligned
                tag = "B강UPTREND+LONG slope=+%.1f%%" % slope_pct
            elif short_aligned:
                cutoff = short_min_aligned
                tag = "B강DOWNTREND+SHORT slope=%.1f%%" % slope_pct
            elif d == "LONG":
                cutoff = long_max
                tag = ("B기본" if option_b else "LIVE") + " slope=%+.1f%%" % slope_pct
            elif d == "SHORT":
                cutoff = short_min
                tag = ("B기본" if option_b else "LIVE") + " slope=%+.1f%%" % slope_pct
            else:
                return (False, "")
            # 차단 판정
            if d == "SHORT" and pos < cutoff:
                return (True, "frame_guard: SHORT 거부 - 레인지 위치 %.0f%% < %.0f%% [%s] (바닥잡기 무리)"
                        % (pos * 100, cutoff * 100, tag))
            if d == "LONG" and pos > cutoff:
                return (True, "frame_guard: LONG 거부 - 레인지 위치 %.0f%% > %.0f%% [%s] (고점잡기 무리)"
                        % (pos * 100, cutoff * 100, tag))
            return (False, "frame_guard OK %s pos=%.0f%% cutoff=%.0f%% [%s]"
                    % (d, pos * 100, cutoff * 100, tag))
        except Exception as exc:
            logger.debug("[FOCUS] _check_frame_guard error: %s", exc)
            return (False, "")  # 에러 시 안전 통과

    def _h4_pulse_only_active(self) -> bool:
        """H4 Close Pulse Only 모드 활성 여부 — enabled 만 검사 (부모 2026-05-28 단순화)."""
        return bool(getattr(self.config, "h4_pulse_only_enabled", False))
