    # ── [2026-05-27 부모] 5M 긴급 탈출 가드 — "여기서 그만!" ⭐ ──
    def _5m_emergency_exit_active(self) -> bool:
        """5M 긴급 탈출 가드 활성 여부 — enabled + green 마스터 토글."""
        # ★ [2026-05-28 저녁 부모] green 마스터 토글 — yellow only 모드 시 OFF
        if not self._is_green_guard_active("exit"):
            return False
        return bool(getattr(self.config, "exit_5m_emergency_enabled", False))

    def _check_5m_emergency_exit(self, market: str, direction: str) -> tuple:
        """5M RSI/MACD/BB 반전 신호 시 긴급 탈출 ("여기서 그만!").
        부모님 정신 (2026-05-27): 시간/peak 무관, 5M 시각적 반전만으로 청산.
        LONG 청산: RSI > overbought + 하락 변곡 / MACD hist 양수→음수 / BB 상단 도달
        SHORT 청산: RSI < oversold + 상승 변곡 / MACD hist 음수→양수 / BB 하단 도달
        3종 중 N 충족 (default 2/3) 시 청산.
        Returns (should_exit: bool, reason: str).
        """
        try:
            raw = self._get_mtf_kline(market, "5", limit=30)
            if not raw or len(raw) < 27:
                return (False, "")
            closes = [float(r[4]) for r in raw]
            from app.strategy.indicators import rsi_with_prev, macd_hist_pair, bollinger_bands as _bb_fn
            rsi_now, rsi_prev = rsi_with_prev(closes, length=14)
            hist_now, hist_prev = macd_hist_pair(closes)
            bb_now = _bb_fn(closes, length=20, k=2.0)
            if not bb_now or bb_now.get("upper", 0) <= bb_now.get("lower", 0):
                return (False, "")
            bb_pct = ((closes[-1] - bb_now["lower"]) / (bb_now["upper"] - bb_now["lower"])) * 100.0
            cfg = self.config
            rsi_overbought = float(getattr(cfg, "exit_5m_rsi_overbought", 70.0))
            rsi_oversold = float(getattr(cfg, "exit_5m_rsi_oversold", 30.0))
            bb_top_pct = float(getattr(cfg, "exit_5m_bb_top_pct", 90.0))
            bb_bot_pct = float(getattr(cfg, "exit_5m_bb_bottom_pct", 10.0))
            min_score = int(getattr(cfg, "exit_5m_min_score", 2))
            d = (direction or "").upper()
            score = 0
            signals = []
            if d == "LONG":
                # ① RSI 과매수 + 하락 변곡
                if rsi_now is not None and rsi_prev is not None:
                    if rsi_now > rsi_overbought and rsi_now < rsi_prev:
                        score += 1
                        signals.append("RSI%.0f>%.0f↓" % (rsi_now, rsi_overbought))
                # ② MACD hist 양수→음수 또는 양수 축소
                if hist_now is not None and hist_prev is not None and hist_prev > 0:
                    if hist_now < 0 or hist_now < hist_prev:
                        score += 1
                        signals.append("MACD%.3f→%.3f↓" % (hist_prev, hist_now))
                # ③ BB 상단 도달
                if bb_pct > bb_top_pct:
                    score += 1
                    signals.append("BB%.0f%%>%.0f%%" % (bb_pct, bb_top_pct))
            elif d == "SHORT":
                # ① RSI 과매도 + 상승 변곡
                if rsi_now is not None and rsi_prev is not None:
                    if rsi_now < rsi_oversold and rsi_now > rsi_prev:
                        score += 1
                        signals.append("RSI%.0f<%.0f↑" % (rsi_now, rsi_oversold))
                # ② MACD hist 음수→양수 또는 음수 축소
                if hist_now is not None and hist_prev is not None and hist_prev < 0:
                    if hist_now > 0 or hist_now > hist_prev:
                        score += 1
                        signals.append("MACD%.3f→%.3f↑" % (hist_prev, hist_now))
                # ③ BB 하단 도달
                if bb_pct < bb_bot_pct:
                    score += 1
                    signals.append("BB%.0f%%<%.0f%%" % (bb_pct, bb_bot_pct))
            else:
                return (False, "")
            if score >= min_score:
                return (True, "5M_EMERGENCY_%s:%s(%d/3)" % (d, ",".join(signals), score))
            return (False, "5M_emergency_partial(%d/3):%s" % (score, ",".join(signals) if signals else "no_sig"))
        except Exception as exc:
            logger.debug("[FOCUS] _check_5m_emergency_exit error %s: %s", market, exc)
            return (False, "")

    # ── [2026-05-27 부모] Phase 6 점수 통합 — 가드 평가를 conv 가산/감점으로 통합 ──
    def _guard_score_mode_active(self) -> bool:
        """점수 통합 모드 활성 여부 — enabled 만 검사 (부모 2026-05-28 단순화)."""
        return bool(getattr(self.config, "guard_score_mode_enabled", False))

    # ────────────────────────────────────────────────────────────
    # ★★★ [2026-05-28 저녁 부모] 가드 묶음 마스터 토글 helper ★★★
    # ────────────────────────────────────────────────────────────
    # 🟢 green = Phase 6/7 새 시스템 (적극 진입)
    # 🟡 yellow = 옛 깐깐 가드 (신중 진입 — 9개월 부모님 안전 자산)
    # both = 둘 다 ON
    # minimal = 핵심만 (TF + PA + SL/HardROE)
    def _is_green_guard_active(self, axis: str = "exit") -> bool:
        """🟢 green 가드 활성 여부 (axis: 'entry' | 'exit').
        Phase 6/7 새 시스템 가드 (charge_exit / tight_trail / exit_5m_emergency 등)."""
        cfg = self.config
        mode = getattr(cfg, f"{axis}_guard_set", "green")
        return mode in ("green", "both")

    def _is_yellow_guard_active(self, axis: str = "exit") -> bool:
        """🟡 yellow 가드 활성 여부 (axis: 'entry' | 'exit').
        옛 깐깐 가드 (BE Stall / Pre-BE / Reverse Drift / Long Hold / Entry Quality 등)."""
        cfg = self.config
        mode = getattr(cfg, f"{axis}_guard_set", "green")
        return mode in ("yellow", "both")

    def _is_minimal_mode(self, axis: str = "exit") -> bool:
        """minimal 모드 여부 — 핵심 가드만 (SL/HardROE/TF+PA)."""
        cfg = self.config
        mode = getattr(cfg, f"{axis}_guard_set", "green")
        return mode == "minimal"

    def _flow_reversal_active(self) -> bool:
        """Phase 7 흐름 전환 룰 활성 여부 — paper auto / LIVE 명시 ON."""
        cfg = self.config
        if bool(getattr(cfg, "flow_reversal_signal_enabled", False)):
            return True
        if bool(getattr(cfg, "flow_reversal_signal_auto_paper", True)) and not self._is_live_mode():
            return True
        return False

    def _compute_flow_reversal_signal(self, market: str, direction: str, entry: dict = None) -> tuple:
        """★ Phase 7 부모님 5조건 룰 (2026-05-28 오후 원전)
        진입 룰: 이전 신호 반대 + Conf↓ + ADX↓ + SIDEWAYS + 1D/H4/H1 정렬.
        대칭 적용 (BUY/SHORT). 충족 조건 수에 따라 가산 점수 반환.
        Returns (bonus: float, condition_count: int, details: str).
        """
        if not self._flow_reversal_active():
            return (0.0, 0, "off")
        cfg = self.config
        entry = entry or {}
        try:
            mkt = market.upper()
            need_prev = "SELL" if direction == "LONG" else "BUY"
            conditions = []  # 충족 조건 list

            # 조건 1: 이전 신호 = 반대 방향
            sig_hist = self._signal_history.get(mkt)
            cond1 = False
            if sig_hist and len(sig_hist) >= 2:
                # 최근 N samples 중 *반대 방향* 1회 이상이면 충족
                recent_sigs = [s for (_, s) in list(sig_hist)[-int(getattr(cfg, "flow_reversal_lookback_samples", 6)):]]
                if need_prev in recent_sigs:
                    cond1 = True
                    conditions.append("prev_opp")

            # 조건 2: Confidence 약화 (5분 전 대비)
            conf_hist = self._confidence_history.get(mkt)
            cond2 = False
            if conf_hist and len(conf_hist) >= 6:
                lookback = int(getattr(cfg, "flow_reversal_lookback_samples", 6))
                conf_now = float(conf_hist[-1][2]) if len(conf_hist[-1]) >= 3 else 0.0
                conf_past_idx = max(0, len(conf_hist) - lookback)
                conf_past = float(conf_hist[conf_past_idx][2]) if len(conf_hist[conf_past_idx]) >= 3 else 0.0
                decline_pct = float(getattr(cfg, "flow_reversal_conf_decline_pct", 0.25))
                if conf_past > 0 and conf_now < conf_past * (1.0 - decline_pct):
                    cond2 = True
                    conditions.append(f"conf{conf_past:.2f}→{conf_now:.2f}")

            # 조건 3: ADX 약화 — entry dict 의 adx vs adx_past 사용 (이미 scanner 에서 계산)
            cond3 = False
            adx_now_e = float(entry.get("adx", 0) or 0)
            adx_past_e = float(entry.get("adx_past", 0) or 0)
            if adx_past_e > 0 and adx_now_e > 0:
                decline_pct = float(getattr(cfg, "flow_reversal_adx_decline_pct", 0.25))
                if adx_now_e < adx_past_e * (1.0 - decline_pct):
                    cond3 = True
                    conditions.append(f"adx{adx_past_e:.0f}→{adx_now_e:.0f}")

            # 조건 4: 현재 Trend = SIDEWAYS
            cond4 = False
            trend_now = str(entry.get("h4_trend", "") or "").upper()
            if not trend_now and conf_hist and len(conf_hist) > 0:
                trend_now = str(conf_hist[-1][1] if len(conf_hist[-1]) >= 2 else "").upper()
            if trend_now == "SIDEWAYS":
                cond4 = True
                conditions.append("SIDE")

            # 조건 5: 1D/H4/H1 진입 방향 정렬
            cond5 = False
            tf_align = entry.get("mtf_align", {}) or {}
            want_trend = "UPTREND" if direction == "LONG" else "DOWNTREND"
            aligned_tfs = 0
            for tf in ("D1", "240", "60"):  # 1D, H4, H1
                if str(tf_align.get(tf, "")).upper() == want_trend:
                    aligned_tfs += 1
            if aligned_tfs >= 2:  # 1D/H4/H1 중 2개 이상 정렬
                cond5 = True
                conditions.append(f"TF_align({aligned_tfs}/3)")

            cnt = sum([cond1, cond2, cond3, cond4, cond5])
            if cnt >= 5:
                bonus = float(getattr(cfg, "flow_reversal_bonus_full", 30.0))
            elif cnt >= 4:
                bonus = float(getattr(cfg, "flow_reversal_bonus_strong", 20.0))
            elif cnt >= 3:
                bonus = float(getattr(cfg, "flow_reversal_bonus_medium", 10.0))
            else:
                bonus = 0.0
            return (bonus, cnt, ",".join(conditions) if conditions else "none")
        except Exception as exc:
            logger.debug("[FOCUS] flow_reversal_signal error %s: %s", market, exc)
            return (0.0, 0, "err")

    def _check_alt_btc_alignment(self, market: str, direction: str) -> tuple:
        """알트-BTC 정렬 (부모 5-28 룰):
           동방향 = 매크로 정렬 = 인내 가능 (+10)
           역방향 = 일시 수익 가능하나 결국 BTC 흐름에 끌려감 (-10)
        Returns (bonus: float, details: str)."""
        cfg = self.config
        if not bool(getattr(cfg, "alt_btc_alignment_enabled", True)):
            return (0.0, "off")
        if market.upper() in ("BTCUSDT", "XAUTUSDT", "XAUUSDT"):
            return (0.0, "btc_self_or_gold")  # BTC 자체와 금은 정렬 평가 스킵
        try:
            # day_direction 또는 BTC trend 가져옴
            btc_dir = ""
            if hasattr(self, "_day_direction") and self._day_direction:
                btc_dir = str(getattr(self._day_direction, "direction", "") or "").upper()
            if not btc_dir:
                # fallback: confidence_history 에서 BTC 최근 trend
                btc_hist = self._confidence_history.get("BTCUSDT")
                if btc_hist and len(btc_hist) > 0:
                    last = btc_hist[-1]
                    if len(last) >= 2:
                        btc_dir = str(last[1] or "").upper()
            if not btc_dir or btc_dir == "SIDEWAYS" or btc_dir == "NEUTRAL":
                return (0.0, "btc_neutral")
            want_alt = "UPTREND" if direction == "LONG" else "DOWNTREND"
            if btc_dir == want_alt:
                return (float(getattr(cfg, "alt_btc_aligned_bonus", 10.0)), f"BTC_aligned({btc_dir})")
            else:
                return (float(getattr(cfg, "alt_btc_opposite_penalty", -10.0)), f"BTC_opposite({btc_dir})")
        except Exception as exc:
            logger.debug("[FOCUS] alt_btc_alignment error %s: %s", market, exc)
            return (0.0, "err")

    def _record_near_miss(self, market: str, direction: str, score: float, reason: str) -> None:
        """점수 합격(임계 통과) 후 막판 게이트/슬롯/페어락 차단 = near-miss 기록.
        peer brief 로 노출 → Peer Brief Scanner '점수 합격인데 진입 막힘' 표시 (2026-06-07 부모).
        ★ [2026-06-08 부모 측정도구] 막힌 코인+시점+가격을 영속(NEARMISS_TRACK_PATH) →
           나중에 nearmiss_eval.py 가 N시간 뒤 가격과 비교해 '신호였나/페이크였나' 판정.
           "들어가려는 코인과 시점, 시간 지나서 결과를 보면 안다" — 기록만, 진입/가드 무관."""
        try:
            _px = 0.0
            try:
                _px = float(self._get_current_price(market) or 0.0)
            except Exception:  # noqa: BLE001
                pass
            # ★ [2026-06-11 부모 관찰 (a)] 막힌 다리 옆에 *반대 다리 base 점수* 표시.
            #   "왜 SHORT 안 하나" = 거의 다 '반대가 점수에서 짐(후행)'. 근접하면 (b)로 넘어갈 단서(⚠).
            _opp_suffix = ""
            try:
                _dc = getattr(self, "_last_dual_conv", {}).get((market or "").upper())
                if _dc:
                    _cl, _cs = float(_dc[0]), float(_dc[1])   # base conviction (같은 스케일)
                    _d = (direction or "").upper()
                    _picked = _cl if _d == "LONG" else _cs    # 막힌(고른) 다리 base
                    _opp = _cs if _d == "LONG" else _cl       # 반대 다리 base
                    _flag = " ⚠근접" if (_picked - _opp) <= 15 else ""   # 반대가 15 이내 = 거의 이길 뻔 → (b) 단서
                    _opp_suffix = f" · dual L{_cl:.0f}/S{_cs:.0f}({'반대 짐' if _opp < _picked else '동급'}){_flag}"
            except Exception:  # noqa: BLE001
                pass
            _rec = {
                "symbol": (market or "").upper(), "direction": (direction or "").upper(),
                "score": round(float(score or 0.0), 1),
                "reason": (str(reason or "")[:60] + _opp_suffix)[:95],
                "ts": time.time(), "price": _px,
            }
            self._recent_near_miss.append(_rec)
            # ★ 영속 — 측정도구용 (deque 는 메모리 20개라 이력 안 쌓임). 작은 append, 실패 무해.
            try:
                with open(NEARMISS_TRACK_PATH, "a", encoding="utf-8") as _f:
                    _f.write(json.dumps(_rec, ensure_ascii=False) + "\n")
            except Exception:  # noqa: BLE001
                pass
        except Exception:  # noqa: BLE001
            pass

    def _compute_guard_score_modifiers(self, market: str, direction: str, entry: dict) -> tuple:
        """모든 가드 평가 → conv 가산/감점 합계 + 상세 breakdown.
        부모님 정신 (2026-05-27): "롱/숏 무관 점수에 따라 진입. 모든 가드 *제대로 평가* 되어야".
        Returns (total_modifier: float, breakdown: str).
        """
        cfg = self.config
        total = 0.0
        bd = []
        # ★ [2026-06-12 cowork 진단] 추세정렬 multicollinearity 캡 — Frame·Trend·AltBTC 는
        #   "거시 추세가 위냐+네 방향 맞냐"는 *같은 질문*을 3번 독립 합산 → 역행 다리 −35~45 핸디캡(문턱 절반).
        #   각 기여를 포착해 함수 끝에서 합산 ±cap 클램프 (default OFF). 켜면 SHORT 이 코인 자체 신호로 경쟁.
        _ra_frame = 0.0
        _ra_trend = 0.0
        _ra_altbtc = 0.0
        _ra_btcalign = 0.0   # ⑩ BTC정렬(day_direction) — 방향 이중계산 제거용 포착
        try:
            # ① PA Completion (H4 OR H1) — 부모님 핵심
            _h4_pa_ok, _ = self._check_pa_completion(market, direction, "240")
            _h1_pa_ok = False
            if not _h4_pa_ok:
                _h1_pa_ok, _ = self._check_pa_completion(market, direction, "60")
            if _h4_pa_ok or _h1_pa_ok:
                s = float(getattr(cfg, "guard_score_pa_completion_ok", 30.0))
                total += s
                bd.append(f"PA+{s:+.0f}({'H4' if _h4_pa_ok else 'H1'})")
            else:
                s = float(getattr(cfg, "guard_score_pa_completion_none", -25.0))
                total += s
                bd.append(f"PA{s:+.0f}")
        except Exception as exc:
            logger.debug("[FOCUS] guard_score PA eval error: %s", exc)
        try:
            # ①-2 D1 (일봉) PA — 부모님 5단계 TF 룰: D1 = 큰 그림 방향
            _d1_pa_ok, _ = self._check_pa_completion(market, direction, "D")
            if _d1_pa_ok:
                s = float(getattr(cfg, "guard_score_d1_pa_ok", 25.0))
                total += s
                bd.append(f"D1PA+{s:+.0f}")
            else:
                s = float(getattr(cfg, "guard_score_d1_pa_none", -15.0))
                total += s
                bd.append(f"D1PA{s:+.0f}")
        except Exception as exc:
            logger.debug("[FOCUS] guard_score D1 PA eval error: %s", exc)
        try:
            # ② H4 Pulse (60분 창)
            _in_h4, _ = self._in_h4_pulse_window()
            if _in_h4:
                s = float(getattr(cfg, "guard_score_h4_pulse_in", 20.0))
                total += s; bd.append(f"H4Pulse+{s:+.0f}")
            else:
                s = float(getattr(cfg, "guard_score_h4_pulse_out", -10.0))
                total += s; bd.append(f"H4Pulse{s:+.0f}")
                # ★ [패치 v2-A] Pre-Close — 마감 전이라도 H4 진행봉 형태완성이면 펄스 인정(밖 점수→안 점수로 전환)
                #   = 선행 진입. enabled+base conv 하한+일일 상한+형태 충족 시만. entry["preclose"] 마킹.
                if (getattr(cfg, "preclose_entry_enabled", False)
                        and float(entry.get("conviction_score", 0) or 0) >= float(getattr(cfg, "preclose_min_conviction", 50.0))
                        and getattr(self, "preclose_used_today", 0) < int(getattr(cfg, "preclose_max_per_day", 5))):
                    _pc_ok, _pc_rsn = self._preclose_pattern_ok(market, direction)
                    if _pc_ok:
                        _pc_in = float(getattr(cfg, "guard_score_h4_pulse_in", 20.0))
                        _pc_bonus = _pc_in - s  # 이미 적용된 밖 점수(s)를 안 점수(_pc_in)로 끌어올림
                        total += _pc_bonus; bd.append(f"PreClose+{_pc_bonus:+.0f}({_pc_rsn})")
                        if isinstance(entry, dict):
                            entry["preclose"] = True
                            entry["_preclose_rsn"] = _pc_rsn
        except Exception as exc:
            logger.debug("[FOCUS] guard_score H4 pulse error: %s", exc)
        try:
            # ③ H1 PA Pulse (15분 창 + PA 인식)
            _h1_ok, _ = self._h1_pa_detected(market, direction)
            if _h1_ok:
                s = float(getattr(cfg, "guard_score_h1_pa_in", 15.0))
                total += s; bd.append(f"H1PA+{s:+.0f}")
            else:
                s = float(getattr(cfg, "guard_score_h1_pa_out", -5.0))
                total += s; bd.append(f"H1PA{s:+.0f}")
        except Exception as exc:
            logger.debug("[FOCUS] guard_score H1 PA error: %s", exc)
        try:
            # ④ Frame Guard (옵션 B — 강추세 정렬 / 중립 / 반대)
            _fg_blocked, _fg_reason = self._check_frame_guard(market, direction)
            if _fg_blocked:
                s = float(getattr(cfg, "guard_score_frame_opposite", -20.0))
                total += s; bd.append(f"Frame{s:+.0f}")
            elif "강" in _fg_reason or "B강" in _fg_reason:
                s = float(getattr(cfg, "guard_score_frame_aligned", 15.0))
                total += s; bd.append(f"Frame+{s:+.0f}(강)")
            else:
                s = float(getattr(cfg, "guard_score_frame_neutral", 5.0))
                total += s; bd.append(f"Frame+{s:+.0f}(중립)")
            _ra_frame = s   # 추세정렬 캡용 포착
        except Exception as exc:
            logger.debug("[FOCUS] guard_score Frame error: %s", exc)
        try:
            # ⑤ Anchor Fast-Track (proximity)
            _ft_ok, _prox, _ = self._check_anchor_fasttrack(market, direction)
            if _ft_ok:
                s = float(getattr(cfg, "guard_score_anchor_close", 20.0))
                total += s; bd.append(f"FT+{s:+.0f}(prox{_prox:.2f})")
            elif _prox > 1.0:
                s = float(getattr(cfg, "guard_score_anchor_far", -10.0))
                total += s; bd.append(f"FT{s:+.0f}(prox{_prox:.2f})")
            # 중간 (0.33~1.0) = 0점
        except Exception as exc:
            logger.debug("[FOCUS] guard_score Anchor error: %s", exc)
        try:
            # ⑥ Day Box Guard (lock 시 edge / 박스 안)
            _box_price = float(self._get_client()._linear_last_price(market) or 0.0)
            if _box_price > 0:
                _box_blocked, _box_reason = self._check_day_box_guard(market, direction, _box_price)
                if _box_blocked:
                    s = float(getattr(cfg, "guard_score_day_box_inside", -15.0))
                    total += s; bd.append(f"DayBox{s:+.0f}")
                elif "edge" in _box_reason:
                    s = float(getattr(cfg, "guard_score_day_box_edge", 10.0))
                    total += s; bd.append(f"DayBox+{s:+.0f}(edge)")
                # 중립(lock 없음) = 0
        except Exception as exc:
            logger.debug("[FOCUS] guard_score Day Box error: %s", exc)
        try:
            # ⑦ microtiming 5M
            if getattr(cfg, "microtiming_5m_enabled", False):
                _mt_ok, _, _ = self._check_microtiming_5m(market, direction)
                if _mt_ok:
                    s = float(getattr(cfg, "guard_score_microtiming_ok", 10.0))
                    total += s; bd.append(f"MT+{s:+.0f}")
                else:
                    s = float(getattr(cfg, "guard_score_microtiming_no", -5.0))
                    total += s; bd.append(f"MT{s:+.0f}")
        except Exception as exc:
            logger.debug("[FOCUS] guard_score microtiming error: %s", exc)
        try:
            # ⑧ raw_body_guard (3봉 net 방향)
            if getattr(cfg, "raw_body_guard_enabled", True):
                _rb_blocked, _ = self._check_raw_body_guard(market, direction)
                if _rb_blocked:
                    s = float(getattr(cfg, "guard_score_raw_body_against", -15.0))
                    total += s; bd.append(f"RawBody{s:+.0f}")
                else:
                    s = float(getattr(cfg, "guard_score_raw_body_align", 5.0))
                    total += s; bd.append(f"RawBody+{s:+.0f}")
        except Exception as exc:
            logger.debug("[FOCUS] guard_score raw_body error: %s", exc)
        try:
            # ⑨ momentum_deriv (RSI/MACD 변화율)
            if getattr(cfg, "momentum_deriv_guard_enabled", False):
                _md_blocked, _ = self._check_momentum_derivative_guard(market, direction)
                if _md_blocked:
                    s = float(getattr(cfg, "guard_score_momentum_deriv_against", -10.0))
                    total += s; bd.append(f"MomDeriv{s:+.0f}")
                else:
                    s = float(getattr(cfg, "guard_score_momentum_deriv_align", 5.0))
                    total += s; bd.append(f"MomDeriv+{s:+.0f}")
        except Exception as exc:
            logger.debug("[FOCUS] guard_score momentum_deriv error: %s", exc)
        # ── [2026-05-27 부모] 추가 가중치 5종 — "좋은 자리 도리만한 코인" ──
        try:
            # ⑩ BTC 방향 정렬 (day_direction 기반)
            dd = (getattr(self, "day_direction", "NEUTRAL") or "NEUTRAL").upper()
            d = (direction or "").upper()
            if dd in ("LONG", "SHORT") and d in ("LONG", "SHORT"):
                if dd == d:
                    s = float(getattr(cfg, "guard_score_btc_aligned", 15.0))
                    total += s; bd.append(f"BTC+{s:+.0f}(정렬)"); _ra_btcalign = s
                else:
                    s = float(getattr(cfg, "guard_score_btc_opposite", -15.0))
                    total += s; bd.append(f"BTC{s:+.0f}(역행)"); _ra_btcalign = s
            # dd=NEUTRAL 시 0 (보너스 X, 페널티 X)
        except Exception as exc:
            logger.debug("[FOCUS] guard_score BTC align error: %s", exc)
        try:
            # ⑪ ADX 강/약
            _adx_result = self._fetch_primary_adx(market)
            adx = float(_adx_result.get("adx", 0.0)) if isinstance(_adx_result, dict) else 0.0
            if adx >= 30:
                # ★ SIDEWAYS-ADX 보정 (flag ON 일 때만) — 구조 횡보면 강추세 가점 면제(점수↔차트 정합).
                _adx_flat = False
                if getattr(cfg, "guard_score_adx_strong_requires_trend", False):
                    try:
                        from app.strategy.greenpen.market_structure import analyze_structure as _as_adx
                        from app.strategy.greenpen.pa_detector import OHLCV as _O_adx
                        _raw_adx = self._get_client().get_kline(market, interval="240", limit=30)
                        _cd_adx = [_O_adx(float(r[1]), float(r[2]), float(r[3]), float(r[4]))
                                   for r in _raw_adx if len(r) >= 5]
                        if len(_cd_adx) >= 20 and _as_adx(_cd_adx).trend.value == "SIDEWAYS":
                            _adx_flat = True
                    except Exception:
                        pass
                if _adx_flat:
                    bd.append(f"ADX·0({adx:.0f}≥30, 횡보=가점면제)")
                else:
                    s = float(getattr(cfg, "guard_score_adx_strong", 10.0))
                    total += s; bd.append(f"ADX+{s:+.0f}({adx:.0f}≥30)")
            elif adx < 20:
                s = float(getattr(cfg, "guard_score_adx_weak", -5.0))
                total += s; bd.append(f"ADX{s:+.0f}({adx:.0f}<20)")
        except Exception as exc:
            logger.debug("[FOCUS] guard_score ADX error: %s", exc)
        try:
            # ⑫ 거래량 big + 방향 일치 (5M 기준)
            raw = self._get_mtf_kline(market, "5", limit=20)
            if raw and len(raw) >= 15:
                vols = [float(r[5]) if len(r) > 5 else 0.0 for r in raw[-15:]]
                cur_vol = vols[-1] if vols else 0.0
                avg_vol = (sum(vols[:-1]) / max(len(vols) - 1, 1)) if len(vols) > 1 else 1.0
                # 마지막 봉 방향
                last = raw[-1]
                last_open = float(last[1]) if len(last) > 1 else 0.0
                last_close = float(last[4]) if len(last) > 4 else 0.0
                last_dir = "UP" if last_close > last_open else "DOWN"
                want_vol_dir = "UP" if direction.upper() == "LONG" else "DOWN"
                if avg_vol > 0 and cur_vol >= avg_vol * 2.0 and last_dir == want_vol_dir:
                    s = float(getattr(cfg, "guard_score_vol_big_align", 10.0))
                    total += s; bd.append(f"Vol+{s:+.0f}(big {cur_vol/avg_vol:.1f}x {last_dir})")
        except Exception as exc:
            logger.debug("[FOCUS] guard_score Vol error: %s", exc)
        try:
            # ⑬ H4 trend confidence (analyze_structure 의 trend strength)
            from app.strategy.greenpen.market_structure import analyze_structure as _as
            from app.strategy.greenpen.pa_detector import OHLCV as _O
            raw = self._get_client().get_kline(market, interval="240", limit=30)
            if raw and len(raw) >= 20:
                candles = [_O(float(r[1]), float(r[2]), float(r[3]), float(r[4])) for r in raw if len(r) >= 5]
                st = _as(candles)
                trend_str = (st.trend.value if hasattr(st.trend, "value") else str(st.trend)).upper()
                # trend confidence: UPTREND/DOWNTREND with strength → 75%+ assumed; SIDEWAYS = mid
                # market_structure 에 confidence 직접 없음 → trend 명확성으로 근사
                d = direction.upper()
                if trend_str == "UPTREND" and d == "LONG":
                    s = float(getattr(cfg, "guard_score_trend_high_conf", 10.0))
                    total += s; bd.append(f"Trend+{s:+.0f}(H4_UP_LONG)"); _ra_trend = s
                elif trend_str == "DOWNTREND" and d == "SHORT":
                    s = float(getattr(cfg, "guard_score_trend_high_conf", 10.0))
                    total += s; bd.append(f"Trend+{s:+.0f}(H4_DN_SHORT)"); _ra_trend = s
                elif trend_str in ("UPTREND", "DOWNTREND"):
                    # 추세 있지만 역행 진입
                    s = float(getattr(cfg, "guard_score_trend_low_conf", -5.0))
                    total += s; bd.append(f"Trend{s:+.0f}(H4_{trend_str[:2]}_역행)"); _ra_trend = s
                # SIDEWAYS = 0
        except Exception as exc:
            logger.debug("[FOCUS] guard_score Trend error: %s", exc)
        try:
            # ⑭ 5M RSI 극단 변곡 (반전 자리 진입)
            raw5 = self._get_mtf_kline(market, "5", limit=20)
            if raw5 and len(raw5) >= 15:
                closes5 = [float(r[4]) for r in raw5]
                from app.strategy.indicators import rsi_with_prev
                rsi_now5, rsi_prev5 = rsi_with_prev(closes5, length=14)
                if rsi_now5 is not None and rsi_prev5 is not None:
                    d = direction.upper()
                    if d == "LONG" and rsi_prev5 < 30 and rsi_now5 > rsi_prev5:
                        s = float(getattr(cfg, "guard_score_rsi_extreme", 10.0))
                        total += s; bd.append(f"RSI5M+{s:+.0f}({rsi_prev5:.0f}<30↑)")
                    elif d == "SHORT" and rsi_prev5 > 70 and rsi_now5 < rsi_prev5:
                        s = float(getattr(cfg, "guard_score_rsi_extreme", 10.0))
                        total += s; bd.append(f"RSI5M+{s:+.0f}({rsi_prev5:.0f}>70↓)")
        except Exception as exc:
            logger.debug("[FOCUS] guard_score RSI extreme error: %s", exc)
        # ── Phase 7 — 부모님 8개월 직감 5조건 룰 (2026-05-28 오후 원전) ──
        try:
            # ⑮ Flow Reversal Signal — prev SELL + Conf↓ + ADX↓ + SIDEWAYS + 1D/H4/H1 정렬
            fr_bonus, fr_cnt, fr_details = self._compute_flow_reversal_signal(market, direction, entry)
            if fr_bonus != 0.0:
                total += fr_bonus
                bd.append(f"FlowRev{fr_bonus:+.0f}({fr_cnt}/5:{fr_details})")
        except Exception as exc:
            logger.debug("[FOCUS] guard_score FlowRev error: %s", exc)
        try:
            # ⑯ Alt-BTC Alignment — 알트 방향이 BTC 매크로와 정렬되면 인내 가치
            ab_bonus, ab_details = self._check_alt_btc_alignment(market, direction)
            if ab_bonus != 0.0:
                total += ab_bonus
                bd.append(f"AltBTC{ab_bonus:+.0f}({ab_details})")
            _ra_altbtc = float(ab_bonus or 0.0)   # 추세정렬 캡용 포착
        except Exception as exc:
            logger.debug("[FOCUS] guard_score AltBTC error: %s", exc)
        try:
            # ⑰ Peer Win — 옆 서버 양의 신호 (2026-06-05 부모)
            #   같은 코인+방향 옆 서버 최근 N분 win (BE/TP/trailing/흑자청산) → +N
            #   본체 가드 (D1/30M+15M/5M) 는 그대로 — 가산점이지 자격 완화 X.
            from app.core.peer_brief import check_peer_win_bonus as _peer_win
            _pw_bonus, _pw_source = _peer_win(market, direction)
            if _pw_bonus > 0:
                total += _pw_bonus
                bd.append(f"PeerWin+{_pw_bonus:+.0f}({_pw_source})")
            # ⑱ Peer SL Caution — 옆 서버 같은 코인+방향 최근 SL → 소프트 감점 (2026-06-06 부모)
            #   "옆이 여기서 SL 났으니 한 번 더 생각" = 하드차단 X, 감점만. 본체 지표(현재
            #   반등 포함)가 강하면 감점 넘어 진입 → 부모님 "반등이면 가점" 효과 자연 처리.
            from app.core.peer_brief import check_peer_sl_caution as _peer_sl
            _ps_pen, _ps_source = _peer_sl(market, direction)
            if _ps_pen > 0:
                total -= _ps_pen
                bd.append(f"PeerSL-{_ps_pen:.0f}({_ps_source})")
            # ⑲ Peer Struggle — 옆이 같은 코인+방향 N분+ 보유하며 한 번도 못 green(헤맴) → 소프트 감점
            #   (2026-06-06 부모 TON 사례: 한 서버 고전 중인데 다른 서버 같은 방향 또 진입 방지)
            from app.core.peer_brief import check_peer_struggle_caution as _peer_struggle
            _pst_pen, _pst_src = _peer_struggle(market, direction)
            if _pst_pen > 0:
                total -= _pst_pen
                bd.append(f"PeerStruggle-{_pst_pen:.0f}({_pst_src})")
            # ⑳ Peer Conflict — 옆이 '반대 방향'을 건강(수익권)하게 보유인데 내가 그 반대로 진입 → 소프트 감점
            #   (2026-06-07 부모 자가충돌: ZEC Home L↔server-c S = 헤지라 손실↓이나 수수료로 이익0 → 신중).
            #   ★ 비대칭: 상대가 헤매면(peak↓=방향 꺾임) 감점 X — 내 반대 진입=전환 포착(레짐 flip).
            from app.core.peer_brief import check_peer_conflict_caution as _peer_conflict
            _pc_pen, _pc_src = _peer_conflict(market, direction)
            if _pc_pen > 0:
                total -= _pc_pen
                bd.append(f"PeerConflict-{_pc_pen:.0f}({_pc_src})")
            # ㉕ Peer Crowding — 옆이 같은 코인+'같은' 방향 *현재 보유*면 몰림 감점 (2026-06-15 부모)
            #   오늘 TRUMP 4서버 동시 진입(분산 깨짐) 사례. struggle 와 달리 age/peak 조건 없이
            #   '갓 진입한 건강 보유'도 셈 → 동시 진입 구멍 차단. soft(본체 강하면 넘어 진입). default OFF.
            from app.core.peer_brief import check_peer_crowding_caution as _peer_crowd
            _pcr_pen, _pcr_src = _peer_crowd(market, direction)
            if _pcr_pen > 0:
                total -= _pcr_pen
                bd.append(f"PeerCrowd-{_pcr_pen:.0f}({_pcr_src})")
        except Exception as exc:
            logger.debug("[FOCUS] guard_score Peer error: %s", exc)
        try:
            # ㉑ Overextension — 끝물 추격 감점 (2026-06-07 부모: TON 천장 LONG 사례)
            #   24H 범위 상단(LONG)/하단(SHORT) + 큰 이동폭 = 소진된 추세 추격 → conviction −N.
            #   ★ ADX 강하면 면제(돌파). DayBox 천장차단의 추세 사각지대 보완. 하드차단 X.
            _ox_pen, _ox_src = self._check_overextension(market, direction)
            if _ox_pen > 0:
                total -= _ox_pen
                bd.append(f"Overext-{_ox_pen:.0f}({_ox_src})")
            # ㉔ [2026-06-13 부모 #1] Blow-off — 24h 급등/급락 *추격* 차단 (ADX 면제 없음, overext 구멍 보완)
            _bo_pen, _bo_src = self._check_blowoff(market, direction)
            if _bo_pen > 0:
                total -= _bo_pen
                bd.append(f"Blowoff-{_bo_pen:.0f}({_bo_src})")
        except Exception as exc:
            logger.debug("[FOCUS] guard_score Overext/Blowoff error: %s", exc)
        try:
            # ㉒ Inflection Setup — 변곡 setup 점수 (2026-06-12 부모 "점수가 차트를 배신")
            #   위치(이동폭 내)×모멘텀 방향을 인코딩. 천장 stall=롱 감점/숏 가점, 바닥 변곡=롱 가점,
            #   벽타기(모멘텀 살아있음)=면제. 방향 대칭. guard_eval 시뮬 검증. default OFF.
            _if_mod, _if_src = self._compute_inflection_setup(market, direction)
            if _if_mod != 0.0:
                total += _if_mod
                bd.append(f"Inflect{_if_mod:+.0f}({_if_src})")
        except Exception as exc:
            logger.debug("[FOCUS] guard_score Inflection error: %s", exc)
        try:
            # ㉓ Retest Setup — 돌파→눌림→지지 = 좋은 진입 자리 (2026-06-12 부모/동생)
            #   변곡(끝물 거르기)의 짝 = 좋은 진입 잡기. 가점 위주. 방향 대칭. guard_eval 시뮬 검증. default OFF.
            _rt_mod, _rt_src = self._compute_retest_setup(market, direction)
            if _rt_mod > 0.0:
                total += _rt_mod
                bd.append(f"Retest+{_rt_mod:.0f}({_rt_src})")
        except Exception as exc:
            logger.debug("[FOCUS] guard_score Retest error: %s", exc)
        # ── ★ [2026-06-12 부모] 방향 이중계산 제거 (dedupe) ── (cap 보다 우선)
        #   Frame·Trend·AltBTC·BTC정렬 = conviction 의 mtf_align·h4_score·btc_regime·day_direction 과 *같은 방향신호*
        #   를 guard 에서 또 셈 = 이중계산. 추세 타는 다리가 같은 신호 두 번 챙김 → SHORT 적자. guard 측 제거(conviction이 주인).
        #   ★ 대칭(ADX·Vol·RSI)·방향공정(PA·RSI 자기방향)은 안 건드림 — 그건 SHORT 적자와 무관(부모 통찰).
        if getattr(cfg, "guard_dir_dedupe_enabled", False):
            try:
                _dd_sum = _ra_frame + _ra_trend + _ra_altbtc + _ra_btcalign
                if _dd_sum != 0.0:
                    total -= _dd_sum
                    bd.append(f"DirDedupe[F{_ra_frame:+.0f}/T{_ra_trend:+.0f}/AltB{_ra_altbtc:+.0f}/BTC{_ra_btcalign:+.0f}=−{_dd_sum:+.0f}]")
            except Exception as exc:
                logger.debug("[FOCUS] guard_dir_dedupe error: %s", exc)
        # ── [2026-06-12 cowork] 추세정렬 합산 캡 (dedupe 대신 *완화*만 원할 때) — dedupe OFF 일 때만 ──
        elif getattr(cfg, "regime_align_cap_enabled", False):
            try:
                _ra_raw = _ra_frame + _ra_trend + _ra_altbtc
                _ra_cap = float(getattr(cfg, "regime_align_cap", 15.0))
                _ra_clamped = max(-_ra_cap, min(_ra_cap, _ra_raw))
                if _ra_clamped != _ra_raw:
                    total += (_ra_clamped - _ra_raw)
                    bd.append(f"RegimeCap[F{_ra_frame:+.0f}/T{_ra_trend:+.0f}/B{_ra_altbtc:+.0f}={_ra_raw:+.0f}→{_ra_clamped:+.0f}]")
            except Exception as exc:
                logger.debug("[FOCUS] regime_align_cap error: %s", exc)
        # ★ [패치 v1] 가산점 총합 캡 — 보너스 인플레이션(실측 +109까지)으로부터 척도 보호
        if getattr(self.config, "guard_score_total_cap_enabled", False):
            _cap = abs(float(getattr(self.config, "guard_score_total_cap", 30.0)))
            if abs(total) > _cap:
                bd.append(f"TotalCap[{total:+.0f}→{max(-_cap, min(_cap, total)):+.0f}]")
                total = max(-_cap, min(_cap, total))
        return (total, " | ".join(bd))

    # ── [2026-05-28 부모] 진입 직전 마지막 가드 — "이것만으로 충분" ──
    #   부모님 의도: 점수 통과 후 (1) 30M+15M 방향 재확인 (2) 5M RSI/MACD/BB 동조
    #   ★ [2026-05-28 저녁 부모 진단] "30m/15m 제대로 안 본 것으로 안 보인다"
    #     → 옛 "둘 다 반대만 차단" = 너무 약함. 진입 *전* 가드는 *하나라도 반대* 면 차단.
    #     부모님 5-28 원전: "30M/15M 견뎌야" = 명확히 반대면 못 견딘다.
    #     SIDE 는 통과 (단기 노이즈 = 인내 가능).
    def _regime_align_override(self, direction: str):
        """거시 컴퍼스 확실(RISK_OFF/RISK_ON) 시 final 정렬게이트가 '상위TF lag' 대신 거시방향을 따름.
        급락(RISK_OFF) 중 상위TF가 아직 UP이라 SHORT veto·LONG endorse 하던 모순 해결 (2026-06-07 부모).
        Returns 'allow'(거시순행=상위TF 무시 통과) / 'block'(거시역행=떨어지는칼 차단) / None(기존 로직)."""
        if not getattr(self.config, "final_align_regime_override_enabled", True):
            return None
        try:
            mc = self._macro_compass()
            state = mc.get("state", "NEUTRAL")
            up = int(mc.get("up", 0) or 0)
            down = int(mc.get("down", 0) or 0)
            strong = int(getattr(self.config, "breadth_strong_n", 8))
            d = (direction or "").upper()
            # ★★ [2026-06-08 부모 "두 다리로 서라"] SHORT 해방 — 봇 LONG편향(4서버 100% LONG) 교정.
            #   SHORT 순행(거시 하락)은 final 게이트(15M=UPTR 역행)에 자주 막혀 거의 0이었음.
            #   거시 down ≥ release_n(mid급 7, strong 9보다 낮춤)이면 SHORT 통과 = LONG 수준으로 결과 균형.
            #   ★ LONG 역행 차단(떨어지는칼)은 strong(9) 유지 / 점수(guard_score 65)는 양쪽 엄격 = 가짜 거름.
            _srel = bool(getattr(self.config, "regime_short_release_enabled", True))
            _sreln = int(getattr(self.config, "regime_short_release_n", 7))
            if state == "RISK_OFF":
                if d == "SHORT" and (down >= strong or (_srel and down >= _sreln)):
                    return "allow"   # SHORT 순행: strong(9) OR release_n(7) 통과 — 두 다리
                if d == "LONG" and down >= strong:
                    return "block"   # LONG 역행(떨어지는칼) 차단은 strong 유지
            if state == "RISK_ON":
                if d == "LONG" and up >= strong:
                    return "allow"   # 상승추세 LONG 순행 통과 (기존)
                if d == "SHORT" and up >= strong:
                    return "block"   # 상승추세 SHORT 역행 차단
        except Exception:  # noqa: BLE001
            pass
        return None

    def _final_30m15m_check(self, market: str, direction: str) -> tuple:
        """진입 직전 30M+15M 방향 최종 확인.
        ★ 강화 (2026-05-28 저녁): 둘 중 *하나라도* 진입 방향과 명확히 반대면 차단.
          SIDE 는 통과 (인내 가능). UPTR/DOWNTREND 만 평가.
        Returns (blocked: bool, reason: str)."""
        try:
            if not getattr(self.config, "final_30m15m_check_enabled", True):
                return (False, "")
            # ★ 거시 확실 시 상위TF lag 무시 (급락 SHORT 통과 / LONG 차단) — 2026-06-07 부모
            _ov = self._regime_align_override(direction)
            if _ov == "allow":
                return (False, "regime_aligned(거시순행)")
            if _ov == "block":
                return (True, "regime_opposed(거시역행=떨어지는칼)")
            _, mtf_label = self._compute_mtf_alignment_matrix(market, direction)
            # 예: "H4:UPTR/H1:UPTR/30M:DOWN/15M:DOWN/5m:SIDE align=2-2=+0"
            dir_up = (direction or "").upper()
            # ★ 강화 — 둘 중 하나라도 반대 = 차단 (옛 "둘 다 반대" → "하나라도 반대")
            if dir_up == "LONG":
                if "30M:DOWN" in mtf_label:
                    return (True, "30M=DOWN vs LONG (진입 마지막 점검)")
                if "15M:DOWN" in mtf_label:
                    return (True, "15M=DOWN vs LONG (진입 마지막 점검)")
            elif dir_up == "SHORT":
                if "30M:UPTR" in mtf_label:
                    return (True, "30M=UPTR vs SHORT (진입 마지막 점검)")
                if "15M:UPTR" in mtf_label:
                    return (True, "15M=UPTR vs SHORT (진입 마지막 점검)")
            # 통과 — label 일부 반환 (로그 가시화)
            try:
                _t30 = mtf_label.split("30M:")[1].split("/")[0]
                _t15 = mtf_label.split("15M:")[1].split("/")[0]
                return (False, f"30M={_t30}/15M={_t15}")
            except Exception:
                return (False, "")
        except Exception as exc:
            logger.debug("[FOCUS] _final_30m15m_check %s error: %s", market, exc)
            return (False, "")

    # ── ★ [2026-05-28 저녁 부모 "단 하나" 룰] D1 정렬 진입 필수 가드 ──
    #   부모님 9개월 끝 진리: "Day 캔들만 거슬리지 않으면 어떻게든 이윤. 물려도 72h 안에 풀림."
    #   D1 평가 = alt 본인 일봉 trend.
    #   LONG 진입 → D1=DOWNTREND = 차단 (D1 역방향)
    #   SHORT 진입 → D1=UPTREND = 차단 (D1 역방향)
    #   D1=SIDEWAYS / D1=정렬 → 통과
    #   이건 *가드 신설* 이 아니라 *진입 트리거 조건* — 부모님 명시 유일 룰.
    def _recent_daily_change_pct(self, market: str, n: int = 5) -> Optional[float]:
        """최근 n 일봉 종가 변화율 % (close[-1] vs close[-1-n]). 캐시된 일봉(D, limit40) 재사용.
        ★ [2026-06-14 부모] final_d1 최근5봉 override 용 — UPTREND 오판(lookback=5 잔상) 검출.
        get_kline = oldest first → raw[-1]=최신 봉, raw[-1-n]=n봉 전. close=index 4."""
        try:
            raw = self._get_mtf_kline(market, "D", limit=40)
            if not raw or len(raw) < n + 1:
                return None
            c_last = float(raw[-1][4])
            c_base = float(raw[-1 - n][4])
            if c_base <= 0:
                return None
            return (c_last - c_base) / c_base * 100.0
        except Exception:
            return None

    def _final_d1_alignment_check(self, market: str, direction: str) -> tuple:
        """D1 정렬 필수 검증 — 부모님 "단 하나" 룰.
        D1 역방향 시 진입 차단 (인내 불가). D1 정렬/SIDEWAYS 시 통과.
        Returns (blocked: bool, reason: str)."""
        try:
            if not getattr(self.config, "final_d1_alignment_check_enabled", True):
                return (False, "")
            # ★ 거시 확실 시 D1 lag 무시 (급락 SHORT 통과 / LONG 떨어지는칼 차단) — 2026-06-07 부모
            _ov = self._regime_align_override(direction)
            if _ov == "allow":
                return (False, "regime_aligned(거시순행)")
            if _ov == "block":
                return (True, "regime_opposed(거시역행=떨어지는칼)")
            _, mtf_label = self._compute_mtf_alignment_matrix(market, direction)
            # 예: "D1:UPTR/H4:UPTR/H1:UPTR/30M:SIDE/15M:SIDE/5m:SIDE align=3-0=+3"
            dir_up = (direction or "").upper()
            # D1 trend 추출
            try:
                _d1_trend = mtf_label.split("D1:")[1].split("/")[0]
            except Exception:
                return (False, "D1_label_parse_fail")
            # D1 역방향 = 진입 차단
            if dir_up == "LONG" and _d1_trend.startswith("DOWN"):
                return (True, f"D1=DOWN vs LONG (Day 캔들 거슬림)")
            if dir_up == "SHORT" and _d1_trend.startswith("UPTR"):
                # ★ [2026-06-14 부모] 최근 5봉 override — D1=UPTREND 라벨이 lookback=5+옛 상승 잔상으로
                #   실제 하락을 오판한 케이스면, 최근 5 일봉이 명확히 DOWN 일 때 SHORT 해방. default OFF.
                if getattr(self.config, "final_d1_recent5_override_enabled", False):
                    _r5 = self._recent_daily_change_pct(market, 5)
                    _drop = abs(float(getattr(self.config, "final_d1_recent5_drop_pct", 1.0) or 1.0))
                    if _r5 is not None and _r5 <= -_drop:
                        logger.info("[FOCUS] 🎯 final_d1 최근5봉 OVERRIDE: %s SHORT — D1=UPTR(라벨) but 최근5일봉 %.1f%% ≤ -%.1f%% → 통과 (UPTREND 오판 해방)",
                                    market, _r5, _drop)
                        return (False, f"D1=UPTR_but_recent5_DOWN({_r5:.1f}%)")
                return (True, f"D1=UPTR vs SHORT (Day 캔들 거슬림)")
            return (False, f"D1={_d1_trend}")
        except Exception as exc:
            logger.debug("[FOCUS] _final_d1_alignment_check %s error: %s", market, exc)
            return (False, "")

    # ── [2026-05-29 부모] Smart Manual Entry — 신호 확인 후 진입 ──
    def _signal_matches_direction(self, market: str, direction: str) -> tuple:
        """부모님 의도 방향이 현재 신호와 일치하는지 검증.
        통과 조건 (3중 확인):
          1. D1 정렬 게이트 (필수) — D1 역방향 X
          2. mtf_align net positive (D1+H4+H1+30M+15M 중 부모님 방향 우세)
          3. conviction ≥ 60 (scanner 최근 점수)
        Returns: (matches: bool, reason: str)"""
        try:
            # 1. D1 정렬 필수
            _d1_blocked, _d1_reason = self._final_d1_alignment_check(market, direction)
            if _d1_blocked:
                return (False, f"D1_block:{_d1_reason}")
            # 2. mtf_align
            try:
                _mtf_score, _mtf_label = self._compute_mtf_alignment_matrix(market, direction)
                if _mtf_score < 1:
                    return (False, f"mtf<1:{_mtf_label}")
            except Exception as exc:
                logger.debug("[FOCUS] _signal_matches mtf err %s: %s", market, exc)
                return (False, "mtf_err")
            # 3. conviction (scanner 최근 점수)
            _conv = float(self._last_scan_conviction.get(market, 0.0) or 0.0)
            if _conv < 60.0:
                return (False, f"conv={_conv:.1f}<60")
            return (True, f"D1ok/mtf={_mtf_score}/conv={_conv:.1f}")
        except Exception as exc:
            logger.debug("[FOCUS] _signal_matches_direction %s error: %s", market, exc)
            return (False, "exception")

    # ── [2026-05-29 부모] Market Consensus Exit — 시장 합의 기반 역방향 손실 청산 ──
    def _compute_market_consensus(self) -> Optional[str]:
        """Scanner 의 모든 market 최신 signal 모음 → 우세 방향 측정.
        Returns: 'LONG'/'SHORT' 우세 시 그 방향, 아니면 None."""
        sig_hist = getattr(self, "_signal_history", None) or {}
        if not sig_hist:
            return None
        longs = 0
        shorts = 0
        for _mkt, _dq in sig_hist.items():
            if not _dq:
                continue
            try:
                _last = _dq[-1]
                _sig = str(_last[1] or "").upper() if len(_last) >= 2 else ""
            except Exception:
                continue
            if _sig in ("BUY", "LONG"):
                longs += 1
            elif _sig in ("SELL", "SHORT"):
                shorts += 1
        total = longs + shorts
        if total < 5:  # 최소 5개 market 신호 (의미 있는 합의 X 시 None)
            return None
        thr = float(getattr(self.config, "market_consensus_threshold_pct", 70.0)) / 100.0
        if longs / total >= thr:
            return "LONG"
        if shorts / total >= thr:
            return "SHORT"
        return None

    def _check_market_consensus_exit(self):
        """tick 마다 호출 — 시장 합의 + 활성 포지션 반대방향 + 손실 시 청산."""
        cfg = self.config
        if not getattr(cfg, "market_consensus_exit_enabled", False):
            return
        if not self.positions:
            return
        consensus_dir = self._compute_market_consensus()
        _now = time.time()
        if not consensus_dir:
            # 합의 깨짐 → 시작 시점 리셋
            self._mce_direction = ""
            self._mce_start_ts = 0.0
            return
        # 합의 유지 — 방향 변경 시 리셋
        if self._mce_direction != consensus_dir:
            self._mce_direction = consensus_dir
            self._mce_start_ts = _now
            return  # 방금 시작 → duration 미달
        # duration 체크
        dur_min_req = float(getattr(cfg, "market_consensus_duration_min", 15.0))
        elapsed = _now - self._mce_start_ts
        if elapsed < dur_min_req * 60.0:
            return  # 아직 N분 미달
        # ★ 합의 발동 — 활성 포지션 반대방향 + 손실 검사
        min_hold_sec = float(getattr(cfg, "market_consensus_min_hold_min", 20.0)) * 60.0
        min_pnl_pct = float(getattr(cfg, "market_consensus_min_pnl_pct", -0.5))
        opposite_dir = "SHORT" if consensus_dir == "LONG" else "LONG"
        for pos in list(self.positions):
            if pos.direction != opposite_dir:
                continue
            _ets = float(getattr(pos, "entry_ts", 0) or 0)
            if _ets <= 0:
                continue
            hold_sec = _now - _ets
            if hold_sec < min_hold_sec:
                continue  # 진입 직후 보호
            try:
                price = self._get_current_price(pos.market) or 0
                if price <= 0:
                    continue
                if pos.direction == "LONG":
                    pnl_pct = (price / pos.entry_price - 1) * 100 if pos.entry_price > 0 else 0
                else:
                    pnl_pct = (1 - price / pos.entry_price) * 100 if pos.entry_price > 0 else 0
                if pnl_pct > min_pnl_pct:
                    continue  # 수익 중 또는 손실 작음 → 보호
                logger.warning(
                    "[FOCUS] ★ Market Consensus Exit: %s %s consensus=%s(%dmin) pnl=%.2f%% hold=%.0fmin → 청산",
                    pos.direction, pos.market, consensus_dir, int(elapsed/60), pnl_pct, hold_sec/60,
                )
                try:
                    self._notify(f"📉 Market Consensus Exit\n{pos.market} {pos.direction}\n시장 합의 {consensus_dir} ({int(elapsed/60)}분) → 자동 청산 (pnl={pnl_pct:.2f}%)")
                except Exception:
                    pass
                self._close_position(pos, f"market_consensus:{consensus_dir}_dom_{int(elapsed/60)}min")
            except Exception as exc:
                logger.debug("[FOCUS] _check_market_consensus_exit %s error: %s", pos.market, exc)

    def _check_pending_manual_entries(self):
        """tick 마다 호출 — 큐 검사:
          - timeout 초과 → 제거 + 알림
          - 신호 매칭 → manual_entry(wait_for_signal=False) 즉시 실행 + 큐 제거
        """
        if not self._pending_manual_entries:
            return
        now = time.time()
        _survivors = []
        for _q in self._pending_manual_entries:
            _mkt = _q.get("market", "")
            _dir = _q.get("direction", "")
            _req_ts = float(_q.get("requested_ts", now))
            _to_sec = float(_q.get("timeout_sec", 3600.0))
            _elapsed = now - _req_ts
            # timeout 체크
            if _elapsed >= _to_sec:
                logger.warning("[FOCUS] ★ Smart Manual Entry TIMEOUT: %s %s (waited %.0fs >= %.0fs) — 큐 제거",
                               _mkt, _dir, _elapsed, _to_sec)
                try:
                    self._notify(f"⏱️ Smart Manual Entry 만료\n{_mkt} {_dir} ({_elapsed/60:.0f}분 대기 후 신호 미감지)")
                except Exception:
                    pass
                continue
            # 신호 매칭 체크
            _matches, _reason = self._signal_matches_direction(_mkt, _dir)
            if _matches:
                logger.warning("[FOCUS] ★ Smart Manual Entry SIGNAL MATCH: %s %s waited=%.0fs reason=%s → 즉시 실행",
                               _mkt, _dir, _elapsed, _reason)
                try:
                    self._notify(f"✅ Smart Manual Entry 신호 감지\n{_mkt} {_dir} ({_elapsed/60:.0f}분 대기) → 진입")
                except Exception:
                    pass
                try:
                    # 즉시 실행 path (wait_for_signal=False)
                    self.manual_entry(_mkt, _dir, wait_for_signal=False)
                except Exception as exc:
                    logger.error("[FOCUS] Smart Manual Entry exec error %s %s: %s", _mkt, _dir, exc)
                continue  # 큐에서 제거 (실행 성공/실패 무관)
            # 매칭 X → 큐 유지
            _survivors.append(_q)
        self._pending_manual_entries = _survivors

    def _final_5m_simple_check(self, market: str, direction: str) -> tuple:
        """진입 직전 5M RSI/MACD/BB 방향 동조 검사 (microtiming 과 별개).
        3종 중 min_score 이상 진입 방향에 동조 시 통과. 부모님 5-28 "이것만으로 충분".
        - LONG 동조: RSI≥40, MACD hist≥0, BB pos 20~90%
        - SHORT 동조: RSI≤60, MACD hist≤0, BB pos 10~80%
        Returns (blocked: bool, reason: str)."""
        try:
            cfg = self.config
            if not getattr(cfg, "final_5m_simple_check_enabled", True):
                return (False, "")
            min_score = int(getattr(cfg, "final_5m_simple_min_score", 2))
            raw = self._get_mtf_kline(market, "5", limit=30)
            if not raw or len(raw) < 27:
                return (False, "5M_no_data")
            from app.strategy.indicators import rsi as _rsi_fn, macd_hist_pair as _macd_pair, bollinger_bands as _bb_fn
            closes = [float(r[4]) for r in raw]
            _rsi_arr = _rsi_fn(closes, 14)
            _rsi_now = float(_rsi_arr[-1]) if isinstance(_rsi_arr, list) and _rsi_arr else float(_rsi_arr or 50)
            _hist_now, _ = _macd_pair(closes)
            _bb = _bb_fn(closes, length=20, k=2.0)
            if not _bb or _bb.get("upper", 0) <= _bb.get("lower", 0):
                return (False, "5M_bb_fail")
            _bb_pct = (closes[-1] - _bb["lower"]) / (_bb["upper"] - _bb["lower"]) * 100.0
            dir_up = (direction or "").upper()
            score = 0
            sig = []
            if dir_up == "LONG":
                if _rsi_now >= 40:
                    score += 1; sig.append(f"RSI{_rsi_now:.0f}✓")
                else:
                    sig.append(f"RSI{_rsi_now:.0f}✗")
                if _hist_now is not None and float(_hist_now) >= 0:
                    score += 1; sig.append("MACD✓")
                else:
                    sig.append("MACD✗")
                _bb_in = (20 <= _bb_pct <= 90)
                _bb_byp = False
                if not _bb_in and _bb_pct > 90 and getattr(cfg, "final_5m_bb_trend_bypass_enabled", False):
                    self._fetch_primary_adx(market)   # _last_adx/_di 그 코인 갱신
                    _bb_byp = self._bb_trend_riding("LONG", closes)[0]
                if _bb_in or _bb_byp:
                    score += 1; sig.append(f"BB{_bb_pct:.0f}{'✓벽' if _bb_byp else '✓'}")
                else:
                    sig.append(f"BB{_bb_pct:.0f}✗")
            elif dir_up == "SHORT":
                if _rsi_now <= 60:
                    score += 1; sig.append(f"RSI{_rsi_now:.0f}✓")
                else:
                    sig.append(f"RSI{_rsi_now:.0f}✗")
                if _hist_now is not None and float(_hist_now) <= 0:
                    score += 1; sig.append("MACD✓")
                else:
                    sig.append("MACD✗")
                _bb_in = (10 <= _bb_pct <= 80)
                _bb_byp = False
                if not _bb_in and _bb_pct < 10 and getattr(cfg, "final_5m_bb_trend_bypass_enabled", False):
                    self._fetch_primary_adx(market)   # _last_adx/_di 그 코인 갱신
                    _bb_byp = self._bb_trend_riding("SHORT", closes)[0]
                if _bb_in or _bb_byp:
                    score += 1; sig.append(f"BB{_bb_pct:.0f}{'✓벽' if _bb_byp else '✓'}")
                else:
                    sig.append(f"BB{_bb_pct:.0f}✗")
            label = f"5M={score}/{min_score}[{','.join(sig)}]"
            if score < min_score:
                return (True, label)
            return (False, label)
        except Exception as exc:
            logger.debug("[FOCUS] _final_5m_simple_check %s error: %s", market, exc)
            return (False, "")

    # ── [2026-05-27 부모] PA Completion Guard — Sig + ไส้หลัง 마감 검증 ──
    def _pa_completion_active(self) -> bool:
        """PA Completion Guard 활성 여부 — enabled 만 검사 (부모 2026-05-28 단순화)."""
        return bool(getattr(self.config, "pa_completion_enabled", False))

    def _check_pa_completion(self, market: str, direction: str, tf: str) -> tuple:
        """진입 직전 PA 완성 검증 — Sig + ไส้หลัง(뒤꼬리) 둘 다 마감.
        부모님 명령 (XAUUSD 88 / GreenPen 교재, 2026-05-27):
          Pat 1/2/3 외 모든 캔들 진입 불가.
          가장 최근 *마감* 캔들 = ไส้หลัง (큰 진입방향)
          ไส้หลัง 직전 캔들 = Sig (반대 방향, 더 작음)
        Returns (ok: bool, info: str).
        에러 시 (False, "") — fail-closed (안전).
        """
        try:
            cfg = self.config
            min_ratio = float(getattr(cfg, "pa_completion_huikkang_min_ratio", 1.5))
            lookback = max(2, int(getattr(cfg, "pa_completion_lookback_bars", 3)))
            sig_max = float(getattr(cfg, "pa_completion_sig_max_ratio", 1.0))
            # kline 가져오기: forming 1봉 + ไส้หลัง 1봉 + Sig 1봉 + lookback 봉 = lookback + 3 이상
            need = lookback + 3
            raw = self._get_client().get_kline(market, interval=tf, limit=max(need + 2, 8))
            if not raw or len(raw) < need:
                return (False, "pa_completion: 캔들 부족 %d<%d" % (len(raw) if raw else 0, need))
            ordered = list(raw)  # oldest first
            # forming 캔들 제외 (마지막) → 마감 캔들만
            closed = ordered[:-1]
            if len(closed) < lookback + 2:
                return (False, "pa_completion: 마감 캔들 부족 %d" % len(closed))
            # ไส้หลัง = 가장 최근 마감 캔들
            huikkang = closed[-1]
            h_open = float(huikkang[1]); h_high = float(huikkang[2])
            h_low = float(huikkang[3]); h_close = float(huikkang[4])
            h_body = abs(h_close - h_open)
            h_dir = "UP" if h_close > h_open else "DOWN"
            want_dir = "UP" if direction.upper() == "LONG" else "DOWN"
            # ① ไส้หลัง 방향 = 진입 방향 일치
            if h_dir != want_dir:
                return (False, "pa_completion: ไส้หลัง %s ≠ %s (진입 방향)" % (h_dir, want_dir))
            # ② ไส้หลัง body ≥ 직전 lookback 봉 평균 × min_ratio
            prev_bodies = []
            for c in closed[-(lookback + 1):-1]:  # ไส้หลัง 직전 lookback 봉
                try:
                    pb = abs(float(c[4]) - float(c[1]))
                    if pb > 0:
                        prev_bodies.append(pb)
                except Exception:
                    continue
            if not prev_bodies:
                return (False, "pa_completion: 직전 봉 body 계산 실패")
            avg_prev = sum(prev_bodies) / len(prev_bodies)
            threshold = avg_prev * min_ratio
            if h_body < threshold:
                return (False, "pa_completion: ไส้หลัง body %.6f < %.6f (평균 %.6f × %.2f) — 약함" %
                        (h_body, threshold, avg_prev, min_ratio))
            # ③ Sig = ไส้หลัง 직전 마감 캔들. 반대 방향. body < ไส้หลัง body × sig_max
            sig = closed[-2]
            s_open = float(sig[1]); s_close = float(sig[4])
            s_body = abs(s_close - s_open)
            s_dir = "UP" if s_close > s_open else "DOWN"
            if s_dir == h_dir:
                return (False, "pa_completion: Sig 방향 %s = ไส้หลัง 방향 %s (반대 필요)" % (s_dir, h_dir))
            if s_body > h_body * sig_max:
                return (False, "pa_completion: Sig body %.6f > ไส้หลัง body %.6f × %.2f — Sig 너무 큼" %
                        (s_body, h_body, sig_max))
            return (True, "PA 완성 — Sig(%s/%.6f) + ไส้หลัง(%s/%.6f, ≥ 평균%.6f×%.2f)" %
                    (s_dir, s_body, h_dir, h_body, avg_prev, min_ratio))
        except Exception as exc:
            logger.debug("[FOCUS] _check_pa_completion error %s %s tf=%s: %s", market, direction, tf, exc)
            return (False, "pa_completion: error")

    def _check_anchor_fasttrack(self, market: str, direction: str) -> tuple:
        """현재가가 앵커 근접 자리(proximity ≤ max)인지 판정.
        proximity = |entry - anchor| / |TP1 - anchor| (0=정점, 1=TP1, >1=라운드 빠짐).
        Returns (fasttrack_ok: bool, proximity: float, reason: str).
        앵커/TP1 계산 실패 시 (False, 0.0, "") — 기존 흐름 유지 (안전 fallback)."""
        try:
            tup = self._compute_tf_round_targets(market, direction)
            if not tup:
                return (False, 0.0, "")
            tp1, _tp2, _sl, _atr = tup
            price = float(self._get_client()._linear_last_price(market) or 0.0)
            if price <= 0:
                return (False, 0.0, "")
            # anchor 역산: LONG TP1 = anchor + (TP1 - anchor) → anchor = TP1 - (TP1 - anchor)
            # _compute_tf_round_targets 에서 LONG: tp1 = anchor + round1 → anchor = tp1 - round1 = tp1 - atr*tp_mult
            # 더 단순: round_dist = |TP1 - anchor| = atr * tp_mult
            tp_mult = float(getattr(self.config, "tf_round_tp_atr_mult", 1.0))
            round_dist = _atr * tp_mult
            if round_dist <= 0:
                return (False, 0.0, "")
            d = (direction or "").upper()
            if d == "LONG":
                anchor = tp1 - round_dist
            else:
                anchor = tp1 + round_dist
            anchor_dist = abs(price - anchor)
            proximity = anchor_dist / round_dist
            max_prox = float(getattr(self.config, "anchor_fasttrack_max_proximity", 0.33))
            ok = proximity <= max_prox
            return (ok, proximity, "anchor=%.4f price=%.4f proximity=%.2f/%.2f" %
                    (anchor, price, proximity, max_prox))
        except Exception as exc:
            logger.debug("[FOCUS] _check_anchor_fasttrack error %s %s: %s", market, direction, exc)
            return (False, 0.0, "")

    def _in_h4_pulse_window(self) -> tuple:
        """현재 시각이 H4 마감 직후 펄스 창 안인지. KST: 01/05/09/13/17/21시 마감.
        Bybit H4(UTC 0/4/8/12/16/20) = KST 9/13/17/21/1/5 = 교재 Exness 마감 시각과 동일.
        Returns (in_window: bool, reason: str)"""
        try:
            import datetime
            w = max(1, int(getattr(self.config, "h4_pulse_window_min", 30)))
            dt = datetime.datetime.now()  # local KST 가정
            if dt.hour not in (1, 5, 9, 13, 17, 21):
                # 다음 펄스 시각 계산
                hours = [1, 5, 9, 13, 17, 21]
                cur = dt.hour
                nxt = next((h for h in hours if h > cur), hours[0])
                wait_h = (nxt - cur) % 24
                return (False, "outside_h4_pulse %02d:%02d (다음 펄스 %02d:00 까지 ~%dh)"
                        % (dt.hour, dt.minute, nxt, wait_h))
            if dt.minute >= w:
                return (False, "outside_h4_pulse %02d:%02d (창 %d분 지남)" % (dt.hour, dt.minute, w))
            return (True, "h4_pulse OK %02d:%02d (+%dm)" % (dt.hour, dt.minute, w))
        except Exception as exc:
            logger.debug("[FOCUS] _in_h4_pulse_window error: %s", exc)
            return (True, "")  # 에러 시 안전 통과 (블록 안 함)

    def _preclose_pattern_ok(self, market: str, direction: str) -> tuple:
        """[패치 v2-A] H4 진행봉이 마감 전이라도 *형태 완성* 인지 판정.
        진행봉 경과율 ≥ preclose_min_elapsed_pct 이고, 방향에 맞는 핀바/몸통 형태면 True.
        순수 판정만 (점수/사이즈/카운터 무관). 에러·미달 시 (False, 사유) — 절대 throw 안 함.
        Returns (ok: bool, reason: str)"""
        try:
            import time as _time
            min_elapsed = float(getattr(self.config, "preclose_min_elapsed_pct", 88.0))
            wick_min = float(getattr(self.config, "preclose_wick_ratio_min", 1.5))
            body_dir_req = bool(getattr(self.config, "preclose_body_dir_required", True))
            raw = self._get_mtf_kline(market, "240", limit=2, ttl=30.0)
            if not raw:
                return (False, "no_h4_data")
            last = raw[-1]
            bar_ts = int(last[0]); bar_open = float(last[1])
            bar_high = float(last[2]); bar_low = float(last[3])
            # live price
            live = 0.0
            try:
                from app.core import price_store
                _lp = price_store.get_price(market, max_age_sec=60.0)
                if _lp and _lp > 0:
                    live = float(_lp)
            except Exception:
                pass
            if live <= 0:
                try:
                    r5 = self._get_mtf_kline(market, "5", limit=2, ttl=5.0)
                    if r5:
                        live = float(r5[-1][4])
                except Exception:
                    pass
            if live <= 0 or bar_open <= 0:
                return (False, "no_live_price")
            now_ms = int(_time.time() * 1000)
            tf_ms = 240 * 60 * 1000
            elapsed_pct = min(100.0, max(0.0, (now_ms - bar_ts) / tf_ms * 100.0))
            if elapsed_pct < min_elapsed:
                return (False, "elapsed=%.0f%%<%.0f" % (elapsed_pct, min_elapsed))
            cur_high = max(bar_high, live)
            cur_low = min(bar_low, live) if bar_low > 0 else live
            rng = max(1e-9, cur_high - cur_low)
            body = abs(live - bar_open)
            d = (direction or "").upper()
            if d in ("LONG", "BUY"):
                lower_wick = min(live, bar_open) - cur_low
                cond_wick = body > 1e-9 and (lower_wick / body) >= wick_min
                cond_body = body_dir_req and (live > bar_open) and ((cur_high - live) <= 0.30 * rng)
                ok = cond_wick or cond_body
                tag = "wick=%.1f" % (lower_wick / body) if body > 1e-9 else "wick=na"
            else:  # SHORT / SELL (거울)
                upper_wick = cur_high - max(live, bar_open)
                cond_wick = body > 1e-9 and (upper_wick / body) >= wick_min
                cond_body = body_dir_req and (live < bar_open) and ((live - cur_low) <= 0.30 * rng)
                ok = cond_wick or cond_body
                tag = "wick=%.1f" % (upper_wick / body) if body > 1e-9 else "wick=na"
            return (bool(ok), "elapsed=%.0f%%,%s" % (elapsed_pct, tag))
        except Exception as exc:
            logger.debug("[FOCUS] _preclose_pattern_ok error %s: %s", market, exc)
            return (False, "error")

    @staticmethod
    def _next_h4_close_after(ts: float) -> float:
        """[패치 v2-A2] entry_ts 직후의 H4 마감 시각(epoch). KST 01/05/09/13/17/21시 마감."""
        try:
            import datetime
            dt = datetime.datetime.fromtimestamp(ts)
            bnds = (1, 5, 9, 13, 17, 21)
            for add in range(1, 26):
                cand = (dt + datetime.timedelta(hours=add)).replace(minute=0, second=0, microsecond=0)
                if cand > dt and cand.hour in bnds:
                    return cand.timestamp()
        except Exception:
            pass
        return ts + 4 * 3600

    def _h4_last_closed_dir_ok(self, market: str, direction: str) -> bool:
        """[패치 v2-A2] 직전 *마감* H4봉이 진입 방향인지 (확인). 데이터/에러 시 True(pnl 게이트가 받침)."""
        try:
            raw = self._get_mtf_kline(market, "240", limit=3, ttl=30.0)
            if not raw or len(raw) < 2:
                return True
            c = raw[-2]  # 직전 마감봉 (raw[-1]=진행중)
            o = float(c[1]); cl = float(c[4])
            if (direction or "").upper() in ("LONG", "BUY"):
                return cl >= o
            return cl <= o
        except Exception:
            return True

    def _execute_preclose_topup(self, pos, add_qty: float, price: float) -> bool:
        """[패치 v2-A2] 나머지 반 증액 — winners_add 와 동일 경로(place_order + 가중평균 갱신)."""
        try:
            add_qty = round(float(add_qty), 4)
            if add_qty <= 0:
                return False
            client = self._get_client()
            side = "Buy" if pos.direction == "LONG" else "Sell"
            resp = client.place_order(pos.market, side, add_qty, reduce_only=False)
            if resp and resp.get("retCode", -1) == 0:
                old_total = pos.entry_price * pos.qty
                new_total = price * add_qty
                total_qty = pos.qty + add_qty
                pos.entry_price = (old_total + new_total) / total_qty if total_qty > 0 else pos.entry_price
                pos.qty = total_qty
                logger.info("[FOCUS] ⏩➕ Pre-Close 마감확인 증액: %s %s +qty=%.4f @ $%.6f → new entry $%.6f total %.4f",
                            pos.direction, pos.market, add_qty, price, pos.entry_price, pos.qty)
                try:
                    self._notify(f"⏩➕ Pre-Close 증액(2차): {pos.direction} {pos.market}\n"
                                 f"  +qty {add_qty} @ ${price:.4f} → avg ${pos.entry_price:.4f}")
                except Exception:
                    pass
                try:
                    self._save_config()
                except Exception:
                    pass
                return True
            logger.warning("[FOCUS] preclose topup %s 거절: %s", pos.market, (resp or {}).get("retMsg", "?"))
        except Exception as exc:
            logger.warning("[FOCUS] preclose topup %s failed: %s", pos.market, exc)
        return False

    def _check_preclose_topup_tick(self):
        """[패치 v2-A2] 메인 tick — 선행 진입 반쪽이 H4 마감 후 확인되면 나머지 반 증액.
        안전: enabled+E-STOP 가드, 확인(pnl≥min + 마감봉 방향), 과다추격 캡, 창 만료 시 반 유지."""
        if not getattr(self.config, "preclose_topup_enabled", False):
            return
        if not getattr(self.config, "enabled", False) or getattr(self, "emergency_stop", False):
            return
        try:
            import time as _t
            now = _t.time()
            min_pnl = float(getattr(self.config, "preclose_topup_min_pnl_pct", 0.0))
            max_chase = float(getattr(self.config, "preclose_topup_max_chase_pct", 1.0))
            grace = float(getattr(self.config, "preclose_topup_grace_min", 60.0)) * 60.0
            req_dir = bool(getattr(self.config, "preclose_topup_require_candle_dir", True))
            for pos in list(getattr(self, "positions", []) or []):
                if not getattr(pos, "preclose_pending_topup", False):
                    continue
                add_qty = float(getattr(pos, "preclose_topup_qty", 0.0) or 0.0)
                entry_ts = float(getattr(pos, "preclose_entry_ts", 0.0) or 0.0)
                if add_qty <= 0 or entry_ts <= 0:
                    pos.preclose_pending_topup = False
                    continue
                close_ts = self._next_h4_close_after(entry_ts)
                if now < close_ts:
                    continue  # 진입봉 아직 마감 전
                if now > close_ts + grace:
                    pos.preclose_pending_topup = False
                    logger.info("[FOCUS] ⏩ Pre-Close 증액 만료(창 %dm 지남): %s — 반 사이즈 유지",
                                int(grace / 60), pos.market)
                    continue
                price = self._get_current_price(pos.market) or pos.entry_price
                if pos.entry_price <= 0 or price <= 0:
                    continue
                pnl_pct = (price / pos.entry_price - 1) * 100.0
                if (pos.direction or "").upper() == "SHORT":
                    pnl_pct = -pnl_pct
                if pnl_pct < min_pnl:
                    pos.preclose_pending_topup = False
                    logger.info("[FOCUS] ⏩ Pre-Close 미확인(pnl %.2f%%<%.2f) → 증액 취소, 반 유지: %s",
                                pnl_pct, min_pnl, pos.market)
                    continue
                if pnl_pct > max_chase:
                    pos.preclose_pending_topup = False
                    logger.info("[FOCUS] ⏩ Pre-Close 과다진행(pnl %.2f%%>cap %.2f) → 증액 취소(늦은추격 방지): %s",
                                pnl_pct, max_chase, pos.market)
                    continue
                if req_dir and not self._h4_last_closed_dir_ok(pos.market, pos.direction):
                    pos.preclose_pending_topup = False
                    logger.info("[FOCUS] ⏩ Pre-Close 마감봉 역방향 → 증액 취소, 반 유지: %s", pos.market)
                    continue
                # 확인됨 → 나머지 반 증액
                if self._execute_preclose_topup(pos, add_qty, price):
                    pos.preclose_pending_topup = False
        except Exception as exc:
            logger.debug("[FOCUS] preclose topup tick error: %s", exc)

    # ── [2026-05-27 부모] Day Box Guard ─────────────────────────
    def _day_box_guard_active(self) -> bool:
        """Day Box Guard 활성 여부 — enabled 만 검사 (부모 2026-05-28 단순화)."""
        return bool(getattr(self.config, "day_box_guard_enabled", False))

    def _update_day_box(self, market: str, price: float) -> None:
        """09:00 KST 부터 window_hours 동안 (high, low) 갱신 + 핑퐁 lock 판정.
        매 _execute_entry 시도 직전 또는 tick 가격 갱신 시 호출.
        per-market 추적 (BTC 만이 아닌 각 코인 자체 박스 — 알트 박스 포착 위해)."""
        if not self._day_box_guard_active() or price <= 0:
            return
        try:
            import datetime as _dt
            kst = _dt.timezone(_dt.timedelta(hours=9))
            now = _dt.datetime.now(_dt.timezone.utc).astimezone(kst)
            today = now.strftime("%Y-%m-%d")
            nine = now.replace(hour=9, minute=0, second=0, microsecond=0)
            if now < nine:
                return  # 09시 이전 — 박스 미시작
            elapsed_h = (now - nine).total_seconds() / 3600.0
            c = self.config
            win_h = float(getattr(c, "day_box_window_hours", 4.0))
            lock_h = float(getattr(c, "day_box_lock_min_hours", 3.5))
            max_ratio = float(getattr(c, "day_box_max_atr_ratio", 0.8))
            min_touch = int(getattr(c, "day_box_min_touches", 2))
            eps = float(getattr(c, "day_box_touch_eps_pct", 0.05)) / 100.0
            breakout = float(getattr(c, "day_box_breakout_pct", 0.10)) / 100.0

            mkt = market.upper()
            st = self.day_box_state.get(mkt)
            if not st or st.get("date") != today:
                # 새 day 박스 시작 — 봇 부팅이 09:00 보다 늦었으면 H1 kline 으로 백필
                # (그렇지 않으면 박스 추적이 *부팅 시점 이후* 만 되어 박스 누락)
                self._backfill_day_box(mkt, today, now, nine)
                # 백필이 작동했으면 state 가 채워짐. 안 됐으면 현재가로 fresh start.
                if mkt not in self.day_box_state or self.day_box_state[mkt].get("date") != today:
                    self.day_box_state[mkt] = {
                        "date": today,
                        "high": price, "low": price,
                        "h_first_ts": now.timestamp(), "l_first_ts": now.timestamp(),
                        "touches_high": 1, "touches_low": 1,
                        "locked": False, "locked_at": 0.0,
                        "logged_lock": False,
                        "lock_eval_logged": False,
                    }
                    logger.info("[FOCUS] 📦 Day Box 시작 %s: %.6f (백필 못함, 부팅 시점부터 추적, elapsed=%.1fh)",
                                mkt, price, elapsed_h)
                return
            # 박스 형성 구간 (0 ~ window_hours)
            if elapsed_h <= win_h:
                if price > st["high"]:
                    st["high"] = price
                    st["h_first_ts"] = now.timestamp()
                    st["touches_high"] = 1
                elif st["high"] > 0 and price >= st["high"] * (1.0 - eps):
                    st["touches_high"] += 1
                if price < st["low"]:
                    st["low"] = price
                    st["l_first_ts"] = now.timestamp()
                    st["touches_low"] = 1
                elif st["low"] > 0 and price <= st["low"] * (1.0 + eps):
                    st["touches_low"] += 1
                # lock 판정 (lock_min_hours 후부터 가능)
                if not st["locked"] and elapsed_h >= lock_h:
                    rng = st["high"] - st["low"]
                    day_atr = float(getattr(self, "day_h4_atr_pct", 0.0) or 0.0)
                    threshold_pct = day_atr * max_ratio
                    box_pct = (rng / st["low"] * 100.0) if (rng > 0 and st["low"] > 0) else 0.0
                    eval_logged = st.get("lock_eval_logged", False)
                    if rng > 0 and st["low"] > 0 and day_atr > 0 and box_pct <= threshold_pct:
                        if st["touches_high"] >= min_touch and st["touches_low"] >= min_touch:
                            st["locked"] = True
                            st["locked_at"] = now.timestamp()
                            if not st["logged_lock"]:
                                logger.info("[FOCUS] 🎰 Day Box LOCK %s: [%.6f ~ %.6f] %.2f%% ≤ %.2f%% touches=%d/%d",
                                            mkt, st["low"], st["high"], box_pct, threshold_pct,
                                            st["touches_high"], st["touches_low"])
                                st["logged_lock"] = True
                                st["lock_eval_logged"] = True
                        elif not eval_logged:
                            logger.info("[FOCUS] 📦 Day Box %s lock_h 도달: [%.6f~%.6f] %.2f%% ≤ %.2f%% but touches=%d/%d < %d → lock X (계속 추적)",
                                        mkt, st["low"], st["high"], box_pct, threshold_pct,
                                        st["touches_high"], st["touches_low"], min_touch)
                            st["lock_eval_logged"] = True
                    elif not eval_logged:
                        # 박스 넓거나 day_atr 미정 — 한 번만 사유 명시
                        if day_atr <= 0:
                            logger.info("[FOCUS] 📦 Day Box %s lock_h 도달: [%.6f~%.6f] %.2f%% (day_atr 미정 — Day Direction 평가 대기)",
                                        mkt, st["low"], st["high"], box_pct)
                        else:
                            logger.info("[FOCUS] 📦 Day Box %s lock_h 도달: [%.6f~%.6f] %.2f%% > %.2f%% → 박스 넓음 lock X (변동성 시장)",
                                        mkt, st["low"], st["high"], box_pct, threshold_pct)
                        st["lock_eval_logged"] = True
            else:
                # window 지남 — 박스 돌파 시 lock 해제 (브레이크아웃 진입 가능)
                if st["locked"]:
                    if price > st["high"] * (1.0 + breakout) or price < st["low"] * (1.0 - breakout):
                        logger.info("[FOCUS] 🔓 Day Box BREAKOUT %s: %.6f (box=[%.6f ~ %.6f])",
                                    mkt, price, st["low"], st["high"])
                        st["locked"] = False
                        st["logged_lock"] = False
        except Exception as exc:
            logger.debug("[FOCUS] _update_day_box %s error: %s", market, exc)

    def _backfill_day_box(self, market: str, today: str, now, nine) -> None:
        """봇 부팅이 09:00 KST 보다 늦었을 때 H1 kline 으로 박스 복원.
        09:00 KST 시작 봉부터 window_hours 안의 H1 마감 봉들 high/low/touches 집계.
        4h 지났으면 lock 판정도 즉시 수행 → 박스 추적 누락 없음.
        실패 시 self.day_box_state 채우지 않음 (호출측이 fresh start)."""
        try:
            import datetime as _dt
            c = self.config
            win_h = float(getattr(c, "day_box_window_hours", 4.0))
            eps = float(getattr(c, "day_box_touch_eps_pct", 0.05)) / 100.0
            lock_h = float(getattr(c, "day_box_lock_min_hours", 3.5))
            max_ratio = float(getattr(c, "day_box_max_atr_ratio", 0.8))
            min_touch = int(getattr(c, "day_box_min_touches", 2))

            elapsed_h = (now - nine).total_seconds() / 3600.0
            if elapsed_h <= 0:
                return  # 09:00 이전 — 백필 불필요
            # H1 kline 가져오기 (24봉이면 24h 충분, 보수적으로 limit=24)
            raw = self._get_client().get_kline(market, interval="60", limit=24)
            if not raw:
                logger.info("[FOCUS] 📦 Day Box 백필 %s: H1 kline 가져오기 실패 → fresh start (부팅 시점부터 추적)",
                            market.upper())
                return
            ordered = list(raw)  # oldest first
            # bybit kline ts = 봉 *시작* 시각 (ms). 09:00 KST 의 H1 봉 ts = 09:00:00.
            nine_ts_ms = int(nine.timestamp() * 1000)
            win_end_ts_ms = int((nine + _dt.timedelta(hours=win_h)).timestamp() * 1000)
            relevant = []
            for r in ordered:
                if len(r) < 5:
                    continue
                try:
                    ts_ms = int(float(r[0]))
                    # 9시 봉 이상 AND window 안에 시작한 봉만 (forming 봉도 포함 가능 = win 끝 시점이면 봉 시작 OK)
                    if ts_ms >= nine_ts_ms and ts_ms < win_end_ts_ms:
                        relevant.append(r)
                except Exception:
                    continue
            if not relevant:
                logger.info("[FOCUS] 📦 Day Box 백필 %s: 09:00 KST 이후 H1 봉 없음 (elapsed=%.1fh, kline %d봉) → fresh start",
                            market.upper(), elapsed_h, len(raw))
                return  # 09:00 이후 봉 없음 — fresh start 권유
            # 첫 봉으로 시작
            first = relevant[0]
            high = float(first[2])
            low = float(first[3])
            h_ts = float(first[0]) / 1000.0
            l_ts = h_ts
            touches_h = 1
            touches_l = 1
            for r in relevant[1:]:
                try:
                    rh = float(r[2])
                    rl = float(r[3])
                    rts = float(r[0]) / 1000.0
                    if rh > high:
                        high = rh; h_ts = rts; touches_h = 1
                    elif high > 0 and rh >= high * (1.0 - eps):
                        touches_h += 1
                    if rl < low:
                        low = rl; l_ts = rts; touches_l = 1
                    elif low > 0 and rl <= low * (1.0 + eps):
                        touches_l += 1
                except Exception:
                    continue
            # lock 판정 (lock_min_hours 이미 지났으면 즉시) — 모든 분기 info 로그 보장
            locked = False
            locked_at = 0.0
            logged_lock = False
            lock_eval_logged = False  # update 분기 진입 시 중복 평가 로그 방지
            rng = high - low
            day_atr = float(getattr(self, "day_h4_atr_pct", 0.0) or 0.0)
            threshold_pct = day_atr * max_ratio
            box_pct = (rng / low * 100.0) if (rng > 0 and low > 0) else 0.0
            if elapsed_h >= lock_h:
                lock_eval_logged = True  # 이 자리에서 평가 마쳤음을 표시
                if rng <= 0 or low <= 0:
                    logger.info("[FOCUS] 📦 Day Box 백필 %s (%d봉): low/high 무효 [%.6f~%.6f] → lock X (계속 추적)",
                                market.upper(), len(relevant), low, high)
                elif day_atr <= 0:
                    logger.info("[FOCUS] 📦 Day Box 백필 %s (%d봉): [%.6f~%.6f] %.2f%% (day_atr 미정 — Day Direction 평가 대기, lock 보류)",
                                market.upper(), len(relevant), low, high, box_pct)
                elif box_pct > threshold_pct:
                    logger.info("[FOCUS] 📦 Day Box 백필 %s (%d봉): [%.6f~%.6f] %.2f%% > %.2f%% → 박스 넓음 lock X (변동성 시장 elapsed=%.1fh)",
                                market.upper(), len(relevant), low, high, box_pct, threshold_pct, elapsed_h)
                elif touches_h < min_touch or touches_l < min_touch:
                    logger.info("[FOCUS] 📦 Day Box 백필 %s (%d봉): [%.6f~%.6f] %.2f%% ≤ %.2f%% but touches=%d/%d < %d → lock X (핑퐁 부족)",
                                market.upper(), len(relevant), low, high, box_pct, threshold_pct,
                                touches_h, touches_l, min_touch)
                else:
                    locked = True
                    locked_at = now.timestamp()
                    logged_lock = True
                    logger.info("[FOCUS] 🎰 Day Box LOCK %s (백필 %d봉): [%.6f ~ %.6f] %.2f%% ≤ %.2f%% touches=%d/%d",
                                market.upper(), len(relevant), low, high, box_pct, threshold_pct,
                                touches_h, touches_l)
            else:
                logger.info("[FOCUS] 📦 Day Box 백필 %s (%d봉): [%.6f~%.6f] %.2f%% (elapsed=%.1fh<%.1fh, window 진행중 — lock 보류)",
                            market.upper(), len(relevant), low, high, box_pct, elapsed_h, lock_h)
            self.day_box_state[market.upper()] = {
                "date": today,
                "high": high, "low": low,
                "h_first_ts": h_ts, "l_first_ts": l_ts,
                "touches_high": touches_h, "touches_low": touches_l,
                "locked": locked, "locked_at": locked_at,
                "logged_lock": logged_lock,
                "lock_eval_logged": lock_eval_logged,
            }
        except Exception as exc:
            logger.debug("[FOCUS] _backfill_day_box %s error: %s", market, exc)

    def _check_day_box_guard(self, market: str, direction: str, price: float) -> tuple:
        """박스 lock 시 박스 안 진입 차단. edge 근처는 방향별 허용 (반전 자리만).
        Returns (blocked: bool, reason: str)."""
        if not self._day_box_guard_active() or price <= 0:
            return (False, "")
        st = self.day_box_state.get(market.upper())
        if not st or not st.get("locked"):
            return (False, "")
        try:
            h = float(st.get("high", 0))
            l = float(st.get("low", 0))
            rng = h - l
            if rng <= 0:
                return (False, "")
            pos = (price - l) / rng
            edge = float(getattr(self.config, "day_box_edge_pct", 0.05))
            d = (direction or "").upper()
            # 상한 근처 (1-edge ~ 1+): SHORT 만 허용
            if pos >= (1.0 - edge):
                if d == "SHORT":
                    return (False, "day_box edge_top SHORT OK pos=%.0f%%" % (pos * 100))
                return (True, "day_box: LONG 거부 - 박스 상단 %.0f%% (반전 자리, SHORT 영역)" % (pos * 100))
            # 하한 근처 (0 ~ edge): LONG 만 허용
            if pos <= edge:
                if d == "LONG":
                    return (False, "day_box edge_bot LONG OK pos=%.0f%%" % (pos * 100))
                return (True, "day_box: SHORT 거부 - 박스 하단 %.0f%% (반전 자리, LONG 영역)" % (pos * 100))
            # 박스 안 (edge ~ 1-edge): 양방향 차단 (핑퐁 중)
            return (True, "day_box: %s 거부 - 박스 안 %.0f%% (핑퐁 중, [%.4f~%.4f])"
                    % (d, pos * 100, l, h))
        except Exception as exc:
            logger.debug("[FOCUS] _check_day_box_guard error %s: %s", market, exc)
            return (False, "")

    def _get_24h_ticker(self, market: str) -> dict:
        """[캐시 TTL 30s] 24h 티커(price24hPcnt/high/low/last). overextension + blowoff 공유 —
        bybit_get 중복 fetch 방지 (rate-limit 보호). 에러 시 직전 캐시 or {}."""
        import time as _t
        mk = (market or "").upper()
        now = _t.time()
        if not hasattr(self, "_ticker24h_cache"):
            self._ticker24h_cache = {}
        hit = self._ticker24h_cache.get(mk)
        if hit and (now - hit[0]) < 30.0:
            return hit[1]
        try:
            from app.core.constants import BYBIT_MARKET_TICKERS, parse_bybit_list
            from app.core.rate_limiter import bybit_get
            resp = bybit_get(BYBIT_MARKET_TICKERS,
                             params={"category": "linear", "symbol": mk}, timeout=5)
            resp.raise_for_status()
            rows = parse_bybit_list(resp.json())
            t = rows[0] if rows else {}
            self._ticker24h_cache[mk] = (now, t)
            return t
        except Exception:
            return hit[1] if hit else {}

    def _check_blowoff(self, market: str, direction: str) -> tuple:
        """[2026-06-13 부모 #1] Blow-off 끝물 — 24h |변동| 크기 기준 *추격* 차단. ★ADX 면제 없음
        (overextension 의 ADX 구멍 보완 — 펌프는 ADX 폭발해 거기선 면제됨). chase=같은방향 진입만 감점.
        LONG on +급등 / SHORT on -급락 = 추격 → 감점. fade(반대)는 면제(옵션). Returns (penalty, detail)."""
        cfg = self.config
        if not getattr(cfg, "blowoff_filter_enabled", False):
            return (0.0, "")
        d = (direction or "").upper()
        if d not in ("LONG", "SHORT"):
            return (0.0, "")
        try:
            t = self._get_24h_ticker(market)
            if not t:
                return (0.0, "")
            chg = float(t.get("price24hPcnt", 0) or 0) * 100.0   # 부호: +급등 / -급락
            move = abs(chg)
            thr = float(getattr(cfg, "blowoff_move_pct", 30.0))
            if move < thr:
                return (0.0, "")
            chasing = (d == "LONG" and chg > 0) or (d == "SHORT" and chg < 0)
            if getattr(cfg, "blowoff_chase_only", True) and not chasing:
                return (0.0, f"fade ok({chg:+.0f}%)")   # 펌프를 *fade* = 추격 아님 → 면제
            base = float(getattr(cfg, "blowoff_penalty", 20.0))
            ext = float(getattr(cfg, "blowoff_extreme_pct", 80.0))
            maxp = float(getattr(cfg, "blowoff_max_penalty", 40.0))
            if move >= ext:
                pen = maxp
            else:
                span = max(1e-9, ext - thr)
                pen = base + (move - thr) / span * (maxp - base)
            pen = max(0.0, min(maxp, pen))
            return (pen, f"{d} 24h{chg:+.0f}% 추격")
        except Exception as exc:
            logger.debug("[FOCUS] _check_blowoff error %s: %s", market, exc)
            return (0.0, "")

    def _check_overextension(self, market: str, direction: str) -> tuple:
        """끝물 추격 감지 (2026-06-07 부모) — 24H 범위 위치 + 이동폭으로 '소진된 추세 추격' 판정.
        LONG: 24H 범위 상단(pos≥range_pos) + 24H 급등(|move|≥min_move) → (penalty, detail)
        SHORT: 24H 범위 하단(pos≤1-range_pos) + 24H 급락 → (penalty, detail)
        ★ ADX≥adx_exempt = 강한 돌파 → 면제(0) (BB 벽타기 철학). 하드차단 X, conviction soft 감점.
        DayBox 천장차단의 사각지대(추세 급등=박스 미lock) 보완. Returns (penalty, detail).
        """
        cfg = self.config
        if not getattr(cfg, "overextension_enabled", True):
            return (0.0, "")
        penalty = float(getattr(cfg, "overextension_penalty", 10.0))
        if penalty <= 0:
            return (0.0, "")
        d = (direction or "").upper()
        if d not in ("LONG", "SHORT"):
            return (0.0, "")
        try:
            t = self._get_24h_ticker(market)   # ★ [2026-06-13] 캐시 공유 (blowoff 와 중복 fetch 제거)
            if not t:
                return (0.0, "")
            last = float(t.get("lastPrice", 0) or 0)
            hi = float(t.get("highPrice24h", 0) or 0)
            lo = float(t.get("lowPrice24h", 0) or 0)
            move = abs(float(t.get("price24hPcnt", 0) or 0)) * 100.0   # 0.1567 → 15.67%
            rng = hi - lo
            if last <= 0 or rng <= 0:
                return (0.0, "")
            pos = (last - lo) / rng   # 0=24H 저점, 1=24H 고점
            min_move = float(getattr(cfg, "overextension_min_move_pct", 8.0))
            if move < min_move:
                return (0.0, "")   # 변동 작으면 끝물 아님
            top = float(getattr(cfg, "overextension_range_pos_pct", 0.85))
            extended = (d == "LONG" and pos >= top) or (d == "SHORT" and pos <= (1.0 - top))
            if not extended:
                return (0.0, "")
            # ★ 강한 돌파 면제 (ADX 높으면 '벽 타고 흐름' 가능 → 끝물로 안 봄)
            adx_exempt = float(getattr(cfg, "overextension_adx_exempt", 30.0))
            if adx_exempt > 0:
                try:
                    _ar = self._fetch_primary_adx(market)
                    _adx = float(_ar.get("adx", 0.0)) if isinstance(_ar, dict) else 0.0
                    if _adx >= adx_exempt:
                        return (0.0, f"exempt:ADX{_adx:.0f}≥{adx_exempt:.0f}")
                except Exception:
                    pass
            return (penalty, f"{d} pos{pos*100:.0f}% move{move:.1f}%")
        except Exception as exc:
            logger.debug("[FOCUS] _check_overextension error %s: %s", market, exc)
            return (0.0, "")

    def _compute_inflection_setup(self, market: str, direction: str) -> tuple:
        """🎯 변곡 setup 점수 (2026-06-12 부모) — "점수가 캔들의 위치×모멘텀을 인코딩".
        봇은 캔들 안 봄, 점수만 봄. 이 항목이 빠진 값(이동폭 내 위치 + 모멘텀 방향)을 채워
        천장 stall(롱 늦음/숏 좋음)·바닥 변곡(롱 좋음)·벽타기(모멘텀 살아있으면 면제)를 구분.

        guard_eval 시뮬과 *동일 수식* (verbatim):
          pos = 24h(5m 288봉) 범위 내 위치 0~1
          slope15m = 최근 3봉(15분) % 변화
          up = clamp(0.75·tanh(slope15m/scale) + 0.25·sign(MACD히스토Δ), -1, 1)
          at_high = max(0, pos-0.5)·2  /  at_low = max(0, 0.5-pos)·2
          LONG  = clamp(W·(at_high·(up-base) + at_low·(base+up)), ±cap)
          SHORT = clamp(W·(at_high·(base-up) + at_low·(-base-up)), ±cap)   # 거울
        Returns (modifier, detail). default OFF. 트리거(microtiming)는 점수 밖 = 별개.
        """
        import math
        cfg = self.config
        if not getattr(cfg, "inflection_setup_enabled", False):
            return (0.0, "")
        d = (direction or "").upper()
        if d not in ("LONG", "SHORT"):
            return (0.0, "")
        try:
            raw = self._get_mtf_kline(market, "5", limit=288, ttl=30.0)
            if not raw or len(raw) < 35:
                return (0.0, "")
            cl = [float(r[4]) for r in raw]
            his = [float(r[2]) for r in raw]
            los = [float(r[3]) for r in raw]
            hi = max(his); lo = min(los); last = cl[-1]
            if hi <= lo or last <= 0:
                return (0.0, "")
            pos = (last - lo) / (hi - lo)
            slope15m = (cl[-1] - cl[-4]) / cl[-4] * 100.0 if cl[-4] != 0 else 0.0
            # MACD 히스토그램 Δ (시뮬과 동일: EMA12/26, signal9)
            def _ema(vals, n):
                k = 2.0 / (n + 1); e = vals[0]; out = [e]
                for v in vals[1:]:
                    e = v * k + e * (1 - k); out.append(e)
                return out
            e12 = _ema(cl, 12); e26 = _ema(cl, 26)
            macd_line = [a - b for a, b in zip(e12, e26)]
            sig = _ema(macd_line, 9)
            histl = [a - b for a, b in zip(macd_line, sig)]
            hist_d = histl[-1] - histl[-2] if len(histl) >= 2 else 0.0
            sscale = float(getattr(cfg, "inflection_setup_slope_scale", 0.40)) or 0.40
            lean = 0.25 * (1 if hist_d > 0 else (-1 if hist_d < 0 else 0))
            up = max(-1.0, min(1.0, 0.75 * math.tanh(slope15m / sscale) + lean))
            at_high = max(0.0, pos - 0.5) * 2.0     # 0(중간)~1(천장)
            at_low = max(0.0, 0.5 - pos) * 2.0      # 0(중간)~1(바닥)
            base = float(getattr(cfg, "inflection_setup_base", 0.45))
            W = float(getattr(cfg, "inflection_setup_weight", 20.0))
            cap = float(getattr(cfg, "inflection_setup_cap", 20.0))
            if d == "LONG":
                val = W * (at_high * (up - base) + at_low * (base + up))
            else:
                val = W * (at_high * (base - up) + at_low * (-base - up))
            val = max(-cap, min(cap, val))
            zone = "천장" if pos >= 0.65 else ("바닥" if pos <= 0.35 else "중간")
            detail = f"pos{pos*100:.0f}%/{zone} up{up:+.2f} sl{slope15m:+.2f}%"
            return (val, detail)
        except Exception as exc:
            logger.debug("[FOCUS] _compute_inflection_setup error %s: %s", market, exc)
            return (0.0, "")

    def _compute_retest_setup(self, market: str, direction: str) -> tuple:
        """🎣 Retest setup 점수 (2026-06-12 부모/동생) — "돌파→눌림→지지=좋은 진입 자리".
        변곡 축(끝물 거르기)의 짝 = 좋은 진입 잡기. 부모님 "눌림 받고 다시 가는 자리".

        guard_eval 시뮬과 *동일 수식* (verbatim): 5m 60봉, 피벗(±width).
          LONG : 직전 swing high 돌파 → 돌파후 고점에서 되돌림(retr) → 돌파레벨 위 유지 + turning up
          SHORT: 거울 (swing low 깸 → 되돌림 위로 → 돌파레벨 아래 유지 + turning down)
          retr = (돌파후극값 - 현재가)/(돌파후극값 - 레벨)   # 0=극값, 1=레벨 복귀
          품질 q = max(0, 1 - |retr-0.6|/0.5),  score = W·q + turn_bonus(turning 시)
          retr<lo=천장추격(0) / retr>hi+0.3=too-deep(0) / 레벨 이탈=실패(0)
        Returns (bonus>=0, detail). default OFF. 가점 위주(좋은 자리 부각).
        """
        cfg = self.config
        if not getattr(cfg, "retest_setup_enabled", False):
            return (0.0, "")
        d = (direction or "").upper()
        if d not in ("LONG", "SHORT"):
            return (0.0, "")
        try:
            raw = self._get_mtf_kline(market, "5", limit=60, ttl=30.0)
            if not raw or len(raw) < 20:
                return (0.0, "")
            hi = [float(r[2]) for r in raw]
            lo = [float(r[3]) for r in raw]
            cl = [float(r[4]) for r in raw]
            op = [float(r[1]) for r in raw]
            n = len(cl); price = cl[-1]
            W = int(getattr(cfg, "retest_pivot_width", 2))
            BRK = 0.001
            RETR_LO = float(getattr(cfg, "retest_retr_lo", 0.30))
            RETR_HI = float(getattr(cfg, "retest_retr_hi", 0.90))
            FAIL = float(getattr(cfg, "retest_fail_pct", 0.005))
            W_RET = float(getattr(cfg, "retest_setup_weight", 12.0))
            TURN = float(getattr(cfg, "retest_setup_turn_bonus", 4.0))
            up = cl[-1] > op[-1] or (len(cl) >= 2 and cl[-1] > cl[-2])
            dn = cl[-1] < op[-1] or (len(cl) >= 2 and cl[-1] < cl[-2])

            def _pivots(vals, ishigh):
                out = []
                for i in range(W, len(vals) - W):
                    seg = vals[i - W:i + W + 1]
                    if ishigh and vals[i] == max(seg):
                        out.append((i, vals[i]))
                    if (not ishigh) and vals[i] == min(seg):
                        out.append((i, vals[i]))
                return out

            if d == "LONG":
                broken = None
                for idx, res in _pivots(hi, True):
                    if any(hi[j] > res * (1 + BRK) for j in range(idx + 1, n)):
                        broken = (idx, res)
                if not broken:
                    return (0.0, "")
                ridx, res = broken
                post_hi = max(hi[ridx:])
                if post_hi <= res:
                    return (0.0, "")
                retr = (post_hi - price) / (post_hi - res)
                if price < res * (1 - FAIL):
                    return (0.0, "")          # 돌파레벨 이탈 = 실패
                if retr < RETR_LO or retr > RETR_HI + 0.3:
                    return (0.0, "")          # 천장추격 / too-deep
                q = max(0.0, 1 - abs(retr - 0.6) / 0.5)
                sc = W_RET * q + (TURN if up else 0.0)
                detail = f"retr{retr*100:.0f}%{'↑' if up else ''}"
            else:
                broken = None
                for idx, sup in _pivots(lo, False):
                    if any(lo[j] < sup * (1 - BRK) for j in range(idx + 1, n)):
                        broken = (idx, sup)
                if not broken:
                    return (0.0, "")
                sidx, sup = broken
                post_lo = min(lo[sidx:])
                if post_lo >= sup:
                    return (0.0, "")
                retr = (price - post_lo) / (sup - post_lo)
                if price > sup * (1 + FAIL):
                    return (0.0, "")
                if retr < RETR_LO or retr > RETR_HI + 0.3:
                    return (0.0, "")
                q = max(0.0, 1 - abs(retr - 0.6) / 0.5)
                sc = W_RET * q + (TURN if dn else 0.0)
                detail = f"retr{retr*100:.0f}%{'↓' if dn else ''}"
            if sc <= 0.0:
                return (0.0, "")
            return (sc, detail)
        except Exception as exc:
            logger.debug("[FOCUS] _compute_retest_setup error %s: %s", market, exc)
            return (0.0, "")

    def _compute_headroom_penalty(self, market: str, direction: str,
                                  candles_primary: Optional[list] = None,
                                  zones_tuple: Optional[Tuple[float, float]] = None) -> Tuple[float, str]:
        """[2026-06-09 부모] 이윤 여력 페널티 — '방향 맞아도 갈 곳 없으면 감점'.
        부모님 통찰: 점수표가 후행 정렬엔 48점 주면서 '어디까지 갈지'는 페널티 없는 보너스뿐 → 고점수=끝물.
        여기서 여력 없는 자리를 음수로 깎아 끝물 진입 거름. 기존 점수함수 무수정 — 격리 추가.
          ① S/R: LONG 저항 코앞 / SHORT 지지 코앞 → -sr_penalty
          ② RSI: LONG 과매수(≥ob) / SHORT 과매도(≤os) → -rsi_penalty
          ③ BB %b: LONG 밴드 상단(≥hi) / SHORT 밴드 하단(≤lo) → -bb_penalty
        Returns (penalty<=0.0, detail). default OFF.
        """
        cfg = self.config
        if not getattr(cfg, "headroom_penalty_enabled", False):
            return (0.0, "")
        d = (direction or "").upper()
        if d not in ("LONG", "SHORT"):
            return (0.0, "")
        if not candles_primary or len(candles_primary) < 20:
            return (0.0, "")
        try:
            _last = candles_primary[-1]
            if hasattr(_last, "close"):
                price = float(_last.close)
            elif isinstance(_last, (list, tuple)) and len(_last) >= 4:
                price = float(_last[3])
            else:
                return (0.0, "")
            if price <= 0:
                return (0.0, "")
            closes = []
            for c in candles_primary:
                if hasattr(c, "close"):
                    closes.append(float(c.close))
                elif isinstance(c, (list, tuple)) and len(c) >= 4:
                    closes.append(float(c[3]))
            pen = 0.0
            parts = []

            # ① S/R 여력 — 저항/지지 코앞 진입 = 갈 곳 없음
            sr_pen = float(getattr(cfg, "headroom_sr_penalty", 6.0))
            if sr_pen > 0:
                z = zones_tuple if zones_tuple else self._zones_for_pa()
                if z and z[0] > 0 and z[1] > 0:
                    sup, res = z
                    near = float(getattr(cfg, "headroom_sr_near_pct", 1.5))
                    d_res = abs(res - price) / price * 100
                    d_sup = abs(price - sup) / price * 100
                    if d == "LONG" and d_res <= near:
                        pen -= sr_pen
                        parts.append(f"R코앞{d_res:.1f}%-{sr_pen:.0f}")
                    elif d == "SHORT" and d_sup <= near:
                        pen -= sr_pen
                        parts.append(f"S코앞{d_sup:.1f}%-{sr_pen:.0f}")

            # ② RSI 극단 여력 — 과매수 LONG / 과매도 SHORT
            rsi_pen = float(getattr(cfg, "headroom_rsi_penalty", 6.0))
            if rsi_pen > 0 and len(closes) >= 15:
                try:
                    from app.strategy.indicators import rsi as _rsi_fn
                    rv = _rsi_fn(closes, length=14)
                    if rv is not None:
                        ob = float(getattr(cfg, "headroom_rsi_overbought", 70.0))
                        os_ = float(getattr(cfg, "headroom_rsi_oversold", 30.0))
                        if d == "LONG" and rv >= ob:
                            pen -= rsi_pen
                            parts.append(f"RSI{rv:.0f}≥{ob:.0f}-{rsi_pen:.0f}")
                        elif d == "SHORT" and rv <= os_:
                            pen -= rsi_pen
                            parts.append(f"RSI{rv:.0f}≤{os_:.0f}-{rsi_pen:.0f}")
                except Exception:
                    pass

            # ③ BB %b 위치 — LONG 밴드 상단 / SHORT 밴드 하단 = 여력 없음
            bb_pen = float(getattr(cfg, "headroom_bb_penalty", 4.0))
            if bb_pen > 0 and len(closes) >= 20:
                try:
                    from app.strategy.indicators import bollinger_bands as _bb_fn
                    bb = _bb_fn(closes, 20, 2.0)
                    if bb and bb.get("upper") and bb.get("lower"):
                        up_b, lo_b = float(bb["upper"]), float(bb["lower"])
                        if up_b > lo_b:
                            pctb = (price - lo_b) / (up_b - lo_b)
                            hi = float(getattr(cfg, "headroom_bb_hi_pctb", 0.80))
                            lo = float(getattr(cfg, "headroom_bb_lo_pctb", 0.20))
                            if d == "LONG" and pctb >= hi:
                                pen -= bb_pen
                                parts.append(f"BB상단{pctb:.2f}-{bb_pen:.0f}")
                            elif d == "SHORT" and pctb <= lo:
                                pen -= bb_pen
                                parts.append(f"BB하단{pctb:.2f}-{bb_pen:.0f}")
                except Exception:
                    pass

            if pen < 0:
                return (pen, " ".join(parts))
            return (0.0, "여력OK")
        except Exception as exc:
            logger.debug("[FOCUS] _compute_headroom_penalty error %s: %s", market, exc)
            return (0.0, "")

    def _macro_short_timing(self, market: str) -> Tuple[float, str]:
        """[2026-06-11 부모] 거시하락 능동 SHORT 진입 2단계 (focus_manager:8087 [2단계] 구현).

        1단계(breadth 방향게이트:8088)는 SHORT 순행에 가점만 줘서 *반응형*(좋은 자리 기다림).
        여기선 거시 RISK_OFF + 개별 코인 5m '반등(데드캣) 후 꺾임' 상태를 *능동 신호*로 보고
        SHORT conviction 에 +delta → guard_score(65) 게이트를 넘겨 능동 진입을 실현.

        ★ 끝물 추격 방지: '반등이 *있었고*(전제) 그게 *꺾였다*'. 쭉 하락만(반등無)이면 0.
        조건:
          1. macro_short_timing_enabled ON (default False)
          2. 거시 RISK_OFF (_macro_compass)
          3. 5m 저점 후 bounce_pct% 이상 반등 존재 (없으면 끝물 → 0)
          4. 꺾임 3신호(마지막봉 음전환 / MACD hist<0 / PA bearish) 중 min_signals 이상
        SHORT 전용(호출부 gate) — LONG 은 1단계 -25 차단 보존. Returns (delta>=0, label).
        """
        cfg = self.config
        if not getattr(cfg, "macro_short_timing_enabled", False):
            return (0.0, "")
        delta = float(getattr(cfg, "macro_short_timing_delta", 12.0))
        if delta <= 0:
            return (0.0, "")
        # 1) 거시 RISK_OFF (대표10 BEAR STRONG/MID) — 완성품 재사용
        try:
            if self._macro_compass().get("state") != "RISK_OFF":
                return (0.0, "not_riskoff")
        except Exception:
            return (0.0, "")
        try:
            lookback = max(6, int(getattr(cfg, "macro_short_timing_lookback", 12)))
            raw = self._get_client().get_kline(market, interval="5", limit=max(lookback + 6, 24))
            if not raw or len(raw) < 8:
                return (0.0, "5m_no_data")
            ordered = [r for r in raw if len(r) >= 5]  # oldest first
            if len(ordered) >= 7:
                ordered = ordered[:-1]  # forming(진행중) 봉 제외 — 마감봉만
            if len(ordered) < 6:
                return (0.0, "5m_few")
            opens = [float(r[1]) for r in ordered]
            highs = [float(r[2]) for r in ordered]
            lows  = [float(r[3]) for r in ordered]
            closes = [float(r[4]) for r in ordered]
            # 3) 반등 존재 전제 — 윈도우 내 '저점 이후 고점' 반등이 bounce_pct% 이상이었나
            wl, wh = lows[-lookback:], highs[-lookback:]
            recent_low = min(wl)
            if recent_low <= 0:
                return (0.0, "5m_badlow")
            _low_idx = wl.index(recent_low)
            bounce_high = max(wh[_low_idx:]) if _low_idx < len(wh) else recent_low
            bounce = (bounce_high / recent_low - 1.0) * 100.0
            bounce_min = float(getattr(cfg, "macro_short_timing_bounce_pct", 0.3))
            if bounce < bounce_min:
                return (0.0, f"반등無({bounce:.2f}<{bounce_min})")  # 쭉 하락 = 끝물 → skip
            # 4) 꺾임 신호 (3개 중 min_signals)
            sigs, parts = 0, []
            # a. 마지막 마감봉 bearish (반등 꺾임 직접 증거)
            if closes[-1] < opens[-1]:
                sigs += 1; parts.append("음전환")
            # b. 5m MACD histogram < 0 (모멘텀 음전환)
            try:
                from app.strategy.indicators import macd_hist_pair
                _hn, _hp = macd_hist_pair(closes)
                if _hn is not None and _hn < 0:
                    sigs += 1; parts.append("MACD<0")
            except Exception:
                pass
            # c. 5m PA bearish (BOS_BEARISH/PIN_BAR/ENGULFING ...) — 부모님 PA 철학 재활용
            try:
                from app.strategy.greenpen.pa_detector import OHLCV as _O, detect_pa_patterns as _dp, Direction as _PD
                _cd = [_O(open=opens[i], high=highs[i], low=lows[i], close=closes[i]) for i in range(len(ordered))]
                for s in _dp(_cd):
                    if s.direction == _PD.SHORT and s.candle_idx >= len(_cd) - 2:
                        sigs += 1; parts.append(f"PA:{s.pattern.value}")
                        break
            except Exception:
                pass
            min_sig = int(getattr(cfg, "macro_short_timing_min_signals", 2))
            if sigs >= min_sig:
                return (delta, f"RISKOFF+5m반등꺾임({'/'.join(parts)})+{delta:.0f}")
            return (0.0, f"꺾임부족({sigs}/{min_sig})")
        except Exception as exc:
            logger.debug("[FOCUS] _macro_short_timing error %s: %s", market, exc)
            return (0.0, "")

    def _volatility_awakening_sl(self, market: str, price: float, atr: float,
                                direction: str, sl_distance: float):
        """[2026-06-11 부모] 변동성 각성 SL 적응 — 멀게 두고 추세 따라붙기.

        지지부진하던 코인이 각성(변동성 확장)하고 Day(코인 D1) 순행이면, SL 을 새 변동성에 맞춰
        *넓게* → risk-based sizing(qty=risk/sl_distance)이 size 자동 축소 = 리스크($) 고정.
        ★ 멀게는 변동성이·견딜지는 Day 정렬이·SL은 %아닌 '각성의 발'(구조점, swing low/high).

        Returns (new_sl_distance, new_sl_price_or_None, label). 변경 없으면 (sl_distance, None, 사유).
        """
        cfg = self.config
        if not getattr(cfg, "awaken_sl_enabled", False):
            return (sl_distance, None, "")
        d = (direction or "").upper()
        if d not in ("LONG", "SHORT") or price <= 0 or sl_distance <= 0:
            return (sl_distance, None, "")
        try:
            from app.strategy.greenpen.pa_detector import OHLCV as _O
            from app.manager.entry_expectation import atr_from_ohlcv as _atr_oh
            lookback = max(10, int(getattr(cfg, "awaken_atr_lookback", 20)))
            raw = self._get_mtf_kline(market, str(self.config.primary_tf), limit=lookback + 8)
            if not raw or len(raw) < 12:
                return (sl_distance, None, "few")
            candles = [_O(float(r[1]), float(r[2]), float(r[3]), float(r[4]))
                       for r in raw if len(r) >= 5]  # 시간순(oldest first)
            if len(candles) < 12:
                return (sl_distance, None, "few")
            # ── 각성 감지: 최근 ATR vs 과거 ATR (코인 자기기준) ──
            recent_atr = _atr_oh(candles[-6:])
            past_src = candles[-lookback:-4] if len(candles) >= lookback + 4 else candles[:-4]
            past_atr = _atr_oh(past_src)
            if past_atr <= 0 or recent_atr <= 0:
                return (sl_distance, None, "noatr")
            ratio = recent_atr / past_atr
            awaken_ratio = float(getattr(cfg, "awaken_atr_ratio", 1.3))
            if ratio < awaken_ratio:
                return (sl_distance, None, f"비각성({ratio:.2f}<{awaken_ratio})")
            # ── 견딤 자격: 개별 코인 D1 순행 (역행/미정 제외) ──
            if getattr(cfg, "awaken_require_day_align", True):
                from app.strategy.greenpen.market_structure import analyze_structure as _as
                d1_raw = self._get_mtf_kline(market, "D", limit=30)
                aligned = False
                if d1_raw and len(d1_raw) >= 10:
                    d1c = [_O(float(r[1]), float(r[2]), float(r[3]), float(r[4]))
                           for r in d1_raw if len(r) >= 5]
                    _st = _as(d1c)
                    _tr = _st.trend.value if hasattr(_st.trend, "value") else str(_st.trend)
                    aligned = ((_tr == "UPTREND" and d == "LONG")
                               or (_tr == "DOWNTREND" and d == "SHORT"))
                if not aligned:
                    return (sl_distance, None, "Day역행/미정→견딤자격X")
            # ── SL 거리 = mode ──
            mode = str(getattr(cfg, "awaken_sl_mode", "both")).lower()
            max_mult = float(getattr(cfg, "awaken_max_sl_mult", 2.5))
            atr_dist = sl_distance * min(ratio, max_mult)
            struct_dist = 0.0
            if mode in ("structure", "both"):
                sw = max(3, int(getattr(cfg, "awaken_swing_lookback", 10)))
                buf = float(getattr(cfg, "awaken_atr_buffer", 0.5))
                rc = candles[-sw:]
                if d == "LONG":
                    swing = min(c.low for c in rc)
                    struct_dist = (price - swing) + recent_atr * buf
                else:
                    swing = max(c.high for c in rc)
                    struct_dist = (swing - price) + recent_atr * buf
            if mode == "atr":
                new_dist = atr_dist
            elif mode == "structure":
                new_dist = struct_dist if struct_dist > 0 else atr_dist
            else:  # both — 더 먼 쪽
                new_dist = max(atr_dist, struct_dist)
            # ── 이중 cap (max_mult 배 + MAX_SL_DISTANCE_PCT) ──
            new_dist = min(new_dist, sl_distance * max_mult)
            max_pct = float(getattr(cfg, "max_sl_distance_pct", 99.0))
            new_dist = min(new_dist, price * max_pct / 100.0)
            if new_dist <= sl_distance:
                return (sl_distance, None, f"확장無({ratio:.2f})")
            new_sl = price - new_dist if d == "LONG" else price + new_dist
            lbl = (f"각성 ratio{ratio:.2f} mode={mode} "
                   f"SL {sl_distance / price * 100:.2f}%→{new_dist / price * 100:.2f}% (size 자동↓)")
            return (new_dist, new_sl, lbl)
        except Exception as exc:
            logger.debug("[FOCUS] _volatility_awakening_sl error %s: %s", market, exc)
            return (sl_distance, None, "")

    # ── [2026-05-27 부모] H1 PA Pulse ─────────────────────────
    def _h1_pa_pulse_active(self) -> bool:
        """H1 PA Pulse 활성 여부 — enabled 만 검사 (부모 2026-05-28 단순화)."""
        return bool(getattr(self.config, "h1_pa_pulse_enabled", False))

    def _h1_pa_detected(self, market: str, direction: str) -> tuple:
        """H1 PA 펄스 통과 검사.
        조건:
          ① 현재 시각 = H1 마감 후 window_min 분 안 (= minute < window_min)
          ② require_day_dir 활성 시: day_direction 가 LONG/SHORT 이면 entry direction 과 일치
             (day_direction = NEUTRAL 은 통과 — 추세 미정 시 H1 PA 허용)
          ③ 최근 lookback_bars 봉 안 detect_pa_patterns 인식
          ④ PA direction = entry direction 일치 AND confidence ≥ min_confidence
        Returns (ok: bool, info: str)."""
        if not self._h1_pa_pulse_active():
            return (False, "")
        c = self.config
        try:
            import datetime as _dt
            # ① 시간 창 (H1 마감 = 매시 정각, 마감 후 window_min 분 안)
            now = _dt.datetime.now()  # local KST 가정 (서버)
            win_m = max(1, int(getattr(c, "h1_pa_pulse_window_min", 15)))
            if now.minute >= win_m:
                return (False, "h1_pa: 창 밖 %02d:%02d (창 %dm)" % (now.hour, now.minute, win_m))
            # ② day_direction 정렬 (NEUTRAL = 통과)
            d = (direction or "").upper()
            if bool(getattr(c, "h1_pa_pulse_require_day_dir", True)):
                dd = (getattr(self, "day_direction", "NEUTRAL") or "NEUTRAL").upper()
                if dd in ("LONG", "SHORT") and dd != d:
                    return (False, "h1_pa: day_direction=%s vs %s 불일치" % (dd, d))
            # ③ H1 PA 인식
            from app.strategy.greenpen.pa_detector import (
                OHLCV as _O, detect_pa_patterns as _dp, Direction as _PD,
            )
            lb = max(1, int(getattr(c, "h1_pa_pulse_lookback_bars", 2)))
            min_conf = float(getattr(c, "h1_pa_pulse_min_confidence", 0.5))
            raw = self._get_client().get_kline(market, interval="60", limit=max(8, lb + 6))
            if not raw or len(raw) < 4:
                return (False, "h1_pa: 캔들 부족 %d" % (len(raw) if raw else 0))
            ordered = list(raw)  # oldest first
            candles = []
            for r in ordered:
                if len(r) < 5:
                    continue
                try:
                    candles.append(_O(
                        open=float(r[1]), high=float(r[2]), low=float(r[3]), close=float(r[4]),
                        volume=float(r[5]) if len(r) > 5 else 0.0,
                        ts=float(r[0]),
                    ))
                except Exception:
                    continue
            # forming H1 캔들 제외 — 마감 H1 까지만 검사 (PA 가 forming 중 사라질 위험 회피)
            # 부모님 의도 "H1 PA 생성" = 마감된 H1 PA. 교재 정신과 일치.
            if len(candles) >= 5:
                candles = candles[:-1]
            if len(candles) < 4:
                return (False, "h1_pa: 마감 캔들 부족 %d" % len(candles))
            signals = _dp(candles)
            if not signals:
                return (False, "h1_pa: 신호 없음")
            want = _PD.LONG if d == "LONG" else _PD.SHORT
            # ④ 최근 lb 봉 안 — pa_detector 는 candle_idx=len-1 (마지막=가장 최근 마감 H1) 으로 set.
            #    lb=1 이면 가장 최근 마감 H1, lb=2 면 그 직전까지 (1시간 전 H1 PA 도 인정).
            total = len(candles)
            recent_min_idx = max(0, total - lb)
            match = None
            for s in signals:
                si = int(getattr(s, "candle_idx", -1))
                pos_idx = si if si >= 0 else total + si
                if pos_idx < recent_min_idx:
                    continue
                sd = getattr(s, "direction", None)
                sc = float(getattr(s, "confidence", 0.0))
                if sd == want and sc >= min_conf:
                    match = (getattr(s, "pattern", None), sc, pos_idx)
                    break
            if not match:
                return (False, "h1_pa: %d개 중 매칭 없음 (want=%s,conf≥%.2f)" % (len(signals), d, min_conf))
            return (True, "h1_pa OK pat=%s conf=%.2f idx=%d %02d:%02d/+%dm" %
                    (str(match[0]).split(".")[-1] if match[0] else "?", match[1], match[2],
                     now.hour, now.minute, win_m))
        except Exception as exc:
            logger.debug("[FOCUS] _h1_pa_detected %s %s error: %s", market, direction, exc)
            return (False, "h1_pa: error")

    # ── Main Tick ───────────────────────────────────────────

    def tick(self, btc_price: float = 0.0) -> Dict[str, Any]:
        """Called every 5 seconds from background loop.

        Returns status dict for logging/API.
        """
        # ★ Phase H (2026-04-20 형 letter#3 A-4): daily reset 은 항상 처리 (disabled/E-STOP 상태에서도)
        # 이전: enabled/emergency_stop 가드가 reset 앞에 있어서 disabled 상태에서 daily boundary 통과 시 reset 누락
        # 수정: lock 진입 직후 reset 우선 처리 → 가드 → return
        with self._lock:
            # ★ [2026-05-15 Tick 락 분리] update_config 가 남긴 config 변경을 여기서 안전하게 파일 flush.
            #   _lock 보유 중 = self.positions/state mutate 와 race 없음. _config_lock 로 config 스냅샷 일관성 확보.
            if self._config_dirty:
                try:
                    with self._config_lock:
                        self._config_dirty = False
                        self._save_config()
                except Exception as _cfexc:
                    logger.warning("[FOCUS] config flush failed: %s", _cfexc, exc_info=True)
            try:
                self._maybe_reset_daily_counters()
            except Exception as _drexc:
                logger.warning("[FOCUS] daily reset failed: %s", _drexc, exc_info=True)
            # ── [2026-05-29 부모] Smart Manual Entry 큐 체크 (매 tick) ──
            try:
                self._check_pending_manual_entries()
            except Exception as _smeexc:
                logger.debug("[FOCUS] Smart Manual Entry queue check error: %s", _smeexc)
            # ── [2026-05-29 부모] Market Consensus Exit (탈출 지혜) ──
            try:
                self._check_market_consensus_exit()
            except Exception as _mceexc:
                logger.debug("[FOCUS] Market Consensus Exit check error: %s", _mceexc)
            # ★ [2026-05-21 부모] Day Direction (09:00 KST) + H4 PA Snapshot (4시간 KST) routine
            try:
                self._update_day_direction()
            except Exception as _ddexc:
                logger.debug("[FOCUS] day_direction tick error: %s", _ddexc)
            try:
                self._update_h4_pa_snapshot()
            except Exception as _h4exc:
                logger.debug("[FOCUS] h4_pa_snapshot tick error: %s", _h4exc)
            # ★ [2026-04-26] Winners Add 체크 (자본 추가 시 유리한 코인 증액)
            try:
                self._check_winners_add_tick()
            except Exception as _wxexc:
                logger.debug("[FOCUS] winners_add check error: %s", _wxexc)
            # ★ [패치 v2-A2] Pre-Close 마감 확인 증액 체크 (선행 반쪽 → 확인 시 나머지 반)
            try:
                self._check_preclose_topup_tick()
            except Exception as _pctexc:
                logger.debug("[FOCUS] preclose topup check error: %s", _pctexc)

            if not self.config.enabled:
                return {"state": "DISABLED"}

            # ★ Emergency Stop 체크 — 전체 시스템 비상정지 시 FOCUS도 정지
            if self.system and bool(getattr(self.system, 'emergency_stop', False)):
                return {"state": "EMERGENCY_STOP", "positions": len(self.positions)}

            now = time.time()
            self.last_tick_ts = now

            results = {}

            # 0) ADX 워밍업 — 재시작 후 첫 tick에서 즉시 fetch
            # ★ Phase H (2026-04-20 형 letter#3 A-3): debug → warning + exc_info (silent fail audit)
            if self._last_adx_value <= 0 and self.config.adx_filter_enabled:
                try:
                    mkt = self.config.lock_market.upper() if self.config.lock_market else "BTCUSDT"
                    self._fetch_primary_adx(mkt)
                    if getattr(self, "_adx_fetch_fail_count", 0) > 0:
                        logger.info("[FOCUS] ADX fetch recovered after %d failures", self._adx_fetch_fail_count)
                        self._adx_fetch_fail_count = 0
                except Exception as exc:
                    self._adx_fetch_fail_count = getattr(self, "_adx_fetch_fail_count", 0) + 1
                    logger.warning("[FOCUS] ADX fetch failed (%d consecutive): %s", self._adx_fetch_fail_count, exc, exc_info=True)
                    if self._adx_fetch_fail_count >= 3:
                        logger.error("[FOCUS] ⚠ ADX fetch %d consecutive failures — scanner ADX gate may be stale", self._adx_fetch_fail_count)

            # 0.5) ★ 운영 중 Bybit 실잔고 동기화 (60초마다) — 고스트 포지션 감지
            # ★ Phase H (2026-04-20 형 letter#3 A-2 CRITICAL): silent 실패 시 잔고 ↔ 실제 거래소 불일치 → 고스트
            if self.positions and (now - self._last_live_sync_ts >= 60):
                self._last_live_sync_ts = now
                try:
                    self._live_sync_positions()
                    if getattr(self, "_live_sync_fail_count", 0) > 0:
                        logger.info("[FOCUS] live_sync recovered after %d failures", self._live_sync_fail_count)
                        self._live_sync_fail_count = 0
                except Exception as _lse:
                    self._live_sync_fail_count = getattr(self, "_live_sync_fail_count", 0) + 1
                    logger.warning("[FOCUS] live_sync_positions failed (%d consecutive): %s", self._live_sync_fail_count, _lse, exc_info=True)
                    if self._live_sync_fail_count >= 3:
                        logger.error("[FOCUS] ⚠ live_sync %d consecutive failures — ghost position risk! Bybit balance vs local state may diverge", self._live_sync_fail_count)

            # 0.7) ★ Drawdown Shield 자동갱신 (5분마다)
            # [2026-04-18] 리팩토링: PnL 기반 → Equity 기반 (DD% 0~100 natural cap)
            if now - self._last_drawdown_update_ts >= 300:
                self._last_drawdown_update_ts = now
                try:
                    from app.manager.drawdown_shield import drawdown_shield as _ds
                    _today_pnl = self._calc_today_pnl()
                    # ★ [2026-05-16 부모] cash_only 옵션 — 미실현 변동 무시 (보유 코인 흔들림이 다른 진입 막는 문제 해결)
                    _use_cash_only = bool(getattr(self.config, "drawdown_shield_use_cash_only", True))
                    if _use_cash_only:
                        _current_equity = float(getattr(self.system, '_last_cash_usdt', 0.0) or 0.0)
                    else:
                        _current_equity = float(getattr(self.system, '_last_equity_usdt', 0.0) or 0.0)
                    if _current_equity <= 0.0:
                        logger.debug("[FOCUS] DrawdownShield skipped — equity/cash warmup")
                    else:
                        # ★ [2026-06-09 부모] config 티어 주입 (하드코딩 → 조정 가능). penalty=cumul/daily 공통.
                        try:
                            _cau_p = float(getattr(self.config, "drawdown_shield_caution_pen", -10.0))
                            _def_p = float(getattr(self.config, "drawdown_shield_defend_pen", -20.0))
                            _cri_p = float(getattr(self.config, "drawdown_shield_crisis_pen", -30.0))
                            _ds.set_tiers(
                                cumul=[
                                    (float(getattr(self.config, "drawdown_shield_crisis_pct", 20.0)), 3, "CRISIS", _cri_p),
                                    (float(getattr(self.config, "drawdown_shield_defend_pct", 10.0)), 2, "DEFEND", _def_p),
                                    (float(getattr(self.config, "drawdown_shield_caution_pct", 5.0)), 1, "CAUTION", _cau_p),
                                    (0.0, 0, "NORMAL", 0),
                                ],
                                daily=[
                                    (float(getattr(self.config, "drawdown_shield_crisis_usd", 100.0)), 3, "CRISIS", _cri_p),
                                    (float(getattr(self.config, "drawdown_shield_defend_usd", 60.0)), 2, "DEFEND", _def_p),
                                    (float(getattr(self.config, "drawdown_shield_caution_usd", 30.0)), 1, "CAUTION", _cau_p),
                                    (0.0, 0, "NORMAL", 0),
                                ],
                            )
                        except Exception as _dst_e:
                            logger.debug("[FOCUS] DrawdownShield set_tiers failed: %s", _dst_e)
                        _ds_result = _ds.update(
                            current_equity=_current_equity,
                            realized_pnl_today=_today_pnl,
                        )
                        _lvl = _ds_result.get("protection_level", 0)
                        if _lvl > 0:
                            # src가 daily면 daily_drawdown($), cumul이면 drawdown_pct(%) 표시
                            _st = _ds.get_status()
                            _src = _ds_result.get("source", "")
                            if _src == "daily":
                                _metric = f"daily_dd=${_st.get('daily_drawdown', 0.0):.1f}"
                            else:
                                _metric = f"equity_dd={_st.get('drawdown_pct', 0.0):.1f}%"
                            logger.info(
                                "[FOCUS] DrawdownShield: level=%d (%s) %s src=%s penalty=%d",
                                _lvl,
                                _ds_result.get("protection_label", ""),
                                _metric,
                                _src,
                                _ds_result.get("conviction_penalty", 0),
                            )
                    if getattr(self, "_drawdown_update_fail_count", 0) > 0:
                        logger.info("[FOCUS] DrawdownShield update recovered after %d failures", self._drawdown_update_fail_count)
                        self._drawdown_update_fail_count = 0
                except Exception as _dse:
                    # ★ Phase H (2026-04-20 형 letter#3 A-1): Phase G 와 같은 계열, silent 실패 시 daily_peak 고착 위험
                    self._drawdown_update_fail_count = getattr(self, "_drawdown_update_fail_count", 0) + 1
                    logger.warning("[FOCUS] DrawdownShield update failed (%d consecutive): %s", self._drawdown_update_fail_count, _dse, exc_info=True)
                    if self._drawdown_update_fail_count >= 3:
                        logger.error("[FOCUS] ⚠ DrawdownShield update %d consecutive failures — CRISIS phantom risk (Phase G 계열)", self._drawdown_update_fail_count)

            # 1) 기존 포지션들 관리 (TP/SL 체크)
            try:
                self._manage_all_positions(now, btc_price)
            except Exception as exc:
                logger.error("[FOCUS] position management error: %s", exc, exc_info=True)

            # 2) 상태 머신 디스패치 — v2: DORMANT/ALERT/HUNT/POSITIONED/CAUTION/COOLDOWN
            try:
                if self.state == FocusState.DORMANT:
                    results.update(self._handle_dormant(now))
                elif self.state == FocusState.ALERT:
                    results.update(self._handle_alert(now))
                elif self.state == FocusState.HUNT:
                    results.update(self._handle_hunt(now, btc_price))
                elif self.state == FocusState.COOLDOWN:
                    results.update(self._handle_cooldown(now))
                elif self.state in (FocusState.POSITIONED, FocusState.CAUTION):
                    # 포지션 관리는 위에서 _manage_all_positions이 담당
                    # 포지션이 전부 청산되면 COOLDOWN (쿨다운 우회 방지)
                    if not self.positions:
                        self.cooldown_start_ts = time.time()
                        self.state = FocusState.COOLDOWN
                        self._save_config()
                        logger.info("[FOCUS] All positions closed → COOLDOWN (%.0fs)", self.config.cooldown_sec)
                    # ★ Scanner 멀티슬롯: 빈 슬롯 있으면 Scanner 스캔 돌림
                    elif (self.config.scanner_entry
                          and len(self.positions) < self.config.max_positions
                          and self.daily_plans_used < self.config.max_daily_plans
                          and now - self.last_scan_ts >= self.config.scan_interval_sec):
                        try:
                            self.last_scan_ts = now
                            scanner_result = self._hunt_scanner_candidates(now, btc_price)
                            if scanner_result.get("scanner_entered"):
                                logger.info("[FOCUS] Scanner entry while %s: %s",
                                            self.state.value, scanner_result.get("scanner_entered"))
                        except Exception as exc:
                            logger.debug("[FOCUS] Scanner in POSITIONED/CAUTION error: %s", exc)
            except Exception as exc:
                logger.warning("[FOCUS] state handler error: %s", exc)

            # 3) HUNT 상태에서는 _handle_hunt()이 스캔 + 진입 담당
            # POSITIONED/CAUTION에서는 위 Scanner 멀티슬롯이 담당

            # ★ 상태 표시 보정: 포지션 있으면 POSITIONED
            if self.positions and self.state == FocusState.DORMANT:
                self.state = FocusState.POSITIONED
            elif not self.positions and self.state in (FocusState.POSITIONED, FocusState.CAUTION):
                self.state = FocusState.DORMANT

            results["state"] = self.state.value
            results["positions"] = len(self.positions)
            return results

    # ── Multi-Position Management ──────────────────────────

    def _manage_all_positions(self, now: float, btc_price: float):
        """모든 오픈 포지션의 TP/SL 관리."""
        # Legacy single position → positions 리스트에 합치기
        if self.position and self.position.market and self.position not in self.positions:
            self.positions.append(self.position)
            self.position = None

        closed = []
        for pos in self.positions:
            try:
                price = self._get_current_price(pos.market)
                if not price or price <= 0:
                    continue

                # ★ [2026-05-28 부모] guard_score 100점 체계로 진입한 포지션은 옛 EXIT 가드 모두 우회.
                # 안전망(SL/TP/BE/multi_be_lock/Hard ROE/Trailing/SL Decay)과 새 가드(charge_exit/
                # tight_trail_after_be/5M 긴급 탈출/expectation_progress)만 작동. 부모님 의도:
                # "어제 오늘 새 조건 진입 시 옛 EXIT 가 끼어들면 안 된다."
                # ★★★ [2026-05-28 저녁 부모] 마스터 토글 통합:
                #   exit_guard_set != "yellow" and != "both" → 옛 EXIT 모두 우회 (yellow 비활성)
                #   exit_guard_set == "minimal" → 모든 가드 우회 (안전망 SL/HardROE 만)
                _yellow_exit_active = self._is_yellow_guard_active(axis="exit")
                _skip_old_exit = (not _yellow_exit_active) or bool(getattr(pos, "guard_score_entry", False))

                # ★★★ Hard ROE Cap (config 화 2026-04-25 Long Hold System) ★★★
                # 부모님 발견: 하드코딩 -10% 가 SL 까지 견디는 Long Hold 의도와 충돌
                # config 로 조정: hard_roe_cap_enabled (default False) / hard_roe_cap_roe_pct
                if getattr(self.config, "hard_roe_cap_enabled", False):
                    _roe_pnl_pct = ((price / pos.entry_price) - 1) * 100 if pos.entry_price > 0 else 0
                    if pos.direction == "SHORT":
                        _roe_pnl_pct = -_roe_pnl_pct
                    _roe_pct = _roe_pnl_pct * pos.leverage   # pos.leverage 사용 (Leverage Tier 반영)
                    _roe_cap = float(getattr(self.config, "hard_roe_cap_roe_pct", -50.0))
                    if _roe_pct <= _roe_cap:
                        logger.warning(
                            "[FOCUS] ★ HARD ROE CAP: %s %s ROE %.1f%% (<= %.1f%%) pnl=%.2f%% lev=%dx — FORCE CLOSE",
                            pos.market, pos.direction, _roe_pct, _roe_cap, _roe_pnl_pct, pos.leverage,
                        )
                        if self._close_position(pos, f"hard_roe_cap:ROE={_roe_pct:.1f}%_pnl={_roe_pnl_pct:.2f}%", is_sl=True):
                            closed.append(pos)
                        continue

                # ★★★ Override Slot Hard ROE Cut (★ 2026-05-10 부모님 결정) ★★★
                # 확장 슬롯 (is_override) 만 발동 — 배신 시 작은 손실로 끝.
                # "묶인 슬롯 = 정수 견딤" / "확장 슬롯 = 단기 확신 베팅, 빠른 컷" 두 시스템 공존.
                if getattr(pos, "is_override", False) and getattr(self.config, "override_slot_enabled", False):
                    _o_roe_pnl_pct = ((price / pos.entry_price) - 1) * 100 if pos.entry_price > 0 else 0
                    if pos.direction == "SHORT":
                        _o_roe_pnl_pct = -_o_roe_pnl_pct
                    _o_roe_pct = _o_roe_pnl_pct * pos.leverage
                    _o_cut = float(getattr(self.config, "override_hard_roe_cut_pct", -10.0))
                    if _o_roe_pct <= _o_cut:
                        logger.warning(
                            "[FOCUS] ★ OVERRIDE Hard ROE Cut: %s %s ROE %.1f%% (<= %.1f%%) pnl=%.2f%% lev=%dx — FORCE CLOSE",
                            pos.market, pos.direction, _o_roe_pct, _o_cut, _o_roe_pnl_pct, pos.leverage,
                        )
                        if self._close_position(pos, f"override_hard_roe_cut:ROE={_o_roe_pct:.1f}%_pnl={_o_roe_pnl_pct:.2f}%", is_sl=True):
                            closed.append(pos)
                        continue

                from app.strategy.greenpen.cycle_tp import CycleTargets, should_partial_exit, should_full_exit

                # ── TP/SL 미설정 복구 (진입 시 실패했으면 여기서 재시도) ──
                if pos.tp1 > 0 and pos.sl > 0 and not getattr(pos, '_tp_sl_confirmed', False):
                    try:
                        tp = pos.tp2 if pos.partial_done else pos.tp1
                        self._get_client().set_trading_stop(pos.market, take_profit=tp, stop_loss=pos.sl)
                        pos._tp_sl_confirmed = True
                        logger.info("[FOCUS] TP/SL confirmed on Bybit: %s TP=$%.4f SL=$%.4f", pos.market, tp, pos.sl)
                    except Exception as _tpsl_err:
                        logger.debug("[FOCUS] TP/SL retry pending %s: %s", pos.market, _tpsl_err)

                # ── ★★ Naked SL 하드가드 — 서버 SL 미확정 + 가격 SL 근접/통과 → 즉시 컷 (무사통과 청산 방지) ──
                #   위 복구가 이번에도 실패해 _tp_sl_confirmed=False 면, 거래소엔 SL 이 없다 → 봇이 직접 막는다.
                if (getattr(self.config, "naked_sl_guard_enabled", True)
                        and not getattr(pos, '_tp_sl_confirmed', False)
                        and pos.sl > 0 and pos.entry_price > 0):
                    _ng_grace_sec = float(getattr(self.config, "be_lock_grace_sec", 60.0) or 0.0)
                    _ng_in_grace = (_ng_grace_sec > 0 and pos.entry_ts > 0
                                    and (time.time() - pos.entry_ts) < _ng_grace_sec)
                    from app.manager.sl_safety import naked_sl_should_cut
                    if naked_sl_should_cut(
                        pos.direction, price, pos.sl,
                        buffer_pct=float(getattr(self.config, "naked_sl_guard_buffer_pct", 0.2)),
                        in_grace=_ng_in_grace,
                    ):
                        logger.warning("[FOCUS] 🚨 NAKED SL GUARD: %s %s 서버SL 미확정 + price $%.4f vs SL $%.4f → 즉시 시장가 청산(무사통과 방지)",
                                       pos.direction, pos.market, price, pos.sl)
                        try:
                            self._notify(f"🚨 {pos.market} 서버SL 미설정 상태에서 SL 근접 — 즉시 청산(naked 보호)")
                        except Exception:
                            pass
                        if self._close_position(pos, f"naked_sl_guard:price={price:.6f}_sl={pos.sl:.6f}", is_sl=True):
                            closed.append(pos)
                        continue

                # ── Morning Shield (야간 수익 보호: 06:00 KST SL 조임) ──
                if self.config.morning_shield_enabled and not self._hold_mode_active():
                    self._apply_morning_shield(pos, price)
                    self._apply_macro_regime_exit(pos, price)

                # ── Event Shield (경제이벤트 수익 보호: 이벤트 윈도우 SL 조임) ──
                if self.config.event_shield_enabled and not self._hold_mode_active():
                    self._apply_event_shield(pos, price)

                # ── Profit Erosion Guard (수익 침식 → BE 보호) ──
                # ★ [2026-06-20] 죽은 배선 부활 — _skip_old_exit(guard_score 진입) 게이트 제거.
                #   peak 침식 BE 백스톱이 guard_score 진입에선 호출조차 안 되던 누수(저널 SERVER_SL).
                #   _check_profit_erosion 은 breakeven_locked 가드 + only-tighten 이라 green 모드서도 안전(중복/역행 무해).
                #   ※ 다른 옛 시간컷(reverse_drift/long_hold)은 _skip_old_exit 유지 — erosion 만 떼어냄.
                if self.config.erosion_guard_enabled and not pos.partial_done:
                    self._check_profit_erosion(pos, price)

                # ── Dynamic Trailing SL (exit 체크 전에 SL 갱신) ──
                if self.config.dynamic_trailing and not pos.partial_done:
                    self._apply_dynamic_trailing_sl(pos, price)

                # ── [2026-05-16 부모 비전 #5] Tight Trail After BE — BE 락 활성 + peak slippage 즉시 컷 ──
                if self._check_tight_trail_after_be(pos, price):
                    _ttab_peak = float(getattr(pos, "peak_profit_pct", 0.0) or 0.0)
                    if self._close_position(pos, f"tight_trail_after_be:peak={_ttab_peak:.2f}%"):
                        continue

                # ── Trailing TP (망치 손잡이 방어: TP를 peak 뒤로 끌어내림) ──
                if self.config.trailing_tp_enabled and not pos.partial_done and not self._hold_mode_active():
                    try:
                        self._apply_trailing_tp(pos, price)
                    except Exception as exc:
                        logger.debug("[FOCUS] trailing_tp error: %s", exc)

                # ── SL Decay (장기 보유 SL 축소: 2h→70%, 3h→50%) ──
                # ★ Trailing 후에 실행 — original_sl이 먼저 설정되어야 Decay 기준이 정확
                _hold_h = (now - pos.entry_ts) / 3600.0 if pos.entry_ts > 0 else 0
                if self.config.sl_decay_enabled and _hold_h >= 2.0:
                    self._apply_sl_decay(pos, _hold_h)

                # ── SL Dodge: 비활성화 (2026-04-10 실전 분석 결과 효과 없음)
                # SL 터지는 순간 = MTF 전원 반대 → 항상 DENIED → API 낭비만
                # 근본 해결: 진입 방향 정확도 + WhaleRadar 방향 오버라이드
                # self._apply_sl_dodge(pos, price)

                targets = CycleTargets(
                    tp1=pos.tp1, tp2=pos.tp2, sl=pos.sl,
                    rr_ratio=0, atr_used=pos.atr_used, direction=pos.direction,
                )

                # SL / TP2 체크
                exit_reason = should_full_exit(
                    price, pos.entry_price, pos.direction, targets,
                    trailing_high=pos.trailing_high,
                    trailing_low=pos.trailing_low,
                    trailing_pct=self.config.trailing_pct,
                )
                if exit_reason:
                    if self._close_position(pos, exit_reason, is_sl="SL hit" in exit_reason):
                        closed.append(pos)
                    # 실패 시 closed에 안 넣음 → 포지션 유지 → 다음 tick에서 재시도
                    continue

                # TP1 부분 청산
                partial = should_partial_exit(
                    price, pos.entry_price, pos.direction, targets,
                    partial_pct=self.config.partial_exit_pct,
                    already_partial=pos.partial_done,
                )
                if partial:
                    self._partial_close(pos, partial, price)
                    if pos.qty <= 0:
                        closed.append(pos)
                        logger.warning("[FOCUS] Position qty=0 after partial → marking closed: %s", pos.market)
                    continue

                # Trailing 업데이트
                if pos.partial_done:
                    if pos.direction == "LONG" and price > pos.trailing_high:
                        pos.trailing_high = price
                    elif pos.direction == "SHORT" and (pos.trailing_low <= 0 or price < pos.trailing_low):
                        pos.trailing_low = price

                # ── peak_profit_price 추적 (항상, dynamic_trailing과 무관) ──
                if pos.direction == "LONG":
                    if price > pos.peak_profit_price:
                        pos.peak_profit_price = price
                        pos.last_peak_update_ts = time.time()   # [BE Stall Exit 2026-04-19]
                else:  # SHORT
                    if pos.peak_profit_price <= 0 or price < pos.peak_profit_price:
                        pos.peak_profit_price = price
                        pos.last_peak_update_ts = time.time()   # [BE Stall Exit 2026-04-19]

                # ── 추세 반전 + 시간 초과 → 빠른 익절 ──
                hold_hours = (now - pos.entry_ts) / 3600.0 if pos.entry_ts > 0 else 0
                pnl_pct = ((price / pos.entry_price) - 1) * 100
                if pos.direction == "SHORT":
                    pnl_pct = -pnl_pct

                # ── ★ [2026-05-21 Phase 6 Stage 8 재재설계] 점수 회복 자동 청산 ──
                # 부모님 진짜 룰: "이윤이 나야 청산이고 BE까지 못가더라도 점수가 회복되는 기미 보이면 탈출".
                # 조건 1: pnl > min_pnl_pct (이윤 중) — 손실 중 X (인내, 기존 SL 가드)
                # 조건 2: conv 회복 (baseline + N 증가) — 봇 신호 회복 = 우리 포지션 위험 = 소액 청산
                # 기존 가드 (BE/SL/multi_be_lock) 그대로 작동. 이건 *보조 청산*.
                # ★ [2026-05-28 저녁 부모] green 마스터 토글 — yellow only 모드 시 skip
                if getattr(self.config, "charge_exit_enabled", True) and not self._hold_mode_active() and self._is_green_guard_active("exit"):
                    try:
                        _ce_min_pnl = float(getattr(self.config, "charge_exit_min_pnl_pct", 0.0))
                        # 조건 1: 이윤 중인가
                        if pnl_pct > _ce_min_pnl:
                            _ce_baseline_conv = float(getattr(pos, "entry_baseline_conv", 0.0) or 0.0)
                            _ce_conv_delta_min = float(getattr(self.config, "charge_exit_conv_delta", 5.0))
                            _ce_current_conv = float(self._last_scan_conviction.get(pos.market, 0.0) or 0.0)
                            _ce_delta_conv = _ce_current_conv - _ce_baseline_conv
                            # 조건 2: conv 회복 기미
                            if (_ce_baseline_conv > 0
                                    and _ce_delta_conv >= _ce_conv_delta_min):
                                _ce_reason = f"conv 회복 +{_ce_delta_conv:.1f} ({_ce_baseline_conv:.1f}→{_ce_current_conv:.1f}) pnl=+{pnl_pct:.2f}%"
                                logger.warning(
                                    "[FOCUS] ★ CHARGE EXIT %s %s — %s · 점수 회복 소액 청산 (부모님 룰)",
                                    pos.direction, pos.market, _ce_reason)
                                self._close_position(pos, reason=f"charge_exit:{_ce_reason}")
                                continue  # 다음 포지션
                    except Exception as exc:
                        logger.debug("[FOCUS] charge_exit check error %s: %s", pos.market, exc)

                # ── BE Stall Exit (2026-04-19, 사용자 실측) ──
                # 실측 패턴: BE → 24~96초 내 신고점 → 유지(평균 24~96s) → 반납 시작.
                # 피크 갱신 후 N초 무갱신 = 유지 끝 + 반전 확정 → 선제 청산.
                # max(be_locked_ts, last_peak_update_ts) 로 BE 직후 피크 無 상황도 커버.
                #
                # ★ 수수료 가드 (2026-04-19): Bybit Taker 왕복 0.11% + 미끄러짐 여유
                #   = 현재 pnl > 0.15% OR peak > 0.3% 중 하나는 만족해야 안전.
                #   안 그러면 "수익 조금 있음 → 청산 → 수수료가 다 먹음" 발생.
                if (not _skip_old_exit
                        and self.config.be_stall_exit_enabled
                        and not self._hold_mode_active()
                        and pos.breakeven_locked
                        and pos.be_locked_ts > 0):
                    _ref_ts = max(pos.be_locked_ts, pos.last_peak_update_ts)
                    _stall_sec = now - _ref_ts
                    if _stall_sec >= self.config.be_stall_exit_sec:
                        _peak_pct_be = 0.0
                        if pos.peak_profit_price > 0 and pos.entry_price > 0:
                            if pos.direction == "LONG":
                                _peak_pct_be = (pos.peak_profit_price / pos.entry_price - 1) * 100
                            else:
                                _peak_pct_be = (1 - pos.peak_profit_price / pos.entry_price) * 100
                        # 수수료 가드: 현재 pnl 0.15% 이상 OR 피크 0.3% 이상
                        _FEE_MIN_PNL = 0.15     # 왕복 수수료 0.11% + 여유
                        _FEE_MIN_PEAK = 0.30    # 방어할 만한 피크 최소
                        if pnl_pct < _FEE_MIN_PNL and _peak_pct_be < _FEE_MIN_PEAK:
                            logger.debug(
                                "[FOCUS] BE Stall Exit SKIP (fee guard): %s %s stall=%.0fs peak=+%.2f%% pnl=+%.2f%% — 수수료로 먹힐 위험",
                                pos.direction, pos.market, _stall_sec, _peak_pct_be, pnl_pct,
                            )
                        else:
                            # ── ★ BE Stall Intelligent (2026-05-15 부모): 모멘텀(MACD/RSI/BB) 연동 ──
                            # 우리편 강함 → stall 무시(보유), 반대편 강함 → 시간 무시 즉시 청산, 중립 → 기존 30s 폴백
                            _intel_decision = "fallback"  # "hold" | "exit_now" | "fallback"
                            _intel_reason = ""
                            if getattr(self.config, "be_stall_intelligent_enabled", False):
                                try:
                                    raw5 = self._get_client().get_kline(pos.market, interval="5", limit=40)
                                    _closes5 = [float(r[4]) for r in raw5 if len(r) >= 5]
                                    if len(_closes5) >= 26:
                                        from app.strategy.indicators import rsi as _rsi_fn, macd_hist_pair, bollinger_bands as _bb_fn
                                        _rsi_v = _rsi_fn(_closes5, length=14)
                                        _hist_now, _hist_prev = macd_hist_pair(_closes5)
                                        _bb_v = _bb_fn(_closes5, 20, 2.0)
                                        _bb_mid = (_bb_v or {}).get("mid", 0.0)
                                        _px = _closes5[-1] if _closes5 else 0.0
                                        _rsi_strong = float(getattr(self.config, "be_stall_intelligent_rsi_strong", 55.0))
                                        _rsi_weak = float(getattr(self.config, "be_stall_intelligent_rsi_weak", 45.0))
                                        if pos.direction == "LONG":
                                            _macd_for_us = (_hist_now is not None and _hist_now > 0 and _hist_now >= _hist_prev)
                                            _macd_against = (_hist_now is not None and _hist_now < 0)
                                            _rsi_for_us = (_rsi_v is not None and _rsi_v >= _rsi_strong)
                                            _rsi_against = (_rsi_v is not None and _rsi_v <= _rsi_weak)
                                            _bb_for_us = (_bb_mid > 0 and _px >= _bb_mid)
                                            _bb_against = (_bb_mid > 0 and _px < _bb_mid)
                                        else:  # SHORT
                                            _macd_for_us = (_hist_now is not None and _hist_now < 0 and _hist_now <= _hist_prev)
                                            _macd_against = (_hist_now is not None and _hist_now > 0)
                                            _rsi_for_us = (_rsi_v is not None and _rsi_v <= _rsi_weak)
                                            _rsi_against = (_rsi_v is not None and _rsi_v >= _rsi_strong)
                                            _bb_for_us = (_bb_mid > 0 and _px <= _bb_mid)
                                            _bb_against = (_bb_mid > 0 and _px > _bb_mid)
                                        _for_score = int(_macd_for_us) + int(_rsi_for_us) + int(_bb_for_us)
                                        _against_score = int(_macd_against) + int(_rsi_against) + int(_bb_against)
                                        if _against_score >= 2 and _for_score == 0:
                                            _intel_decision = "exit_now"
                                            _intel_reason = f"momentum_flip(macd={_hist_now:.3f},rsi={_rsi_v:.0f},bb={'below' if _bb_against else 'above'})"
                                        elif _for_score >= 2 and _against_score == 0:
                                            _intel_decision = "hold"
                                            _intel_reason = f"momentum_for_us(macd={_hist_now:.3f},rsi={_rsi_v:.0f})"
                                        else:
                                            _intel_decision = "fallback"
                                            _intel_reason = f"neutral(for={_for_score},against={_against_score})"
                                except Exception as _intel_exc:
                                    logger.debug("[FOCUS] BE Stall Intelligent calc failed (fallback to time): %s", _intel_exc)
                                    _intel_decision = "fallback"

                            if _intel_decision == "hold":
                                logger.info(
                                    "[FOCUS] BE Stall Intelligent HOLD: %s %s stall=%.0fs peak=+%.2f%% pnl=+%.2f%% — %s",
                                    pos.direction, pos.market, _stall_sec, _peak_pct_be, pnl_pct, _intel_reason,
                                )
                                # stall 타이머 리셋 (한 번 hold 판정 후 다음 tick 재평가)
                                pos.last_peak_update_ts = now
                                # 청산 안 함 — 다음 단계로 진행
                            else:
                                if _intel_decision == "exit_now":
                                    logger.info(
                                        "[FOCUS] ★ BE Stall Intelligent EXIT: %s %s stall=%.0fs peak=+%.2f%% pnl=+%.2f%% — %s",
                                        pos.direction, pos.market, _stall_sec, _peak_pct_be, pnl_pct, _intel_reason,
                                    )
                                    reason = f"be_stall_intel_{int(_stall_sec)}s_peak+{_peak_pct_be:.2f}%_{_intel_reason}"
                                else:
                                    logger.info(
                                        "[FOCUS] ★ BE Stall Exit: %s %s stall=%.0fs peak=+%.2f%% pnl=+%.2f%% — 피크 반납 방어",
                                        pos.direction, pos.market, _stall_sec, _peak_pct_be, pnl_pct,
                                    )
                                    reason = f"be_stall_{int(_stall_sec)}s_peak+{_peak_pct_be:.2f}%"
                                if self._close_position(pos, reason=reason):
                                    closed.append(pos)
                                continue

                # ── ★★★ [2026-05-18 부모 비전 #6] Grace Period 중 Force Exit 통합 체크 ──
                # A/B 확률 게임: 그레이스 기간 동안 옆 서버 + 뉴스 = A 패턴 신호 2종 통합 체크
                # 둘 중 하나만 반대 신호여도 force exit (안전 우선)
                # 그레이스 기간 끝나면 기존 가드 (pre_be_stall + reverse_drift) 정상 작동
                if self._in_entry_grace_period(pos, now):
                    _gf, _gr = self._check_grace_force_exit(pos, now)
                    if _gf:
                        logger.info("[FOCUS] ★ Grace Force Exit (A 패턴 감지): %s %s — %s",
                                    pos.direction, pos.market, _gr)
                        if self._close_position(pos, reason=_gr):
                            closed.append(pos)
                        continue

                # ── ★ Pre-BE Stall Exit (2026-04-23 부모 직접 요청) ──
                # BE 락 가기 전, 작은 수익 + 정체 시 청산. AUTO 모드는 진입 코인 ATR 기준.
                # BE Stall Exit (BE 후) 의 동생 — BE 전 단계 보호.
                _pre_mode = (getattr(self.config, "pre_be_stall_exit_mode", "AUTO") or "AUTO").upper()
                if not _skip_old_exit and _pre_mode != "OFF" and not pos.breakeven_locked and not self._in_entry_grace_period(pos, now):
                    _pre_min_profit = float(getattr(self.config, "pre_be_stall_min_profit_pct", 0.10))
                    _pre_stall_sec = float(getattr(self.config, "pre_be_stall_sec", 60.0))
                    _pre_vol_thr = float(getattr(self.config, "pre_be_stall_volatility_threshold_pct", 2.0))
                    # peak 수익 계산
                    _peak_pct_pre = 0.0
                    if pos.peak_profit_price > 0 and pos.entry_price > 0:
                        if pos.direction == "LONG":
                            _peak_pct_pre = (pos.peak_profit_price / pos.entry_price - 1) * 100
                        else:
                            _peak_pct_pre = (1 - pos.peak_profit_price / pos.entry_price) * 100
                    if _peak_pct_pre >= _pre_min_profit and pos.last_peak_update_ts > 0:
                        _pre_stall = now - pos.last_peak_update_ts
                        # [2026-05-16] stale peak 보호 — 30분 넘은 peak는 미발동 (reverse_drift 사고 패턴 동일)
                        _pre_max_stall = float(getattr(self.config, "pre_be_stall_max_since_peak_sec", 1800.0))
                        if _pre_stall >= _pre_stall_sec and _pre_stall <= _pre_max_stall:
                            # AUTO 모드: 진입 코인 ATR% 기준 횡보 판정
                            _coin_atr_pct = (pos.atr_used / pos.entry_price * 100) if pos.entry_price > 0 else 0.0
                            _is_sideways = _coin_atr_pct < _pre_vol_thr
                            _should_fire = (_pre_mode == "ON") or (_pre_mode == "AUTO" and _is_sideways)
                            if _should_fire:
                                # ★★★ [2026-05-18 부모 비전 #6 B 옵션] 시간 무관 OR 조건
                                _pre_consensus = self._check_exit_consensus(pos, now)
                                if _pre_consensus == "hold":
                                    logger.info(
                                        "[FOCUS] ▶ Pre-BE Stall HOLD (consensus=hold, B 패턴): %s %s peak=+%.2f%% — 옆친구+뉴스 같은 방향 → 견디기",
                                        pos.direction, pos.market, _peak_pct_pre,
                                    )
                                    # 컷 안 함
                                else:
                                    _consensus_tag = f"_{_pre_consensus}" if _pre_consensus != "neutral" else ""
                                    logger.info(
                                        "[FOCUS] ★ Pre-BE Stall Exit: %s %s peak=+%.2f%% stall=%.0fs atr=%.2f%% mode=%s%s — 작은 수익 확정",
                                        pos.direction, pos.market, _peak_pct_pre, _pre_stall, _coin_atr_pct, _pre_mode, _consensus_tag,
                                    )
                                    reason = f"pre_be_stall_{int(_pre_stall)}s_peak+{_peak_pct_pre:.2f}%_atr{_coin_atr_pct:.1f}%{_consensus_tag}"
                                    if self._close_position(pos, reason=reason):
                                        closed.append(pos)
                                    continue
                            elif _pre_mode == "AUTO":
                                logger.debug(
                                    "[FOCUS] Pre-BE Stall AUTO skip: %s %s atr=%.2f%% >= %.2f%% (급변동, 추세 따라감)",
                                    pos.direction, pos.market, _coin_atr_pct, _pre_vol_thr,
                                )

                # ── ★ Reverse Drift Exit (2026-05-16 부모 직접 요청) ──
                # pre_be_stall 약점 보완: AUTO 가 ATR 높을 때 미발동 → 추세가 우리 반대로 흐르면 손실.
                # 차별점: pre_be_stall = "정체 (peak update 안 됨)" / reverse_drift = "역행 (peak에서 멀어짐)"
                # ATR 높아도 그 흐름이 entry 쪽으로 가면 컷.
                # BTC SHORT peak 0.19→-0.09 / SOL SHORT peak 0.28→-0.23 같은 케이스 보호.
                if not _skip_old_exit and getattr(self.config, "reverse_drift_exit_enabled", False) and not pos.breakeven_locked and not self._in_entry_grace_period(pos, now) and not self._hold_mode_active():
                    _rd_peak_min = float(getattr(self.config, "reverse_drift_peak_min_pct", 0.05))
                    _rd_peak_max = float(getattr(self.config, "reverse_drift_peak_max_pct", 0.35))
                    _rd_min_since_peak = float(getattr(self.config, "reverse_drift_min_since_peak_sec", 180.0))
                    _rd_max_since_peak = float(getattr(self.config, "reverse_drift_max_since_peak_sec", 1800.0))
                    _rd_base = float(getattr(self.config, "reverse_drift_pct", 0.10))
                    # peak% 계산 (direction 고려)
                    _rd_peak_pct = 0.0
                    if pos.peak_profit_price > 0 and pos.entry_price > 0:
                        if pos.direction == "LONG":
                            _rd_peak_pct = (pos.peak_profit_price / pos.entry_price - 1) * 100
                        else:
                            _rd_peak_pct = (1 - pos.peak_profit_price / pos.entry_price) * 100
                    # 영역 + 시간 조건 (stale peak 보호: min ≤ stall ≤ max)
                    _rd_stall_sec = (now - pos.last_peak_update_ts) if pos.last_peak_update_ts > 0 else 0.0
                    if (_rd_peak_min <= _rd_peak_pct < _rd_peak_max
                            and pos.last_peak_update_ts > 0
                            and _rd_min_since_peak <= _rd_stall_sec <= _rd_max_since_peak):
                        # 역행% (peak에서 entry 쪽으로 진행한 폭)
                        _rd_drift = 0.0
                        if pos.peak_profit_price > 0:
                            if pos.direction == "LONG":
                                _rd_drift = (pos.peak_profit_price - price) / pos.peak_profit_price * 100
                            elif pos.direction == "SHORT":
                                _rd_drift = (price - pos.peak_profit_price) / pos.peak_profit_price * 100
                        # ── ATR 적응 (tight_trail 명세 계승) ──
                        _rd_thr = _rd_base
                        _rd_atr_pct = 0.0
                        if getattr(self.config, "reverse_drift_atr_adaptive_enabled", True):
                            try:
                                _rd_atr_tf = str(getattr(self.config, "reverse_drift_atr_tf", "5") or "5")
                                _rd_atr_n = int(getattr(self.config, "reverse_drift_atr_period", 14))
                                _rd_atr_mult = float(getattr(self.config, "reverse_drift_atr_multiplier", 0.2))
                                _rd_atr_cap = float(getattr(self.config, "reverse_drift_atr_cap_pct", 0.4))
                                raw = self._get_client().get_kline(pos.market, interval=_rd_atr_tf, limit=_rd_atr_n + 5)
                                if raw and len(raw) >= _rd_atr_n + 2:
                                    ordered = list(raw)
                                    trs = []
                                    for i in range(1, len(ordered)):
                                        h = float(ordered[i][2])
                                        l = float(ordered[i][3])
                                        pc = float(ordered[i - 1][4])
                                        trs.append(max(h - l, abs(h - pc), abs(l - pc)))
                                    if len(trs) >= _rd_atr_n:
                                        atr = sum(trs[-_rd_atr_n:]) / _rd_atr_n
                                        last_close = float(ordered[-1][4])
                                        if last_close > 0 and atr > 0:
                                            _rd_atr_pct = atr / last_close * 100.0
                                            adaptive = _rd_atr_pct * _rd_atr_mult
                                            # clamp: floor=_rd_base, cap=_rd_atr_cap
                                            _rd_thr = max(_rd_base, min(_rd_atr_cap, adaptive))
                            except Exception as exc:
                                logger.debug("[FOCUS] reverse_drift ATR 적응 실패 (base 유지): %s", exc)
                        if _rd_drift >= _rd_thr:
                            _rd_stall = now - pos.last_peak_update_ts
                            # ★★★ [2026-05-18 부모 비전 #6 B 옵션] 시간 무관 OR 조건 — 옆 서버 + 뉴스 consensus 확인
                            _rd_consensus = self._check_exit_consensus(pos, now)
                            if _rd_consensus == "hold":
                                logger.info(
                                    "[FOCUS] ▶ Reverse Drift HOLD (consensus=hold, B 패턴 신호): %s %s peak=+%.2f%% drift=%.2f%%p — 옆친구+뉴스 같은 방향 → 견디기",
                                    pos.direction, pos.market, _rd_peak_pct, _rd_drift,
                                )
                                # 컷 안 함 (가드 무시)
                            else:
                                _consensus_tag = f"_consensus={_rd_consensus}" if _rd_consensus != "neutral" else ""
                                logger.info(
                                    "[FOCUS] ★ Reverse Drift Exit: %s %s peak=+%.2f%% drift=%.2f%%p (thr=%.2f, atr=%.2f%%) since_peak=%.0fs%s — 수익 역행 컷",
                                    pos.direction, pos.market, _rd_peak_pct, _rd_drift, _rd_thr, _rd_atr_pct, _rd_stall, _consensus_tag,
                                )
                                reason = (
                                    f"reverse_drift_peak+{_rd_peak_pct:.2f}%_"
                                    f"drift{_rd_drift:.2f}%p_thr{_rd_thr:.2f}_{int(_rd_stall)}s"
                                    + (f"_{_rd_consensus}" if _rd_consensus != "neutral" else "")
                                )
                                if self._close_position(pos, reason=reason):
                                    closed.append(pos)
                                continue

                # ── 🐢 ★ Pre-BE 손실방지선 (2026-06-09 부모 "지금 나우") ──
                # pre_be_stall(정체)·reverse_drift(역행)의 사각: peak<0.1 못 띄운 헤맴(🐢)이
                # entry 기준 손실로 밀릴 때. peak 분모 안 씀(reverse_drift 과민 회피) = entry 기준 손실%.
                # 진입 1% 못 넘기는 현실 + peak<0.1 SL직행 10건 -21.87(2026-06-09 실증) 대응.
                # entry 대비 -X% 밀리면 작은 컷 → SL 풀 직행 방지. consensus=hold 면 견딤(A/B 게임).
                if (not _skip_old_exit
                        and getattr(self.config, "pre_be_loss_guard_enabled", False)
                        and not pos.breakeven_locked
                        and not self._in_entry_grace_period(pos, now)
                        and not self._hold_mode_active()):
                    _pbl_peak_max = float(getattr(self.config, "pre_be_loss_guard_peak_max_pct", 0.1))
                    _pbl_trig = float(getattr(self.config, "pre_be_loss_guard_trigger_loss_pct", 0.5))
                    _pbl_min_hold = float(getattr(self.config, "pre_be_loss_guard_min_hold_sec", 60.0))
                    _pbl_max_age = float(getattr(self.config, "pre_be_loss_guard_max_age_sec", 1800.0))
                    # peak% (direction) — 못 띄운 헤맴 판정
                    _pbl_peak = 0.0
                    if pos.peak_profit_price > 0 and pos.entry_price > 0:
                        if pos.direction == "LONG":
                            _pbl_peak = (pos.peak_profit_price / pos.entry_price - 1) * 100
                        else:
                            _pbl_peak = (1 - pos.peak_profit_price / pos.entry_price) * 100
                    # 현재 손익% (entry 기준, direction) — peak 분모 회피
                    _pbl_cur = 0.0
                    if pos.entry_price > 0:
                        if pos.direction == "LONG":
                            _pbl_cur = (price / pos.entry_price - 1) * 100
                        else:
                            _pbl_cur = (1 - price / pos.entry_price) * 100
                    _pbl_age = (now - pos.entry_ts) if pos.entry_ts > 0 else 0.0
                    # 헤맴(peak≤max) + entry 손실밀림(-trig) + stale 보호(min_hold≤age≤max_age)
                    if (_pbl_peak <= _pbl_peak_max
                            and _pbl_cur <= -_pbl_trig
                            and _pbl_min_hold <= _pbl_age <= _pbl_max_age):
                        _pbl_consensus = self._check_exit_consensus(pos, now)
                        if _pbl_consensus == "hold":
                            logger.info(
                                "[FOCUS] ▶ Pre-BE Loss HOLD (consensus=hold): %s %s cur=%.2f%% peak=%.2f%% — 옆친구+뉴스 견디기",
                                pos.direction, pos.market, _pbl_cur, _pbl_peak,
                            )
                        else:
                            _pbl_ctag = f"_{_pbl_consensus}" if _pbl_consensus != "neutral" else ""
                            logger.info(
                                "[FOCUS] 🐢 ★ Pre-BE 손실방지선 Exit: %s %s cur=%.2f%% peak=%.2f%% age=%.0fs%s — 헤맴+손실밀림 작은 컷",
                                pos.direction, pos.market, _pbl_cur, _pbl_peak, _pbl_age, _pbl_ctag,
                            )
                            reason = f"pre_be_loss_{_pbl_cur:.2f}%_peak{_pbl_peak:.2f}%_age{int(_pbl_age)}s{_pbl_ctag}"
                            if self._close_position(pos, reason=reason):
                                closed.append(pos)
                            continue

                # ── ★ 갭 천장/바닥 접근 청산 (2026-06-03 부모님 "갭 체크") ──
                # LONG: 최근 N봉 고가(천장)에 proximity_pct 이내 접근 → 선제 청산
                # SHORT: 최근 N봉 저가(바닥)에 proximity_pct 이내 접근 → 선제 청산
                if (getattr(self.config, "gap_proximity_exit_enabled", False)
                        and not pos.breakeven_locked
                        and price > 0):
                    try:
                        _gpe_tf = str(getattr(self.config, "gap_proximity_exit_tf", "15"))
                        _gpe_bars = int(getattr(self.config, "gap_check_lookback_bars", 12))
                        _gpe_prox = float(getattr(self.config, "gap_proximity_exit_pct", 0.2))
                        _gpe_raw = self._get_mtf_kline(pos.market, _gpe_tf, limit=_gpe_bars + 2, ttl=60.0)
                        if _gpe_raw and len(_gpe_raw) >= _gpe_bars:
                            _gpe_recent = _gpe_raw[-_gpe_bars:]
                            if pos.direction == "LONG":
                                _gpe_wall = max(float(r[2]) for r in _gpe_recent if len(r) >= 5)
                                _gpe_dist = (_gpe_wall - price) / price * 100.0
                            else:
                                _gpe_wall = min(float(r[3]) for r in _gpe_recent if len(r) >= 5)
                                _gpe_dist = (price - _gpe_wall) / price * 100.0
                            if 0 < _gpe_dist < _gpe_prox:
                                _reason = f"gap_proximity:{_gpe_dist:.2f}%<{_gpe_prox:.2f}%(wall={_gpe_wall:.4f})"
                                logger.info(
                                    "[FOCUS] ⛔ 갭 접근 청산: %s %s wall=%.4f dist=%.2f%%<%.2f%% → 청산",
                                    pos.direction, pos.market, _gpe_wall, _gpe_dist, _gpe_prox,
                                )
                                if self._close_position(pos, reason=_reason):
                                    closed.append(pos)
                                continue
                    except Exception as _gpe_exc:
                        logger.debug("[FOCUS] gap_proximity_exit error: %s", _gpe_exc)

                # ── ★ Long Hold Timeout (2026-04-25 부모 신규) ──
                # 장기 방치 자동 컷. Pre-BE Stall 이 놓치는 "peak 오르락내리락 + 긴 보유" 패턴.
                # 새벽 XAUT 128분 -$6.73 / ETH 164분 -$12.81 방어용.
                # 3-tier: 60분/120분/180분 절대 컷오프. BE 락 도달 전에만 작동.
                if not _skip_old_exit and getattr(self.config, "long_hold_timeout_enabled", True) and not pos.breakeven_locked:
                    _hold_min = (now - pos.entry_ts) / 60.0 if pos.entry_ts > 0 else 0.0
                    _t1_min = float(getattr(self.config, "long_hold_timeout_tier1_min", 60.0))
                    _t1_peak = float(getattr(self.config, "long_hold_timeout_tier1_peak_pct", 0.3))
                    _t2_min = float(getattr(self.config, "long_hold_timeout_tier2_min", 120.0))
                    _t2_peak = float(getattr(self.config, "long_hold_timeout_tier2_peak_pct", 0.5))
                    _t3_min = float(getattr(self.config, "long_hold_timeout_tier3_min", 30.0))
                    _t3_peak = float(getattr(self.config, "long_hold_timeout_tier3_peak_pct", 0.2))
                    # peak 수익 계산 (direction 고려)
                    _peak_pct_lht = 0.0
                    if pos.peak_profit_price > 0 and pos.entry_price > 0:
                        if pos.direction == "LONG":
                            _peak_pct_lht = (pos.peak_profit_price / pos.entry_price - 1) * 100
                        else:
                            _peak_pct_lht = (1 - pos.peak_profit_price / pos.entry_price) * 100
                    # tier 판정 (가장 강한 tier 부터) — 2026-05-13: tier3에도 peak 조건 추가
                    _lht_fire = False
                    _lht_tag = ""
                    if _hold_min >= _t3_min and _peak_pct_lht < _t3_peak:
                        _lht_fire = True
                        _lht_tag = f"t3_{int(_hold_min)}m_peak{_peak_pct_lht:.2f}%<{_t3_peak}%"
                    elif _hold_min >= _t2_min and _peak_pct_lht < _t2_peak:
                        _lht_fire = True
                        _lht_tag = f"t2_{int(_hold_min)}m_peak{_peak_pct_lht:.2f}%<{_t2_peak}%"
                    elif _hold_min >= _t1_min and _peak_pct_lht < _t1_peak:
                        _lht_fire = True
                        _lht_tag = f"t1_{int(_hold_min)}m_peak{_peak_pct_lht:.2f}%<{_t1_peak}%"
                    if _lht_fire:
                        logger.info(
                            "[FOCUS] ★ Long Hold Timeout: %s %s %s — 장기 방치 자동 컷",
                            pos.direction, pos.market, _lht_tag,
                        )
                        reason = f"long_hold_timeout_{_lht_tag}"
                        if self._close_position(pos, reason=reason):
                            closed.append(pos)
                        continue

                # ── ★ Expectation Progress Exit (2026-05-14 부모 — 목표단위 청산) ──
                # LHT 시간컷의 과학적 대체: "시간 됐다 나가" 가 아니라
                # "목표(reward_target) 대비 진행률이 이만큼인데도 못 갔다 = 동력 없음".
                # reward_target 미산정(0)이면 비활성 — 이때는 기존 LHT 가 fallback.
                if (getattr(self.config, "expectation_progress_exit_enabled", False)
                        and not self._hold_mode_active()
                        and not pos.breakeven_locked
                        and pos.reward_target > 0 and pos.entry_price > 0):
                    _ep_hold_min = (now - pos.entry_ts) / 60.0 if pos.entry_ts > 0 else 0.0
                    # 진행률 = 현재 이동거리 / 목표 이동거리 (음수 = 반대로 진행)
                    if pos.direction == "LONG":
                        _ep_goal_dist = pos.reward_target - pos.entry_price
                        _ep_cur_dist = price - pos.entry_price
                    else:
                        _ep_goal_dist = pos.entry_price - pos.reward_target
                        _ep_cur_dist = pos.entry_price - price
                    _ep_progress_pct = (_ep_cur_dist / _ep_goal_dist * 100.0) if _ep_goal_dist > 0 else 0.0
                    _ep_t1_min = float(getattr(self.config, "expectation_progress_t1_min", 15.0))
                    _ep_t1_pct = float(getattr(self.config, "expectation_progress_t1_pct", 30.0))
                    _ep_t2_min = float(getattr(self.config, "expectation_progress_t2_min", 30.0))
                    _ep_t2_pct = float(getattr(self.config, "expectation_progress_t2_pct", 50.0))
                    _ep_fire = False
                    _ep_tag = ""
                    # ★ 음수 progress 즉시 컷 (2026-05-15 부모): 손실 방향 명백시 t2 기다리지 않음
                    _ep_neg_en = bool(getattr(self.config, "expectation_progress_neg_cut_enabled", True))
                    _ep_neg_pct = float(getattr(self.config, "expectation_progress_neg_cut_pct", -50.0))
                    _ep_neg_min = float(getattr(self.config, "expectation_progress_neg_cut_min", 30.0))
                    if _ep_neg_en and _ep_hold_min >= _ep_neg_min and _ep_progress_pct < _ep_neg_pct:
                        _ep_fire = True
                        _ep_tag = f"neg_{int(_ep_hold_min)}m_progress{_ep_progress_pct:.0f}%<{_ep_neg_pct:.0f}%"
                    elif _ep_hold_min >= _ep_t2_min and _ep_progress_pct < _ep_t2_pct:
                        _ep_fire = True
                        _ep_tag = f"t2_{int(_ep_hold_min)}m_progress{_ep_progress_pct:.0f}%<{_ep_t2_pct:.0f}%"
                    elif _ep_hold_min >= _ep_t1_min and _ep_progress_pct < _ep_t1_pct:
                        _ep_fire = True
                        _ep_tag = f"t1_{int(_ep_hold_min)}m_progress{_ep_progress_pct:.0f}%<{_ep_t1_pct:.0f}%"
                    if _ep_fire:
                        logger.info(
                            "[FOCUS] ★ Expectation Progress Exit: %s %s %s — 목표 동력 없음 (target=$%.6g)",
                            pos.direction, pos.market, _ep_tag, pos.reward_target,
                        )
                        reason = f"expectation_progress_{_ep_tag}"
                        if self._close_position(pos, reason=reason):
                            closed.append(pos)
                        continue

                # ── Coin Profit Lock-in (2026-04-19, 기본 OFF) ──
                # 코인별 N시간 누적 수익 × 70% 보존선 방어. BE 락 이후만 활성화.
                # 수익 잠금 관점: 이미 번 것을 포지션 drawdown으로 까먹지 않게.
                # 활성화하려면 focus_config.json에 coin_profit_lockin_enabled=true 넣고 재시작.
                if self.config.coin_profit_lockin_enabled:
                    _notional = pos.entry_price * pos.qty if pos.entry_price > 0 else 0.0
                    _unrealized_gross = _notional * (pnl_pct / 100.0)
                    _fee_est = _notional * 0.0011   # 왕복 0.11% 추정
                    _unrealized_net = _unrealized_gross - _fee_est
                    _lockin_trigger, _lockin_info = self._check_profit_lockin(pos, _unrealized_net)
                    if _lockin_trigger:
                        logger.info(
                            "[FOCUS] ★ Profit Lock-in: %s %s realized_4h=$%.2f unreal=$%+.2f total=$%.2f < thr=$%.2f — 수익 잠금",
                            pos.direction, pos.market,
                            _lockin_info["realized_n"], _lockin_info["unrealized"],
                            _lockin_info["total"], _lockin_info["threshold"],
                        )
                        reason = (f"profit_lockin:realized=${_lockin_info['realized_n']:.1f}_"
                                  f"total=${_lockin_info['total']:.1f}_thr=${_lockin_info['threshold']:.1f}")
                        if self._close_position(pos, reason=reason):
                            closed.append(pos)
                        continue

                # ── Fast-Reject (진입 직후 "한번도 수면 위로 못 올라옴" 조기 청산) ──
                #   H4 entry가 5~15분 내에 peak도 못 찍고 의미있는 손실 → 타이밍 실패
                #   2026-04-16 데이터: LONG 손실 16건 중 15건이 이 패턴.
                #   SL(2%+) 기다리는 대신 -0.3% 대에서 소손절로 끊어서 평균 손실 1/3로 압축.
                #   thesis_invalidation(1h+ 30M 구조)과 독립 — 이건 price-only, 빠름.
                if not _skip_old_exit and self.config.fast_reject_enabled and pos.entry_ts > 0:
                    _hold_sec = now - pos.entry_ts
                    # peak_profit_price → peak_pct 환산 (두 규칙 모두 사용)
                    _peak_pct_fr = 0.0
                    if pos.peak_profit_price > 0 and pos.entry_price > 0:
                        if pos.direction == "LONG":
                            _peak_pct_fr = (pos.peak_profit_price / pos.entry_price - 1) * 100
                        else:
                            _peak_pct_fr = (1 - pos.peak_profit_price / pos.entry_price) * 100

                    # ★ Phase L.1 (2026-04-22, Harpoon 0-6 → FOCUS 이식):
                    # Rule 0 — fast_reject_v2: 진입 후 10~30초 peak 거의 0% + 작은 손실 → 즉시 컷
                    # Harpoon forensic 04-14 두 사례 (peak 0%, 5초/17초 SL) 패턴 직접 대응
                    # 기존 Rule 1 (5분 wait) 보다 훨씬 빠름. 검사 윈도우 짧고 임계 엄격.
                    if getattr(self.config, "fast_reject_v2_enabled", False):
                        _frv2_max = float(getattr(self.config, "fast_reject_v2_max_sec", 30.0))
                        _frv2_peak_th = float(getattr(self.config, "fast_reject_v2_peak_threshold_pct", 0.05))
                        _frv2_pnl_th = float(getattr(self.config, "fast_reject_v2_pnl_pct", -0.05))
                        if (10.0 <= _hold_sec <= _frv2_max
                                and _peak_pct_fr < _frv2_peak_th
                                and pnl_pct <= _frv2_pnl_th):
                            logger.warning(
                                "[FOCUS] Phase L.1 FAST-REJECT v2: %s %s hold=%.0fs peak=%.3f%% pnl=%.3f%% "
                                "— Harpoon-style 즉시 컷 (peak 0%% + 손실)",
                                pos.direction, pos.market, _hold_sec, _peak_pct_fr, pnl_pct,
                            )
                            if self._close_position(
                                pos,
                                f"fast_reject_v2:hold={_hold_sec:.0f}s_peak={_peak_pct_fr:.3f}%_pnl={pnl_pct:.3f}%",
                                is_sl=True,
                            ):
                                closed.append(pos)
                            continue

                    # ★ Rule 1: 기존 fast_reject (5~15분, peak 미달 + 손실)
                    if (self.config.fast_reject_min_sec <= _hold_sec
                            <= self.config.fast_reject_max_sec):
                        # 조건: peak 미달 + 현재 손실 구간
                        if (_peak_pct_fr < self.config.fast_reject_peak_threshold_pct
                                and pnl_pct <= self.config.fast_reject_trigger_pnl_pct):
                            logger.info(
                                "[FOCUS] FAST-REJECT: %s %s hold=%.0fs peak=%.2f%% pnl=%.2f%% — entry mistimed, cutting loss",
                                pos.direction, pos.market, _hold_sec, _peak_pct_fr, pnl_pct
                            )
                            if self._close_position(
                                pos,
                                f"fast_reject:hold={_hold_sec:.0f}s_peak={_peak_pct_fr:.2f}%_pnl={pnl_pct:.2f}%",
                                is_sl=True,  # 손실 청산 → daily_sl_count 증가
                            ):
                                closed.append(pos)
                            continue

                    # ★ Rule 2: fast_reject_underwater
                    # [2026-05-28 부모] 값 완화 — 10분/peak≤0% → 30분/peak≤-0.2% (옛 모드 한정).
                    # 새 guard_score 진입은 위 _skip_old_exit 에서 이미 우회. 옛 모드에서도
                    # NEAR 사례 (peak=-0.05%, hold=623s) 같은 작은 변동까지 컷하지 않게 한다.
                    _UNDERWATER_MIN_SEC = 1800.0   # 30분 (구 10분)
                    _UNDERWATER_PEAK_MAX = -0.2    # peak 이 -0.2% 이하여야 발동 (구 0.0)
                    if _hold_sec >= _UNDERWATER_MIN_SEC and _peak_pct_fr <= _UNDERWATER_PEAK_MAX and pnl_pct < 0:
                        logger.warning(
                            "[FOCUS] FAST-REJECT UNDERWATER: %s %s hold=%.0fs peak=%.2f%% pnl=%.2f%% "
                            "— 10min+ with ZERO positive peak, completely wrong entry",
                            pos.direction, pos.market, _hold_sec, _peak_pct_fr, pnl_pct,
                        )
                        if self._close_position(
                            pos,
                            f"fast_reject_underwater:hold={_hold_sec:.0f}s_peak={_peak_pct_fr:.2f}%_pnl={pnl_pct:.2f}%",
                            is_sl=True,
                        ):
                            closed.append(pos)
                        continue

                # 1) 추세 + BB + MACD 기반 청산 (최소 1시간 보유 후)
                #    순서: 추세 먼저 → BB 감안 → MACD 확인 → 결정
                #    MACD 강하면 BB 벽 타고 오르/내리므로 BB만 보면 안 됨
                if hold_hours >= 1.0:
                    try:
                        raw = self._get_client().get_kline(pos.market, interval=self.config.primary_tf, limit=40)
                        from app.strategy.greenpen.pa_detector import OHLCV as _O
                        from app.strategy.greenpen.market_structure import analyze_structure as _as
                        _candles = [_O(float(r[1]),float(r[2]),float(r[3]),float(r[4])) for r in raw if len(r)>=5]
                        if len(_candles) >= 10:
                            _struct = _as(_candles)
                            trend_val = _struct.trend.value

                            # 1a) 완전 추세 반전 → 즉시 청산 (BB/MACD 볼 필요 없음)
                            # ★ [2026-04-26] config 노출 — 부모님 통제 하에 ON/OFF
                            trend_opposed = (
                                (pos.direction == "SHORT" and trend_val == "UPTREND") or
                                (pos.direction == "LONG" and trend_val == "DOWNTREND")
                            )
                            if not _skip_old_exit and getattr(self.config, "trend_reversal_enabled", False) and trend_opposed:
                                logger.info("[FOCUS] TREND REVERSAL! %s now %s → EXIT (pnl=%.1f%%) NO HESITATION",
                                            pos.market, trend_val, pnl_pct)
                                if self._close_position(pos, f"trend_reversal:{trend_val}_pnl:{pnl_pct:.1f}%",
                                                     is_sl=(pnl_pct < 0)):
                                    closed.append(pos)
                                continue

                            # 1a-2) 30M 구조적 전환 — 진입 근거 소멸 조기 탈출
                            #   H4는 아직 반전 안 했지만, 30M 구조가 포지션 반대로 꺾인 경우
                            #   + 수익 진전 없으면(peak < 0.3%) → SL 기다리지 말고 소손절
                            if not _skip_old_exit and self.config.thesis_invalidation_enabled and hold_hours >= self.config.thesis_invalidation_min_hold_h:
                                try:
                                    raw_30m = self._get_client().get_kline(pos.market, interval="30", limit=20)
                                    _c30 = [_O(float(r[1]),float(r[2]),float(r[3]),float(r[4]))
                                            for r in raw_30m if len(r) >= 5]
                                    if len(_c30) >= 10:
                                        _s30 = _as(_c30)
                                        _t30 = _s30.trend.value
                                        _thesis_broken = (
                                            (pos.direction == "LONG" and _t30 == "DOWNTREND") or
                                            (pos.direction == "SHORT" and _t30 == "UPTREND")
                                        )
                                        if _thesis_broken:
                                            # peak_profit_price 기반 계산, 없으면 현재 pnl_pct 사용
                                            _peak_pct = pnl_pct  # fallback: 현재 손익
                                            if pos.peak_profit_price > 0 and pos.entry_price > 0:
                                                if pos.direction == "LONG":
                                                    _peak_pct = (pos.peak_profit_price / pos.entry_price - 1) * 100
                                                else:
                                                    _peak_pct = (1 - pos.peak_profit_price / pos.entry_price) * 100
                                            if _peak_pct < self.config.thesis_invalidation_max_peak_pct:
                                                logger.info("[FOCUS] THESIS INVALIDATED: %s %s, 30M=%s, peak=%.2f%%, pnl=%.2f%% → EXIT",
                                                            pos.direction, pos.market, _t30, _peak_pct, pnl_pct)
                                                if self._close_position(pos,
                                                        f"thesis_invalidated:30M_{_t30}_peak:{_peak_pct:.1f}%_pnl:{pnl_pct:.1f}%",
                                                        is_sl=(pnl_pct < 0)):
                                                    closed.append(pos)
                                                continue
                                            else:
                                                logger.debug("[FOCUS] 30M against (%s) but peak=%.2f%% > threshold → DT/TP handles",
                                                             _t30, _peak_pct)
                                except Exception as exc:
                                    logger.debug("[FOCUS] 30M structural check error: %s", exc)

                            # 1b) 추세 SIDEWAYS + BB 불리 + MACD 약화 → 스마트 청산
                            # ★ [2026-04-26] config 노출 — 부모님 통제 하에 ON/OFF
                            if not _skip_old_exit and getattr(self.config, "bb_macd_sw_enabled", False) and hold_hours >= float(getattr(self.config, "bb_macd_sw_min_hold_hours", 2.0)) and trend_val == "SIDEWAYS" and len(_candles) >= 20:
                                from app.strategy.indicators import bollinger_bands as _bb_fn
                                from app.strategy.indicators import macd as _macd_fn
                                _closes = [c.close for c in _candles]
                                _bb = _bb_fn(_closes, 20, 2.0)
                                _macd_line, _macd_sig, _macd_hist = _macd_fn(_closes)

                                if _bb and _macd_hist is not None:
                                    bb_mid = _bb["mid"]
                                    bb_upper = _bb["upper"]
                                    bb_lower = _bb["lower"]

                                    # BB 위치 불리한가?
                                    bb_unfavorable = (
                                        (pos.direction == "LONG" and price < bb_mid) or
                                        (pos.direction == "SHORT" and price > bb_mid)
                                    )

                                    # MACD 모멘텀이 우리 방향에 불리한가?
                                    # LONG인데 histogram ≤ 0 → 상승 모멘텀 없음
                                    # SHORT인데 histogram ≥ 0 → 하락 모멘텀 없음
                                    # MACD가 강하면(우리 방향) → BB 벽 타는 중 → 나가면 안 됨
                                    macd_weak = (
                                        (pos.direction == "LONG" and _macd_hist <= 0) or
                                        (pos.direction == "SHORT" and _macd_hist >= 0)
                                    )

                                    _bb_pnl_low = float(getattr(self.config, "bb_macd_sw_pnl_low", -2.0))
                                    _bb_pnl_high = float(getattr(self.config, "bb_macd_sw_pnl_high", 0.5))
                                    if bb_unfavorable and macd_weak and _bb_pnl_low < pnl_pct < _bb_pnl_high:
                                        # ★ 핵심: LONG 청산 조건 = SHORT 기회 (그 반대도)
                                        flip_dir = "SHORT" if pos.direction == "LONG" else "LONG"
                                        logger.info(
                                            "[FOCUS] BB+MACD+SIDEWAYS exit: %s dir=%s price=%.1f "
                                            "bb=[%.1f/%.1f/%.1f] macd_hist=%.2f trend=%s pnl=%.2f%% → FLIP→%s",
                                            pos.market, pos.direction, price,
                                            bb_lower, bb_mid, bb_upper,
                                            _macd_hist, trend_val, pnl_pct, flip_dir,
                                        )
                                        if self._close_position(
                                            pos,
                                            f"bb_macd_sw:{pos.direction}_bb={bb_mid:.0f}_macd={_macd_hist:.1f}_pnl:{pnl_pct:.1f}%",
                                            is_sl=(pnl_pct < 0),
                                        ):
                                            closed.append(pos)
                                            # 방향 전환 기회 기록 — 쿨다운 단축 + 방향 힌트
                                            self._pending_flip = flip_dir
                                        continue
                    except Exception as exc:
                        logger.debug("[FOCUS] operation failed: %s", exc)

                # 3) 장시간 보유 + 수익 중 → TP 축소하여 빠른 익절
                #    H4 전략: 최소 8시간은 기다려야 의미 있음
                # ★ [2026-04-26] config 노출 — 부모님 통제
                _qtp_min_h = float(getattr(self.config, "quick_tp_min_hold_hours", 8.0))
                _qtp_min_pnl = float(getattr(self.config, "quick_tp_min_pnl_pct", 1.0))
                if not _skip_old_exit and getattr(self.config, "quick_tp_enabled", False) and hold_hours >= _qtp_min_h and pnl_pct >= _qtp_min_pnl:
                    tightened_tp1 = pos.entry_price + (pos.tp1 - pos.entry_price) * 0.5
                    if pos.direction == "SHORT":
                        tightened_tp1 = pos.entry_price - (pos.entry_price - pos.tp1) * 0.5
                    if (pos.direction == "LONG" and price >= tightened_tp1) or \
                       (pos.direction == "SHORT" and price <= tightened_tp1):
                        logger.info("[FOCUS] Time-based quick TP %s: %.1fh held, +%.1f%%",
                                    pos.market, hold_hours, pnl_pct)
                        if self._close_position(pos, f"quick_tp:{hold_hours:.0f}h_pnl:{pnl_pct:.1f}%"):
                            closed.append(pos)
                        continue

                # ★ [2026-04-26] BTC Emergency — 부모님 "급락=기회, 트렌드 정렬"
                # 급락 → SHORT 트렌드 (LONG 청산, SHORT 유지/가속) / 급등 → LONG 트렌드 (대칭)
                if getattr(self.config, "btc_emergency_pause_enabled", True) and btc_price > 0 and not getattr(self, "_btc_emergency_fired", False):
                    try:
                        from app.core.hyper_price_store import price_store
                        _ep_window_min = float(getattr(self.config, "btc_emergency_pause_window_min", 10.0))
                        _ep_count = max(10, int(_ep_window_min * 6))
                        btc_prices = price_store.get_prices("BTCUSDT", count=_ep_count)
                        if btc_prices and len(btc_prices) >= 10:
                            btc_recent = [float(p) for p in btc_prices[-_ep_count:] if p]
                            if btc_recent and btc_recent[0] > 0:
                                btc_change = (btc_recent[-1] / btc_recent[0] - 1) * 100
                                _ep_th = abs(float(getattr(self.config, "btc_emergency_pause_threshold_pct", 5.0)))
                                if abs(btc_change) >= _ep_th and self.config.enabled:
                                    _mode = str(getattr(self.config, "btc_emergency_mode", "trend_aligned"))
                                    trend_dir = "SHORT" if btc_change < 0 else "LONG"
                                    opposite = "LONG" if trend_dir == "SHORT" else "SHORT"
                                    logger.warning(
                                        "[FOCUS] 🚨 BTC EMERGENCY: %.2f%% in %.0fmin → mode=%s trend=%s",
                                        btc_change, _ep_window_min, _mode, trend_dir
                                    )
                                    if _mode == "trend_aligned":
                                        # 역방향 자동 청산
                                        _closed_count = 0
                                        for _p in list(self.positions):
                                            if _p.direction == opposite:
                                                if self._close_position(_p, f"btc_emergency_{trend_dir}_aligned:{btc_change:.1f}%_opp_close", is_sl=True):
                                                    closed.append(_p)
                                                    _closed_count += 1
                                        # 순방향 유지 + 진입 가속 플래그 (시간 만료 시 자동 reset)
                                        self._emergency_aligned_dir = trend_dir
                                        _aligned_dur_min = float(getattr(self.config, "btc_emergency_aligned_duration_min", 120.0))
                                        self._emergency_aligned_until = time.time() + (_aligned_dur_min * 60)
                                        try:
                                            self._notify(
                                                f"🚨 BTC {btc_change:+.1f}% in {_ep_window_min:.0f}min — TREND={trend_dir}\n"
                                                f"  {opposite} 자동 청산: {_closed_count}건\n"
                                                f"  {trend_dir} 유지 + 빈 슬롯 가속 진입"
                                            )
                                        except Exception:
                                            pass
                                    elif _mode == "close_all":
                                        for _p in list(self.positions):
                                            if self._close_position(_p, f"btc_emergency_close_all:{btc_change:.1f}%", is_sl=True):
                                                closed.append(_p)
                                    elif _mode == "pause":
                                        self.config.enabled = False
                                        try:
                                            self._notify(f"🚨 BTC EMERGENCY {btc_change:+.1f}% — FOCUS PAUSED")
                                        except Exception:
                                            pass
                                    self._btc_emergency_fired = True  # 한 번만 발동
                                    try:
                                        self._save_config()
                                    except Exception:
                                        pass
                                    break
                    except Exception as exc:
                        logger.debug("[FOCUS] btc_emergency check error: %s", exc)

                # 다단계 긴급 탈출 (BTC crash) — 기존 자동 청산 (default OFF, 부모님 "기회를 컷? 말도 안 됨")
                if self.config.emergency_tp_tiers and btc_price > 0:
                    try:
                        from app.core.hyper_price_store import price_store
                        btc_prices = price_store.get_prices("BTCUSDT", count=60)
                        if btc_prices and len(btc_prices) >= 10:
                            btc_recent = [float(p) for p in btc_prices[-10:] if p]
                            if btc_recent and btc_recent[0] > 0:
                                btc_change = (btc_recent[-1] / btc_recent[0] - 1) * 100
                                _btc_crash_th = float(getattr(self.config, "btc_crash_threshold_pct", -5.0))
                                if btc_change < _btc_crash_th:
                                    if self._close_position(pos, f"BTC_CRASH:{btc_change:.1f}%", is_sl=True):
                                        closed.append(pos)
                    except Exception as exc:
                        logger.debug("[FOCUS] import price_store failed: %s", exc)

                # ── [2026-06-08 부모] Auto Take-Profit (트레일링 거두기) — 무장 후 최고점 반납 시 거둠 ──
                #   $1 넘으면 '이 이익 지킨다' 무장만 → 쭉쭉 오르면 따라가고(peak) → 꺾여 반납하면 거둠. 고정 익절 X.
                #   ★ 무장 후엔 견딤 모드(hold)여도 우선 작동 (그 이익 지킴) — 부모님 "무장 후만 견딤보다 우선".
                #     무장 전(_atp_armed=False)은 자동으로 안 거둠 = 견딤 엔진이 처리. 그래서 hold_mode 조건 불필요.
                if getattr(self.config, "auto_tp_enabled", False) and pos not in closed:
                    try:
                        _atp_fee = float(getattr(self.config, "caution_fee_rate", 0.00055))
                        _atp_rtfee = price * pos.qty * _atp_fee * 2           # 왕복 수수료
                        _atp_gross = (price - pos.entry_price) * pos.qty if pos.direction == "LONG" \
                            else (pos.entry_price - price) * pos.qty
                        _atp_net = _atp_gross - _atp_rtfee                     # 현재 순익
                        _atp_arm = float(getattr(self.config, "auto_tp_usdt", 0.0) or 0.0)   # 무장 임계
                        _atp_gb = float(getattr(self.config, "auto_tp_peak_giveback_pct", 0.4) or 0.4)

                        # peak 순익 (peak_profit_price 기반 — 최고가에서 거뒀다면 얼마였을지)
                        _atp_peak_net = None
                        if pos.peak_profit_price > 0 and pos.entry_price > 0:
                            _pk_gross = (pos.peak_profit_price - pos.entry_price) * pos.qty if pos.direction == "LONG" \
                                else (pos.entry_price - pos.peak_profit_price) * pos.qty
                            _atp_peak_net = _pk_gross - _atp_rtfee

                        # 무장: peak 순익이 arm($1) 이상 한 번 도달 → 그 이익을 지킴 (이후 견딤보다 우선)
                        _atp_armed = (_atp_arm > 0 and _atp_peak_net is not None and _atp_peak_net >= _atp_arm)
                        # ★ 무장 순간 SL을 본전(+수수료 쿠션)으로 — 급락 건너뜀 시 손실 0 ("무장=지킨다" 완성)
                        #   부모님 우려 "$1 무장 후 급락하면 못 걸고 손실?" 해결. only tighten + 1회.
                        if _atp_armed and not pos.breakeven_locked:
                            _atp_be_cushion = 0.0015   # 왕복 수수료(~0.11%) + 슬리피지 여유
                            _atp_be_sl = pos.entry_price * (1 + _atp_be_cushion) if pos.direction == "LONG" \
                                else pos.entry_price * (1 - _atp_be_cushion)
                            _atp_be_tighten = (pos.direction == "LONG" and _atp_be_sl > pos.sl) \
                                or (pos.direction == "SHORT" and _atp_be_sl < pos.sl)
                            if _atp_be_tighten:
                                _atp_old_sl = pos.sl
                                pos.sl = round(_atp_be_sl, 8)
                                pos.breakeven_locked = True
                                pos.be_locked_ts = time.time()
                                logger.info("[FOCUS] Auto TP 무장(SL→본전): %s %s SL $%.4f→$%.4f (peak 순익 $%.2f≥$%.2f)",
                                            pos.direction, pos.market, _atp_old_sl, pos.sl, _atp_peak_net, _atp_arm)
                                self._update_bybit_sl(pos)
                                self._save_config()
                        # 거두기: 무장 후 최고점에서 giveback%(40%) 반납 + 여전히 순익 + → 거둠
                        if _atp_armed and 0 < _atp_net <= _atp_peak_net * (1 - _atp_gb):
                            _atp_reason = f"auto_tp_trail:arm=${_atp_arm:.2f} peak=${_atp_peak_net:.4f}→now=${_atp_net:.4f}(-{_atp_gb*100:.0f}%)"
                            logger.info("[FOCUS] Auto Take-Profit (트레일링): %s %s %s → 거둠", pos.direction, pos.market, _atp_reason)
                            if self._close_position(pos, _atp_reason):
                                closed.append(pos)
                    except Exception as exc:
                        logger.debug("[FOCUS] auto_tp error: %s", exc)

                # ── [2026-06-08 부모] Auto Stop-Loss (손실 N% 자동컷) — default OFF, 기존 SL 과 OR ──
                if getattr(self.config, "auto_sl_pct_enabled", False) and pos not in closed and not self._hold_mode_active():
                    try:
                        if pos.entry_price > 0:
                            _asl_loss = (1 - price / pos.entry_price) * 100 if pos.direction == "LONG" \
                                else (price / pos.entry_price - 1) * 100      # 손실률 % (양수=손실)
                            _asl_N = float(getattr(self.config, "auto_sl_pct", 0.0) or 0.0)
                            if _asl_N > 0 and _asl_loss >= _asl_N:
                                logger.info("[FOCUS] Auto Stop-Loss: %s %s loss %.2f%% >= %.2f%% → 컷",
                                            pos.direction, pos.market, _asl_loss, _asl_N)
                                if self._close_position(pos, f"auto_sl_pct:loss={_asl_loss:.2f}%>={_asl_N:.2f}%", is_sl=True):
                                    closed.append(pos)
                    except Exception as exc:
                        logger.debug("[FOCUS] auto_sl error: %s", exc)

                # ── v2: CAUTION 감지 (횡보 시작 징조) ──
                # ★ 최소 보유 시간: config 노출 (default 30분)
                min_hold_sec = float(getattr(self.config, "caution_min_hold_sec", 1800.0))
                hold_time = now - pos.entry_ts if pos.entry_ts else 9999
                if not _skip_old_exit and getattr(self.config, "caution_sideways_profit_secure_enabled", False) and not self._hold_mode_active() and pos not in closed and hold_time >= min_hold_sec:
                    try:
                        if self._detect_sideways_starting(pos.market):
                            fee_rate = float(getattr(self.config, "caution_fee_rate", 0.00055))
                            gross_pnl = (price - pos.entry_price) * pos.qty if pos.direction == "LONG" \
                                else (pos.entry_price - price) * pos.qty
                            round_trip_fee = price * pos.qty * fee_rate * 2
                            net_pnl = gross_pnl - round_trip_fee
                            # ★ 최소 순이익 기준: config 노출 (default 수수료 × 3배)
                            min_profit = round_trip_fee * float(getattr(self.config, "caution_min_profit_multiplier", 3.0))
                            if net_pnl > min_profit:
                                logger.info("[FOCUS] CAUTION: sideways starting + net profit $%.4f (min $%.4f) → closing to secure",
                                            net_pnl, min_profit)
                                if self._close_position(pos, f"caution_sideways_profit_secure:net=${net_pnl:.4f}"):
                                    closed.append(pos)
                            else:
                                # 이윤 없음 → CAUTION 상태로, DT/SL에 맡김
                                if self.state != FocusState.CAUTION:
                                    self.state = FocusState.CAUTION
                                    logger.info("[FOCUS] POSITIONED → CAUTION: sideways starting, no profit, DT/SL will handle")
                                    self._save_config()
                    except Exception as exc:
                        logger.debug("[FOCUS] caution check error: %s", exc)

                # ── [2026-05-27 부모] 5M 긴급 탈출 가드 — "여기서 그만!" ⭐ ──
                #   부모님 정신: TP/SL 외 긴급 탈출 = 5M RSI/MACD/BB 반전 신호로만.
                #   시간/peak 무관. 시각적 반전 3종 (RSI 과매수+변곡 / MACD cross / BB 끝점) 2/3 충족 시 즉시 청산.
                if self._5m_emergency_exit_active() and not self._hold_mode_active() and pos not in closed:
                    try:
                        _5m_exit, _5m_reason = self._check_5m_emergency_exit(pos.market, pos.direction)
                        if _5m_exit:
                            logger.info("[FOCUS] 🚨 5M EMERGENCY EXIT %s %s — %s",
                                        pos.market, pos.direction, _5m_reason)
                            if self._close_position(pos, _5m_reason):
                                closed.append(pos)
                    except Exception as exc:
                        logger.debug("[FOCUS] 5m emergency exit error: %s", exc)

            except Exception as exc:
                logger.warning("[FOCUS] position manage error for %s: %s", pos.market, exc)

        # 청산된 포지션 제거
        for pos in closed:
            if pos in self.positions:
                self.positions.remove(pos)
            # ★ FIX: legacy self.position 참조도 함께 제거 (2중 기록 방지)
            if self.position is pos:
                self.position = None
        if closed:
            self._save_config()

    # ── Dynamic Trailing SL ─────────────────────────────────

    def _trend_adaptive_exit_factor(self, market: str) -> float:
        """🎯 [2026-06-12 부모 ESPORTS/WLD] 코인별 추세-적응 출구 factor.
        runner(강추세 ADX≥strong) → factor<1 (preserve↓/slip↑ = 태움).
        chopper(약추세 ADX≤weak) → factor>1 (preserve↑/slip↓ = 빨리 챙김).
        중립/OFF/실패 → 1.0 (영향 0). ADX 캐시(코인별 TTL) — 매 tick fetch 방지. default OFF."""
        cfg = self.config
        if not getattr(cfg, "trend_adaptive_exit_enabled", False):
            return 1.0
        mk = (market or "").upper()
        if not mk:
            return 1.0
        try:
            now = time.time()
            ttl = float(getattr(cfg, "trend_adaptive_exit_adx_cache_sec", 30.0))
            cache = getattr(self, "_tae_adx_cache", None)
            if cache is None:
                cache = {}
                self._tae_adx_cache = cache
            hit = cache.get(mk)
            if hit and (now - hit[0]) < ttl:
                adx = hit[1]; _miss = False
            else:
                adx_data = self._fetch_primary_adx(mk)
                adx = float(adx_data.get("adx", 0.0)) if adx_data else 0.0
                cache[mk] = (now, adx); _miss = True
            if adx <= 0:
                return 1.0
            strong = float(getattr(cfg, "trend_adaptive_exit_adx_strong", 30.0))
            weak = float(getattr(cfg, "trend_adaptive_exit_adx_weak", 18.0))
            if adx >= strong:
                _f = float(getattr(cfg, "trend_adaptive_exit_runner_factor", 0.6)); _cls = "runner 태움(트레일 완화)"
            elif adx <= weak:
                _f = float(getattr(cfg, "trend_adaptive_exit_chop_factor", 1.4)); _cls = "chopper 스캘프(트레일 강화)"
            else:
                return 1.0   # 중립 = 현행
            # ★ 부모님 "보이게" — 캐시 미스(코인당 TTL 1회)에만 INFO = 스팸 X
            if _miss:
                logger.info("[FOCUS] 🎯 trend-adaptive exit %s: ADX=%.1f → %s (factor %.2f)", mk, adx, _cls, _f)
            return _f
        except Exception as exc:
            logger.debug("[FOCUS] _trend_adaptive_exit_factor %s: %s", mk, exc)
            return 1.0

    def _check_tight_trail_after_be(self, pos, price: float) -> bool:
        """[2026-05-16 부모 비전 #5] BE 락 활성 시 peak slippage 즉시 컷.

        부모님 관찰: "LINK peak +0.58% → SL +0.33% 보전 = peak 의 43% 만 잠금"
        → 더 가까이 따라붙어 70%+ 보전하도록.

        조건:
          - BE 락 활성 (breakeven_locked = True)
          - peak_profit_pct >= tight_trail_min_peak_pct (작은 peak 제외)
          - peak 에서 현재가까지 slippage >= tight_trail_max_slippage_pct%p

        Returns: True 면 즉시 컷 (호출자가 _close_position 처리)
        """
        cfg = self.config
        # ★ [2026-05-28 저녁 부모] green 마스터 토글 — yellow only 모드 시 skip
        if self._hold_mode_active() or not getattr(cfg, "tight_trail_after_be_enabled", True) or not self._is_green_guard_active("exit"):
            return False
        if not getattr(pos, "breakeven_locked", False):
            return False
        peak_pct = float(getattr(pos, "peak_profit_pct", 0.0) or 0.0)
        min_peak = float(getattr(cfg, "tight_trail_min_peak_pct", 0.4))
        if peak_pct < min_peak:
            return False
        max_slip = float(getattr(cfg, "tight_trail_max_slippage_pct", 0.2))
        # ── ATR 변동성 적응 — 변동성 큰 자리는 slippage 임계 자동 확대 ──
        if getattr(cfg, "tight_trail_atr_adaptive_enabled", True):
            try:
                _atr_tf = str(getattr(cfg, "tight_trail_atr_tf", "5") or "5")
                _atr_n = int(getattr(cfg, "tight_trail_atr_period", 14))
                _atr_mult = float(getattr(cfg, "tight_trail_atr_multiplier", 0.3))
                _atr_cap = float(getattr(cfg, "tight_trail_atr_cap_pct", 0.6))
                _market = getattr(pos, "market", "") or ""
                if _market:
                    raw = self._get_client().get_kline(_market, interval=_atr_tf, limit=_atr_n + 5)
                    if raw and len(raw) >= _atr_n + 2:
                        # Bybit kline: [start, open, high, low, close, ...] 최신이 [0]
                        ordered = list(raw)
                        trs = []
                        for i in range(1, len(ordered)):
                            h = float(ordered[i][2])
                            l = float(ordered[i][3])
                            pc = float(ordered[i - 1][4])
                            tr = max(h - l, abs(h - pc), abs(l - pc))
                            trs.append(tr)
                        if len(trs) >= _atr_n:
                            atr = sum(trs[-_atr_n:]) / _atr_n
                            last_close = float(ordered[-1][4])
                            if last_close > 0 and atr > 0:
                                atr_pct = atr / last_close * 100.0
                                adaptive_slip = atr_pct * _atr_mult
                                # clamp: floor=max_slip (기본 0.2), cap=_atr_cap (기본 0.6)
                                _final_slip = max(max_slip, min(_atr_cap, adaptive_slip))
                                if abs(_final_slip - max_slip) > 0.001:
                                    logger.debug("[FOCUS] tight_trail ATR 적응 %s: atr=%.3f%% → slip %.2f → %.2f%%p",
                                                 _market, atr_pct, max_slip, _final_slip)
                                max_slip = _final_slip
            except Exception as exc:
                logger.debug("[FOCUS] tight_trail ATR 적응 실패 (기본값 유지): %s", exc)
        # ★ [2026-06-12 부모] 코인별 추세 적응 — runner면 slip 임계 확대(안 자름)/chopper면 축소(빨리 자름).
        #   ATR 적응(변동성)은 둘 다 키워 runner/chopper 구별 X → ADX(추세)로 가름. default OFF → factor 1.0.
        _tae_f = self._trend_adaptive_exit_factor(getattr(pos, "market", "") or "")
        if _tae_f != 1.0 and _tae_f > 0:
            max_slip = max_slip / _tae_f   # runner(<1)→max_slip↑(태움) / chopper(>1)→↓(스캘프)
        try:
            entry_price = float(getattr(pos, "entry_price", 0.0) or 0.0)
            if entry_price <= 0:
                return False
            direction = (getattr(pos, "direction", "") or "").upper()
            if direction == "LONG":
                current_pct = (price - entry_price) / entry_price * 100.0
            elif direction == "SHORT":
                current_pct = (entry_price - price) / entry_price * 100.0
            else:
                return False
            slippage = peak_pct - current_pct
            if slippage >= max_slip:
                logger.info("[FOCUS] 🔒 tight_trail_after_be %s: peak=%.2f%% → current=%.2f%% (slip=%.2f%%p >= %.2f) → CUT",
                            getattr(pos, "market", "?"), peak_pct, current_pct, slippage, max_slip)
                return True
            return False
        except Exception as exc:
            logger.debug("[FOCUS] _check_tight_trail_after_be error: %s", exc)
            return False

    def _apply_dynamic_trailing_sl(self, pos: FocusPosition, price: float):
        """동적 트레일링 SL: 수익권 진입 시 SL을 손익분기→수익 추적으로 이동.

        Stage 1: profit >= breakeven_trigger_pct → SL을 진입가(손익분기)로 이동
        Stage 2: 이후 최고수익의 trailing_preserve_pct%를 보존하도록 SL 추적
        SL은 절대 역방향으로 이동 안 함 (only tighten, never loosen).
        """
        # 원본 SL/TP 기록 (최초 1회)
        if pos.original_sl <= 0:
            pos.original_sl = pos.sl
        if pos.original_tp1 <= 0 and pos.tp1 > 0:
            pos.original_tp1 = pos.tp1

        # 현재 수익률 계산
        if pos.direction == "LONG":
            pnl_pct = (price / pos.entry_price - 1) * 100 if pos.entry_price > 0 else 0
        else:  # SHORT
            pnl_pct = (1 - price / pos.entry_price) * 100 if pos.entry_price > 0 else 0

        # 최고 수익 가격 추적
        if pos.direction == "LONG":
            if price > pos.peak_profit_price:
                pos.peak_profit_price = price
                pos.last_peak_update_ts = time.time()   # [BE Stall Exit 2026-04-19]
        else:  # SHORT
            if pos.peak_profit_price <= 0 or price < pos.peak_profit_price:
                pos.peak_profit_price = price
                pos.last_peak_update_ts = time.time()   # [BE Stall Exit 2026-04-19]

        trigger_pct = self.config.breakeven_trigger_pct
        # ★ Progressive Trailing U-curve: 소이익은 꽉 잡고, 중이익은 숨 쉬게, 대이익은 확보
        #   Backtest 209건: 131건 개선, 0건 악화, +$174 (+81.7%)
        #   소이익(< 0.5%): small_preserve (default 80%) — 수수료 이상 확보
        #   중이익(0.5~1%): small → base 전이 (숨 쉬게 해서 TP 도달 기회)
        #   대이익(> 1%):   base + accel (기존과 동일)
        #   ★ Regime-Adaptive: 추세장이면 자동으로 여유 확대 (수동 전환 불필요)
        small_preserve = self.config.trailing_small_profit_preserve_pct / 100.0
        base_preserve = self.config.trailing_preserve_pct / 100.0
        accel_rate = self.config.trailing_accel_pct / 100.0
        _TRANSITION_PCT = 0.5  # small → base 전이 시작점

        # ── Regime-Adaptive: 추세장이면 preserve 줄여서 숨 쉬게 ──
        #   SIDEWAYS/VOLATILE: 설정값 그대로 (횡보장에서 꽉 잡기)
        #   BULL/BEAR: small_preserve × 0.82 (80% → 66%, 75% → 62%)
        #   RegimeDetector는 30초 캐시 — 매 tick API 호출 없음
        _TREND_DISCOUNT = 0.82  # 추세장 할인율
        try:
            from app.core.market_regime import RegimeDetector
            det = getattr(self, "_regime_detector", None)
            if det is None:
                det = RegimeDetector()
                self._regime_detector = det
            regime_result = det.detect("BTCUSDT")
            regime = str(getattr(regime_result, "regime", "SIDEWAYS")).upper()
            if "." in regime:
                regime = regime.split(".")[-1]
            if regime in ("BULL", "BEAR"):
                small_preserve = small_preserve * _TREND_DISCOUNT
                base_preserve = base_preserve * _TREND_DISCOUNT
        except Exception as exc:
            logger.debug("[FOCUS] import RegimeDetector failed: %s", exc)  # 감지 실패 시 설정값 그대로 (안전 fallback)
        if pnl_pct > trigger_pct:
            if pnl_pct < _TRANSITION_PCT:
                # 소이익 구간: 모든 pip이 소중 → aggressive preserve
                preserve_ratio = small_preserve
            elif pnl_pct < 1.0:
                # 전이 구간: small_preserve → base_preserve 선형 전이
                t = (pnl_pct - _TRANSITION_PCT) / (1.0 - _TRANSITION_PCT)
                preserve_ratio = small_preserve - t * (small_preserve - base_preserve)
            else:
                # 대이익 구간: base + accel (기존 로직)
                extra = pnl_pct - 1.0
                preserve_ratio = base_preserve + extra * accel_rate
            preserve_ratio = min(0.90, preserve_ratio)
        else:
            preserve_ratio = small_preserve

        # ★ [2026-06-12 부모] 코인별 추세 적응 — runner면 preserve↓(완화·태움)/chopper면 preserve↑(강화·스캘프).
        #   위 BTC 레짐 할인은 *시장* 추세, 이건 *코인 자기* 추세(ADX). default OFF → factor 1.0(영향 0).
        _tae_f = self._trend_adaptive_exit_factor(pos.market)
        if _tae_f != 1.0:
            preserve_ratio = max(0.05, min(0.90, preserve_ratio * _tae_f))

        # ── Stage 1: 손익분기 잠금 ──
        if not pos.breakeven_locked and pnl_pct >= trigger_pct:
            # [2026-05-29 부모 7번째 fix] 진입 직후 grace — Bybit 슬리피지 peak 노이즈 차단
            _grace_sec_d = float(getattr(self.config, "be_lock_grace_sec", 60.0) or 0.0)
            if _grace_sec_d > 0 and pos.entry_ts > 0 and (time.time() - pos.entry_ts) < _grace_sec_d:
                return  # 진입 직후 N초 동안 BE lock 발동 X

            # ★ [2026-06-04 부모] Smart BE Lock — 모멘텀 확인 후 발동
            # ① RSI 이윤 방향이면 달리는 중 → 보류
            # ② 직전 N봉 연속 이윤 방향이면 가속 중 → 보류
            # 둘 다 OFF 또는 둘 다 미충족 → 즉시 발동 (기존 동작)
            _smart_defer = False
            _cfg = self.config
            _rsi_chk = getattr(_cfg, "be_lock_smart_rsi_check", True)
            _candle_chk = getattr(_cfg, "be_lock_smart_candle_check", True)
            if _rsi_chk or _candle_chk:
                try:
                    _sm_raw = self._get_mtf_kline(pos.market, "5", limit=20, ttl=30.0)
                    if _sm_raw and len(_sm_raw) >= 6:
                        # ① RSI 체크
                        if _rsi_chk:
                            _sm_closes = [float(r[4]) for r in _sm_raw if len(r) >= 5]
                            if len(_sm_closes) >= 14:
                                _gains, _losses = [], []
                                for _i in range(1, len(_sm_closes)):
                                    _d = _sm_closes[_i] - _sm_closes[_i - 1]
                                    _gains.append(max(0, _d))
                                    _losses.append(max(0, -_d))
                                _ag = sum(_gains[-14:]) / 14.0
                                _al = sum(_losses[-14:]) / 14.0
                                _rsi = 100.0 - (100.0 / (1.0 + _ag / _al)) if _al > 0 else 100.0
                                _rsi_long_min = float(getattr(_cfg, "be_lock_smart_rsi_long_min", 55.0))
                                _rsi_short_max = float(getattr(_cfg, "be_lock_smart_rsi_short_max", 45.0))
                                if pos.direction == "LONG" and _rsi >= _rsi_long_min:
                                    _smart_defer = True
                                elif pos.direction == "SHORT" and _rsi <= _rsi_short_max:
                                    _smart_defer = True
                        # ② 봉 연속 체크
                        if _candle_chk and not _smart_defer:
                            _n = int(getattr(_cfg, "be_lock_smart_candle_count", 3))
                            _recent = _sm_raw[-_n:]
                            if len(_recent) >= _n:
                                if pos.direction == "LONG":
                                    _all_up = all(float(r[4]) > float(r[1]) for r in _recent if len(r) >= 5)
                                    if _all_up:
                                        _smart_defer = True
                                else:
                                    _all_down = all(float(r[4]) < float(r[1]) for r in _recent if len(r) >= 5)
                                    if _all_down:
                                        _smart_defer = True
                except Exception as _sm_exc:
                    logger.debug("[FOCUS] smart BE check failed (proceed to lock): %s", _sm_exc)
            # ★ [2026-06-20] peak반납 failsafe — smart_defer 가 '달리는 중'이라며 BE락을 무기한 보류하다
            #   peak 를 토하고 원SL까지 흘러내리는 누수(저널: 락 안 걸린 25건 -$35.71) 차단.
            #   peak 가 trigger 를 넘었던 적 있고 현재 그 peak 에서 giveback_pct%p 이상 반납했으면 보류 해제 → 그 tick 에 BE락.
            #   (반납 전까진 여전히 보류 = 러너는 사람이 수확. ★peak 는 peak_profit_price 로 환산 — pos.peak_profit_pct 필드 없음(NameError 방지).)
            if _smart_defer:
                _gb = float(getattr(_cfg, "be_lock_smart_defer_giveback_pct", 0.3) or 0.0)
                if _gb > 0 and pos.entry_price > 0 and pos.peak_profit_price > 0:
                    if pos.direction == "LONG":
                        _peak_pct = (pos.peak_profit_price / pos.entry_price - 1) * 100
                    else:
                        _peak_pct = (1 - pos.peak_profit_price / pos.entry_price) * 100
                    if _peak_pct >= trigger_pct and (_peak_pct - pnl_pct) >= _gb:
                        _smart_defer = False
                        logger.info(
                            "[FOCUS] 🔒 Smart BE FAILSAFE %s %s — peak +%.2f%% 에서 %.2f%%p 반납 → 보류 해제·BE락",
                            pos.direction, pos.market, _peak_pct, _peak_pct - pnl_pct,
                        )
            if _smart_defer:
                logger.debug("[FOCUS] 🔓 Smart BE DEFER %s %s pnl=+%.2f%% — 모멘텀 이윤 방향 (보류)",
                             pos.direction, pos.market, pnl_pct)
                # 발동 보류 — 다음 tick에서 재확인
                # trailing은 기존 SL 유지, peak 추적은 계속됨
                return

            new_sl = pos.entry_price
            should_lock = False

            if pos.direction == "LONG" and new_sl > pos.sl:
                should_lock = True
            elif pos.direction == "SHORT" and new_sl < pos.sl:
                should_lock = True

            if should_lock:
                old_sl = pos.sl
                pos.sl = new_sl
                pos.breakeven_locked = True
                pos.be_locked_ts = time.time()   # [BE Stall Exit 2026-04-19] 락 발동 시각
                logger.info(
                    "[FOCUS] 🔒 Dynamic SL → BREAKEVEN %s %s: SL $%.2f→$%.2f (profit +%.2f%%)",
                    pos.direction, pos.market, old_sl, pos.sl, pnl_pct,
                )
                self._update_bybit_sl(pos)
                self._save_config()
                return

        # ── Stage 2: 수익 추적 (breakeven 잠금 이후) ──
        if pos.breakeven_locked and pos.peak_profit_price > 0:
            if pos.direction == "LONG":
                peak_gain = pos.peak_profit_price / pos.entry_price - 1  # e.g. 0.006 = 0.6%
                trail_offset = peak_gain * preserve_ratio
                new_sl = pos.entry_price * (1 + trail_offset)
                if new_sl > pos.sl:  # SL을 올린다 (tighten)
                    old_sl = pos.sl
                    pos.sl = round(new_sl, 8)
                    peak_pnl = peak_gain * 100
                    locked_pnl = trail_offset * 100
                    logger.info(
                        "[FOCUS] 📈 Dynamic SL trail %s %s: SL $%.2f→$%.2f "
                        "(peak +%.2f%%, locked +%.2f%%)",
                        pos.direction, pos.market, old_sl, pos.sl,
                        peak_pnl, locked_pnl,
                    )
                    self._update_bybit_sl(pos)
                    self._save_config()
            else:  # SHORT
                peak_gain = 1 - pos.peak_profit_price / pos.entry_price  # e.g. 0.006 = 0.6%
                trail_offset = peak_gain * preserve_ratio
                new_sl = pos.entry_price * (1 - trail_offset)
                if new_sl < pos.sl:  # SL을 내린다 (tighten for SHORT)
                    old_sl = pos.sl
                    pos.sl = round(new_sl, 8)
                    peak_pnl = peak_gain * 100
                    locked_pnl = trail_offset * 100
                    logger.info(
                        "[FOCUS] 📉 Dynamic SL trail %s %s: SL $%.2f→$%.2f "
                        "(peak +%.2f%%, locked +%.2f%%)",
                        pos.direction, pos.market, old_sl, pos.sl,
                        peak_pnl, locked_pnl,
                    )
                    self._update_bybit_sl(pos)
                    self._save_config()

        # ★ #6 [2026-04-26] Multi-Stage BE Lock — peak 단계별 lock 강화
        # ★ #3 [2026-04-26 형 fix] 현재가 가드 — Bybit SL update race 방지 (4-25 RAVE/AXS 사례)
        if pos.breakeven_locked and getattr(self.config, "multi_be_lock_enabled", True) and pos.peak_profit_price > 0:
            if pos.direction == "LONG":
                peak_pct = (pos.peak_profit_price / pos.entry_price - 1) * 100
            else:
                peak_pct = (1 - pos.peak_profit_price / pos.entry_price) * 100
            target_lock_pct = self._multi_be_lock_target(peak_pct, pos)
            if target_lock_pct > -999:
                if pos.direction == "LONG":
                    new_sl_ms = pos.entry_price * (1 + target_lock_pct / 100.0)
                    if new_sl_ms > pos.sl:
                        # ★ 현재가 가드 — 가격이 새 SL 아래로 빠진 순간이면 즉시 close 위험
                        if price <= new_sl_ms:
                            logger.warning("[FOCUS] ⚠ Multi-Stage BE Lock SKIP %s LONG: price $%.4f <= new_sl $%.4f (race 방지)",
                                           pos.market, price, new_sl_ms)
                        else:
                            old_sl = pos.sl
                            pos.sl = round(new_sl_ms, 8)
                            logger.info("[FOCUS] 🔒 Multi-Stage BE Lock LONG %s: SL $%.4f→$%.4f (peak +%.2f%%, lock +%.2f%%)",
                                        pos.market, old_sl, pos.sl, peak_pct, target_lock_pct)
                            self._update_bybit_sl(pos)
                            self._save_config()
                else:
                    new_sl_ms = pos.entry_price * (1 - target_lock_pct / 100.0)
                    if new_sl_ms < pos.sl:
                        # ★ 현재가 가드 — 가격이 새 SL 위로 빠진 순간이면 즉시 close 위험
                        if price >= new_sl_ms:
                            logger.warning("[FOCUS] ⚠ Multi-Stage BE Lock SKIP %s SHORT: price $%.4f >= new_sl $%.4f (race 방지)",
                                           pos.market, price, new_sl_ms)
                        else:
                            old_sl = pos.sl
                            pos.sl = round(new_sl_ms, 8)
                            logger.info("[FOCUS] 🔒 Multi-Stage BE Lock SHORT %s: SL $%.4f→$%.4f (peak +%.2f%%, lock +%.2f%%)",
                                        pos.market, old_sl, pos.sl, peak_pct, target_lock_pct)
                            self._update_bybit_sl(pos)
                            self._save_config()

    # ────────────────────────────────────────────────────────
    # Trailing TP (망치 손잡이 방어): Peak 뒤를 따라 TP를 내려
    # SERVER_SL exit 시 $1 미만 수익 구간(48%)의 포착률 개선
    # ────────────────────────────────────────────────────────
    def _apply_trailing_tp(self, pos: FocusPosition, price: float):
        """Trailing TP (TP Trail-Down) — 망치 손잡이 방어.

        Peak이 TP1 가까이 갈수록 TP가 peak 뒤를 따라 내려옴.
        wick이 조금만 돌려줘도 TP 체결 → peak 근처 이익 확보.

        원칙:
        - Only-tighten (TP는 가까워지기만, 절대 멀어지지 않음)
        - 현재가 "반대편" 유지 (LONG: TP>price, SHORT: TP<price) — 즉시 체결 방지
        - TP1 부분청산 이전에만 (partial_done=False)
        - original_tp1 기준으로 진행도 계산 (Decay·변경 영향 안 받음)
        """
        if not self.config.trailing_tp_enabled:
            return
        if pos.partial_done:
            return
        if pos.entry_price <= 0 or pos.peak_profit_price <= 0:
            return
        if pos.tp1 <= 0:
            return
        # original_tp1이 없으면 현재 tp1을 최초값으로 기록
        if pos.original_tp1 <= 0:
            pos.original_tp1 = pos.tp1

        # Peak·TP1 진행률 계산 (수익률 %)
        if pos.direction == "LONG":
            peak_pct = (pos.peak_profit_price / pos.entry_price - 1) * 100
            tp1_pct = (pos.original_tp1 / pos.entry_price - 1) * 100
        else:  # SHORT
            peak_pct = (1 - pos.peak_profit_price / pos.entry_price) * 100
            tp1_pct = (1 - pos.original_tp1 / pos.entry_price) * 100

        if tp1_pct <= 0 or peak_pct <= 0:
            return

        progress = peak_pct / tp1_pct  # 0.0 ~ 1.0+
        if progress < self.config.trailing_tp_min_progress:
            return

        # Tier별 follow ratio
        if progress < 0.60:
            follow = self.config.trailing_tp_follow_low
        elif progress < 0.80:
            follow = self.config.trailing_tp_follow_mid
        else:
            follow = self.config.trailing_tp_follow_high

        # 새 TP 위치 = entry × (1 ± peak_pct × follow / 100)
        new_tp_pct = peak_pct * follow
        if pos.direction == "LONG":
            new_tp = pos.entry_price * (1 + new_tp_pct / 100)
        else:
            new_tp = pos.entry_price * (1 - new_tp_pct / 100)

        # 안전장치 1: 즉시체결 방지 — new_tp는 현재가 반대편에 있어야
        # (LONG: TP > price, SHORT: TP < price).
        # wick이 작아서 price ≈ peak인 tick에는 skip, 크게 되돌림 오면 발동.
        if pos.direction == "LONG" and new_tp <= price:
            return
        if pos.direction == "SHORT" and new_tp >= price:
            return

        # 안전장치 2: Only-tighten — TP는 가까워지기만 (절대 멀어지지 않음)
        if pos.direction == "LONG" and new_tp >= pos.tp1:
            return
        if pos.direction == "SHORT" and new_tp <= pos.tp1:
            return

        old_tp = pos.tp1
        pos.tp1 = round(new_tp, 8)
        logger.info(
            "[FOCUS] 🎯 Trailing TP %s %s: TP $%.4f→$%.4f "
            "(peak %.2f%%, progress %.0f%%, follow %.0f%%)",
            pos.direction, pos.market, old_tp, pos.tp1,
            peak_pct, progress * 100, follow * 100,
        )
        self._update_bybit_tp(pos)
        self._save_config()

    def _update_bybit_tp(self, pos: FocusPosition):
        """Bybit에 TP만 갱신 (SL 유지). _update_bybit_sl과 동일 패턴."""
        for _try in range(2):
            try:
                self._get_client().set_trading_stop(
                    pos.market, take_profit=pos.tp1, stop_loss=pos.sl
                )
                return
            except Exception as exc:
                logger.warning(
                    "[FOCUS] Bybit TP update failed %s (attempt %d/2): %s",
                    pos.market, _try + 1, exc,
                )
                if _try == 0:
                    import time as _t
                    _t.sleep(0.5)

    # ────────────────────────────────────────────────────────
    # [2026-05-21 부모] Day Direction + H4 PA Snapshot routine
    # ────────────────────────────────────────────────────────
    def _update_day_direction(self):
        """매일 09:00 KST 도달 시 1회 — BTC H4 trend + ADX → day_direction (LONG/SHORT/NEUTRAL)."""
        if not getattr(self.config, "day_direction_enabled", True):
            return
        try:
            import datetime as _dt
            now_utc = _dt.datetime.now(_dt.timezone.utc)
            kst_now = now_utc + _dt.timedelta(hours=9)
            today_kst = kst_now.strftime("%Y-%m-%d")
            target_hour = float(getattr(self.config, "day_direction_hour_kst", 9.0))
            kst_hour_frac = kst_now.hour + kst_now.minute / 60.0
            if kst_hour_frac < target_hour:
                return
            if self.day_direction_date == today_kst:
                return  # 오늘 이미 평가 완료

            # BTC H4 trend + ADX 평가
            from app.strategy.greenpen.market_structure import analyze_structure as _as
            from app.strategy.greenpen.pa_detector import OHLCV as _O
            raw = self._get_mtf_kline("BTCUSDT", "240", limit=40)
            if not raw or len(raw) < 20:
                self.day_direction = "NEUTRAL"
                self.day_direction_reason = "BTC H4 data insufficient"
            else:
                candles = [_O(float(r[1]), float(r[2]), float(r[3]), float(r[4])) for r in raw if len(r) >= 5]
                st = _as(candles)
                trend = st.trend.value if hasattr(st.trend, 'value') else str(st.trend)
                # [2026-05-23 부모] H4 ATR(등락폭) → 그날 시장 변동성 기준 + TP1/TP2 예상
                try:
                    from app.manager.entry_expectation import atr_from_ohlcv as _atr_oh
                    _h4_atr = _atr_oh(candles)
                    _h4_price = candles[-1].close if candles else 0.0
                    self.day_h4_atr_pct = round(_h4_atr / _h4_price * 100.0, 3) if _h4_price > 0 else 0.0
                    _tp1m = float(getattr(self.config, "cycle_tp1_mult", 1.8))
                    _tp2m = float(getattr(self.config, "cycle_tp2_mult", 3.0))
                    self.day_tp1_expected_pct = round(self.day_h4_atr_pct * _tp1m, 3)
                    self.day_tp2_expected_pct = round(self.day_h4_atr_pct * _tp2m, 3)
                except Exception as _atr_exc:
                    logger.debug("[FOCUS] day H4 ATR calc failed: %s", _atr_exc)
                try:
                    _adx_result = self._fetch_primary_adx("BTCUSDT")
                    adx = float(_adx_result.get("adx", 0.0)) if isinstance(_adx_result, dict) else 0.0
                except Exception:
                    adx = 0.0
                min_adx = float(getattr(self.config, "day_direction_btc_adx_min", 18.0))
                if adx < min_adx:
                    self.day_direction = "NEUTRAL"
                    self.day_direction_reason = f"BTC ADX={adx:.1f} < {min_adx} (추세 미약)"
                elif trend == "UPTREND":
                    self.day_direction = "LONG"
                    self.day_direction_reason = f"BTC H4 UPTREND + ADX={adx:.1f}"
                elif trend == "DOWNTREND":
                    self.day_direction = "SHORT"
                    self.day_direction_reason = f"BTC H4 DOWNTREND + ADX={adx:.1f}"
                else:
                    self.day_direction = "NEUTRAL"
                    self.day_direction_reason = f"BTC H4 SIDEWAYS + ADX={adx:.1f}"

            self.day_direction_date = today_kst
            logger.info("[FOCUS] 🌅 Day Direction (%s KST %.1f시): %s — %s | H4 등락폭=%.2f%% → 기대 TP1=%.2f%% TP2=%.2f%%",
                        today_kst, target_hour, self.day_direction, self.day_direction_reason,
                        self.day_h4_atr_pct, self.day_tp1_expected_pct, self.day_tp2_expected_pct)
        except Exception as exc:
            logger.warning("[FOCUS] day_direction update failed: %s", exc)

    def _update_h4_pa_snapshot(self):
        """매 4시간 KST 시점 도달 시 1회 — 모든 활성 코인 H4 PA + trend snapshot."""
        if not getattr(self.config, "h4_pa_snapshot_enabled", True):
            return
        try:
            import datetime as _dt
            import time as _time
            now_utc = _dt.datetime.now(_dt.timezone.utc)
            kst_now = now_utc + _dt.timedelta(hours=9)
            kst_hour = kst_now.hour
            hours_csv = str(getattr(self.config, "h4_pa_snapshot_hours_kst", "1,5,9,13,17,21"))
            try:
                target_hours = {int(h.strip()) for h in hours_csv.split(",") if h.strip()}
            except Exception:
                target_hours = {1, 5, 9, 13, 17, 21}
            if kst_hour not in target_hours:
                return
            if self.h4_pa_snapshot_last_hour == kst_hour:
                return  # 이 시간대 이미 snapshot 완료

            # snapshot 진행 — Scanner 의 candidate markets 사용
            from app.strategy.greenpen.market_structure import analyze_structure as _as
            from app.strategy.greenpen.pa_detector import OHLCV as _O, detect_pa_patterns as _dp
            snapshot: Dict[str, Dict[str, Any]] = {}
            try:
                # _get_scanner_candidates 또는 비슷한 함수 — 없으면 self._scanner_universe 등 polled
                # 안전 fallback: positions 의 markets + popular tickers
                markets_set = set()
                for pos in self.positions.values():
                    if getattr(pos, "market", ""):
                        markets_set.add(pos.market)
                # 보유 코인 + BTC/ETH/SOL 기본 + scanner universe (있으면)
                markets_set.update({"BTCUSDT", "ETHUSDT", "SOLUSDT", "XRPUSDT", "DOGEUSDT"})
                if hasattr(self, "_last_scanner_candidates"):
                    try:
                        for m in (self._last_scanner_candidates or []):
                            markets_set.add(m)
                    except Exception:
                        pass
            except Exception:
                markets_set = {"BTCUSDT", "ETHUSDT", "SOLUSDT"}

            for market in list(markets_set)[:30]:  # 상한 30 — 부하 보호
                try:
                    raw = self._get_mtf_kline(market, "240", limit=30)
                    if not raw or len(raw) < 10:
                        continue
                    candles = [_O(float(r[1]), float(r[2]), float(r[3]), float(r[4])) for r in raw if len(r) >= 5]
                    st = _as(candles)
                    trend = st.trend.value if hasattr(st.trend, 'value') else str(st.trend)
                    pa_list = _dp(candles)
                    pa_label = "none"
                    if pa_list:
                        first = pa_list[0]
                        pat = getattr(first, "pattern", None)
                        pa_label = pat.value if pat and hasattr(pat, "value") else str(pat or "none")
                    snapshot[market] = {"trend": trend, "pa": pa_label}
                except Exception:
                    continue

            self.h4_pa_snapshot = snapshot
            self.h4_pa_snapshot_last_hour = kst_hour
            self.h4_pa_snapshot_ts = _time.time()
            # 강신호 markets (pa != none) 정렬
            strong = [(m, d) for m, d in snapshot.items() if d.get("pa", "none") != "none"]
            strong_str = ", ".join(f"{m}:{d['trend'][:4]}/{d['pa']}" for m, d in strong[:5])
            logger.info("[FOCUS] 🕐 H4 PA Snapshot (%02d:00 KST): %d coins, strong=%s",
                        kst_hour, len(snapshot), strong_str if strong else "none")
        except Exception as exc:
            logger.warning("[FOCUS] h4_pa_snapshot update failed: %s", exc)

    # ────────────────────────────────────────────────────────
    # Morning Shield (아침 방패): 06:00 KST 수익 보호
    # ────────────────────────────────────────────────────────
    def _apply_morning_shield(self, pos: FocusPosition, price: float):
        """Morning Shield: 06:00-06:59 KST에 수익 포지션 SL을 조여 야간 이익 보호.

        아시아 세션 오픈(07:00-09:30 KST) 전에 SL을 올려서
        밤새 번 수익이 아침 변동성에 날아가는 것을 방지.

        Rules:
          - profit >= 1%: SL을 이익의 morning_shield_lock_pct% 보존 위치로 이동
          - profit 0.3%-1%: SL을 breakeven(진입가)으로 이동
          - profit < 0.3%: 터치하지 않음 (기존 SL이 보호)
          - 하루 1회만 적용 (morning_shield_date로 추적)
          - SL은 절대 역방향 이동 안 함 (only tighten)
        """
        import datetime as _dt

        # 1) 시간 체크: 06:00-06:59 KST = 21:00-21:59 UTC
        now_utc = _dt.datetime.now(_dt.timezone.utc)
        kst_hour = (now_utc.hour + 9) % 24
        if kst_hour != 6:
            return

        # 2) 오늘 이미 적용했는지 체크 (KST 날짜 기준)
        kst_now = now_utc + _dt.timedelta(hours=9)
        today_kst = kst_now.strftime("%Y-%m-%d")
        if pos.morning_shield_date == today_kst:
            return

        # 3) 현재 수익률 계산
        if pos.entry_price <= 0:
            return
        if pos.direction == "LONG":
            pnl_pct = (price / pos.entry_price - 1) * 100
        else:  # SHORT
            pnl_pct = (1 - price / pos.entry_price) * 100

        # 4) 수익 구간별 SL 결정
        if pnl_pct >= 1.0:
            # Lock morning_shield_lock_pct% of gains
            lock_ratio = self.config.morning_shield_lock_pct / 100.0
            if pos.direction == "LONG":
                gain = price - pos.entry_price
                new_sl = pos.entry_price + gain * lock_ratio
            else:  # SHORT
                gain = pos.entry_price - price
                new_sl = pos.entry_price - gain * lock_ratio
            action = f"lock_{self.config.morning_shield_lock_pct:.0f}%"

        elif pnl_pct >= 0.3:
            # Move to breakeven
            new_sl = pos.entry_price
            action = "breakeven"

        else:
            # 수익 미미 — SL 터치 안 함, 적용 완료 마킹만
            pos.morning_shield_date = today_kst
            logger.info(
                "[FOCUS] Morning Shield: %s %s profit +%.2f%% < 0.3%% — no SL change",
                pos.direction, pos.market, pnl_pct,
            )
            return

        # 5) "SL only tightens" rule
        sl_would_tighten = False
        if pos.direction == "LONG" and new_sl > pos.sl:
            sl_would_tighten = True
        elif pos.direction == "SHORT" and new_sl < pos.sl:
            sl_would_tighten = True

        if not sl_would_tighten:
            # 현재 SL이 이미 더 좋음 — 유지
            pos.morning_shield_date = today_kst
            logger.info(
                "[FOCUS] Morning Shield: %s %s SL $%.2f already better than shield $%.2f — kept",
                pos.direction, pos.market, pos.sl, new_sl,
            )
            return

        # [2026-05-29 부모 7번째 fix] 진입 직후 grace — Bybit 슬리피지 peak 노이즈 차단
        _grace_sec_m = float(getattr(self.config, "be_lock_grace_sec", 60.0) or 0.0)
        if _grace_sec_m > 0 and pos.entry_ts > 0 and (time.time() - pos.entry_ts) < _grace_sec_m:
            return

        # 6) SL 변경 적용
        old_sl = pos.sl
        pos.sl = round(new_sl, 8)
        pos.morning_shield_date = today_kst
        # ★ [2026-06-08 부모] 근본 fix: SL이 실제 본전 위(LONG)/아래(SHORT)로 올라간 후에만 BE 락 ON
        #   (ALLO 가짜 BE — 락=True인데 SL 본전 아래 → -23% 방치 차단. "락=보호 보장")
        _be_at_breakeven = (pos.direction == "LONG" and pos.sl >= pos.entry_price) or \
                           (pos.direction == "SHORT" and pos.sl <= pos.entry_price)
        if not pos.breakeven_locked and pnl_pct >= self.config.breakeven_trigger_pct and _be_at_breakeven:
            pos.breakeven_locked = True
            pos.be_locked_ts = time.time()   # [BE Stall Exit 2026-04-19] 락 발동 시각

        logger.info(
            "[FOCUS] Morning Shield: %s %s SL $%.2f -> $%.2f (%s, profit +%.2f%%)",
            pos.direction, pos.market, old_sl, pos.sl, action, pnl_pct,
        )
        self._update_bybit_sl(pos)
        self._save_config()

        try:
            self._notify(
                f"Morning Shield\n"
                f"{pos.direction} {pos.market}\n"
                f"SL: ${old_sl:.2f} -> ${pos.sl:.2f}\n"
                f"Action: {action} (profit +{pnl_pct:.2f}%)"
            )
        except Exception as exc:
            logger.debug("[FOCUS] self._notify failed: %s", exc)

    def _apply_event_shield(self, pos: FocusPosition, price: float):
        """Event Shield: 경제이벤트(CPI 등) 윈도우 진입 시 수익 포지션 SL 조임.

        [2026-06-08 부모] "CPI 때 E-STOP 손 올릴까 걱정 → 봇이 대신."
        Morning Shield 형제 — 트리거만 '시간대(06시)' 대신 '이벤트 윈도우(±N분)'.
        부모님 "더 강하게": lock_pct 70% (Morning Shield 50%보다 강한 수익 보호).

        Rules (only tighten):
          - profit >= 1%: SL을 이익의 event_shield_lock_pct%(=70%) 보존 위치로
          - profit 0.3%-1%: SL을 breakeven(진입가)으로
          - profit < 0.3%: 터치 안 함 (기존 SL이 보호) — ★마킹 X, 윈도우 내 수익 오르면 재평가
          - 이벤트별 1회 (event_shield_done = 라벨) — ★실제 SL을 조였을 때만 소진
        """
        label = self._event_shield_label()
        if not label:
            return
        if pos.event_shield_done == label:
            return  # 이 이벤트는 이미 적용함
        if pos.entry_price <= 0:
            return

        if pos.direction == "LONG":
            pnl_pct = (price / pos.entry_price - 1) * 100
        else:  # SHORT
            pnl_pct = (1 - price / pos.entry_price) * 100

        if pnl_pct >= 1.0:
            lock_ratio = self.config.event_shield_lock_pct / 100.0
            if pos.direction == "LONG":
                gain = price - pos.entry_price
                new_sl = pos.entry_price + gain * lock_ratio
            else:  # SHORT
                gain = pos.entry_price - price
                new_sl = pos.entry_price - gain * lock_ratio
            action = f"lock_{self.config.event_shield_lock_pct:.0f}%"
        elif pnl_pct >= 0.3:
            new_sl = pos.entry_price
            action = "breakeven"
        else:
            # ── [2026-06-08 부모 지시 · 형 리뷰 fix] 이익 < 0.3% = 아직 조일 이익이 없음 → 넘기되 *마킹하지 않는다* ──
            #   ★ 옛 누수: 여기서 event_shield_done 을 찍으면 이벤트 윈도우(前 window+lead + 後 window ≈ 45분) 동안
            #     진입 직후 노이즈(이익 0.1%) 한 번에 1회 소진 → 같은 윈도우에서 이익이 1%로 올라도
            #     맨 위 `if pos.event_shield_done == label: return` 에 막혀 SL 조임을 영영 못 함.
            #     (게다가 이 경로는 아래 grace(60초) 체크보다 앞 = 진입 직후 슬리피지 구간까지 소진시킴)
            #   → 의도("이벤트 변동성 전 미리 이익 지킴")와 정반대로, 하필 이익이 막 붙기 시작할 때 잠겼다.
            #   fix: 마킹 제거 + info→debug(윈도우 내내 매 tick 찍힐 수 있어 스팸 방지). 실제 SL 조였을 때만 소진.
            logger.debug(
                "[FOCUS] Event Shield(%s): %s %s profit +%.2f%% < 0.3%% — 대기(미소진, 수익 오르면 재평가)",
                label, pos.direction, pos.market, pnl_pct,
            )
            return

        # only tighten
        sl_would_tighten = (
            (pos.direction == "LONG" and new_sl > pos.sl)
            or (pos.direction == "SHORT" and new_sl < pos.sl)
        )
        if not sl_would_tighten:
            pos.event_shield_done = label
            logger.info(
                "[FOCUS] Event Shield(%s): %s %s SL $%.4f already better than shield $%.4f — kept",
                label, pos.direction, pos.market, pos.sl, new_sl,
            )
            return

        # 진입 직후 grace — Bybit 슬리피지 peak 노이즈 차단
        _grace_sec_e = float(getattr(self.config, "be_lock_grace_sec", 60.0) or 0.0)
        if _grace_sec_e > 0 and pos.entry_ts > 0 and (time.time() - pos.entry_ts) < _grace_sec_e:
            return

        old_sl = pos.sl
        pos.sl = round(new_sl, 8)
        pos.event_shield_done = label
        # ★ [2026-06-08 부모] 근본 fix: SL이 실제 본전 위(LONG)/아래(SHORT)로 올라간 후에만 BE 락 ON
        #   (ALLO 가짜 BE — 락=True인데 SL 본전 아래 → -23% 방치 차단. "락=보호 보장")
        _be_at_breakeven = (pos.direction == "LONG" and pos.sl >= pos.entry_price) or \
                           (pos.direction == "SHORT" and pos.sl <= pos.entry_price)
        if not pos.breakeven_locked and pnl_pct >= self.config.breakeven_trigger_pct and _be_at_breakeven:
            pos.breakeven_locked = True
            pos.be_locked_ts = time.time()

        logger.info(
            "[FOCUS] Event Shield(%s): %s %s SL $%.4f -> $%.4f (%s, profit +%.2f%%)",
            label, pos.direction, pos.market, old_sl, pos.sl, action, pnl_pct,
        )
        self._update_bybit_sl(pos)
        self._save_config()

        try:
            self._notify(
                f"Event Shield ({label})\n"
                f"{pos.direction} {pos.market}\n"
                f"SL: ${old_sl:.4f} -> ${pos.sl:.4f}\n"
                f"Action: {action} (profit +{pnl_pct:.2f}%)"
            )
        except Exception as exc:
            logger.debug("[FOCUS] self._notify failed: %s", exc)

    def _apply_macro_regime_exit(self, pos: FocusPosition, price: float):
        """★ [2026-06-06 부모] 레짐 역행 시 보유분 즉시 탈출 — SL 을 현재가 가까운 출구로 당김.
        "불난 아파트 = 엘리베이터 모든 버튼 눌러 탈출." 레짐이 확실히 역행이면 SL까지 미련 X.
        Morning Shield 패턴 재활용 (only tighten + grace + _update_bybit_sl). 트리거만 '레짐 역행'.
        안전: STRONG(N/10)만 + only tighten + grace(방금진입 제외) + default OFF + 시뮬 후 ON.
          - RISK_ON(상승 확실) + SHORT 보유 = 역행 / RISK_OFF(하락 확실) + LONG 보유 = 역행
          - SL→현재가±cushion: 손실中=소손절 유도 / 수익中=소익절 락 / 반등하면 안 맞고 본전 (즉시 시장가보다 안전)
        """
        if not getattr(self.config, "macro_exit_enabled", False):
            return
        if pos.entry_price <= 0 or pos.sl <= 0:
            return
        # grace — 진입 직후 슬리피지 노이즈 제외 (부모님 "10분~1시간 전 진입"이 대상이라 짧게)
        _grace = float(getattr(self.config, "be_lock_grace_sec", 60.0) or 0.0)
        if _grace > 0 and pos.entry_ts > 0 and (time.time() - pos.entry_ts) < _grace:
            return
        # 레짐 역행 '확실' 판정 — STRONG (breadth N/10 일제) 만 (가짜 화재경보 방어)
        mc = self._macro_compass()
        state = mc.get("state", "NEUTRAL")
        up, down = int(mc.get("up", 0) or 0), int(mc.get("down", 0) or 0)
        _strong = int(getattr(self.config, "macro_exit_breadth_min", 8))
        adverse = ((pos.direction == "SHORT" and state == "RISK_ON" and up >= _strong) or
                   (pos.direction == "LONG" and state == "RISK_OFF" and down >= _strong))
        if not adverse:
            return
        # ★ [2026-06-06 ALLO/TON] 개별 강세 예외 — 거시역행이어도 이 코인이 강세(수익 中)면 안 자름.
        #   ALLO +44%(폭등 라이딩)/TON +0.27% = 거시 이기는 중 → 보유유지. SOL -11% = 개별도 무너짐 → 탈출.
        #   "견디는 힘 = 개별 강세 유지"(부모님). 거시역행 + 개별약세(손실) 이중악재만 탈출.
        if getattr(self.config, "macro_exit_strong_coin_exempt", True):
            try:
                _roe = (price - pos.entry_price) / pos.entry_price * 100.0
                if pos.direction == "SHORT":
                    _roe = -_roe
                _exempt_min = float(getattr(self.config, "macro_exit_exempt_min_roe", 0.0))
                if _roe > _exempt_min:
                    logger.info("[FOCUS] 🧭 Macro Exit 면제(개별강세): %s %s ROE%+.2f%%>%.2f%% — 거시역행이나 코인 강세, 보유 유지",
                                pos.direction, pos.market, _roe, _exempt_min)
                    return
            except Exception as _e:
                logger.debug("[FOCUS] macro_exit exempt calc failed: %s", _e)
        # SL 을 현재가 가까운 출구로 (cushion)
        _cu = float(getattr(self.config, "macro_exit_sl_cushion_pct", 0.15) or 0.15) / 100.0
        new_sl = price * (1 - _cu) if pos.direction == "LONG" else price * (1 + _cu)
        # only tighten — SL 후퇴 금지 (이미 더 가까우면 유지)
        if pos.direction == "LONG" and new_sl <= pos.sl:
            return
        if pos.direction == "SHORT" and new_sl >= pos.sl:
            return
        old_sl = pos.sl
        pos.sl = round(new_sl, 8)
        logger.info("[FOCUS] 🚨 Macro Regime Exit: %s %s 레짐역행(%s up%d/dn%d≥%d) → SL %.6f→%.6f (가까운출구)",
                    pos.direction, pos.market, state, up, down, _strong, old_sl, pos.sl)
        self._update_bybit_sl(pos)
        self._save_config()
        try:
            self._notify(f"🚨 레짐역행 탈출 ({state})\n{pos.direction} {pos.market}\nSL: {old_sl:.6f} → {pos.sl:.6f} (가까운 출구)")
        except Exception as _e:
            logger.debug("[FOCUS] macro_exit notify failed: %s", _e)

    def _is_morning_guard_active(self) -> bool:
        """Morning Guard: 07:00-09:30 KST 진입 제한 활성 여부.

        위험 시간대에 conviction threshold를 morning_guard_conviction_boost만큼 올려
        확신도 낮은 진입을 차단.
        """
        # [2026-04-18] user 요청 "24시간 돌아가게 다 풀자" — Morning Guard 완전 비활성화
        return False
        if not self.config.morning_guard_enabled:
            return False

        import datetime as _dt
        now_utc = _dt.datetime.now(_dt.timezone.utc)
        kst_now = now_utc + _dt.timedelta(hours=9)
        kst_hour_frac = kst_now.hour + kst_now.minute / 60.0

        # 07:00 KST (= 7.0) ~ morning_guard_end_hour_kst (default 9.5 = 09:30)
        return 7.0 <= kst_hour_frac < self.config.morning_guard_end_hour_kst

    def _event_shield_label(self) -> Optional[str]:
        """현재(KST)가 어떤 경제이벤트 윈도우(±window분) 안이면 그 이벤트 라벨 반환, 아니면 None.

        [2026-06-08 부모] CPI 등 시각 박힌 이벤트 전후 변동성 구간 보호.
        이벤트 시각 소스 = ①수동 입력(event_shield_times_kst CSV) + ②자동 fetch
        (ForexFactory USD High impact, event_shield_auto_fetch). 둘의 합집합 검사.
        반환값(라벨)으로 ①신규진입 hard block ②SL 조임(이벤트별 1회) 둘 다 판정.

        ★ 비대칭 윈도우 [2026-06-08 부모 "슬리피지 시간만큼 먼저"]: 군중 봇이 다 ±window분에
        똑같이 반응하면 그 경계에서 슬리피지 터짐 → 우리는 이벤트 前 (window+lead)분부터,
        後 window분까지. 즉 진입차단·SL조임을 군중보다 lead분 먼저 시작.
        """
        if not self.config.event_shield_enabled:
            return None
        import datetime as _dt
        kst_now = (_dt.datetime.now(_dt.timezone.utc) + _dt.timedelta(hours=9)).replace(tzinfo=None)
        _w = max(0.0, float(self.config.event_shield_window_min or 0.0))
        _lead = max(0.0, float(getattr(self.config, "event_shield_lead_min", 0.0) or 0.0))
        win_after = _dt.timedelta(minutes=_w)              # 이벤트 後
        win_before = _dt.timedelta(minutes=_w + _lead)     # 이벤트 前 — 슬리피지 리드만큼 더 일찍

        # 이벤트 시각 소스 = 수동 입력 + 자동 fetch (둘 다 "YYYY-MM-DD HH:MM" KST)
        labels = []
        raw = (self.config.event_shield_times_kst or "").strip()
        if raw:
            labels.extend(t.strip() for t in raw.split(",") if t.strip())
        if getattr(self.config, "event_shield_auto_fetch", True):
            try:
                from app.manager import economic_calendar as _econ
                _econ.maybe_refresh()   # ttl(6h) 만료 시 백그라운드 fetch — 논블로킹
                labels.extend(_econ.get_event_times())
            except Exception as _ec_err:
                logger.debug("[FOCUS] econ calendar unavailable: %s", _ec_err)

        for label in labels:
            try:
                ev = _dt.datetime.strptime(label, "%Y-%m-%d %H:%M")
            except ValueError:
                continue  # 형식 오류 토큰은 무시 (안전)
            if (ev - win_before) <= kst_now <= (ev + win_after):
                return label
        return None

    def _event_shield_events(self) -> list:
        """수동 입력 + 자동 fetch 이벤트 시각 합집합 (중복 제거·정렬)."""
        events = []
        raw = (self.config.event_shield_times_kst or "").strip()
        if raw:
            events.extend(t.strip() for t in raw.split(",") if t.strip())
        if getattr(self.config, "event_shield_auto_fetch", True):
            try:
                from app.manager import economic_calendar as _econ
                events.extend(_econ.get_event_times())
            except Exception:
                pass
        return sorted(set(events))

    def _event_shield_status(self) -> dict:
        """UI 헤더 카운트다운용 — 활성 여부 + 전체 이벤트 시각 + 윈도우(비대칭) 파라미터."""
        lab = self._event_shield_label()
        return {
            "enabled": bool(self.config.event_shield_enabled),
            "active": lab is not None,
            "label": lab or "",
            "events": self._event_shield_events(),
            "window_min": float(self.config.event_shield_window_min or 0.0),
            "lead_min": float(getattr(self.config, "event_shield_lead_min", 0.0) or 0.0),
        }

    # ────────────────────────────────────────────────────────
    # 양방향 평가 Phase 1 관찰 (2026-06-08 부모) — 진입 동작 변경 0
    # ────────────────────────────────────────────────────────
    def _observe_dual_direction(self, market: str, candles_primary: list,
                                zones, cur_dir: str, cur_conv: float) -> None:
        """봇 LONG 편향 근본fix 연구의 Phase 1 — 반대 방향 conviction 만 그림자로 계산해 기록.

        [2026-06-08 부모] "양쪽 다리 다 쓰는 봇." 진짜 뿌리 = 방향을 1개 먼저 정하고
        그 방향만 점수 매김 → SHORT 는 계산조차 안 받음. 양방향 평가(높은 쪽 진입)가 근본.
        ★ Phase 1 = 진입은 절대 안 바꾸고, "양방향 켜면 방향이 바뀔지/얼마나 더 높은지/추가 비용"
          만 측정. 현재 방향 점수(cur_conv)는 재사용 + *반대 방향만* 1회 추가 계산
          → 이 추가 계산 시간이 곧 양방향 ON 시의 증분 비용. runtime/dual_direction_observe.jsonl.
        """
        if not getattr(self.config, "dual_direction_observe", True):
            return
        try:
            cur = (cur_dir or "").upper()
            if cur not in ("LONG", "SHORT"):
                return
            opp = "SHORT" if cur == "LONG" else "LONG"
            _t0 = time.time()
            opp_conv = self._compute_conviction_score(market, candles_primary, opp, zones)
            opp_ms = (time.time() - _t0) * 1000.0

            long_conv = float(cur_conv) if cur == "LONG" else float(opp_conv)
            short_conv = float(cur_conv) if cur == "SHORT" else float(opp_conv)
            best_dir = "LONG" if long_conv >= short_conv else "SHORT"  # 동점=LONG (보수적 tie-break)
            best_conv = max(long_conv, short_conv)

            _price = 0.0
            try:
                if candles_primary:
                    _price = float(candles_primary[-1].close)
            except Exception:
                pass

            rec = {
                "ts": round(time.time(), 1),
                "market": market,
                "cur_dir": cur,                              # 봇이 실제 고른 방향 (signal 기반)
                "cur_conv": round(float(cur_conv), 1),       # 그 방향 점수 (순수 conviction, penalty 전)
                "long_conv": round(long_conv, 1),
                "short_conv": round(short_conv, 1),
                "best_dir": best_dir,                        # 양방향이면 골랐을 방향
                "best_conv": round(best_conv, 1),
                "would_flip": best_dir != cur,               # ★ 양방향 켜면 방향 바뀌나
                "delta": round(best_conv - float(cur_conv), 1),  # 더 높아지는 점수폭
                "opp_calc_ms": round(opp_ms, 1),             # ★ 증분 비용
                "price": round(_price, 8),                   # would_flip 자리 이후 MFE 추적용
            }
            self._dd_observe_write(rec)
            if rec["would_flip"]:
                logger.info("[FOCUS] DualDir 관찰: %s cur=%s(%.0f) → best=%s(%.0f) Δ+%.0f (flip, %.0fms)",
                            market, cur, cur_conv, best_dir, best_conv, rec["delta"], opp_ms)
        except Exception as exc:
            logger.debug("[FOCUS] dual_direction observe error: %s", exc)

    def _dd_observe_write(self, rec: dict) -> None:
        """관찰 1건 append (JSONL). 진입 무관·실패해도 조용히 (관찰이 거래에 영향 X)."""
        try:
            import os as _os
            import json as _json
            _os.makedirs("runtime", exist_ok=True)
            with open(_os.path.join("runtime", "dual_direction_observe.jsonl"), "a", encoding="utf-8") as f:
                f.write(_json.dumps(rec, ensure_ascii=False) + "\n")
        except Exception:
            pass

    def _detect_weak_server(self) -> bool:
        """INV-7 약서버 감지 (해결안 C). 명시 override(FOCUS_WEAK_SERVER) 우선,
        없으면 물리 RAM ≤ 임계(기본 20GiB → server-b 16GB=약 / home 32·server-a 64=강).
        감지 불가(psutil 부재 등) = 안전하게 False(강서버 간주 → 기존 동작 불변)."""
        ov = os.getenv("FOCUS_WEAK_SERVER", "").strip().lower()
        if ov in ("1", "true", "yes", "on"):
            return True
        if ov in ("0", "false", "no", "off"):
            return False
        try:
            import psutil
            gib = psutil.virtual_memory().total / (1024 ** 3)
            thr = float(os.getenv("FOCUS_WEAK_SERVER_RAM_GIB", "20") or "20")
            return gib <= thr
        except Exception:  # noqa: BLE001 — 감지 불가 = 강서버로 간주(기존 동작 유지)
            return False

    def _pick_best_direction(self, market: str, candles_primary: list, zones, signal_dir: str):
        """양방향 평가 (Phase 2) — 진입 방향 결정의 단일 관문. 3경로(scanner/locked/scan) 공유.

        [2026-06-09 부모 GO] "양쪽 다리 다 쓰는 봇." 방향을 signal 이 독점하던 것 → LONG/SHORT
        둘 다 채점해 높은 쪽. 단 *방향 균형은 봇 원칙*이되 *조건은 양쪽 엄격*(가짜 거름은 점수가).

        모드별:
          · direction_mode long_only/short_only = 한방 강제 (그 방향만 1회 채점).
          · both + dual_direction_enabled ON     = 양방향 채점 → 높은 쪽 진입 (방향 교체 가능).
          · both + OFF                            = signal_dir 그대로 (기존 동작). 단 observe ON 이면
                                                    양방향 채점해 기록만(Phase 1 관찰, 진입 무관).
        반환: (direction, conviction, info{flipped, long_conv, short_conv}).
        ★ 호출 위치 = candles 확보 직후·방향의존 게이트(PRIMARY/30M/dir_cap/reentry) 평가 *전*.
          그래야 교체된 방향이 모든 하위 게이트에 일관 적용됨 (중간 교체의 어긋남 방지).
        """
        sd = (signal_dir or "LONG").upper()
        if sd not in ("LONG", "SHORT"):
            sd = "LONG"
        mode = getattr(self.config, "direction_mode", "both")
        if mode == "long_only":
            c = self._compute_conviction_score(market, candles_primary, "LONG", zones)
            return "LONG", c, {"flipped": False}
        if mode == "short_only":
            c = self._compute_conviction_score(market, candles_primary, "SHORT", zones)
            return "SHORT", c, {"flipped": False}

        dual = getattr(self.config, "dual_direction_enabled", False)
        observe = getattr(self.config, "dual_direction_observe", True)
        # ★ [해결안 C / §9.2-C] 약서버 observe 자동 OFF — observe(record-only)만 끔, 진입 불변.
        #   dual=True 면 어차피 양방향 계산하므로 무영향. dual=False+observe=True 인 "관찰만" 비용만 제거.
        #   발동 = UI 토글(config) AND 이 서버가 약서버(__init__ 캐시). 강서버는 부모님 dual 의도 유지.
        if observe and not dual and getattr(self.config, "dual_observe_auto_off_weak", False) and getattr(self, "_is_weak_server", False):
            observe = False
        if not dual and not observe:
            # 양방향·관찰 둘 다 OFF = 기존 동작 100% (signal 방향만 채점, 기록 X)
            c = self._compute_conviction_score(market, candles_primary, sd, zones)
            return sd, c, {"flipped": False}

        # 양방향 채점 (dual 또는 observe 중 하나라도 ON)
        cl = self._compute_conviction_score(market, candles_primary, "LONG", zones)
        cs = self._compute_conviction_score(market, candles_primary, "SHORT", zones)
        best = "LONG" if cl >= cs else "SHORT"          # 동점 = LONG (보수적 tie-break)
        best_conv = cl if best == "LONG" else cs
        cur_conv = cl if sd == "LONG" else cs

        # ★ [2026-06-11 부모] near-miss 관찰 (a) — 양방향 base 점수 stash → _record_near_miss 가
        #   "막힌 다리 옆에 반대 다리 점수"를 표시. "왜 SHORT 안 하나"가 매 코인 눈에 보이게.
        try:
            if not hasattr(self, "_last_dual_conv"):
                self._last_dual_conv = {}
            self._last_dual_conv[(market or "").upper()] = (round(float(cl), 1), round(float(cs), 1))
        except Exception:  # noqa: BLE001
            pass

        try:
            _price = float(candles_primary[-1].close) if candles_primary else 0.0
        except Exception:
            _price = 0.0
        self._dd_observe_write({
            "ts": round(time.time(), 1), "market": market,
            "cur_dir": sd, "cur_conv": round(float(cur_conv), 1),
            "long_conv": round(float(cl), 1), "short_conv": round(float(cs), 1),
            "best_dir": best, "best_conv": round(float(best_conv), 1),
            "would_flip": best != sd, "delta": round(float(best_conv - cur_conv), 1),
            "opp_calc_ms": 0.0, "price": round(_price, 8),
            "applied": bool(dual),                       # Phase 2 = 실제 진입 반영 / Phase 1 = 기록만
        })

        if dual:
            # Phase 2: 높은 쪽으로 진입 방향 교체
            return best, best_conv, {"flipped": best != sd, "long_conv": cl, "short_conv": cs}
        # observe-only (Phase 1): 진입은 signal 방향 유지 (관찰만)
        return sd, cur_conv, {"flipped": False, "long_conv": cl, "short_conv": cs}

    # ────────────────────────────────────────────────────────
    # Profit Erosion Guard: 수익 침식 방지
    # ────────────────────────────────────────────────────────
    def _check_profit_erosion(self, pos: FocusPosition, price: float):
        """수익 침식 감지: peak >= 0.5%였는데 70%+ 깎이면 SL을 BE로 보호.

        "가랑비에 옷 젖는" 상황 방지 — 최고 수익에서 서서히 빠져나가
        결국 SL까지 밀리는 것을 막음. 최소한 본전은 지킨다.

        예: peak +0.78%, 현재 +0.2% (74% 침식) → SL을 진입가로 이동
            반등하면 다시 이윤, 더 빠지면 본전에 나감.
        """
        if pos.breakeven_locked:
            return  # 이미 BE 잠금 상태 → 불필요

        if pos.entry_price <= 0 or pos.peak_profit_price <= 0:
            return

        # [2026-05-29 부모 7번째 fix] 진입 직후 grace — Bybit 슬리피지 peak 노이즈 차단
        _grace_sec_e = float(getattr(self.config, "be_lock_grace_sec", 60.0) or 0.0)
        if _grace_sec_e > 0 and pos.entry_ts > 0 and (time.time() - pos.entry_ts) < _grace_sec_e:
            return

        # peak 수익률 계산
        if pos.direction == "LONG":
            peak_pct = (pos.peak_profit_price / pos.entry_price - 1) * 100
            cur_pct = (price / pos.entry_price - 1) * 100
        else:
            peak_pct = (1 - pos.peak_profit_price / pos.entry_price) * 100
            cur_pct = (1 - price / pos.entry_price) * 100

        # peak이 최소 기준 미달 → 의미 있는 수익이 없었음
        if peak_pct < self.config.erosion_guard_peak_pct:
            return

        # 침식 비율 체크: 현재가 peak의 30% 이하로 떨어졌는가?
        if cur_pct > peak_pct * self.config.erosion_guard_ratio:
            return  # 아직 충분한 수익 남아있음

        # ── 침식 감지! SL을 BE로 이동 ──
        new_sl = pos.entry_price

        # SL only tighten 원칙
        if pos.direction == "LONG" and new_sl <= pos.sl:
            return
        if pos.direction == "SHORT" and new_sl >= pos.sl:
            return

        old_sl = pos.sl
        pos.sl = round(new_sl, 8)
        pos.breakeven_locked = True
        pos.be_locked_ts = time.time()   # [BE Stall Exit 2026-04-19] 락 발동 시각

        logger.info(
            "[FOCUS] Erosion Guard: %s %s peak +%.2f%% → now +%.2f%% (%.0f%% eroded) → SL $%.2f → $%.2f (BE)",
            pos.direction, pos.market, peak_pct, cur_pct,
            (1 - cur_pct / peak_pct) * 100 if peak_pct > 0 else 0,
            old_sl, pos.sl,
        )
        self._update_bybit_sl(pos)
        self._save_config()

        try:
            self._notify(
                f"Erosion Guard\n"
                f"{pos.direction} {pos.market}\n"
                f"Peak +{peak_pct:.2f}% → Now +{cur_pct:.2f}%\n"
                f"SL: ${old_sl:.2f} → ${pos.sl:.2f} (BE)"
            )
        except Exception as exc:
            logger.debug("[FOCUS] self._notify failed: %s", exc)

    def _sl_dodge_survival_check(self, pos: FocusPosition, price: float) -> tuple:
        """🧠 멀티TF 가중 생존 판단 — 살릴 가치가 있는가?

        가까운 TF일수록 "지금 반등할 수 있는가"에 더 중요:
          5M  ×3  — 지금 당장의 흐름 (반등의 첫 신호)
          30M ×2  — 단기 구조 (반등 지속 가능성)
          1H  ×1  — 중기 맥락
          H4  ×1  — 큰 그림

        각 TF: 아군 +weight, 중립 0, 적군 -weight
        최대 +7(전원 아군) ~ -7(전원 적군)

        Returns: (should_dodge: bool, score: int, detail: str)
          score >= -3 → dodge OK (반등 가능성 있음)
          score <= -4 → dodge 거부 (가중 과반 이상 적군)
        """
        client = self._get_client()
        from app.strategy.greenpen.pa_detector import OHLCV as _O
        from app.strategy.greenpen.market_structure import analyze_structure as _as

        # (label, interval, candle_limit, weight)
        tf_map = [
            ("PRI", self.config.primary_tf, 40, 1),  # primary_tf(H1) 큰 그림 ×1
            ("1H", "60", 30, 1),                       # 중기 ×1
            ("30M", "30", 20, 2),                      # 단기 구조 ×2
            ("5M", "5", 30, 3),                        # 즉각 흐름 ×3
        ]

        score = 0
        max_score = 0  # 체크된 TF의 가중치 합
        details = []

        for label, interval, limit, weight in tf_map:
            try:
                raw = client.get_kline(pos.market, interval=interval, limit=limit)
                candles = [_O(float(r[1]), float(r[2]), float(r[3]), float(r[4]))
                           for r in raw if len(r) >= 5]
                if len(candles) < 10:
                    details.append(f"{label}:?")
                    continue
                struct = _as(candles)
                trend = struct.trend.value if hasattr(struct.trend, 'value') else str(struct.trend)

                max_score += weight

                if pos.direction == "LONG":
                    if trend == "UPTREND":
                        score += weight
                        details.append(f"{label}:UP(+{weight})")
                    elif trend == "DOWNTREND":
                        score -= weight
                        details.append(f"{label}:DN(-{weight})")
                    else:
                        details.append(f"{label}:SW(0)")
                else:  # SHORT
                    if trend == "DOWNTREND":
                        score += weight
                        details.append(f"{label}:DN(+{weight})")
                    elif trend == "UPTREND":
                        score -= weight
                        details.append(f"{label}:UP(-{weight})")
                    else:
                        details.append(f"{label}:SW(0)")
            except Exception as exc:
                logger.debug("[FOCUS] operation failed (fallback): %s", exc)
                details.append(f"{label}:err")

        detail_str = " ".join(details)

        # 판정: 가중 점수가 -4 이하면 → 과반 적군 → dodge 금지
        #   -4 = 5M(-3)+1H(-1) 또는 5M(-3)+30M(-2)+H4(+1) 등
        #   즉, 5M이 적군이면 다른 1개도 적군이어야 거부
        #   5M만 적군(-3)이고 나머지 중립이면 -3 → 아직 dodge OK
        if max_score >= 4 and score <= -4:
            return (False, score, detail_str)

        return (True, score, detail_str)

    def _apply_sl_decay(self, pos: FocusPosition, hold_hours: float):
        """장기 보유 SL+TP 동시 축소 — 3시간+ 방치 방지.

        데이터 근거: 3시간+ 보유 평균손실 -$50 (전체 -$208).
        SL과 TP 거리를 같은 비율로 축소하여 빠른 결정 유도.
        - SL만 조이면 불공평 → TP도 같이 조여서 작은 움직임에도 결판
        - "조이기만" 원칙: 이미 더 좋은 SL이면 건드리지 않음
        - BE Lock 된 포지션은 스킵 (이미 보호됨)
        """
        if not self.config.sl_decay_enabled:
            return
        if pos.breakeven_locked:
            return  # BE Lock 이미 작동 중
        if hold_hours < 2.0:
            return  # 2시간 미만은 건드리지 않음

        original_sl = pos.original_sl if pos.original_sl > 0 else pos.sl
        if original_sl <= 0:
            return

        # SL 거리 계산
        if pos.direction == "LONG":
            sl_distance = pos.entry_price - original_sl
        else:  # SHORT
            sl_distance = original_sl - pos.entry_price

        if sl_distance <= 0:
            return  # SL이 이미 entry 안쪽 (BE 상태)

        # 시간에 따른 비율 결정
        if hold_hours >= 3.0:
            ratio = self.config.sl_decay_3h_ratio
        else:
            ratio = self.config.sl_decay_2h_ratio

        # ── SL 축소 ──
        new_sl_distance = sl_distance * ratio
        if pos.direction == "LONG":
            new_sl = pos.entry_price - new_sl_distance
        else:
            new_sl = pos.entry_price + new_sl_distance

        # "SL 조이기만" — 기존 SL보다 나빠지면 건드리지 않음
        sl_changed = False
        if pos.direction == "LONG":
            if new_sl > pos.sl:
                old_sl = pos.sl
                pos.sl = round(new_sl, 6)
                sl_changed = True
        else:
            if new_sl < pos.sl:
                old_sl = pos.sl
                pos.sl = round(new_sl, 6)
                sl_changed = True

        # ── TP 축소 (같은 비율, 원본 TP1 기준) ──
        # partial_done=True면 TP1 이미 달성 → TP2로 운영 중 → TP Decay 안 함
        tp_changed = False
        original_tp1 = pos.original_tp1 if pos.original_tp1 > 0 else pos.tp1
        if original_tp1 and original_tp1 > 0 and not pos.partial_done:
            if pos.direction == "LONG":
                tp_distance = original_tp1 - pos.entry_price
                if tp_distance > 0:
                    new_tp = pos.entry_price + tp_distance * ratio
                    if new_tp < pos.tp1:  # TP 조이기만
                        old_tp = pos.tp1
                        pos.tp1 = round(new_tp, 6)
                        tp_changed = True
            else:  # SHORT
                tp_distance = pos.entry_price - original_tp1
                if tp_distance > 0:
                    new_tp = pos.entry_price - tp_distance * ratio
                    if new_tp > pos.tp1:  # TP 조이기만
                        old_tp = pos.tp1
                        pos.tp1 = round(new_tp, 6)
                        tp_changed = True

        if not sl_changed and not tp_changed:
            return  # 이미 충분히 조여져 있음

        log_parts = []
        if sl_changed:
            log_parts.append(f"SL ${old_sl:.4f}->${pos.sl:.4f}")
        if tp_changed:
            log_parts.append(f"TP ${old_tp:.4f}->${pos.tp1:.4f}")
        logger.info(
            "[FOCUS] Decay: %s %s hold=%.1fh ratio=%.0f%% — %s",
            pos.direction, pos.market, hold_hours, ratio * 100,
            ", ".join(log_parts),
        )

        # _update_bybit_sl은 TP+SL을 함께 set_trading_stop으로 전송
        if sl_changed or tp_changed:
            self._update_bybit_sl(pos)
        self._save_config()

    def _apply_sl_dodge(self, pos: FocusPosition, price: float):
        """🛡️ SL Dodge — 고래 전략: SL 근접 시 후퇴하여 청산 회피.

        원리: 진입 판단이 맞았으면 SL 부근은 지지/저항선 → 반등 가능성 높음.
        고래들이 하는 것처럼 SL을 살짝씩 후퇴시켜 스탑 사냥 wick을 피함.

        ★ 단, 멀티TF 전원 반대면 dodge 안 함 — 무조건 살리기 금지!
           H4/1H/30M/5M 중 3개+ 반대 추세 → 진짜 틀린 거 → SL 맞는 게 나음

        Trigger: 가격이 SL의 proximity_pct(1.5%) 이내 접근
        Guard: 멀티TF 생존 판단 통과 시에만 발동
        Action: SL을 retreat_pct(1.5%)만큼 후퇴
        Limit: max_count(3)회, 총 max_total_pct(5%) 후퇴
        LONG/SHORT 모두 적용.
        """
        if not self.config.sl_dodge_enabled:
            return
        if pos.sl_dodge_count >= self.config.sl_dodge_max_count:
            return  # 최대 후퇴 횟수 도달 — 더 이상 후퇴 불가

        # original_sl 기록 (최초 1회)
        if pos.original_sl <= 0:
            pos.original_sl = pos.sl

        # SL까지 거리(%) 계산
        if price <= 0 or pos.sl <= 0:
            return
        if pos.direction == "LONG":
            sl_dist_pct = (price - pos.sl) / price * 100
        else:
            sl_dist_pct = (pos.sl - price) / price * 100

        if sl_dist_pct <= 0:
            return  # 이미 SL 터짐 (너무 늦음)

        # proximity 이내인가?
        if sl_dist_pct > self.config.sl_dodge_proximity_pct:
            return  # 아직 SL에서 멀다 — 발동 안 함

        # ★★★ 멀티TF 생존 판단 — 살릴 가치가 있는가? ★★★
        try:
            should_dodge, tf_score, tf_detail = self._sl_dodge_survival_check(pos, price)
            if not should_dodge:
                logger.info(
                    "[FOCUS] 🛡️❌ SL Dodge DENIED %s %s: MTF score=%d (%s) → all against, let SL hit",
                    pos.direction, pos.market, tf_score, tf_detail,
                )
                self._notify(
                    f"🛡️❌ SL Dodge DENIED — {pos.direction} {pos.market}\n"
                    f"MTF: {tf_detail}\n"
                    f"Score: {tf_score} (all timeframes against)\n"
                    f"→ Letting SL hit. No hope of recovery."
                )
                # dodge 횟수를 max로 설정하여 이후 재시도 방지
                pos.sl_dodge_count = self.config.sl_dodge_max_count
                return
        except Exception as exc:
            logger.warning("[FOCUS] SL Dodge survival check failed: %s — dodge anyway", exc)
            # 분석 실패 시에는 dodge 허용 (분석 실패 = 정보 부족, 의심의 이익)

        # 총 후퇴 한도 체크
        if pos.entry_price > 0 and pos.original_sl > 0:
            original_dist = abs(pos.entry_price - pos.original_sl)
            current_dist = abs(pos.entry_price - pos.sl)
            retreated_so_far = current_dist - original_dist
            max_retreat_total = pos.entry_price * (self.config.sl_dodge_max_total_pct / 100)
            if retreated_so_far >= max_retreat_total:
                logger.info("[FOCUS] 🛡️ SL Dodge MAX reached %s: already retreated $%.2f (limit $%.2f)",
                            pos.market, retreated_so_far, max_retreat_total)
                return

        # 후퇴량 계산
        retreat_amount = price * (self.config.sl_dodge_retreat_pct / 100)

        if pos.direction == "LONG":
            new_sl = pos.sl - retreat_amount
        else:
            new_sl = pos.sl + retreat_amount

        # 총 후퇴 절대 한도 적용
        if pos.entry_price > 0 and pos.original_sl > 0:
            max_retreat = pos.entry_price * (self.config.sl_dodge_max_total_pct / 100)
            if pos.direction == "LONG":
                floor_sl = pos.original_sl - max_retreat
                new_sl = max(new_sl, floor_sl)
            else:
                ceil_sl = pos.original_sl + max_retreat
                new_sl = min(new_sl, ceil_sl)

        old_sl = pos.sl
        pos.sl = round(new_sl, 8)
        pos.sl_dodge_count += 1

        logger.info(
            "[FOCUS] 🛡️✅ SL DODGE #%d/%d %s %s: SL $%.4f → $%.4f "
            "(proximity %.2f%%, MTF=%d [%s])",
            pos.sl_dodge_count, self.config.sl_dodge_max_count,
            pos.direction, pos.market,
            old_sl, pos.sl, sl_dist_pct,
            tf_score, tf_detail,
        )

        # Bybit에 새 SL 즉시 반영
        self._update_bybit_sl(pos)
        self._save_config()

        # 텔레그램 알림
        remain = self.config.sl_dodge_max_count - pos.sl_dodge_count
        self._notify(
            f"🛡️ SL DODGE #{pos.sl_dodge_count} — {pos.direction} {pos.market}\n"
            f"SL: ${old_sl:.2f} → ${pos.sl:.2f}\n"
            f"Price: ${price:.2f} (proximity {sl_dist_pct:.1f}%)\n"
            f"MTF: {tf_detail} (score={tf_score})\n"
            f"Remaining dodges: {remain}"
        )

    def _update_bybit_sl(self, pos: FocusPosition):
        """Bybit에 SL만 업데이트 (TP 유지). 실패 시 재시도 1회.
        [2026-04-18] 'zero position' 에러 감지 시 즉시 phantom EXIT 기록 → Scanner 재진입 방지
          이전: SL update 실패 후 다음 SYNC(수초~30초 후)에서 phantom detect
          문제: 그 사이 Scanner가 'ORDI not held'로 봐서 2차 진입 → 중복 포지션 손실
        """
        tp = pos.tp2 if pos.partial_done else pos.tp1
        for _try in range(2):
            try:
                self._get_client().set_trading_stop(pos.market, take_profit=tp, stop_loss=pos.sl)
                return  # 34040 "not modified" is handled inside set_trading_stop → success
            except Exception as exc:
                _err_str = str(exc).lower()
                # zero position 감지 — Bybit 측에서 이미 닫힌 포지션
                if "zero position" in _err_str or "retCode=10001" in str(exc) and "zero" in _err_str:
                    logger.warning("[FOCUS] %s position closed on Bybit side — recording phantom EXIT immediately", pos.market)
                    self._record_phantom_exit(pos, reason_hint="ZERO_POSITION")
                    return
                logger.warning("[FOCUS] Bybit SL update failed %s (attempt %d/2): %s", pos.market, _try + 1, exc)
                if _try == 0:
                    import time as _t; _t.sleep(0.5)

    def _record_phantom_exit(self, pos: FocusPosition, reason_hint: str = "PHANTOM"):
        """Bybit에서 이미 닫힌 포지션 즉시 EXIT 기록 + 내부 상태 정리.
        [2026-04-18] SYNC 주기 기다리지 않고 즉시 처리 → Scanner 중복 진입 방지
        [2026-04-19] ★ DOUBLE-LOG FIX: _close_position 이 이미 처리 중이면 journal 중복 방지를 위해 skip.
        """
        # ★ DOUBLE-LOG FIX: _close_position 이 동일 마켓 청산 진행 중이면 그 쪽이 journal 을 쓰므로 여기서는 skip.
        try:
            if pos.market.upper() in self._closing_markets:
                logger.info("[FOCUS] phantom EXIT skipped for %s — _close_position in progress",
                            pos.market)
                return
        except Exception:
            pass
        try:
            _exit_price = self._get_current_price(pos.market) or pos.entry_price
            _hold = (time.time() - pos.entry_ts) if pos.entry_ts > 0 else 0

            # TP/SL 판별
            _exit_reason = reason_hint
            if pos.sl and pos.sl > 0 and _exit_price > 0:
                if pos.direction == "LONG" and _exit_price <= pos.sl * 1.002:
                    _exit_reason = "SERVER_SL"
                    _exit_price = pos.sl
                    self._record_sl_hit(pos.market)  # #2A
                elif pos.direction == "SHORT" and _exit_price >= pos.sl * 0.998:
                    _exit_reason = "SERVER_SL"
                    _exit_price = pos.sl
                    self._record_sl_hit(pos.market)  # #2A
                elif pos.tp2 and pos.tp2 > 0:
                    if pos.direction == "LONG" and _exit_price >= pos.tp2 * 0.998:
                        _exit_reason = "SERVER_TP"
                        _exit_price = pos.tp2
                    elif pos.direction == "SHORT" and _exit_price <= pos.tp2 * 1.002:
                        _exit_reason = "SERVER_TP"
                        _exit_price = pos.tp2

            _peak = 0.0
            if pos.peak_profit_price > 0 and pos.entry_price > 0:
                if pos.direction == "LONG":
                    _peak = (pos.peak_profit_price / pos.entry_price - 1) * 100
                else:
                    _peak = (1 - pos.peak_profit_price / pos.entry_price) * 100

            from app.manager.trade_journal import journal
            journal.record_exit(
                strategy="FOCUS", market=pos.market, direction=pos.direction,
                entry_price=pos.entry_price, exit_price=_exit_price, qty=pos.qty,
                reason=_exit_reason, leverage=pos.leverage, hold_sec=_hold,
                phase=f"conviction={pos.conviction_score}",
                dynamic_trailing=self.config.dynamic_trailing,
                breakeven_locked=pos.breakeven_locked,
                peak_profit_pct=_peak,
            )
            logger.warning("[FOCUS] %s phantom EXIT RECORDED — %s @ $%.4f (entry=$%.4f, hold=%.0fs)",
                           pos.market, _exit_reason, _exit_price, pos.entry_price, _hold)

            # 퇴장 정보 기록 (재진입 쿨다운용)
            self._last_exit_direction = pos.direction
            self._last_exit_price = _exit_price
            self._last_exit_ts = time.time()
            self._last_exit_market = pos.market

            # self.positions에서 즉시 제거 → Scanner가 'not held'로 보지만 쿨다운이 막음
            try:
                self.positions = [p for p in self.positions if p.market != pos.market]
                # 포지션이 없으면 상태 초기화
                if not self.positions:
                    if self.state == FocusState.POSITIONED:
                        self.state = FocusState.HUNT
                self._save_config()
            except Exception as exc:
                logger.warning("[FOCUS] positions cleanup after phantom EXIT failed: %s", exc)
        except Exception as exc:
            logger.error("[FOCUS] _record_phantom_exit failed %s: %s", pos.market, exc)

    @staticmethod
    def _extract_fill(order, fallback_price: float = 0.0, fallback_qty: float = 0.0):
        """place_order/get_order 반환(_convert_order 정규화 dict)에서 실제 체결 정보 추출.

        ★ [2026-06-11] cowork 진단 ①② — place_order 응답을 읽지 않아 손익 오염 + 유령 포지션.
        bybit_trade._convert_order 정규화 키: avg_price / executed_volume / state(done/wait/cancel).
        raw Bybit 키(avgPrice/cumExecQty/orderStatus)도 fallback 으로 함께 본다.

        Returns: (fill_price, filled_qty, state, is_filled)
          - fill_price: 실제 평균 체결가 (없으면 fallback_price)
          - filled_qty: 실제 체결량 (없으면 fallback_qty)
          - state: 정규화 상태 문자열 ("done"/"wait"/"cancel"/...)
          - is_filled: 체결 확인 여부 (state=done 또는 체결량>0 이며 취소 아님)
        """
        o = order or {}
        def _f(*keys):
            for k in keys:
                v = o.get(k)
                if v not in (None, "", "0"):
                    try:
                        fv = float(v)
                        if fv != 0:
                            return fv
                    except (TypeError, ValueError):
                        continue
            return 0.0
        fill_price = _f("avg_price", "avgPrice", "price") or float(fallback_price or 0)
        filled_qty = _f("executed_volume", "cumExecQty", "filled") or float(fallback_qty or 0)
        raw_state = str(o.get("state", o.get("orderStatus", "")) or "").lower()
        is_cancel = raw_state in ("cancel", "cancelled", "rejected", "deactivated")
        # 정규화 done = 완전체결. 체결량>0 이고 취소 아니면 (부분이라도) 체결로 인정.
        is_filled = (raw_state == "done") or (filled_qty > 0 and not is_cancel)
        return fill_price, filled_qty, raw_state, is_filled

    def _query_position_size(self, market: str):
        """거래소 실제 포지션 size 재조회 (live 전용). 청산 검증·유령 방지용.

        ★ [2026-06-11] cowork 진단 ② — 청산 후 거래소 잔량을 확인하지 않아
        부분체결이 "완전 청산"으로 처리되던 desync 방어.

        Returns: float size (>=0). live 가 아니거나 조회 실패 시 None (검증 skip 신호).
        """
        if not self._is_live_mode():
            return None
        try:
            client = self._get_client()
            from app.core.constants import BYBIT_POSITION_LIST
            resp = client._request("GET", BYBIT_POSITION_LIST,
                                   params={"category": "linear", "symbol": market})
            lst = resp.get("list", []) if isinstance(resp, dict) else []
            total = 0.0
            for bp in lst:
                try:
                    total += abs(float(bp.get("size", 0) or 0))
                except (TypeError, ValueError):
                    continue
            return total
        except Exception as exc:
            logger.warning("[FOCUS] _query_position_size(%s) failed: %s", market, exc)
            return None

    def _close_position(self, pos: FocusPosition, reason: str, is_sl: bool = False) -> bool:
        """단일 포지션 청산. ★ 실패 시 포지션 유지 → 다음 tick에서 재시도.
        Returns: True if closed successfully, False if failed (position kept)."""
        # ★ DOUBLE-LOG FIX: 본 호출 진행 중엔 _live_sync_positions가 고스트로 중복 기록 못 하도록 가드.
        _mkt_key = pos.market.upper()
        self._closing_markets.add(_mkt_key)
        try:
            client = self._get_client()
            side = "Sell" if pos.direction == "LONG" else "Buy"
            closed = False
            _orig_qty = pos.qty  # ★ [2026-06-11] 장부 기록용 원 수량 보존 (부분체결 재시도 시 pos.qty 변동)
            for attempt in range(3):
                try:
                    order = client.place_order(market=pos.market, side=side, ord_type="market", volume=pos.qty, reduce_only=True)
                    # ★ [2026-06-11] cowork ①② — 실제 체결가/체결량/상태 추출 (가정 제거)
                    fill_price, filled_qty, order_state, _is_filled = self._extract_fill(
                        order, fallback_price=self._get_current_price(pos.market) or pos.entry_price,
                        fallback_qty=pos.qty)
                    if order_state in ("cancel", "cancelled", "rejected"):
                        logger.warning("[FOCUS] Close order CANCELLED %s (attempt %d)", pos.market, attempt+1)
                        if attempt < 2:
                            import time as _ct; _ct.sleep(0.3)
                        continue
                    # ★ [2026-06-11] cowork ② — 청산 후 거래소 실제 잔량 재조회 → 부분/미체결 desync 방어.
                    #   기본값 "done" 신뢰 금지: 잔량이 남으면 "완전 청산" 처리하지 않고 잔량으로 재시도.
                    remaining = self._query_position_size(pos.market)
                    if remaining is not None and remaining > 1e-9:
                        logger.warning("[FOCUS] Close PARTIAL/미체결 %s: 거래소 잔량=%.8f (qty=%.8f) — 잔량 재시도 (state=%s)",
                                       pos.market, remaining, pos.qty, order_state)
                        pos.qty = remaining
                        self._save_config()
                        if attempt < 2:
                            import time as _ct; _ct.sleep(0.3)
                        continue
                    # remaining ~ 0 (또는 non-live/조회불가) → 완전 청산 인정
                    _exit_fill = fill_price if (_is_filled and fill_price > 0) else (self._get_current_price(pos.market) or pos.entry_price)
                    logger.info("[FOCUS] Closed %s %s %.4f @ $%.4f: %s (attempt %d, state=%s)",
                                pos.direction, pos.market, _orig_qty, _exit_fill, reason, attempt+1, order_state)
                    self._notify(f"🔴 CLOSE {pos.direction} {pos.market}\nqty={_orig_qty} @ ${_exit_fill:.4f} | {reason}\nconviction={pos.conviction_score}")
                    # ── 장부 기록 ──
                    try:
                        from app.manager.trade_journal import journal
                        _price = _exit_fill  # ★ 실제 체결가 (추정치 _get_current_price 대체)
                        _hold = (time.time() - pos.entry_ts) if pos.entry_ts > 0 else 0
                        _peak = 0.0
                        if pos.peak_profit_price > 0 and pos.entry_price > 0:
                            if pos.direction == "LONG":
                                _peak = (pos.peak_profit_price / pos.entry_price - 1) * 100
                            else:
                                _peak = (1 - pos.peak_profit_price / pos.entry_price) * 100
                        journal.record_exit(
                            strategy="FOCUS", market=pos.market, direction=pos.direction,
                            entry_price=pos.entry_price, exit_price=_price, qty=_orig_qty,
                            reason=reason, leverage=pos.leverage, hold_sec=_hold,
                            phase=f"conviction={pos.conviction_score}",
                            dynamic_trailing=self.config.dynamic_trailing,
                            breakeven_locked=pos.breakeven_locked,
                            peak_profit_pct=_peak,
                        )
                    except Exception as exc:
                        logger.warning("[FOCUS] journal.record_exit failed (%s %s): %s", pos.market, reason, exc)
                    # ── v2: 퇴장 정보 기록 (재진입 차단용) ──
                    self._last_exit_direction = pos.direction
                    self._last_exit_price = _exit_fill
                    self._last_exit_ts = time.time()
                    self._last_exit_market = pos.market
                    # ★ FIX: legacy self.position 즉시 제거 (다음 tick 재처리 방지)
                    if self.position is pos:
                        self.position = None
                    closed = True
                    break
                except Exception as exc:
                    # ★ 110017 = "position is zero" — Bybit 서버 SL/TP가 먼저 체결한 경우
                    exc_str = str(exc)
                    if "110017" in exc_str or "position is zero" in exc_str.lower():
                        # ★ [2026-04-23] ZERO-LOG FIX: 기존엔 journal 미기록 + _sync_with_bybit 도
                        #   _closing_markets 가드로 스킵 → BNBUSDT 흔적 소실 사건. 여기서 직접 기록.
                        logger.info("[FOCUS] Close skipped %s: already closed by server-side SL/TP — recording EXIT", pos.market)
                        try:
                            from app.manager.trade_journal import journal
                            _exit_price = self._get_current_price(pos.market) or pos.entry_price
                            _hold = (time.time() - pos.entry_ts) if pos.entry_ts > 0 else 0
                            # SL/TP 판별 (SYNC phantom 경로 로직과 동일)
                            _exit_reason = reason
                            _is_sl = False
                            if pos.sl and pos.sl > 0 and _exit_price > 0:
                                if pos.direction == "LONG" and _exit_price <= pos.sl * 1.002:
                                    _exit_reason = "SERVER_SL"
                                    _exit_price = pos.sl
                                    _is_sl = True
                                elif pos.direction == "SHORT" and _exit_price >= pos.sl * 0.998:
                                    _exit_reason = "SERVER_SL"
                                    _exit_price = pos.sl
                                    _is_sl = True
                            if not _is_sl and pos.tp2 and pos.tp2 > 0:
                                if pos.direction == "LONG" and _exit_price >= pos.tp2 * 0.998:
                                    _exit_reason = "SERVER_TP"
                                    _exit_price = pos.tp2
                                elif pos.direction == "SHORT" and _exit_price <= pos.tp2 * 1.002:
                                    _exit_reason = "SERVER_TP"
                                    _exit_price = pos.tp2
                            # peak profit
                            _peak = 0.0
                            if pos.peak_profit_price > 0 and pos.entry_price > 0:
                                if pos.direction == "LONG":
                                    _peak = (pos.peak_profit_price / pos.entry_price - 1) * 100
                                else:
                                    _peak = (1 - pos.peak_profit_price / pos.entry_price) * 100
                            # dedup 가드가 SYNC 경로와의 경쟁을 막아주므로 안전하게 기록
                            journal.record_exit(
                                strategy="FOCUS", market=pos.market, direction=pos.direction,
                                entry_price=pos.entry_price, exit_price=_exit_price, qty=pos.qty,
                                reason=_exit_reason, leverage=pos.leverage, hold_sec=_hold,
                                phase=f"conviction={pos.conviction_score}",
                                dynamic_trailing=self.config.dynamic_trailing,
                                breakeven_locked=pos.breakeven_locked,
                                peak_profit_pct=_peak,
                            )
                            # 퇴장 정보 (재진입 차단용)
                            self._last_exit_direction = pos.direction
                            self._last_exit_price = _exit_price
                            self._last_exit_ts = time.time()
                            self._last_exit_market = pos.market
                            # SL 카운터
                            if _is_sl:
                                self.daily_sl_count += 1
                            logger.warning("[FOCUS] %s ZERO-POS EXIT RECORDED — %s @ $%.4f (entry=$%.4f, hold=%.0fs)",
                                           pos.market, _exit_reason, _exit_price, pos.entry_price, _hold)
                        except Exception as _rec_exc:
                            logger.error("[FOCUS] journal.record_exit failed (%s 110017 path): %s", pos.market, _rec_exc)
                        # 로컬 state 정리 — positions 목록에서 이 포지션 제거
                        try:
                            self.positions = [p for p in self.positions if p.market != pos.market]
                            if self.position is pos:
                                self.position = None
                            if not self.positions and self.state == FocusState.POSITIONED:
                                self.state = FocusState.HUNT
                            self._save_config()
                        except Exception as _clean_exc:
                            logger.warning("[FOCUS] positions cleanup after 110017 failed: %s", _clean_exc)
                        # sync 는 상태 일관성 보장을 위해 호출 유지 (dedup 가드가 중복 기록 막음)
                        self._sync_with_bybit()
                        return True  # 이미 닫힘
                    logger.error("[FOCUS] Close FAILED %s (attempt %d/3): %s", pos.market, attempt+1, exc)
                    if attempt < 2:
                        import time as _t; _t.sleep(0.3)  # ★ M18 FIX: lock 차단 최소화
            if not closed:
                # ★ H9 FIX: dataclass 필드 사용 (영속화됨)
                pos.close_retry_count += 1
                retry_count = pos.close_retry_count
                if retry_count >= 10:
                    # ★ 10회 실패 → Bybit 실잔고 강제 동기화 후 제거 판단
                    logger.critical("[FOCUS] CLOSE FAILED 10x: %s — forcing Bybit sync to check actual state", pos.market)
                    self._sync_with_bybit()
                    return True  # sync가 실잔고 기준으로 정리
                logger.critical("[FOCUS] CLOSE FAILED 3x (%d total): %s %s qty=%.4f — retry next tick",
                               retry_count, pos.direction, pos.market, pos.qty)
                return False

            if is_sl:
                self.daily_sl_count += 1
            # Phase C-2 (2026-04-20): WebSocket push — UI 실시간 갱신. fire-and-forget.
            try:
                from app.api.websocket_router import state_broadcast_safe
                _exit_p = self._get_current_price(pos.market) or pos.entry_price
                _hold = (time.time() - pos.entry_ts) if pos.entry_ts > 0 else 0
                if pos.direction == "LONG":
                    _pnl_pct = (_exit_p / pos.entry_price - 1) * 100 if pos.entry_price > 0 else 0
                else:
                    _pnl_pct = (1 - _exit_p / pos.entry_price) * 100 if pos.entry_price > 0 else 0
                state_broadcast_safe("POSITION_CLOSE", {
                    "market": pos.market, "direction": pos.direction,
                    "exit_price": _exit_p, "pnl_pct": round(_pnl_pct, 2),
                    "hold_sec": round(_hold, 1), "reason": reason,
                })
            except Exception:
                pass
            return True
        finally:
            self._closing_markets.discard(_mkt_key)

    def _partial_close(self, pos: FocusPosition, partial, price: float):
        """부분 청산 (TP1). ★ 실제 체결량 확인."""
        close_qty = pos.qty * (partial.exit_pct / 100.0)
        client = self._get_client()
        try:
            side = "Sell" if pos.direction == "LONG" else "Buy"
            order = client.place_order(market=pos.market, side=side, ord_type="market", volume=close_qty)
            # ★ 실제 체결량 확인 — 가정 대신 실제 값 사용
            actual_filled = float((order or {}).get("executed_volume", 0) or (order or {}).get("cumExecQty", 0) or 0)
            if actual_filled > 0:
                close_qty = actual_filled  # Bybit 실제 체결량이 최종
            pos.partial_done = True
            pos.qty -= close_qty
            pos.sl = partial.new_sl
            if pos.direction == "LONG":
                pos.trailing_high = price
            else:
                pos.trailing_low = price
            logger.info("[FOCUS] Partial %.0f%% %s @ %.2f → SL moved to breakeven", partial.exit_pct, pos.market, price)
            try:
                client.set_trading_stop(pos.market, take_profit=pos.tp2, stop_loss=pos.sl)
            except Exception as exc:
                logger.debug("[FOCUS] client.set_trading_stop(pos.market, take failed: %s", exc)
        except Exception as exc:
            logger.error("[FOCUS] Partial close FAILED %s: %s", pos.market, exc)

    # ── v2: ADX / Conviction / Reentry Helpers ─────────────

    def _bb_trend_riding(self, direction: Optional[str] = None, closes: Optional[list] = None) -> Tuple[bool, float]:
        """★ [2026-06-06 부모] BB 닿는 순간 '튈 것(반전)' vs '탈 것(벽타기)' 판별.
        진입 조건이 BB 극단(닿음/가까움)이라, 거기서 흐를지 튈지를 3조건으로 본다:
          ① ADX ≥ bb_block_trend_bypass_adx — 추세 세기 (횡보면 진짜 닿고 튐)
          ② DI 방향 일치 (bb_trend_bypass_require_di) — SHORT면 -DI>+DI = 진짜 하락추세 ('튈 것' 거름)
          ③ MACD 모멘텀 (bb_trend_bypass_macd_min>0, 허용치 조절) — 그 방향 가속 중일 때만
        셋 다 충족 = 벽타기(차단 우회). 하나라도 미달 = 닿고 튈 수도 = 차단 유지. → (bypass, adx)
        """
        try:
            thr = float(getattr(self.config, "bb_block_trend_bypass_adx", 30.0) or 0.0)
            if thr <= 0:
                return False, 0.0
            adx = float(getattr(self, "_last_adx_value", 0.0) or 0.0)
            if adx < thr:
                return False, adx  # ① 추세 약함 = 횡보 = 닿고 튈 위험 → 차단 유지
            _d = (direction or "").upper()
            # ② 방향 확정 — 추세가 '진짜 그 방향'인가 (DI 못 읽으면 ①만으로 통과)
            if _d and bool(getattr(self.config, "bb_trend_bypass_require_di", True)):
                pdi = float(getattr(self, "_last_plus_di", 0.0) or 0.0)
                mdi = float(getattr(self, "_last_minus_di", 0.0) or 0.0)
                if pdi > 0 or mdi > 0:
                    if _d in ("SHORT", "SELL") and not (mdi > pdi):
                        return False, adx  # 하락추세 아님 → 닿고 튈 위험
                    if _d in ("LONG", "BUY") and not (pdi > mdi):
                        return False, adx
            # ③ MACD 모멘텀 (허용치 노브, 0=비활성) — 그 방향으로 가속 중인가
            macd_min = float(getattr(self.config, "bb_trend_bypass_macd_min", 0.0) or 0.0)
            if macd_min > 0 and _d and closes and len(closes) >= 35:
                try:
                    from app.strategy.indicators import macd_hist_pair as _mhp
                    _hn, _hp = _mhp(closes)
                    if _hn is not None:
                        if _d in ("SHORT", "SELL") and not (_hn < 0 and abs(_hn) >= macd_min):
                            return False, adx
                        if _d in ("LONG", "BUY") and not (_hn > 0 and abs(_hn) >= macd_min):
                            return False, adx
                except Exception:
                    pass
            return True, adx
        except Exception:
            return False, 0.0

    def _fetch_primary_adx(self, market: str) -> Optional[Dict]:
        """primary_tf(H1) ADX 조회. market별 캐싱 적용 (최소 60초 간격). [2026-05-15] _fetch_h4_adx 에서 개명."""
        now = time.time()
        # market별 캐시 (이전: 전역 1개 → 다른 코인 ADX 오염)
        if not hasattr(self, '_adx_cache'):
            self._adx_cache: Dict[str, tuple] = {}  # {market: (ts, adx_val)}
        cached = self._adx_cache.get(market)
        if cached and now - cached[0] < 60 and cached[1] > 0:
            self._last_adx_value = cached[1]
            if len(cached) >= 4:
                self._last_plus_di = cached[2]
                self._last_minus_di = cached[3]
            return {"adx": cached[1],
                    "plus_di": (cached[2] if len(cached) >= 4 else 0.0),
                    "minus_di": (cached[3] if len(cached) >= 4 else 0.0)}
        try:
            from app.strategy.indicators import adx as _adx_fn
            raw = self._get_client().get_kline(market, interval=self.config.primary_tf, limit=60)
            if not raw or len(raw) < 30:
                return None
            highs = [float(r[2]) for r in raw if len(r) >= 5]
            lows = [float(r[3]) for r in raw if len(r) >= 5]
            closes = [float(r[4]) for r in raw if len(r) >= 5]
            result = _adx_fn(highs, lows, closes, period=14)
            if result:
                _pdi = float(result.get("plus_di", 0.0) or 0.0)
                _mdi = float(result.get("minus_di", 0.0) or 0.0)
                self._adx_cache[market] = (now, result["adx"], _pdi, _mdi)
                # 레거시 호환 (대시보드 표시용)
                self._last_adx_value = result["adx"]
                self._last_plus_di = _pdi
                self._last_minus_di = _mdi
                self._last_adx_ts = now
            return result
        except Exception as exc:
            logger.debug("[FOCUS] ADX fetch failed for %s: %s", market, exc)
            return None

    def _peak_fade_penalty(self, candles_primary: list, direction: str) -> int:
        """봉우리 추적 감점 — 높은산→더높은산→작은산 = 내리막 신호.

        [2026-04-18] user 요청 "24시간 돌아가게 다 풀자" — Peak Fade 완전 비활성화
        이전 -5 감점이 HYPE/ORDI conviction을 지속 차단 → 진입 기회 봉쇄의 주원인
        """
        return 0
        PENALTY = -5  # [2026-04-17] -3 → -5 강화: conv7-5=2(간신히통과), conv6-5=1(BLOCKED)
        try:
            if not candles_primary or len(candles_primary) < 15:
                return 0

            from app.strategy.greenpen.pa_detector import OHLCV as _O
            from app.strategy.greenpen.market_structure import (
                _detect_swing_highs, _detect_swing_lows, SwingType
            )

            _candles = []
            for c in candles_primary:
                if hasattr(c, 'high'):
                    _candles.append(c)
                elif isinstance(c, (list, tuple)) and len(c) >= 4:
                    _candles.append(_O(float(c[0]), float(c[1]), float(c[2]), float(c[3])))
            if len(_candles) < 15:
                return 0

            dir_upper = direction.upper()

            if dir_upper == "LONG":
                # 고점 추적: 최근 3개 swing high
                highs = _detect_swing_highs(_candles, lookback=3)
                if len(highs) >= 3:
                    h1, h2, h3 = highs[-3][1], highs[-2][1], highs[-1][1]
                    # HH → HH → LH (높은산→더높은산→작은산)
                    if h2 > h1 and h3 < h2:
                        logger.info(
                            "[FOCUS] Peak Fade: LONG penalty — highs %.2f→%.2f→%.2f (HH→HH→LH)",
                            h1, h2, h3
                        )
                        return PENALTY
                    # HH → LH → LH (이미 내리막)
                    if h2 < h1 and h3 < h2:
                        logger.info(
                            "[FOCUS] Peak Fade: LONG penalty — highs %.2f→%.2f→%.2f (LH→LH descending)",
                            h1, h2, h3
                        )
                        return PENALTY

            elif dir_upper == "SHORT":
                # 저점 추적: 최근 3개 swing low
                lows = _detect_swing_lows(_candles, lookback=3)
                if len(lows) >= 3:
                    l1, l2, l3 = lows[-3][1], lows[-2][1], lows[-1][1]
                    # LL → LL → HL (낮은골→더낮은골→높은골)
                    if l2 < l1 and l3 > l2:
                        logger.info(
                            "[FOCUS] Peak Fade: SHORT penalty — lows %.2f→%.2f→%.2f (LL→LL→HL)",
                            l1, l2, l3
                        )
                        return PENALTY
                    # LL → HL → HL (이미 오르막)
                    if l2 > l1 and l3 > l2:
                        logger.info(
                            "[FOCUS] Peak Fade: SHORT penalty — lows %.2f→%.2f→%.2f (HL→HL ascending)",
                            l1, l2, l3
                        )
                        return PENALTY

        except Exception as exc:
            logger.debug("[FOCUS] peak_fade_penalty error: %s", exc)
        return 0

    def _record_skip(self, market: str, direction: str, conviction: int, pa: str, reason: str) -> None:
        """Skip 이유 추적 (부모 지시 가시화). 최신 N건만 유지.

        Args:
            market: 코인 (예: BTCUSDT)
            direction: LONG/SHORT/"-"
            conviction: 점수 (0~16)
            pa: PA pattern 이름 (없으면 "-")
            reason: skip 사유 (low_conviction, bb_extreme_overbought, ...)
        """
        try:
            entry = {
                "ts": time.time(),
                "market": str(market or "-"),
                "direction": str(direction or "-"),
                "conviction": float(conviction or 0),  # [2026-05-17 100점 ×10] int 절삭 제거 (분별력 보존)
                "pa": str(pa or "-"),
                "reason": str(reason or "-"),
            }
            self.recent_skips.append(entry)
            # 최신 N건만 유지 (오래된 것부터 제거)
            if len(self.recent_skips) > self.recent_skips_max:
                self.recent_skips = self.recent_skips[-self.recent_skips_max:]
        except Exception as exc:
            logger.debug("[FOCUS] _record_skip error: %s", exc)

    def _zones_for_pa(self) -> Optional[Tuple[float, float]]:
        """self.zones (list of dict) → (support_price, resistance_price) tuple.
        PA detector zone_prices 형식 변환. 둘 중 하나라도 없으면 None.
        """
        try:
            sup_prices = []
            res_prices = []
            for z in (self.zones or []):
                ztype = str(z.get("type", "")).upper()
                pl = float(z.get("price_low", 0) or 0)
                ph = float(z.get("price_high", 0) or 0)
                mid = (pl + ph) / 2 if (pl > 0 and ph > 0) else (pl or ph)
                if mid <= 0:
                    continue
                if "SUPPORT" in ztype or "DEMAND" in ztype:
                    sup_prices.append(mid)
                elif "RESIST" in ztype or "SUPPLY" in ztype:
                    res_prices.append(mid)
            if not sup_prices or not res_prices:
                return None
            # 가장 가까운 support / 가장 가까운 resistance — 단순화: max sup / min res
            return (max(sup_prices), min(res_prices))
        except Exception:
            return None

    def _compute_zones_for_symbol(self, symbol: str, candles_primary: list) -> Optional[Tuple[float, float]]:
        """[2026-05-17 Phase 4.7] 코인별 zones 동적 계산 (Scanner 다코인 모드 대응).

        부모님 발견: Scanner 가 다른 코인 평가 시 self._zones_for_pa() = self.selected_market(XAUT) zones
        → 모든 코인에 XAUT zones 적용 → S/R 위치 % 계산 비정상.

        해결: candles_primary (해당 symbol H4) 로 full_analysis 호출 → 코인별 zones.
        캐싱: 1시간 TTL (H4 변화 느림).
        Returns: (support_price, resistance_price) 또는 None.
        """
        if not candles_primary or len(candles_primary) < 20:
            return None
        if not hasattr(self, '_zones_cache'):
            self._zones_cache = {}  # {symbol: (ts, zones_tuple)}
        import time as _time
        now = _time.time()
        cached = self._zones_cache.get(symbol)
        if cached and (now - cached[0]) < 3600:
            return cached[1]
        try:
            from app.strategy.greenpen import full_analysis
            analysis = full_analysis(candles_primary)
            zones_raw = getattr(analysis, 'zones', []) or []
            sup_prices = []
            res_prices = []
            for z in zones_raw:
                ztype = str(getattr(z, 'type', '')).upper()
                if hasattr(getattr(z, 'type', None), 'value'):
                    ztype = str(z.type.value).upper()
                pl = float(getattr(z, 'price_low', 0) or 0)
                ph = float(getattr(z, 'price_high', 0) or 0)
                mid = (pl + ph) / 2 if (pl > 0 and ph > 0) else (pl or ph)
                if mid <= 0:
                    continue
                if "SUPPORT" in ztype or "DEMAND" in ztype:
                    sup_prices.append(mid)
                elif "RESIST" in ztype or "SUPPLY" in ztype:
                    res_prices.append(mid)
            if not sup_prices or not res_prices:
                self._zones_cache[symbol] = (now, None)
                return None
            zones_tuple = (max(sup_prices), min(res_prices))
            self._zones_cache[symbol] = (now, zones_tuple)
            return zones_tuple
        except Exception as exc:
            logger.debug("[FOCUS] zones for symbol %s error: %s", symbol, exc)
            return None

    def _compute_pa_weight(self, candles_primary: list, direction: str, zones: Optional[Tuple[float, float]] = None, caller: str = "focus") -> Tuple[int, str]:
        """PA Pattern conviction weight 계산 (0~6).

        Thai GreenPen 원본 5패턴 + BOS 신규 매핑.
        반환: (점수, 디버그 라벨)

        ★ caller 차별화 (2026-04-24 부모 지시):
          - "focus"  : FocusConfig.pa_weight_* 사용 (STAR_V1 우대 = H4 reversal)
          - "harpoon": HarpoonConfig.pa_weight_* 사용 (PIN/ENG/SQUEEZE/BOS 우대 = 단기)

        규칙:
          1) detect_pa_patterns() → 최근 봉 신호만 (idx == -1 or last)
          2) direction 일치 신호만 인정
          3) 패턴별 base score (caller config 적용)
          4) 동시 발견 시 max() 채택 (중복 가산 금지)
          5) zone 근처면 +zone_bonus / 멀면 ×penalty
        """
        cfg = self.config
        if not getattr(cfg, "pa_weight_enabled", False):
            return (0, "pa_off")
        if not candles_primary or len(candles_primary) < 4:
            return (0, "pa_no_candles")
        if not direction:
            return (0, "pa_no_direction")

        # ── caller 별 가중치 dict 결정 ──
        if caller == "harpoon":
            try:
                from app.manager.harpoon_manager import harpoon_manager
                hcfg = harpoon_manager.config
                weights = {
                    "PIN_BAR": int(getattr(hcfg, "pa_weight_pin_bar", 2)),
                    "ENGULFING": int(getattr(hcfg, "pa_weight_engulfing", 3)),
                    "STAR_V1": int(getattr(hcfg, "pa_weight_star_v1", 1)),
                    "STAR_V2": int(getattr(hcfg, "pa_weight_star_v2", 3)),
                    "SQUEEZE_BREAK": int(getattr(hcfg, "pa_weight_squeeze_break", 3)),
                    "BOS_BULLISH": int(getattr(hcfg, "pa_weight_bos", 3)),
                    "BOS_BEARISH": int(getattr(hcfg, "pa_weight_bos", 3)),
                }
                zone_bonus = int(getattr(hcfg, "pa_weight_zone_bonus", 1))
                proximity_atr = float(getattr(hcfg, "pa_zone_proximity_atr", 0.5))
                penalty_mult = float(getattr(hcfg, "pa_location_penalty_far", 0.5))
            except Exception:
                # fallback to focus weights
                caller = "focus"

        if caller == "focus":
            weights = {
                "PIN_BAR": int(getattr(cfg, "pa_weight_pin_bar", 1)),
                "ENGULFING": int(getattr(cfg, "pa_weight_engulfing", 2)),
                "STAR_V1": int(getattr(cfg, "pa_weight_star_v1", 3)),
                "STAR_V2": int(getattr(cfg, "pa_weight_star_v2", 3)),
                "SQUEEZE_BREAK": int(getattr(cfg, "pa_weight_squeeze_break", 2)),
                "BOS_BULLISH": int(getattr(cfg, "pa_weight_bos", 2)),
                "BOS_BEARISH": int(getattr(cfg, "pa_weight_bos", 2)),
            }
            zone_bonus = int(getattr(cfg, "pa_weight_zone_bonus", 1))
            proximity_atr = float(getattr(cfg, "pa_zone_proximity_atr", 0.5))
            penalty_mult = float(getattr(cfg, "pa_location_penalty_far", 0.5))

        try:
            from app.strategy.greenpen.pa_detector import (
                detect_pa_patterns, OHLCV as _PAO, PatternType, Direction as PADir,
            )
            # 후보 candles_primary → OHLCV 정규화
            _pa_candles = []
            for c in candles_primary[-50:]:  # 최근 50봉만
                if hasattr(c, "open") and hasattr(c, "close"):
                    _pa_candles.append(c)
                elif isinstance(c, (list, tuple)) and len(c) >= 4:
                    _pa_candles.append(_PAO(float(c[0]), float(c[1]), float(c[2]), float(c[3])))
            if len(_pa_candles) < 4:
                return (0, "pa_too_short")

            signals = detect_pa_patterns(_pa_candles, zone_prices=zones)
            if not signals:
                return (0, "pa_no_signal")

            target_dir = PADir.LONG if direction.upper() == "LONG" else PADir.SHORT
            last_idx = len(_pa_candles) - 1
            # 최근 봉(또는 -1) 신호만 인정
            recent = [s for s in signals
                      if s.direction == target_dir
                      and (s.candle_idx == -1 or s.candle_idx == last_idx or s.candle_idx >= last_idx - 1)]
            if not recent:
                return (0, "pa_dir_mismatch")

            # 패턴별 max score (caller 별 weights 적용)
            best = 0
            best_label = "pa_none"
            for s in recent:
                pname = s.pattern.value
                w = weights.get(pname, 0)
                if w > best:
                    best, best_label = w, f"{pname}({w})"

            if best <= 0:
                return (0, "pa_unknown")

            # ── Location 보정 (Thai 원본 강조: 지지/저항 근처) ──
            if zones is not None and len(zones) >= 2:
                support, resistance = float(zones[0]), float(zones[1])
                last_price = float(_pa_candles[-1].close)
                # ATR proxy: 최근 14봉 H-L 평균
                _hl = [c.high - c.low for c in _pa_candles[-14:]]
                atr_est = sum(_hl) / max(1, len(_hl)) if _hl else (last_price * 0.01)
                if atr_est <= 0:
                    atr_est = last_price * 0.01

                if direction.upper() == "LONG":
                    dist = abs(last_price - support) / atr_est
                elif direction.upper() == "SHORT":
                    dist = abs(resistance - last_price) / atr_est
                else:
                    dist = 999.0

                if dist <= proximity_atr:
                    best += zone_bonus
                    best_label += f"+zone({zone_bonus})"
                else:
                    new_best = int(best * penalty_mult)
                    best_label += f"×{penalty_mult:.1f}far({best}->{new_best})"
                    best = new_best

            # 최대 cap (overflow 방어) — 부모님 5/19 100점 native: 6 → 10
            best = max(0, min(best, 10))
            return (best, best_label)

        except Exception as exc:
            logger.debug("[FOCUS] _compute_pa_weight error: %s", exc)
            return (0, f"pa_err:{exc.__class__.__name__}")

    # ─────────────────────────────────────────────────────────────────
    # ★★★ Phase 1 Conviction 정밀화 helper 함수 (2026-05-11 부모님 95%/98% 목표)
    # "신뢰도 점수에 진짜 눈의 역할" — 시그널 개수 X, 시그널 품질 + 충돌 + 역행
    # ─────────────────────────────────────────────────────────────────

    def _get_mtf_kline(self, market: str, interval: str, limit: int = 40, ttl: float = 60.0) -> list:
        """MTF kline 캐시 조회 — _compute_mtf_conflict_penalty 전용. key=f"{market}:{interval}", TTL 60초.

        [2026-05-15] H1 전환으로 MTF fetch 가 2→4 건 증가 → 16코인 스캔 시 부하 누적.
        같은 (market, interval) 캔들을 60초 내 재호출하면 캐시 히트 → 실 API 호출 대폭 감소.
        """
        ck = f"{market}:{interval}"
        now = time.time()
        cached = self._mtf_kline_cache.get(ck)
        # [2026-06-12] 키가 {market}:{interval} 라 limit 무시 → 작은 limit 이 먼저 캐시되면
        # 큰 limit 요청이 모자란 봉을 받는 충돌. len(cached) >= limit 일 때만 캐시 사용.
        # (cowork 재미나이 catch — 잠재 collision 가드)
        if cached and (now - cached[0]) < ttl and len(cached[1]) >= limit:
            return cached[1]
        try:
            raw = self._get_client().get_kline(market, interval=interval, limit=limit)
            if raw:
                self._mtf_kline_cache[ck] = (now, raw)
                return raw
        except Exception as exc:
            logger.debug("[FOCUS] MTF kline fetch failed %s: %s", ck, exc)
        # fetch 실패 시 stale 캐시라도 반환 (없으면 빈 리스트)
        return cached[1] if cached else []

    def _compute_tf_progress(self, market: str) -> dict:
        """7개 TF (D/H4/H1/30M/15M/5M/3M) 의 *진행 중* 봉 정보 — 수동 진입 참고용.

        [2026-05-21 부모님 결정] 봉 닫히기 전 흐름 시각화.
        진입 로직/가드 변경 X — 정보 표시 전용.

        각 TF row:
          - elapsed_pct: 봉 시작 후 흐른 시간 / TF 주기 × 100
          - delta_pct: 봉 시가 → 현재가 ±%
          - direction: bull / bear / flat
          - body_pct: |close-open|/open × 100 (몸통 크기)
          - upper_wick_pct, lower_wick_pct: 꼬리 비율
          - open/high/low/current
        """
        import time as _time
        tf_table = [
            ("D", 1440, "D"),
            ("H4", 240, "240"),
            ("H1", 60, "60"),
            ("30M", 30, "30"),
            ("15M", 15, "15"),
            ("5M", 5, "5"),
            ("3M", 3, "3"),
        ]

        # 현재 가격 (live)
        live_price = 0.0
        try:
            from app.core import price_store
            _lp = price_store.get_price(market, max_age_sec=60.0)
            if _lp and _lp > 0:
                live_price = float(_lp)
        except Exception:
            pass
        if live_price <= 0:
            try:
                raw_5 = self._get_mtf_kline(market, "5", limit=2, ttl=5.0)
                if raw_5:
                    live_price = float(raw_5[-1][4])
            except Exception:
                return {"ok": False, "market": market, "error": "no_live_price"}

        now_ms = int(_time.time() * 1000)
        rows = []
        for tf_name, tf_min, tf_str in tf_table:
            try:
                raw = self._get_mtf_kline(market, tf_str, limit=2, ttl=10.0)
                if not raw:
                    rows.append({"tf": tf_name, "ok": False, "reason": "no_data"})
                    continue
                last = raw[-1]
                bar_ts = int(last[0])
                bar_open = float(last[1])
                bar_high = float(last[2])
                bar_low = float(last[3])
                tf_ms = tf_min * 60 * 1000
                elapsed_ms = max(0, now_ms - bar_ts)
                elapsed_pct = min(100.0, (elapsed_ms / tf_ms) * 100.0)

                # 가격 계산 — high/low 는 live 와 비교해서 갱신 (현재 봉이 진행 중이라)
                cur_high = max(bar_high, live_price)
                cur_low = min(bar_low, live_price) if bar_low > 0 else live_price

                if bar_open > 0:
                    delta_pct = ((live_price - bar_open) / bar_open) * 100.0
                    body_pct = abs(live_price - bar_open) / bar_open * 100.0
                    range_pct = (cur_high - cur_low) / bar_open * 100.0
                    upper_wick = (cur_high - max(live_price, bar_open)) / bar_open * 100.0
                    lower_wick = (min(live_price, bar_open) - cur_low) / bar_open * 100.0
                else:
                    delta_pct = body_pct = range_pct = upper_wick = lower_wick = 0.0

                if delta_pct > 0.01:
                    direction = "bull"
                elif delta_pct < -0.01:
                    direction = "bear"
                else:
                    direction = "flat"

                rows.append({
                    "tf": tf_name,
                    "ok": True,
                    "elapsed_pct": round(elapsed_pct, 1),
                    "delta_pct": round(delta_pct, 3),
                    "direction": direction,
                    "body_pct": round(body_pct, 3),
                    "range_pct": round(range_pct, 3),
                    "upper_wick_pct": round(max(0.0, upper_wick), 3),
                    "lower_wick_pct": round(max(0.0, lower_wick), 3),
                    "open": bar_open,
                    "high": cur_high,
                    "low": cur_low,
                    "current": live_price,
                })
            except Exception as exc:
                rows.append({"tf": tf_name, "ok": False, "reason": str(exc)[:40]})

        # 합의도: bull/bear 개수
        n_bull = sum(1 for r in rows if r.get("direction") == "bull")
        n_bear = sum(1 for r in rows if r.get("direction") == "bear")
        n_flat = sum(1 for r in rows if r.get("direction") == "flat")
        if n_bull >= 5:
            consensus = "STRONG_BULL"
        elif n_bear >= 5:
            consensus = "STRONG_BEAR"
        elif n_bull >= 4:
            consensus = "BULL"
        elif n_bear >= 4:
            consensus = "BEAR"
        else:
            consensus = "MIXED"

        return {
            "ok": True,
            "market": market,
            "current_price": live_price,
            "ts": now_ms,
            "rows": rows,
            "consensus": consensus,
            "n_bull": n_bull,
            "n_bear": n_bear,
            "n_flat": n_flat,
        }

    def _check_microtiming_5m(self, market: str, direction: str) -> Tuple[bool, str, int]:
        """5m 마이크로 타이밍 게이트 — RSI/MACD/BB 변곡 3종 점수.

        [2026-05-16 부모] "들어갈 자리를 억지로라도 찾아야" → BLOCK 아닌 WAIT.
        conviction 통과 후보를 5m 캔들 20봉으로 검사. 점수 ≥ min_score 면 GO, 아니면 defer.

        Returns: (pass, label, score)
            pass: bool — True=진입 GO / False=defer (호출자가 BLOCK 카운트 없이 다음 후보로)
            label: 사람 읽기용 ("rsi+1,macd+1,bb+0=2/3")
            score: int 0~3
        """
        # ★ [2026-05-28 저녁 부모] yellow 마스터 토글 — green only 모드 시 skip
        if not getattr(self.config, "microtiming_5m_enabled", False) or not self._is_yellow_guard_active("entry"):
            return True, "OFF", 0
        dir_up = (direction or "").upper()
        if dir_up not in ("LONG", "SHORT"):
            return True, "no-dir", 0

        try:
            raw = self._get_mtf_kline(market, "5", limit=30)
            if not raw or len(raw) < 27:  # MACD 26 + 1 prev 필요
                logger.debug("[FOCUS] microtiming_5m: %s insufficient 5m candles (%d)", market, len(raw) if raw else 0)
                return True, "fetch_short", 0  # fetch 실패 시 통과 (게이트 자체 무효화 — 안전 측)
            closes = [float(r[4]) for r in raw]

            from app.strategy.indicators import rsi_with_prev, macd_hist_pair, bollinger_bands as _bb_fn

            # RSI 변곡: 직전 vs 현재
            rsi_now, rsi_prev = rsi_with_prev(closes, length=14)

            # MACD hist 변곡: 직전 vs 현재
            hist_now, hist_prev = macd_hist_pair(closes)

            # BB position: (price - lower) / (upper - lower) * 100
            bb_now = _bb_fn(closes, length=20, k=2.0)
            bb_prev = _bb_fn(closes[:-1], length=20, k=2.0) if len(closes) >= 21 else None

            def _bb_pct(bb: Optional[Dict], price: float) -> Optional[float]:
                if not bb or bb.get("upper", 0) <= bb.get("lower", 0):
                    return None
                rng = bb["upper"] - bb["lower"]
                return ((price - bb["lower"]) / rng) * 100.0

            bb_now_pct = _bb_pct(bb_now, closes[-1])
            bb_prev_pct = _bb_pct(bb_prev, closes[-2]) if bb_prev and len(closes) >= 2 else None

            rsi_long_thr = float(getattr(self.config, "microtiming_5m_rsi_long_threshold", 35.0))
            rsi_short_thr = float(getattr(self.config, "microtiming_5m_rsi_short_threshold", 65.0))
            bb_low_pct = float(getattr(self.config, "microtiming_5m_bb_low_pct", 20.0))
            bb_recover_pct = float(getattr(self.config, "microtiming_5m_bb_recover_pct", 30.0))

            # ── 3종 점수 ──
            rsi_score = 0
            macd_score = 0
            bb_score = 0

            if dir_up == "LONG":
                # RSI: 직전 oversold(≤thr) → 현재 상승 변곡
                if rsi_prev is not None and rsi_now is not None:
                    if rsi_prev <= rsi_long_thr and rsi_now > rsi_prev:
                        rsi_score = 1
                # MACD hist: 직전 음수 → 현재 양수 OR 음수 절댓값 축소
                if hist_prev is not None and hist_now is not None and hist_prev < 0:
                    if hist_now > 0 or hist_now > hist_prev:
                        macd_score = 1
                # BB: 직전 하단권 → 현재 회복
                if bb_prev_pct is not None and bb_now_pct is not None:
                    if bb_prev_pct < bb_low_pct and bb_now_pct >= bb_recover_pct:
                        bb_score = 1
            else:  # SHORT
                if rsi_prev is not None and rsi_now is not None:
                    if rsi_prev >= rsi_short_thr and rsi_now < rsi_prev:
                        rsi_score = 1
                if hist_prev is not None and hist_now is not None and hist_prev > 0:
                    if hist_now < 0 or hist_now < hist_prev:
                        macd_score = 1
                if bb_prev_pct is not None and bb_now_pct is not None:
                    bb_high_pct = 100.0 - bb_low_pct
                    bb_drop_pct = 100.0 - bb_recover_pct
                    if bb_prev_pct > bb_high_pct and bb_now_pct <= bb_drop_pct:
                        bb_score = 1

            total = rsi_score + macd_score + bb_score
            min_score = int(getattr(self.config, "microtiming_5m_min_score", 2))
            ok = total >= min_score

            # 라벨 (디버그용 — 실제 값 일부 표시)
            _rn = f"{rsi_now:.0f}" if rsi_now is not None else "?"
            _rp = f"{rsi_prev:.0f}" if rsi_prev is not None else "?"
            _hn = f"{hist_now:.3f}" if hist_now is not None else "?"
            _hp = f"{hist_prev:.3f}" if hist_prev is not None else "?"
            _bn = f"{bb_now_pct:.0f}" if bb_now_pct is not None else "?"
            _bp = f"{bb_prev_pct:.0f}" if bb_prev_pct is not None else "?"
            label = (f"rsi+{rsi_score}({_rp}→{_rn}),"
                     f"macd+{macd_score}({_hp}→{_hn}),"
                     f"bb+{bb_score}({_bp}%→{_bn}%)={total}/3")
            return ok, label, total

        except Exception as exc:
            logger.debug("[FOCUS] microtiming_5m calc error for %s: %s", market, exc)
            return True, "ERROR", 0  # 에러 시 안전 측: 통과 (게이트 자체 무효화)

    def _check_micro_1m(self, market: str, direction: str) -> Tuple[bool, str]:
        """★ [2026-06-05 부모] 1M 마이크로 체크 — "지금 이 순간" 타이밍 검증.

        conv 100이어도 5M 봉 끝에서 진입 = 즉시 역행 패턴 방지.
        ① 마지막 1M 봉 방향 (역방향이면 WAIT)
        ② 1M 거래량 연속 감소 (추진력 소진이면 WAIT)
        ③ 1M RSI 극단 (과열이면 WAIT)
        하나라도 WAIT 이면 이번 tick 진입 보류 (다음 tick 재평가).
        Returns: (ok: bool, reason: str)
        """
        cfg = self.config
        if not getattr(cfg, "micro_1m_check_enabled", True):
            return True, ""
        dir_up = (direction or "").upper()
        try:
            raw = self._get_mtf_kline(market, "1", limit=16, ttl=10.0)
            if not raw or len(raw) < 6:
                return True, "1m_no_data"  # fail-open

            # ① 마지막 1M 봉 방향
            if getattr(cfg, "micro_1m_candle_check", True):
                # ★ [2026-06-11 부모 B안] 추세 강하면(ADX≥exempt=벽타기) 1M 봉 잔파동 무시 → 진입 지연 방지.
                #   STG LONG 90.8점이 1M 음봉에 3분 막혀 고점 진입 / BEAT SHORT 98점이 1M 양봉에 40분 막혀 기회 소멸 → 실증.
                _ce_exempt = False
                _ce_adx = float(getattr(cfg, "micro_1m_candle_trend_exempt_adx", 0.0) or 0.0)
                if _ce_adx > 0:
                    try:
                        _ce_d = self._fetch_primary_adx(market)
                        if _ce_d and float(_ce_d.get("adx", 0.0)) >= _ce_adx:
                            _ce_exempt = True
                            logger.debug("[FOCUS] micro_1m candle 면제(벽타기): %s %s ADX≥%.0f — 1M 봉 무시", direction, market, _ce_adx)
                    except Exception:
                        pass
                if not _ce_exempt:
                    last = raw[-1]
                    if len(last) >= 5:
                        _open = float(last[1])
                        _close = float(last[4])
                        if dir_up == "LONG" and _close < _open:
                            return False, f"1m_candle_against(LONG but 1M 음봉 o={_open:.4f} c={_close:.4f})"
                        elif dir_up == "SHORT" and _close > _open:
                            return False, f"1m_candle_against(SHORT but 1M 양봉 o={_open:.4f} c={_close:.4f})"
                        # ④ [2026-06-06 부모] body 강도(점화) — 방향 맞아도 약한 도지면 "지금" 아님 → 대기
                        _body_min = float(getattr(cfg, "micro_1m_body_min_pct", 0.0) or 0.0)
                        if _body_min > 0 and _open > 0:
                            _body_pct = abs(_close - _open) / _open * 100.0
                            if _body_pct < _body_min:
                                return False, f"1m_body_weak(body={_body_pct:.3f}%<{_body_min}% 약한봉 점화대기)"

            # ② 거래량 연속 감소
            if getattr(cfg, "micro_1m_volume_check", True):
                n = int(getattr(cfg, "micro_1m_vol_decline_bars", 3))
                if len(raw) >= n + 1:
                    vols = [float(r[5]) if len(r) >= 6 else 0 for r in raw[-(n+1):]]
                    if all(v > 0 for v in vols):
                        declining = all(vols[i] > vols[i+1] for i in range(len(vols)-1))
                        if declining:
                            return False, f"1m_vol_decline({n}봉 연속 감소 {[round(v,0) for v in vols]})"

            # ③ RSI 극단
            if getattr(cfg, "micro_1m_rsi_check", True):
                closes = [float(r[4]) for r in raw if len(r) >= 5]
                if len(closes) >= 15:
                    gains, losses = [], []
                    for i in range(1, len(closes)):
                        d = closes[i] - closes[i-1]
                        gains.append(max(0, d))
                        losses.append(max(0, -d))
                    ag = sum(gains[-14:]) / 14.0
                    al = sum(losses[-14:]) / 14.0
                    rsi = 100.0 - (100.0 / (1.0 + ag / al)) if al > 0 else 100.0
                    _long_max = float(getattr(cfg, "micro_1m_rsi_long_max", 70.0))
                    _short_min = float(getattr(cfg, "micro_1m_rsi_short_min", 30.0))
                    if dir_up == "LONG" and rsi > _long_max:
                        return False, f"1m_rsi_overheat(LONG RSI={rsi:.1f}>{_long_max})"
                    elif dir_up == "SHORT" and rsi < _short_min:
                        return False, f"1m_rsi_overheat(SHORT RSI={rsi:.1f}<{_short_min})"

            return True, "1m_ok"
        except Exception as exc:
            logger.debug("[FOCUS] micro_1m error (fail-open): %s", exc)
            return True, "1m_error"

    def _compute_momentum_reversal_penalty(self, market: str, direction: str) -> Tuple[int, str]:
        """Momentum Reversal 감점 — 진입 직전 5m 1~3봉 역행 감지.

        "이미 다 움직인 후 진입" 회피. LONG 진입에 5m 1봉 -ATR*1.0 = 강한 역행.

        Returns: (penalty, label)
            penalty: 0 ~ momentum_reversal_strong_weight (-3 default)
            label: "strong_rev (1.2ATR)" / "medium_rev (0.7ATR)" / "ok (+0.3ATR)"
        """
        if not getattr(self.config, "momentum_reversal_enabled", True):
            return 0, "OFF"
        dir_up = (direction or "").upper()
        if dir_up not in ("LONG", "SHORT"):
            return 0, "no-dir"

        try:
            raw = self._get_client().get_kline(market, interval="5", limit=20)
            if not raw or len(raw) < 5:
                return 0, "no-data"

            # candle 형식: [ts, open, high, low, close, volume]
            highs = [float(r[2]) for r in raw[-15:] if len(r) >= 5]
            lows = [float(r[3]) for r in raw[-15:] if len(r) >= 5]
            closes = [float(r[4]) for r in raw[-15:] if len(r) >= 5]

            lookback = int(getattr(self.config, "momentum_reversal_lookback_bars", 3))
            lookback = max(1, min(lookback, 5))

            if len(closes) < lookback + 2:
                return 0, "no-data"

            # ATR 5m (true range, period=14) 인라인 — 옛 `indicators.atr` import 가 깨져
            # 이 guard 가 통째로 no-op(except→0감점) 였음. spot_entry_guards.check_momentum_reversal
            # 와 동일한 직접 계산으로 교정(로직/임계 불변, ATR 산식만 살림).
            trs, pc = [], None
            for h, l, c in zip(highs, lows, closes):
                tr = (h - l) if pc is None else max(h - l, abs(h - pc), abs(l - pc))
                trs.append(tr)
                pc = c
            atr_val = sum(trs[-14:]) / min(len(trs), 14) if trs else 0.0
            if not atr_val or atr_val <= 0:
                return 0, "no-atr"

            # 마지막 1봉 close 변화
            last_change = closes[-1] - closes[-2]

            # 진입 방향 vs 역행 (양수 = 역행)
            if dir_up == "LONG":
                adverse_1bar = -last_change  # 하락 = 역행
            else:  # SHORT
                adverse_1bar = last_change   # 상승 = 역행

            strong_thr = float(getattr(self.config, "momentum_reversal_strong_atr", 1.0)) * atr_val
            medium_thr = float(getattr(self.config, "momentum_reversal_medium_atr", 0.5)) * atr_val

            strong_w = float(getattr(self.config, "momentum_reversal_strong_weight", -30.0))  # [100점 ×10]
            medium_w = float(getattr(self.config, "momentum_reversal_medium_weight", -20.0))  # [100점 ×10]

            if adverse_1bar >= strong_thr:
                return strong_w, f"strong_rev ({adverse_1bar/atr_val:+.1f}ATR)"
            elif adverse_1bar >= medium_thr:
                return medium_w, f"medium_rev ({adverse_1bar/atr_val:+.1f}ATR)"
            else:
                # 누적 lookback 봉 역행 체크 (1봉은 약해도 3봉 누적 강하면 감점)
                cumulative = closes[-1] - closes[-1 - lookback]
                if dir_up == "LONG":
                    cum_adverse = -cumulative
                else:
                    cum_adverse = cumulative
                if cum_adverse >= strong_thr:
                    return medium_w, f"cum{lookback}_rev ({cum_adverse/atr_val:+.1f}ATR)"

            return 0, f"ok ({adverse_1bar/atr_val:+.1f}ATR)"

        except Exception as exc:
            logger.debug("[FOCUS] momentum reversal calc error for %s: %s", market, exc)
            return 0, "ERROR"

    # ─────────────────────────────────────────────────────────────────
    # ★★★ Phase 2 Conviction 정밀화 helper 함수 (2026-05-11 부모님 95%/98% 두 번째 걸음)
    # "이 표의 점수 = 시스템의 눈" — 위치 정밀 + 모멘텀 동조
    # ─────────────────────────────────────────────────────────────────

    # ============================================================
    # ★ [2026-05-17 Phase 4 Top-down 100점 산식 - 신규 헬퍼 5개]
    #   plan: docs/plan_conviction_phase4_top_down_2026-05-17.md
    #   18 조건 = 멀티 TF 정렬 매트릭스 + 4 TF 변화율 + RSI + S/R + Volume + 기존 ADX/MACD/BB/PA + 시간/코인 + 별도 (Reentry/Context/MomRev)
    # ============================================================

    def _coin_baseline_stats(self, market: str, candles_primary: Optional[list]) -> Optional[dict]:
        """[2026-05-17 Phase 4.5] 코인 평소 변동성 통계 (H4 100 캔들).

        부모님 통찰: "코인 특성에 맞는 변동폭 기준 점수화"
        BILL (도박형 BB 18%) vs BTC (안정 BB 1.5%) 같은 임계 X → 정규화.
        plan: docs/plan_conviction_phase4_5_coin_normalization_2026-05-17.md

        Returns: dict 또는 None (데이터 부족)
          'bb_avg': float (BB 밴드폭% 평균)
          'macd_avg': float (MACD hist% 평균)
          'adx_avg': float (ADX 평균)
          'atr_avg_pct': float (ATR% 평균)
          'n': int (실제 사용 캔들 수)
        캐싱: 코인별 TTL 3600s (H4 변화 느림)
        """
        if not hasattr(self, '_phase45_stats_cache'):
            self._phase45_stats_cache = {}
        import time as _time
        now = _time.time()
        cached = self._phase45_stats_cache.get(market)
        if cached and (now - cached[0]) < 3600:
            return cached[1]

        if not candles_primary or len(candles_primary) < 50:
            return None

        try:
            from app.strategy.indicators import bollinger_bands, macd_hist_pair, atr_simplified

            closes = []
            for c in candles_primary:
                if hasattr(c, 'close'): closes.append(float(c.close))
                elif isinstance(c, (list, tuple)) and len(c) >= 4: closes.append(float(c[3]))

            if len(closes) < 50:
                return None

            N = min(100, len(closes))
            recent = closes[-N:]

            # BB 밴드폭% 평균 (슬라이딩 윈도우)
            bb_widths = []
            for i in range(20, N):
                bb = bollinger_bands(recent[max(0, i-19):i+1], 20, 2.0)
                if bb and bb.get("bandwidth"):
                    bb_widths.append(bb["bandwidth"] * 100)
            bb_avg = sum(bb_widths) / len(bb_widths) if bb_widths else 1.0

            # MACD hist% 평균 (last 부분만 — 부담 줄임)
            macd_hists = []
            for i in range(35, N, 2):  # 격칸 = 부담 절반
                h, _ = macd_hist_pair(recent[:i+1])
                if recent[i] > 0:
                    macd_hists.append(abs(h) / recent[i] * 100)
            macd_avg = sum(macd_hists) / len(macd_hists) if macd_hists else 0.1

            # ATR% 평균 (atr_simplified — closes 기반 근사)
            atr_pcts = []
            for i in range(14, N, 2):
                a = atr_simplified(recent[:i+1], length=14)
                if a and recent[i] > 0:
                    atr_pcts.append(a / recent[i] * 100)
            atr_avg_pct = sum(atr_pcts) / len(atr_pcts) if atr_pcts else 1.0

            # ADX 평균 — H1 100 캔들 adx_series 평균 (Phase 4.6 정밀화)
            adx_baseline = 25.0  # fallback (안정 코인 평균)
            try:
                from app.strategy.indicators import adx_series
                raw_h1 = self._get_client().get_kline(
                    market, interval=self.config.primary_tf, limit=100
                )
                if raw_h1 and len(raw_h1) >= 30:
                    highs_h1 = [float(r[2]) for r in raw_h1 if len(r) >= 5]
                    lows_h1 = [float(r[3]) for r in raw_h1 if len(r) >= 5]
                    closes_h1 = [float(r[4]) for r in raw_h1 if len(r) >= 5]
                    adx_vals = adx_series(highs_h1, lows_h1, closes_h1, period=14)
                    if adx_vals:
                        adx_only = [d["adx"] for d in adx_vals if d and "adx" in d]
                        if adx_only:
                            # 마지막 50개 평균 (최근 안정 평균)
                            recent = adx_only[-50:] if len(adx_only) >= 50 else adx_only
                            adx_baseline = sum(recent) / len(recent)
            except Exception as exc:
                logger.debug("[FOCUS] adx baseline calc error %s: %s", market, exc)

            stats = {
                'bb_avg': bb_avg,
                'macd_avg': macd_avg,
                'adx_avg': adx_baseline,
                'atr_avg_pct': atr_avg_pct,
                'n': N,
            }
            self._phase45_stats_cache[market] = (now, stats)
            logger.debug("[FOCUS] Phase4.5 baseline %s: bb_avg=%.2f%% macd_avg=%.3f%% atr_avg=%.2f%% n=%d",
                         market, bb_avg, macd_avg, atr_avg_pct, N)
            return stats
        except Exception as exc:
            logger.debug("[FOCUS] coin baseline stats error %s: %s", market, exc)
            return None

    def _get_trend_velocity(self, market: str, lookback_sec: float = 300.0) -> Dict[str, float]:
        """[2026-05-20 Phase 6 Stage 0] 에너지바 변화율 산출.

        부모님 직감 룰: BUY 신호 + confidence 하락 = 곧 반대 전환 → SHORT 진입.

        Returns:
            dict with keys:
              - 'current': 현재 confidence (0~1)
              - 'past': lookback_sec 전 confidence (0~1)
              - 'delta_pp': 변화량 (%p, 현재 - 과거, *100 환산)
              - 'trend_now': 현재 trend ("UPTREND"/"DOWNTREND"/"SIDEWAYS")
              - 'trend_past': 과거 trend
              - 'samples': 사용된 데이터 포인트 수
            데이터 부족 시 모든 값 0 / "" 반환.
        """
        try:
            hist = self._confidence_history.get(market)
            if not hist or len(hist) < 2:
                return {'current': 0.0, 'past': 0.0, 'delta_pp': 0.0,
                        'trend_now': "", 'trend_past': "", 'samples': 0}
            now_ts = time.time()
            cutoff_ts = now_ts - lookback_sec
            past_entry = None
            for entry in hist:
                if entry[0] <= cutoff_ts:
                    past_entry = entry
                else:
                    break
            if past_entry is None:
                past_entry = hist[0]
            current = hist[-1]
            delta_pp = (current[2] - past_entry[2]) * 100.0
            return {
                'current': current[2],
                'past': past_entry[2],
                'delta_pp': delta_pp,
                'trend_now': current[1],
                'trend_past': past_entry[1],
                'samples': len(hist),
            }
        except Exception as exc:
            logger.debug("[FOCUS] _get_trend_velocity error %s: %s", market, exc)
            return {'current': 0.0, 'past': 0.0, 'delta_pp': 0.0,
                    'trend_now': "", 'trend_past': "", 'samples': 0}

    def _get_m5_candle_pattern(self, market: str, n: int = 5) -> Dict[str, Any]:
        """[2026-05-20 Phase 6 Stage 4] M5 직전 N봉 패턴 분석.

        부모님 비전 (DOGE 사례): "M5 봉의 기울기 + 갯수에 따른 가산점 → 오르내리는 패턴 가늠".

        Returns:
            dict:
              - 'bull_count': 양봉 수
              - 'bear_count': 음봉 수
              - 'avg_body_pct': 평균 body pct (절대값)
              - 'last_slope_pct': 가장 최근 봉 (open→close) %, 양수=양봉
              - 'dominant_dir': 'BULL'/'BEAR'/'MIXED'
              - 'samples': 실제 분석된 봉 수
            실패 시 빈 dict.
        """
        try:
            client = self._get_client()
            if not client:
                return {}
            cache_key = f"{market}:5"
            now = time.time()
            cached = self._mtf_kline_cache.get(cache_key)
            if cached and (now - cached[0]) < 60:
                raw = cached[1]
            else:
                raw = client.get_kline(market, interval="5", limit=max(n + 1, 10))
                self._mtf_kline_cache[cache_key] = (now, raw)
            if not raw or len(raw) < n:
                return {}
            # Bybit kline 응답은 [최신, ...] 순 — 0번 인덱스 = 현재 진행 중 봉.
            # 진행 중 봉 제외하고 직전 N봉 분석.
            recent = raw[1:n + 1] if len(raw) >= n + 1 else raw[:n]
            bull_count = 0
            bear_count = 0
            bodies = []
            slopes = []
            for r in recent:
                if len(r) < 5:
                    continue
                try:
                    o = float(r[1])
                    c = float(r[4])
                except (ValueError, TypeError):
                    continue
                if o > 0:
                    body_pct = (c - o) / o * 100.0
                    slopes.append(body_pct)
                    bodies.append(abs(body_pct))
                    if c > o:
                        bull_count += 1
                    elif c < o:
                        bear_count += 1
            if not bodies:
                return {}
            avg_body = sum(bodies) / len(bodies)
            last_slope = slopes[0] if slopes else 0.0
            if bull_count >= bear_count + 2:
                dominant = 'BULL'
            elif bear_count >= bull_count + 2:
                dominant = 'BEAR'
            else:
                dominant = 'MIXED'
            return {
                'bull_count': bull_count,
                'bear_count': bear_count,
                'avg_body_pct': avg_body,
                'last_slope_pct': last_slope,
                'dominant_dir': dominant,
                'samples': len(bodies),
            }
        except Exception as exc:
            logger.debug("[FOCUS] _get_m5_candle_pattern error %s: %s", market, exc)
            return {}

    # ── 🌍 거시 레짐 (Market Breadth) — 2026-06-02 부모님 핵심 통찰 ──
    #   대표 10개 코인 5분봉 방향 집계 = 봇 행동 무관 *시장 진실* (B12 자기참조 함정 회피).
    #   부모님: 8/10 같은 방향 = 강한 쓰나미 → 회피+텔레그램 / 6~7 = 중간 → 역행 사이즈↓ / else 약함.
    _BREADTH_COINS = ["BTCUSDT", "ETHUSDT", "SOLUSDT", "BNBUSDT", "XRPUSDT", "DOGEUSDT", "ADAUSDT", "AVAXUSDT", "LINKUSDT", "SUIUSDT"]

    def _coin_dir_simple(self, market: str) -> int:
        """코인 거시 방향 (+1/0/−1) — 1시간 변화율 주력 + 5분 EMA 보조. breadth 집계용.
        [2026-06-02 보강] 5분 EMA spread(0.15%)만으론 하락장도 5분 횡보면 0 = 둔감.
        거시 일제성은 *몇시간 흐름*이지 5분 노이즈가 아니라, 1시간 변화율을 주력으로.
        충돌(전환 중) 시 중립=정밀 — 방향만 정확히 잡고 진입은 안 죽임 (부모님 원칙)."""
        try:
            raw = self._get_mtf_kline(market, "5", limit=25, ttl=60.0)
            if not raw or len(raw) < 21:
                return 0
            closes = [float(r[4]) for r in raw]
            from app.strategy import indicators as _ind
            e9 = _ind.ema(closes, 9)
            e21 = _ind.ema(closes, 21)
            if not e9 or not e21 or closes[-1] <= 0:
                return 0
            spread = (e9 - e21) / closes[-1]                      # 단기 EMA 방향 (보조)
            _b = closes[-13] if len(closes) >= 13 else closes[0]  # 1시간(12봉) 전
            chg1h = (closes[-1] - _b) / _b if _b > 0 else 0.0     # 1시간 변화율 (주력)
            _ct = float(getattr(self.config, "breadth_dir_chg1h_pct", 0.3)) / 100.0   # 1h 변화율 임계 (UI)
            _et = float(getattr(self.config, "breadth_dir_ema_pct", 0.10)) / 100.0    # EMA spread 임계 (UI)
            _up = (chg1h > _ct) or (spread > _et)
            _dn = (chg1h < -_ct) or (spread < -_et)
            if _up and not _dn:
                return 1
            if _dn and not _up:
                return -1
            return 0
        except Exception:
            return 0

    def _compute_market_breadth(self) -> dict:
        """거시 레짐 = 대표 10개 코인 방향 집계. 60초 캐시. 봇 무관 시장 진실.
        부모님 8/10 = 강한 쓰나미(회피) / 6~7 = 중간(사이즈↓) / else 약함. 대칭 양방향."""
        now = time.time()
        _c = getattr(self, "_breadth_cache", None)
        if _c and (now - _c[0]) < 60.0:
            return _c[1]
        # 캐시 없을 때 — 바로 NEUTRAL 반환 후 백그라운드 계산 (느림 방지)
        _neutral = {"verdict": "NEUTRAL", "level": "WEAK", "dir": 0, "up": 0, "down": 0, "total": 10, "label": "NEUTRAL/WEAK(캐시없음)"}
        if getattr(self, "_breadth_computing", False):
            return _neutral
        self._breadth_computing = True
        up = down = 0
        for m in self._BREADTH_COINS:
            d = self._coin_dir_simple(m)
            if d > 0:
                up += 1
            elif d < 0:
                down += 1
        total = len(self._BREADTH_COINS)
        _sn = int(getattr(self.config, "breadth_strong_n", 8))   # STRONG 임계 N/10 (UI 조절)
        _mn = int(getattr(self.config, "breadth_mid_n", 6))      # MID 임계 N/10
        if up >= _sn:
            verdict, level, rdir = "BULL", "STRONG", 1
        elif down >= _sn:
            verdict, level, rdir = "BEAR", "STRONG", -1
        elif up >= _mn:
            verdict, level, rdir = "BULL", "MID", 1
        elif down >= _mn:
            verdict, level, rdir = "BEAR", "MID", -1
        else:
            verdict, level, rdir = "NEUTRAL", "WEAK", 0
        result = {"verdict": verdict, "level": level, "dir": rdir,
                  "up": up, "down": down, "total": total,
                  "label": f"{verdict}/{level}({up}up{down}dn/{total})"}
        self._breadth_cache = (now, result)
        self._breadth_computing = False
        return result

    def _macro_compass(self) -> dict:
        """★ [2026-06-06 부모] 거시 레짐 나침반 — 급락→회복 '전환' 감지 (표시 전용, 진입 0영향).
        대표10 breadth 전환으로 판정: RISK_OFF(급락=떨어지는칼) / RECOVERING(회복전환 후보) /
        RISK_ON(상승추세) / NEUTRAL. 회복은 예고가 없으니 미리 띄워두고 정확도부터 검증 →
        맞으면 Phase 2서 conviction 연결. ("BB 닿으면 반전 아니듯, 거시도 전환을 본다.")
        """
        try:
            now = time.time()
            bd = self._compute_market_breadth()
            verdict = bd.get("verdict", "NEUTRAL")
            level = bd.get("level", "WEAK")
            rdir = int(bd.get("dir", 0) or 0)
            up, down = int(bd.get("up", 0) or 0), int(bd.get("down", 0) or 0)
            if verdict == "BEAR" and level in ("STRONG", "MID"):
                state = "RISK_OFF"
                self._macro_riskoff_ts = now
            elif verdict == "BULL" and level in ("STRONG", "MID"):
                state = "RISK_ON"
            else:
                # 최근 1h내 급락 있었고 지금 하락압력 풀림(상승 우세 시작) = 회복 전환 후보
                _ro_age = now - float(getattr(self, "_macro_riskoff_ts", 0) or 0)
                if _ro_age < 3600.0 and rdir >= 0 and up > down:
                    state = "RECOVERING"
                else:
                    state = "NEUTRAL"
            _emoji = {"RISK_OFF": "🔴 급락(떨어지는칼)", "RECOVERING": "🟡 회복 전환?",
                      "RISK_ON": "🟢 상승추세", "NEUTRAL": "⚪ 중립"}.get(state, state)
            return {"state": state, "label": _emoji, "breadth": bd.get("label", ""),
                    "up": up, "down": down, "dir": rdir}
        except Exception:
            return {"state": "NEUTRAL", "label": "⚪ 중립", "breadth": "", "up": 0, "down": 0, "dir": 0}

    def _compute_regime_direction(self, market: str, candles_primary: Optional[list] = None) -> Tuple[int, float, str]:
        """[2026-06-02 레짐 컴퍼스 Step 1] 시장 레짐 방향 (진입 direction 무관).

        6TF(D1/H4/H1/30M/15M/5M) trend 를 상위 가중 종합 → regime_dir(+1 상승/0 중립/-1 하락) + strength(0~1 확신도).
        ★ paper 단계 — _dbg 로그만, conviction 점수 미반영. _compute_mtf_alignment_matrix 패턴 재활용(direction 제거 + 상위가중).
        """
        try:
            from app.strategy.greenpen.pa_detector import OHLCV as _O
            from app.strategy.greenpen.market_structure import analyze_structure as _as

            def _trend_of(raw, is_raw=True):
                try:
                    if not raw or len(raw) < 10:
                        return "?"
                    _c = []
                    if is_raw:
                        for r in raw:
                            if len(r) >= 5:
                                _c.append(_O(float(r[1]), float(r[2]), float(r[3]), float(r[4])))
                    else:
                        for c in raw:
                            if hasattr(c, 'open'):
                                _c.append(c)
                            elif isinstance(c, (list, tuple)) and len(c) >= 4:
                                _c.append(_O(float(c[0]), float(c[1]), float(c[2]), float(c[3])))
                    if len(_c) < 10:
                        return "?"
                    st = _as(_c)
                    return st.trend.value if hasattr(st.trend, 'value') else str(st.trend)
                except Exception:
                    return "?"

            _primary = str(self.config.primary_tf)

            def _trend_for(interval: str) -> str:
                if interval == _primary and candles_primary:
                    return _trend_of(candles_primary, is_raw=False)
                return _trend_of(self._get_mtf_kline(market, interval))

            # (interval, 상위 가중) — D1·H4 무겁게 (부모님 "Day 캔들" 중시 + 상위 = 판). 검토포인트: W값
            tf_weights = [("D", 3), ("240", 3), ("60", 2), ("30", 1), ("15", 1), ("5", 1)]
            s = 0
            maxw = 0
            parts = []
            for interval, w in tf_weights:
                t = _trend_for(interval)
                td = 1 if t == "UPTREND" else -1 if t == "DOWNTREND" else 0
                s += w * td
                maxw += w
                parts.append(f"{interval}:{(t or '?')[:4]}")
            regime_dir = 1 if s >= 3 else -1 if s <= -3 else 0   # 상승/중립/하락 (검토포인트: 임계 3)
            regime_strength = (abs(s) / maxw) if maxw else 0.0    # 0~1 확신도 = 선행 다이얼
            label = f"{'/'.join(parts)} sum{s:+d}/{maxw}"
            return regime_dir, regime_strength, label
        except Exception as exc:
            logger.debug("[FOCUS] _compute_regime_direction: %s", exc)
            return 0, 0.0, "err"

    def _btc_regime_dir_cached(self) -> int:
        """시장 엄지손가락 = BTC 6TF 종합 방향 (+1/0/-1). 스캔당 1회 캐시 (per-coin 재계산 방지).
        ★ btc_regime(EMA) 가 conviction 에 박는 일률 LONG/SHORT 페널티의 '방향' 판정용 — 같은 6TF 도구로 일관."""
        try:
            now = time.time()
            ttl = float(getattr(self.config, "coin_decouple_btc_cache_sec", 120.0))
            cache = getattr(self, "_btc_decouple_cache", None)
            if cache and (now - cache[0]) < ttl:
                return cache[1]
            bdir, _bstr, _blab = self._compute_regime_direction("BTCUSDT")
            self._btc_decouple_cache = (now, int(bdir))
            return int(bdir)
        except Exception as exc:
            logger.debug("[FOCUS] _btc_regime_dir_cached: %s", exc)
            return 0

    def _coin_decoupling_release(self, market: str, direction: str, coin_dir: int, coin_str: float) -> Tuple[float, str]:
        """🦵 개별 코인 디커플링 → 시장에 눌린 약자 다리 해방 (2026-06-11 부모 "양다리 자유롭게").

        문제: BTC=BULL 이면 btc_regime 이 *모든 코인*에 일률 SHORT-20 → 코인이 자기만 무너져도 SHORT 점수
              -20 구멍 + HTF lag 못 메워 임계 영영 못 넘음 = 한 다리 묶임.
        해법(부모님 "개별 디커플링만"): 시장(BTC 6TF)과 코인 자기 6TF 구조가 *명확히 반대(strength≥min)* 일 때만
              코인 구조가 가리키는 다리를 +release / 역행 다리를 -penalty. 추세 따라가는 코인(coin==btc)엔 영향 0.
        ★ 코인·BTC 둘 다 _compute_regime_direction(6TF) 사용. coin_dir/coin_str = 호출부에서 이미 계산한 값 재사용.
        Returns (delta, label)."""
        if not getattr(self.config, "coin_decouple_enabled", False):
            return 0.0, ""
        d = (direction or "").upper()
        if d not in ("LONG", "SHORT") or not coin_dir:
            return 0.0, ""
        if float(coin_str or 0.0) < float(getattr(self.config, "coin_decouple_min_strength", 0.5)):
            return 0.0, ""          # 코인 구조 약함 = 흔들림 → 미발동 (럭비공 방지)
        btc_dir = self._btc_regime_dir_cached()
        if btc_dir == 0 or btc_dir == coin_dir:
            return 0.0, ""          # 시장 중립 or 코인이 시장 따라감 = 디커플링 아님 (영향 0)
        # ── 여기 도달 = 디커플링 (coin_dir 와 btc_dir 둘 다 비0 + 반대) ──
        rel = float(getattr(self.config, "coin_decouple_short_release", 22.0))
        pen = float(getattr(self.config, "coin_decouple_long_penalty", 12.0))
        coin_side = "SHORT" if coin_dir < 0 else "LONG"   # 코인 6TF 구조가 가리키는 다리(=약자)
        _tag = "↓" if coin_dir < 0 else "↑"
        if d == coin_side:
            return rel, f"디커플{_tag}(coinVSbtc) 해방+{rel:.0f}"
        return -pen, f"디커플{_tag}(coinVSbtc) 역행-{pen:.0f}"

    def _mom_pos_up(self, raw) -> Optional[Tuple[float, float]]:
        """5m klines → (pos, up). 변곡(_compute_inflection_setup)과 *동일 수식* (verbatim).
        pos=24h(288봉) 범위 내 위치 0~1 / up=0.75·tanh(slope15m/scale)+0.25·sign(MACD히스토Δ)."""
        import math
        if not raw or len(raw) < 35:
            return None
        cl = [float(r[4]) for r in raw]
        his = [float(r[2]) for r in raw]; los = [float(r[3]) for r in raw]
        hi = max(his); lo = min(los); last = cl[-1]
        if hi <= lo or last <= 0:
            return None
        pos = (last - lo) / (hi - lo)
        slope15m = (cl[-1] - cl[-4]) / cl[-4] * 100.0 if cl[-4] != 0 else 0.0

        def _ema(vals, n):
            k = 2.0 / (n + 1); e = vals[0]; out = [e]
            for v in vals[1:]:
                e = v * k + e * (1 - k); out.append(e)
            return out
        e12 = _ema(cl, 12); e26 = _ema(cl, 26)
        ml = [a - b for a, b in zip(e12, e26)]; sig = _ema(ml, 9)
        hl = [a - b for a, b in zip(ml, sig)]
        hd = hl[-1] - hl[-2] if len(hl) >= 2 else 0.0
        sscale = float(getattr(self.config, "inflection_setup_slope_scale", 0.40)) or 0.40
        lean = 0.25 * (1 if hd > 0 else (-1 if hd < 0 else 0))
        up = max(-1.0, min(1.0, 0.75 * math.tanh(slope15m / sscale) + lean))
        return pos, up

    def _btc_momentum_cached(self) -> float:
        """BTC 5m 모멘텀 up (변곡 수식). 스캔당 캐시 — 코인 상대발산(div) 판정용."""
        try:
            now = time.time()
            ttl = float(getattr(self.config, "mom_decouple_btc_cache_sec", 60.0))
            cache = getattr(self, "_btc_mom_cache", None)
            if cache and (now - cache[0]) < ttl:
                return cache[1]
            raw = self._get_mtf_kline("BTCUSDT", "5", limit=288, ttl=30.0)
            pu = self._mom_pos_up(raw)
            up = float(pu[1]) if pu else 0.0
            self._btc_mom_cache = (now, up)
            return up
        except Exception as exc:
            logger.debug("[FOCUS] _btc_momentum_cached: %s", exc)
            return 0.0

    def _momentum_decouple_release(self, market: str, direction: str) -> Tuple[float, str]:
        """🦵🌊 모멘텀 decouple (2026-06-12 부모 "오르내리는 거 둘 다 잡기") — coin_decouple 의 *선행* 버전.

        coin_decouple(_coin_decoupling_release)은 analyze_structure(구조분류)로 디커플 판정 → 후행이라
        천장 코인(6TF 아직 UP)에 영영 미발동. 여기선 검출을 변곡 up(모멘텀 미분, 선행)으로 바꿔 그 순간을 잡음.
        부모님 직감 "점수가 55→…→75→73→71 꺾이면 그 자리서 SHORT" = up 이 천장에서 음수로 도는 그 자리.

        게이트(코인별 격리): BTC 6TF 레짐 vs 코인 모멘텀 *반대* + BTC 모멘텀 대비 발산(div) + 위치 extended.
          → 벽타기(모멘텀 살아있음)=0 / 시장 동반 눌림(div 부족)=0 → 진짜 *코인 혼자 꺾인* 자리만.
        값=변곡식 스케일(천장 강도 pos×모멘텀死 ↑). conviction 가산(dual 방향선택 반영). default OFF.
        Returns (delta, label)."""
        cfg = self.config
        if not getattr(cfg, "mom_decouple_enabled", False):
            return 0.0, ""
        d = (direction or "").upper()
        if d not in ("LONG", "SHORT"):
            return 0.0, ""
        btc_dir = self._btc_regime_dir_cached()
        if btc_dir == 0:
            return 0.0, ""          # 시장 중립 = 디커플 기준 없음
        try:
            raw = self._get_mtf_kline(market, "5", limit=288, ttl=30.0)
            pu = self._mom_pos_up(raw)
            if not pu:
                return 0.0, ""
            pos, up = pu
            btc_up = self._btc_momentum_cached()
            div = up - btc_up
            thr = float(getattr(cfg, "mom_decouple_up_thr", 0.40))
            dthr = float(getattr(cfg, "mom_decouple_div_thr", 0.20))
            pos_hi = float(getattr(cfg, "mom_decouple_pos_hi", 0.60))
            pos_lo = float(getattr(cfg, "mom_decouple_pos_lo", 0.40))
            # 약자 다리 식별 (디커플 방향 + 위치 extended)
            weak = None
            if btc_dir > 0 and up <= -thr and div <= -dthr and pos >= pos_hi:
                weak = "SHORT"      # BTC 상승 vs 코인 천장 모멘텀死 → SHORT 해방
            elif btc_dir < 0 and up >= thr and div >= dthr and pos <= pos_lo:
                weak = "LONG"       # BTC 하락 vs 코인 바닥 모멘텀生 → LONG 해방
            if weak is None:
                return 0.0, ""
            W = float(getattr(cfg, "mom_decouple_weight", 30.0))
            cap = float(getattr(cfg, "mom_decouple_cap", 35.0))
            base = float(getattr(cfg, "mom_decouple_base", 0.45))
            at_high = max(0.0, pos - 0.5) * 2.0
            at_low = max(0.0, 0.5 - pos) * 2.0
            if d == "LONG":
                val = W * (at_high * (up - base) + at_low * (base + up))
            else:
                val = W * (at_high * (base - up) + at_low * (-base - up))
            val = max(-cap, min(cap, val))
            _tag = "↓천장" if weak == "SHORT" else "↑바닥"
            _side = "해방" if d == weak else "역행"
            _label = f"momDecouple{_tag}(btc{btc_dir:+d}/up{up:+.2f}/div{div:+.2f}/pos{pos*100:.0f}%){_side}{val:+.0f}"
            # ★ 부모님 "보고 싶다" — 해방(약자다리 푸는) 쪽만 INFO 로그(conviction breakdown 은 파일 미기록이라 안 보임).
            if d == weak:
                logger.info("[FOCUS] 🦵🌊 mom_decouple FIRE: %s %s — %s (conviction %+.0f)", market, d, _label, val)
            return val, _label
        except Exception as exc:
            logger.debug("[FOCUS] _momentum_decouple_release %s: %s", market, exc)
            return 0.0, ""

    def _compute_mtf_alignment_matrix(self, market: str, direction: str, candles_primary: Optional[list] = None) -> Tuple[int, str]:
        """[2026-05-17 Phase 4 / 2026-05-21 부모] 멀티 TF 정렬 매트릭스 5 TF 통합 (±20).

        5 TF (H4/H1/M30/M15/M5) 진입 방향 정렬 카운트 (평등 가중):
          net=5(전원 일치) → +20, 4 → +16, 3 → +12, 2 → +8, 1 → +4, 0 → 0
          ... (반대 동일 음수)
        Score = net × 4. 자중 ×0.75 적용 시 -15 ~ +15.

        [변경 이력]
          2026-05-21: primary_tf=H4 전환 + 5 TF 통합 (이전 ±18 H4 보너스 ×0.5 디자인 폐기).
                     primary_tf 가 변하면 candles_primary 의 TF 도 변하므로 그에 맞춰 매트릭스 안에서 활용.
                     깊은 자리만 입학 (5 TF 모두 일치 = 명문대 합격) — 부모님 의도.
        """
        if not getattr(self.config, "phase4_mtf_matrix_enabled", True):
            return 0, "OFF"
        dir_up = (direction or "").upper()
        if dir_up not in ("LONG", "SHORT"):
            return 0, "no-dir"
        try:
            from app.strategy.greenpen.pa_detector import OHLCV as _O
            from app.strategy.greenpen.market_structure import analyze_structure as _as

            def _trend_of(raw, is_raw=True, reality_drop=0.0):
                try:
                    if not raw or len(raw) < 10:
                        return "?"
                    _c = []
                    if is_raw:
                        for r in raw:
                            if len(r) >= 5:
                                _c.append(_O(float(r[1]), float(r[2]), float(r[3]), float(r[4])))
                    else:
                        for c in raw:
                            if hasattr(c, 'open'):
                                _c.append(c)
                            elif isinstance(c, (list, tuple)) and len(c) >= 4:
                                _c.append(_O(float(c[0]), float(c[1]), float(c[2]), float(c[3])))
                    if len(_c) < 10:
                        return "?"
                    st = _as(_c, recent_reality_drop_pct=reality_drop)
                    return st.trend.value if hasattr(st.trend, 'value') else str(st.trend)
                except Exception:
                    return "?"

            # 5 TF trend — primary_tf 일치 TF 는 candles_primary 재활용 (캐시 효율), 나머지는 별도 fetch
            _primary_interval = str(self.config.primary_tf)
            # ★ [2026-06-14 부모] Fix D — D1 라벨에만 reality check (최근5일봉 폭락 시 UPTREND→SIDEWAYS 강등). default OFF.
            _rd_on = getattr(self.config, "d1_reality_demote_enabled", False)
            _rd_pct = abs(float(getattr(self.config, "d1_reality_demote_drop_pct", 1.0) or 1.0)) if _rd_on else 0.0
            def _trend_for(interval: str) -> str:
                _rd = _rd_pct if interval == "D" else 0.0
                if interval == _primary_interval and candles_primary:
                    return _trend_of(candles_primary, is_raw=False, reality_drop=_rd)
                return _trend_of(self._get_mtf_kline(market, interval), reality_drop=_rd)

            # ★ [2026-05-28 저녁 부모] D1 평가 추가 — 부모님 "단 하나 — Day 캔들 거슬리지 않으면 어떻게든 이윤"
            #   6 TF (D1/H4/H1/30M/15M/5M) 통합 — 옛 5 TF 의 D1 사각지대 보완.
            d1_trend = _trend_for("D")
            h4_trend = _trend_for("240")
            h1_trend = _trend_for("60")
            m30_trend = _trend_for("30")
            m15_trend = _trend_for("15")
            m5_trend = _trend_for("5")

            def _is_align(t):
                return ((dir_up == "LONG" and t == "UPTREND") or (dir_up == "SHORT" and t == "DOWNTREND"))

            def _is_opposite(t):
                return ((dir_up == "LONG" and t == "DOWNTREND") or (dir_up == "SHORT" and t == "UPTREND"))

            # 6 TF 매트릭스 (평등 가중) — net × 4 (범위 -24~+24)
            # ★ D1 포함 → 부모님 "Day 캔들" 정렬 자동 반영
            trends = [d1_trend, h4_trend, h1_trend, m30_trend, m15_trend, m5_trend]
            align_count = sum(1 for t in trends if _is_align(t))
            opp_count = sum(1 for t in trends if _is_opposite(t))
            net = align_count - opp_count  # 범위 -6 ~ +6
            score = net * 4  # net=6→24, 5→20, ..., -6→-24

            label = f"D1:{d1_trend[:4]}/H4:{h4_trend[:4]}/H1:{h1_trend[:4]}/30M:{m30_trend[:4]}/15M:{m15_trend[:4]}/5m:{m5_trend[:4]} align={align_count}-{opp_count}={net:+d}"
            return score, label
        except Exception as exc:
            logger.debug("[FOCUS] mtf alignment matrix error for %s: %s", market, exc)
            return 0, "ERROR"

    def _compute_tf_change_rate(self, market: str, tf_str: str, direction: str, candles_primary: Optional[list] = None) -> Tuple[int, str]:
        """[2026-05-17 Phase 4] 각 TF 변화율 (6점) — E 복합: 가격 속도 + 방향 일관성.

        tf_str: "H1" / "30" / "15" / "5"
        가격 속도 = (현재 close - N전 close) / N전 close, % 변화
        방향 일관성 = 최근 5 캔들 같은 방향 비율 (0~1)

        결합:
          진입 방향 일치 + 강한 가속  = +6
          진입 방향 일치 + 약한 변화 = +3
          진입 방향 일치 + 반대 가속  = -3 (반전 시작)
          진입 방향 반대 + 강한 가속  = -6 (위험)
          진입 방향 반대 + 약한 변화  = 0
          진입 방향 반대 + 일치 가속  = +4 (전환 시작 — 부모님 M5 급변 통찰)
        """
        if not getattr(self.config, "phase4_change_rate_enabled", True):
            return 0, "OFF"
        dir_up = (direction or "").upper()
        if dir_up not in ("LONG", "SHORT"):
            return 0, "no-dir"
        try:
            # candles 가져오기 — primary_tf 와 일치하는 tf_str 만 candles_primary 사용 ([2026-05-21] primary_tf=H4 전환 대응)
            _tf_interval = {"D1": "D", "H4": "240", "H1": "60"}.get(tf_str, tf_str)
            if _tf_interval == str(self.config.primary_tf) and candles_primary:
                closes = []
                for c in candles_primary:
                    if hasattr(c, 'close'): closes.append(float(c.close))
                    elif isinstance(c, (list, tuple)) and len(c) >= 4: closes.append(float(c[3]))
            else:
                raw = self._get_mtf_kline(market, _tf_interval)
                if not raw or len(raw) < 10:
                    return 0, f"{tf_str}:no-data"
                closes = [float(r[4]) for r in raw if len(r) >= 5]

            if len(closes) < 6:
                return 0, f"{tf_str}:short"

            # 가격 속도 — 최근 5캔들 평균 변화율 (%)
            N = 5
            speed_pct = (closes[-1] - closes[-N-1]) / closes[-N-1] * 100 if closes[-N-1] > 0 else 0
            # 방향 일관성 — 최근 5 캔들 same-direction 비율
            up_count = sum(1 for i in range(-N, 0) if closes[i] > closes[i-1])
            down_count = sum(1 for i in range(-N, 0) if closes[i] < closes[i-1])
            dominant_count = max(up_count, down_count)
            consistency = dominant_count / N
            dominant_dir = "UP" if up_count > down_count else ("DOWN" if down_count > up_count else "FLAT")

            # ★ [2026-06-14 부모 BEAT 사고] Fix A — 방향 라벨(개수) vs 실제 순변화율(speed) 괴리 교정.
            #   개수 UP인데 speed<0 (또는 개수 DOWN인데 speed>0) = 사실상 모호 → 중립(FLAT).
            #   BEAT: H1 개수UP인데 실제 -4.52% 하락 → LONG 가점 버그성 직격. 방향 대칭. default OFF.
            if getattr(self.config, "cr_speed_sign_guard_enabled", False) and dominant_dir != "FLAT":
                _speed_dir = "UP" if speed_pct > 0 else ("DOWN" if speed_pct < 0 else "FLAT")
                if _speed_dir != dominant_dir:
                    dominant_dir = "FLAT"

            # ★ [2026-06-14 부모 BEAT 사고] Fix C — 큰 추세 동의 가드.
            #   5캔들 dominant_dir 이 더 긴 창(lookback)의 net 추세와 반대면 중립(FLAT).
            #   5캔들 잔물결을 추세로 착각 차단 — 봇이 차트 전체 방향을 같이 보게. 방향 대칭. default OFF.
            if getattr(self.config, "cr_trend_agree_guard_enabled", False) and dominant_dir != "FLAT":
                _long_n = int(getattr(self.config, "cr_trend_agree_lookback", 20))
                if len(closes) > _long_n and closes[-_long_n - 1] > 0:
                    _long_chg = (closes[-1] - closes[-_long_n - 1]) / closes[-_long_n - 1] * 100
                    _long_dir = "UP" if _long_chg > 0 else ("DOWN" if _long_chg < 0 else "FLAT")
                    if _long_dir != "FLAT" and _long_dir != dominant_dir:
                        dominant_dir = "FLAT"

            # 진입 방향 일치 여부
            entry_aligned = (dir_up == "LONG" and dominant_dir == "UP") or (dir_up == "SHORT" and dominant_dir == "DOWN")
            entry_opposite = (dir_up == "LONG" and dominant_dir == "DOWN") or (dir_up == "SHORT" and dominant_dir == "UP")

            # [Phase 4.5] 강한 가속 = 일관성 ≥ 0.8 + |speed| ≥ ATR 평균 1배
            baseline = self._coin_baseline_stats(market, candles_primary)
            atr_ref = baseline['atr_avg_pct'] if baseline else 0.5
            speed_ratio = abs(speed_pct) / atr_ref if atr_ref > 0 else 1.0
            # ★ [2026-06-14 부모 BEAT 사고] Fix B — 극단 폭등/폭락(blow-off) 끝물 → 방향 중립(FLAT).
            #   speed_ratio 가 극단 임계 초과 = 지속 불가 끝물. BEAT D1 +103% 잔상 직격. 방향 대칭. default OFF.
            if getattr(self.config, "cr_blowoff_extreme_guard_enabled", False) and dominant_dir != "FLAT":
                _ext_ratio = float(getattr(self.config, "cr_blowoff_extreme_ratio", 4.0))
                if speed_ratio >= _ext_ratio:
                    dominant_dir = "FLAT"
                    entry_aligned = False
                    entry_opposite = False
            strong_accel = consistency >= 0.8 and speed_ratio >= 1.0
            weak_change = consistency < 0.6 or speed_ratio < 0.4

            if entry_aligned:
                if strong_accel: score = 6
                elif weak_change: score = 3
                else: score = 4  # 중간 (가속/일관성 중간)
            elif entry_opposite:
                if strong_accel: score = -6
                elif weak_change: score = 0
                else: score = -3
            else:  # FLAT or sideways
                score = 0

            # 전환 신호 — 반대 우세인데 *최근 1~2 캔들* 진입 방향으로 급변 (부모님 통찰)
            if entry_opposite and len(closes) >= 3:
                recent_up = closes[-1] > closes[-2] and closes[-2] > closes[-3]
                recent_down = closes[-1] < closes[-2] and closes[-2] < closes[-3]
                if (dir_up == "LONG" and recent_up) or (dir_up == "SHORT" and recent_down):
                    score = 4  # 전환 시작 보너스

            # ★ [2026-06-03 부모] TF별 가중치 — 기본 1.0(×6=최대6). UI 조절 가능
            _tf_w_key = {"D1": "d1_trend_weight", "H4": "h4_trend_weight", "H1": "h1_trend_weight",
                         "30": "m30_trend_weight", "15": "m15_trend_weight", "5": "m5_trend_weight"}.get(tf_str)
            _tf_w = float(getattr(self.config, _tf_w_key, 1.0)) if _tf_w_key else 1.0
            score = int(round(score * _tf_w))
            label = f"{tf_str}:{dominant_dir}({consistency:.0%},{speed_pct:+.2f}%){score:+d}"
            return score, label
        except Exception as exc:
            logger.debug("[FOCUS] tf change rate error %s %s: %s", market, tf_str, exc)
            return 0, "ERROR"

    def _compute_sr_position_v2(self, market: str, direction: str, candles_primary: Optional[list] = None, zones_tuple: Optional[Tuple[float, float]] = None) -> Tuple[int, str]:
        """[2026-05-17 Phase 4] S/R 가격 위치 (0~8점, 페널티 없음).

        LONG: support + 2% 이내 = +8, 5% 이내 = +5, 중간 = +3, R 근처 = 0
        SHORT: resistance - 2% 이내 = +8, 5% 이내 = +5, 중간 = +3, S 근처 = 0
        부모님 룰 "코인 실패 배제 금지" 정신 — 페널티 없음 (기존 _compute_zone_position_score 와 차이).
        """
        if not getattr(self.config, "phase4_sr_position_enabled", True):
            return 0, "OFF"
        dir_up = (direction or "").upper()
        if dir_up not in ("LONG", "SHORT"):
            return 0, "no-dir"
        try:
            if not candles_primary or len(candles_primary) == 0:
                return 0, "no-candles"
            _last = candles_primary[-1]
            if hasattr(_last, 'close'): current_price = float(_last.close)
            elif isinstance(_last, (list, tuple)) and len(_last) >= 4: current_price = float(_last[3])
            else: return 0, "no-price"

            if zones_tuple is None:
                zones_tuple = self._zones_for_pa()
            if not zones_tuple:
                return 0, "no-zones"
            support_price, resistance_price = zones_tuple
            if support_price <= 0 or resistance_price <= 0 or current_price <= 0:
                return 0, "invalid"

            # % 거리 (가격 대비)
            dist_to_support_pct = abs(current_price - support_price) / current_price * 100
            dist_to_resistance_pct = abs(resistance_price - current_price) / current_price * 100

            if dir_up == "LONG":
                if dist_to_support_pct <= 2.0: return 8, f"near_S({dist_to_support_pct:.1f}%)+8"
                if dist_to_support_pct <= 5.0: return 5, f"mid_S({dist_to_support_pct:.1f}%)+5"
                if dist_to_resistance_pct <= 5.0: return 0, f"near_R({dist_to_resistance_pct:.1f}%)+0"
                return 3, f"between(S:{dist_to_support_pct:.1f}/R:{dist_to_resistance_pct:.1f}%)+3"
            else:  # SHORT
                if dist_to_resistance_pct <= 2.0: return 8, f"near_R({dist_to_resistance_pct:.1f}%)+8"
                if dist_to_resistance_pct <= 5.0: return 5, f"mid_R({dist_to_resistance_pct:.1f}%)+5"
                if dist_to_support_pct <= 5.0: return 0, f"near_S({dist_to_support_pct:.1f}%)+0"
                return 3, f"between(S:{dist_to_support_pct:.1f}/R:{dist_to_resistance_pct:.1f}%)+3"
        except Exception as exc:
            logger.debug("[FOCUS] sr position v2 error for %s: %s", market, exc)
            return 0, "ERROR"

    def _compute_volume_pattern_score(self, market: str, direction: str) -> Tuple[int, str]:
        """[2026-05-17 Phase 4] Volume 패턴 (0~5점).

        최근 5m 캔들 volume 평균 대비 현재 봉:
          큰 봉 (≥2× avg) + 진입 방향 일치 (현재 봉 진입 방향)  = +5 (capitulation/breakout)
          큰 봉 + 진입 방향 반대 = 0 (자리 X)
          평균 봉 (0.7~2× avg) = +2
          작은 봉 (<0.7× avg) = +1
        """
        if not getattr(self.config, "phase4_volume_pattern_enabled", True):
            return 0, "OFF"
        dir_up = (direction or "").upper()
        if dir_up not in ("LONG", "SHORT"):
            return 0, "no-dir"
        try:
            raw = self._get_mtf_kline(market, "5")
            if not raw or len(raw) < 10:
                return 0, "no-vol-data"
            vols = []
            opens_closes = []
            for r in raw:
                if len(r) >= 6:
                    vols.append(float(r[5]))
                    opens_closes.append((float(r[1]), float(r[4])))
            if len(vols) < 6:
                return 0, "short-vol"

            # [Phase 4.5 fix] 마감된 직전 봉 평가 (마지막은 실시간 진행 중 — volume 부정확)
            if len(vols) < 7:
                return 0, "short-vol"
            avg_vol = sum(vols[-7:-2]) / 5  # 마감된 5봉 평균
            current_vol = vols[-2]           # 마감된 직전 봉
            if avg_vol <= 0:
                return 0, "zero-avg"
            ratio = current_vol / avg_vol

            # 마감 봉 방향 (open vs close)
            cur_open, cur_close = opens_closes[-2]
            candle_dir = "UP" if cur_close > cur_open else ("DOWN" if cur_close < cur_open else "FLAT")
            entry_aligned = (dir_up == "LONG" and candle_dir == "UP") or (dir_up == "SHORT" and candle_dir == "DOWN")

            if ratio >= 2.0:
                if entry_aligned: return 5, f"big({ratio:.1f}x){candle_dir}+5"
                else: return 0, f"big({ratio:.1f}x){candle_dir}+0"
            if ratio >= 0.7:
                return 2, f"avg({ratio:.1f}x)+2"
            return 1, f"small({ratio:.1f}x)+1"
        except Exception as exc:
            logger.debug("[FOCUS] volume pattern error for %s: %s", market, exc)
            return 0, "ERROR"

    def _compute_rsi_score(self, market: str, direction: str, candles_primary: Optional[list] = None) -> Tuple[int, str]:
        """[2026-05-17 Phase 4] RSI 점수 (0~4점).

        LONG: RSI 30~50 (회복 자리) = +4 / 50~70 = +2 / <30 = +2 / ≥70 = 0
        SHORT: RSI 50~70 = +4 / 30~50 = +2 / ≥70 = +2 / <30 = 0
        """
        if not getattr(self.config, "phase4_rsi_enabled", True):
            return 0, "OFF"
        dir_up = (direction or "").upper()
        if dir_up not in ("LONG", "SHORT"):
            return 0, "no-dir"
        try:
            from app.strategy.indicators import rsi as _rsi_fn
            if not candles_primary or len(candles_primary) < 15:
                return 0, "no-candles"
            closes = []
            for c in candles_primary:
                if hasattr(c, 'close'): closes.append(float(c.close))
                elif isinstance(c, (list, tuple)) and len(c) >= 4: closes.append(float(c[3]))
            if len(closes) < 15:
                return 0, "short"
            rsi_val = _rsi_fn(closes, length=14)
            if rsi_val is None:
                return 0, "no-rsi"

            if dir_up == "LONG":
                if 30 <= rsi_val < 50: score = 4
                elif 50 <= rsi_val < 70: score = 2
                elif rsi_val < 30: score = 2
                else: score = 0  # ≥70 과매수
            else:  # SHORT
                if 50 <= rsi_val < 70: score = 4
                elif 30 <= rsi_val < 50: score = 2
                elif rsi_val >= 70: score = 2
                else: score = 0  # <30 과매도
            return score, f"RSI={rsi_val:.1f}+{score}"
        except Exception as exc:
            logger.debug("[FOCUS] rsi score error for %s: %s", market, exc)
            return 0, "ERROR"

    # ─────────────────────────────────────────────────────────────────
    # ★★★ [Phase 5] PA 5 STEP 완성도 헬퍼 (2026-05-17 부모님 비전)
    # PDF 출처: XAUUSD 88 (ครูลูกแก้ว 녹색 펜 시스템) EP.6 "M5 백만 브레이크"
    # 부모님: "PA = 추세 본체. 다른 추세 지표 (MTF/변화율/ADX) = 간접 검증"
    # PA 통합 22점 = PA Pattern (0~10) + 5 STEP (0~12)
    # ─────────────────────────────────────────────────────────────────

    def _compute_pa_5step_score(self, market: str, direction: str,
                                 zones: Optional[Tuple[float, float]] = None) -> Tuple[int, str]:
        """[Phase 5] PA 5 STEP 완성도 점수 (0~12).

        plan: docs/plan_conviction_phase5_pa_5step_2026-05-17.md
        ★ PDF 의도 = "M5 백만 브레이크" = 진입봉 (config.entry_tf) 패턴.
           candles 는 wrapper 가 entry_tf 자동 fetch — primary_tf(H1) 사용 X.
        검증:
          STEP 1 큰 캔들 + 강한 볼륨 (Body 1.5×, Vol 1.5×)        +2
          STEP 2 다음 작은 캔들 (Body 0.6×, Vol 감소)              +2
          STEP 3 ZONE REJECT (zone 0.5×ATR + wick > body)         +2
          STEP 4 색 반대 변경 (직전 ≠ 진입색)                       +2
          STEP 5 RETEST (break 후 zone 재거부)                     +2
          OVL 보너스 — 2차 break 자리 (1차 함정, 2차 진짜)         +2
        Returns: (score 0~12, label "S1+/S2+/.../OVL+ → 10")
        """
        try:
            from app.strategy.greenpen.pa_5step import _pa_5step_score_impl
            entry_tf = getattr(self.config, "entry_tf", "5")
            raw = self._get_mtf_kline(market, entry_tf, limit=30)
            if not raw or len(raw) < 8:
                return (0, f"entry_tf({entry_tf})_short:{len(raw) if raw else 0}")
            # bybit V5 kline raw: [ts, o, h, l, c, v, turnover] → impl 용 dict 변환
            candles = []
            for k in raw:
                if isinstance(k, (list, tuple)) and len(k) >= 6:
                    candles.append({
                        'o': float(k[1]), 'h': float(k[2]), 'l': float(k[3]),
                        'c': float(k[4]), 'v': float(k[5]),
                    })
            if len(candles) < 8:
                return (0, f"entry_tf({entry_tf})_parse:{len(candles)}")
            return _pa_5step_score_impl(direction, candles, zones)
        except Exception as exc:
            logger.debug("[FOCUS] 5step calc error for %s: %s", market, exc)
            return (0, "ERROR")

    def _compute_phase3_context_bonus(self, market: str, ts: Optional[float] = None) -> int:
        """[2026-05-17 Phase 4 자중] 시간대 + 코인 가산점.

        Phase 3 ±10/+5 → Phase 4 자중 ±4/+2 (전체 14점 환경 그룹 내 비중)
          KST 시간대 양수 EV (21,22,4,12,19,1,5,6,3,18h) → +4
          KST 시간대 음수 EV (16,20,2,13,15h)            → -4
          양수 EV 코인 (ZBT,HYPE,INJ,TAO,BTC,ZEC)        → +2
        """
        import time as _time
        from datetime import datetime as _dt, timezone as _tz, timedelta as _td

        if ts is None:
            ts = _time.time()

        hr = _dt.fromtimestamp(ts, tz=_tz(_td(hours=9))).hour

        bonus = 0
        if hr in {21, 22, 4, 12, 19, 1, 5, 6, 3, 18}:
            bonus += 4
        elif hr in {16, 20, 2, 13, 15}:
            bonus -= 4

        if market in {"ZBTUSDT", "HYPEUSDT", "INJUSDT", "TAOUSDT", "BTCUSDT", "ZECUSDT"}:
            bonus += 2

        return bonus

    def _compute_conviction_score(self, market: str, candles_primary: list, direction: str = "", zones: Optional[Tuple[float, float]] = None) -> float:
        """확신 점수 계산 (0~100 float) — Phase 5 PA 통째 재설계 + 5 STEP.

        부모님 비전 (2026-05-17): "PA = 추세 본체. 다른 추세 지표는 간접 검증."
        plan: docs/plan_conviction_phase5_pa_5step_2026-05-17.md

        ★ Phase 5 변화 — 추세 그룹 50→40, PA 통합 12→22:
          - 멀티 TF      : ±16 → ±12 (×0.75)
          - 변화율 4 TF  : ±24 → ±18 (각 ×0.75)
          - PA Pattern   : 0~12 → 0~10 (×1.67 from 0~6)
          - 5 STEP 신규  : 0~12 (PDF EP.6 M5 백만 브레이크)

        | # | 그룹     | 항목                          | 점수      |
        |---|----------|-------------------------------|-----------|
        | 1 | 추세 40  | 멀티 TF 정렬 매트릭스          | ±12 ★     |
        | 2 |          | H1 변화율                      | ±4.5 ★    |
        | 3 |          | M30 변화율                     | ±4.5 ★    |
        | 4 |          | M15 변화율                     | ±4.5 ★    |
        | 5 |          | M5 변화율                      | ±4.5 ★    |
        | 6 |          | ADX 강도 (자중)                | 0~10      |
        | 7 | 모멘텀16 | MACD hist (자중)               | 0~8       |
        | 8 |          | RSI                            | 0~4       |
        | 9 |          | BB 밴드폭% (자중)              | 0~4       |
        | 10| 자리 30  | PA Pattern (자중 ×1.67)        | 0~10 ★    |
        | 10.5|        | 5 STEP 완성도 (신규)           | 0~12 ★    |
        | 11|          | S/R 가격 위치 v2 (페널티 X)    | 0~8       |
        | 12| 환경 14  | Volume 패턴                    | 0~5       |
        | 13|          | News Sentiment (자중)          | ±3        |
        | 14|          | 시간대 (Play C 자중)           | ±4        |
        | 15|          | 코인 보너스 (Play C 자중)      | +2        |
        | 16| 별도     | Reentry Penalty                | hard      |
        | 17|          | Context Engine block/델타      | hard      |
        | 18|          | Momentum Reversal (자중)       | hard -10  |

        H4 = FOCUS 점수 X (참조만 — 로그 출력만, 다른 전략 AUTOLOOP/PINGPONG/GAZUA 는 그대로).
        멀티 TF 인프라: _get_mtf_kline + market_structure.analyze_structure.
        """
        # piecewise linear 보간 헬퍼
        def _pwl(v, points):
            if v <= points[0][0]: return float(points[0][1])
            if v >= points[-1][0]: return float(points[-1][1])
            for i in range(len(points) - 1):
                x0, y0 = points[i]
                x1, y1 = points[i + 1]
                if x0 <= v <= x1:
                    r = (v - x0) / (x1 - x0) if x1 != x0 else 0
                    return float(y0 + (y1 - y0) * r)
            return float(points[-1][1])

        score = 0.0
        _dbg = {}
        # ★ [Phase 4.5] 코인 평소 변동성 baseline (H4 100 캔들, 1시간 캐싱)
        baseline = self._coin_baseline_stats(market, candles_primary)
        try:
            # 6) ADX 강도 (0~10) — Phase 4.6 코인별 정규화 (H1 100캔들 평균 기반)
            adx_data = self._fetch_primary_adx(market)
            if adx_data:
                adx_val = adx_data["adx"]
                try:  # ★ [패치 v1] post-guards ceiling 의 벽타기 면제 판정용 ADX 캐시
                    if not hasattr(self, "_conv_adx_cache"):
                        self._conv_adx_cache = {}
                    self._conv_adx_cache[(market or "").upper()] = float(adx_val)
                except Exception:
                    pass
                if baseline and baseline.get('adx_avg', 0) > 0:
                    ratio = adx_val / baseline['adx_avg']
                    # ratio < 0.5 = 0 (평소보다 약함), 1.0 = 평소, 2.0 = 만점
                    adx_s = _pwl(ratio, [(0, 0), (0.5, 0), (0.8, 2), (1.0, 4), (1.5, 8), (2.0, 10)])
                    _dbg["adx"] = f"{adx_val:.1f}/{baseline['adx_avg']:.1f}=r{ratio:.2f}→{adx_s:.1f}"
                else:
                    adx_s = _pwl(adx_val, [(0, 0), (15, 1), (25, 4), (40, 8), (55, 9.5), (100, 10)])
                    _dbg["adx"] = f"{adx_val:.1f}(abs)→{adx_s:.1f}"
                score += adx_s

            # 9) BB 밴드폭% (0~4) — Phase 4.5 코인별 정규화 (ratio = 현재/평소)
            from app.strategy.indicators import bollinger_bands
            closes = [float(getattr(c, 'close', c)) for c in candles_primary] if candles_primary else []
            if len(closes) >= 20:
                bb = bollinger_bands(closes, 20, 2.0)
                if bb and bb.get("bandwidth"):
                    bw_pct = bb["bandwidth"] * 100
                    if baseline and baseline['bb_avg'] > 0:
                        ratio = bw_pct / baseline['bb_avg']
                        # [Phase 4.5 fix] ratio < 0.5 = 0점 (평소보다 약함 = 진입 자리 X)
                        bb_s = _pwl(ratio, [(0, 0), (0.5, 0), (0.8, 1.5), (1.0, 2.5), (1.5, 3.5), (2.0, 4)])
                        _dbg["bb"] = f"{bw_pct:.1f}%/{baseline['bb_avg']:.1f}%=r{ratio:.2f}→{bb_s:.1f}"
                    else:
                        bb_s = _pwl(bw_pct, [(0, 0), (2, 1), (4, 3), (6, 3.5), (10, 4)])
                        _dbg["bb"] = f"{bw_pct:.1f}%(abs)→{bb_s:.1f}"
                    score += bb_s

            # 7) MACD hist% (0~8) — Phase 4.5 코인별 정규화
            # [2026-05-19 Phase 6 fix] 방향 일치 검증 — abs() 로 부호 소멸 8개월 버그 fix
            #   기존 버그: LONG 진입 시 hist<0 (하락 모멘텀)이어도 abs() 로 +점수 받음
            #   변경: hist 부호 == 진입 방향일 때만 가산. 불일치 = 0 (페널티 X, 보너스만 제거)
            from app.strategy.indicators import macd_hist_pair
            if len(closes) >= 35:
                hist_now, _ = macd_hist_pair(closes)
                _dir_up = (direction or "").upper()
                _macd_aligned = (
                    (_dir_up == "LONG" and hist_now > 0)
                    or (_dir_up == "SHORT" and hist_now < 0)
                    or _dir_up not in ("LONG", "SHORT")  # direction 없을 때 = 호환 모드
                )
                if closes[-1] > 0 and _macd_aligned:
                    hist_pct = abs(hist_now) / closes[-1] * 100
                    if baseline and baseline['macd_avg'] > 0:
                        ratio = hist_pct / baseline['macd_avg']
                        # [Phase 4.5 fix] ratio < 0.5 = 0점 (평소보다 약함)
                        macd_s = _pwl(ratio, [(0, 0), (0.5, 0), (0.8, 3), (1.0, 5), (2.0, 7), (3.0, 8)])
                        _dbg["macd"] = f"{hist_pct:.3f}%/{baseline['macd_avg']:.3f}%=r{ratio:.2f}→{macd_s:.1f}"
                    else:
                        macd_s = _pwl(hist_pct, [(0, 0), (0.05, 2), (0.2, 6), (0.4, 7), (1.0, 8)])
                        _dbg["macd"] = f"{hist_pct:.3f}%(abs)→{macd_s:.1f}"
                    score += macd_s
                elif closes[-1] > 0:
                    # 방향 불일치 — 가산점 없음 (기존 abs() 버그 제거)
                    _dbg["macd"] = f"{hist_now:+.4f}({_dir_up}↔)+0"

            # H4 추세 = H1과 같은 급으로 점수화 (★2026-06-03 부모님 — 참조→실전 반영)
            # H4가 판을 정한다: H4 하락이면 LONG 감점/SHORT 가점, 상승이면 반대. H1 cr_H1과 동급.
            if candles_primary and len(candles_primary) >= 10:
                from app.strategy.greenpen.pa_detector import OHLCV as _O
                from app.strategy.greenpen.market_structure import analyze_structure as _as
                _candles = []
                for c in candles_primary:
                    if hasattr(c, 'open'): _candles.append(c)
                    elif isinstance(c, (list, tuple)) and len(c) >= 4:
                        _candles.append(_O(float(c[0]), float(c[1]), float(c[2]), float(c[3])))
                if len(_candles) >= 10:
                    struct = _as(_candles)
                    trend_val = struct.trend.value if hasattr(struct.trend, 'value') else str(struct.trend)
                    conf = struct.confidence if hasattr(struct, 'confidence') else 0
                    _dbg["h4_ref"] = f"{trend_val}({conf:.2f})"
                    # ★ [2026-06-03 부모] H4 추세 점수화 — H1 cr_H1과 동급 (참조→실전)
                    if direction:
                        _h4_dir = 1 if trend_val == "UPTREND" else -1 if trend_val == "DOWNTREND" else 0
                        _h4_sign = 1 if direction.upper() == "LONG" else -1
                        _h4_s = _h4_dir * _h4_sign * float(conf) * float(getattr(self.config, "h4_trend_weight", 6.0))
                        score += _h4_s
                        _dbg["h4_score"] = f"{trend_val}×conf{conf:.2f}×dir={_h4_s:+.1f}"
                    # ★ [2026-06-02 레짐 컴퍼스 Phase 3 — 실전] M/W/H&S 반전 → conviction 반영 (부모 "실전!" 지시).
                    #   struct(H4) 재활용. 순행(반전방향=진입) +reversal_score / 역행 −. 형성중 ×0.5 / 확정(BOS돌파) ×1.0.
                    try:
                        from app.strategy.greenpen.market_structure import detect_reversal as _drev
                        _rev = _drev(struct)
                        if _rev.pattern != "NONE" and direction:
                            # ★ [2026-06-02 부모 "실전!"] 반전 방향 vs 진입 방향 → conviction 반영
                            _rev_sign = 1 if _rev.direction == "BULLISH" else -1   # BULLISH=LONG우호
                            _dir_s = 1 if direction.upper() == "LONG" else -1
                            _rev_base = float(getattr(self.config, "reversal_score", 10.0))
                            if not _rev.confirmed:
                                _rev_base *= 0.5   # 형성중 = 절반 (BOS 넥라인 돌파 시 full)
                            _rev_macro = _rev_base if (_rev_sign == _dir_s) else -_rev_base
                            score += _rev_macro
                            _dbg["reversal"] = f"{_rev.pattern}/{_rev.direction}{'✓' if _rev.confirmed else '~'}={_rev_macro:+.0f}"
                    except Exception as _rev_exc:
                        logger.debug("[FOCUS] detect_reversal error %s: %s", market, _rev_exc)
        except Exception as exc:
            logger.warning("[FOCUS] conviction base calc error for %s: %s", market, exc)

        # 10) PA Pattern (0~10) — PA 통합 22 중 절반
        # 부모님 5/19 결정: "UI 값 = 실제 효과" — 옛 ×1.67 트릭 제거.
        # pa_weight_* default 가 직접 100점 영역 값 (PIN=2, ENG=3, STAR=5 등).
        # [Phase 4.5 fix] 패턴 인식했는데 far 페널티로 0점 = 최소 2점 보장
        try:
            _pa_score, _pa_label = self._compute_pa_weight(candles_primary, direction, zones)
            _pa_v2 = min(10.0, float(_pa_score)) if _pa_score > 0 else 0.0
            if _pa_v2 == 0.0 and any(p in _pa_label for p in ("PIN_BAR", "ENGULFING", "BOS_BULLISH", "BOS_BEARISH")):
                _pa_v2 = 2.0  # 패턴 인식 = 최소 가치 인정
            score += _pa_v2
            _dbg["pa"] = f"{_pa_label}+{_pa_v2:.1f}"
        except Exception as exc:
            logger.debug("[FOCUS] pa weight error: %s", exc)

        # 10.5) ★ [Phase 5 신규] PA 5 STEP 완성도 (0~12) — PA 통합 22점의 나머지
        # 부모님 비전 (2026-05-17): "PA 패턴 연구 = 추세 본체"
        # PDF: ครูลูกแก้ว 녹색 펜 EP.6 M5 백만 브레이크
        # ★ entry_tf (M5) 자동 fetch — primary_tf(H1) candles 안 씀
        if direction:
            try:
                _5s_score, _5s_label = self._compute_pa_5step_score(market, direction, zones)
                if _5s_score > 0:
                    score += float(_5s_score)
                    _dbg["5step"] = _5s_label
            except Exception as exc:
                logger.debug("[FOCUS] 5step error: %s", exc)

        # 1) 멀티 TF 정렬 매트릭스 (±12, Phase 5 자중 ×0.75 from ±16)
        if direction:
            try:
                mtf_s, mtf_label = self._compute_mtf_alignment_matrix(market, direction, candles_primary)
                mtf_v5 = mtf_s * 0.75
                score += mtf_v5
                _dbg["mtf_align"] = f"{mtf_label}{mtf_s:+d}×.75={mtf_v5:+.1f}"
            except Exception as exc:
                logger.debug("[FOCUS] mtf alignment error: %s", exc)

        # ★ [2026-06-02 레짐 컴퍼스 Step 1] 레짐 방향 — paper (로그만, score 미반영). 부모님 검증용.
        #   진입 direction 무관 시장 레짐. 며칠 로그 보고 "레짐이 시장과 맞나" 검증 후 Step 2(선행 다이얼).
        _rdir, _rstr = 0, 0.0
        try:
            _rdir, _rstr, _rlabel = self._compute_regime_direction(market, candles_primary)
            _dbg["regime"] = f"dir={_rdir:+d}/str={_rstr:.2f}/{_rlabel}"
        except Exception as exc:
            logger.debug("[FOCUS] regime direction error: %s", exc)

        # ── 🦵 [2026-06-11 부모 "양다리 자유롭게"] 개별 코인 디커플링 SHORT 해방 ──
        #   BTC(시장)와 코인 자기 6TF 구조가 명확히 반대일 때만 약자 다리 해방 (btc_regime 일률 -20 구멍 메움).
        #   추세 따라가는 코인엔 영향 0. coin_dir/str = 위 _compute_regime_direction 재사용 (재계산 X). default OFF.
        if direction:
            try:
                _dc_d, _dc_l = self._coin_decoupling_release(market, direction, _rdir, _rstr)
                if _dc_d != 0.0:
                    score += _dc_d
                    _dbg["decouple"] = _dc_l
            except Exception as exc:
                logger.debug("[FOCUS] coin_decouple error: %s", exc)

        # ── 🦵🌊 [2026-06-12 부모] 모멘텀 decouple — coin_decouple(구조=후행)의 *선행* 버전 ──
        #   천장에서 코인 혼자 모멘텀死(부모 "75→73→71 꺾이면 SHORT") → 약자다리 conviction 해방 = dual 이 SHORT 고름.
        #   벽타기/시장동반 눌림엔 0(코인별 격리). default OFF. whip 방어=트리거(final_5m/1m).
        if direction:
            try:
                _md_d, _md_l = self._momentum_decouple_release(market, direction)
                if _md_d != 0.0:
                    score += _md_d
                    _dbg["mom_decouple"] = _md_l
            except Exception as exc:
                logger.debug("[FOCUS] mom_decouple error: %s", exc)

        # ★★ [2026-06-02 거시 레짐 = 방향 게이트] Market Breadth (대표10 쓰나미). 부모님 정수.
        #   ※ '정지/회피' 아님 → *방향*을 읽는 것. 일제 하락 = SHORT 기회(순행 가점) / LONG 떨어지는칼(역행 차단).
        #   부모님 "적극 역발상": 순행 가점 적극(+12/+6) / 역행 강한 차단(−25/−7). 비대칭(차단>기회, 남발 방지).
        #   봇이 방향 읽으면 위험이 아닌 기회 → 정지·텔레그램·자동끄고켜기 *불필요*. B12 자기참조 회피(봇 무관 시장 가격).
        #   [2단계 구현됨 2026-06-11] 거시 하락 + 5m 반등꺾임 = 능동 SHORT 진입 → 아래 _macro_short_timing (breadth 직후).
        if direction:
            try:
                _bd = self._compute_market_breadth()
                _bdir = _bd.get("dir", 0)
                _dir_sign = 1 if direction.upper() == "LONG" else -1
                _macro = 0
                if _bdir != 0:
                    if _bdir == _dir_sign:   # 순행 (흐름 따름 = 기회) — 적극 가점 (UI 조절)
                        _macro = {"STRONG": float(getattr(self.config, "breadth_aligned_strong", 20.0)),
                                  "MID": float(getattr(self.config, "breadth_aligned_mid", 8.0))}.get(_bd.get("level"), 0)
                    else:                    # 역행 (흐름 거스름 = 떨어지는 칼) — 강한 차단 (UI 조절)
                        _macro = {"STRONG": float(getattr(self.config, "breadth_counter_strong", -25.0)),
                                  "MID": float(getattr(self.config, "breadth_counter_mid", -7.0))}.get(_bd.get("level"), 0)
                score += _macro
                _dbg["breadth"] = f"{_bd.get('label','')} vs {direction[:1]}={_macro:+d}"
                # ★ [2026-06-08 부모 ⑤] STRONG 역행 = 떨어지는칼 확실 → conviction cap
                #   개별 강세가 -25 감점 압도해도 점수를 cap 아래로 눌러 = 계속 시도·풀릴때 stale진입 차단.
                if (_macro < 0 and _bd.get("level") == "STRONG"
                        and getattr(self.config, "regime_counter_strong_cap_enabled", True)):
                    _cap = float(getattr(self.config, "regime_counter_strong_cap", 50.0))
                    if score > _cap:
                        _dbg["breadth_cap"] = f"STRONG역행 conv {score:.0f}→{_cap:.0f} cap(떨어지는칼)"
                        score = _cap
            except Exception as exc:
                logger.debug("[FOCUS] breadth macro error: %s", exc)

        # ── 🌊 [2026-06-11 부모 2단계] 거시하락 능동 SHORT 진입 타이밍 — 위 8087 [2단계] 구현 ──
        #   1단계(breadth)는 SHORT 순행 가점만 = 반응형. 여기선 거시 RISK_OFF + 5m '반등 후 꺾임'을
        #   능동 신호로 SHORT 가점 → guard_score 게이트 통과 = 능동 진입. SHORT 전용·default OFF·끝물방지.
        if direction and direction.upper() == "SHORT":
            try:
                _mst_d, _mst_l = self._macro_short_timing(market)
                if _mst_d:
                    score += _mst_d
                    _dbg["macro_short"] = _mst_l
            except Exception as exc:
                logger.debug("[FOCUS] macro_short_timing error: %s", exc)

        # ── 🧭 [2026-06-06 부모 P2] 레짐 컴퍼스 RECOVERING 가점 (눌림목의 거시 신호) ──
        #   위 breadth(순행/역행)는 RISK_OFF/RISK_ON 처리. 여기선 *회복 전환(RECOVERING)* 만 신설.
        #   SOL 고점선제=RISK_OFF(위에서 역행 -25 차단) / TON 눌림목=RECOVERING(여기서 가점) = 부모님 통찰 코드화.
        #   가짜회복(죽은고양이) 방어: +DI>-DI flip + ADX≥임계 동반일 때만 LONG 가점. 기본 OFF·delta 0(paper).
        if direction and getattr(self.config, "macro_compass_enabled", False):
            try:
                _mc = self._macro_compass()
                if _mc.get("state") == "RECOVERING":
                    _rdelta = float(getattr(self.config, "macro_recovering_conv_delta", 0.0))
                    if direction.upper() == "LONG":
                        _confirm = True
                        if getattr(self.config, "macro_recovering_require_di_adx", True):
                            _pdi = float(getattr(self, "_last_plus_di", 0.0) or 0.0)
                            _mdi = float(getattr(self, "_last_minus_di", 0.0) or 0.0)
                            _adx = float(getattr(self, "_last_adx_value", 0.0) or 0.0)
                            _min_adx = float(getattr(self.config, "macro_recovering_min_adx", 20.0))
                            _confirm = (_pdi > _mdi) and (_adx >= _min_adx)
                        if _confirm:
                            score += _rdelta
                            _dbg["compass_rec"] = f"RECOVERING L{_rdelta:+.0f}{' paper' if _rdelta == 0 else ''}"
                        else:
                            _dbg["compass_rec"] = "RECOVERING L 무확인(죽은고양이?) +0"
                    else:
                        score += -_rdelta
                        _dbg["compass_rec"] = f"RECOVERING S{-_rdelta:+.0f}{' paper' if _rdelta == 0 else ''}"
            except Exception as exc:
                logger.debug("[FOCUS] compass recovering error: %s", exc)

        # 2~5) 각 TF 변화율 (±18, 4×4.5 — Phase 5 자중 ×0.75 from ±24)
        if direction:
            for tf in ("D1", "H4", "H1", "30", "15", "5"):
                try:
                    cr_s, cr_label = self._compute_tf_change_rate(market, tf, direction, candles_primary)
                    cr_v5 = cr_s * 0.75
                    score += cr_v5
                    _dbg[f"cr_{tf}"] = f"{cr_label}×.75={cr_v5:+.1f}"
                except Exception as exc:
                    logger.debug("[FOCUS] change rate %s error: %s", tf, exc)

        # 8) RSI (0~4)
        if direction:
            try:
                rsi_s, rsi_label = self._compute_rsi_score(market, direction, candles_primary)
                score += rsi_s
                _dbg["rsi"] = rsi_label
            except Exception as exc:
                logger.debug("[FOCUS] rsi error: %s", exc)

        # 11) S/R 가격 위치 v2 (0~8, 페널티 X)
        if direction:
            try:
                sr_s, sr_label = self._compute_sr_position_v2(market, direction, candles_primary, zones)
                score += sr_s
                _dbg["sr"] = sr_label
            except Exception as exc:
                logger.debug("[FOCUS] sr v2 error: %s", exc)

        # 11.5) ★ [2026-05-17 부모 비전 #3] CFID 변곡점 임박 가산점
        # PA Pattern (사후 인식) → CFID (예측). 부모님 "급변동 직전 감지" 비전 통합.
        # BULL/BEAR_IMMINENT 일치 = +15 (예측 적중 보너스), 반대 = -10 (변곡점 반대 방향 위험)
        if direction:
            try:
                cfid_dir, cfid_strength = self._detect_coin_flip_imminent_impl(market)
                if cfid_dir != "NONE":
                    aligned = ((direction == "LONG" and cfid_dir == "BULL_IMMINENT") or
                               (direction == "SHORT" and cfid_dir == "BEAR_IMMINENT"))
                    if aligned:
                        cfid_s = 15
                        score += cfid_s
                        _dbg["cfid"] = f"{cfid_dir}(s={cfid_strength:.0f})+{cfid_s}"
                    else:
                        cfid_s = -10
                        score += cfid_s
                        _dbg["cfid"] = f"{cfid_dir}(s={cfid_strength:.0f}){cfid_s}"
            except Exception as exc:
                logger.debug("[FOCUS] cfid integrate error: %s", exc)

        # 12) Volume 패턴 (0~5)
        if direction:
            try:
                vol_s, vol_label = self._compute_volume_pattern_score(market, direction)
                score += vol_s
                _dbg["vol"] = vol_label
            except Exception as exc:
                logger.debug("[FOCUS] vol pattern error: %s", exc)

        # 13) News Sentiment (±3, 자중 from ±20)
        try:
            from app.core.news_sentiment import get_news_sentiment
            _ns = get_news_sentiment()
            if _ns.config.get("focus_enabled"):
                _ns_r = _ns.get_sentiment(coin=market.replace("USDT", ""))
                if _ns_r and _ns_r.source != "fallback":
                    _news_raw = _ns_r.conviction_bonus  # ±20 scale
                    _news_v2 = max(-3, min(3, _news_raw // 7))
                    _dir_up = direction.upper() if direction else ""
                    if _dir_up == "LONG": score += _news_v2
                    elif _dir_up == "SHORT": score -= _news_v2
                    else: score += _news_v2
                    _dbg["news"] = f"{_news_raw}→{_news_v2:+d}"
        except Exception as exc:
            logger.debug("[FOCUS] news error: %s", exc)

        # 별도 17) Context Engine — block 또는 ±델타 (기존 hard rule 유지)
        try:
            ctx_delta, ctx_block, ctx_summary = self._apply_context_engine(market=market, direction=direction)
            if ctx_block:
                logger.info("[FOCUS] CONTEXT BLOCK %s %s: %s", market, direction, ctx_summary)
                return 0.0  # hard block
            if ctx_delta != 0:
                score += ctx_delta
                _dbg["ctx"] = f"{ctx_summary}{ctx_delta:+d}"
        except Exception as exc:
            logger.warning("[FOCUS] context_engine error: %s", exc, exc_info=True)

        # 별도 16) Reentry Penalty (hard 기존 유지)
        if direction and getattr(self.config, "coin_reentry_penalty_enabled", True):
            try:
                reentry_pen = self._compute_reentry_penalty(market, direction)
                if reentry_pen < 0:
                    score += reentry_pen
                    _dbg["reentry"] = f"{reentry_pen:+d}"
            except Exception as exc:
                logger.debug("[FOCUS] reentry error: %s", exc)

        # 별도 18) Momentum Reversal — 부모님 5/19 "UI 값 = 실제 효과" 결정
        # 옛 mom_pen // 3 트릭 제거 — dataclass strong_weight (-30) / medium (-20) 그대로 사용
        if direction:
            try:
                mom_pen, mom_label = self._compute_momentum_reversal_penalty(market, direction)
                if mom_pen < 0:
                    score += mom_pen
                    _dbg["mom_rev"] = f"{mom_label}{mom_pen:+d}"
            except Exception as exc:
                logger.debug("[FOCUS] mom rev error: %s", exc)

        # 14+15) Phase 3 Play C — 시간 ±4 + 코인 +2 (자중 적용된 함수)
        if getattr(self.config, "phase3_context_bonus_enabled", True):
            try:
                _ctx_bonus = self._compute_phase3_context_bonus(market)
                if _ctx_bonus != 0:
                    score += _ctx_bonus
                    _dbg["phase3"] = f"{_ctx_bonus:+d}"
            except Exception as exc:
                logger.debug("[FOCUS] phase3 ctx bonus error: %s", exc)

        # ★ [2026-05-21 부모] Day Direction conviction 가산 — 매일 09:00 KST 결정된 우세 방향
        # 우세 방향 일치 +N, 반대 -N, NEUTRAL = 0
        try:
            _dd = getattr(self, "day_direction", "NEUTRAL")
            _dd_delta = float(getattr(self.config, "day_direction_conv_delta", 5.0))
            if _dd_delta != 0 and _dd in ("LONG", "SHORT") and direction in ("LONG", "SHORT"):
                if direction == _dd:
                    score += _dd_delta
                    _dbg["day"] = f"{_dd}+{_dd_delta:.0f}"
                else:
                    score -= _dd_delta
                    _dbg["day"] = f"{_dd}-{_dd_delta:.0f}"
        except Exception as exc:
            logger.debug("[FOCUS] day_direction conv adj error: %s", exc)

        # ★ [2026-05-19 Phase 6 Step 2] Combinatorial Weighting — 부모님 비전 "극복 메커니즘"
        # 부모님 결정 (2026-05-19): 100점 도입 시점부터 우려하시던 비전 — "어떤 조합일때 다른 조건이 비록 부족해도 극복된다"
        #   A: PA 강 + zone + MTF → +25 (위치 + 패턴 + 추세 3중) — B-Full 완화
        #   B: CFID + EMA + volume → +35 (변곡점 임박)              — B-Full 완화
        #   C: 5step 만점급 + volume → +15 (추진 정렬)               — B-Full 완화
        #   D: News strong + aligned → +15                          — B-Full 완화
        # 조합 발생 시 다른 부족 조건 *극복* → 자연 분포 형성 (평범 30-50 / 강 70-85 / 극강 85-100)
        #
        # ★ [2026-05-19 B-Full] 부모님 결정 — H1+100점 유지하면서 옛 system (사무실2) 빈도 회복 목표.
        #   "옛 system 진입 자리도 양호 (BE 발동 자주) → 더 강한 자리 아니어도 묶임 위험 X"
        #   "묶임 회피는 이미 출구 가드 (be_stall/reverse_drift/caution_sideways/entry_expectation)
        #     + 진입 가드 (mtf_align/momentum_deriv/zone패널티/BB85차단/MACD fix) 가 담당"
        #   → 조합 발동 조건 대폭 완화 + 가산 점수 약간 ↓ (너무 쉬운 70 도달 방지)
        #   변경:
        #     A: PA STAR_V1/ENGULFING/+PIN_BAR + sr_s≥8/+5 + mtf_s≥4/+2 → +30/+25
        #     B: CFID strength≥70/+50 + vol big/+avg 까지 → +50/+35
        #     C: 5step≥10/+7 → +20/+15
        #     D: news raw |10|+/+|6|+ → +20/+15
        try:
            _pa_l = locals().get('_pa_label', '') or ''
            _5s_s_v = locals().get('_5s_score', 0)
            _mtf_s_v = locals().get('mtf_s', 0)
            _sr_s_v = locals().get('sr_s', 0)
            _cfid_d_v = locals().get('cfid_dir', 'NONE') or 'NONE'
            _cfid_st_v = locals().get('cfid_strength', 0) or 0
            _vol_l = (locals().get('vol_label', '') or '')

            # [2026-05-19 B-Full] 동적 임계 — dataclass 에서 읽음 (프리셋/UI 조정 가능)
            _a_bonus = int(getattr(self.config, 'phase6_combo_a_bonus', 25))
            _a_sr_min = int(getattr(self.config, 'phase6_combo_a_sr_min', 5))
            _a_mtf_min = int(getattr(self.config, 'phase6_combo_a_mtf_min', 2))
            _b_bonus = int(getattr(self.config, 'phase6_combo_b_bonus', 35))
            _b_strength_min = int(getattr(self.config, 'phase6_combo_b_strength_min', 50))
            _c_bonus = int(getattr(self.config, 'phase6_combo_c_bonus', 15))
            _c_5step_min = int(getattr(self.config, 'phase6_combo_c_5step_min', 7))
            _d_bonus = int(getattr(self.config, 'phase6_combo_d_bonus', 15))
            _d_news_abs_min = int(getattr(self.config, 'phase6_combo_d_news_abs_min', 6))

            _combo_b = 0
            _combo_p = []
            # A: PA 양호 (캔들 STAR_V1/ENGULFING/PIN_BAR + 구조 BOS 방향 일치) + zone (sr_s≥a_sr_min) + MTF 정렬 (mtf_s≥a_mtf_min)
            # [2026-05-19] BOS 추가 — Break of Structure = 시장 구조 변화 = 캔들 패턴 동급 진입 신호
            #              ZEC LONG 같은 4 TF 정렬 + BOS_BULLISH 자리 발동 가능
            _pa_ok = (
                'STAR_V1' in _pa_l or 'ENGULFING' in _pa_l or 'PIN_BAR' in _pa_l
                or (direction == "LONG" and 'BOS_BULLISH' in _pa_l)
                or (direction == "SHORT" and 'BOS_BEARISH' in _pa_l)
            )
            if _pa_ok and _sr_s_v >= _a_sr_min and _mtf_s_v >= _a_mtf_min:
                _combo_b += _a_bonus
                _combo_p.append(f"A:PA+zone+MTF+{_a_bonus}")
            # B: CFID aligned (strength≥b_strength_min) + vol big OR avg
            _cfid_align = ((direction == "LONG" and _cfid_d_v == "BULL_IMMINENT") or
                           (direction == "SHORT" and _cfid_d_v == "BEAR_IMMINENT"))
            if _cfid_align and _cfid_st_v >= _b_strength_min and ('big' in _vol_l or 'avg' in _vol_l):
                _combo_b += _b_bonus
                _combo_p.append(f"B:CFID+EMA+vol+{_b_bonus}")
            # C: 5step ≥ c_5step_min + vol big
            if _5s_s_v >= _c_5step_min and 'big' in _vol_l:
                _combo_b += _c_bonus
                _combo_p.append(f"C:5step+vol+{_c_bonus}")
            # D: |news_raw| ≥ d_news_abs_min + direction aligned
            _news_r = locals().get('_news_raw', 0) or 0
            _news_aligned = ((direction == "LONG" and _news_r >= _d_news_abs_min) or
                             (direction == "SHORT" and _news_r <= -_d_news_abs_min))
            if _news_aligned:
                _combo_b += _d_bonus
                _combo_p.append(f"D:news({_news_r:+d})+{_d_bonus}")

            if _combo_b > 0:
                score += _combo_b
                _dbg["combo"] = "|".join(_combo_p) + f"=+{_combo_b}"
        except Exception as exc:
            logger.debug("[FOCUS] combo weighting error: %s", exc)

        # ★ [2026-05-20 Phase 6 Stage 3] Combo E — 직감 가산점 (RSI/MACD/BB 극단 → 반대 방향 가산)
        # 부모님 직감 룰 (DOGE 사례): "BUY 신호 + RSI 과매수 + MACD 약세 + BB 상단 → 곧 반대 전환 → SHORT 진입"
        # 대칭 적용 — direction 별로 *반대 신호* 강하면 가산:
        #   direction=SHORT: RSI>70 + MACD hist<0 + BB pct≥99 → SHORT 가산 +50~90
        #   direction=LONG:  RSI<30 + MACD hist>0 + BB pct≤1  → LONG  가산 +50~90
        # 가산점: base 50 + (80 - confidence%)/80 × 40 → 50~90 (에너지바 짧을수록 ↑)
        if direction and getattr(self.config, 'phase6_combo_e_enabled', True):
            try:
                _e_bonus_max = int(getattr(self.config, 'phase6_combo_e_bonus_max', 90))
                _e_bonus_base = int(getattr(self.config, 'phase6_combo_e_bonus_base', 50))
                _e_rsi_ob = float(getattr(self.config, 'phase6_combo_e_rsi_overbought', 70.0))
                _e_rsi_os = float(getattr(self.config, 'phase6_combo_e_rsi_oversold', 30.0))
                _e_bb_high = float(getattr(self.config, 'phase6_combo_e_bb_high_pct', 99.0))
                _e_bb_low = float(getattr(self.config, 'phase6_combo_e_bb_low_pct', 1.0))

                _closes = locals().get('closes', None)
                if _closes and len(_closes) >= 35:
                    # RSI 계산 (재사용 가능한 indicator)
                    from app.strategy.indicators import rsi as _rsi_fn, bollinger_bands as _bb_fn_e
                    _rsi_now = _rsi_fn(_closes, 14)
                    _hist_now_e, _ = macd_hist_pair(_closes)
                    _bb_e = _bb_fn_e(_closes, 20, 2.0)
                    _bb_pct_e = None
                    if _bb_e and _bb_e.get("upper", 0) > _bb_e.get("lower", 0):
                        _bb_pct_e = (_closes[-1] - _bb_e["lower"]) / (_bb_e["upper"] - _bb_e["lower"]) * 100

                    _e_trigger = False
                    _e_reason = ""
                    if direction == "SHORT" and _rsi_now is not None and _bb_pct_e is not None:
                        if _rsi_now > _e_rsi_ob and _hist_now_e < 0 and _bb_pct_e >= _e_bb_high:
                            _e_trigger = True
                            _e_reason = f"RSI{_rsi_now:.0f}>OB · MACD{_hist_now_e:+.4f}<0 · BB{_bb_pct_e:.0f}%≥{_e_bb_high:.0f}"
                    elif direction == "LONG" and _rsi_now is not None and _bb_pct_e is not None:
                        if _rsi_now < _e_rsi_os and _hist_now_e > 0 and _bb_pct_e <= _e_bb_low:
                            _e_trigger = True
                            _e_reason = f"RSI{_rsi_now:.0f}<OS · MACD{_hist_now_e:+.4f}>0 · BB{_bb_pct_e:.0f}%≤{_e_bb_low:.0f}"

                    if _e_trigger:
                        # 에너지바 confidence — _get_trend_velocity 우선, fallback 으로 candles_primary 분석
                        _conf_pct = 0.0
                        _vel_e = self._get_trend_velocity(market, lookback_sec=300.0)
                        if _vel_e.get('samples', 0) > 0:
                            _conf_pct = _vel_e.get('current', 0.0) * 100.0
                        # 가산점 = base + (80 - confidence%)/80 × (max-base), clamp [base, max]
                        _e_extra = max(0.0, (80.0 - _conf_pct) / 80.0) * (_e_bonus_max - _e_bonus_base)
                        _e_bonus = max(_e_bonus_base, min(_e_bonus_max, int(_e_bonus_base + _e_extra)))
                        score += _e_bonus
                        _dbg["combo_e"] = f"E:{_e_reason} conf={_conf_pct:.0f}%+{_e_bonus}"
                        logger.info("[FOCUS] Phase6 Combo E %s %s: %s → +%d (conf=%.0f%%)",
                                    market, direction, _e_reason, _e_bonus, _conf_pct)
            except Exception as exc:
                logger.debug("[FOCUS] combo E error: %s", exc)

        # ★ [2026-05-20 Phase 6 Stage 4] Combo F — 봉 흐름 가산점 (MTF + M5 직전 5봉)
        # 부모님 비전 (DOGE 사례): "MTF 4단(H4/H1/30M/15M) 방향 + M5 직전 봉의 기울기·갯수 → 오르내리는 패턴"
        # A층(combo E)이 *방향 판단* (반대 진입 자격) → B층(combo F)은 *지금 자리* 판단 (봉 흐름 일치).
        # 3가지 sub-bonus:
        #   F1: MTF 정렬 (mtf_s 활용) — 부분 정렬 +10 / 완전 정렬 +20
        #   F2: M5 dominant_dir == direction → +15
        #   F3: M5 avg_body_pct ≥ 임계 (강한 봉 흐름) → +15
        # 총 최대 +50. 진입 자격 검증용 (수동 진입에도 적용 — Stage 5).
        if direction and getattr(self.config, 'phase6_combo_f_enabled', True):
            try:
                _f_total = 0
                _f_parts = []
                _f_mtf_partial = int(getattr(self.config, 'phase6_combo_f_mtf_partial_bonus', 10))
                _f_mtf_full = int(getattr(self.config, 'phase6_combo_f_mtf_full_bonus', 20))
                _f_m5_dir_bonus = int(getattr(self.config, 'phase6_combo_f_m5_dir_bonus', 15))
                _f_m5_body_bonus = int(getattr(self.config, 'phase6_combo_f_m5_body_bonus', 15))
                _f_m5_body_threshold = float(getattr(self.config, 'phase6_combo_f_m5_body_threshold', 0.3))
                # ★ [2026-06-12 부모 "이중계산 없애기"] 데이터(conviction 6.7k 분해): combo_f 가 SHORT 적자 최대(격차19.5).
                #   F1 = mtf_s 재사용 → mtf_align term 과 *MTF 이중계산*. F2 = M5방향 → cr_5/cr_15 와 *M5 이중계산*.
                #   dedupe ON → F1·F2 skip(이미 다른 항목서 셈), F3(body=대칭·변동성, 방향 중복 아님) 유지. default OFF.
                _f_dedupe = bool(getattr(self.config, 'combo_f_dedupe_enabled', False))

                # F1: MTF 정렬 (mtf_s 는 ±2 범위 — _compute_mtf_alignment_matrix 결과)
                if not _f_dedupe:
                    _mtf_s_f = int(locals().get('mtf_s', 0))
                    if _mtf_s_f >= 2:
                        _f_total += _f_mtf_full
                        _f_parts.append(f"F1:MTF_full+{_f_mtf_full}")
                    elif _mtf_s_f >= 1:
                        _f_total += _f_mtf_partial
                        _f_parts.append(f"F1:MTF_partial+{_f_mtf_partial}")

                # F2/F3: M5 봉 패턴
                _m5p = self._get_m5_candle_pattern(market, n=5)
                if _m5p:
                    _expected_dir = 'BULL' if direction == "LONG" else 'BEAR'
                    if (not _f_dedupe) and _m5p.get('dominant_dir') == _expected_dir:
                        _f_total += _f_m5_dir_bonus
                        _f_parts.append(f"F2:M5_{_m5p['dominant_dir']}({_m5p['bull_count']}↑/{_m5p['bear_count']}↓)+{_f_m5_dir_bonus}")
                    if _m5p.get('avg_body_pct', 0.0) >= _f_m5_body_threshold:
                        _f_total += _f_m5_body_bonus
                        _f_parts.append(f"F3:M5_body{_m5p['avg_body_pct']:.2f}%+{_f_m5_body_bonus}")

                if _f_total > 0:
                    score += _f_total
                    _dbg["combo_f"] = "|".join(_f_parts) + f"=+{_f_total}"
            except Exception as exc:
                logger.debug("[FOCUS] combo F error: %s", exc)

        # ENTRY phase 기록용
        self._last_conviction_breakdown = _dbg

        # ── ★ 이윤 여력 페널티 (2026-06-09 부모 "방향 맞아도 갈 곳 없으면 감점") ──
        # 후행 정렬로 쌓은 고점수를, 여력 없는 끝물 자리(저항/지지 코앞·RSI 극단·BB 밴드 끝)면 음수로 끌어내림.
        try:
            _hr_pen, _hr_detail = self._compute_headroom_penalty(market, direction, candles_primary, zones)
            if _hr_pen < 0:
                score += _hr_pen   # _hr_pen 은 음수
                _dbg["headroom"] = f"{_hr_detail}={_hr_pen:.0f}"
                logger.info("[FOCUS] ★ 여력 페널티: %s %s conv %.0f→%.0f (%s) — 갈 곳 없는 자리",
                            market, direction, score - _hr_pen, score, _hr_detail)
        except Exception as _hr_exc:
            logger.debug("[FOCUS] headroom penalty error: %s", _hr_exc)

        # ── ② ★ 끝물 상한 감점 (2026-06-09 부모 "90+=끝물=50↓, 벽타기 예외") ──
        # conviction 90+ = 후행/끝물 → target(50)으로 cap → 65 게이트 미달 = 차단. ADX≥exempt(벽타기)는 면제.
        if (getattr(self.config, "conviction_ceiling_enabled", False)
                and not getattr(self.config, "conviction_ceiling_post_guards", False)):  # ★ [패치 v1] post 모드면 합산 후 적용
            _cc_start = float(getattr(self.config, "conviction_ceiling_start", 90.0))
            if score >= _cc_start:
                _cc_target = float(getattr(self.config, "conviction_ceiling_target", 50.0))
                _cc_exempt = float(getattr(self.config, "conviction_ceiling_adx_exempt", 30.0))
                try:
                    _cc_adx = float(adx_val)  # 함수 내 진입 코인 primary ADX
                except (NameError, ValueError, TypeError):
                    _cc_adx = float(getattr(self, "_last_adx_value", 0.0) or 0.0)
                if _cc_exempt > 0 and _cc_adx >= _cc_exempt:
                    logger.info("[FOCUS] ② 끝물 면제(벽타기): %s %s conv=%.0f ADX=%.0f≥%.0f — 강한 돌파, 점수 유지",
                                market, direction, score, _cc_adx, _cc_exempt)
                else:
                    logger.info("[FOCUS] ② ★ 끝물 상한 감점: %s %s conv %.0f→%.0f (ADX=%.0f<%.0f, 벽타기 아님) — 후행/끝물 차단",
                                market, direction, score, _cc_target, _cc_adx, _cc_exempt)
                    score = min(score, _cc_target)

        logger.info("[FOCUS] conviction Phase5 %s %s → score=%.1f/100 | %s",
                    market, direction, score,
                    " ".join(f"{k}={v}" for k, v in _dbg.items()))

        return min(100.0, max(0.0, float(score)))  # [Phase 5] 0~100 cap

    def _effective_dir_cap(self, direction: str) -> int:
        """방향별 슬롯 상한 해석 (2026-04-20 형 지시).
        Auto(-1) = "반대 방향 포지션이 있으면 차단, 없으면 Same Dir 허용"
          → 먼저 들어간 방향이 자동으로 포트폴리오 잠금.
            B11 regime lock과 합쳐 "상승=LONG only, 하락=SHORT only" 자동 실현.
        0 = 해당 방향 완전 차단. >0 = 명시값 (양쪽 다 >0이면 기존 양방향 허용 구조).
        금(lock_market=XAUTUSDT) 포지션은 "별 시장"이라 opp 카운트에서 제외."""
        cfg = self.config
        dir_up = (direction or "").upper()
        if dir_up == "LONG":
            v = int(getattr(cfg, "max_long_positions", -1))
            opp = "SHORT"
        else:
            v = int(getattr(cfg, "max_short_positions", -1))
            opp = "LONG"
        if v >= 0:
            return v  # 명시값
        # Auto 모드 — auto_first_dir_lock 토글로 두 정신 분기 (2026-04-26 부모님 결정)
        # True (default, 초단타 정신): 첫 발 방향 잠금 + 손실 cap 보호 (4-25)
        # False (롱홀드 정신): 양방향 자유 + same_dir cap 으로 편중 보호 (4-26)
        if getattr(cfg, "auto_first_dir_lock", True):
            lock_mkt = (getattr(cfg, "lock_market", "") or "").upper()
            opp_count = sum(1 for p in self.positions
                            if p.direction == opp
                            and (not lock_mkt or p.market.upper() != lock_mkt))
            if opp_count > 0:
                return 0
        return int(getattr(cfg, "max_same_direction", 3))

    def _get_context_engine(self):
        """Context Engine lazy-init."""
        if self._context_engine is None:
            try:
                from app.manager.context_engine import ContextEngine
                self._context_engine = ContextEngine(self.config)
            except Exception as exc:
                logger.warning("[FOCUS] context_engine init failed: %s", exc)
                return None
        return self._context_engine

    def _get_btc_regime_candles(self):
        """BTC regime 캔들 60봉 — primary_tf(H1, "60") · 10분 캐시. [2026-05-15] _get_btc_primary_candles 에서 개명."""
        now = time.time()
        ts, cached = self._btc_candles_cache
        if cached and (now - ts) < 600.0:
            return cached
        try:
            raw = self._get_client().get_kline("BTCUSDT", interval="60", limit=60)
            if raw and len(raw) >= 30:
                self._btc_candles_cache = (now, raw)
                return raw
        except Exception as exc:
            logger.debug("[FOCUS] BTC kline fetch failed: %s", exc)
        return []

    def _apply_context_engine(self, market: str, direction: str):
        """Context Engine 호출 래퍼. Returns: (delta, block, summary_str).

        ★ [2026-04-25 부모 설계] 동적 상태 머신 — 합창 vs 솔로 자동 전환:
           합창 active (B12 BREADTH_BULL/BEAR) → BTC 솔로 OFF (중복 방지)
           합창 NEUTRAL (B12 N 미달)           → BTC 솔로 ON  (솔로가 길잡이)
           B11 모드                            → BTC 솔로 OFF (B11 이 BTC 자체)
           regime_lock OFF                      → BTC 솔로 ON  (유일한 방향 정보)
        """
        cfg = self.config
        # ── 합창-솔로 자동 전환: btc_regime 유효 여부 결정 ──
        btc_regime_effective = getattr(cfg, "btc_regime_enabled", False)
        _btc_skip_reason = ""
        if btc_regime_effective:
            _mode = (getattr(cfg, "regime_lock_mode", "B11") or "B11").upper()
            if _mode == "B12":
                # 합창 모드 — 현재 B12 breadth 상태 조회
                try:
                    vote = self._get_b12_breadth_vote()
                    _verdict = (vote.get("verdict", "NEUTRAL") or "NEUTRAL").upper()
                    if _verdict in ("BREADTH_BULL", "BREADTH_BEAR"):
                        # 합창 활성 → BTC 솔로 suppressed
                        btc_regime_effective = False
                        _btc_skip_reason = f"B12_{_verdict}_active"
                except Exception as exc:
                    logger.debug("[FOCUS] b12 vote check failed: %s", exc)
            elif _mode == "B11":
                # B11 = BTC EMA regime lock = BTC 지배 → btc_regime 중복
                btc_regime_effective = False
                _btc_skip_reason = "b11_mode_duplicate"
            # OFF 모드 → 원래대로 btc_regime 사용 (유일한 BTC 정보)

        any_on = (
            getattr(cfg, "session_profile_enabled", False)
            or getattr(cfg, "direction_memory_enabled", False)
            or btc_regime_effective
            or getattr(cfg, "market_bias_enabled", False)
        )
        if not any_on:
            return (0, False, "")

        eng = self._get_context_engine()
        if eng is None:
            return (0, False, "")

        btc_candles = None
        if btc_regime_effective:
            btc_candles = self._get_btc_regime_candles()
        elif _btc_skip_reason:
            logger.debug("[FOCUS] btc_regime suppressed: %s", _btc_skip_reason)

        # btc_regime 자동 OFF 인 경우 config 임시 override 필요
        # → eng.evaluate() 내부에서 self.config.btc_regime_enabled 체크하므로
        #   대신 btc_candles=None 으로 넘기면 btc_regime.py 가 알아서 skip
        #   (btc_regime.evaluate 는 candles 없으면 delta=0 반환)
        # 추가: btc_regime_enabled 이 True 여도 candles 없으면 sensible no-op
        verdict = eng.evaluate(
            market=market,
            direction=direction or "",
            now_ts=time.time(),
            btc_candles=btc_candles,
        )

        # ★ [2026-04-25 부모 "경계선 구제"] 교차 검증 bonus/penalty
        # BTC + B12 합창 두 소리가 같은 방향 = +1 (경계선 구제)
        #                  반대 방향      = -1 (양쪽 경고)
        #                  한쪽만 의견    = 0  (기존 logic)
        # 대칭 원칙: B11/B12/OFF 모드 무관 항상 적용
        cross_delta = 0
        cross_tag = ""
        try:
            if direction:
                dir_u = direction.upper()
                # B12 breadth 방향 (mode 무관 항상 조회)
                vote = self._get_b12_breadth_vote()
                b12_verdict = (vote.get("verdict", "NEUTRAL") or "NEUTRAL").upper()
                # BTC 현재 regime (캐시된 상태)
                btc_regime_now = getattr(self, "_b11_regime_state", ("", 0.0))[0] or "NEUTRAL"
                btc_regime_now = btc_regime_now.upper()

                # ★ [2026-04-26 부모님 정정] cross_check = B12 합창 전용 / BTC 는 #4 BTC Trend Conv Bonus 가 전담
                # 이중 계산 방지 — 이전엔 B12+BTC 합쳐 ±1, BTC trend bonus +2 와 합치면 +3 가중 위험
                b12_favor = (b12_verdict == "BREADTH_BULL" and dir_u == "LONG") or \
                            (b12_verdict == "BREADTH_BEAR" and dir_u == "SHORT")
                b12_against = (b12_verdict == "BREADTH_BULL" and dir_u == "SHORT") or \
                              (b12_verdict == "BREADTH_BEAR" and dir_u == "LONG")

                if b12_favor:
                    cross_delta = +1
                    cross_tag = f"cross+1(B12 합창 {dir_u} 우호)"
                elif b12_against:
                    cross_delta = -1
                    cross_tag = f"cross-1(B12 합창 {dir_u} 반대)"
                # B12 NEUTRAL → cross_delta = 0
                # btc_regime_now 는 #4 BTC Trend Conv Bonus 가 전담 (더 이상 cross 에서 안 봄)
        except Exception as exc:
            logger.debug("[FOCUS] cross check failed: %s", exc)

        final_delta = verdict.delta + cross_delta
        # ★ #5A [2026-04-26 형 fix] cross_delta 추적 (BTC bonus cap 산정용)
        self._last_cross_delta = cross_delta
        summary = verdict.summary()
        if cross_tag:
            summary = (summary + "/" if summary else "") + cross_tag
            logger.info("[FOCUS] %s %s cross-check: %s (base %+d + cross %+d = %+d)",
                        market, direction, cross_tag, verdict.delta, cross_delta, final_delta)

        return (final_delta, verdict.block, summary)

    def _get_locked_slot_count(self) -> int:
        """지정 window(h) 이상 묶인 슬롯 수 (★ 2026-05-10 부모님 Conviction Override Slot).

        '묶인 슬롯' = override_locked_slot_min_hours (default 24h) 이상 보유 일반 슬롯.
        window 는 사용자 knob (시장 따라 조정).
        확장 슬롯 추가 허용 수 = min(이 카운트, override_max_extra_slots).
        """
        try:
            min_hours = float(getattr(self.config, "override_locked_slot_min_hours", 24.0))
            min_sec = min_hours * 3600.0
            now = time.time()
            count = 0
            for pos in self.positions:
                if getattr(pos, "is_override", False):
                    continue  # 확장 슬롯 자체는 카운트 X
                hold_sec = now - float(getattr(pos, "entry_ts", now))
                if hold_sec < min_sec:
                    continue
                # 미실현 손실 여부: peak < entry (LONG) 또는 peak > entry (SHORT) 등 다양 — 단순화: 24h+ 만 카운트
                count += 1
            return count
        except Exception as exc:
            logger.debug("[FOCUS] _get_locked_slot_count exception: %s", exc)
            return 0

    def _get_effective_max_positions(self, is_override: bool = False, allow_slot_expand: bool = False) -> int:
        """진입 가능 최대 슬롯 수 (Override / Slot Auto Expand 시 +N 허용).

        - 일반 슬롯: max_positions (default 5)
        - Override 슬롯 (is_override=True): max_positions + min(locked, override_max_extra_slots)
        - Slot Auto Expand (allow_slot_expand=True): + slot_auto_expand_max_extra (조건 충족 시)
        """
        base = int(getattr(self.config, "max_positions", 5))
        # Override 확장
        if is_override and getattr(self.config, "override_slot_enabled", False):
            locked = self._get_locked_slot_count()
            extra_cap = int(getattr(self.config, "override_max_extra_slots", 3))
            base += min(locked, extra_cap)
        # [2026-05-29 부모] Slot Auto Expand — 강신호 시 +1 추가
        if allow_slot_expand and self._slot_auto_expand_can_try():
            base += int(getattr(self.config, "slot_auto_expand_max_extra", 1))
        return base

    def _slot_auto_expand_can_try(self) -> bool:
        """[2026-05-29 부모] Slot Auto Expand 기본 조건 (코인 무관).
          - enabled
          - 슬롯 가득 (len == max_positions)
          - 모든 슬롯 lock_hours+ 묶임
          - extras 미사용 (< max_extra)
        강신호 conv 체크는 _slot_auto_expand_eligible() (코인별)."""
        cfg = self.config
        if not getattr(cfg, "slot_auto_expand_enabled", False):
            return False
        base_max = int(getattr(cfg, "max_positions", 4))
        if len(self.positions) < base_max:
            return False  # 슬롯 가득 아님 → 불필요
        # 모든 슬롯 hold 시간 체크
        lock_h = float(getattr(cfg, "slot_auto_expand_lock_hours", 1.0))
        min_hold_sec = lock_h * 3600.0
        _now = time.time()
        for pos in self.positions:
            _ets = float(getattr(pos, "entry_ts", 0) or 0)
            if _ets <= 0:
                return False
            if (_now - _ets) < min_hold_sec:
                return False  # 한 슬롯이라도 미달
        # 이미 확장 슬롯 사용 중?
        max_extra = int(getattr(cfg, "slot_auto_expand_max_extra", 1))
        extras = sum(1 for p in self.positions if getattr(p, "is_slot_expand", False))
        if extras >= max_extra:
            return False
        return True

    def _slot_auto_expand_eligible(self, conv: float) -> bool:
        """[2026-05-29 부모] Slot Auto Expand 발동 (코인별 conv 포함).
        강신호 (conv ≥ min_conv) + 기본 조건 통과 시 True."""
        if not self._slot_auto_expand_can_try():
            return False
        min_conv = float(getattr(self.config, "slot_auto_expand_min_conviction", 85.0))
        return float(conv or 0) >= min_conv

    def _is_override_qualified(self, entry: dict) -> bool:
        """확장 슬롯 진입 자격 체크 (★ 2026-05-10 부모님 결정).

        Phase 2A 단순화: conviction + ADX 만 체크.
        Phase 2B 강화 예정: + multi-frame alignment + b12 합창 + BTC trend 일치.
        """
        if not getattr(self.config, "override_slot_enabled", False):
            return False
        try:
            conv = float(entry.get("conviction_score", 0) or 0)  # [2026-05-17 100점] int 절삭 제거
            adx = float(entry.get("adx", 0) or 0)
            if conv < float(getattr(self.config, "override_min_conviction", 80.0)):  # [100점 ×10] 9→80
                return False
            if adx < float(getattr(self.config, "override_min_adx", 50.0)):
                return False
            # Phase 2B 추후: mtf_align, b12_n, btc_match 추가
            return True
        except Exception as exc:
            logger.debug("[FOCUS] _is_override_qualified exception: %s", exc)
            return False

    def _compute_entry_budget(self, conviction_score: float, market: str) -> float:
        """[2026-05-17 100점 ×10] 확신 점수 기반 진입 예산.

        ★ [2026-04-26 부모님 "slot 수에 따라 budget 유동적"]
        max_single = available / N_slots — 슬롯 수 비례 자동 분배
          - 5-slot:  available/5 = 20% (큰 사이즈, 자본 활용)
          - 60-slot: available/60 = 1.67% (작은 사이즈, 분산)
        부모님이 max_positions 변경하면 자동으로 사이즈 재배분.

        ★ [2026-05-17 100점 마이그 사고 수정]
        unit = available / 10.0 → / 100.0 — 옛 0~10 score 가정. score 100 면 budget 10x 초과 사고.
        """
        # 가용 잔고 결정
        available = self.config.budget_usdt
        if available <= 0:
            available = self._get_available_margin()
        if available <= 0:
            # fallback: 기존 _get_effective_budget 사용
            available = self._get_effective_budget(market)

        unit = available / 100.0  # [2026-05-17 100점] /10 → /100. 1점당 unit = available 의 1%
        budget = unit * float(conviction_score)
        # ★ #2 [2026-04-26 → 2026-05-17 100점] Conviction-Weighted Sizing
        # low(≤50)=0.5x / mid=1.0x / high(≥80)=1.5x (옛 5/9 → 50/80, ×10)
        conv_mult = self._conv_sizing_multiplier(conviction_score)
        budget *= conv_mult

        # ★ [2026-04-26] Slot 비례 cap — 부모님 의도 자동
        n_slots = max(1, int(getattr(self.config, "max_positions", 5)))
        max_single = available / n_slots
        cap_pct = (1.0 / n_slots) * 100.0
        if budget > max_single:
            logger.info("[FOCUS] Budget capped: $%.2f → $%.2f (%.1f%% of $%.2f avail, conv=%.1f, conv_mult=%.1fx, slots=%d)",
                        budget, max_single, cap_pct, available, conviction_score, conv_mult, n_slots)
            budget = max_single

        return max(5.0, budget)

    # ★ [2026-04-26] Winners-Only Add — 부모님 "진정한 Autocoin"
    # "Winners ride, losers cut" 정신. 자본 추가 시 유리한 코인만 증액.
    def _detect_capital_added(self) -> float:
        """자본 추가 감지 — Bybit deposit history 기반 (4-26 형 #4 fix).

        이전 버그: equity 비교는 미실현 PnL 변동을 capital_added 로 오인 → false positive.
        수정: Bybit /v5/asset/deposit/query-record 조회. 최근 N분 내 실제 deposit 만 인정.
        """
        if not getattr(self.config, "winners_add_enabled", False):
            return 0.0
        try:
            import requests as _req, time as _t, hashlib, hmac
            now_ms = int(_t.time() * 1000)
            window_min = float(getattr(self.config, "winners_add_capital_threshold_pct", 20.0))
            # threshold 의미 변경: 기존 % 에서 deposit 감지 후 실제 입금액 (USDT) 으로
            # window_min 은 deposit 감지 윈도우 (분) — capital_threshold_pct 재활용 (상한 기본 20분)
            window_ms = int(window_min * 60 * 1000)
            last_check = float(getattr(self, "_winners_deposit_last_check_ms", 0))
            since_ms = max(now_ms - window_ms, int(last_check))
            self._winners_deposit_last_check_ms = now_ms

            key = os.environ.get('BYBIT_API_KEY', '')
            secret = os.environ.get('BYBIT_API_SECRET', '')
            if not key or not secret:
                return 0.0
            ts = str(now_ms)
            recv = '5000'
            # startTime / endTime 은 UTC ms
            params_str = f'coin=USDT&startTime={since_ms}&endTime={now_ms}'
            sign_str = ts + key + recv + params_str
            sig = hmac.new(secret.encode(), sign_str.encode(), hashlib.sha256).hexdigest()
            headers = {'X-BAPI-API-KEY': key, 'X-BAPI-TIMESTAMP': ts,
                       'X-BAPI-RECV-WINDOW': recv, 'X-BAPI-SIGN': sig}
            r = _req.get('https://api.bybit.com/v5/asset/deposit/query-record',
                         params={'coin': 'USDT', 'startTime': since_ms, 'endTime': now_ms},
                         headers=headers, timeout=5)
            d = r.json()
            rows = (d.get('result', {}) or {}).get('rows', []) or []
            total_deposit = 0.0
            for row in rows:
                # status 3 = success
                if int(row.get('status', 0)) == 3:
                    total_deposit += float(row.get('amount', 0) or 0)
            if total_deposit > 0:
                logger.info("[FOCUS] 💰 Real deposit detected: $%.2f (Bybit deposit history, last %.0fmin)",
                            total_deposit, window_min)
                return total_deposit
            return 0.0
        except Exception as exc:
            logger.debug("[FOCUS] _detect_capital_added (deposit history) failed: %s", exc)
            return 0.0

    def _select_winners_to_add(self, max_count: int = 2) -> list:
        """유리한 코인 우선순위 선별. 1순위 pnl ≥ min, 2순위 peak 임박."""
        min_pnl = float(getattr(self.config, "winners_add_min_pnl_pct", 0.3))
        candidates = []
        for pos in self.positions:
            try:
                price = self._get_current_price(pos.market)
                if not price or price <= 0 or pos.entry_price <= 0:
                    continue
                if pos.direction == "LONG":
                    pnl_pct = (price / pos.entry_price - 1) * 100
                else:
                    pnl_pct = (1 - price / pos.entry_price) * 100
                if pnl_pct >= min_pnl:
                    score = pnl_pct + 10.0  # 이미 수익 = 큰 보너스
                    candidates.append((score, pos))
                else:
                    # 2순위: peak 임박
                    if pos.peak_profit_price > 0:
                        if pos.direction == "LONG":
                            peak_pct = (pos.peak_profit_price / pos.entry_price - 1) * 100
                        else:
                            peak_pct = (1 - pos.peak_profit_price / pos.entry_price) * 100
                        if peak_pct >= min_pnl:
                            candidates.append((peak_pct, pos))
            except Exception as exc:
                logger.debug("[FOCUS] winners_select error %s: %s", pos.market, exc)
        candidates.sort(key=lambda x: x[0], reverse=True)
        return [pos for _, pos in candidates[:max_count]]

    def _execute_winners_add(self, added_capital: float, winners: list) -> int:
        """Winners 코인에 추가 자본 분배 + Bybit 추가 진입. 반환: 성공 수."""
        if not winners or added_capital <= 5.0:
            return 0
        max_pct = float(getattr(self.config, "winners_add_max_pct_per_coin", 100.0)) / 100.0
        per_coin_budget = added_capital / len(winners)
        success = 0
        for pos in winners:
            try:
                current_margin = pos.entry_price * pos.qty / max(1, self.config.leverage)
                max_add = current_margin * max_pct
                add_budget = min(per_coin_budget, max_add)
                if add_budget < 5.0:
                    continue
                price = self._get_current_price(pos.market) or pos.entry_price
                add_notional = add_budget * self.config.leverage
                add_qty = add_notional / price
                if add_qty <= 0:
                    continue
                client = self._get_client()
                side = "Buy" if pos.direction == "LONG" else "Sell"
                order_resp = client.place_order(pos.market, side, round(add_qty, 4), reduce_only=False)
                if order_resp and order_resp.get("retCode", -1) == 0:
                    # 평균가 가중평균 갱신
                    old_total = pos.entry_price * pos.qty
                    new_total = price * add_qty
                    total_qty = pos.qty + add_qty
                    pos.entry_price = (old_total + new_total) / total_qty if total_qty > 0 else pos.entry_price
                    pos.qty = total_qty
                    logger.info(
                        "[FOCUS] 🎯 Winners Add: %s %s +qty=%.4f budget=$%.2f → new entry=$%.6f total qty=%.4f",
                        pos.direction, pos.market, add_qty, add_budget, pos.entry_price, pos.qty
                    )
                    try:
                        self._notify(
                            f"🎯 Winners Add: {pos.direction} {pos.market}\n"
                            f"  +${add_budget:.2f} @ ${price:.4f}\n"
                            f"  new avg entry: ${pos.entry_price:.4f}"
                        )
                    except Exception:
                        pass
                    success += 1
            except Exception as exc:
                logger.warning("[FOCUS] winners_add %s failed: %s", pos.market, exc)
        return success

    def _check_winners_add_tick(self):
        """메인 tick에서 호출 — Winners Add 자동 발동.

        2026-04-26 #5 강화: capital_added 외에 self_growth (수익코인 자체 +X% 도달) 도 트리거.
        """
        if not getattr(self.config, "winners_add_enabled", False):
            return
        last_ts = float(getattr(self, "_winners_last_add_ts", 0))
        cooldown = float(getattr(self.config, "winners_add_cooldown_sec", 3600))
        if time.time() - last_ts < cooldown:
            return
        added = self._detect_capital_added()
        # ★ #5 강화 — self_growth 트리거: 수익 코인 자체가 +X% 도달 시 추가 자본 없어도 발동
        # ★ [2026-04-26 형 #1 fix] (1) 가장 수익 큰 코인 우선 (첫 매칭 break X), (2) ratio_pct config 노출
        if added <= 0 and getattr(self.config, "winners_add_self_growth_enabled", True):
            growth_th = float(getattr(self.config, "winners_add_self_growth_pct", 1.5))
            ratio_pct = float(getattr(self.config, "winners_add_self_growth_ratio_pct", 50.0))
            best_pos = None
            best_pnl = -999.0
            for pos in self.positions:
                pnl_pct = self._compute_position_pnl_pct(pos) if hasattr(self, "_compute_position_pnl_pct") else 0
                if pnl_pct >= growth_th and pnl_pct > best_pnl:
                    best_pos = pos
                    best_pnl = pnl_pct
            if best_pos is not None:
                margin = (best_pos.entry_price * best_pos.qty) / max(1, self.config.leverage)
                added = margin * (ratio_pct / 100.0)
                logger.info("[FOCUS] Winners Add self_growth trigger: %s %s pnl=%+.2f%% margin=$%.2f × %.0f%% → add=$%.2f",
                            best_pos.market, best_pos.direction, best_pnl, margin, ratio_pct, added)
        if added <= 0:
            return
        max_count = int(getattr(self.config, "winners_add_max_per_event", 2))
        winners = self._select_winners_to_add(max_count)
        if not winners:
            logger.info("[FOCUS] Winners Add: capital +$%.2f detected but no winners (모든 코인 손실 중) — skip", added)
            return
        count = self._execute_winners_add(added, winners)
        if count > 0:
            self._winners_last_add_ts = time.time()
            logger.info("[FOCUS] Winners Add complete: %d positions added", count)

    def _get_coin_repeat_info(self, market: str, direction: str = "") -> tuple:
        """최근 24시간 내 같은 코인 EXIT 횟수 + 마지막 EXIT 시각.
        [2026-04-18] direction 지정 시 해당 방향만 카운트 — LONG/SHORT 축적 분리
        Returns: (count, last_exit_ts)"""
        try:
            from app.manager.trade_journal import JOURNAL_PATH
            window_sec = self.config.coin_repeat_window_hours * 3600
            cutoff = time.time() - window_sec
            mkt_upper = market.upper()
            dir_upper = direction.upper() if direction else ""
            count = 0
            last_ts = 0.0
            if not os.path.exists(JOURNAL_PATH):
                return (0, 0.0)
            with open(JOURNAL_PATH, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        rec = json.loads(line)
                        ts = rec.get("ts", 0)
                        if ts < cutoff:
                            continue
                        if rec.get("market", "").upper() == mkt_upper and rec.get("event") == "EXIT":
                            # [2026-04-18] 방향 필터 — 같은 코인 LONG 반복이 SHORT 브레이크까지 걸던 거 분리
                            if dir_upper and rec.get("direction", "").upper() != dir_upper:
                                continue
                            count += 1
                            if ts > last_ts:
                                last_ts = ts
                    except (json.JSONDecodeError, KeyError):
                        continue
            return (count, last_ts)
        except Exception as exc:
            logger.warning("[FOCUS] coin_repeat_info error: %s", exc)
            return (0, 0.0)

    # ── B9/B8/B6 Reentry Defense Layer (2026-04-19) ──────────────
    def _get_last_exit_info(self, market: str, direction: str) -> tuple:
        """저널에서 해당 market+direction 의 최근 EXIT 정보.
        SERVER_SL 포함 모든 exit 경로 반영.
        Returns: (last_exit_ts, exit_reason, pnl_net, pnl_pct) or (0.0, "", 0.0, 0.0)

        [2026-04-24] pnl_pct 추가 — Sliding Loss Cooldown tier 분류용 (부모 발상 "유치장")
        """
        try:
            from app.manager.trade_journal import JOURNAL_PATH
            if not os.path.exists(JOURNAL_PATH):
                return (0.0, "", 0.0, 0.0)
            mkt_upper = market.upper()
            dir_upper = direction.upper()
            last_ts = 0.0
            last_reason = ""
            last_pnl = 0.0
            last_pct = 0.0
            with open(JOURNAL_PATH, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        rec = json.loads(line)
                        if rec.get("event") != "EXIT":
                            continue
                        if rec.get("market", "").upper() != mkt_upper:
                            continue
                        if rec.get("direction", "").upper() != dir_upper:
                            continue
                        ts = rec.get("ts", 0)
                        if ts > last_ts:
                            last_ts = ts
                            last_reason = rec.get("exit_reason", "") or ""
                            last_pnl = float(rec.get("pnl_net", 0) or 0)
                            last_pct = float(rec.get("pnl_pct", 0) or 0)
                    except (json.JSONDecodeError, KeyError, ValueError):
                        continue
            return (last_ts, last_reason, last_pnl, last_pct)
        except Exception as exc:
            logger.warning("[FOCUS] last_exit_info error: %s", exc)
            return (0.0, "", 0.0, 0.0)

    def _compute_dynamic_leverage(self, atr_pct: float, market: str = "") -> int:
        """★ [2026-04-25 부모 신규] ATR% 기반 동적 레버리지 결정.

        저변동 코인(ETH 같은) 에 lev 7 적용 시 SL 너무 멀어 큰 손실 → lev 5 로 낮춤.
        고변동 알트 (ZEC 같은) 는 lev 7 유지.

        Args:
            atr_pct: ATR / price * 100 (진입 코인 기준)
            market: 로그용 라벨 (선택)
        Returns:
            int leverage (5~10 clamp)
        """
        cfg = self.config
        base_lev = int(getattr(cfg, "leverage", 7))
        if not getattr(cfg, "leverage_tier_enabled", False):
            return base_lev
        low_pct = float(getattr(cfg, "leverage_tier_atr_low_pct", 1.5))
        high_pct = float(getattr(cfg, "leverage_tier_atr_high_pct", 2.5))
        low_lev = int(getattr(cfg, "leverage_tier_low", 5))
        high_lev = int(getattr(cfg, "leverage_tier_high", 7))

        if atr_pct < low_pct:
            dyn = low_lev
            tier = "LOW"
        elif atr_pct >= high_pct:
            dyn = high_lev
            tier = "HIGH"
        else:
            dyn = base_lev
            tier = "MID"

        # 안전 clamp: 1~20 (Bybit USDT perp 일반 범위)
        dyn = max(1, min(20, dyn))
        logger.info("[FOCUS] leverage tier %s: ATR=%.2f%% → lev %dx (was %dx) %s",
                    tier, atr_pct, dyn, base_lev, market or "")
        return dyn

    def _check_consecutive_loss_pause(self) -> tuple:
        """★ [2026-04-24] 부모님 단순 발상: 연패 N회 → M분 시간 정지.

        max_daily_sl(그날 끝)와 dm_streak_block(영구) 의 사이.
        모든 코인 대상 (전체 FOCUS 정지). HARPOON 의 max_consecutive_loss 모델 모방.

        규칙:
          - journal 의 최근 EXIT 들 (모든 코인) 시간 역순 스캔
          - 최신부터 연속 손실 streak 카운트 (이익 만나면 끊김)
          - streak >= count_threshold 면 "마지막 손실 ts" 기준 M분 동안 차단
          - 시간 만료 시 자동 해제

        Returns: (blocked: bool, reason: str)
        """
        cfg = self.config
        if not getattr(cfg, "consecutive_loss_pause_enabled", True):
            return (False, "")
        count_threshold = int(getattr(cfg, "consecutive_loss_pause_count", 3))
        pause_min = int(getattr(cfg, "consecutive_loss_pause_min", 60))
        if count_threshold <= 0 or pause_min <= 0:
            return (False, "")
        try:
            from app.manager.trade_journal import JOURNAL_PATH
            if not os.path.exists(JOURNAL_PATH):
                return (False, "")
            now = time.time()
            # 최근 EXIT 만 (모든 코인). 최대 50건 본다.
            exits = []
            with open(JOURNAL_PATH, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        rec = json.loads(line)
                        if rec.get("event") != "EXIT":
                            continue
                        if (rec.get("strategy") or "").upper() != "FOCUS":
                            continue
                        exits.append({
                            "ts": float(rec.get("ts", 0) or 0),
                            "pnl": float(rec.get("pnl_net", 0) or 0),
                        })
                    except (json.JSONDecodeError, KeyError, ValueError):
                        continue
            if not exits:
                return (False, "")
            exits.sort(key=lambda x: x["ts"], reverse=True)
            # ★ [2026-05-11 부모님 AMNESTY 누락 수정] 사면 이후 손실만 streak 카운트
            #   AMNESTY = 부모님 "다시 시작" 명령 = consecutive_loss_pause 도 자동 해제
            amnesty_ts = float(getattr(self, "_amnesty_ts", 0.0) or 0.0)
            # 최신부터 연속 손실 streak
            streak = 0
            last_loss_ts = 0.0
            for ex in exits[:50]:
                if ex["ts"] < amnesty_ts:
                    break  # ★ AMNESTY 이전 손실 = streak 끊김 (사면)
                if ex["pnl"] >= 0:
                    break  # 이익 만나면 streak 끊김
                streak += 1
                if last_loss_ts == 0:
                    last_loss_ts = ex["ts"]
            if streak < count_threshold:
                return (False, "")
            # 차단 — 마지막 손실 시각 기준 pause_min 분
            elapsed = now - last_loss_ts
            pause_sec = pause_min * 60.0
            if elapsed < pause_sec:
                remain_min = (pause_sec - elapsed) / 60.0
                return (True, f"consecutive_loss_pause: {streak}연패 → {pause_min}분 정지 중 ({remain_min:.1f}분 남음)")
            return (False, "")
        except Exception as exc:
            logger.warning("[FOCUS] consecutive_loss_pause error: %s", exc)
            return (False, "")

    def _check_direction_fail_window(self, direction: str) -> tuple:
        """★ [2026-06-04 부모] 방향별 레짐 윈도우 실패 차단.

        N시간(기본 4H = H4 레짐 단위) 내 LONG/SHORT 실패 누적이 fail_max 초과 시
        해당 방향만 차단 — 반대 방향은 계속 허용.

        consecutive_loss_pause 보다 정교:
          - 방향 분리: LONG 3번 실패 → LONG만 차단, SHORT는 OK
          - 연속 아닌 누적: 중간에 다른 코인 이익 나도 카운트
          - 레짐 윈도우: 4시간 단위 (H4 한 봉 = 레짐 단위)

        Returns: (blocked: bool, reason: str)
        """
        cfg = self.config
        if not getattr(cfg, "regime_direction_fail_enabled", True):
            return (False, "")
        try:
            from app.manager.trade_journal import JOURNAL_PATH
            if not os.path.exists(JOURNAL_PATH):
                return (False, "")
            window_hours = float(getattr(cfg, "regime_direction_fail_window_hours", 4.0))
            fail_max     = int(getattr(cfg, "regime_direction_fail_max", 3))
            manual_exit  = {"manual_close_one", "manual_close_all", "ZERO_POSITION"}
            now          = time.time()
            cutoff       = now - window_hours * 3600.0
            dir_upper    = (direction or "").upper()
            fail_count   = 0
            last_fail_ts = 0.0
            with open(JOURNAL_PATH, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        rec = json.loads(line)
                        if rec.get("event") != "EXIT":
                            continue
                        ts = float(rec.get("ts", 0))
                        if ts < cutoff:
                            continue
                        if rec.get("direction", "").upper() != dir_upper:
                            continue
                        if rec.get("exit_reason", "") in manual_exit:
                            continue
                        pnl = float(rec.get("pnl_net", 0) or 0)
                        if pnl <= 0:
                            fail_count += 1
                            if ts > last_fail_ts:
                                last_fail_ts = ts
                    except (json.JSONDecodeError, KeyError, ValueError):
                        continue
            if fail_count >= fail_max:
                remain_h = (cutoff + window_hours * 3600.0 - last_fail_ts) / 3600.0
                if remain_h > 0:
                    logger.debug("[FOCUS] dir_fail_window: %s %d실패/%d허용 (%.1fh 윈도우) → %s 차단 %.1fh 남음",
                                 dir_upper, fail_count, fail_max, window_hours, dir_upper, remain_h)
                    return (True, f"dir_fail_window:{dir_upper} {fail_count}실패≥{fail_max} ({window_hours:.0f}h내) → {dir_upper} 차단 {remain_h:.1f}h 남음")
            return (False, "")
        except Exception as exc:
            logger.warning("[FOCUS] direction_fail_window error: %s", exc)
            return (False, "")

    def _count_coin_dir_loss(self, market: str, direction: str, window_hours: float = 4.0) -> int:
        """[2026-06-11] 내 저널의 *같은 코인+방향* 윈도우내 손실 수 — 함대 dir_fail 의 로컬 카운트.
        (dir_fail_window 는 코인 무관 '방향' 누적이고, 이건 코인별. 함대 합산용.)"""
        try:
            from app.manager.trade_journal import JOURNAL_PATH
            if not os.path.exists(JOURNAL_PATH):
                return 0
            now = time.time()
            cutoff = now - max(0.1, float(window_hours)) * 3600.0
            mk = (market or "").upper()
            dr = (direction or "").upper()
            manual_exit = {"manual_close_one", "manual_close_all", "ZERO_POSITION"}
            cnt = 0
            with open(JOURNAL_PATH, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        rec = json.loads(line)
                        if rec.get("event") != "EXIT":
                            continue
                        if float(rec.get("ts", 0)) < cutoff:
                            continue
                        if str(rec.get("market", "")).upper() != mk:
                            continue
                        if str(rec.get("direction", "")).upper() != dr:
                            continue
                        if rec.get("exit_reason", "") in manual_exit:
                            continue
                        if float(rec.get("pnl_net", 0) or 0) <= 0:
                            cnt += 1
                    except (json.JSONDecodeError, KeyError, ValueError):
                        continue
            return cnt
        except Exception as exc:
            logger.debug("[FOCUS] _count_coin_dir_loss error %s: %s", market, exc)
            return 0

    def _check_post_trade_pause(self, market: str, direction: str) -> tuple:
        """B9: 모든 exit 후 의무 냉각기 (익절/손절/fast_reject 별).
        Returns: (blocked: bool, reason: str)

        [2026-04-24] Sliding Loss Cooldown 추가 — 부모님 발상 "유치장"
          기존: 손실 = 일률 600초 → 수수료 미만 -0.04% 도 10분 차단 (기회 박탈)
          신규: 손실 % 따라 5단계 차등 (0.5% < 60s, ..., 10%+ → 4시간)
        """
        cfg = self.config
        if not getattr(cfg, "post_trade_pause_enabled", True):
            return (False, "")
        last_ts, reason, pnl, pnl_pct = self._get_last_exit_info(market, direction)
        if last_ts <= 0:
            return (False, "")
        # ★ [2026-06-09 부모] 대사면 — amnesty 이전 청산은 유치장(post_trade_pause) 면제
        if getattr(self, "_amnesty_ts", 0.0) > 0 and last_ts <= self._amnesty_ts:
            return (False, "")
        elapsed = time.time() - last_ts
        # 냉각기 유형 분류: fast_reject > loss > profit
        reason_lower = (reason or "").lower()
        if "fast_reject" in reason_lower or "fast-reject" in reason_lower:
            required = getattr(cfg, "post_trade_pause_fastreject_sec", 900.0)
            kind = "fast_reject"
        elif pnl < 0:
            # ★ Sliding Loss Cooldown — 손실 % 기반 차등 (부모 발상)
            if getattr(cfg, "post_trade_pause_loss_sliding_enabled", True):
                loss_abs_pct = abs(float(pnl_pct))
                t1_pct = float(getattr(cfg, "post_trade_pause_loss_tier1_pct", 0.5))
                t2_pct = float(getattr(cfg, "post_trade_pause_loss_tier2_pct", 2.0))
                t3_pct = float(getattr(cfg, "post_trade_pause_loss_tier3_pct", 5.0))
                t4_pct = float(getattr(cfg, "post_trade_pause_loss_tier4_pct", 10.0))
                if loss_abs_pct < t1_pct:
                    required = float(getattr(cfg, "post_trade_pause_loss_tier1_sec", 60.0))
                    kind = f"loss_t1(<{t1_pct}%)"
                elif loss_abs_pct < t2_pct:
                    required = float(getattr(cfg, "post_trade_pause_loss_tier2_sec", 300.0))
                    kind = f"loss_t2(<{t2_pct}%)"
                elif loss_abs_pct < t3_pct:
                    required = float(getattr(cfg, "post_trade_pause_loss_tier3_sec", 1800.0))
                    kind = f"loss_t3(<{t3_pct}%)"
                elif loss_abs_pct < t4_pct:
                    required = float(getattr(cfg, "post_trade_pause_loss_tier4_sec", 3600.0))
                    kind = f"loss_t4(<{t4_pct}%)"
                else:
                    required = float(getattr(cfg, "post_trade_pause_loss_tier5_sec", 14400.0))
                    kind = f"loss_t5(>={t4_pct}%, JAIL)"
            else:
                # Sliding OFF — legacy 일률 600초
                required = getattr(cfg, "post_trade_pause_loss_sec", 600.0)
                kind = "loss"
        else:
            required = getattr(cfg, "post_trade_pause_profit_sec", 300.0)
            kind = "profit"
        if elapsed < required:
            remaining = required - elapsed
            return (True, f"post_trade_pause[{kind}]: {elapsed:.0f}s/{required:.0f}s (wait {remaining:.0f}s more, pnl=${pnl:+.2f}/{pnl_pct:+.2f}%)")
        return (False, "")

    def _check_direction_exhaustion(self, market: str, direction: str) -> tuple:
        """B8: 같은 market+direction 연속 익절 N회 = 방향 소진 → 하드블록.
        Returns: (blocked: bool, reason: str)"""
        cfg = self.config
        if not getattr(cfg, "direction_exhaustion_enabled", True):
            return (False, "")
        try:
            from app.manager.trade_journal import JOURNAL_PATH
            if not os.path.exists(JOURNAL_PATH):
                return (False, "")
            window = getattr(cfg, "direction_exhaustion_window_sec", 900.0)
            threshold = getattr(cfg, "direction_exhaustion_profit_count", 2)
            block_sec = getattr(cfg, "direction_exhaustion_block_sec", 1800.0)
            mkt_upper = market.upper()
            dir_upper = direction.upper()
            now = time.time()
            cutoff = now - window
            profit_count = 0
            last_profit_ts = 0.0
            with open(JOURNAL_PATH, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        rec = json.loads(line)
                        if rec.get("event") != "EXIT":
                            continue
                        ts = rec.get("ts", 0)
                        if ts < cutoff:
                            continue
                        if rec.get("market", "").upper() != mkt_upper:
                            continue
                        if rec.get("direction", "").upper() != dir_upper:
                            continue
                        pnl = float(rec.get("pnl_net", 0) or 0)
                        if pnl > 0:
                            profit_count += 1
                            if ts > last_profit_ts:
                                last_profit_ts = ts
                    except (json.JSONDecodeError, KeyError, ValueError):
                        continue
            if profit_count >= threshold and last_profit_ts > 0:
                elapsed = now - last_profit_ts
                if elapsed < block_sec:
                    remaining = block_sec - elapsed
                    return (True, f"direction_exhaustion: {profit_count} profits in {int(window/60)}m window → block {remaining:.0f}s more")
            return (False, "")
        except Exception as exc:
            logger.warning("[FOCUS] direction_exhaustion error: %s", exc)
            return (False, "")

    def _check_profit_exit_block(self, market: str, direction: str) -> tuple:
        """B10: 같은 코인 + 같은 방향 + 연속 N회 수익 청산 시 그 방향만 N시간 차단.

        ★ Phase F (2026-04-20 형 의도 복원):
        - 조건 3개 모두 충족해야 차단: (1) 같은 코인 (2) 같은 방향 (3) 연속 N회 수익
        - "드나들다 대판 잃는" 패턴 방어 — 한 코인 한 방향 반복 진입 차단
        - 반대 방향 진입은 허용 (block_opposite=False) — FLIP 기회 보존
        - 손실 또는 방향 전환이 섞이면 streak 끊김 → 차단 해제

        Returns: (blocked: bool, reason: str)"""
        cfg = self.config
        if not getattr(cfg, "profit_exit_block_enabled", True):
            return (False, "")
        try:
            from app.manager.trade_journal import JOURNAL_PATH
            if not os.path.exists(JOURNAL_PATH):
                return (False, "")
            block_sec = getattr(cfg, "profit_exit_block_hours", 12.0) * 3600.0
            min_pnl = getattr(cfg, "profit_exit_block_min_pnl", 0.5)
            min_consecutive = int(getattr(cfg, "profit_exit_block_min_consecutive", 3))
            block_opposite = bool(getattr(cfg, "profit_exit_block_block_opposite", False))
            mkt_upper = market.upper()
            dir_upper = (direction or "").upper()
            now = time.time()
            cutoff = now - block_sec
            # 해당 코인의 EXIT 수집
            exits = []
            with open(JOURNAL_PATH, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        rec = json.loads(line)
                        if rec.get("event") != "EXIT":
                            continue
                        if rec.get("market", "").upper() != mkt_upper:
                            continue
                        exits.append({
                            "ts": rec.get("ts", 0),
                            "direction": (rec.get("direction") or "").upper(),
                            "pnl": float(rec.get("pnl_net", 0) or 0),
                        })
                    except (json.JSONDecodeError, KeyError, ValueError):
                        continue
            if not exits:
                return (False, "")
            # 최신 순으로 정렬
            exits.sort(key=lambda x: x["ts"], reverse=True)
            # 최신부터 연속 "같은 방향 수익" streak 카운트
            streak_dir = exits[0]["direction"]
            streak_count = 0
            streak_last_ts = 0.0
            streak_total_pnl = 0.0
            for ex in exits:
                if ex["direction"] != streak_dir:
                    break   # 방향 전환 → streak 끊김
                if ex["pnl"] <= min_pnl:
                    break   # 손실 또는 노이즈 → streak 끊김
                if ex["ts"] < cutoff:
                    break   # 블록 윈도우 밖 → 더 이상 집계 안 함
                streak_count += 1
                streak_total_pnl += ex["pnl"]
                if streak_last_ts == 0:
                    streak_last_ts = ex["ts"]
            # 조건 1: 연속 N회 이상
            if streak_count < min_consecutive:
                return (False, "")
            # 조건 2: 현재 진입 방향이 streak 방향과 일치 (또는 block_opposite=True)
            if not block_opposite and dir_upper != streak_dir:
                return (False, "")   # 반대 방향은 허용
            # 차단 — streak 마지막 시각 기준 block_sec 대기
            elapsed = now - streak_last_ts
            if elapsed < block_sec:
                remain_h = (block_sec - elapsed) / 3600.0
                return (True, f"profit_exit_block: {mkt_upper} {streak_dir} {streak_count}연승(+${streak_total_pnl:.2f}) {elapsed/3600:.1f}h ago → wait {remain_h:.1f}h more")
            return (False, "")
        except Exception as exc:
            logger.warning("[FOCUS] profit_exit_block error: %s", exc)
            return (False, "")

    # ═══════════════════════════════════════════════════════════════════
    # ★ Phase M (2026-04-24) — HARPOON 조율용 read-only 헬퍼 3개
    #   부모님 지시: HARPOON 탈바꿈 + FOCUS 비파괴 원칙
    #   기존 로직 건드리지 않고 read-only 조회만 제공
    # ═══════════════════════════════════════════════════════════════════

    def _get_held_markets_for_harpoon(self) -> List[tuple]:
        """HARPOON 조율용: 현재 FOCUS 가 보유한 (market, direction) 리스트.
        HARPOON 이 respect_focus_coin_lock / respect_focus_direction_lock 체크 시 사용."""
        try:
            result = []
            for p in (self.positions or []):
                mkt = getattr(p, "market", "") or ""
                d = getattr(p, "direction", "") or ""
                if mkt and d:
                    result.append((mkt.upper(), d.upper()))
            return result
        except Exception as exc:
            logger.debug("[FOCUS] _get_held_markets_for_harpoon failed: %s", exc)
            return []

    def _get_most_recent_entry_ts_for_harpoon(self) -> float:
        """HARPOON 조율용: FOCUS 가 가장 최근 진입한 timestamp.
        HARPOON 이 focus_entry_freeze_sec 체크 시 사용 (FOCUS 진입 직후 N초 HARPOON skip)."""
        try:
            tss = [getattr(p, "entry_ts", 0) or 0 for p in (self.positions or [])]
            tss = [t for t in tss if t > 0]
            return max(tss) if tss else 0.0
        except Exception as exc:
            logger.debug("[FOCUS] _get_most_recent_entry_ts_for_harpoon failed: %s", exc)
            return 0.0

    def _get_total_margin_for_harpoon(self) -> float:
        """HARPOON 조율용: FOCUS 가 사용 중인 총 margin (USDT).
        HARPOON 이 budget 분리 시 FOCUS margin 차감하고 잔여 계산할 때 사용."""
        try:
            total = 0.0
            for p in (self.positions or []):
                entry_price = float(getattr(p, "entry_price", 0) or 0)
                qty = float(getattr(p, "qty", 0) or 0)
                lev = float(getattr(p, "leverage", 1) or 1)
                if entry_price > 0 and qty > 0 and lev > 0:
                    notional = entry_price * qty
                    margin = notional / lev
                    total += margin
            return total
        except Exception as exc:
            logger.debug("[FOCUS] _get_total_margin_for_harpoon failed: %s", exc)
            return 0.0

    def _get_shared_guard_state_for_harpoon(self, market: str, direction: str) -> dict:
        """HARPOON 조율용: 공유 가드 상태 일괄 조회 (Phase 5 read-only).

        반환 dict:
          {
            "profit_exit_blocked": (bool, str),    # B10
            "direction_exhaustion_blocked": (bool, str),  # B8
            "coin_loss_cap_blocked": (bool, str),  # 24h $20+
            "manual_exit_penalty_active": bool,
            "coin_repeat_count": int,
          }

        FOCUS 메서드 read-only 호출만 — 기존 로직 영향 X.
        """
        result = {
            "profit_exit_blocked": (False, ""),
            "direction_exhaustion_blocked": (False, ""),
            "coin_loss_cap_blocked": (False, ""),
            "manual_exit_penalty_active": False,
            "coin_repeat_count": 0,
        }
        if not market or not direction:
            return result
        mkt_u = market.upper()
        dir_u = direction.upper()
        try:
            # B10 profit_exit_block
            if getattr(self.config, "profit_exit_block_enabled", True):
                blocked, reason = self._check_profit_exit_block(mkt_u, dir_u)
                result["profit_exit_blocked"] = (blocked, reason)
        except Exception as exc:
            logger.debug("[FOCUS] guard state profit_exit_block failed: %s", exc)
        try:
            # B8 direction_exhaustion
            if getattr(self.config, "direction_exhaustion_enabled", True):
                blocked, reason = self._check_direction_exhaustion(mkt_u, dir_u)
                result["direction_exhaustion_blocked"] = (blocked, reason)
        except Exception as exc:
            logger.debug("[FOCUS] guard state direction_exhaustion failed: %s", exc)
        try:
            # coin_loss_cap (24h 누적)
            if getattr(self.config, "coin_loss_cap_enabled", True):
                cap = self._effective_coin_loss_cap()
                loss_total = self._get_coin_loss_total(mkt_u, dir_u)
                if loss_total <= -cap:
                    result["coin_loss_cap_blocked"] = (
                        True,
                        f"coin_loss_cap: {mkt_u} {dir_u} 24h_loss=${loss_total:.2f} <= -${cap:.2f}"
                    )
        except Exception as exc:
            logger.debug("[FOCUS] guard state coin_loss_cap failed: %s", exc)
        try:
            # manual_exit_penalty
            if getattr(self.config, "manual_exit_penalty_enabled", True):
                expire_ts = self._manual_exit_penalties.get(mkt_u, 0)
                result["manual_exit_penalty_active"] = (expire_ts > time.time())
        except Exception as exc:
            logger.debug("[FOCUS] guard state manual_exit_penalty failed: %s", exc)
        try:
            # coin_repeat 카운트 (정보만, 차단 결정은 HARPOON 자체)
            count, _last_ts = self._get_coin_repeat_info(mkt_u, dir_u)
            result["coin_repeat_count"] = count
        except Exception as exc:
            logger.debug("[FOCUS] guard state coin_repeat failed: %s", exc)
        return result

    def _get_btc_regime_lock_reason(self, direction: str) -> tuple:
        """★ HARPOON Stage 0-1 용 wrapper (2026-04-22 형 letter FAIL 수정).

        외부 (HARPOON 등) 에서 호출하는 B11 regime lock 체크.
        market 미지정 = lock_market 우회 비활성 (HARPOON 은 어느 코인이든 적용).
        Returns: (blocked: bool, reason: str)
        """
        try:
            return self._check_regime_direction_lock(direction, market="")
        except Exception as exc:
            logger.debug("[FOCUS] _get_btc_regime_lock_reason failed: %s", exc)
            return (False, f"check_exc: {exc}")  # 안전 fallback

    def execute_amnesty(self) -> dict:
        """★ 2026-04-23 부모 직접 지시: 대사면 (General Amnesty).
        "법이 미비할 때 저지른 일이니 일단 풀어주자"

        B11 1명 판단 시대의 모든 누적 형벌 기록 해제:
        1. _last_exit_*  : 재진입 차단 해제
        2. _manual_exit_penalties : 수동 퇴장 페널티 전면 해제
        3. _amnesty_ts   : 이 시각 이후 journal 이벤트만 penalty 계산에 쓰임
                          (direction_exhaustion / profit_exit_block / coin_loss_cap
                           / coin_repeat_brake / dm_streak_block / B12 vote 모두 영향)

        Journal 기록 자체는 보존 (감사 추적 유지).
        Returns: amnesty 결과 요약 dict."""
        prev_manual = dict(self._manual_exit_penalties)
        prev_last_exit = {
            "market": self._last_exit_market,
            "direction": self._last_exit_direction,
            "ts": self._last_exit_ts,
        }
        # 1. 즉시 형벌 해제
        self._manual_exit_penalties.clear()
        self._last_exit_market = ""
        self._last_exit_direction = ""
        self._last_exit_ts = 0.0
        self._last_exit_price = 0.0
        # 2. Journal-based penalty 시계 재시작
        self._amnesty_ts = time.time()
        logger.info(
            "[FOCUS] ★ GENERAL AMNESTY executed at %.0f — "
            "cleared %d manual_penalties, cleared last_exit_* (%s %s), "
            "journal penalty filter now >= %s",
            self._amnesty_ts,
            len(prev_manual),
            prev_last_exit["market"] or "-",
            prev_last_exit["direction"] or "-",
            time.strftime("%Y-%m-%d %H:%M:%S", time.localtime(self._amnesty_ts)),
        )
        # ★ [2026-05-11 자녀 누락 수정] AMNESTY 후 즉시 state 영속화
        #   누락 시: 재시작 → _amnesty_ts=0 → consecutive_loss_pause 다시 적용 (부모님 사고)
        try:
            self._save_config()
            logger.info("[FOCUS] AMNESTY state persisted to disk (_amnesty_ts=%.0f)", self._amnesty_ts)
        except Exception as exc:
            logger.warning("[FOCUS] AMNESTY save_config failed: %s", exc)
        return {
            "ok": True,
            "amnesty_ts": self._amnesty_ts,
            "cleared_manual_penalties": len(prev_manual),
            "cleared_last_exit": prev_last_exit,
            "message": "General Amnesty executed. All coin-level penalties released.",
        }

    def _get_b12_breadth_vote(self) -> dict:
        """B12: 최근 b12_window_sec 내 스캐너가 본 entry 시도들의 방향 카운트.

        journal 의 BLOCKED + ENTRY 이벤트에서 (market, direction) 추출 → 마켓당 최신 1건.

        ★ 2026-04-23 02:30 부모 발견 chicken-and-egg 해결:
           B11→B12 전환 직후 BLOCKED 이벤트가 안 쌓여 vote 0/0 → 영원히 NEUTRAL 함정.
           해결: primary window 데이터 부족(<2 markets) 시 자동 확장 (3x → 12x).
           예: 20분 부족 → 60분 → 240분. 옛 데이터라도 의견 표명 우선.
           실제 사용 윈도우는 'window_sec_used' 로 UI 에 노출.

        Returns: {
            'long_count': int, 'short_count': int, 'total_active': int,
            'verdict': 'BREADTH_BULL'/'BREADTH_BEAR'/'NEUTRAL',
            'window_sec': float (configured), 'window_sec_used': float (actual fallback),
            'threshold_n': int,
            'markets_long': [...], 'markets_short': [...]
        }
        """
        cfg = self.config
        n = int(getattr(cfg, "b12_threshold_n", 6))
        primary_window = float(getattr(cfg, "b12_window_sec", 1200.0))
        # Fallback ladder: 1x → 3x → 12x. 옛 데이터라도 vote 우선.
        windows_to_try = [primary_window, primary_window * 3, primary_window * 12]
        latest_by_market = {}
        actual_window_sec = primary_window
        try:
            from app.manager.trade_journal import journal
            # ★ [2026-06-05] dashboard freeze fix — 매 status 폴링/스캔마다 47MB 저널을
            #   raw open + 전 줄 json.loads 풀파싱하던 것을 인메모리 캐시(write-through) 순회로 교체.
            #   feedback_journal_cache_leak_fix(2026-05-15) 의 재발: b12 만 캐시를 우회하고 있었음.
            #   결과 동일 (BLOCKED/ENTRY 의 ts/market/direction 추출), 호출당 0.6~4.7초 → ~ms.
            journal._ensure_cache()
            if journal._cache:
                # 캐시 순회 — 모든 윈도우 동시 평가 (파일 I/O 없음). get_trades/get_markets 와 동일 패턴.
                all_records = []
                # ★ 대사면 필터 — amnesty_ts 이전 이벤트는 B12 투표에서 제외
                amnesty_cutoff = float(getattr(self, "_amnesty_ts", 0.0))
                for rec in journal._cache:
                    try:
                        ts = rec.get("ts", 0)
                        if ts < amnesty_cutoff:   # 사면 전 기록 무시
                            continue
                        evt = rec.get("event", "")
                        if evt not in ("BLOCKED", "ENTRY"):
                            continue
                        mkt = (rec.get("market", "") or "").upper()
                        d = (rec.get("direction", "") or "").upper()
                        if not mkt or d not in ("LONG", "SHORT"):
                            continue
                        all_records.append((ts, mkt, d))
                    except Exception:
                        continue
                # 최신 데이터부터 sliding window 적용 — 충분한 데이터 모일 때까지 윈도우 확장
                for window_sec in windows_to_try:
                    cutoff = time.time() - window_sec
                    candidates = {}
                    for ts, mkt, d in all_records:
                        if ts < cutoff:
                            continue
                        prev = candidates.get(mkt)
                        if not prev or ts > prev[1]:
                            candidates[mkt] = (d, ts)
                    if len(candidates) >= 2:  # 최소 2 markets — vote 가능
                        latest_by_market = candidates
                        actual_window_sec = window_sec
                        break
                # 최후: 모든 윈도우 부족이면 가장 큰 윈도우 데이터 사용 (있는 만큼)
                if not latest_by_market and all_records:
                    cutoff = time.time() - windows_to_try[-1]
                    for ts, mkt, d in all_records:
                        if ts < cutoff:
                            continue
                        prev = latest_by_market.get(mkt)
                        if not prev or ts > prev[1]:
                            latest_by_market[mkt] = (d, ts)
                    actual_window_sec = windows_to_try[-1]
        except Exception as exc:
            logger.debug("[B12] vote scan error: %s", exc)
        long_markets = [m for m, (d, _) in latest_by_market.items() if d == "LONG"]
        short_markets = [m for m, (d, _) in latest_by_market.items() if d == "SHORT"]
        long_count = len(long_markets)
        short_count = len(short_markets)
        total_active = long_count + short_count
        # ★ 2026-04-23 부모 v3: Net Consensus (반대 차감) — "박빙 NEUTRAL" 강화.
        #   기존: long >= N AND long > short → BULL  (6 vs 5 같은 박빙도 BULL — 위험)
        #   신규: long - short >= N           → BULL  (반대 의견 1개당 +1 더 요구)
        #   부모 직관: "반대되는 신호 수만큼 더 필요로 하면?"
        net_long = long_count - short_count       # +면 LONG 우세, -면 SHORT 우세
        if net_long >= n:
            verdict = "BREADTH_BULL"
        elif -net_long >= n:                       # = short - long >= n
            verdict = "BREADTH_BEAR"
        else:
            verdict = "NEUTRAL"
        return {
            "long_count": long_count,
            "short_count": short_count,
            "total_active": total_active,
            "net_long": net_long,                  # ★ 신규: UI 에 "Net +X" 표시
            "verdict": verdict,
            "window_sec": primary_window,
            "window_sec_used": actual_window_sec,
            "threshold_n": n,
            "markets_long": long_markets,
            "markets_short": short_markets,
        }

    def _check_market_breadth_lock(self, direction: str, market: str) -> tuple:
        """B12: 스캐너 합창 기반 방향 강제 (2026-04-23 부모 직접 요청).
        '11명 중 N명 이상 같은 방향 가리키면 그 방향만, 미충족이면 간섭 안 함'

        - LONG_count >= N AND > SHORT_count → BREADTH_BULL → SHORT 차단
        - SHORT_count >= N AND > LONG_count → BREADTH_BEAR → LONG 차단
        - 둘 다 N 미충족 → NEUTRAL → 간섭 안 함 (양방향 허용, "장벽 푸는 도구")
        - lock_market 우회 — B11 과 동일 정책

        Returns: (blocked: bool, reason: str)"""
        cfg = self.config
        # lock_market 우회
        lock_mkt = (getattr(cfg, "lock_market", "") or "").upper()
        if lock_mkt and market.upper() == lock_mkt:
            return (False, "")
        vote = self._get_b12_breadth_vote()
        n = vote["threshold_n"]
        verdict = vote["verdict"]
        long_c = vote["long_count"]
        short_c = vote["short_count"]
        total = vote["total_active"]
        if verdict == "BREADTH_BULL" and direction.upper() == "SHORT":
            return (True, f"market_breadth_lock: BREADTH_BULL (LONG {long_c}/{total} >= N={n}) → SHORT blocked")
        if verdict == "BREADTH_BEAR" and direction.upper() == "LONG":
            return (True, f"market_breadth_lock: BREADTH_BEAR (SHORT {short_c}/{total} >= N={n}) → LONG blocked")
        # NEUTRAL or 동의방향 — 간섭 안 함
        return (False, "")

    def _detect_imminent_flip(self, target_regime: str) -> str:
        """[2026-05-16 부모 통찰] freeze 윈도우 안에서도 한 발 앞선 진입 허용.

        3중 AND 신호:
          (a) BTC EMA20-50 gap < imminent_flip_ema_gap_pct (기존 _btc_ema_gap_pct 재사용)
          (b) H1 (+30M 옵션) EMA20-50 gap 좁아지는 추세 — lookback 봉 전보다 작아짐
          (c) ADX 상승 전환 — lookback 봉 전 대비 +imminent_flip_adx_rise_min 이상

        방향 = +DI > -DI → BULL_IMMINENT / -DI > +DI → BEAR_IMMINENT.
        Returns: "BULL_IMMINENT" | "BEAR_IMMINENT" | "NONE"
        """
        cfg = self.config
        if not getattr(cfg, "imminent_flip_enabled", False):
            return "NONE"
        try:
            # (a) BTC EMA gap (이미 _check_regime_direction_lock 에서 self._btc_ema_gap_pct 갱신됨)
            ema_gap = float(getattr(self, "_btc_ema_gap_pct", 999.0))
            gap_thr = float(getattr(cfg, "imminent_flip_ema_gap_pct", 0.3))
            if ema_gap >= gap_thr:
                return "NONE"

            # (b) H1 EMA gap 좁아짐 추세
            h1_candles = self._get_btc_regime_candles()
            ema_short_n = int(getattr(cfg, "btc_regime_ema_short", 20))
            ema_long_n = int(getattr(cfg, "btc_regime_ema_long", 50))
            lookback = max(1, int(getattr(cfg, "imminent_flip_gap_lookback", 3)))
            if not h1_candles or len(h1_candles) < ema_long_n + lookback + 2:
                return "NONE"
            h1_closes = [float(c[4]) for c in h1_candles]

            def _ema_at(closes, period, end_idx):
                sub = closes[:end_idx]
                if len(sub) < period:
                    return None
                k = 2.0 / (period + 1.0)
                v = sum(sub[:period]) / period
                for p in sub[period:]:
                    v = p * k + v * (1 - k)
                return v

            es_now = _ema_at(h1_closes, ema_short_n, len(h1_closes))
            el_now = _ema_at(h1_closes, ema_long_n, len(h1_closes))
            es_prev = _ema_at(h1_closes, ema_short_n, len(h1_closes) - lookback)
            el_prev = _ema_at(h1_closes, ema_long_n, len(h1_closes) - lookback)
            if any(x is None for x in (es_now, el_now, es_prev, el_prev)):
                return "NONE"
            gap_now_h1 = abs(es_now - el_now)
            gap_prev_h1 = abs(es_prev - el_prev)
            if gap_now_h1 >= gap_prev_h1:
                return "NONE"

            # 30M 보조 (옵션)
            if getattr(cfg, "imminent_flip_use_30m", True):
                try:
                    m30_raw = self._get_client().get_kline("BTCUSDT", interval="30", limit=ema_long_n + lookback + 5)
                    if m30_raw and len(m30_raw) >= ema_long_n + lookback + 2:
                        m30_closes = [float(c[4]) for c in m30_raw]
                        m_es_now = _ema_at(m30_closes, ema_short_n, len(m30_closes))
                        m_el_now = _ema_at(m30_closes, ema_long_n, len(m30_closes))
                        m_es_prev = _ema_at(m30_closes, ema_short_n, len(m30_closes) - lookback)
                        m_el_prev = _ema_at(m30_closes, ema_long_n, len(m30_closes) - lookback)
                        if all(x is not None for x in (m_es_now, m_el_now, m_es_prev, m_el_prev)):
                            if abs(m_es_now - m_el_now) >= abs(m_es_prev - m_el_prev):
                                return "NONE"
                        else:
                            return "NONE"
                    else:
                        return "NONE"
                except Exception as exc:
                    logger.debug("[FOCUS] imminent_flip 30M check failed: %s", exc)
                    return "NONE"

            # (c) ADX 상승 전환 + 방향 (DI 비교)
            try:
                from app.strategy.indicators import adx_series
            except Exception as exc:
                logger.debug("[FOCUS] imminent_flip adx_series import failed: %s", exc)
                return "NONE"
            h1_highs = [float(c[2]) for c in h1_candles]
            h1_lows = [float(c[3]) for c in h1_candles]
            adx_data = adx_series(h1_highs, h1_lows, h1_closes, 14)
            if not adx_data or len(adx_data) < lookback + 1:
                return "NONE"
            adx_now = float(adx_data[-1].get("adx", 0.0))
            adx_prev = float(adx_data[-1 - lookback].get("adx", 0.0))
            adx_rise_min = float(getattr(cfg, "imminent_flip_adx_rise_min", 2.0))
            if (adx_now - adx_prev) < adx_rise_min:
                return "NONE"

            plus_di = float(adx_data[-1].get("plus_di", 0.0))
            minus_di = float(adx_data[-1].get("minus_di", 0.0))
            if plus_di > minus_di:
                return "BULL_IMMINENT"
            if minus_di > plus_di:
                return "BEAR_IMMINENT"
            return "NONE"
        except Exception as exc:
            logger.debug("[FOCUS] _detect_imminent_flip error: %s", exc)
            return "NONE"

    def _check_same_coin_flip_cooldown(self, market: str, direction: str) -> tuple:
        """[2026-05-16 부모] 같은 코인 LONG↔SHORT 신규 진입 N분 cooldown.

        TAO 사례: 23:16 LONG -$10 → 47분 후 SHORT -$2.48 = 양방향 다 패.
        같은 코인 직전 EXIT 가 N분 안에 있고 방향 반대면 BLOCK.
        Returns: (blocked: bool, reason: str)
        """
        cfg = self.config
        if not getattr(cfg, "same_coin_flip_cooldown_enabled", True):
            return (False, "")
        cooldown_min = int(getattr(cfg, "same_coin_flip_cooldown_min", 60))
        if cooldown_min <= 0:
            return (False, "")
        try:
            from app.manager.trade_journal import JOURNAL_PATH
            if not os.path.exists(JOURNAL_PATH):
                return (False, "")
            mkt_upper = (market or "").upper()
            dir_upper = (direction or "").upper()
            cutoff_ts = time.time() - (cooldown_min * 60)
            # 가장 최근 EXIT 만 찾으면 충분 (역순)
            last_exit_dir = ""
            last_exit_ts = 0.0
            with open(JOURNAL_PATH, "r", encoding="utf-8") as f:
                lines = f.readlines()
            for line in reversed(lines[-500:]):  # 최근 500줄로 cap
                line = line.strip()
                if not line:
                    continue
                try:
                    rec = json.loads(line)
                except Exception:
                    continue
                if (rec.get("strategy") or "").upper() != "FOCUS":
                    continue
                if (rec.get("event") or "").upper() != "EXIT":
                    continue
                if (rec.get("market") or "").upper() != mkt_upper:
                    continue
                ts = float(rec.get("ts") or 0.0)
                if ts < cutoff_ts:
                    break  # 더 오래된 건 무시
                last_exit_dir = (rec.get("direction") or "").upper()
                last_exit_ts = ts
                break
            if not last_exit_dir or last_exit_ts <= 0:
                return (False, "")
            # 같은 방향이면 cooldown 무시 (re-entry 는 다른 가드가 처리)
            if last_exit_dir == dir_upper:
                return (False, "")
            elapsed_min = (time.time() - last_exit_ts) / 60.0
            remain_min = cooldown_min - elapsed_min
            return (True, f"same_coin_flip_cooldown: {last_exit_dir}→{dir_upper} {elapsed_min:.1f}m ago → wait {remain_min:.1f}m more")
        except Exception as exc:
            logger.debug("[FOCUS] _check_same_coin_flip_cooldown error: %s", exc)
            return (False, "")

    def _check_raw_body_guard(self, market: str, direction: str) -> tuple:
        """[2026-05-16 부모 통찰] 5m raw 봉 몸통 = "에너지" 가드.

        최근 N봉 (5m) 시가→종가 합산. net 방향이 진입 방향과 반대면 BLOCK.
        microtiming (RSI/MACD 가공값) 통과한 자리 중 raw price action 반대인 자리 잡음.

        BILL 사례: 5m 매수 에너지 살아있는데 SHORT 진입 → 즉시 +2% 반대 (peak -0.17%).
        Returns: (blocked: bool, reason: str)
        """
        cfg = self.config
        if not getattr(cfg, "raw_body_guard_enabled", True):
            return (False, "")
        lookback = max(1, int(getattr(cfg, "raw_body_guard_lookback", 3)))
        min_net_pct = float(getattr(cfg, "raw_body_guard_min_net_pct", 0.0))
        try:
            client = self._get_client()
            # 가장 최근 (lookback + 1) 봉 — 마지막 봉은 진행 중일 수 있으므로 직전 N봉 사용
            raw = client.get_kline(market, interval="5", limit=lookback + 1)
            if not raw or len(raw) < lookback + 1:
                return (False, "")
            # Bybit kline: [start, open, high, low, close, volume, turnover] (최신이 [0])
            # 직전 lookback 봉만 사용 (인덱스 1 ~ lookback)
            recent = raw[1:lookback + 1]
            net_sum = 0.0
            ref_price = float(recent[0][4]) if recent[0][4] else 0.0
            if ref_price <= 0:
                return (False, "")
            for bar in recent:
                open_p = float(bar[1])
                close_p = float(bar[4])
                net_sum += (close_p - open_p)
            net_pct = (net_sum / ref_price) * 100.0
            dir_upper = (direction or "").upper()
            # LONG 진입인데 net 매도(<0) / SHORT 진입인데 net 매수(>0) → BLOCK
            if dir_upper == "LONG" and net_pct < -abs(min_net_pct):
                return (True, f"raw_body_guard: {lookback}봉 net={net_pct:+.3f}% (매도) → LONG 차단")
            if dir_upper == "SHORT" and net_pct > abs(min_net_pct):
                return (True, f"raw_body_guard: {lookback}봉 net={net_pct:+.3f}% (매수) → SHORT 차단")
            return (False, "")
        except Exception as exc:
            logger.debug("[FOCUS] _check_raw_body_guard error: %s", exc)
            return (False, "")

    def _check_momentum_derivative_guard(self, market: str, direction: str) -> tuple:
        """[2026-05-16] Cache wrapper — 25s TTL per (market, direction). state_machine 중복 호출 방지."""
        cfg = self.config
        if not getattr(cfg, "momentum_deriv_guard_enabled", True):
            return (False, "")
        if not hasattr(self, '_guard_cache'):
            self._guard_cache = {}
        _key = ('mdg', (market or "").upper(), (direction or "").upper())
        _now = time.time()
        _cached = self._guard_cache.get(_key)
        if _cached and (_now - _cached[0]) < 25.0:
            return _cached[1]
        _result = self._check_momentum_derivative_guard_impl(market, direction)
        self._guard_cache[_key] = (_now, _result)
        return _result

    def _check_momentum_derivative_guard_impl(self, market: str, direction: str) -> tuple:
        """[2026-05-16 부모 비전] RSI/MACD 변화율 (1차 미분) 가드.

        "같은 RSI=50 이라도 올라오는 중 vs 꺾이는 중" 구분.
        최근 N봉 평균 vs 그 전 N봉 평균 비교 → 진입 방향과 반대 가속/감속 시 BLOCK.

        - LONG 진입인데 RSI 가 -min_slope 이상 하락 추세 → BLOCK
        - SHORT 진입인데 RSI 가 +min_slope 이상 상승 추세 → BLOCK
        - require_both=True 면 RSI+MACD 둘 다 반대여야 차단, False 면 둘 중 하나만 반대여도 차단

        Returns: (blocked: bool, reason: str)
        """
        cfg = self.config
        if not getattr(cfg, "momentum_deriv_guard_enabled", True):
            return (False, "")
        tf = str(getattr(cfg, "momentum_deriv_guard_tf", "5") or "5")
        lookback = max(2, int(getattr(cfg, "momentum_deriv_guard_lookback", 5)))
        rsi_slope_thr = float(getattr(cfg, "momentum_deriv_guard_rsi_min_slope", 2.0))
        macd_slope_thr = float(getattr(cfg, "momentum_deriv_guard_macd_min_slope", 0.0))
        require_both = bool(getattr(cfg, "momentum_deriv_guard_require_both", False))
        try:
            # 5m 봉 충분히 가져옴 (RSI 14 + lookback*2 봉 필요)
            need = 14 + lookback * 2 + 5
            raw = self._get_client().get_kline(market, interval=tf, limit=need)
            if not raw or len(raw) < need:
                return (False, "")
            # Bybit kline: [start, open, high, low, close, ...] (최신이 [0])
            closes = [float(c[4]) for c in raw]  # 오래된→최신 순으로

            try:
                from app.strategy.indicators import rsi_series, macd_hist_series
            except Exception as exc:
                logger.debug("[FOCUS] momentum_deriv import failed: %s", exc)
                return (False, "")

            rsi_vals = rsi_series(closes, 14)
            macd_hist = macd_hist_series(closes, 12, 26, 9)
            if not rsi_vals or len(rsi_vals) < lookback * 2:
                return (False, "")
            if not macd_hist or len(macd_hist) < lookback * 2:
                return (False, "")

            # 최근 N봉 평균 vs 그 전 N봉 평균
            rsi_recent = sum(rsi_vals[-lookback:]) / lookback
            rsi_prev = sum(rsi_vals[-2 * lookback:-lookback]) / lookback
            rsi_delta = rsi_recent - rsi_prev

            macd_recent = sum(macd_hist[-lookback:]) / lookback
            macd_prev = sum(macd_hist[-2 * lookback:-lookback]) / lookback
            macd_delta = macd_recent - macd_prev

            dir_upper = (direction or "").upper()

            # LONG: RSI 가 -rsi_slope_thr 이상 하락 또는 MACD hist 가 -macd_slope_thr 이상 하락 → 반대
            # SHORT: RSI 가 +rsi_slope_thr 이상 상승 또는 MACD hist 가 +macd_slope_thr 이상 상승 → 반대
            rsi_against = False
            macd_against = False
            if dir_upper == "LONG":
                rsi_against = rsi_delta < -abs(rsi_slope_thr)
                macd_against = macd_delta < -abs(macd_slope_thr)
            elif dir_upper == "SHORT":
                rsi_against = rsi_delta > abs(rsi_slope_thr)
                macd_against = macd_delta > abs(macd_slope_thr)
            else:
                return (False, "")

            if require_both:
                blocked = rsi_against and macd_against
            else:
                blocked = rsi_against or macd_against

            if blocked:
                reason = (f"momentum_deriv_guard: {dir_upper} 반대 흐름 "
                          f"(RSI Δ={rsi_delta:+.2f} {'AGAINST' if rsi_against else 'ok'}, "
                          f"MACD Δ={macd_delta:+.4f} {'AGAINST' if macd_against else 'ok'}, "
                          f"mode={'AND' if require_both else 'OR'})")
                return (True, reason)
            return (False, "")
        except Exception as exc:
            logger.debug("[FOCUS] _check_momentum_derivative_guard error: %s", exc)
            return (False, "")

    def _classify_coin_state(self, market: str, direction: str) -> tuple:
        """[2026-05-16 부모 비전 #4] 코인 진입 시점 상태 분류.

        분류 우선순위:
          1. CFID IMMINENT 방향 일치 → FLIP_IMMINENT (가장 강한 신호)
          2. momentum_deriv & mtf_align 둘 다 BLOCK → DECEL (가장 보수적)
          3. 둘 중 하나만 BLOCK → STEADY (애매)
          4. 둘 다 OK → ACCEL (정상)

        Returns: (state_label, conv_adjust)
          - state_label: "FLIP_IMMINENT" | "DECEL" | "STEADY" | "ACCEL" | ""
          - conv_adjust: dataclass 값 (단계별 conviction 보정)
        """
        cfg = self.config
        # ★ [2026-05-28 저녁 부모] yellow 마스터 토글 — green only 모드 시 skip (DECEL/STEADY 페널티 OFF)
        if not self._is_yellow_guard_active("entry"):
            return ("", 0)
        if not getattr(cfg, "coin_state_machine_enabled", True):
            return ("", 0)
        dir_upper = (direction or "").upper()
        if dir_upper not in ("LONG", "SHORT"):
            return ("", 0)
        try:
            # 1. CFID 먼저 (우선순위 최고)
            cfid_dir, _cfid_str = self._detect_coin_flip_imminent(market)
            if ((dir_upper == "LONG" and cfid_dir == "BULL_IMMINENT") or
                (dir_upper == "SHORT" and cfid_dir == "BEAR_IMMINENT")):
                return ("FLIP_IMMINENT", int(getattr(cfg, "coin_state_flip_imminent_conv_adj", 1)))

            # 2/3. momentum_deriv + mtf_align BLOCK 카운트
            md_blocked, _ = self._check_momentum_derivative_guard(market, direction)
            mtf_blocked, _ = self._check_mtf_momentum_alignment(market, direction)

            if md_blocked and mtf_blocked:
                return ("DECEL", int(getattr(cfg, "coin_state_decel_conv_adj", -2)))
            if md_blocked or mtf_blocked:
                return ("STEADY", int(getattr(cfg, "coin_state_steady_conv_adj", -1)))
            return ("ACCEL", int(getattr(cfg, "coin_state_accel_conv_adj", 0)))
        except Exception as exc:
            logger.debug("[FOCUS] _classify_coin_state error: %s", exc)
            return ("", 0)

    def _detect_coin_flip_imminent(self, market: str) -> tuple:
        """[2026-05-16] Cache wrapper — 25s TTL per market. CFID 는 60+30 TF fetch 라 무거움."""
        cfg = self.config
        if not getattr(cfg, "cfid_enabled", True):
            return ("NONE", 0.0)
        if not hasattr(self, '_guard_cache'):
            self._guard_cache = {}
        _key = ('cfid', (market or "").upper())
        _now = time.time()
        _cached = self._guard_cache.get(_key)
        if _cached and (_now - _cached[0]) < 25.0:
            return _cached[1]
        _result = self._detect_coin_flip_imminent_impl(market)
        self._guard_cache[_key] = (_now, _result)
        return _result

    def _detect_coin_flip_imminent_impl(self, market: str) -> tuple:
        """[2026-05-16 부모 비전 #3] 코인별 변곡점 임박 감지 (imminent_flip 일반화).

        3중 신호:
          (a) EMA20-50 gap / price * 100 < cfid_ema_gap_thr_pct  (좁아짐 → 교차 임박)
          (b) 최근 N봉 거래량 평균 vs 이전 N봉 → spike (cfid_volume_spike_ratio 이상)
          (c) ADX 변화율 절댓값 ≥ cfid_adx_change_min  (트렌드 변화 진행 중)
        3중 AND 충족 시 +DI > -DI 면 BULL_IMMINENT / 반대면 BEAR_IMMINENT.

        Returns: (direction_label, strength_score)
          - direction_label: "BULL_IMMINENT" | "BEAR_IMMINENT" | "NONE"
          - strength_score: 0.0 ~ 3.0 (충족 신호 강도 합, 진단/로그용)
        """
        cfg = self.config
        if not getattr(cfg, "cfid_enabled", True):
            return ("NONE", 0.0)
        tf = str(getattr(cfg, "cfid_tf", "60") or "60")
        ema_gap_thr = float(getattr(cfg, "cfid_ema_gap_thr_pct", 0.4))
        vol_spike_ratio = float(getattr(cfg, "cfid_volume_spike_ratio", 1.5))
        adx_change_min = float(getattr(cfg, "cfid_adx_change_min", 1.0))
        lookback = max(3, int(getattr(cfg, "cfid_lookback", 5)))
        try:
            client = self._get_client()
            need = 50 + lookback * 2 + 5  # EMA50 + ADX 14 + lookback*2
            raw = client.get_kline(market, interval=tf, limit=need)
            if not raw or len(raw) < need:
                return ("NONE", 0.0)
            # Bybit kline: [start, open, high, low, close, volume, ...] (최신이 [0])
            ordered = list(raw)  # 오래된→최신
            closes = [float(c[4]) for c in ordered]
            highs = [float(c[2]) for c in ordered]
            lows = [float(c[3]) for c in ordered]
            volumes = [float(c[5]) for c in ordered if len(c) > 5]
            if not volumes or len(volumes) < lookback * 2:
                return ("NONE", 0.0)

            # EMA20 / EMA50
            def _ema(prices, period):
                if len(prices) < period:
                    return None
                k = 2.0 / (period + 1.0)
                v = sum(prices[:period]) / period
                for p in prices[period:]:
                    v = p * k + v * (1 - k)
                return v
            ema_short = _ema(closes, 20)
            ema_long = _ema(closes, 50)
            if ema_short is None or ema_long is None:
                return ("NONE", 0.0)
            last_price = closes[-1]
            if last_price <= 0:
                return ("NONE", 0.0)
            ema_gap_pct = abs(ema_short - ema_long) / last_price * 100.0

            # (a) gap 좁음 체크
            gap_ok = ema_gap_pct < ema_gap_thr

            # (b) 거래량 spike
            vol_recent = sum(volumes[-lookback:]) / lookback
            vol_prev = sum(volumes[-2 * lookback:-lookback]) / lookback
            vol_ratio = (vol_recent / vol_prev) if vol_prev > 0 else 0.0
            vol_ok = vol_ratio >= vol_spike_ratio

            # (c) ADX 변화율 + DI 비교 (방향 결정)
            try:
                from app.strategy.indicators import adx_series
            except Exception:
                return ("NONE", 0.0)
            adx_data = adx_series(highs, lows, closes, 14)
            if not adx_data or len(adx_data) < lookback + 1:
                return ("NONE", 0.0)
            adx_now = float(adx_data[-1].get("adx", 0.0))
            adx_prev = float(adx_data[-1 - lookback].get("adx", 0.0))
            adx_change = adx_now - adx_prev
            adx_ok = abs(adx_change) >= adx_change_min

            plus_di = float(adx_data[-1].get("plus_di", 0.0))
            minus_di = float(adx_data[-1].get("minus_di", 0.0))

            strength = (1.0 if gap_ok else 0.0) + (1.0 if vol_ok else 0.0) + (1.0 if adx_ok else 0.0)

            if not (gap_ok and vol_ok and adx_ok):
                return ("NONE", strength)

            if plus_di > minus_di:
                return ("BULL_IMMINENT", strength)
            if minus_di > plus_di:
                return ("BEAR_IMMINENT", strength)
            return ("NONE", strength)
        except Exception as exc:
            logger.debug("[FOCUS] _detect_coin_flip_imminent error: %s", exc)
            return ("NONE", 0.0)

    def _check_mtf_momentum_alignment(self, market: str, direction: str) -> tuple:
        """[2026-05-16] Cache wrapper — 25s TTL. mtf_align 은 TF 3개 × API 호출이라 가장 무거움."""
        cfg = self.config
        if not getattr(cfg, "mtf_momentum_align_enabled", True):
            return (False, "")
        if not hasattr(self, '_guard_cache'):
            self._guard_cache = {}
        _key = ('mtf', (market or "").upper(), (direction or "").upper())
        _now = time.time()
        _cached = self._guard_cache.get(_key)
        if _cached and (_now - _cached[0]) < 25.0:
            return _cached[1]
        _result = self._check_mtf_momentum_alignment_impl(market, direction)
        self._guard_cache[_key] = (_now, _result)
        return _result

    def _check_mtf_momentum_alignment_impl(self, market: str, direction: str) -> tuple:
        """[2026-05-16 부모 비전 #2] Multi-TF 모멘텀 흐름 일관성 검증.

        H1/30M/5M 각 TF 에서 RSI Δ (옵션: MACD hist Δ) 측정.
        진입 방향과 가속 방향이 일치하는 TF 수가 임계 미만이면 BLOCK.
        - 1번 momentum_deriv 가 단일 TF (5m) 라면 이건 multi-TF 합의.
        - "TF 들이 서로 다른 말 한다" = 흐름 일관성 없음 = 위험.

        Returns: (blocked: bool, reason: str)
        """
        cfg = self.config
        if not getattr(cfg, "mtf_momentum_align_enabled", True):
            return (False, "")
        tfs_csv = str(getattr(cfg, "mtf_momentum_align_tfs", "60,30,5") or "60,30,5")
        tfs = [t.strip() for t in tfs_csv.split(",") if t.strip()]
        if not tfs:
            return (False, "")
        lookback = max(2, int(getattr(cfg, "mtf_momentum_align_lookback", 5)))
        min_aligned = int(getattr(cfg, "mtf_momentum_align_min_aligned", 2))
        use_macd = bool(getattr(cfg, "mtf_momentum_align_use_macd", True))
        rsi_thr = float(getattr(cfg, "mtf_momentum_align_rsi_slope_thr", 0.5))
        dir_upper = (direction or "").upper()
        if dir_upper not in ("LONG", "SHORT"):
            return (False, "")
        try:
            from app.strategy.indicators import rsi_series, macd_hist_series
        except Exception as exc:
            logger.debug("[FOCUS] mtf_momentum_align import failed: %s", exc)
            return (False, "")
        try:
            client = self._get_client()
            need = 14 + lookback * 2 + 5
            per_tf_results = []  # (tf, rsi_delta, macd_delta, aligned_bool)
            for tf in tfs:
                try:
                    raw = client.get_kline(market, interval=tf, limit=need)
                    if not raw or len(raw) < need:
                        per_tf_results.append((tf, None, None, None))
                        continue
                    closes = [float(c[4]) for c in raw]
                    rsi_vals = rsi_series(closes, 14)
                    if not rsi_vals or len(rsi_vals) < lookback * 2:
                        per_tf_results.append((tf, None, None, None))
                        continue
                    rsi_recent = sum(rsi_vals[-lookback:]) / lookback
                    rsi_prev = sum(rsi_vals[-2 * lookback:-lookback]) / lookback
                    rsi_delta = rsi_recent - rsi_prev

                    macd_delta = 0.0
                    if use_macd:
                        macd_hist = macd_hist_series(closes, 12, 26, 9)
                        if macd_hist and len(macd_hist) >= lookback * 2:
                            m_recent = sum(macd_hist[-lookback:]) / lookback
                            m_prev = sum(macd_hist[-2 * lookback:-lookback]) / lookback
                            macd_delta = m_recent - m_prev

                    # 가속 방향 일치 판정
                    rsi_aligned_for_dir = False
                    if dir_upper == "LONG":
                        rsi_aligned_for_dir = rsi_delta > rsi_thr
                    else:  # SHORT
                        rsi_aligned_for_dir = rsi_delta < -rsi_thr

                    macd_aligned_for_dir = True  # use_macd=False 면 기본 통과
                    if use_macd:
                        if dir_upper == "LONG":
                            macd_aligned_for_dir = macd_delta > 0
                        else:
                            macd_aligned_for_dir = macd_delta < 0

                    # RSI 와 MACD 둘 다 일치해야 그 TF 가 진짜 "정렬됨"
                    tf_aligned = rsi_aligned_for_dir and macd_aligned_for_dir
                    per_tf_results.append((tf, rsi_delta, macd_delta, tf_aligned))
                except Exception as exc:
                    logger.debug("[FOCUS] mtf_momentum_align tf=%s failed: %s", tf, exc)
                    per_tf_results.append((tf, None, None, None))
                    continue

            # 데이터 정상인 TF 만 카운트
            valid = [r for r in per_tf_results if r[3] is not None]
            if not valid:
                return (False, "")
            aligned_count = sum(1 for r in valid if r[3])
            if aligned_count < min_aligned:
                detail = " | ".join(
                    f"TF{r[0]}: RSIΔ={r[1]:+.2f}, MACDΔ={r[2]:+.4f} ({'OK' if r[3] else 'NO'})"
                    for r in valid
                )
                reason = f"mtf_momentum_align: {aligned_count}/{len(valid)} TF aligned < {min_aligned} [{detail}]"
                return (True, reason)
            return (False, "")
        except Exception as exc:
            logger.debug("[FOCUS] _check_mtf_momentum_alignment error: %s", exc)
            return (False, "")

    def _check_regime_direction_lock(self, direction: str, market: str) -> tuple:
        """B11: BTC H4 regime 기반 방향 강제 (2026-04-19 형 직접 지시).
        '상승장이면 LONG only, 하락장이면 SHORT only, 그 외엔 REST'
        + '레짐이 멈추거나 바뀔 기미가 보이면 올스톱'

        BTC H4 EMA20/EMA50 + slope 사용 (기존 btc_regime_* 설정 재활용).
        - clearly_above + slope_up → BULL → SHORT 차단
        - clearly_below + slope_dn → BEAR → LONG 차단
        - 그 외(거리 좁거나 slope 평탄) → NEUTRAL → 양방향 차단 (REST)
        - regime 변경 직후 freeze_sec 동안 양방향 차단 (whipsaw 방어)
        - lock_market(XAUTUSDT) 우회 — 금은 별 시장

        ★ 2026-04-23 부모 지시: regime_lock_mode dispatcher 추가
           - mode=="B11" : 기존 동작 (이 함수 본체)
           - mode=="B12" : _check_market_breadth_lock 위임
           - mode=="OFF" : 둘 다 해제 (즉시 통과)
        Returns: (blocked: bool, reason: str)"""
        cfg = self.config
        # ★ B11/B12/OFF dispatcher (2026-04-23 부모 직접 요청)
        mode = (getattr(cfg, "regime_lock_mode", "B11") or "B11").upper()
        if mode == "OFF":
            return (False, "")
        if mode == "B12":
            return self._check_market_breadth_lock(direction, market)
        # mode == "B11" (기본) — 아래 본체 실행
        if not getattr(cfg, "regime_direction_lock_enabled", True):
            return (False, "")
        # lock_market 우회
        lock_mkt = (getattr(cfg, "lock_market", "") or "").upper()
        if lock_mkt and market.upper() == lock_mkt:
            return (False, "")
        try:
            candles = self._get_btc_regime_candles()
            ema_long_n = int(getattr(cfg, "btc_regime_ema_long", 50))
            if not candles or len(candles) < ema_long_n + 3:
                return (True, f"regime_direction_lock: insufficient BTC regime data ({len(candles) if candles else 0} bars) → REST")
            closes = [float(c[4]) for c in candles]
            ema_short_n = int(getattr(cfg, "btc_regime_ema_short", 20))
            trans_band = float(getattr(cfg, "btc_regime_trans_band_pct", 1.0))
            slope_thr = float(getattr(cfg, "btc_regime_slope_flat_thr_pct", 0.3))
            freeze_sec = float(getattr(cfg, "regime_direction_lock_freeze_sec", 1800.0))
            neutral_block = bool(getattr(cfg, "regime_direction_lock_neutral_block", True))
            # 3축 토글 (꺼진 축은 해당 판정 무시 = "통과"로 취급)
            use_slope = bool(getattr(cfg, "regime_lock_use_slope", True))
            use_distance = bool(getattr(cfg, "regime_lock_use_distance", True))
            use_cross = bool(getattr(cfg, "regime_lock_use_cross", True))

            def _ema(prices, period):
                if len(prices) < period:
                    return None
                k = 2.0 / (period + 1.0)
                v = sum(prices[:period]) / period
                for p in prices[period:]:
                    v = p * k + v * (1 - k)
                return v

            ema_short = _ema(closes, ema_short_n)
            ema_long = _ema(closes, ema_long_n)
            ema_short_prev = _ema(closes[:-3], ema_short_n)
            if ema_short is None or ema_long is None or ema_short_prev is None:
                return (True, "regime_direction_lock: EMA calc failed → REST")
            last_close = closes[-1]
            dist_pct = (last_close - ema_long) / ema_long * 100.0 if ema_long > 0 else 0.0
            slope_pct = (ema_short - ema_short_prev) / ema_short_prev * 100.0 if ema_short_prev > 0 else 0.0

            # 축별 방향 판정 — 꺼진 축은 양쪽 True (통과)
            cross_bull = (ema_short > ema_long) if use_cross else True
            cross_bear = (ema_short < ema_long) if use_cross else True
            dist_bull = (dist_pct > trans_band) if use_distance else True
            dist_bear = (dist_pct < -trans_band) if use_distance else True
            slope_bull = (slope_pct > slope_thr) if use_slope else True
            slope_bear = (slope_pct < -slope_thr) if use_slope else True

            clearly_above = cross_bull and dist_bull and slope_bull
            clearly_below = cross_bear and dist_bear and slope_bear

            # 모든 축 OFF 시 양쪽 다 True — 가격 부호로 tiebreak
            if clearly_above and clearly_below:
                if dist_pct > 0 or ema_short > ema_long:
                    clearly_below = False
                elif dist_pct < 0 or ema_short < ema_long:
                    clearly_above = False
                else:
                    clearly_above = clearly_below = False

            if clearly_above:
                regime = "BULL"
            elif clearly_below:
                regime = "BEAR"
            else:
                regime = "NEUTRAL"

            # 어떤 축이 켜져 있었는지 로그에 표시
            axes_used = "+".join([a for a, on in [("cross", use_cross), ("dist", use_distance), ("slope", use_slope)] if on]) or "none"

            # ★ Phase K (2026-04-21): BTC EMA gap 저장 — detect_regime_transition 이 소비
            # gap = |EMA20-EMA50|/price*100. 0.3% 미만 = 전환 임박 선행 신호 (72% 적중 증명)
            if last_close > 0:
                self._btc_ema_gap_pct = abs(ema_short - ema_long) / last_close * 100.0
            else:
                self._btc_ema_gap_pct = 999.0
            # ★ BTC 전용 ADX 저장 (regime_reversal_pause 용, 2026-06-04 버그 수정)
            # _last_adx_value 는 마지막 스캔 코인 ADX — BTC 전용으로 분리
            try:
                from app.strategy.indicator_cache import compute_adx
                _btc_h4 = self._get_btc_regime_candles()
                if _btc_h4 and len(_btc_h4) >= 16:
                    _highs = [float(c[2]) for c in _btc_h4]
                    _lows  = [float(c[3]) for c in _btc_h4]
                    _cls   = [float(c[4]) for c in _btc_h4]
                    _adx_r = compute_adx(_highs, _lows, _cls, period=14)
                    if _adx_r:
                        self._btc_adx_value = float(_adx_r.get("adx", 0))
            except Exception:
                pass

            now = time.time()
            prev_regime, _prev_change_ts = getattr(self, "_b11_regime_state", ("", 0.0))
            if regime != prev_regime:
                if prev_regime:
                    # 실제 regime 전환 → freeze 30분 타이머 개시
                    self._b11_regime_state = (regime, now)
                    logger.info("[FOCUS] 🔄 BTC Regime change: %s → %s (dist=%.2f%%, slope=%.2f%%)",
                                prev_regime, regime, dist_pct, slope_pct)
                else:
                    # 재시작 직후 첫 관측 — freeze 즉시 만료 (가짜 "→NEUTRAL 변경" 방지)
                    self._b11_regime_state = (regime, now - freeze_sec)
                # ★ Phase D-2 (2026-04-20): 영구 저장 — 다음 재시작 시 복원 (whipsaw 창 닫음)
                # ★ Phase H (형 letter#3 A-6): silent 실패 시 재시작 whipsaw 재발 → AAVE 07:05 같은 사건
                try:
                    from app.core.io_utils import safe_write_json
                    safe_write_json(B11_STATE_PATH, {"regime": regime, "change_ts": self._b11_regime_state[1]})
                    if getattr(self, "_b11_save_fail_count", 0) > 0:
                        logger.info("[FOCUS] B11 state save recovered after %d failures", self._b11_save_fail_count)
                        self._b11_save_fail_count = 0
                except Exception as exc:
                    self._b11_save_fail_count = getattr(self, "_b11_save_fail_count", 0) + 1
                    logger.warning("[FOCUS] B11 state save failed (%d consecutive): %s", self._b11_save_fail_count, exc, exc_info=True)
                    if self._b11_save_fail_count >= 3:
                        logger.error("[FOCUS] ⚠ B11 state save %d consecutive failures — 재시작 시 whipsaw 위험 (AAVE 07:05 사건 계열)", self._b11_save_fail_count)
            last_change_ts = self._b11_regime_state[1]
            elapsed = now - last_change_ts
            # 기미 감지: regime 변경 후 freeze 윈도우면 무조건 양방향 차단
            if prev_regime and elapsed < freeze_sec:
                remain = freeze_sec - elapsed
                # ★ [2026-05-16 부모] imminent flip 감지 시 freeze 해제 — "한 발 앞선 진입"
                imminent = self._detect_imminent_flip(regime)
                aligned = (
                    (regime == "BULL" and imminent == "BULL_IMMINENT") or
                    (regime == "BEAR" and imminent == "BEAR_IMMINENT")
                )
                if aligned:
                    logger.info("[FOCUS] 🚀 imminent flip aligned (%s, regime=%s, gap=%.3f%%) → freeze lifted (%.1fm/%.1fm) [axes=%s]",
                                imminent, regime, float(getattr(self, "_btc_ema_gap_pct", 0.0)),
                                elapsed/60, freeze_sec/60, axes_used)
                    # freeze 통과 — 아래 BULL/BEAR/NEUTRAL 분기로 진행 (return 안 함)
                else:
                    if imminent != "NONE":
                        logger.info("[FOCUS] imminent flip detected (%s) but regime=%s mismatch → freeze maintained", imminent, regime)
                    return (True, f"regime_direction_lock: regime change ({prev_regime}→{regime}) {elapsed/60:.1f}m ago → freeze {remain/60:.1f}m more (ALL STOP) [axes={axes_used}]")
            # NEUTRAL → 양방향 차단
            if regime == "NEUTRAL" and neutral_block:
                return (True, f"regime_direction_lock: REGIME=NEUTRAL (dist={dist_pct:.2f}%, slope={slope_pct:.2f}%, axes={axes_used}) → REST (both dir blocked)")
            # BULL → SHORT 차단
            if regime == "BULL" and direction.upper() == "SHORT":
                return (True, f"regime_direction_lock: REGIME=BULL → SHORT blocked (dist={dist_pct:.2f}%, slope={slope_pct:.2f}%, axes={axes_used})")
            # BEAR → LONG 차단
            if regime == "BEAR" and direction.upper() == "LONG":
                return (True, f"regime_direction_lock: REGIME=BEAR → LONG blocked (dist={dist_pct:.2f}%, slope={slope_pct:.2f}%, axes={axes_used})")
            return (False, "")
        except Exception as exc:
            logger.warning("[FOCUS] regime_direction_lock error: %s", exc)
            # 오류 시 보수적: 차단
            return (True, f"regime_direction_lock: error → REST ({exc})")

    def _compute_reentry_penalty(self, market: str, direction: str) -> float:
        """[2026-05-17 100점 ×10] B6: 같은 market+direction 최근 N분 재진입 ENTRY 카운트 × -penalty.
        Returns: penalty (<=0, float)"""
        cfg = self.config
        if not getattr(cfg, "coin_reentry_penalty_enabled", True):
            return 0.0
        try:
            from app.manager.trade_journal import JOURNAL_PATH
            if not os.path.exists(JOURNAL_PATH):
                return 0.0
            window = getattr(cfg, "coin_reentry_penalty_window_sec", 900.0)
            per_count = float(getattr(cfg, "coin_reentry_penalty_per_count", 10.0))  # [100점 ×10]
            mkt_upper = market.upper()
            dir_upper = direction.upper()
            now = time.time()
            cutoff = now - window
            entry_count = 0
            with open(JOURNAL_PATH, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        rec = json.loads(line)
                        if rec.get("event") != "ENTRY":
                            continue
                        ts = rec.get("ts", 0)
                        if ts < cutoff:
                            continue
                        if rec.get("market", "").upper() != mkt_upper:
                            continue
                        if rec.get("direction", "").upper() != dir_upper:
                            continue
                        entry_count += 1
                    except (json.JSONDecodeError, KeyError, ValueError):
                        continue
            if entry_count > 0:
                return -float(per_count * entry_count)  # [100점 ×10] float 반환
            return 0.0
        except Exception as exc:
            logger.warning("[FOCUS] reentry_penalty error: %s", exc)
            return 0.0

    def _get_coin_loss_total(self, market: str, direction: str = "") -> float:
        """24시간 내 해당 코인의 누적 실현 손실 합계 (음수).
        수익은 상쇄하지 않음 — 독약 코인은 승률 높아도 1건이 모든 수익 삼킴.
        [2026-04-18] direction 지정 시 해당 방향만 누적 — LONG 손실이 SHORT까지 차단하던 거 해제"""
        try:
            from app.manager.trade_journal import JOURNAL_PATH
            window_sec = self.config.coin_loss_cap_window_hours * 3600
            cutoff = time.time() - window_sec
            mkt_upper = market.upper()
            dir_upper = direction.upper() if direction else ""
            total_loss = 0.0
            if not os.path.exists(JOURNAL_PATH):
                return 0.0
            with open(JOURNAL_PATH, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        rec = json.loads(line)
                        ts = rec.get("ts", 0)
                        if ts < cutoff:
                            continue
                        if (rec.get("market", "").upper() == mkt_upper
                                and rec.get("event") == "EXIT"
                                and rec.get("strategy") == "FOCUS"):
                            # [2026-04-18] 방향 필터 — 같은 코인 LONG 손실이 SHORT 진입까지 막던 거 분리
                            if dir_upper and rec.get("direction", "").upper() != dir_upper:
                                continue
                            pnl = rec.get("pnl_net", 0)
                            if pnl < 0:
                                total_loss += pnl  # 음수 누적
                    except (json.JSONDecodeError, KeyError):
                        continue
            return total_loss
        except Exception as exc:
            logger.warning("[FOCUS] coin_loss_total error: %s", exc)
            return 0.0

    # ── Pair Group Helpers (2026-04-19) ──────────────────────────────
    def _get_pair_group(self, market: str) -> str:
        """코인이 속한 그룹 이름 리턴. 없으면 "" (고립 코인)."""
        mkt_upper = market.upper()
        for group_name, coins in self.PAIR_GROUPS.items():
            if mkt_upper in coins:
                return group_name
        return ""

    def _check_pair_block(self, market: str, direction: str) -> tuple:
        """짝 그룹 기반 진입 차단 체크.
        Returns (blocked: bool, reason: str).
        - aggressive: 같은 방향 그룹 내 N개까지 허용, 반대는 차단
        - conservative: 그룹 내 어느 방향이든 1개만 (어느 포지션 있으면 차단)
        """
        if not self.config.pair_block_enabled:
            return (False, "")
        group = self._get_pair_group(market)
        if not group:
            return (False, "")  # 고립 코인은 체크 안 함
        group_coins = set(c.upper() for c in self.PAIR_GROUPS[group])
        same_dir_count = 0
        for pos in self.positions:  # [2026-05-30 fix] self.state(FocusState enum).positions = AttributeError → self.positions
            if pos.market.upper() not in group_coins:
                continue
            if pos.market.upper() == market.upper():
                continue  # 같은 코인은 재진입 게이트(다른 곳)에서 처리
            if pos.direction != direction:
                # 반대 방향 포지션 존재 → 공통 차단
                return (True, f"pair_opposite:{group}:{pos.market}_{pos.direction}")
            else:
                same_dir_count += 1
        # 여기 왔으면 반대 방향 포지션은 없음
        if self.config.pair_block_mode == "conservative" and same_dir_count > 0:
            return (True, f"pair_conservative:{group}:same_dir_{same_dir_count}")
        if self.config.pair_block_mode == "aggressive" and same_dir_count >= self.config.pair_block_same_limit:
            return (True, f"pair_aggressive_limit:{group}:{same_dir_count}/{self.config.pair_block_same_limit}")
        return (False, "")

    # ── Coin Profit Lock-in Helpers (2026-04-19) ─────────────────────
    def _get_coin_realized_pnl_window(self, market: str, hours: float) -> float:
        """N시간 내 해당 코인의 실현 PnL 합 (수익+손실, 수수료 차감 후 net)."""
        try:
            from app.manager.trade_journal import JOURNAL_PATH
            window_sec = hours * 3600
            cutoff = time.time() - window_sec
            mkt_upper = market.upper()
            total = 0.0
            if not os.path.exists(JOURNAL_PATH):
                return 0.0
            with open(JOURNAL_PATH, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        rec = json.loads(line)
                        ts = rec.get("ts", 0)
                        if ts < cutoff:
                            continue
                        if (rec.get("market", "").upper() == mkt_upper
                                and rec.get("event") == "EXIT"
                                and rec.get("strategy") == "FOCUS"):
                            total += rec.get("pnl_net", 0)
                    except (json.JSONDecodeError, KeyError):
                        continue
            return total
        except Exception as exc:
            logger.warning("[FOCUS] coin_realized_pnl_window error: %s", exc)
            return 0.0

    def _check_profit_lockin(self, pos, current_unrealized_usd: float) -> tuple:
        """코인 단위 누적 수익 보호. Returns (trigger: bool, info: dict).
        로직:
          realized_N = 최근 N시간 해당 코인 실현 PnL 합
          total = realized_N + current_unrealized
          threshold = realized_N × protect_ratio
          realized_N 이 min_realized 미만이면 건너뜀 (의미 없는 작은 수익 보호 배제)
          total < threshold 이면 TRIGGER → 청산 권고
        """
        info = {"realized_n": 0.0, "unrealized": current_unrealized_usd, "total": 0.0, "threshold": 0.0}
        if not self.config.coin_profit_lockin_enabled:
            return (False, info)
        # H4 전략 충돌 방지: BE 락 이후에만 활성화
        if self.config.coin_profit_lockin_require_be and not pos.breakeven_locked:
            return (False, info)
        realized_n = self._get_coin_realized_pnl_window(
            pos.market, self.config.coin_profit_lockin_window_hours)
        info["realized_n"] = realized_n
        # 실현 수익이 최소 임계 미만이면 적용 안 함
        if realized_n < self.config.coin_profit_lockin_min_realized:
            return (False, info)
        total = realized_n + current_unrealized_usd
        threshold = realized_n * self.config.coin_profit_lockin_protect_ratio
        info["total"] = total
        info["threshold"] = threshold
        if total < threshold:
            return (True, info)
        return (False, info)

    # ── Direction Block (runtime 파일 기반 coin×direction 잠금) ─────────
    #   focus_config.json을 봇 실행 중 수정하면 경쟁 조건 위험이 있어
    #   (memory: 2026-04-11) 별도 파일 runtime/direction_blocks.json으로 분리.
    #   데이터-구동 차단 용도: "이 코인의 이 방향만 일정 시간 차단".
    #   스키마:
    #     { "ETHUSDT": { "LONG": { "until_ts": 1234567890.0, "reason": "..." } } }
    #   until_ts == 0 이면 영구 (수동 해제 전까지).
    DIRECTION_BLOCK_PATH = os.path.join("runtime", "direction_blocks.json")

    # ── Pair Groups (2026-04-19) ─────────────────────────────────────
    # 상관관계 0.85+ 추정. 같은 그룹에서 반대 방향 포지션 = 수수료만 손해.
    # aggressive 모드: 같은 방향 N개까지 OK, 반대만 차단
    # conservative 모드: 그룹당 1개만 (어느 방향이든)
    # 반대 차단은 두 모드 공통.
    PAIR_GROUPS = {
        "L1_ALT":   ["ETHUSDT", "SOLUSDT", "SUIUSDT", "APTUSDT", "AVAXUSDT", "NEARUSDT"],
        "L2":       ["ARBUSDT", "OPUSDT", "STRKUSDT"],
        "DEFI":     ["UNIUSDT", "AAVEUSDT", "LDOUSDT", "MKRUSDT", "COMPUSDT"],
        "AI":       ["WLDUSDT", "TAOUSDT", "FETUSDT", "OCEANUSDT"],
        "MEME":     ["DOGEUSDT", "SHIBUSDT", "PEPEUSDT", "WIFUSDT", "BONKUSDT", "FLOKIUSDT"],
        "ORACLE":   ["LINKUSDT", "BANDUSDT", "PYTHUSDT"],
        "GAMING":   ["AXSUSDT", "SANDUSDT", "MANAUSDT", "IMXUSDT"],
        "BTC_CORR": ["BTCUSDT", "ETHUSDT"],  # BTC-ETH 최대 베타
    }

    # ── H4 Context Filter (상위 타임프레임 맥락 확인) ──────────
    # [2026-04-18 저녁] user 지적: "ETH H4 5봉 하락 뒤 구름 중간 걸친 상태에서 LONG 잡지 마라.
    #   조금 길게 보면 답이 나온다." M5만 봐선 미끄럼틀 맥락을 놓친다.
    #   조건:
    #     LONG: H4 최근 5봉 중 4봉 이상 음봉 → BLOCK
    #     LONG: H4 최근 5봉 누적 낙폭 -3% 초과 → BLOCK
    #     SHORT: 반대 (양봉 4개+ / +3% 초과)
    #   이건 방향 신호(BUY/SELL)가 뭐든 **타이밍**이 아직 아니라는 뜻.
    #   SW_BB 면제 없음 — H4 강하락 중 mean reversion LONG은 추가 매맞기.
    def _primary_context_filter(self, market: str, direction: str) -> tuple:
        """[2026-05-15 H1 전환] primary_tf(H1) 5봉 맥락 확인. Returns (pass=True/False, reason)."""
        try:
            raw = self._get_client().get_kline(market, interval=self.config.primary_tf, limit=6)
        except Exception as exc:
            logger.debug("[FOCUS] primary_context: fetch fail → PASS: %s", exc)
            return (True, "")
        if not raw or len(raw) < 5:
            return (True, "")

        from app.strategy.greenpen.pa_detector import OHLCV
        candles = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4]))
                   for r in raw if len(r) >= 5]
        if len(candles) < 5:
            return (True, "")

        last5 = candles[-5:]
        first_open = last5[0].open
        last_close = last5[-1].close
        net_pct = (last_close - first_open) / first_open * 100 if first_open > 0 else 0

        if direction == "LONG":
            declining = sum(1 for c in last5 if c.close < c.open)
            if declining >= 4:
                return (False, f"primary_5bar_bear:{declining}of5_red")
            if net_pct <= -3.0:
                return (False, f"primary_5bar_netdown:{net_pct:.1f}%")
        else:  # SHORT
            rising = sum(1 for c in last5 if c.close > c.open)
            if rising >= 4:
                return (False, f"primary_5bar_bull:{rising}of5_green")
            if net_pct >= 3.0:
                return (False, f"primary_5bar_netup:{net_pct:.1f}%")

        return (True, "")

    # ── Anti-Falling-Knife (바닥 확인 필터) ───────────────────
    # [2026-04-18 저녁] user 지적: "미끄럼틀 하단에서 장꼬리 캔들 하나 보고 LONG 잡는다"
    #   4/13-14에 수익 났을 때는 이런 위치 진입이 없었다 → 최근 도입된 로직(SIDEWAYS BB
    #   mean reversion, Entry Quality 해제 등)이 "떨어지는 칼 잡기"를 허용하고 있음.
    #   3조건 중 하나라도 걸리면 진입 차단:
    #     (1) 현재 M5 봉이 최근 5봉 중 신저가/신고가  — 아직 미끄럼틀 진행 중
    #     (2) 최근 3봉 모두 역방향 (LONG인데 3연속 음봉, SHORT인데 3연속 양봉) — 추락/급등 중
    #     (3) 최근 3봉 종가가 단조감소/단조증가 — 계단식 하락/상승
    #   모든 진입 경로 (Primary + Scanner + SW_BB) 공통 적용. M5 1회 API 호출.
    def _anti_falling_knife_check(self, market: str, direction: str) -> tuple:
        """바닥(천장) 확인 필터. Returns (pass=True/False, reason).
        실패 시 reason 문자열로 어떤 조건이 걸렸는지 리턴.
        """
        try:
            raw = self._get_client().get_kline(market, interval=self.config.entry_tf, limit=10)
        except Exception as exc:
            logger.debug("[FOCUS] anti_knife: kline fetch fail → PASS: %s", exc)
            return (True, "")
        if not raw or len(raw) < 5:
            return (True, "")

        from app.strategy.greenpen.pa_detector import OHLCV
        candles = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4]))
                   for r in raw if len(r) >= 5]
        if len(candles) < 5:
            return (True, "")

        last = candles[-1]

        if direction == "LONG":
            # 조건 1: 최근 5봉 중 현재봉이 최저가 → 신저가 = 아직 떨어지는 중
            lows5 = [c.low for c in candles[-5:]]
            if last.low <= min(lows5):
                return (False, f"new_low_5bar:{last.low:.6f}")
            # 조건 2: 최근 3봉 전부 음봉 → 추락 중
            last3 = candles[-3:]
            reds = sum(1 for c in last3 if c.close < c.open)
            if reds >= 3:
                return (False, "3red_falling")
            # 조건 3: 3봉 종가 단조감소 → 계단식 하락
            c1, c2, c3 = [c.close for c in last3]
            if c1 > c2 > c3:
                return (False, f"monotonic_down:{c1:.6f}>{c2:.6f}>{c3:.6f}")
        else:  # SHORT
            highs5 = [c.high for c in candles[-5:]]
            if last.high >= max(highs5):
                return (False, f"new_high_5bar:{last.high:.6f}")
            last3 = candles[-3:]
            greens = sum(1 for c in last3 if c.close > c.open)
            if greens >= 3:
                return (False, "3green_rising")
            c1, c2, c3 = [c.close for c in last3]
            if c1 < c2 < c3:
                return (False, f"monotonic_up:{c1:.6f}<{c2:.6f}<{c3:.6f}")

        return (True, "")

    # ── Entry Quality Filter ──────────────────────────────────
    def _entry_quality_check(self, market: str, direction: str, price: float) -> tuple:
        """M5 마이크로타이밍 3중 필터. (pass=True, fail=False+reason)
        [2026-04-18] user 요청 "24시간 돌아가게 다 풀자" — Entry Quality 완전 비활성화
        [2026-05-28 저녁 부모] yellow 마스터 토글 — green only 모드 시 skip
        """
        # green only 모드: Entry Quality 통째 OFF (yellow 가드 묶음)
        if not self._is_yellow_guard_active("entry"):
            return (True, "yellow_off")
        return (True, "disabled_per_user_20260418")
        if not self.config.entry_quality_enabled:
            return (True, "")
        # M5 캔들 1회 호출 (3필터 공유)
        try:
            raw = self._get_client().get_kline(market, interval=self.config.entry_tf, limit=30)
            if not raw or len(raw) < 5:
                return (True, "")
        except Exception as exc:
            logger.debug("[FOCUS] EntryQuality: M5 fetch fail — PASS: %s", exc)
            return (True, "")

        from app.strategy.greenpen.pa_detector import OHLCV
        candles = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4]))
                   for r in raw if len(r) >= 5]
        if len(candles) < 5:
            return (True, "")

        # ── (1) M5 모멘텀: 최근 N봉 중 K봉 이상 우리 방향 ──
        if self.config.eq_momentum_enabled:
            n = min(self.config.eq_momentum_count, len(candles))
            recent = candles[-n:]
            if direction == "LONG":
                agree = sum(1 for c in recent if c.close > c.open)
            else:
                agree = sum(1 for c in recent if c.close < c.open)
            if agree < self.config.eq_momentum_min_agree:
                reason = f"m5_momentum:{agree}/{n}_in_{direction}"
                return (False, reason)

        # ── (2) BB 위치: 상단/하단 극단 차단 ──
        if self.config.eq_bb_enabled:
            from app.strategy.indicators import bollinger_bands
            closes = [c.close for c in candles]
            bb = bollinger_bands(closes, 20, 2.0)
            if bb and bb["upper"] > bb["lower"]:
                bb_pct = (price - bb["lower"]) / (bb["upper"] - bb["lower"]) * 100
                if direction == "LONG" and bb_pct > self.config.eq_bb_upper_pct:
                    reason = f"bb_position:LONG@{bb_pct:.0f}%>limit{self.config.eq_bb_upper_pct:.0f}%"
                    return (False, reason)
                if direction == "SHORT" and bb_pct < self.config.eq_bb_lower_pct:
                    reason = f"bb_position:SHORT@{bb_pct:.0f}%<limit{self.config.eq_bb_lower_pct:.0f}%"
                    return (False, reason)

        # ── (3) N봉 추세: 직전 N봉 HH/HL 과반수 + 순방향 ──
        if self.config.eq_nbar_enabled:
            n = min(self.config.eq_nbar_count, len(candles))
            if n >= 3:
                bars = candles[-n:]
                pairs = n - 1
                if direction == "LONG":
                    hh = sum(1 for i in range(1, n) if bars[i].high > bars[i-1].high)
                    net = bars[-1].close - bars[0].open
                    if hh / pairs < self.config.eq_nbar_min_ratio or net <= 0:
                        reason = f"nbar_trend:LONG_HH={hh}/{pairs}_net={net:.4f}"
                        return (False, reason)
                else:
                    lh = sum(1 for i in range(1, n) if bars[i].high < bars[i-1].high)
                    net = bars[-1].close - bars[0].open
                    if lh / pairs < self.config.eq_nbar_min_ratio or net >= 0:
                        reason = f"nbar_trend:SHORT_LH={lh}/{pairs}_net={net:.4f}"
                        return (False, reason)

        logger.debug("[FOCUS] EntryQuality PASS: %s %s @ %.4f", direction, market, price)
        return (True, "")

    def _is_direction_blocked(self, market: str, direction: str) -> tuple:
        """Returns (blocked: bool, reason: str).

        파일 없음/빈파일/파싱오류 → 차단 안 함 (안전 기본값).
        mtime 기반 TTL 캐시로 반복 호출 비용 최소화.
        """
        try:
            path = self.DIRECTION_BLOCK_PATH
            if not os.path.exists(path):
                return False, ""
            mtime = os.path.getmtime(path)
            cache = getattr(self, "_dir_block_cache", None)
            if cache is None or cache[0] != mtime:
                with open(path, "r", encoding="utf-8") as f:
                    data = json.load(f) or {}
                self._dir_block_cache = (mtime, data)
            else:
                data = cache[1]

            entry = (data.get(market.upper(), {}) or {}).get(direction.upper())
            if not entry:
                return False, ""
            until_ts = float(entry.get("until_ts", 0) or 0)
            # until_ts == 0 → 영구; > 0 이면 만료 체크
            if until_ts > 0 and time.time() >= until_ts:
                return False, ""
            reason = str(entry.get("reason", "no reason"))
            return True, reason
        except Exception as exc:
            logger.debug("[FOCUS] direction_block check failed: %s", exc)
            return False, ""

    # ─────────────────────────────────────────────────────────────────
    # ★★★ [2026-05-18 부모 비전 #5] Leading Entry — 선행 진입 헬퍼 2개
    # 부모님: "1분이라도 선행 진입. 이미 움직일 방향으로 미리 들어가는 것"
    # mutually exclusive — 한 번에 한 모드만 (config.leading_entry_mode)
    # ─────────────────────────────────────────────────────────────────

    def _check_cfid_leading_entry(self, market: str, direction: str) -> tuple:
        """[Leading CFID] CFID 변곡점 임박 시 선행 진입 후보 검증.

        Returns: (eligible: bool, reason: str)
          - mode != CFID → False
          - cfid_dir == direction (BULL=LONG/BEAR=SHORT) AND strength >= 임계 → True
        """
        cfg = self.config
        if (getattr(cfg, "leading_entry_mode", "OFF") or "OFF").upper() != "CFID":
            return False, "mode_not_CFID"
        if not getattr(cfg, "cfid_enabled", True):
            return False, "cfid_disabled"
        try:
            cfid_dir, cfid_strength = self._detect_coin_flip_imminent(market)
        except Exception as exc:
            return False, f"cfid_err:{exc.__class__.__name__}"
        if cfid_dir == "NONE":
            return False, "no_cfid_signal"
        expected_dir = "LONG" if cfid_dir == "BULL_IMMINENT" else "SHORT"
        if (direction or "").upper() != expected_dir:
            return False, f"dir_mismatch({cfid_dir} vs {direction})"
        min_strength = float(getattr(cfg, "cfid_leading_min_strength", 70.0))
        if cfid_strength < min_strength:
            return False, f"strength_low({cfid_strength:.0f}<{min_strength:.0f})"
        return True, f"CFID_LEAD({cfid_dir},s={cfid_strength:.0f})"

    def _check_pattern_leading_entry(self, market: str, direction: str,
                                       candles_primary: list,
                                       zones: Optional[Tuple[float, float]] = None) -> tuple:
        """[Leading PATTERN] 5step retest + sr proximity + mtf align 패턴 검증.

        부모님 SOL test 자리 (지지선 가까이 + UPTREND 강함) 자동 인식.
        Returns: (eligible: bool, reason: str)
        """
        cfg = self.config
        if (getattr(cfg, "leading_entry_mode", "OFF") or "OFF").upper() != "PATTERN":
            return False, "mode_not_PATTERN"
        # 1) 5step 점수 (entry_tf M5 자동 fetch)
        try:
            from app.strategy.greenpen.pa_5step import _pa_5step_score_impl
            entry_tf = getattr(cfg, "entry_tf", "5")
            raw = self._get_mtf_kline(market, entry_tf, limit=30)
            if not raw or len(raw) < 8:
                return False, "no_5m_candles"
            candles_5m = []
            for k in raw:
                if isinstance(k, (list, tuple)) and len(k) >= 6:
                    candles_5m.append({
                        'o': float(k[1]), 'h': float(k[2]), 'l': float(k[3]),
                        'c': float(k[4]), 'v': float(k[5]),
                    })
            if len(candles_5m) < 8:
                return False, "5m_parse_short"
            score_5s, label_5s = _pa_5step_score_impl(direction, candles_5m, zones)
            min_5s = int(getattr(cfg, "pattern_leading_min_5step_score", 6))
            if score_5s < min_5s:
                return False, f"5step_low({score_5s}<{min_5s})"
        except Exception as exc:
            return False, f"5step_err:{exc.__class__.__name__}"
        # 2) sr proximity (지지/저항 가까이)
        if not zones or len(zones) < 2:
            return False, "no_zones"
        try:
            support, resistance = float(zones[0]), float(zones[1])
        except Exception:
            return False, "zones_invalid"
        if not candles_primary:
            return False, "no_candles"
        try:
            last_c = candles_primary[-1]
            if hasattr(last_c, 'close'):
                last_price = float(last_c.close)
            elif isinstance(last_c, (list, tuple)) and len(last_c) >= 4:
                last_price = float(last_c[3])
            else:
                return False, "price_extract_fail"
        except Exception:
            return False, "price_err"
        if last_price <= 0:
            return False, "no_price"
        max_sr_pct = float(getattr(cfg, "pattern_leading_max_sr_pct", 1.0))
        dir_up = (direction or "").upper()
        if dir_up == "LONG":
            sr_dist_pct = abs(last_price - support) / last_price * 100
        elif dir_up == "SHORT":
            sr_dist_pct = abs(resistance - last_price) / last_price * 100
        else:
            return False, "no_dir"
        if sr_dist_pct > max_sr_pct:
            return False, f"sr_far({sr_dist_pct:.2f}%>{max_sr_pct:.1f}%)"
        # 3) mtf_align 정렬 (1 TF = align +1 = +4점, 임계 = min_aligned × 4)
        try:
            mtf_score, mtf_label = self._compute_mtf_alignment_matrix(market, direction, candles_primary)
        except Exception as exc:
            return False, f"mtf_err:{exc.__class__.__name__}"
        min_align = int(getattr(cfg, "pattern_leading_min_mtf_align", 2))
        if mtf_score < (min_align * 4):
            return False, f"mtf_low({mtf_score}<{min_align*4})"
        return True, f"PATTERN_LEAD(5s={score_5s},sr={sr_dist_pct:.2f}%,mtf={mtf_score})"

    def detect_regime_transition(
        self,
        market: str,
        scanner_direction: str,
        conviction: int,
        adx_now: float,
        adx_past: float,
        candles_primary: list,
    ) -> tuple:
        """Phase K — 레짐 전환 선점 진입 감지.

        Returns: (allow_flip: bool, opposite_direction: str, reason: str)

        7대 AND 조건:
          1. ADX 하락: adx_now < adx_past * decline_ratio (default 5%)
          2. BTC EMA gap < threshold (default 0.3%)  — 동생 증명: 72% 적중
          3. PA 패턴 존재 + 반전형 (PIN/ENGULFING/BOS)
          4. PA 방향 ≠ scanner 방향
          5. conviction >= regime_transition_min_conviction (default 8)
          6. MTF 3개 정렬 (scanner 가 이미 H4/H1 체크 — 여기선 PA 존재로 근사)
          7. last_regime_change_age > 3h (연속 flip 방지)

        J v2 와 동시 ON 금지 — 여긴 호출자가 보장.
        """
        if not getattr(self.config, "regime_transition_enabled", False):
            return False, "", "disabled"

        # 조건 1: ADX 하락
        decline_ratio = float(getattr(self.config, "regime_transition_adx_decline_ratio", 0.95))
        if adx_past <= 0:
            return False, "", "no_adx_past"
        if adx_now >= adx_past * decline_ratio:
            return False, "", f"adx_not_declining: now={adx_now:.1f} past={adx_past:.1f} ratio={adx_now/adx_past:.3f}"

        # 조건 2: BTC EMA gap
        gap_thr = float(getattr(self.config, "regime_transition_ema_gap_threshold_pct", 0.3))
        btc_gap = getattr(self, "_btc_ema_gap_pct", None)
        if btc_gap is None:
            return False, "", "btc_gap_not_computed"
        if btc_gap >= gap_thr:
            return False, "", f"btc_gap_wide: {btc_gap:.3f}% >= {gap_thr}%"

        # 조건 3-4: PA 반전 패턴 + scanner 방향 불일치
        pa_dir = ""
        pa_name = ""
        try:
            if candles_primary and len(candles_primary) >= 15:
                from app.strategy.greenpen import full_analysis as _k_full
                _k_ana = _k_full(candles_primary)
                _k_pas = getattr(_k_ana, "pa_signals", []) or []
                if _k_pas:
                    best = _k_pas[0]
                    pa_name = getattr(best.pattern, "value", str(best.pattern)) if hasattr(best, "pattern") else ""
                    pa_dir = getattr(best.direction, "value", str(best.direction)) if hasattr(best, "direction") else ""
        except Exception as exc:
            logger.debug("[FOCUS] Phase K PA detect failed %s: %s", market, exc)
            return False, "", f"pa_detect_failed: {exc}"

        if not pa_dir or not pa_name:
            return False, "", "no_pa"

        _reversal_set = ("PIN_BAR", "ENGULFING", "BOS_BULLISH", "BOS_BEARISH", "STAR_V1")
        if pa_name not in _reversal_set:
            return False, "", f"pa_not_reversal: {pa_name}"

        if pa_dir.upper() == scanner_direction.upper():
            return False, "", f"pa_agrees_with_scanner: pa={pa_dir} scan={scanner_direction}"

        # 조건 5: conviction
        min_conv = float(getattr(self.config, "regime_transition_min_conviction", 80.0))  # [100점 ×10] 8→80
        if conviction < min_conv:
            return False, "", f"conv_too_low: {conviction:.1f}<{min_conv:.1f}"

        # 조건 7: last regime change age
        min_age_min = float(getattr(self.config, "regime_transition_last_change_age_min", 180.0))
        _b11_state = getattr(self, "_b11_regime_state", ("", 0.0))
        last_change_ts = _b11_state[1] if _b11_state and len(_b11_state) > 1 else 0.0
        age_min = (time.time() - last_change_ts) / 60.0 if last_change_ts > 0 else 9999.0
        if age_min < min_age_min:
            return False, "", f"regime_change_too_recent: {age_min:.0f}min<{min_age_min:.0f}min"

        reason = (f"regime_transition: adx_decl={adx_now:.1f}/{adx_past:.1f} "
                  f"gap={btc_gap:.3f}% pa={pa_name}({pa_dir}) conv={conviction} age={age_min:.0f}min")
        return True, pa_dir.upper(), reason

    def _phase_k_paper_log(self, entry: dict) -> None:
        """Phase K paper-mode / live 기록 (append-only JSONL).

        entry: dict with ts, market, scanner_dir, opp_dir, reason, paper_mode 등.
        실패해도 silent — paper log 는 optional.
        """
        try:
            os.makedirs(os.path.dirname(PHASE_K_PAPER_LOG_PATH), exist_ok=True)
            with open(PHASE_K_PAPER_LOG_PATH, "a", encoding="utf-8") as f:
                f.write(json.dumps(entry, ensure_ascii=False) + "\n")
        except Exception as exc:
            logger.debug("[FOCUS] Phase K paper log failed: %s", exc)

    # ============================================================
    # ★ Phase L (2026-04-22) — S3 Fee-Aware net_ev Gate
    # 형 9일 진단: net_vs_fee 0.16x → 목표 0.20~0.26x (1주)
    # 형 letter #11 검수 기준 10항목 + 엣지 7건 준수
    # 부모 ① D paper_mode + ② A FOCUS 이식 + ③ A 1주 paper 확정
    # ============================================================

    def _get_taker_fee_rate(self, market: str) -> float:
        """Bybit taker fee rate (엣지 ②: API 오류 시 fallback)."""
        try:
            client = self._get_client()
            # Bybit linear perpetual taker fee 기본 0.055%, maker -0.01% (rebate)
            # 시장가 진입은 taker. 청산도 시장가면 taker.
            rate = getattr(client, "get_taker_fee_rate", lambda m: None)(market)
            if rate is None or not (0 < rate < 0.01):
                return 0.00055  # fallback 0.055%
            return float(rate)
        except Exception as exc:
            logger.debug("[S3_GATE] fee rate fetch failed (%s), fallback 0.055%%: %s", market, exc)
            return 0.00055  # hardcode fallback (taker)

    def _check_s3_fee_gate(
        self,
        market: str,
        direction: str,
        price: float,
        atr: float,
        size_usdt: float,
        leverage: int,
        tp_mult: float,
        sl_mult: float,
        pa_double_confirmed: bool = False,  # Phase L.3 입력 (선택)
    ) -> tuple:
        """진입 직전 fee-aware net expected value 게이트.

        Returns: (allow: bool, reason: str, stats: dict)
          - allow=True  : 진입 허용 (paper_mode 시 가상 카운터만 증가)
          - allow=False : 차단 (live mode 만 실효, journal.record_blocked)
          - reason      : "[S3_GATE] ..." 표준 포맷
          - stats       : 측정 dict (영속화용)

        엣지 처리 (형 letter #11 7건):
          ① 0 나눗셈 — qty/price/ATR 모두 > 0 가드
          ② fee API 오류 — _get_taker_fee_rate fallback
          ③ 레버리지 변경 중 — leverage 입력 그대로 사용 (호출측 책임)
          ④ size_usdt 미정 — None or 0 → reject (skip)
          ⑤ paper→live 경계 — 호출 시점 cfg 값 그대로 사용
          ⑥ 재시작 복원 — 외부 stats 파일 read 안 함 (호출측에서 누적)
          ⑦ 동시성 — write 는 호출자가 lock 안에서

        검수 기준 #1~#10 준수.
        """
        cfg = self.config
        # ① enabled 체크
        if not getattr(cfg, "s3_gate_enabled", False):
            return True, "s3_gate_disabled", {}

        paper = bool(getattr(cfg, "s3_gate_paper_mode", True))

        # ① 0 나눗셈 가드
        if price <= 0 or atr <= 0 or size_usdt is None or size_usdt <= 0 or leverage <= 0:
            reason = (f"[S3_GATE] {market} {direction} INPUT_INVALID "
                      f"price={price} atr={atr} size={size_usdt} lev={leverage}")
            logger.warning(reason)
            return True, reason, {"input_invalid": True}  # 안전 fallback: 통과 (S3 Gate 가 거래 막지 않게)

        # ② fee 계산 (왕복 ×2)
        fee_rate = self._get_taker_fee_rate(market)
        fee_mult = float(getattr(cfg, "s3_gate_fee_multiplier", 2.0))
        # qty 추정: size_usdt × leverage / price = notional / price
        notional = size_usdt * leverage
        qty = notional / price
        fee_one_side = notional * fee_rate
        fee_total = fee_one_side * fee_mult  # 왕복 ×2 (형 검수 기준 #1)

        # 슬리피지 추정 (5bp = 0.05%)
        slippage_bps = float(getattr(cfg, "s3_gate_slippage_bps", 5.0))
        slippage = notional * (slippage_bps / 10000.0)

        # net_ev 계산 (검수 기준 #2)
        # 예상 PnL = ATR × tp_mult × qty (notional 변화량)
        # Phase L.3: PA 2건 합의 시 net_ev 가중 +10%
        gross_ev = atr * tp_mult * qty
        if pa_double_confirmed and getattr(cfg, "pa_double_confirm_enabled", False):
            gross_ev *= 1.10  # 품질 가중

        net_ev = gross_ev - fee_total - slippage

        # threshold 결정 (LINK 도박 가드)
        threshold = float(getattr(cfg, "s3_gate_min_net_ev_usdt", 0.0))
        if market.upper() == "LINKUSDT":
            link_mult = float(getattr(cfg, "s3_gate_link_multiplier", 1.3))
            threshold *= link_mult
            # threshold 가 0 이면 LINK 만 별도 최소값 적용 (수수료의 1.3배)
            if threshold <= 0:
                threshold = fee_total * (link_mult - 1.0)

        # 판정
        passed = net_ev > threshold
        mode_str = "paper" if paper else "live"
        passed_str = "passed" if passed else "blocked"

        # 검수 기준 #9 표준 로그 포맷
        reason = (f"[S3_GATE] {market} {direction} "
                  f"net_ev={net_ev:.4f} fee×{fee_mult}={fee_total:.4f} "
                  f"slip={slippage:.4f} gross_ev={gross_ev:.4f} "
                  f"th={threshold:.4f} gate={passed_str} mode={mode_str}")

        stats = {
            "ts": time.time(),
            "market": market,
            "direction": direction,
            "net_ev": round(net_ev, 4),
            "gross_ev": round(gross_ev, 4),
            "fee_total": round(fee_total, 4),
            "slippage": round(slippage, 4),
            "threshold": round(threshold, 4),
            "fee_rate": round(fee_rate, 6),
            "passed": passed,
            "mode": mode_str,
            "link_boosted": (market.upper() == "LINKUSDT"),
            "pa_double_confirmed": bool(pa_double_confirmed),
        }

        if passed:
            # 통과 (live/paper 동일)
            logger.info(reason)
            return True, reason, stats

        # 차단 케이스
        if paper:
            # Paper mode (검수 기준 #5): 진입 허용하되 "skip 했을 것" 카운터만
            logger.info("%s [PAPER skip-counted, entry ALLOWED]", reason)
            return True, reason + " [paper_skip_counted]", stats
        else:
            # Live mode: 실차단
            logger.warning("%s [LIVE BLOCKED]", reason)
            # 검수 기준 #4: journal.record_blocked
            try:
                from app.manager.trade_journal import journal
                journal.record_blocked(
                    "FOCUS", market, direction,
                    reason="s3_fee_gate",
                    detail=f"net_ev={net_ev:.4f} th={threshold:.4f} fee={fee_total:.4f}"
                )
            except Exception as exc:
                logger.debug("[S3_GATE] record_blocked failed: %s", exc)
            return False, reason, stats

    def _persist_s3_gate_stats(self, stats_entry: dict) -> None:
        """검수 기준 #8 — safe_write_json 영속화 + jsonl append.

        엣지 ⑦ 동시성: 호출자(_execute_entry)가 self._lock 보유 가정.
        엣지 ⑥ 재시작: stats 파일 없으면 빈 dict 로 초기화.
        """
        try:
            # 1) jsonl append (시계열 데이터 — 영원히 보존)
            os.makedirs(os.path.dirname(S3_GATE_LOG_PATH), exist_ok=True)
            with open(S3_GATE_LOG_PATH, "a", encoding="utf-8") as f:
                f.write(json.dumps(stats_entry, ensure_ascii=False) + "\n")

            # 2) summary stats (atomic, 누적 카운터)
            from app.core.io_utils import safe_write_json
            summary = {}
            if os.path.exists(S3_GATE_STATS_PATH):
                try:
                    with open(S3_GATE_STATS_PATH, "r", encoding="utf-8") as f:
                        summary = json.load(f) or {}
                except Exception:
                    summary = {}  # 손상 시 reset (엣지 ⑥)

            # 누적 업데이트
            mode = stats_entry.get("mode", "?")
            passed = bool(stats_entry.get("passed", False))
            virtual_net_saved = 0.0
            if not passed and mode == "paper":
                # paper skip 시 "절약했을 net_ev 의 음수 절댓값" 누적
                virtual_net_saved = abs(stats_entry.get("net_ev", 0.0))

            summary.setdefault("totals", {"checks": 0, "passed": 0, "blocked": 0,
                                         "paper_skips": 0, "live_blocks": 0})
            summary.setdefault("virtual_net_saved", 0.0)
            summary.setdefault("link_bypass_count", 0)
            summary.setdefault("first_ts", stats_entry.get("ts"))
            summary["last_ts"] = stats_entry.get("ts")

            t = summary["totals"]
            t["checks"] += 1
            if passed:
                t["passed"] += 1
                if stats_entry.get("link_boosted") and stats_entry.get("net_ev", 0) > 0:
                    # LINK 가 게이트 통과 = 우회 (승격 조건 ④ 카운터)
                    summary["link_bypass_count"] += 1
            else:
                t["blocked"] += 1
                if mode == "paper":
                    t["paper_skips"] += 1
                    summary["virtual_net_saved"] += virtual_net_saved
                else:
                    t["live_blocks"] += 1

            safe_write_json(S3_GATE_STATS_PATH, summary)
        except Exception as exc:
            logger.warning("[S3_GATE] persist stats failed: %s", exc)

    def _in_entry_grace_period(self, pos, now: float) -> bool:
        """진입 후 분위기 파악 시간 (부모 비전 #6, 2026-05-18).

        부모님 원문: "진입 후 분위기 파악을 위한 시간이 더 필요해"
        A/B 확률 게임 — 진입 직후는 A(장기물림) 인지 B(작은계곡후언덕) 인지 모름.
        N초 동안 빠른 컷 가드 비활성 → 판별 시간 벌기.

        적용 가드: pre_be_stall_exit + reverse_drift_exit (호출처에서 조건 추가)
        영향 X: be_stall_exit (수익 가드), long_hold_timeout (시간 단위), SL, Hard ROE
        """
        grace_sec = float(getattr(self.config, "entry_grace_period_sec", 0.0))
        if grace_sec <= 0:
            return False
        if not pos or getattr(pos, "entry_ts", 0) <= 0:
            return False
        return (now - pos.entry_ts) < grace_sec

    def _check_news_force_exit(self, pos, now: float) -> tuple:
        """그레이스 기간 중 뉴스 sentiment 가 진입 방향과 반대 강이면 즉시 컷 (부모 비전 #6 보조).

        부모님 원문: "뉴스를 되살리는 방법... 진입변수 뿐 아니라 탈출 변수에도 사용되는건데"
        진입 시점 = focus_manager.py 4305 (conviction 산식) — 이미 통합됨, focus_enabled=True 만 필요
        탈출 시점 = 본 helper — 그레이스 기간 중 force exit 트리거

        A/B 확률 게임:
          - sentiment 반대 방향 강 (LONG 인데 -0.5 미만 / SHORT 인데 +0.5 초과) → A 패턴 → 즉시 컷
          - sentiment 같은 방향 또는 NEUTRAL → 견디기 (B 패턴 가능성)

        Returns: (force_exit: bool, reason: str)
        """
        try:
            from app.core.news_sentiment import get_news_sentiment
            _ns = get_news_sentiment()
            if not _ns or not _ns.config.get("focus_enabled"):
                return False, ""  # news 자체 dormant
            coin = pos.market.replace("USDT", "").replace("USD", "")
            result = _ns.get_sentiment(coin=coin)
            if not result or result.source == "fallback":
                return False, ""  # 신뢰할 수 없는 데이터
            sentiment_score = float(result.score)  # -1.0 ~ +1.0
            threshold = float(getattr(self.config, "news_grace_exit_threshold", 0.5))
            dir_up = (pos.direction or "").upper()
            if dir_up == "LONG" and sentiment_score <= -threshold:
                return True, f"news_grace_against_LONG_s{sentiment_score:+.2f}"
            elif dir_up == "SHORT" and sentiment_score >= threshold:
                return True, f"news_grace_against_SHORT_s{sentiment_score:+.2f}"
        except Exception as exc:
            logger.debug("[FOCUS] _check_news_force_exit error: %s", exc)
        return False, ""

    def _check_grace_force_exit(self, pos, now: float) -> tuple:
        """그레이스 기간 중 force exit 신호 통합 체크 (market_bias + news_sentiment).

        부모 비전 #6 1차 시도 (시간 기반). 부모님 정정으로 사용 안 함 (default OFF).
        대신 _check_exit_consensus 사용 (시간 무관).
        """
        # 1. market_bias
        if getattr(self.config, "market_bias_grace_exit_enabled", False):
            force, reason = self._check_market_bias_force_exit(pos, now)
            if force:
                return True, reason
        # 2. news_sentiment
        if getattr(self.config, "news_grace_exit_enabled", False):
            force, reason = self._check_news_force_exit(pos, now)
            if force:
                return True, reason
        return False, ""

    def _check_exit_consensus(self, pos, now: float) -> str:
        """기존 청산 가드 발동 시 옆 서버 + 뉴스 의견 종합 (부모 비전 #6 B 옵션, 2026-05-18 저녁).

        부모님 정신: "시간컷 해 놓으니 소액 연속 손실 / 견딘다 해도 장기 미손실 코인" = 시간 기반 X.
        해법: 기존 가드 발동 시 옆 서버 + 뉴스 의견 *종합* 확인 후 컷/견디기 결정.

        A/B 확률 게임:
          - 둘 다 반대 (또는 같은 방향 dominance) → A 패턴 → "exit" (가드 동의)
          - 둘 다 같은 방향 (또는 진입 방향 sentiment 강) → B 패턴 → "hold" (가드 무시)
          - 엇갈리거나 신호 없음 → "neutral" (기본 = 가드 따름)

        시간 무관 = 부모님 *시간 기반 회의* 정신 일치.

        Returns: "exit" / "hold" / "neutral"
        """
        if not getattr(self.config, "exit_consensus_enabled", False):
            return "neutral"
        votes_exit = 0
        votes_hold = 0
        # 1. market_bias 의견
        try:
            engine = self._get_context_engine()
            if engine and getattr(engine, "bias", None) and getattr(self.config, "market_bias_enabled", False):
                result = engine.bias.evaluate(pos.market, pos.direction, now)
                delta = float(result.get("delta", 0))
                if delta < 0:
                    votes_exit += 1  # 반대 dominance = A 신호
                elif delta == 0:
                    bias = result.get("bias", "NEUTRAL")
                    dir_up = (pos.direction or "").upper()
                    if bias == dir_up:
                        votes_hold += 1  # 같은 방향 dominance = B 신호
        except Exception as exc:
            logger.debug("[FOCUS] exit_consensus mb error: %s", exc)
        # 2. news sentiment 의견
        try:
            from app.core.news_sentiment import get_news_sentiment
            _ns = get_news_sentiment()
            if _ns and _ns.config.get("focus_enabled"):
                coin = pos.market.replace("USDT", "").replace("USD", "")
                result = _ns.get_sentiment(coin=coin)
                if result and result.source != "fallback":
                    sentiment = float(result.score)
                    threshold = float(getattr(self.config, "exit_consensus_news_threshold", 0.3))
                    dir_up = (pos.direction or "").upper()
                    if dir_up == "LONG":
                        if sentiment <= -threshold:
                            votes_exit += 1
                        elif sentiment >= threshold:
                            votes_hold += 1
                    elif dir_up == "SHORT":
                        if sentiment >= threshold:
                            votes_exit += 1
                        elif sentiment <= -threshold:
                            votes_hold += 1
        except Exception as exc:
            logger.debug("[FOCUS] exit_consensus news error: %s", exc)
        # 종합 판정
        if votes_exit > votes_hold:
            return "exit"
        elif votes_hold > votes_exit:
            return "hold"
        return "neutral"

    def _check_market_bias_force_exit(self, pos, now: float) -> tuple:
        """그레이스 기간 중 market_bias 가 반대 방향이면 즉시 컷 권장 (부모 비전 #6 보조).

        부모님 원문: "다른 연계된 코인들의 방향을 따라가는것이 조금 안전..옆 서버들의 눈치를 보는것"

        A/B 확률 게임:
          - 옆 서버들 (market_bias) 같은 방향 → B 패턴 → 견디기 (그레이스 유지)
          - 옆 서버들 반대 방향 → A 패턴 → 즉시 컷 (옛 -$1063 회피)

        market_bias 모듈 재활용 (진입 시점 페널티 → 청산 시점 force exit 확장).
        Returns: (force_exit: bool, reason: str)
        """
        try:
            engine = self._get_context_engine()
            if not engine or not getattr(engine, "bias", None):
                return False, ""
            if not getattr(self.config, "market_bias_enabled", False):
                return False, ""
            result = engine.bias.evaluate(pos.market, pos.direction, now)
            delta = float(result.get("delta", 0))
            # delta < 0 = 반대 방향 dominance = A 패턴 신호
            if delta < 0:
                bias = result.get("bias", "?")
                dom = float(result.get("dominance", 0))
                return True, f"mb_grace_against_{bias}_dom{dom:.2f}"
        except Exception as exc:
            logger.debug("[FOCUS] _check_market_bias_force_exit error: %s", exc)
        return False, ""

    def _check_reentry_allowed(self, direction: str, market: str, price: float) -> bool:
        """같은 방향 즉시 재진입 차단 — 시장이 사이클 거치면 허용.

        차단: direction == _last_exit_direction AND market == _last_exit_market

        허용 조건 (하나만 충족하면 됨):
        1. 다른 방향이면 항상 허용
        2. 가격이 퇴장가에서 왕복수수료의 2배 이상 이동 (|현재가-퇴장가|/퇴장가 > 0.22%)
        3. ADX가 dormant 아래로 갔다가 다시 min_adx_entry 위로 (새 추세 시작)
        4. DORMANT→ALERT→HUNT 사이클을 완전히 거침
        """
        # ★ 수동 퇴장 페널티 최우선 체크 — 사용자가 직접 내보낸 코인은 4시간 금지
        # [2026-04-18 밤] 형 검수 반영: toggle OFF 시 기존 페널티까지 즉시 해제 (선택지 A)
        #   사용자 UX 기대: "OFF = 즉시 모든 블록 해제". 죽은 dict 남기지 말고 싹 비운다.
        mkt_upper = market.upper()
        if not getattr(self.config, "manual_exit_penalty_enabled", True):
            if self._manual_exit_penalties:
                logger.info("[FOCUS] Manual penalty DISABLED — clearing %d existing penalty(s)", len(self._manual_exit_penalties))
                self._manual_exit_penalties.clear()
        elif mkt_upper in self._manual_exit_penalties:
            expire_ts = self._manual_exit_penalties[mkt_upper]
            remaining = expire_ts - time.time()
            if remaining > 0:
                hours_left = remaining / 3600
                logger.info("[FOCUS] ⛔ MANUAL PENALTY: %s blocked for %.1fh more (user manually closed)", mkt_upper, hours_left)
                return False
            else:
                # 만료 → 제거
                del self._manual_exit_penalties[mkt_upper]
                logger.info("[FOCUS] Manual penalty expired for %s — re-entry allowed", mkt_upper)

        # ★ [2026-04-24] Consecutive Loss Pause — 부모님 단순 발상
        # 연패 N회 → M분 자동 정지 (모든 코인 / 모든 방향). market/direction 무관 전체 차단.
        # max_daily_sl(그날 끝)과 dm_streak_block(영구) 사이의 시간 기반 안전망.
        consec_blocked, consec_reason = self._check_consecutive_loss_pause()
        if consec_blocked:
            logger.info("[FOCUS] ⛔ %s", consec_reason)
            try:
                from app.manager.trade_journal import journal
                journal.record_blocked(
                    "FOCUS", market, direction,
                    reason="consecutive_loss_pause",
                    detail=consec_reason,
                )
            except Exception:
                pass
            return False

        # ★ [2026-06-04 부모] 방향별 레짐 윈도우 실패 차단
        # N시간 내 해당 방향 누적 실패 N회 → 그 방향만 차단 / 반대 방향 허용
        dir_fail_blocked, dir_fail_reason = self._check_direction_fail_window(direction)
        if dir_fail_blocked:
            logger.info("[FOCUS] ⛔ %s", dir_fail_reason)
            try:
                from app.manager.trade_journal import journal
                journal.record_blocked(
                    "FOCUS", market, direction,
                    reason="dir_fail_window",
                    detail=dir_fail_reason,
                )
            except Exception:
                pass
            return False

        # ── 🛡️ [2026-06-11 부모] 함대 dir_fail — 옆 서버 실패 공유 (같은 코인+방향 누적 차단) ──
        #   오늘 VELVET LONG 순차 줄초상(server-b→server-a→home, 50분 시간차) 방지. default OFF.
        try:
            from app.core.peer_brief import (
                check_peer_direction_fail_caution, get_peer_fleet_dirfail_window_min,
            )
            _fleet_lc = self._count_coin_dir_loss(
                market, direction, get_peer_fleet_dirfail_window_min() / 60.0)
            _fleet_blocked, _fleet_src = check_peer_direction_fail_caution(
                market, direction, local_count=_fleet_lc)
            if _fleet_blocked:
                logger.info("[FOCUS] ⛔ %s", _fleet_src)
                try:
                    from app.manager.trade_journal import journal
                    journal.record_blocked(
                        "FOCUS", market, direction,
                        reason="peer_fleet_dirfail", detail=_fleet_src,
                    )
                except Exception:
                    pass
                return False
        except Exception as exc:
            logger.debug("[FOCUS] peer fleet dirfail check error: %s", exc)

        # ★ Phase L.2 (2026-04-22, Harpoon 0-7 → FOCUS 이식):
        # SL/Fast-Reject/Fast-Reject-v2 발생 시 (market, direction) 30분 차단.
        # B9 post_trade_pause (loss 600s / fast_reject 900s) 보다 더 엄격한 추가 층.
        # 이유: AAVE 같은 코인이 5~15분 만에 같은 setup 재시도 함정 패턴 (Harpoon forensic ③).
        # default OFF — 부모 승인 후 활성.
        if getattr(self.config, "reentry_cooldown_v2_enabled", False):
            try:
                from app.manager.trade_journal import journal
                cd_min = float(getattr(self.config, "reentry_cooldown_v2_min", 30.0))
                cd_sec = cd_min * 60.0
                _now = time.time()
                # 최근 EXIT 중 SL/Fast-Reject 계열 + 같은 (market, direction) 검사
                # journal.get_trades 사용 (get_recent_exits 미존재)
                _resp = journal.get_trades(
                    limit=20, strategy="FOCUS", market=mkt_upper, include_blocked=False, page=1
                ) or {}
                recent = _resp.get("trades", [])
                for e in recent:
                    if e.get("event") != "EXIT":
                        continue
                    if e.get("direction", "").upper() != direction.upper():
                        continue
                    er = (e.get("exit_reason", "") or "").lower()
                    if not any(k in er for k in ("sl", "fast_reject", "stop_loss")):
                        continue
                    age = _now - float(e.get("ts", 0) or 0)
                    if 0 <= age < cd_sec:
                        remain_min = (cd_sec - age) / 60.0
                        logger.info(
                            "[FOCUS] ⛔ Phase L.2 reentry_cooldown_v2: %s %s blocked %.1fmin more "
                            "(SL/fast_reject %.1fmin ago, cd=%.0fmin)",
                            mkt_upper, direction, remain_min, age/60.0, cd_min
                        )
                        try:
                            journal.record_blocked(
                                "FOCUS", market, direction,
                                reason="reentry_cooldown_v2",
                                detail=f"SL {age/60:.1f}min ago, cd {cd_min:.0f}min",
                            )
                        except Exception:
                            pass
                        return False
            except Exception as exc:
                logger.debug("[FOCUS] Phase L.2 cooldown check failed: %s", exc)

        # ★ [2026-04-19] B9 — Post-Trade Pause (journal 기반, SERVER_SL 우회 방지)
        # `self._last_exit_*` 메모리는 SERVER_SL 경로에서 갱신 안 되는 버그가 있음.
        # → journal EXIT 전수조사로 재구성. 이전 exit 성격별 다른 쿨다운:
        #   profit       → 300s (수명 다한 방향 복수 진입 방어)
        #   loss         → 600s (학습 없이 재진입 방어)
        #   fast_reject  → 900s (빠른 이탈 직후 추격 방어)
        # "모든 것은 설정값에 따른 결과" — 우연이 아닌 계산된 쿨다운
        if getattr(self.config, "post_trade_pause_enabled", True):
            pause_blocked, pause_reason = self._check_post_trade_pause(market, direction)
            if pause_blocked:
                logger.info("[FOCUS] ⛔ Post-Trade Pause: %s %s — %s", market, direction, pause_reason)
                try:
                    from app.manager.trade_journal import journal
                    journal.record_blocked(
                        "FOCUS", market, direction,
                        reason="post_trade_pause",
                        detail=pause_reason,
                    )
                except Exception as exc:
                    logger.debug("[FOCUS] post_trade_pause journal failed: %s", exc)
                return False

        # ★ [2026-04-19] B8 — Direction Exhaustion (연속 수익 후 같은 방향 고갈)
        # 최근 N분 내 같은 코인×방향 수익 exit M회 이상 → 해당 방향 차단.
        # 철학: "연속 이윤 낸 방향은 거의 수명이 다했다고 봐도 된다" (형)
        #       "롱솟 동시 구사 → 놓쳐도 아쉽지 않다" (반대 방향 기회 살아있음)
        if getattr(self.config, "direction_exhaustion_enabled", True):
            exh_blocked, exh_reason = self._check_direction_exhaustion(market, direction)
            if exh_blocked:
                logger.info("[FOCUS] ⛔ Direction Exhaustion: %s %s — %s", market, direction, exh_reason)
                try:
                    from app.manager.trade_journal import journal
                    journal.record_blocked(
                        "FOCUS", market, direction,
                        reason="direction_exhaustion",
                        detail=exh_reason,
                    )
                except Exception as exc:
                    logger.debug("[FOCUS] direction_exhaustion journal failed: %s", exc)
                return False

        # ★ [2026-04-19 → 2026-04-20 Phase F 복원] B10 — Profit-Exit Coin Block
        # 형 의도: 같은 코인 + 같은 방향 + 연속 N회 수익 시 그 방향만 차단
        # "드나들다 대판 잃는" 패턴 방어 — FLIP (반대 방향) 은 허용
        if getattr(self.config, "profit_exit_block_enabled", True):
            peb_blocked, peb_reason = self._check_profit_exit_block(market, direction)
            if peb_blocked:
                logger.info("[FOCUS] ⛔ Profit-Exit Block: %s %s — %s", market, direction, peb_reason)
                try:
                    from app.manager.trade_journal import journal
                    journal.record_blocked(
                        "FOCUS", market, direction,
                        reason="profit_exit_block",
                        detail=peb_reason,
                    )
                except Exception as exc:
                    logger.debug("[FOCUS] profit_exit_block journal failed: %s", exc)
                return False

        # ★ [2026-04-19] B11 — Regime Direction Lock (형 직접 지시, 친구 조언)
        # "상승장이면 LONG only, 하락장이면 SHORT only, 그 외엔 REST"
        # + "기미 보이면 올스톱" — 양쪽 다 잡으려는 욕심 자체를 코드 차원에서 차단.
        # 4/13~14 +$200/+$300 → 직후 며칠 −$264/−$37 토함의 근본 진단.
        if getattr(self.config, "regime_direction_lock_enabled", True):
            rdl_blocked, rdl_reason = self._check_regime_direction_lock(direction, market)
            if rdl_blocked:
                logger.info("[FOCUS] ⛔ Regime Lock: %s %s — %s", market, direction, rdl_reason)
                try:
                    from app.manager.trade_journal import journal
                    journal.record_blocked(
                        "FOCUS", market, direction,
                        reason="regime_direction_lock",
                        detail=rdl_reason,
                    )
                except Exception as exc:
                    logger.debug("[FOCUS] regime_direction_lock journal failed: %s", exc)
                return False

        # 조건 0: 퇴장 이력이 없으면 항상 허용
        if not self._last_exit_direction or not self._last_exit_market:
            return True

        # ★ [2026-04-18] 마켓별 최소 재진입 간격: 같은 마켓 + 같은 방향만 300초 대기
        # 기존: 방향 무관 차단 → LONG 청산 후 SHORT 플립도 5분 봉쇄 (편향 원인 #5)
        # 수정: 같은 방향 재진입만 차단 — FLIP은 즉시 허용
        # [주의] SERVER_SL 경로에서 self._last_exit_*가 갱신 안 될 수 있어 B9가 메인 방어선
        if (market.upper() == self._last_exit_market.upper()
                and direction == self._last_exit_direction):
            elapsed = time.time() - self._last_exit_ts
            if elapsed < 300:
                logger.info("[FOCUS] Reentry BLOCKED: %s %s exited %.0fs ago (min 300s, same dir)",
                            market, direction, elapsed)
                return False

        # ★ Coin Repeat Brake: 같은 코인 N회 이상 → 쿨다운 base × (N-free)초, 최대 1800초
        #   5회까지 자유, 6회부터 브레이크 (방귀가 잦으면 똥이 나온다)
        # [2026-04-18] 방향별 분리 — LONG 반복이 SHORT 브레이크까지 걸던 거 해제
        # [2026-04-18] user 요청 "24시간 돌아가게 다 풀자" — Repeat Brake 완전 비활성화
        # [2026-04-18 20:50] ★ 재활성화 — RAVE 3분 7회 -$74 대학살 이후
        #   "다 풀자"로 끈 것이 반복 손실 방어막이었음을 실전에서 증명
        if self.config.coin_repeat_brake_enabled:
            repeat_count, coin_last_exit_ts = self._get_coin_repeat_info(market, direction)
            free = self.config.coin_repeat_free_count
            if repeat_count >= free and coin_last_exit_ts > 0:
                excess = repeat_count - free  # 초과분만 페널티 (6회→1배, 8회→3배)
                required_cd = min(self.config.coin_repeat_cooldown_base * excess, 1800.0)  # 최대 30분 캡
                elapsed_since_coin_exit = time.time() - coin_last_exit_ts
                if elapsed_since_coin_exit < required_cd:
                    remaining = required_cd - elapsed_since_coin_exit
                    logger.info(
                        "[FOCUS] Repeat Brake: %s traded %d times in %dh — cooldown %.0fs (%.0fx%d excess), %.0fs remaining",
                        market, repeat_count, int(self.config.coin_repeat_window_hours),
                        required_cd, self.config.coin_repeat_cooldown_base, excess, remaining
                    )
                    # ★ 원장 기록 — 차단 사유 영구 보존
                    try:
                        from app.manager.trade_journal import journal
                        journal.record_blocked(
                            "FOCUS", market, direction,
                            reason="repeat_brake",
                            detail=f"count={repeat_count},cooldown={required_cd:.0f}s,remaining={remaining:.0f}s",
                        )
                    except Exception as exc:
                        logger.debug("[FOCUS] import journal failed: %s", exc)
                    return False
                else:
                    logger.info(
                        "[FOCUS] Repeat Brake: %s traded %d times, cooldown %.0fs elapsed (need %.0fs) — allowed",
                        market, repeat_count, elapsed_since_coin_exit, required_cd
                    )

        # ★ Direction Block (runtime 파일 기반 coin×direction 잠금)
        #   데이터-구동 긴급 차단용. ex) ETH LONG이 24h -$29 출혈 → 12h 차단.
        #   코인 전체가 아닌 "특정 방향만" 차단이라 반대 방향 기회는 유지.
        #   "코인 실패 배제 금지" 원칙과 양립 (블랙리스트 아닌 임시 허들).
        _dir_blocked, _dir_reason = self._is_direction_blocked(market, direction)
        if _dir_blocked:
            logger.info(
                "[FOCUS] ⛔ Direction Block: %s %s — %s",
                market, direction, _dir_reason,
            )
            try:
                from app.manager.trade_journal import journal
                journal.record_blocked(
                    "FOCUS", market, direction,
                    reason="direction_block",
                    detail=_dir_reason,
                )
            except Exception as exc:
                logger.debug("[FOCUS] import journal failed: %s", exc)
            return False

        # ★ Coin Loss Cap: 24시간 내 누적 손실 초과 시 차단
        # [2026-04-18] 방향별 분리 — LONG 누적손실이 SHORT까지 차단하던 거 해제
        if self.config.coin_loss_cap_enabled:
            total_loss = self._get_coin_loss_total(market, direction)
            cap = self._effective_coin_loss_cap()
            if total_loss < 0 and abs(total_loss) >= cap:
                logger.info(
                    "[FOCUS] Coin Loss Cap: %s 24h loss $%.2f exceeds cap $%.2f — BLOCKED",
                    market, total_loss, cap,
                )
                try:
                    from app.manager.trade_journal import journal
                    journal.record_blocked(
                        "FOCUS", market, direction,
                        reason="coin_loss_cap",
                        detail=f"24h_loss=${total_loss:.2f},cap=${cap:.2f}",
                    )
                except Exception as exc:
                    logger.debug("[FOCUS] import journal failed: %s", exc)
                return False

        # ★ [2026-04-19] Pair Group Block (기본 OFF, 사용자 opt-in)
        # 짝 코인 반대 방향 = 수수료 상쇄. 공격/보수 모드 지원.
        # pair_block_enabled=False 일 때 _check_pair_block은 (False, "") 즉시 반환.
        _pair_blocked, _pair_reason = self._check_pair_block(market, direction)
        if _pair_blocked:
            logger.info("[FOCUS] ⛔ Pair Block: %s %s — %s", market, direction, _pair_reason)
            try:
                from app.manager.trade_journal import journal
                journal.record_blocked(
                    "FOCUS", market, direction,
                    reason="pair_block",
                    detail=_pair_reason,
                )
            except Exception as exc:
                logger.debug("[FOCUS] pair_block journal failed: %s", exc)
            return False

        # 조건 1: 다른 방향이면 항상 허용
        if direction != self._last_exit_direction:
            return True

        # 다른 마켓이면 허용
        if market.upper() != self._last_exit_market.upper():
            return True

        # ── 이하: 같은 방향 + 같은 마켓 = 재진입 차단 대상 ──

        # 조건 2: 가격이 충분히 이동했으면 허용 (왕복 수수료 × 2 = 0.22%)
        if self._last_exit_price > 0 and price > 0:
            price_change_pct = abs(price - self._last_exit_price) / self._last_exit_price * 100
            if price_change_pct >= 0.22:
                logger.info("[FOCUS] Reentry allowed: price moved %.3f%% from exit (>0.22%%)", price_change_pct)
                return True

        # 조건 3: ADX가 dormant 아래로 갔다가 다시 올라옴 → 새 추세
        # (_last_adx_value가 dormant 아래로 갔다가 현재 min_adx_entry 이상)
        # 이건 _handle_dormant→_handle_hunt 사이클에서 자동 처리됨

        # 조건 4: DORMANT→ALERT→HUNT 사이클 완료
        if self._completed_dormant_cycle:
            logger.info("[FOCUS] Reentry allowed: completed DORMANT→ALERT→HUNT cycle")
            self._completed_dormant_cycle = False
            return True

        logger.info("[FOCUS] Reentry BLOCKED: same direction=%s same market=%s, price_diff=%.3f%%",
                     direction, market,
                     abs(price - self._last_exit_price) / self._last_exit_price * 100 if self._last_exit_price > 0 else 0)
        return False

    def apply_manual_exit_penalty(self, market: str, hours: float = 4.0):
        """수동 퇴장 시 해당 코인 재진입 금지 페널티 부과.
        Args:
            market: 코인 심볼 (e.g. ZECUSDT)
            hours: 금지 시간 (기본 4시간)
        """
        mkt = market.upper()
        expire_ts = time.time() + hours * 3600
        self._manual_exit_penalties[mkt] = expire_ts
        self._save_config()
        logger.warning("[FOCUS] ⛔ MANUAL EXIT PENALTY: %s banned for %.1fh (until %s)",
                       mkt, hours, time.strftime("%H:%M", time.localtime(expire_ts)))
        self._notify(f"⛔ {mkt} 수동 퇴장 → {hours:.0f}시간 진입 금지\n해제: {time.strftime('%H:%M', time.localtime(expire_ts))}")

    def _detect_sideways_ending(self, market: str) -> bool:
        """횡보 끝나가는 징조 감지. DORMANT → ALERT 전환 트리거.

        2개 이상 징조가 있으면 True:
        1. BB 극수축 (bollinger_squeeze)
        2. ADX 바닥 반등 (하락하다 상승 전환, 아직 < 25)
        3. MACD 히스토그램 제로선에서 확대
        4. 거래량 급증 (kline volume > 20기간 평균 × 1.5)
        """
        signs = 0
        try:
            raw = self._get_client().get_kline(market, interval=self.config.primary_tf, limit=60)
            if not raw or len(raw) < 25:
                return False

            closes = [float(r[4]) for r in raw if len(r) >= 5]
            highs = [float(r[2]) for r in raw if len(r) >= 5]
            lows = [float(r[3]) for r in raw if len(r) >= 5]
            volumes = [float(r[5]) for r in raw if len(r) >= 6]

            # 1) BB squeeze
            from app.strategy.indicators import bollinger_squeeze
            if len(closes) >= 20:
                sq = bollinger_squeeze(closes)
                if sq and sq.get("is_squeeze"):
                    signs += 1

            # 2) ADX 바닥 반등
            from app.strategy.indicators import adx_series as _adx_series_fn
            if len(closes) >= 30:
                adx_s = _adx_series_fn(highs, lows, closes, period=14)
                if len(adx_s) >= 3:
                    a1, a2, a3 = adx_s[-3]["adx"], adx_s[-2]["adx"], adx_s[-1]["adx"]
                    # 하락하다 상승으로 전환, 아직 25 미만
                    if a1 > a2 and a3 > a2 and a3 < 25:
                        signs += 1

            # 3) MACD hist 제로선에서 확대
            from app.strategy.indicators import macd_hist_series
            if len(closes) >= 35:
                hist_s = macd_hist_series(closes)
                if len(hist_s) >= 3:
                    h1, h2, h3 = abs(hist_s[-3]), abs(hist_s[-2]), abs(hist_s[-1])
                    if h3 > h2 > h1 and h1 < closes[-1] * 0.001:  # 제로 근처에서 확대
                        signs += 1

            # 4) 거래량 급증
            if len(volumes) >= 21:
                avg_vol = sum(volumes[-21:-1]) / 20
                if avg_vol > 0 and volumes[-1] > avg_vol * 1.5:
                    signs += 1

        except Exception as exc:
            logger.debug("[FOCUS] sideways ending detection error: %s", exc)

        return signs >= 2

    def _detect_sideways_starting(self, market: str) -> bool:
        """횡보 시작 징조 감지. POSITIONED → CAUTION 전환 트리거.

        2개 이상 징조가 있으면 True:
        1. ADX 3캔들 연속 하락
        2. BB폭 3캔들 연속 감소
        3. MACD hist 절대값 3캔들 연속 감소
        4. Market structure = SIDEWAYS
        """
        signs = 0
        try:
            raw = self._get_client().get_kline(market, interval=self.config.primary_tf, limit=60)
            if not raw or len(raw) < 30:
                return False

            closes = [float(r[4]) for r in raw if len(r) >= 5]
            highs = [float(r[2]) for r in raw if len(r) >= 5]
            lows = [float(r[3]) for r in raw if len(r) >= 5]

            # 1) ADX 3캔들 연속 하락
            from app.strategy.indicators import adx_series as _adx_series_fn
            if len(closes) >= 30:
                adx_s = _adx_series_fn(highs, lows, closes, period=14)
                if len(adx_s) >= 3:
                    a1, a2, a3 = adx_s[-3]["adx"], adx_s[-2]["adx"], adx_s[-1]["adx"]
                    if a1 > a2 > a3:
                        signs += 1

            # 2) BB폭 3캔들 연속 감소
            from app.strategy.indicators import bollinger_bands as _bb_fn
            if len(closes) >= 23:
                bw_series = []
                for i in range(3):
                    end_idx = len(closes) - (2 - i)
                    bb = _bb_fn(closes[:end_idx], 20, 2.0)
                    if bb and bb.get("bandwidth"):
                        bw_series.append(bb["bandwidth"])
                if len(bw_series) == 3 and bw_series[0] > bw_series[1] > bw_series[2]:
                    signs += 1

            # 3) MACD hist 절대값 3캔들 연속 감소
            from app.strategy.indicators import macd_hist_series
            if len(closes) >= 35:
                hist_s = macd_hist_series(closes)
                if len(hist_s) >= 3:
                    h1, h2, h3 = abs(hist_s[-3]), abs(hist_s[-2]), abs(hist_s[-1])
                    if h1 > h2 > h3:
                        signs += 1

            # 4) Market structure = SIDEWAYS
            from app.strategy.greenpen.pa_detector import OHLCV as _O
            from app.strategy.greenpen.market_structure import analyze_structure as _as
            candles = [_O(float(r[1]), float(r[2]), float(r[3]), float(r[4])) for r in raw if len(r) >= 5]
            if len(candles) >= 10:
                struct = _as(candles)
                trend_val = struct.trend.value if hasattr(struct.trend, 'value') else str(struct.trend)
                if trend_val == "SIDEWAYS":
                    signs += 1

        except Exception as exc:
            logger.debug("[FOCUS] sideways starting detection error: %s", exc)

        return signs >= 2

    # ── State Handlers ──────────────────────────────────────

    def _handle_dormant(self, now: float) -> Dict:
        """DORMANT: ADX < dormant_threshold.
        스캔 간격: ADX < 10이면 1시간, 10~14이면 30분, 15+ 이면 즉시 ALERT."""
        # 일일 제한 체크
        if self.daily_plans_used >= self.config.max_daily_plans:
            return {"state": "DORMANT", "reason": "daily_plan_limit"}
        if self.daily_sl_count >= self.config.max_daily_sl:
            return {"state": "DORMANT", "reason": "daily_sl_limit"}

        # 동적 스캔 간격: ADX 수준에 따라 짧아짐
        # Scanner ON이면 기회 포착을 위해 간격 단축
        scanner_active = self.config.scanner_entry and self.config.max_positions > 1
        last_adx = self._last_adx_value
        if last_adx <= 0 or last_adx < 10:
            dormant_interval = 600.0 if scanner_active else 3600.0   # Scanner: 10분, 기본: 1시간
        elif last_adx < self.config.dormant_adx_threshold:
            dormant_interval = 300.0 if scanner_active else 1800.0   # Scanner: 5분, 기본: 30분
        elif last_adx >= self.config.min_adx_entry:
            # [2026-04-09] ADX가 이미 진입 가능 → 빠르게 HUNT 전환
            dormant_interval = self.config.scan_interval_sec  # 60초
        else:
            dormant_interval = 120.0 if scanner_active else 300.0  # 2분/5분

        if now - self.last_scan_ts < dormant_interval:
            remaining = dormant_interval - (now - self.last_scan_ts)
            return {"state": "DORMANT", "next_scan_in": round(remaining)}

        self.last_scan_ts = now

        # ADX 필터가 꺼져있으면 바로 HUNT
        if not self.config.adx_filter_enabled:
            self.state = FocusState.HUNT
            self._save_config()
            logger.info("[FOCUS] DORMANT → HUNT (ADX filter disabled)")
            return {"state": "HUNT"}

        # lock_market이면 해당 코인, 아니면 BTCUSDT 기준
        check_market = self.config.lock_market.upper() if self.config.lock_market else "BTCUSDT"
        adx_data = self._fetch_primary_adx(check_market)

        if not adx_data:
            return {"state": "DORMANT", "reason": "adx_fetch_failed"}

        adx_val = adx_data["adx"]
        logger.info("[FOCUS] DORMANT check: %s ADX=%.1f (entry=%d, dormant=%d)",
                     check_market, adx_val, self.config.min_adx_entry, self.config.dormant_adx_threshold)

        if adx_val >= self.config.min_adx_entry:
            # 추세 확정 → HUNT 직행
            self.state = FocusState.HUNT
            self._completed_dormant_cycle = True
            self.last_scan_ts = 0  # [2026-04-09] HUNT 전환 후 즉시 스캔
            self._save_config()
            logger.info("[FOCUS] DORMANT → HUNT (ADX %.1f >= %d)", adx_val, self.config.min_adx_entry)
            return {"state": "HUNT", "adx": round(adx_val, 1)}

        if adx_val >= self.config.dormant_adx_threshold:
            # ADX가 dormant 임계 이상 → 즉시 ALERT (추가 조건 없음)
            self.state = FocusState.ALERT
            self._save_config()
            # 횡보 끝 징조도 로깅 (참고용, 게이트 아님)
            target_market = self.config.lock_market.upper() if self.config.lock_market else check_market
            sw_ending = self._detect_sideways_ending(target_market)
            logger.info("[FOCUS] DORMANT → ALERT (ADX %.1f >= %d, sideways_ending=%s)",
                         adx_val, self.config.dormant_adx_threshold, sw_ending)
            return {"state": "ALERT", "adx": round(adx_val, 1)}

        # ── Scanner 독립 HUNT: 금이 자도 다른 코인이 뛰면 깨어남 ──
        if self.config.scanner_entry and self.config.max_positions > 1:
            try:
                candidates = self._get_scanner_candidates()
                hunt_ready = [c for c in candidates
                              if c.get("adx", 0) >= self.config.scanner_min_adx]
                if hunt_ready:
                    best = max(hunt_ready, key=lambda c: c.get("adx", 0))
                    self.state = FocusState.HUNT
                    self.last_scan_ts = 0  # [2026-04-09] 즉시 스캔
                    self._save_config()
                    logger.info("[FOCUS] DORMANT → HUNT (primary %s ADX=%.1f dormant, "
                                "but scanner found %s ADX=%.1f)",
                                check_market, adx_val,
                                best["market"], best["adx"])
                    return {"state": "HUNT", "adx": round(adx_val, 1),
                            "scanner_trigger": best["market"]}
            except Exception as exc:
                logger.debug("[FOCUS] Scanner check in DORMANT failed: %s", exc)

        return {"state": "DORMANT", "adx": round(adx_val, 1)}

    def _handle_alert(self, now: float) -> Dict:
        """ALERT: 횡보 끝 징조. Scanner ON이면 3분, OFF면 15분 간격."""
        # Scanner ON이면 짧게: ALERT는 DORMANT보다 HUNT에 가까우니 더 자주 확인
        scanner_active = self.config.scanner_entry and self.config.max_positions > 1
        alert_interval = 180.0 if scanner_active else 900.0  # 3분 / 15분
        if now - self.last_scan_ts < alert_interval:
            remaining = alert_interval - (now - self.last_scan_ts)
            return {"state": "ALERT", "next_scan_in": round(remaining)}

        self.last_scan_ts = now
        check_market = self.config.lock_market.upper() if self.config.lock_market else "BTCUSDT"
        adx_data = self._fetch_primary_adx(check_market)

        if not adx_data:
            return {"state": "ALERT", "reason": "adx_fetch_failed"}

        adx_val = adx_data["adx"]

        if adx_val >= self.config.min_adx_entry:
            # 추세 확정 → HUNT
            self.state = FocusState.HUNT
            self._completed_dormant_cycle = True
            self.last_scan_ts = 0  # [2026-04-09] HUNT 전환 후 즉시 스캔
            self._save_config()
            logger.info("[FOCUS] ALERT → HUNT (ADX %.1f >= %d)", adx_val, self.config.min_adx_entry)
            return {"state": "HUNT", "adx": round(adx_val, 1)}

        if adx_val < self.config.dormant_adx_threshold:
            # 다시 빠짐 → DORMANT
            self.state = FocusState.DORMANT
            self._save_config()
            logger.info("[FOCUS] ALERT → DORMANT (ADX %.1f < %d)", adx_val, self.config.dormant_adx_threshold)
            return {"state": "DORMANT", "adx": round(adx_val, 1)}

        # ── Scanner 독립 HUNT: ALERT에서도 scanner 코인 강세면 HUNT ──
        if self.config.scanner_entry and self.config.max_positions > 1:
            try:
                candidates = self._get_scanner_candidates()
                hunt_ready = [c for c in candidates
                              if c.get("adx", 0) >= self.config.scanner_min_adx]
                if hunt_ready:
                    best = max(hunt_ready, key=lambda c: c.get("adx", 0))
                    self.state = FocusState.HUNT
                    self._save_config()
                    logger.info("[FOCUS] ALERT → HUNT (primary %s ADX=%.1f, "
                                "scanner %s ADX=%.1f triggered)",
                                check_market, adx_val,
                                best["market"], best["adx"])
                    return {"state": "HUNT", "adx": round(adx_val, 1),
                            "scanner_trigger": best["market"]}
            except Exception as exc:
                logger.debug("[FOCUS] Scanner check in ALERT failed: %s", exc)

        return {"state": "ALERT", "adx": round(adx_val, 1)}

    def _handle_hunt(self, now: float, btc_price: float) -> Dict:
        """HUNT: 기존 SELECTING + WATCHING + ZONE_WAIT 통합. scan_interval_sec 간격."""
        # 스캔 간격 체크
        if now - self.last_scan_ts < self.config.scan_interval_sec:
            remaining = self.config.scan_interval_sec - (now - self.last_scan_ts)
            return {"state": "HUNT", "next_scan_in": round(remaining)}

        self.last_scan_ts = now

        # ── ADX 재확인: 임계값 아래면 DORMANT 복귀 (단, Scanner 강세면 유지) ──
        if self.config.adx_filter_enabled:
            check_market = self.config.lock_market.upper() if self.config.lock_market else "BTCUSDT"
            adx_data = self._fetch_primary_adx(check_market)
            if adx_data and adx_data["adx"] < self.config.dormant_adx_threshold:
                # Scanner 코인 중 강세가 있으면 HUNT 유지
                scanner_keeps_hunt = False
                if self.config.scanner_entry and self.config.max_positions > 1:
                    try:
                        cands = self._get_scanner_candidates()
                        scanner_keeps_hunt = any(
                            c.get("adx", 0) >= self.config.scanner_min_adx for c in cands)
                    except Exception as exc:
                        logger.debug("[FOCUS] cands failed: %s", exc)
                if not scanner_keeps_hunt:
                    self.state = FocusState.DORMANT
                    self._save_config()
                    logger.info("[FOCUS] HUNT → DORMANT (ADX %.1f < %d, no scanner candidates)",
                                adx_data["adx"], self.config.dormant_adx_threshold)
                    return {"state": "DORMANT", "reason": "adx_below_threshold"}
                else:
                    logger.info("[FOCUS] HUNT maintained: primary %s ADX=%.1f low, "
                                "but scanner has active candidates",
                                check_market, adx_data["adx"])

        # ── 슬롯 + 일일제한 체크 ──
        open_count = len(self.positions)
        if open_count >= self.config.max_positions:
            # [2026-05-29 부모] Slot Auto Expand 가능성 — 슬롯 가득해도 강신호 시 +1 진입 허용
            if not self._slot_auto_expand_can_try():
                return {"state": "HUNT", "skip": f"full({open_count}/{self.config.max_positions})"}
        if self.daily_plans_used >= self.config.max_daily_plans or \
           self.daily_sl_count >= self.config.max_daily_sl:
            return {"state": "HUNT", "skip": "daily_limit"}

        # ── 잔고 사전 체크: 빈 슬롯 있어도 돈 없으면 스캔 생략 (API 낭비 방지) ──
        _skip_new_entry = False
        if open_count < self.config.max_positions:
            try:
                _bal = self._get_client().get_balance("USDT")
                _avail = float(_bal) if not isinstance(_bal, dict) else float(
                    _bal.get("available", 0) or _bal.get("availableBalance", 0) or 0)
                if _avail < 5.0:
                    _skip_new_entry = True
                    # 잔고 부족 시 다음 스캔 5분 뒤로 연기 (API 절약)
                    self.last_scan_ts = now + 240  # 60s 기본 + 240 = 5분 뒤
                    logger.info("[FOCUS] No budget ($%.2f) — skipping scan, retry in 5min", _avail)
            except Exception as exc:
                logger.debug("[FOCUS] _bal failed: %s", exc)  # 잔고 조회 실패 시 스캔은 진행

        if not _skip_new_entry:
            # ── lock_market 코인 분석 또는 자동 선택 ──
            if self.config.lock_market:
                result = self._hunt_locked_market(now, btc_price)
            else:
                result = self._hunt_scan_market(now, btc_price)

            # -- Scanner multi-slot --
            # [2026-05-29 부모] Slot Auto Expand 시 slot 가득해도 scanner 작동 허용
            _slot_room_ok = (
                len(self.positions) < self.config.max_positions
                or self._slot_auto_expand_can_try()
            )
            if (self.config.scanner_entry
                    and _slot_room_ok
                    and self.daily_plans_used < self.config.max_daily_plans):
                try:
                    scanner_result = self._hunt_scanner_candidates(now, btc_price)
                    result.update(scanner_result)
                except Exception as exc:
                    logger.warning("[FOCUS] scanner hunt error: %s", exc)
        else:
            result = {"state": "HUNT", "skip": "no_budget"}

        return result

    def _hunt_locked_market(self, now: float, btc_price: float) -> Dict:
        """HUNT에서 lock_market 코인 분석 + 진입."""
        locked = self.config.lock_market.upper()

        # ── H4 분석 ──
        direction = "HOLD"  # [2026-04-17] LONG → HOLD: 분석 실패 시 진입하지 않음
        candles_primary = []
        atr_val = 0
        _primary_trend = ""  # H4 추세 (whale override 제한용)
        _trend_pa_conflict = False  # [2026-04-17] PA↔추세 충돌 플래그
        try:
            from app.strategy.greenpen import full_analysis
            from app.strategy.greenpen.pa_detector import OHLCV
            raw = self._get_client().get_kline(locked, interval=self.config.primary_tf, limit=100)
            candles_primary = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4])) for r in raw if len(r) >= 5]
            if len(candles_primary) >= 20:
                analysis = full_analysis(candles_primary)
                pa_list = getattr(analysis, 'pa_signals', []) or []
                struct = getattr(analysis, 'structure', None)
                trend_val = ""
                if struct and hasattr(struct, 'trend'):
                    trend_val = struct.trend.value if hasattr(struct.trend, 'value') else str(struct.trend)
                    _primary_trend = trend_val
                if pa_list:
                    best_pa = pa_list[0]
                    direction = best_pa.direction.value
                    # [2026-04-17] 추세-PA 충돌 시: PA 방향 유지 + conviction 감점 (추세 강제 override 제거)
                    if trend_val and (
                        (direction == "SHORT" and trend_val == "UPTREND") or
                        (direction == "LONG" and trend_val == "DOWNTREND")
                    ):
                        # PA가 감지한 반전 신호를 존중 — 특히 꼭대기에서 PA SHORT는 중요
                        logger.info("[FOCUS] HUNT %s: PA=%s vs trend=%s — keeping PA direction, conviction -3",
                                    locked, direction, trend_val)
                        # conviction 감점은 아래 conviction 계산 후 적용 (플래그 저장)
                        _trend_pa_conflict = True
                    else:
                        _trend_pa_conflict = False
                elif trend_val == "DOWNTREND":
                    direction = "SHORT"
                elif trend_val == "UPTREND":
                    direction = "LONG"
                elif trend_val == "SIDEWAYS":
                    # [2026-04-18] SIDEWAYS BB 방향 결정 — locked HUNT에도 Phase 2-1 확장
                    # BB 70%+ → 상단 접근 → SHORT / BB 30%- → 하단 접근 → LONG
                    # 30~70% → HOLD (direction 유지)
                    # 안전망: conviction 검사 + BB 하드블록(15%-) + M5 역추세 체크
                    try:
                        from app.strategy.indicators import bollinger_bands as _lsw_bb_fn
                        _lsw_closes = [c.close for c in candles_primary]
                        _lsw_bb = _lsw_bb_fn(_lsw_closes, 20, 2.0)
                        if _lsw_bb and _lsw_bb["upper"] > _lsw_bb["lower"]:
                            _lsw_bb_pct = (_lsw_closes[-1] - _lsw_bb["lower"]) / (_lsw_bb["upper"] - _lsw_bb["lower"]) * 100
                            if _lsw_bb_pct > 70:
                                direction = "SHORT"
                                logger.info("[FOCUS] HUNT locked %s: SIDEWAYS + BB%.0f%% > 70 → SHORT (mean reversion)", locked, _lsw_bb_pct)
                            elif _lsw_bb_pct < 30:
                                direction = "LONG"
                                logger.info("[FOCUS] HUNT locked %s: SIDEWAYS + BB%.0f%% < 30 → LONG (mean reversion)", locked, _lsw_bb_pct)
                            # 30~70% → HOLD 유지 (direction="HOLD"로 line 2573에서 skip)
                    except Exception as exc:
                        logger.debug("[FOCUS] HUNT locked SIDEWAYS BB check failed: %s", exc)

                if self.config.direction_mode == "long_only":
                    direction = "LONG"
                elif self.config.direction_mode == "short_only":
                    direction = "SHORT"

                atr_val = getattr(analysis, 'atr', 0) or 0
                self.primary_sig = {
                    "pattern": pa_list[0].pattern.value if pa_list else "-",
                    "direction": direction,
                    "confidence": pa_list[0].confidence if pa_list else 0,
                    "atr": atr_val,
                }
                zones_raw = getattr(analysis, 'zones', []) or []
                self.zones = [{"type": getattr(z, 'type', {}).value if hasattr(getattr(z, 'type', None), 'value') else str(getattr(z, 'type', '')),
                               "price_low": getattr(z, 'price_low', 0), "price_high": getattr(z, 'price_high', 0),
                               "strength": getattr(z, 'strength', 1.0)}
                              for z in zones_raw]
        except Exception as exc:
            logger.warning("[FOCUS] HUNT lock analysis failed: %s — direction=HOLD (no blind entry)", exc)

        # [2026-04-17] HOLD 상태면 분석 실패 — 진입하지 않음
        if direction == "HOLD":
            logger.info("[FOCUS] HUNT %s: direction=HOLD after analysis — skipping entry", locked)
            return {"state": "HUNT", "market": locked, "skip": "no_direction(HOLD)"}

        self.selected_market = locked
        self.selected_direction = direction

        # ── 양방향 평가 (Phase 2) — 방향 확정 + conviction (아래 BB penalty·reentry 가 새 방향에 적용) ──
        _signal_dir = direction
        direction, conviction, _dd_info = self._pick_best_direction(locked, candles_primary, self._zones_for_pa(), _signal_dir)
        if _dd_info.get("flipped"):
            self.selected_direction = direction
            logger.info("[FOCUS] DualDir(locked) 방향 교체: %s→%s (conv %.0f)", _signal_dir, direction, conviction)

        # ★ Peak Fade 감점 — 봉우리가 꺾이면 conviction 차감
        _pf_penalty = self._peak_fade_penalty(candles_primary, direction)
        if _pf_penalty:
            conviction = max(0, conviction + _pf_penalty)

        # ★ [2026-04-17] PRIMARY BB 위치 감점: overbought/oversold 구간에서 추세 방향 진입 감점
        # BB 75%+ & LONG → -2, BB 25%- & SHORT → -2
        _bb_pos_penalty = 0
        if candles_primary and len(candles_primary) >= 20:
            try:
                from app.strategy.indicators import bollinger_bands as _bb_conv_fn
                _conv_closes = [c.close for c in candles_primary]
                _conv_bb = _bb_conv_fn(_conv_closes, 20, 2.0)
                if _conv_bb and _conv_bb["upper"] > _conv_bb["lower"]:
                    _conv_bb_pct = (_conv_closes[-1] - _conv_bb["lower"]) / (_conv_bb["upper"] - _conv_bb["lower"]) * 100
                    # ★ [2026-04-17] BB hardblock (ORDI 교훈)
                    # [2026-05-19 부모 결정] dataclass 화 — UI 조정 가능, 대칭 가정 (LONG > X / SHORT < 100-X)
                    _bb_block_t = float(getattr(self.config, 'bb_block_threshold_pct', 85.0))
                    _bb_pen_t = float(getattr(self.config, 'bb_penalty_threshold_pct', 75.0))
                    _bb_pen_amt = float(getattr(self.config, 'bb_penalty_amount', 20.0))
                    if direction == "LONG" and _conv_bb_pct > _bb_block_t:
                        _tr_byp, _tr_adx = self._bb_trend_riding(direction, _conv_closes)
                        if self._guard_score_mode_active():
                            logger.info("[FOCUS] HUNT %s: BB%.0f%% extreme(LONG) — guard_score_mode bypass", locked, _conv_bb_pct)
                        elif _tr_byp:
                            logger.info("[FOCUS] HUNT %s: BB%.0f%% extreme(LONG) BUT ADX%.0f≥강추세 벽타기 → 통과", locked, _conv_bb_pct, _tr_adx)
                        else:
                            logger.info("[FOCUS] HUNT %s: PRIMARY BB%.0f%% > %.0f%% + LONG → BLOCKED (extreme overbought)",
                                        locked, _conv_bb_pct, _bb_block_t)
                            self._record_skip(locked, direction, conviction, (self.primary_sig or {}).get("pattern", "-"),
                                              f"bb_extreme_overbought(BB={_conv_bb_pct:.0f}%)")
                            return {"state": "HUNT", "market": locked, "conviction": conviction, "skip": "bb_extreme_overbought"}
                    elif direction == "SHORT" and _conv_bb_pct < (100.0 - _bb_block_t):
                        _tr_byp, _tr_adx = self._bb_trend_riding(direction, _conv_closes)
                        if self._guard_score_mode_active():
                            logger.info("[FOCUS] HUNT %s: BB%.0f%% extreme(SHORT) — guard_score_mode bypass", locked, _conv_bb_pct)
                        elif _tr_byp:
                            logger.info("[FOCUS] HUNT %s: BB%.0f%% extreme(SHORT) BUT ADX%.0f≥강추세 벽타기 → 통과", locked, _conv_bb_pct, _tr_adx)
                        else:
                            logger.info("[FOCUS] HUNT %s: PRIMARY BB%.0f%% < %.0f%% + SHORT → BLOCKED (extreme oversold)",
                                        locked, _conv_bb_pct, 100.0 - _bb_block_t)
                            self._record_skip(locked, direction, conviction, (self.primary_sig or {}).get("pattern", "-"),
                                              f"bb_extreme_oversold(BB={_conv_bb_pct:.0f}%)")
                            return {"state": "HUNT", "market": locked, "conviction": conviction, "skip": "bb_extreme_oversold"}
                    elif direction == "LONG" and _conv_bb_pct > _bb_pen_t:
                        _bb_pos_penalty = -int(_bb_pen_amt)
                        conviction = max(0.0, conviction - _bb_pen_amt)
                        logger.info("[FOCUS] HUNT %s: PRIMARY BB%.0f%% > %.0f%% + LONG → conviction -%.0f → %.1f",
                                    locked, _conv_bb_pct, _bb_pen_t, _bb_pen_amt, conviction)
                    elif direction == "SHORT" and _conv_bb_pct < (100.0 - _bb_pen_t):
                        _bb_pos_penalty = -int(_bb_pen_amt)
                        conviction = max(0.0, conviction - _bb_pen_amt)
                        logger.info("[FOCUS] HUNT %s: PRIMARY BB%.0f%% < %.0f%% + SHORT → conviction -%.0f → %.1f",
                                    locked, _conv_bb_pct, 100.0 - _bb_pen_t, _bb_pen_amt, conviction)
            except Exception as _bbe:
                logger.debug("[FOCUS] PRIMARY BB conviction penalty error: %s", _bbe)

        # ★ [2026-04-17 → 2026-05-17 100점 ×10] 추세-PA 충돌 감점: PA 방향 유지하되 conviction -30 (옛 -3)
        if _trend_pa_conflict:
            conviction = max(0.0, conviction - 30.0)
            logger.info("[FOCUS] HUNT %s: trend-PA conflict penalty → conviction=%.1f", locked, conviction)

        # ★ WhaleRadar — 비활성화 (2026-04-12): 관찰만, conviction/방향 영향 없음
        _whale_score = 0
        # try:
        #     from app.core.whale_radar import whale_radar
        #     raw_5m = self._get_client().get_kline(locked, interval="5", limit=120)
        #     _wsig = whale_radar.scan(locked, raw_5m)
        #     if _wsig:
        #         _whale_score = _wsig.score
        # except Exception:
        #     pass

        logger.info("[FOCUS] HUNT %s: direction=%s conviction=%d whale=%d (min=%d)",
                     locked, direction, conviction, _whale_score, self.config.min_conviction)

        # ── Event Shield: 경제이벤트 윈도우 신규진입 hard block (conviction 무관) ──
        _es_label = self._event_shield_label()
        if _es_label:
            logger.info("[FOCUS] Event Shield(%s): entry blocked %s — event window", _es_label, locked)
            self._record_skip(locked, direction, conviction, (self.primary_sig or {}).get("pattern", "-"),
                              f"event_shield({_es_label})")
            return {"state": "HUNT", "market": locked, "conviction": conviction, "skip": "event_shield"}

        _min_conv = self.config.min_conviction
        if self._is_morning_guard_active():
            _min_conv += self.config.morning_guard_conviction_boost
        if conviction < _min_conv:
            if _min_conv > self.config.min_conviction:
                logger.info("[FOCUS] Morning Guard: entry blocked %s, conviction %d < %d (morning +%d)",
                             locked, conviction, _min_conv, self.config.morning_guard_conviction_boost)
            self._record_skip(locked, direction, conviction, (self.primary_sig or {}).get("pattern", "-"),
                              f"low_conviction({conviction}<{_min_conv})")
            return {"state": "HUNT", "market": locked, "conviction": conviction, "skip": "low_conviction"}

        # ── 재진입 차단 체크 ──
        price = self._get_current_price(locked)
        if not price or price <= 0:
            return {"state": "HUNT", "error": "no_price"}
        if not self._check_reentry_allowed(direction, locked, price):
            self._record_skip(locked, direction, conviction, (self.primary_sig or {}).get("pattern", "-"),
                              "reentry_blocked")
            return {"state": "HUNT", "market": locked, "skip": "reentry_blocked"}

        # ── M5 진입 확인 ──
        try:
            from app.manager.focus_entry_signal import check_m5_entry
            entry = check_m5_entry(
                self._get_client(), locked, direction, self.config.entry_tf,
                btc_price=btc_price, zones=self.zones,
            )
        except Exception as exc:
            logger.warning("[FOCUS] HUNT M5 check failed: %s", exc)
            entry = None

        if entry and entry.get("enter"):
            entry.setdefault("market", locked)
            entry["conviction_score"] = conviction
            # ★ [2026-05-11 Phase 1+2] mtf/mom/zone/align 정보 phase 에 박음 (저널 분석용)
            _p1_mods = getattr(self, '_last_conviction_breakdown', {}) or {}
            _mtf_pen = _p1_mods.get('mtf_pen', 0)
            _mom_pen = _p1_mods.get('mom_pen', 0)
            _zone_pos = _p1_mods.get('zone_pos', 0)
            _mom_align = _p1_mods.get('mom_align', 0)
            entry["_conviction_modifiers"] = f"peak_fade={_pf_penalty},bb_pos={_bb_pos_penalty},whale={_whale_score},mtf={_mtf_pen},mom={_mom_pen},zone={_zone_pos},align={_mom_align}"
            budget = self._compute_entry_budget(conviction, locked)
            entry["conviction_budget"] = budget
            # ★ 최소 예산 체크: $5 미만이면 진입 불가
            if budget < 5.0:
                logger.info("[FOCUS] HUNT %s budget $%.1f < $5 — skip entry", locked, budget)
                return {"state": "HUNT", "market": locked, "skip": f"budget_too_low(${budget:.1f})"}
            return self._execute_entry(entry)

        # H4 고신뢰도 직접 진입 (기존 로직 유지)
        primary_conf = float((self.primary_sig or {}).get("confidence", 0) or 0)
        if primary_conf >= 0.85:
            # M5 추세 확인
            try:
                from app.strategy.greenpen.pa_detector import OHLCV
                from app.strategy.greenpen.market_structure import analyze_structure as _az
                m5_raw = self._get_client().get_kline(locked, interval=self.config.entry_tf, limit=20)
                m5_candles = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4])) for r in m5_raw if len(r) >= 5]
                if len(m5_candles) >= 10:
                    _m5s = _az(m5_candles, lookback=3)
                    _m5t = _m5s.trend.value if hasattr(_m5s.trend, 'value') else str(_m5s.trend)
                    if (direction == "LONG" and _m5t == "DOWNTREND") or \
                       (direction == "SHORT" and _m5t == "UPTREND"):
                        return {"state": "HUNT", "market": locked, "skip": "m5_against"}
            except Exception as exc:
                logger.debug("[FOCUS] import OHLCV failed: %s", exc)

            atr = atr_val if atr_val > 0 else price * 0.02
            primary_budget = self._compute_entry_budget(conviction, locked)
            if primary_budget < 5.0:
                return {"state": "HUNT", "market": locked, "skip": f"primary_budget_too_low(${primary_budget:.1f})"}
            return self._execute_entry({
                "enter": True, "direction": direction,
                "market": locked, "price": price, "atr": atr,
                "reason": f"primary_high_conf:{primary_conf:.0%}",
                "conviction_score": conviction,
                "conviction_budget": primary_budget,
            })

        return {"state": "HUNT", "market": locked, "direction": direction, "conviction": conviction}

    def _hunt_scan_market(self, now: float, btc_price: float) -> Dict:
        """HUNT에서 자동 코인 선택 + 진입."""
        try:
            from app.manager.focus_coin_selector import select_focus_coin
            result = select_focus_coin(
                self.system, self._get_client(),
                direction_mode=self.config.direction_mode,
                primary_tf=self.config.primary_tf,
            )
        except Exception as exc:
            logger.warning("[FOCUS] HUNT scan failed: %s", exc)
            return {"state": "HUNT", "error": str(exc)}

        if not result or not result.get("market"):
            return {"state": "HUNT", "result": "no_candidate"}

        market = result["market"]
        # [2026-04-18] LONG fallback 제거 — direction 없으면 skip
        direction = result.get("direction")
        if not direction or direction not in ("LONG", "SHORT"):
            logger.info("[FOCUS] HUNT scan skip %s: no valid direction", market)
            return {"state": "HUNT", "skip": "no_direction"}
        conf = float(result.get("confidence", 0) or 0)

        # ★ 단가 짜잘이 필터 (config 로 조정 가능, 2026-04-25 0.10 default)
        _min_price_filter = float(getattr(self.config, "scanner_min_price_usdt", 0.10))
        _scan_price = float(result.get("price", 0) or 0)
        if 0 < _scan_price < _min_price_filter:
            logger.info("[FOCUS] HUNT scan skip %s: price $%.4f < $%.2f", market, _scan_price, _min_price_filter)
            return {"state": "HUNT", "skip": f"low_price(${_scan_price:.2f})"}

        # 블랙리스트 체크
        bl = getattr(self, '_temp_blacklist', {})
        if market in bl and bl[market] > time.time():
            return {"state": "HUNT", "skip": "blacklisted"}

        # 이미 보유 체크
        held = {p.market for p in self.positions}
        if market in held:
            return {"state": "HUNT", "skip": "already_held"}

        # ★ Cross-strategy guard: Nunnaya가 이미 이 마켓을 보유 중이면 진입 불가
        try:
            from app.core.cross_strategy_guard import is_market_owned_by_other
            _other = is_market_owned_by_other(self.system, market, "FOCUS")
            if _other:
                logger.warning("[FOCUS] BLOCKED: %s already held by %s (qty=%.4f) — cross-strategy guard",
                               market, _other.owner, _other.qty)
                return {"state": "HUNT", "skip": "cross_strategy_conflict"}
        except Exception as exc:
            logger.debug("[FOCUS] cross_strategy_guard scan check: %s", exc)

        # price_store 등록
        try:
            if self.system:
                feed = getattr(self.system, "price_feed", None)
                if feed and hasattr(feed, "add_symbol"):
                    feed.add_symbol(market)
        except Exception as exc:
            logger.debug("[FOCUS] if self.system: failed: %s", exc)

        self.selected_market = market
        self.selected_direction = direction
        self.zones = result.get("zones", [])
        self.primary_sig = result.get("primary_sig")

        # Conviction 계산
        candles_primary = []
        try:
            from app.strategy.greenpen.pa_detector import OHLCV
            raw = self._get_client().get_kline(market, interval=self.config.primary_tf, limit=60)
            candles_primary = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4])) for r in raw if len(r) >= 5]
        except Exception as exc:
            logger.debug("[FOCUS] import OHLCV failed: %s", exc)
        # ── 양방향 평가 (Phase 2) — 방향 확정 + conviction (아래 게이트가 새 방향에 적용) ──
        _signal_dir = direction
        direction, conviction, _dd_info = self._pick_best_direction(market, candles_primary, self._zones_for_pa(), _signal_dir)
        if _dd_info.get("flipped"):
            self.selected_direction = direction
            logger.info("[FOCUS] DualDir(scan) 방향 교체: %s→%s (conv %.0f)", _signal_dir, direction, conviction)

        # ★ Peak Fade 감점
        _pf_penalty = self._peak_fade_penalty(candles_primary, direction)
        if _pf_penalty:
            conviction = max(0, conviction + _pf_penalty)

        # ★ [2026-04-17] PRIMARY BB 위치 감점: overbought/oversold 구간에서 추세 방향 진입 감점
        if candles_primary and len(candles_primary) >= 20:
            try:
                from app.strategy.indicators import bollinger_bands as _bb_scan_fn
                _scan_bb_closes = [c.close for c in candles_primary]
                _scan_bb = _bb_scan_fn(_scan_bb_closes, 20, 2.0)
                if _scan_bb and _scan_bb["upper"] > _scan_bb["lower"]:
                    _scan_bb_pct = (_scan_bb_closes[-1] - _scan_bb["lower"]) / (_scan_bb["upper"] - _scan_bb["lower"]) * 100
                    # ★ [2026-04-17] BB hardblock (ORDI 교훈) / [2026-05-19] dataclass 화
                    _bb_block_t = float(getattr(self.config, 'bb_block_threshold_pct', 85.0))
                    _bb_pen_t = float(getattr(self.config, 'bb_penalty_threshold_pct', 75.0))
                    _bb_pen_amt = float(getattr(self.config, 'bb_penalty_amount', 20.0))
                    # Scanner 는 옛 코드가 -2 였음 (Phase 5 정정 누락) — 메인과 일관성 위해 _bb_pen_amt 사용
                    if direction == "LONG" and _scan_bb_pct > _bb_block_t:
                        _tr_byp, _tr_adx = self._bb_trend_riding(direction, _scan_bb_closes)
                        if self._guard_score_mode_active():
                            logger.info("[FOCUS] HUNT scan %s: BB%.0f%% extreme(LONG) — guard_score_mode bypass", market, _scan_bb_pct)
                        elif _tr_byp:
                            logger.info("[FOCUS] HUNT scan %s: BB%.0f%% extreme(LONG) BUT ADX%.0f≥강추세 벽타기 → 통과", market, _scan_bb_pct, _tr_adx)
                        else:
                            logger.info("[FOCUS] HUNT scan %s: PRIMARY BB%.0f%% > %.0f%% + LONG → BLOCKED (extreme overbought)",
                                        market, _scan_bb_pct, _bb_block_t)
                            return {"state": "HUNT", "market": market, "conviction": conviction, "skip": "bb_extreme_overbought"}
                    elif direction == "SHORT" and _scan_bb_pct < (100.0 - _bb_block_t):
                        _tr_byp, _tr_adx = self._bb_trend_riding(direction, _scan_bb_closes)
                        if self._guard_score_mode_active():
                            logger.info("[FOCUS] HUNT scan %s: BB%.0f%% extreme(SHORT) — guard_score_mode bypass", market, _scan_bb_pct)
                        elif _tr_byp:
                            logger.info("[FOCUS] HUNT scan %s: BB%.0f%% extreme(SHORT) BUT ADX%.0f≥강추세 벽타기 → 통과", market, _scan_bb_pct, _tr_adx)
                        else:
                            logger.info("[FOCUS] HUNT scan %s: PRIMARY BB%.0f%% < %.0f%% + SHORT → BLOCKED (extreme oversold)",
                                        market, _scan_bb_pct, 100.0 - _bb_block_t)
                            return {"state": "HUNT", "market": market, "conviction": conviction, "skip": "bb_extreme_oversold"}
                    elif direction == "LONG" and _scan_bb_pct > _bb_pen_t:
                        conviction = max(0, conviction - _bb_pen_amt)
                        logger.info("[FOCUS] HUNT scan %s: PRIMARY BB%.0f%% > %.0f%% + LONG → conviction -%.0f → %d",
                                    market, _scan_bb_pct, _bb_pen_t, _bb_pen_amt, conviction)
                    elif direction == "SHORT" and _scan_bb_pct < (100.0 - _bb_pen_t):
                        conviction = max(0, conviction - _bb_pen_amt)
                        logger.info("[FOCUS] HUNT scan %s: PRIMARY BB%.0f%% < %.0f%% + SHORT → conviction -%.0f → %d",
                                    market, _scan_bb_pct, 100.0 - _bb_pen_t, _bb_pen_amt, conviction)
            except Exception as exc:
                logger.debug("[FOCUS] import bollinger_bands as _bb_scan_fn failed: %s", exc)

        # ── Event Shield: 경제이벤트 윈도우 신규진입 hard block (conviction 무관) ──
        _es_label = self._event_shield_label()
        if _es_label:
            logger.info("[FOCUS] Event Shield(%s): scan entry blocked %s — event window", _es_label, market)
            self._record_skip(market, direction, conviction, str(result.get("pa_pattern", "-")),
                              f"event_shield({_es_label})")
            return {"state": "HUNT", "market": market, "conviction": conviction, "skip": "event_shield"}

        _min_conv = self.config.min_conviction
        if self._is_morning_guard_active():
            _min_conv += self.config.morning_guard_conviction_boost
        if conviction < _min_conv:
            if self._guard_score_mode_active():
                logger.info("[FOCUS] HUNT scan %s: conv=%d<%d — guard_score_mode bypass (점수 평가에 위임)",
                            market, conviction, _min_conv)
            else:
                if _min_conv > self.config.min_conviction:
                    logger.info("[FOCUS] Morning Guard: scan entry blocked %s, conviction %d < %d (morning +%d)",
                                 market, conviction, _min_conv, self.config.morning_guard_conviction_boost)
                self._record_skip(market, direction, conviction, str(result.get("pa_pattern", "-")),
                                  f"scan_low_conviction({conviction}<{_min_conv})")
                return {"state": "HUNT", "market": market, "conviction": conviction, "skip": "low_conviction"}

        # 재진입 차단 체크
        price = float(result.get("price", 0) or 0)
        if not price or price <= 0:
            price = self._get_current_price(market) or 0
        if price <= 0:
            return {"state": "HUNT", "error": "no_price"}
        if not self._check_reentry_allowed(direction, market, price):
            self._record_skip(market, direction, conviction, str(result.get("pa_pattern", "-")),
                              "scan_reentry_blocked")
            return {"state": "HUNT", "market": market, "skip": "reentry_blocked"}

        if conf >= 0.85:
            atr = float(result.get("atr", 0) or price * 0.02)
            scan_budget = self._compute_entry_budget(conviction, market)
            if scan_budget < 5.0:
                logger.info("[FOCUS] HUNT scan %s budget $%.1f < $5 — skip", market, scan_budget)
                return {"state": "HUNT", "market": market, "skip": f"budget_too_low(${scan_budget:.1f})"}
            logger.info("[FOCUS] HUNT scan: %s %s conf=%.0f%% conviction=%d budget=$%.1f",
                        direction, market, conf * 100, conviction, scan_budget)
            entry_result = self._execute_entry({
                "enter": True, "market": market, "direction": direction,
                "price": price, "atr": atr,
                "reason": f"hunt_scan_conf:{conf:.0%}",
                "conviction_score": conviction,
                "conviction_budget": scan_budget,
                "_conviction_modifiers": f"peak_fade={_pf_penalty}",
            })
            if entry_result.get("state") == "POSITIONED":
                self.last_scan_ts = 0  # 즉시 재스캔
            return entry_result

        return {"state": "HUNT", "market": market, "conviction": conviction}

    # ── Scanner Multi-Slot helpers ─────────────────────────────

    def _get_scanner_candidates(self) -> list:
        """Top 10 scanner candidates for multi-slot entry."""
        try:
            from app.strategy.greenpen import full_analysis
            from app.strategy.greenpen.pa_detector import OHLCV
            from app.core.constants import BYBIT_MARKET_TICKERS, parse_bybit_list
            from app.core.rate_limiter import bybit_get
            from app.strategy.indicators import adx as _adx_fn

            resp = bybit_get(BYBIT_MARKET_TICKERS, params={"category": "linear"}, timeout=10)
            resp.raise_for_status()
            tickers = parse_bybit_list(resp.json())

            # ★ [2026-04-25 universe 확장] config 로 조정 가능
            min_turnover = float(getattr(self.config, "scanner_min_turnover_24h", 1_000_000.0))
            min_price = float(getattr(self.config, "scanner_min_price_usdt", 0.10))
            top_n = int(getattr(self.config, "scanner_top_n", 20))

            scored = []
            for t in tickers:
                if not isinstance(t, dict):
                    continue
                symbol = str(t.get("symbol", ""))
                if not symbol.endswith("USDT"):
                    continue
                turnover = float(t.get("turnover24h", 0) or 0)
                if turnover < min_turnover:
                    continue
                last_price = float(t.get("lastPrice", 0) or 0)
                # ★ 단가 짜잘이 필터 (config 로 조정 가능)
                if last_price < min_price:
                    continue
                scored.append({"symbol": symbol, "turnover": turnover,
                              "price": last_price})

            scored.sort(key=lambda x: -x["turnover"])
            candidates = scored[:top_n]

            results = []
            client = self._get_client()
            for c in candidates:
                symbol = c["symbol"]
                try:
                    raw = client.get_kline(symbol, interval=self.config.primary_tf, limit=60)
                    candles = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4]),
                               volume=float(r[5]) if len(r) > 5 else 0)
                              for r in raw if len(r) >= 5]
                    if len(candles) < 10:
                        continue
                    gp = full_analysis(candles)
                    # ── [2026-05-20 Phase 6 Stage 0] Energy bar 시계열 캐시 ──
                    #   부모님 직감 룰 기반: 코인별 (ts, trend, confidence) 적재.
                    #   _get_trend_velocity 가 이 데이터로 변화율 계산 → Energy 모드 트리거.
                    try:
                        _gp_trend = gp.structure.trend.value  # UPTREND/DOWNTREND/SIDEWAYS
                        _gp_conf = float(getattr(gp.structure, "confidence", 0.0))
                        _hist = self._confidence_history.get(symbol)
                        if _hist is None:
                            _hist = deque(maxlen=self._confidence_history_maxlen)
                            self._confidence_history[symbol] = _hist
                        _hist.append((time.time(), _gp_trend, _gp_conf))
                    except Exception:
                        pass
                    signal = "HOLD"
                    pa_name = "-"
                    _sw_flag = False  # [2026-04-18] SIDEWAYS BB mean reversion 플래그
                    if gp.pa_signals:
                        best = gp.pa_signals[0]
                        signal = "BUY" if best.direction.value == "LONG" else "SELL"
                        pa_name = best.pattern.value
                    else:
                        # [2026-04-09] Market structure fallback — BOS / Trend
                        _struct = gp.structure
                        _bos = getattr(_struct, "bos", None)
                        if _bos and getattr(_bos, "detected", False):
                            signal = "BUY" if _bos.direction == "BULLISH" else "SELL"
                            pa_name = f"BOS_{_bos.direction}"
                        elif _struct.trend.value == "UPTREND":
                            signal = "BUY"
                            pa_name = "TREND_UP"
                        elif _struct.trend.value == "DOWNTREND":
                            signal = "SELL"
                            pa_name = "TREND_DN"
                        elif _struct.trend.value == "SIDEWAYS":
                            # [2026-04-18] SIDEWAYS BB 방향 결정 — mean reversion SHORT/LONG 기회 생성
                            # BB 70%+ → 상단 접근 → SELL / BB 30%- → 하단 접근 → BUY
                            # 30~70% → HOLD (중앙 = 방향 불명확)
                            # 3중 안전망: (1)BB 70/30 보수 (2)conviction 검사 (3)하단 BB hard block 85/15
                            # ── [2026-05-29 부모] entry_auto_flip_enabled=False 시 차단 ──
                            # 부모님 원칙: "자동 direction FLIP 영구 X" (5-28 ICP 사고 확장).
                            # mean reversion 도 *예상 신호 외 방향 결정* — FLIP 과 같은 의도.
                            if not bool(getattr(self.config, "entry_auto_flip_enabled", False)):
                                logger.debug("[FOCUS] Scanner %s: SIDEWAYS BB mean reversion skip (entry_auto_flip_enabled=False)", symbol)
                                # HOLD 유지 (signal 미정 → 다음 candidate 로)
                            else:
                                try:
                                    from app.strategy.indicators import bollinger_bands as _sw_bb_fn
                                    _sw_closes = [c.close for c in candles]
                                    _sw_bb = _sw_bb_fn(_sw_closes, 20, 2.0)
                                    if _sw_bb and _sw_bb["upper"] > _sw_bb["lower"]:
                                        _sw_bb_pct = (_sw_closes[-1] - _sw_bb["lower"]) / (_sw_bb["upper"] - _sw_bb["lower"]) * 100
                                        if _sw_bb_pct > 70:
                                            signal = "SELL"
                                            pa_name = "SW_UPPER_BB"
                                            _sw_flag = True
                                            logger.info("[FOCUS] Scanner %s: SIDEWAYS + BB%.0f%% > 70 → SELL (mean reversion)", symbol, _sw_bb_pct)
                                        elif _sw_bb_pct < 30:
                                            signal = "BUY"
                                            pa_name = "SW_LOWER_BB"
                                            _sw_flag = True
                                            logger.info("[FOCUS] Scanner %s: SIDEWAYS + BB%.0f%% < 30 → BUY (mean reversion)", symbol, _sw_bb_pct)
                                        # 30~70% → HOLD 유지
                                except Exception as exc:
                                    logger.debug("[FOCUS] SIDEWAYS BB check failed %s: %s", symbol, exc)
                    # ★ [2026-04-16] PRIMARY BB 극단 플립 — 과매수→SHORT / 과매도→LONG
                    # BB% > 110 = 고점 극단 → BUY를 SELL로 플립 (ORDI -$20 교훈)
                    # BB% < -10 = 저점 극단 → SELL을 BUY로 플립
                    # ※ 반드시 BB gate보다 먼저 실행 — 110%+ 에서 FLIP 기회를 gate가 삼키면 안 됨
                    _bb_flipped = False
                    _cached_bb_pct = None  # gate와 flip이 BB 계산 공유
                    # ── [2026-05-29 부모] entry_auto_flip_enabled=False 시 PRIMARY BB FLIP 차단 ──
                    # 부모님 원칙: "자동 direction FLIP 영구 X" (5-28 ICP 사고).
                    # NEAR 5-29 사고: PIN_BAR SELL → PRIMARY BB FLIP → BUY 진입 = 부모님 모순 인식.
                    # BB 계산은 진행 (cached_bb_pct gate 용도), FLIP 자체는 차단.
                    _auto_flip_ok = bool(getattr(self.config, "entry_auto_flip_enabled", False))
                    if signal in ("BUY", "SELL"):
                        try:
                            from app.strategy.indicators import bollinger_bands as _bb_fn
                            _primary_closes = [c.close for c in candles]
                            _primary_bb = _bb_fn(_primary_closes, 20, 2.0)
                            if _primary_bb and _primary_bb["upper"] > _primary_bb["lower"]:
                                _primary_bb_pct = (_primary_closes[-1] - _primary_bb["lower"]) / (_primary_bb["upper"] - _primary_bb["lower"]) * 100
                                _cached_bb_pct = _primary_bb_pct
                                if _primary_bb_pct > 110 and signal == "BUY":
                                    if _auto_flip_ok:
                                        logger.info("[FOCUS] Scanner %s: PRIMARY BB %.0f%% > 110%% → FLIP BUY→SELL (overbought)", symbol, _primary_bb_pct)
                                        signal = "SELL"
                                        pa_name = f"{pa_name}→PRIMARY_BB_FLIP_SHORT"
                                        _bb_flipped = True
                                    else:
                                        logger.info("[FOCUS] Scanner %s: PRIMARY BB %.0f%% > 110%% BUY FLIP skip (entry_auto_flip_enabled=False) → 신호 그대로 BUY", symbol, _primary_bb_pct)
                                elif _primary_bb_pct < -10 and signal == "SELL":
                                    if _auto_flip_ok:
                                        logger.info("[FOCUS] Scanner %s: PRIMARY BB %.0f%% < -10%% → FLIP SELL→BUY (oversold)", symbol, _primary_bb_pct)
                                        signal = "BUY"
                                        pa_name = f"{pa_name}→PRIMARY_BB_FLIP_LONG"
                                        _bb_flipped = True
                                    else:
                                        logger.info("[FOCUS] Scanner %s: PRIMARY BB %.0f%% < -10%% SELL FLIP skip (entry_auto_flip_enabled=False) → 신호 그대로 SELL", symbol, _primary_bb_pct)
                        except Exception as exc:
                            logger.debug("[FOCUS] import bollinger_bands as _bb_fn failed: %s", exc)

                    # ── [2026-05-20 부모님 재설계] Energy 모드 폐기 — Reverse 모드로 교체 ──
                    # 이전 Energy FLIP (confidence 변화율 기반) → 부모님 새 통찰 "낮은 conv + 낮은 ADX 자체가 자리".
                    # Reverse 모드 로직은 Scanner conv 산출 후 영역으로 이동 (entry_mode == "reverse" 일 때 작동).

                    # ★ [2026-04-17] PRIMARY BB 위치 게이트 — 추세/BOS 폴백에서 과매수/과매도 구간 차단
                    # BUY(TREND_UP/BOS_BULLISH) + BB 75~110% → HOLD (FLIP 대상 아닌 고점)
                    # SELL(TREND_DN/BOS_BEARISH) + BB -10~25% → HOLD (FLIP 대상 아닌 저점)
                    # ※ BB FLIP 이후 실행 — 110%+는 이미 FLIP됨, 75~110% 구간만 gate가 처리
                    if signal in ("BUY", "SELL") and not _bb_flipped and pa_name in ("TREND_UP", "TREND_DN", "BOS_BULLISH", "BOS_BEARISH"):
                        try:
                            if _cached_bb_pct is not None:
                                _gate_bb_pct = _cached_bb_pct
                            else:
                                from app.strategy.indicators import bollinger_bands as _bb_gate_fn
                                _gate_closes = [c.close for c in candles]
                                _gate_bb = _bb_gate_fn(_gate_closes, 20, 2.0)
                                _gate_bb_pct = None
                                if _gate_bb and _gate_bb["upper"] > _gate_bb["lower"]:
                                    _gate_bb_pct = (_gate_closes[-1] - _gate_bb["lower"]) / (_gate_bb["upper"] - _gate_bb["lower"]) * 100
                            if _gate_bb_pct is not None:
                                _tr_byp, _tr_adx = self._bb_trend_riding(signal, _gate_closes)
                                if signal == "BUY" and _gate_bb_pct > 75:
                                    if _tr_byp:
                                        logger.info("[FOCUS] Scanner %s: BB gate BUY BB%.0f%% BUT ADX%.0f≥강추세 벽타기 → 통과",
                                                    symbol, _gate_bb_pct, _tr_adx)
                                    else:
                                        logger.info("[FOCUS] Scanner %s: BB gate — %s BB%.0f%% > 75%% → HOLD (overbought for trend-buy)",
                                                    symbol, pa_name, _gate_bb_pct)
                                        signal = "HOLD"
                                        pa_name = f"{pa_name}→BB_GATE_HOLD"
                                        c["_block_reason"] = f"BB_GATE({int(_gate_bb_pct)}%)"  # ★ scan-list UI 표시용
                                elif signal == "SELL" and _gate_bb_pct < 25:
                                    if _tr_byp:
                                        logger.info("[FOCUS] Scanner %s: BB gate SELL BB%.0f%% BUT ADX%.0f≥강추세 벽타기 → 통과",
                                                    symbol, _gate_bb_pct, _tr_adx)
                                    else:
                                        logger.info("[FOCUS] Scanner %s: BB gate — %s BB%.0f%% < 25%% → HOLD (oversold for trend-sell)",
                                                    symbol, pa_name, _gate_bb_pct)
                                        signal = "HOLD"
                                        pa_name = f"{pa_name}→BB_GATE_HOLD"
                                        c["_block_reason"] = f"BB_GATE({int(_gate_bb_pct)}%)"  # ★ scan-list UI 표시용
                        except Exception as exc:
                            logger.debug("[FOCUS] operation failed: %s", exc)

                    # ★ [2026-04-15] 30M 복합 판정 — primary(H1)↔30M 방향 충돌 시 HOLD
                    # [2026-05-15] H1 전환: primary_tf 가 H1 이 되며 옛 "H4↔H1" 비교가 H1↔H1 중복 → 한 칸 내려 primary↔30M.
                    # [2026-05-17 부모 비전 #3] BOS + CFID FLIP_IMMINENT 일치 시 면제 (변곡점 예측 우선 — "BOS_BEARISH = 추세 반전 시작 = 기회")
                    _primary_signal = signal
                    if signal in ("BUY", "SELL") and not _bb_flipped and pa_name in ("TREND_UP", "TREND_DN", "BOS_BULLISH", "BOS_BEARISH"):
                        # BOS + CFID 결합 면제 체크
                        _bos_cfid_exempt = False
                        if pa_name in ("BOS_BULLISH", "BOS_BEARISH"):
                            try:
                                _cfid_dir, _cfid_strength = self._detect_coin_flip_imminent_impl(symbol)
                                if (signal == "BUY" and _cfid_dir == "BULL_IMMINENT") or \
                                   (signal == "SELL" and _cfid_dir == "BEAR_IMMINENT"):
                                    _bos_cfid_exempt = True
                                    logger.info("[FOCUS] Scanner %s %s + CFID %s 일치 → 30M conflict 면제 (변곡점 예측 우선)",
                                                symbol, pa_name, _cfid_dir)
                            except Exception as _bce:
                                logger.debug("[FOCUS] Scanner BOS+CFID check %s: %s", symbol, _bce)

                        # ★ [2026-05-21 부모] Reverse 모드 시 30M conflict 우회 — signal HOLD 변경 안 함.
                        # 부모님 룰: "낮은 conv + 낮은 ADX → 반대 진입" — 30M conflict 무관.
                        # signal=BUY/SELL 유지 → 뒤쪽 reverse 검사 도달 가능.
                        _rev_mode_m30_bypass = getattr(self.config, "entry_mode", "score") == "reverse"
                        if not _bos_cfid_exempt and not _rev_mode_m30_bypass:
                            try:
                                from app.strategy.greenpen.market_structure import analyze_structure as _az_m30s
                                _raw_m30 = client.get_kline(symbol, interval="30", limit=30)
                                if _raw_m30 and len(_raw_m30) >= 10:
                                    _m30c = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4]))
                                             for r in _raw_m30 if len(r) >= 5]
                                    if len(_m30c) >= 10:
                                        _m30s = _az_m30s(_m30c, lookback=3)
                                        _m30t = _m30s.trend.value if hasattr(_m30s.trend, 'value') else str(_m30s.trend)
                                        # primary UPTREND + 30M DOWNTREND → LONG 위험, HOLD
                                        if signal == "BUY" and _m30t == "DOWNTREND":
                                            signal = "HOLD"
                                            pa_name = f"{pa_name}→M30_DN_HOLD"
                                            logger.info("[FOCUS] Scanner candidate %s: PRIMARY %s but 30M DOWNTREND → HOLD",
                                                        symbol, _primary_signal)
                                        # primary DOWNTREND + 30M UPTREND → SHORT 위험, HOLD
                                        elif signal == "SELL" and _m30t == "UPTREND":
                                            signal = "HOLD"
                                            pa_name = f"{pa_name}→M30_UP_HOLD"
                                            logger.info("[FOCUS] Scanner candidate %s: PRIMARY %s but 30M UPTREND → HOLD",
                                                        symbol, _primary_signal)
                            except Exception as _m30e:
                                logger.debug("[FOCUS] Scanner 30M check failed %s: %s", symbol, _m30e)
                        elif _rev_mode_m30_bypass:
                            logger.debug("[FOCUS] Scanner %s: Reverse 모드 30M conflict 우회 (signal=%s 보존)", symbol, signal)

                    _adx_val = 0
                    _adx_past_val = 0
                    # adx_past 의미 (형 letter 2026-04-21 검수 3-2 답):
                    #   candles = primary_tf (H4) OHLCV 리스트. 현재 adx_val = 마지막 H4 봉 기준.
                    #   _adx_past_val = N개 H4 봉 **이전**의 ADX. lookback_bars=3 → 12시간 전 ADX.
                    #   즉 "직전 tick 변동" 아니라 **3 H4 봉 전 vs 현재 봉** 비교.
                    #   Phase J v2 (2% decline) + Phase K (5% decline) 둘 다 이 값 소비.
                    try:
                        _h = [cd.high for cd in candles]
                        _l = [cd.low for cd in candles]
                        _c = [cd.close for cd in candles]
                        _r = _adx_fn(_h, _l, _c, period=14)
                        if _r:
                            _adx_val = round(_r.get("adx", 0), 1)
                        # ★ Phase J (2026-04-21): N봉 전 ADX 도 계산 (slope check 용)
                        _lookback = int(getattr(self.config, "adx_slope_lookback_bars", 3))
                        if len(_h) >= 14 + _lookback:
                            # [:-_lookback] = 마지막 _lookback 봉 제외 → N봉 전 시점의 ADX 계산
                            _r_past = _adx_fn(_h[:-_lookback], _l[:-_lookback], _c[:-_lookback], period=14)
                            if _r_past:
                                _adx_past_val = round(_r_past.get("adx", 0), 1)
                    except Exception as exc:
                        logger.debug("[FOCUS] _h failed: %s", exc)
                    results.append({"market": symbol, "signal": signal,
                                   "pa_pattern": pa_name, "adx": _adx_val,
                                   "adx_past": _adx_past_val,
                                   "atr": round(gp.atr, 2), "price": c["price"],
                                   "bb_flipped": _bb_flipped,
                                   "sw_flag": _sw_flag})
                except Exception as exc:
                    logger.debug("[FOCUS] _h failed: %s", exc)
                    continue

            # [2026-04-18] BUY 우선 정렬 제거 — ADX 순으로만 정렬 (LONG 편향 방지)
            # 기존: signal_order BUY=0/SELL=1 → BUY 후보가 항상 SELL보다 먼저
            #       → 슬롯 다 차면 SHORT 기회 원천 봉쇄
            # 수정: 방향 무관 ADX 높은 코인부터 시도
            results.sort(key=lambda x: -x.get("adx", 0))
            return results
        except Exception as exc:
            logger.warning("[FOCUS] scanner candidates failed: %s", exc)
            return []

    def _hunt_scanner_candidates(self, now: float, btc_price: float) -> Dict:
        """Fill remaining slots with scanner candidates."""
        if not self.config.scanner_entry:
            return {}

        open_count = len(self.positions)
        # ★ Conviction Override Slot (2026-05-10): override 자격 candidate 가능성 열어둠 → effective max 사용
        # [2026-05-29 부모] Slot Auto Expand 도 함께 허용 (allow_slot_expand=True)
        eff_max = self._get_effective_max_positions(is_override=True, allow_slot_expand=True)
        if open_count >= eff_max:
            return {"scanner": f"slots_full({open_count}/{eff_max})"}

        # Exposure cap check — [2026-04-09] get_balance("USDT") returns float
        client = self._get_client()
        try:
            _bal = client.get_balance("USDT")
            available = float(_bal) if not isinstance(_bal, dict) else float(
                _bal.get("available", 0) or _bal.get("availableBalance", 0) or 0)
        except Exception as _be:
            logger.warning("[FOCUS] Scanner balance check failed: %s", _be)
            # Fallback: margin 조회
            try:
                available = self._get_available_margin()
            except Exception as exc:
                logger.debug("[FOCUS] available failed (fallback): %s", exc)
                available = 100.0  # assume available if can't check
        if available < 5.0:
            logger.info("[FOCUS] Scanner: no_budget (available=$%.2f)", available)
            return {"scanner": "no_budget"}

        held = {p.market.upper() for p in self.positions}
        if self.config.lock_market:
            held.add(self.config.lock_market.upper())

        candidates = self._get_scanner_candidates()
        if not candidates:
            return {"scanner": "no_candidates"}

        entered = []
        _scan_log = []  # [2026-04-09] 디버그: 스캐너 차단 추적
        _pipeline_syms = set()  # ★ [2026-06-15 해결안 B] _execute_entry 거쳐 journal.record_blocked 로 이미 집계된 심볼 (gate_ledger 중복 방지)
        # ★ [2026-05-17] Scanner 적용 최종 conviction 캐싱 (UI CONV 칼럼 통일용)
        self._last_scan_conviction = {}
        if not hasattr(self, '_last_guard_score'):
            self._last_guard_score = {}  # ★ [2026-05-28] 가드 점수 캐시 — scan-list API 가 분리 컬럼 표시용
        for c in candidates:
            # ★ Conviction Override Slot (2026-05-10): per-candidate 자격 체크 + effective max 분기
            _is_override_candidate = self._is_override_qualified(c)
            # [2026-05-29 부모] Slot Auto Expand 자격 체크 — 강신호 (conv ≥ min) + 모든 슬롯 묶임
            _c_conv = float(c.get("conviction_score", 0) or 0)
            _is_slot_expand_candidate = (
                not _is_override_candidate  # Override 우선 — 중복 방지
                and self._slot_auto_expand_eligible(_c_conv)
            )
            _eff_max_for_c = self._get_effective_max_positions(
                is_override=_is_override_candidate,
                allow_slot_expand=_is_slot_expand_candidate,
            )
            if open_count >= _eff_max_for_c:
                if _is_override_candidate or _is_slot_expand_candidate:
                    # override / slot_expand 자격 인데도 effective max 다 참 → 종료
                    break
                else:
                    # 일반 자격 — 다음 candidate 가 override/expand 자격일 수 있으니 계속
                    continue
            # entry 에 override 마커 (사이즈/SL/Hard ROE 분기 위해)
            if _is_override_candidate:
                c["_is_override"] = True
            # [2026-05-29 부모] Slot Auto Expand 마커 (사이즈 축소 분기 위해)
            if _is_slot_expand_candidate:
                c["_slot_expand"] = True
                logger.warning("[FOCUS] ★ Slot Auto Expand SIGNAL: %s conv=%.1f (모든 슬롯 묶임 + 강신호) → 임시 +1 슬롯 진입",
                               c.get("market", ""), _c_conv)
            symbol = c.get("market", "").upper()
            if symbol in held:
                _scan_log.append(f"{symbol}:held")
                continue
            # ★ 블랙리스트 체크 (영구 + 임시)
            # ★ [2026-06-02] suffix(USDT/USDC) 무시 매칭 — "XAUT" 만 넣어도 "XAUTUSDT" 막힘 (부모 blacklist 누락 버그 fix)
            _bl = self.config.scanner_blacklist or []
            _sym_base = symbol.upper().replace("USDT", "").replace("USDC", "").replace("PERP", "")
            if symbol in _bl or _sym_base in _bl:
                _scan_log.append(f"{symbol}:blacklisted")
                continue
            _tbl = getattr(self, '_temp_blacklist', {})
            if symbol in _tbl and _tbl[symbol] > time.time():
                _scan_log.append(f"{symbol}:temp_blocked")
                continue
            if c.get("signal") not in ("BUY", "SELL"):
                # ★ [2026-05-28 부모] guard_score_mode 활성 시 HOLD 도 평가 — H4 trend 기반 방향 추정 후 점수에 위임
                if self._guard_score_mode_active():
                    _h4_t = str(c.get("h4_trend", "") or c.get("primary_trend", "") or "").upper()
                    if "DOWN" in _h4_t:
                        c["signal"] = "SELL"
                    elif "UP" in _h4_t:
                        c["signal"] = "BUY"
                    else:
                        # ★ [2026-06-02 부모] SIDEWAYS/미정 → 거시 breadth 방향으로 추정.
                        #   기존 무조건 BUY = 하락장도 LONG 평가(오전 95% 편향의 뿌리). breadth BEAR면 SELL 평가
                        #   → 하락장에서 SHORT를 "비집고 들어가게". breadth 보강(1h 변화율)과 한 짝. (방향변환 아님: 원래 HOLD)
                        try:
                            _bdir = self._compute_market_breadth().get("dir", 0)
                        except Exception:
                            _bdir = 0
                        c["signal"] = "SELL" if _bdir < 0 else "BUY"   # 거시 하락→SHORT 평가 / else BUY
                    logger.info("[FOCUS] Scanner %s: sig=HOLD → guard_score_mode bypass 추정 %s (h4_trend=%s)",
                                symbol, c["signal"], _h4_t or "?")
                else:
                    # ★ BB gate 등 자세한 차단 이유 우선 (없으면 sig=HOLD)
                    _sig_reason = c.get("_block_reason") or f"sig={c.get('signal')}"
                    _scan_log.append(f"{symbol}:{_sig_reason}")
                    continue

            # ★ 단가 짜잘이 필터 (config 로 조정 가능, 2026-04-25 0.10 default)
            _min_price_filter2 = float(getattr(self.config, "scanner_min_price_usdt", 0.10))
            _cprice = float(c.get("price", 0))
            if _cprice > 0 and _cprice < _min_price_filter2:
                _scan_log.append(f"{symbol}:low_price(${_cprice:.2f})")
                continue

            # ★ ADX/PA 필터 — whale이 강하면 완화 (whale scan은 아래에서)
            # 1차 필터: ADX 15 이상은 통과 (whale 완화 가능 범위)
            # ADX < 15면 whale이어도 너무 약함 → 무조건 차단
            # ★ [2026-05-21 부모] Reverse 모드 = 낮은 ADX = 럭비공 = 자리. ADX<15 도 우회.
            _coin_adx = c.get("adx", 0)
            _rev_mode_dormant_bypass = (
                getattr(self.config, "entry_mode", "score") == "reverse"
                and _coin_adx <= float(getattr(self.config, "reverse_adx_max", 20.0))
            )
            if _coin_adx < 15 and not _rev_mode_dormant_bypass and not self._guard_score_mode_active():
                _scan_log.append(f"{symbol}:adx={_coin_adx}<15")
                continue
            # ★ Phase J v2 (2026-04-21 사용자 의도 명확화): ADX 하락 중이면 방향 무관 skip
            # 근거: "시장 식어가는 끝자락" = regime 전환 임박 구간
            # 진입 후 1-10분 머무는 동안 regime 전환 시 손실
            # → 어느 방향이든 추세 약화 시점 진입 방지
            # 형 letter #6: peak 대비 2-3% 이상 하락 시 block (노이즈 흡수)
            # ★ J/K 상호 배제 (2026-04-21, 형 letter #9 옵션 A 수정):
            #   K live 일 때만 J v2 skip (같은 ADX 하락 신호에 K=flip 우선).
            #   K paper_mode 일 때는 J v2 와 공존 — paper 는 log-only, 실진입 차단은 J v2 가 담당.
            #   원래 mutex (paper 무관 K=True 면 J off) 는 K paper 기간에 ADX 하락 방어 공백 발생.
            _k_enabled = getattr(self.config, "regime_transition_enabled", False)
            _k_paper_mode = getattr(self.config, "regime_transition_paper_mode", True)
            _k_live_active = _k_enabled and not _k_paper_mode
            if getattr(self.config, "adx_slope_check_enabled", True) and not _k_live_active:
                _adx_past = c.get("adx_past", 0)
                _signal = c.get("signal","HOLD")
                _intended_dir = "LONG" if _signal == "BUY" else ("SHORT" if _signal == "SELL" else None)
                if _adx_past > 0 and _intended_dir and _coin_adx < _adx_past:
                    _decl_pct = (_adx_past - _coin_adx) / _adx_past * 100
                    _threshold = float(getattr(self.config, "adx_slope_decline_threshold_pct", 2.0))
                    if _decl_pct >= _threshold and not self._guard_score_mode_active():
                        logger.info("[FOCUS] Scanner %s: ADX 하락 %.1f%% (%.1f→%.1f) + %s → SKIP (시장 식어감)",
                                    symbol, _decl_pct, _adx_past, _coin_adx, _intended_dir)
                        _scan_log.append(f"{symbol}:adx_decl-{_decl_pct:.1f}pct_{_intended_dir}_skip")
                        continue
            # ADX 15~22: whale >= 5면 통과, 아니면 차단 (아래서 whale scan 후 재체크)
            # [2026-04-18 저녁] 하드캡 제거 — config 값 그대로 사용 (투명성)
            _effective_scan_adx = self.config.scanner_min_adx
            _adx_soft_pass = _coin_adx >= _effective_scan_adx
            _pa_soft_pass = c.get("pa_pattern", "-") != "-"

            # ★ [2026-05-20 부모] Reverse 모드 = 낮은 ADX 자체가 *조건* (럭비공 자리).
            # ADX 차단 우회 — entry_mode=reverse + ADX ≤ reverse_adx_max 시 통과.
            _rev_mode_adx_bypass = (
                getattr(self.config, "entry_mode", "score") == "reverse"
                and _coin_adx <= float(getattr(self.config, "reverse_adx_max", 20.0))
            )

            # ADX와 PA 둘 다 실패면 whale 기회도 없음 (단, Reverse 모드 / guard_score_mode 우회)
            if not _adx_soft_pass and not _pa_soft_pass and not _rev_mode_adx_bypass and not self._guard_score_mode_active():
                _scan_log.append(f"{symbol}:adx={_coin_adx},no_pa")
                continue
            if _rev_mode_adx_bypass and not _adx_soft_pass:
                logger.info("[FOCUS] Scanner %s: Reverse 모드 ADX 우회 (ADX=%.1f ≤ %.0f, 럭비공 자리)",
                            symbol, _coin_adx, float(getattr(self.config, "reverse_adx_max", 20.0)))

            direction = "LONG" if c["signal"] == "BUY" else "SHORT"
            _is_bb_flip = c.get("bb_flipped", False)
            _is_sw_bb = c.get("sw_flag", False)  # [2026-04-18] SW_UPPER_BB/SW_LOWER_BB mean reversion 면제용
            # ★ 방향 분산: 방향별 슬롯 상한 — 2026-04-20 Long/Short 분리 (형 지시)
            # [2026-04-19 Option B] 원방향만 saturated 면 통과 (MTF FLIP 이 반대 방향 시도).
            #   둘 다 saturated 일 때만 진짜 skip.
            # ★ Override Slot (2026-05-10 부모님 결정 — 옵션 A 자유): 확장 슬롯은 same_dir 면제.
            #   "묶였다는 것은 이미 그 방향이 아니라서 묶인거니깐" — 묶인 슬롯과 별도 모드, 시장 방향 자유 진입.
            if c.get("_is_override", False):
                _scan_log.append(f"{symbol}:override_same_dir_exempt({direction})")
            else:
                same_dir_count = sum(1 for p in self.positions if p.direction == direction)
                opp_dir = "SHORT" if direction == "LONG" else "LONG"
                opp_dir_count = sum(1 for p in self.positions if p.direction == opp_dir)
                _same_cap = self._effective_dir_cap(direction)
                _opp_cap = self._effective_dir_cap(opp_dir)
                if same_dir_count >= _same_cap and opp_dir_count >= _opp_cap:
                    _scan_log.append(f"{symbol}:dir_limit_both({direction}={same_dir_count}/{_same_cap},{opp_dir}={opp_dir_count}/{_opp_cap})")
                    continue
                if same_dir_count >= _same_cap:
                    # 원방향만 full → _execute_entry 의 MTF FLIP 이 opposite 시도. 스캐너에서는 차단 안 함.
                    _scan_log.append(f"{symbol}:dir_full_try_flip({direction}={same_dir_count}/{_same_cap})")
            price = float(c.get("price", 0))
            if price <= 0:
                _scan_log.append(f"{symbol}:no_price")
                continue
            if not self._check_reentry_allowed(direction, symbol, price):
                _scan_log.append(f"{symbol}:reentry_blocked")
                continue

            # ★ WhaleRadar — 비활성화 (2026-04-12): conviction/방향/필터 완화 전부 제거
            _whale_score = 0
            _whale_boost = 0
            _whale_type = ""

            # ADX/PA 필터 — whale 완화 없이 원래 기준 적용
            # ★ [2026-05-21 부모] Reverse 모드 = 낮은 ADX 자체가 조건. ADX/PA 둘 다 우회.
            _rev_mode_filter_bypass = (
                getattr(self.config, "entry_mode", "score") == "reverse"
                and _coin_adx <= float(getattr(self.config, "reverse_adx_max", 20.0))
            )
            if not _adx_soft_pass and not _rev_mode_filter_bypass and not self._guard_score_mode_active():
                _scan_log.append(f"{symbol}:adx={_coin_adx}<{_effective_scan_adx}")
                continue
            if not _pa_soft_pass and not _rev_mode_filter_bypass and not self._guard_score_mode_active():
                _scan_log.append(f"{symbol}:no_pa")
                continue

            # Conviction -- need H4 candles for this coin
            try:
                raw_primary = client.get_kline(symbol, interval=self.config.primary_tf, limit=60)
                from app.strategy.greenpen.pa_detector import OHLCV
                candles_primary = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4])) for r in raw_primary if len(r) >= 5]
            except Exception as exc:
                logger.debug("[FOCUS] raw_primary failed (fallback): %s", exc)
                candles_primary = []

            # ── 양방향 평가 (Phase 2, 2026-06-09 부모 GO) — candles 확보 직후 *방향 확정* ──
            #   ★ 여기서 방향을 정해야 아래 PRIMARY 역추세·30M penalty·conviction 이 올바른 방향에 적용됨.
            #   dual OFF 면 signal 방향 그대로 + conviction 1회(기존 동작). zones·conviction 재사용(중복 X).
            _sym_zones = self._compute_zones_for_symbol(symbol, candles_primary)
            _signal_dir = direction
            direction, conviction, _dd_info = self._pick_best_direction(symbol, candles_primary, _sym_zones, _signal_dir)
            if _dd_info.get("flipped"):
                # 방향 교체됨 → dir cap·reentry 를 *새 방향* 으로 재확인 (위 12636~ 은 옛 방향 기준 판정)
                if not self._check_reentry_allowed(direction, symbol, price):
                    _scan_log.append(f"{symbol}:reentry_blocked(dual {direction})")
                    continue
                _nd = sum(1 for p in self.positions if p.direction == direction)
                _od = "SHORT" if direction == "LONG" else "LONG"
                _odc = sum(1 for p in self.positions if p.direction == _od)
                if _nd >= self._effective_dir_cap(direction) and _odc >= self._effective_dir_cap(_od):
                    _scan_log.append(f"{symbol}:dir_limit_both(dual {direction})")
                    continue
                logger.info("[FOCUS] DualDir 진입방향 교체: %s %s→%s (conv %.0f)", symbol, _signal_dir, direction, conviction)

            # ★ H4 역추세 — [2026-04-18 저녁] 차단 → 통과 (FLIP 위임)
            # user 지적: "차단만 하지 말고 H1/M30/M15 유동 따라 LONG 아니면 SHORT 쳐야지"
            # 이전: (direction vs H4) 역추세면 continue → 신호 소멸
            # 변경: 신호를 _execute_entry까지 보내고 거기 MTF 게이트(Anti-Knife + H4 Context)가
            #       - 원 방향 적합하면 → 진입
            #       - 원 방향 부적합 + 반대 방향 적합 → FLIP 진입
            #       - 둘 다 부적합 → 진짜 skip
            # 기존 continue를 제거하면 MTF FLIP 로직이 비로소 살아난다.
            # BB FLIP / SW 면제는 여전히 의미 있음 (의도적 역방향 신호는 log에 남기기 위해)
            _primary_t = ""
            if len(candles_primary) >= 10:
                try:
                    from app.strategy.greenpen.market_structure import analyze_structure as _az_s
                    _primary_s = _az_s(candles_primary, lookback=3)
                    _primary_t = _primary_s.trend.value if hasattr(_primary_s.trend, 'value') else str(_primary_s.trend)
                    if not _is_bb_flip and not _is_sw_bb:
                        if (direction == "LONG" and _primary_t == "DOWNTREND") or \
                           (direction == "SHORT" and _primary_t == "UPTREND"):
                            _scan_log.append(f"{symbol}:PRIMARY_cnt_defer({direction}vs{_primary_t})→MTF_FLIP")
                            logger.info("[FOCUS] Scanner PRIMARY counter-trend noted (will be handled by MTF FLIP): %s %s vs PRI %s",
                                        symbol, direction, _primary_t)
                            # [2026-04-18 저녁] continue 제거 — _execute_entry의 MTF 게이트로 위임
                except Exception as exc:
                    logger.debug("[FOCUS] import analyze_structure as _az_s failed: %s", exc)

            # ★ 30M trend alignment — primary(H1)↔30M 충돌 시 conviction 감점
            # [2026-05-15] H1 전환: 옛 "H4↔H1" 비교가 H1↔H1 중복 → 한 칸 내려 primary↔30M.
            # BB FLIP은 면제: 극단 플립은 의도적 역방향이므로 30M 충돌 당연
            # [2026-04-18] SW 면제: SIDEWAYS mean reversion은 30M의 trending-TF 편향과 충돌 당연
            _m30_penalty = 1.0
            if not _is_bb_flip and not _is_sw_bb:
                try:
                    raw_m30 = client.get_kline(symbol, interval="30", limit=30)
                    if raw_m30 and len(raw_m30) >= 10:
                        from app.strategy.greenpen.pa_detector import OHLCV as _O1
                        from app.strategy.greenpen.market_structure import analyze_structure as _az_m30
                        _m30_candles = [_O1(float(r[1]), float(r[2]), float(r[3]), float(r[4])) for r in raw_m30 if len(r) >= 5]
                        if len(_m30_candles) >= 10:
                            _m30s = _az_m30(_m30_candles, lookback=3)
                            _m30t = _m30s.trend.value if hasattr(_m30s.trend, 'value') else str(_m30s.trend)
                            # [2026-05-20 부모] dataclass 화 — 옛 hardcoded 0.5 → UI 노출
                            _pri_pen = float(getattr(self.config, "scanner_m30_primary_conflict_penalty", 0.7))
                            _dir_pen = float(getattr(self.config, "scanner_m30_direction_conflict_penalty", 0.7))
                            # primary↔30M 충돌 → conviction × _pri_pen
                            if (_primary_t == "UPTREND" and _m30t == "DOWNTREND") or \
                               (_primary_t == "DOWNTREND" and _m30t == "UPTREND"):
                                _m30_penalty *= _pri_pen
                                logger.info("[FOCUS] Scanner 30M conflict %s: PRI=%s 30M=%s → penalty×%.2f", symbol, _primary_t, _m30t, _pri_pen)
                            # 방향↔30M 충돌 → conviction × _dir_pen
                            if (direction == "LONG" and _m30t == "DOWNTREND") or \
                               (direction == "SHORT" and _m30t == "UPTREND"):
                                _m30_penalty *= _dir_pen
                                logger.info("[FOCUS] Scanner 30M dir conflict %s: %s vs 30M=%s → penalty×%.2f", symbol, direction, _m30t, _dir_pen)
                except Exception as exc:
                    logger.debug("[FOCUS] Scanner 30M check failed %s: %s", symbol, exc)

            # [2026-04-18] direction 전달 for News Sentiment 방향 인식
            # [2026-04-24] zones 전달 for PA Pattern weight (location 보너스/패널티)
            # [2026-05-17 Phase 4.7] Scanner = 코인별 zones 동적 계산 (XAUT zones 오용 fix)
            # conviction·_sym_zones·direction = 위 _pick_best_direction 에서 확정 (재계산 X · 관찰 기록도 거기서)
            # 30M 패널티 적용 [2026-05-17 100점 float — int 절삭 제거 (분별력 보존)]
            if _m30_penalty < 1.0:
                conviction = float(conviction) * _m30_penalty
                logger.info("[FOCUS] Scanner %s conviction after 30M penalty: %.1f (×%.2f)", symbol, conviction, _m30_penalty)

            # ★★★ [2026-05-18 부모 비전 #5] Leading Entry 사전 평가
            # 부모님: "1분이라도 선행 진입 — 이미 움직일 방향으로 미리 들어가는 것"
            # mode 별로 한 번만 평가 — 이후 BB_REGIME/conv 차단 우회 결정에 활용
            _leading_eligible = False
            _leading_mode = ""
            _leading_reason = ""
            _leading_bypass_microtiming = False
            _leading_bypass_bb_regime = False
            _leading_size_pct = 0.0
            _le_mode = (getattr(self.config, "leading_entry_mode", "OFF") or "OFF").upper()
            if _le_mode == "CFID":
                _le_ok, _le_reason = self._check_cfid_leading_entry(symbol, direction)
                if _le_ok:
                    _leading_eligible = True
                    _leading_mode = "CFID"
                    _leading_reason = _le_reason
                    _leading_bypass_microtiming = bool(getattr(self.config, "cfid_leading_bypass_microtiming", True))
                    _leading_bypass_bb_regime = bool(getattr(self.config, "cfid_leading_bypass_bb_regime", True))
                    _leading_size_pct = float(getattr(self.config, "cfid_leading_size_pct", 5.0))
                    logger.info("[FOCUS] Leading CFID 가능: %s %s — %s", symbol, direction, _le_reason)
            elif _le_mode == "PATTERN":
                _le_ok, _le_reason = self._check_pattern_leading_entry(symbol, direction, candles_primary, _sym_zones)
                if _le_ok:
                    _leading_eligible = True
                    _leading_mode = "PATTERN"
                    _leading_reason = _le_reason
                    _leading_bypass_microtiming = bool(getattr(self.config, "pattern_leading_bypass_microtiming", True))
                    _leading_bypass_bb_regime = bool(getattr(self.config, "pattern_leading_bypass_bb_regime", True))
                    _leading_size_pct = float(getattr(self.config, "pattern_leading_size_pct", 5.0))
                    logger.info("[FOCUS] Leading PATTERN 가능: %s %s — %s", symbol, direction, _le_reason)

            # ★ Peak Fade 감점 — 봉우리 꺾임 감지
            # [2026-04-18] SW 신호 면제 — SIDEWAYS mean reversion은 trending 가정과 충돌
            #   Peak Fade는 UPTREND/DOWNTREND 가정으로 설계됐는데 SW는 SIDEWAYS
            #   같은 구조 모순이 H4 counter_trend에서도 있었고 _is_sw_bb로 면제한 바 있음
            #   Peak Fade도 동일 패턴으로 면제 — 일관성 + 5시간 0진입 해결
            if _is_sw_bb:
                _pf_penalty = 0
            else:
                _pf_penalty = self._peak_fade_penalty(candles_primary, direction)
            if _pf_penalty:
                conviction = max(0, conviction + _pf_penalty)

            # ★ [2026-04-17] PRIMARY BB 위치 감점: overbought/oversold 구간에서 추세 방향 진입 감점
            if candles_primary and len(candles_primary) >= 20:
                try:
                    from app.strategy.indicators import bollinger_bands as _bb_scanner_fn
                    _scnr_bb_closes = [c.close for c in candles_primary]
                    _scnr_bb = _bb_scanner_fn(_scnr_bb_closes, 20, 2.0)
                    if _scnr_bb and _scnr_bb["upper"] > _scnr_bb["lower"]:
                        _scnr_bb_pct = (_scnr_bb_closes[-1] - _scnr_bb["lower"]) / (_scnr_bb["upper"] - _scnr_bb["lower"]) * 100
                        # ★ Phase I (2026-04-20 옵션 D 완화): regime BULL/BEAR 명확하면 trend continuation 허용
                        # 이전: BB 85%+ LONG / BB 15%- SHORT 무조건 완전 차단 (ORDI -$18 교훈)
                        # 변경: regime이 같은 방향이면 차단 대신 conv -3 강감점만 (trend follow 보존)
                        # NEUTRAL/역방향 regime 일 때만 기존 차단 유지 (정점/저점 회피)
                        _current_regime = getattr(self, "_b11_regime_state", ("", 0.0))[0]
                        if direction == "LONG" and _scnr_bb_pct > 85:
                            _tr_byp, _tr_adx = self._bb_trend_riding(direction, _scnr_bb_closes)
                            if _current_regime == "BULL" or _tr_byp:
                                # BULL or 강한 추세(ADX) = trend continuation = BB 벽타기. 차단 대신 conv -3
                                conviction = max(0, conviction - 3)
                                _tr_why = "BULL regime" if _current_regime == "BULL" else f"ADX{_tr_adx:.0f}≥강추세 벽타기"
                                logger.info("[FOCUS] Scanner %s: PRIMARY BB%.0f%% > 85%% + LONG (%s) → trend follow 허용, conv -3 → %d",
                                            symbol, _scnr_bb_pct, _tr_why, conviction)
                            else:
                                # NEUTRAL/BEAR + BB 85%+ LONG = 정점 위험 (ORDI 교훈 유지)
                                # ★ [2026-05-18] Leading Entry 우회 — CFID/PATTERN 모드 + bypass 옵션 ON 시 통과
                                if _leading_eligible and _leading_bypass_bb_regime:
                                    logger.info("[FOCUS] Scanner %s: BB%.0f%% > 85%% LONG (정점) BUT %s_LEAD 우회 → conv -5",
                                                symbol, _scnr_bb_pct, _leading_mode)
                                    conviction = max(0, conviction - 5)
                                else:
                                    logger.info("[FOCUS] Scanner %s: PRIMARY BB%.0f%% > 85%% + LONG → BLOCKED (regime=%s, 정점 위험)",
                                                symbol, _scnr_bb_pct, _current_regime or "?")
                                    _scan_log.append(f"{symbol}:BB_REGIME({int(_scnr_bb_pct)}%>85,정점)")  # ★ UI STATUS
                                    continue
                        elif direction == "LONG" and _scnr_bb_pct > 75:
                            conviction = max(0, conviction - 2)
                            logger.info("[FOCUS] Scanner %s: PRIMARY BB%.0f%% > 75%% + LONG → conviction -2 → %d",
                                        symbol, _scnr_bb_pct, conviction)
                        elif direction == "SHORT" and _scnr_bb_pct < 15:
                            _tr_byp, _tr_adx = self._bb_trend_riding(direction, _scnr_bb_closes)
                            if _current_regime == "BEAR" or _tr_byp:
                                # BEAR or 강한 추세(ADX) = downtrend continuation = BB 벽타기. 차단 대신 conv -3
                                conviction = max(0, conviction - 3)
                                _tr_why = "BEAR regime" if _current_regime == "BEAR" else f"ADX{_tr_adx:.0f}≥강추세 벽타기"
                                logger.info("[FOCUS] Scanner %s: PRIMARY BB%.0f%% < 15%% + SHORT (%s) → trend follow 허용, conv -3 → %d",
                                            symbol, _scnr_bb_pct, _tr_why, conviction)
                            else:
                                # NEUTRAL/BULL + BB 15%- SHORT = 저점 위험
                                # ★ [2026-05-18] Leading Entry 우회 — CFID/PATTERN 모드 + bypass 옵션 ON 시 통과
                                if _leading_eligible and _leading_bypass_bb_regime:
                                    logger.info("[FOCUS] Scanner %s: BB%.0f%% < 15%% SHORT (저점) BUT %s_LEAD 우회 → conv -5",
                                                symbol, _scnr_bb_pct, _leading_mode)
                                    conviction = max(0, conviction - 5)
                                else:
                                    logger.info("[FOCUS] Scanner %s: PRIMARY BB%.0f%% < 15%% + SHORT → BLOCKED (regime=%s, 저점 위험)",
                                                symbol, _scnr_bb_pct, _current_regime or "?")
                                    _scan_log.append(f"{symbol}:BB_REGIME({int(_scnr_bb_pct)}%<15,저점)")  # ★ UI STATUS
                                    continue
                        elif direction == "SHORT" and _scnr_bb_pct < 25:
                            conviction = max(0, conviction - 2)
                            logger.info("[FOCUS] Scanner %s: PRIMARY BB%.0f%% < 25%% + SHORT → conviction -2 → %d",
                                        symbol, _scnr_bb_pct, conviction)
                except Exception as exc:
                    logger.debug("[FOCUS] import bollinger_bands as _bb_scanner failed: %s", exc)

            # ★ Coin Report Card 등급 감점 — [2026-04-18] user 요청으로 비활성화
            # try:
            #     from app.manager.coin_report_card import CoinReportCard
            #     _crc = CoinReportCard()
            #     _coin_scores = _crc.get_coin_scores()
            #     _cscore = _coin_scores.get(symbol, 50.0)
            #     if _cscore < 25:
            #         conviction = max(0, conviction - 3)
            #     elif _cscore < 40:
            #         conviction = max(0, conviction - 2)
            # except Exception as _cge:
            #     logger.debug("[FOCUS] Coin grade check failed: %s", _cge)

            # whale boost 비활성화 (2026-04-12)

            # [2026-04-18 저녁] 하드캡 제거 — config 값 그대로 사용 (투명성)
            #   형 서버 config=6 사례에서 하드캡의 config 덮어쓰기 위험 학습
            #   동생 서버는 config 값 자체를 낮게(=3) 설정해서 동일 효과 달성
            # ── Event Shield: 경제이벤트 윈도우 신규진입 hard block (conviction 무관) ──
            _es_label = self._event_shield_label()
            if _es_label:
                self._record_skip(symbol, direction, conviction, "-", f"event_shield({_es_label})")
                continue  # 이벤트 윈도우 — 이 코인 후보 제외

            _effective_min_conv = self.config.scanner_min_conviction

            # Morning Guard: 아침 위험 시간대 conviction 상향
            if self._is_morning_guard_active():
                _effective_min_conv += self.config.morning_guard_conviction_boost

            # ★ [2026-05-17] Scanner 최종 conviction 캐싱 (UI CONV 통일용)
            self._last_scan_conviction[symbol] = float(conviction)

            # ★ [Phase 7 2026-05-28] signal_history — 부모님 5조건 룰 1번 (이전 신호 추적)
            # "SELL이었던 것이..." 룰 검사용. BUY/SELL 만 저장 (HOLD 제외).
            # ★ FIX (2026-05-28 15:25): 이 scope 변수명은 _signal (밑줄) — signal 은 NameError.
            try:
                if _signal in ("BUY", "SELL"):
                    _sig_hist = self._signal_history.get(symbol)
                    if _sig_hist is None:
                        _sig_hist = deque(maxlen=self._signal_history_maxlen)
                        self._signal_history[symbol] = _sig_hist
                    _sig_hist.append((time.time(), _signal))
            except NameError:
                # _signal 미정의 path (defensive) — skip silently
                pass

            # ── ★ [2026-05-20 부모님 재설계 + 5-21 00:08 변수 fix] Reverse 모드 — 봇 신호 반대 자동 진입 ──
            # 부모님 1차 룰: "봇 신호 + 낮은 conv (≤ 50) + 낮은 ADX (≤ 20) → 반대 진입 = 확실".
            # 럭비공 (ADX 낮음) 자체가 *조건* — 부모님 직감 자리. 무조건 진입 (반대 conv 검증 X).
            # 안전 가드 = _execute_entry 의 _mtf_gate (반대 방향도 Anti-Knife/primary_context 작동).
            # ★ [수정 23:53] conv < _effective_min_conv 조건 제거 — 부모님이 min_conv 낮춰도 reverse 트리거 작동.
            # ★ [수정 00:08] _adx_val → _coin_adx (다른 함수 scope, NameError fix).
            _entry_mode_cycle = getattr(self.config, "entry_mode", "score")
            _rev_conv_threshold = float(getattr(self.config, "reverse_conv_threshold", 50.0))
            _rev_adx_max = float(getattr(self.config, "reverse_adx_max", 20.0))
            if (_entry_mode_cycle == "reverse"
                    and getattr(self.config, "direction_mode", "both") == "both"  # ★ [2026-06-21 부모] long_only/short_only 면 reverse 금지 — 방향 강제가 절대 우선. reverse가 long_only LONG 후보를 SHORT로 뒤집어 진입하던 버그 fix.
                    and conviction <= _rev_conv_threshold
                    and _coin_adx <= _rev_adx_max):
                _opp_dir_rev = "SHORT" if direction == "LONG" else "LONG"
                logger.warning(
                    "[FOCUS] ★ REVERSE MODE: %s %s conv=%.1f≤%.0f ADX=%.1f≤%.0f → 반대 %s 자동 진입 (부모님 1차 룰)",
                    symbol, direction, conviction, _rev_conv_threshold, _coin_adx, _rev_adx_max, _opp_dir_rev)
                # direction 교체 + conv 임계 우회 (reverse 모드 = 부모님 무조건 진입 룰)
                direction = _opp_dir_rev
                conviction = float(_effective_min_conv)  # 우회용 (실제 안전 가드는 _execute_entry _mtf_gate)
                self._last_scan_conviction[symbol] = conviction

            # ★ [2026-05-18] Leading Entry — conviction 미달 시에도 통과 (선행 진입 경로)
            # ★ [2026-05-28 부모] guard_score_mode 활성 시 Scanner conv 게이트 우회 (점수 평가에 위임)
            if conviction < _effective_min_conv:
                if self._guard_score_mode_active():
                    logger.info("[FOCUS] Scanner %s %s: conv=%.1f<%d — guard_score_mode bypass (점수 평가에 위임)",
                                symbol, direction, float(conviction), _effective_min_conv)
                elif _leading_eligible:
                    logger.info("[FOCUS] %s_LEAD 발동: %s %s conv=%.1f<%d 미달 BUT 선행 진입 진행 (%s)",
                                _leading_mode, symbol, direction, float(conviction), _effective_min_conv, _leading_reason)
                else:
                    if self._is_morning_guard_active():
                        logger.info("[FOCUS] Morning Guard: scanner blocked %s, conviction %d < %d (morning +%d)",
                                     symbol, conviction, _effective_min_conv, self.config.morning_guard_conviction_boost)
                    _scan_log.append(f"{symbol}:conv={float(conviction):.1f}")  # ★ <50 표시 생략 (임계 매 코인 동일)
                    continue

            # ★ [2026-05-18] Leading Entry 사이즈 override — equity × leading_size_pct
            if _leading_eligible and _leading_size_pct > 0:
                _avail = self.config.budget_usdt
                if _avail <= 0:
                    _avail = self._get_available_margin()
                if _avail <= 0:
                    _avail = self._get_effective_budget(symbol)
                budget = max(5.0, _avail * (_leading_size_pct / 100.0))
                logger.info("[FOCUS] %s_LEAD 사이즈: $%.2f (%.1f%% × $%.2f equity)",
                            _leading_mode, budget, _leading_size_pct, _avail)
            else:
                budget = self._compute_entry_budget(conviction, symbol)
            if budget < 5.0:
                _scan_log.append(f"{symbol}:budget=${budget:.1f}")
                continue

            atr = float(c.get("atr", 0)) or price * 0.02
            _reason = f"scanner:adx={c.get('adx')},conv={conviction},pa={c.get('pa_pattern')}"
            if _whale_score >= 3:
                _reason += f",whale={_whale_score}({_whale_type})"

            # ★ Phase K (2026-04-21): Regime Transition Preemptive Entry ★
            # 이중 검증 완료 (형 88%/동생 94%/BTC 500봉 72%). J v2 와 동시 ON 시 K 우선 (J 자동 무시).
            # enabled=False 면 hook 자체가 NoOp. paper_mode 면 진입 skip + JSONL 기록만.
            _phase_k_active = False
            _phase_k_flip_dir = ""
            _phase_k_reason = ""
            if getattr(self.config, "regime_transition_enabled", False):
                try:
                    _k_allow, _k_opp, _k_reason = self.detect_regime_transition(
                        market=symbol,
                        scanner_direction=direction,
                        conviction=conviction,
                        adx_now=float(c.get("adx", 0) or 0),
                        adx_past=float(c.get("adx_past", 0) or 0),
                        candles_primary=candles_primary,
                    )
                    if _k_allow and _k_opp:
                        _phase_k_active = True
                        _phase_k_flip_dir = _k_opp
                        _phase_k_reason = _k_reason
                        _paper = bool(getattr(self.config, "regime_transition_paper_mode", True))
                        self._phase_k_paper_log({
                            "ts": time.time(),
                            "market": symbol,
                            "scanner_dir": direction,
                            "flip_dir": _k_opp,
                            "conviction": conviction,
                            "adx_now": c.get("adx", 0),
                            "adx_past": c.get("adx_past", 0),
                            "btc_ema_gap_pct": getattr(self, "_btc_ema_gap_pct", None),
                            "reason": _k_reason,
                            "paper_mode": _paper,
                        })
                        if _paper:
                            logger.info("[FOCUS] Phase K PAPER: %s flip %s→%s %s (진입 skip, log only)",
                                        symbol, direction, _k_opp, _k_reason)
                            _scan_log.append(f"{symbol}:phase_k_paper_flip_{_k_opp}")
                            continue
                        else:
                            logger.info("[FOCUS] Phase K LIVE: %s flip %s→%s %s (size×%.2f tp×%.2f sl×%.2f)",
                                        symbol, direction, _k_opp, _k_reason,
                                        self.config.regime_transition_size_mult,
                                        self.config.regime_transition_tp_mult,
                                        self.config.regime_transition_sl_mult)
                            direction = _k_opp  # ★ 실제 방향 교체
                            _reason = f"phase_k_regime_transition:{_k_reason}"
                except Exception as exc:
                    logger.debug("[FOCUS] Phase K detect failed %s: %s", symbol, exc)

            # ★ [2026-04-26] BTC Emergency Aligned 진입 가속 — 트렌드 역방향 차단
            _em_aligned_dir = getattr(self, "_emergency_aligned_dir", None)
            _em_aligned_until = getattr(self, "_emergency_aligned_until", 0)
            if _em_aligned_dir and time.time() < _em_aligned_until:
                if getattr(self.config, "btc_emergency_aggressive_entry", True) and direction != _em_aligned_dir:
                    logger.info("[FOCUS] BTC Emergency Aligned: %s %s skip (aligned=%s, %.0fs left)",
                                direction, symbol, _em_aligned_dir, _em_aligned_until - time.time())
                    _scan_log.append(f"{symbol}:btc_em_skip_opp")
                    continue
            elif _em_aligned_dir and time.time() >= _em_aligned_until:
                # 시간 만료 → reset (다음 발동 가능하게)
                logger.info("[FOCUS] BTC Emergency Aligned reset (duration expired)")
                self._emergency_aligned_dir = None
                self._btc_emergency_fired = False

            # ★ #7 [2026-04-26] Regime Reversal Pause — 전환점 학비 회피
            _rrp_paused, _rrp_reason = self._check_regime_reversal_pause()
            if _rrp_paused:
                _scan_log.append(f"{symbol}:{_rrp_reason}")
                continue
            # ★ #2A [2026-04-26 형 fix] Portfolio SL Rate Pause — 동시 SL 방어
            _psl_paused, _psl_reason = self._check_portfolio_sl_rate_pause()
            if _psl_paused:
                _scan_log.append(f"{symbol}:{_psl_reason}")
                continue
            # ★ #4 [2026-04-26] BTC trend-aligned conviction bonus
            _btc_bonus = self._btc_trend_conv_bonus(direction)
            # ★ #5A [2026-04-26 형 fix] BTC + B12 합산 cap — "+3 다른 지표 무력화" 우려
            if _btc_bonus > 0 and getattr(self.config, "btc_b12_combined_cap_enabled", True):
                cap = int(getattr(self.config, "btc_b12_combined_cap_max", 2))
                last_cross = int(getattr(self, "_last_cross_delta", 0))
                if last_cross > 0 and (last_cross + _btc_bonus) > cap:
                    _orig = _btc_bonus
                    _btc_bonus = max(0, cap - last_cross)
                    logger.info("[FOCUS] BTC bonus capped: +%d → +%d (cross+%d, cap +%d)",
                                _orig, _btc_bonus, last_cross, cap)
            if _btc_bonus > 0:
                conviction += _btc_bonus
                logger.info("[FOCUS] BTC trend bonus +%d for %s %s → conv=%d", _btc_bonus, direction, symbol, conviction)
            logger.info("[FOCUS] Scanner attempting: %s %s adx=%.1f conv=%d whale=%d budget=$%.1f",
                        direction, symbol, c.get("adx", 0), conviction, _whale_score, budget)
            _entry_payload = {
                "enter": True, "market": symbol, "direction": direction,
                "price": price, "atr": atr,
                "reason": _reason,
                "conviction_score": conviction,
                "conviction_budget": budget,
                "_conviction_modifiers": (lambda _m=getattr(self, '_last_conviction_breakdown', {}) or {}: f"peak_fade={_pf_penalty},whale={_whale_score},mtf={_m.get('mtf_pen', 0)},mom={_m.get('mom_pen', 0)},zone={_m.get('zone_pos', 0)},align={_m.get('mom_align', 0)}")(),
                "_scanner_entry": True,
                "_is_sw_bb": _is_sw_bb,  # [2026-04-18] Entry Quality 면제용
            }
            # ★ [2026-05-18] Leading Entry 플래그 — _execute_entry 우회 + journal 표시
            if _leading_eligible:
                _entry_payload["_leading_entry"] = True
                _entry_payload["_leading_mode"] = _leading_mode  # "CFID" / "PATTERN"
                _entry_payload["_leading_reason"] = _leading_reason
                _entry_payload["_bypass_microtiming"] = _leading_bypass_microtiming
                _entry_payload["_bypass_bb_regime"] = _leading_bypass_bb_regime
                # reason 에도 표시 (journal/log 추적)
                _entry_payload["reason"] = f"{_reason}|{_leading_mode}_LEAD:{_leading_reason}"
            if _phase_k_active:
                _entry_payload["_phase_k"] = True
                _entry_payload["_phase_k_reason"] = _phase_k_reason
                _entry_payload["_phase_k_size_mult"] = float(self.config.regime_transition_size_mult)
                _entry_payload["_phase_k_tp_mult"] = float(self.config.regime_transition_tp_mult)
                _entry_payload["_phase_k_sl_mult"] = float(self.config.regime_transition_sl_mult)
                # size_mult 적용: conviction_budget 축소
                _entry_payload["conviction_budget"] = budget * float(self.config.regime_transition_size_mult)
            # ★ Phase L.3 (2026-04-22) — PA 2건 합의 (S3 Gate 품질 게이트로 병합)
            # in-memory PA history 활용. 윈도우 내 같은 (symbol, direction) PA 2건 이상 = double confirmed.
            # default OFF — payload 항상 False (S3 Gate 가중 0). enabled 시만 작동.
            _pa_double = False
            if getattr(self.config, "pa_double_confirm_enabled", False):
                try:
                    _win_sec = float(getattr(self.config, "pa_double_confirm_window_sec", 60.0))
                    _pa_hist = getattr(self, "_pa_signal_history", {})
                    if not _pa_hist:
                        self._pa_signal_history = {}
                        _pa_hist = self._pa_signal_history
                    _key = (symbol.upper(), direction)
                    _now = time.time()
                    # 기존 ts 들 중 윈도우 내 것만 유지
                    _hist = [t for t in _pa_hist.get(_key, []) if (_now - t) <= _win_sec]
                    _hist.append(_now)
                    _pa_hist[_key] = _hist
                    if len(_hist) >= 2:
                        _pa_double = True
                        logger.info("[FOCUS] Phase L.3 PA double confirmed: %s %s (%d signals in %.0fs)",
                                    symbol, direction, len(_hist), _win_sec)
                except Exception as _l3_exc:
                    logger.debug("[FOCUS] Phase L.3 PA double check failed: %s", _l3_exc)
            _entry_payload["_pa_double_confirmed"] = _pa_double

            # ★ [2026-05-18] Leading Entry — _scan_log 에도 정보 표시 (UI STATUS 녹색/보라 배지)
            if _leading_eligible:
                _scan_log.append(f"{symbol}:{_leading_mode}_LEAD({_leading_reason})")

            result = self._execute_entry(_entry_payload)
            if result.get("state") == "POSITIONED":
                entered.append(symbol)
                held.add(symbol)
                open_count += 1
                logger.info("[FOCUS] Scanner ENTERED: %s %s adx=%.1f conv=%d%s",
                           direction, symbol, c.get("adx", 0), conviction,
                           f" [{_leading_mode}_LEAD]" if _leading_eligible else "")
                break  # 성공 → 틱당 1개 진입
            elif result.get("microtiming_deferred"):
                # [2026-05-16] 5m Microtiming Gate defer — BLOCK 카운트 안 쌓이는 조용한 대기
                _scan_log.append(f"{symbol}:microtiming_defer")
                # 상태 변경 없음 — 다음 후보로 자연 진행
                if self.state != FocusState.HUNT and self.state != FocusState.POSITIONED:
                    self.state = FocusState.HUNT
                continue
            else:
                # [2026-04-09] 실패 시 다음 코인 시도 (break 제거)
                # ★ [2026-05-17] UI STATUS 용 — _execute_entry 거절 사유 추출 (전체 result dict 노출 X)
                _err_reason = ""
                if isinstance(result, dict):
                    _err_reason = (result.get("error") or result.get("skip") or result.get("reason") or "exec_fail")
                else:
                    _err_reason = "exec_fail"
                _scan_log.append(f"{symbol}:{_err_reason}")
                _pipeline_syms.add(symbol)  # ★ 이 심볼은 _execute_entry 안에서 record_blocked→sink 로 집계됨 (아래 prefilter 집계서 제외)
                logger.warning("[FOCUS] Scanner entry FAILED: %s %s → %s — trying next", direction, symbol, result)
                # _execute_entry가 DORMANT로 바꿨을 수 있음 → HUNT 복원
                if self.state != FocusState.HUNT and self.state != FocusState.POSITIONED:
                    self.state = FocusState.HUNT
                continue  # 다음 코인 시도

        if _scan_log:
            # ★ Phase H (2026-04-20 형 letter#3 B-1): [:8] cap → [:25]
            # ZEC 같은 SW_LOWER_BB 신호가 8번째 이후에 위치하면 안 보여서 데드 의심받음
            logger.info("[FOCUS] Scanner filter (%d items): %s", len(_scan_log), " | ".join(_scan_log[:25]))
        # ★ [2026-05-17] scan-list API 용 차단 이유 캐싱 (UI STATUS 칼럼 표시)
        _block_dict = {}
        for entry in _scan_log:
            if ':' in entry:
                _sym, _reason = entry.split(':', 1)
                _block_dict[_sym] = _reason
        self._last_scan_filter = {'ts': time.time(), 'items': _block_dict}
        # ★ [2026-06-15 해결안 B] scanner pre-filter(BB_REGIME 정점/blacklisted/held/reentry/adx/conv 등)도
        #   gate_ledger 에 집계 — '왜 침묵했나' 완성. _pipeline_syms(record_blocked sink 가 이미 셈)는 제외=중복 0.
        if self._gate_ledger is not None and self.config.gate_ledger_enabled:
            for _sym, _reason in _block_dict.items():
                if _sym in _pipeline_syms:
                    continue
                # 라벨 정규화: 첫 토큰만 (BB_REGIME(..)→BB_REGIME, adx=13<15→adx, dir_limit_both(..)→dir_limit_both)
                _label = _reason.split('(')[0].split(':')[0].split(',')[0].split('=')[0].split('<')[0].split('>')[0].split(' ')[0].strip()[:40] or "-"
                try:
                    self._gate_ledger.record(_sym, _label, passed=False)
                except Exception:  # noqa: BLE001
                    pass

        return {"scanner_entered": entered} if entered else {"scanner": "no_match"}

    def _handle_idle(self, now: float) -> Dict:
        # Check daily plan limit
        if self.daily_plans_used >= self.config.max_daily_plans:
            return {"state": "DORMANT", "reason": "daily_plan_limit"}
        if self.daily_sl_count >= self.config.max_daily_sl:
            return {"state": "DORMANT", "reason": "daily_sl_limit"}

        # Time for next scan?
        if now - self.last_scan_ts >= self.config.scan_interval_sec:
            self.state = FocusState.HUNT
            self.last_scan_ts = now
            self._save_config()
            logger.info("[FOCUS] IDLE → SELECTING")

        return {"state": "DORMANT", "next_scan_in": max(0, self.config.scan_interval_sec - (now - self.last_scan_ts))}

    def _handle_selecting(self, now: float) -> Dict:
        """Run 3-point confirmation coin scan."""
        # ★ lock_market: 고정 코인이 설정되어 있으면 스캔 건너뛰고 바로 진입
        if self.config.lock_market:
            locked = self.config.lock_market.upper()
            logger.info("[FOCUS] LOCKED to %s — skipping scan", locked)
            # [2026-04-18] LONG fallback 제거 — H4 분석 실패 시 진입 안 함
            direction = "HOLD"
            try:
                from app.strategy.greenpen import full_analysis
                from app.strategy.greenpen.pa_detector import OHLCV
                raw = self._get_client().get_kline(locked, interval=self.config.primary_tf, limit=100)
                candles = [OHLCV(float(r[1]),float(r[2]),float(r[3]),float(r[4])) for r in raw if len(r)>=5]
                if len(candles) >= 20:
                    analysis = full_analysis(candles)
                    # full_analysis returns GreenPenAnalysis dataclass, not dict
                    pa_list = getattr(analysis, 'pa_signals', []) or []
                    struct = getattr(analysis, 'structure', None)
                    trend_val = ""
                    if struct and hasattr(struct, 'trend'):
                        trend_val = struct.trend.value if hasattr(struct.trend, 'value') else str(struct.trend)
                    if pa_list:
                        best_pa = pa_list[0]
                        direction = best_pa.direction.value  # "LONG" or "SHORT"
                        # ★ 추세-PA 방향 충돌 시 추세 우선 (역추세 진입 방지)
                        if trend_val and (
                            (direction == "SHORT" and trend_val == "UPTREND") or
                            (direction == "LONG" and trend_val == "DOWNTREND")
                        ):
                            logger.warning("[FOCUS] PA %s → %s conflicts with %s — overriding to trend direction",
                                          best_pa.pattern.value, direction, trend_val)
                            direction = "LONG" if trend_val == "UPTREND" else "SHORT"
                    elif trend_val == "DOWNTREND":
                        direction = "SHORT"
                    elif trend_val == "UPTREND":
                        direction = "LONG"
                    if self.config.direction_mode == "long_only":
                        direction = "LONG"
                    elif self.config.direction_mode == "short_only":
                        direction = "SHORT"
                    self.primary_sig = {
                        "pattern": pa_list[0].pattern.value if pa_list else "-",
                        "direction": direction,
                        "confidence": pa_list[0].confidence if pa_list else 0,
                        "atr": getattr(analysis, 'atr', 0) or 0,
                    }
                    zones_raw = getattr(analysis, 'zones', []) or []
                    self.zones = [{"type": getattr(z, 'type', {}).value if hasattr(getattr(z, 'type', None), 'value') else str(getattr(z, 'type', '')),
                                   "price_low": getattr(z, 'price_low', 0), "price_high": getattr(z, 'price_high', 0),
                                   "strength": getattr(z, 'strength', 1.0)}
                                  for z in zones_raw]
            except Exception as exc:
                logger.warning("[FOCUS] lock_market analysis failed: %s — using HOLD (no entry)", exc)

            self.selected_market = locked
            self.selected_direction = direction
            self.state = FocusState.HUNT
            self.last_scan_ts = now
            self._save_config()
            logger.info("[FOCUS] LOCKED %s %s → WATCHING", locked, direction)
            return {"state": "HUNT", "market": locked, "direction": direction, "locked": True}

        try:
            from app.manager.focus_coin_selector import select_focus_coin
            result = select_focus_coin(
                self.system,
                self._get_client(),
                direction_mode=self.config.direction_mode,
                primary_tf=self.config.primary_tf,
            )
        except Exception as exc:
            logger.warning("[FOCUS] coin selection failed: %s", exc)
            self.state = FocusState.DORMANT
            self._save_config()
            return {"state": "HUNT", "error": str(exc)}

        if not result or not result.get("market"):
            logger.info("[FOCUS] No coin passed 3-point confirmation → IDLE")
            self.state = FocusState.DORMANT
            self._save_config()
            return {"state": "HUNT", "result": "no_candidate"}

        # ★ 블랙리스트 체크 (주문 거부된 코인 10분간 제외)
        bl = getattr(self, '_temp_blacklist', {})
        if result["market"] in bl and bl[result["market"]] > time.time():
            logger.info("[FOCUS] %s blacklisted (%.0fs remaining) — IDLE",
                        result["market"], bl[result["market"]] - time.time())
            self.state = FocusState.DORMANT
            self._save_config()
            return {"state": "DORMANT", "skip": "blacklisted"}

        # 이미 보유한 코인이면 스킵
        held_markets = {p.market for p in self.positions}
        if result["market"] in held_markets:
            logger.info("[FOCUS] %s already held — skipping", result["market"])
            self.state = FocusState.DORMANT
            return {"state": "DORMANT", "skip": "already_held"}

        # Coin selected!
        self.selected_market = result["market"]
        self.selected_direction = result.get("direction", "")
        self.zones = result.get("zones", [])
        self.primary_sig = result.get("primary_sig")

        # ★ 선정된 코인을 price_store에 등록 → WebSocket 실시간 가격 수신
        try:
            if self.system:
                feed = getattr(self.system, "price_feed", None)
                if feed and hasattr(feed, "add_symbol"):
                    feed.add_symbol(result["market"])
                    logger.info("[FOCUS] Added %s to price feed subscription", result["market"])
        except Exception as exc:
            logger.debug("[FOCUS] price feed subscription failed: %s", exc)

        # 강한 신호 (conf >= 70%) → ZONE_WAIT/WATCHING 건너뛰고 바로 진입
        conf = float(result.get("confidence", 0) or 0)
        if conf >= 0.85:
            price = self._get_current_price(self.selected_market)
            if price and price > 0:
                atr = float(result.get("atr", 0) or price * 0.02)
                logger.info("[FOCUS] Strong signal %.0f%% — FAST ENTRY %s %s @ %.2f",
                            conf * 100, self.selected_direction, self.selected_market, price)
                return self._execute_entry({
                    "enter": True,
                    "direction": self.selected_direction,
                    "market": self.selected_market,  # ★ M15 FIX
                    "price": price,
                    "atr": atr,
                    "reason": f"fast_entry_conf:{conf:.0%}",
                })

        self.state = FocusState.ALERT
        self._save_config()
        logger.info("[FOCUS] Selected %s %s (conf=%.0f%%) → ZONE_WAIT", self.selected_market, self.selected_direction, conf * 100)
        return {"state": "ALERT", "market": self.selected_market, "direction": self.selected_direction}

    def _handle_zone_wait(self, now: float) -> Dict:
        """Wait for H4 PA SIG at Zone."""
        # 스캔 간격마다 재분석 (lock_market이어도 존 갱신 필요)
        if now - self.last_scan_ts >= self.config.scan_interval_sec:
            self.last_scan_ts = now
            if not self.config.lock_market:
                self.state = FocusState.HUNT
                logger.info("[FOCUS] ZONE_WAIT → re-scan for better coin")
                return self._handle_selecting(now)
            else:
                # ★ lock_market: 코인은 안 바꾸지만 존/시그널은 갱신
                try:
                    from app.strategy.greenpen import full_analysis
                    from app.strategy.greenpen.pa_detector import OHLCV
                    raw = None
                    for _kl_try in range(2):
                        try:
                            raw = self._get_client().get_kline(self.config.lock_market, interval=self.config.primary_tf, limit=50)
                            break
                        except (ConnectionError, OSError) as _ke:
                            if _kl_try == 0:
                                import time as _kt; _kt.sleep(1)
                            else:
                                logger.warning("[FOCUS] ZONE_WAIT kline retry failed: %s", _ke)
                    if not raw:
                        raise RuntimeError("kline fetch failed")
                    candles = [OHLCV(float(r[1]),float(r[2]),float(r[3]),float(r[4])) for r in raw if len(r)>=5]
                    if len(candles) >= 20:
                        analysis = full_analysis(candles)
                        zones_raw = getattr(analysis, 'zones', []) or []
                        self.zones = [{"type": getattr(z, 'type', {}).value if hasattr(getattr(z, 'type', None), 'value') else str(getattr(z, 'type', '')),
                                       "price_low": getattr(z, 'price_low', 0), "price_high": getattr(z, 'price_high', 0),
                                       "strength": getattr(z, 'strength', 1.0)}
                                      for z in zones_raw]
                        # ATR + 방향도 갱신
                        struct = getattr(analysis, 'structure', None)
                        trend_val = ""
                        if struct and hasattr(struct, 'trend'):
                            trend_val = struct.trend.value if hasattr(struct.trend, 'value') else str(struct.trend)
                        atr_val = getattr(analysis, 'atr', 0) or 0
                        if trend_val:
                            self.selected_direction = "LONG" if trend_val == "UPTREND" else ("SHORT" if trend_val == "DOWNTREND" else self.selected_direction)
                        self.primary_sig = {
                            # [2026-04-18] LONG fallback 제거 — dead code 재활성화 대비
                            "pattern": "-", "direction": self.selected_direction or "HOLD",
                            "confidence": 0, "atr": atr_val,
                        }
                        logger.info("[FOCUS] ZONE_WAIT refresh: %d zones, ATR=%.2f, trend=%s",
                                    len(self.zones), atr_val, trend_val or "-")
                        self._save_config()
                except Exception as exc:
                    logger.warning("[FOCUS] ZONE_WAIT zone refresh failed: %s", exc)

        try:
            from app.manager.focus_entry_signal import check_primary_sig
            sig = check_primary_sig(
                self._get_client(),
                self.selected_market,
                self.zones,
                self.config.primary_tf,
            )
        except Exception as exc:
            logger.warning("[FOCUS] PRIMARY SIG check failed: %s", exc)
            return {"state": "ALERT", "error": str(exc)}

        if sig and sig.get("valid"):
            self.primary_sig = sig
            self.state = FocusState.HUNT
            self._save_config()
            logger.info("[FOCUS] PRIMARY SIG confirmed → WATCHING: %s", sig.get("pattern"))
            return {"state": "HUNT", "sig": sig}

        # ★ PA 패턴 없어도 ATR은 저장 (Harpoon이 ATR 필요)
        if not self.primary_sig or not isinstance(self.primary_sig, dict) or not self.primary_sig.get("atr"):
            try:
                from app.strategy.greenpen.pa_detector import OHLCV
                from app.strategy.greenpen import _simple_atr
                raw = self._get_client().get_kline(self.selected_market, interval=self.config.primary_tf, limit=20)
                candles = [OHLCV(float(r[1]),float(r[2]),float(r[3]),float(r[4])) for r in raw if len(r)>=5]
                if len(candles) >= 5:
                    atr = _simple_atr(candles)
                    self.primary_sig = {
                        # [2026-04-18] LONG fallback 제거 — dead code 재활성화 대비
                        "pattern": "-", "direction": self.selected_direction or "HOLD",
                        "confidence": 0, "atr": atr,
                    }
            except Exception as exc:
                logger.debug("[FOCUS] import OHLCV failed: %s", exc)

        return {"state": "ALERT", "market": self.selected_market}

    def _handle_watching(self, now: float, btc_price: float) -> Dict:
        """Wait for M5 precision entry signal."""
        # 스캔 간격마다 더 좋은 코인이 있는지 재확인 (lock_market이면 재스캔 불필요)
        if not self.config.lock_market and now - self.last_scan_ts >= self.config.scan_interval_sec:
            self.last_scan_ts = now
            self.state = FocusState.HUNT
            logger.info("[FOCUS] WATCHING → re-scan for better coin")
            return self._handle_selecting(now)

        # [2026-04-18] LONG fallback 제거 — direction 없으면 진입 안 함
        _watch_dir = self.selected_direction or (self.primary_sig or {}).get("direction")
        if _watch_dir not in ("LONG", "SHORT"):
            return {"state": "ALERT", "skip": "no_direction"}

        try:
            from app.manager.focus_entry_signal import check_m5_entry
            entry = check_m5_entry(
                self._get_client(),
                self.selected_market,
                _watch_dir,
                self.config.entry_tf,
                btc_price=btc_price,
                zones=self.zones,
            )
        except Exception as exc:
            logger.warning("[FOCUS] M5 entry check failed: %s", exc)
            return {"state": "HUNT", "error": str(exc)}

        if entry and entry.get("enter"):
            entry.setdefault("market", self.selected_market)
            return self._execute_entry(entry)

        # PRIMARY SIG confidence가 70%+ 이면 M5 확인 없이 직접 진입 (기다림이 기회를 놓침)
        primary_conf = float((self.primary_sig or {}).get("confidence", 0) or 0)
        if primary_conf >= 0.85 and not entry:
            # [2026-04-18] LONG fallback 제거 — direction 불명확하면 진입 안 함
            primary_dir = self.selected_direction or (self.primary_sig or {}).get("direction") or "HOLD"
            if primary_dir not in ("LONG", "SHORT"):
                return {"state": "ALERT", "skip": "no_direction"}
            price = self._get_current_price(self.selected_market)
            if price and price > 0:
                from app.strategy.greenpen import _simple_atr
                from app.strategy.greenpen.pa_detector import OHLCV
                candles = []
                try:
                    raw = self._get_client().get_kline(self.selected_market, interval=self.config.entry_tf, limit=20)
                    candles = [OHLCV(float(r[1]),float(r[2]),float(r[3]),float(r[4])) for r in raw if len(r)>=5]
                    atr = _simple_atr(candles) if len(candles) >= 5 else price * 0.02
                except Exception as exc:
                    logger.debug("[FOCUS] raw failed (fallback): %s", exc)
                    atr = price * 0.02

                # ── 최소한의 M5 추세 확인 (고신뢰도라도 역추세 직접 진입 차단) ──
                if len(candles) >= 10:
                    try:
                        from app.strategy.greenpen.market_structure import analyze_structure as _az
                        _m5s = _az(candles, lookback=3)
                        _m5t = _m5s.trend.value if hasattr(_m5s.trend, 'value') else str(_m5s.trend)
                        if primary_dir == "LONG" and _m5t == "DOWNTREND":
                            logger.info("[FOCUS] PRIMARY conf %.0f%% but M5 DOWNTREND — skip direct entry",
                                        primary_conf * 100)
                            return {"state": "HUNT", "market": self.selected_market}
                        if primary_dir == "SHORT" and _m5t == "UPTREND":
                            logger.info("[FOCUS] PRIMARY conf %.0f%% but M5 UPTREND — skip direct entry",
                                        primary_conf * 100)
                            return {"state": "HUNT", "market": self.selected_market}
                    except Exception as exc:
                        logger.debug("[FOCUS] import analyze_structure as _az failed: %s", exc)  # 분석 실패 시 H4 고신뢰도 우선 허용

                logger.info("[FOCUS] PRIMARY conf %.0f%% >= 70%% — direct entry %s %s @ %.2f",
                            primary_conf * 100, primary_dir, self.selected_market, price)
                return self._execute_entry({
                    "enter": True, "direction": primary_dir,
                    "market": self.selected_market,  # ★ M15 FIX
                    "price": price, "atr": atr,
                    "reason": f"primary_high_conf:{primary_conf:.0%}",
                })

        return {"state": "HUNT", "market": self.selected_market}

    def _handle_positioned(self, now: float, btc_price: float) -> Dict:
        """LEGACY — tick()에서 직접 호출되지 않음. _manage_all_positions이 대체.
        API disable → _execute_exit 경로에서만 간접 참조됨."""
        if not self.position:
            self.state = FocusState.DORMANT
            self._save_config()
            return {"state": "POSITIONED", "error": "no_position"}

        price = self._get_current_price(self.position.market)
        if not price or price <= 0:
            return {"state": "POSITIONED", "market": self.position.market, "price": "unavailable"}

        from app.strategy.greenpen.cycle_tp import (
            CycleTargets, should_partial_exit, should_full_exit,
        )

        targets = CycleTargets(
            tp1=self.position.tp1,
            tp2=self.position.tp2,
            sl=self.position.sl,
            rr_ratio=0,
            atr_used=self.position.atr_used,
            direction=self.position.direction,
        )

        # Check SL / TP2
        exit_reason = should_full_exit(
            price, self.position.entry_price, self.position.direction, targets,
        )
        if exit_reason:
            return self._execute_exit(exit_reason, is_sl="SL hit" in exit_reason)

        # Check TP1 partial
        partial = should_partial_exit(
            price, self.position.entry_price, self.position.direction, targets,
            partial_pct=self.config.partial_exit_pct,
            already_partial=self.position.partial_done,
        )
        if partial:
            return self._execute_partial(partial, price)

        # ── 다단계 긴급 탈출 (업비트 친구 시스템) ──
        if self.config.emergency_tp_tiers and btc_price > 0:
            try:
                from app.core.hyper_price_store import price_store
                btc_prices = price_store.get_prices("BTCUSDT", count=60)
                if btc_prices and len(btc_prices) >= 10:
                    btc_recent = [float(p) for p in btc_prices[-10:] if p]
                    if btc_recent and btc_recent[0] > 0:
                        btc_change_pct = (btc_recent[-1] / btc_recent[0] - 1) * 100
                        # Tier 1: BTC -3% → TP 축소 50%
                        if btc_change_pct < -3.0:
                            reduced_tp1 = self.position.entry_price + (self.position.tp1 - self.position.entry_price) * 0.5
                            if self.position.direction == "SHORT":
                                reduced_tp1 = self.position.entry_price - (self.position.entry_price - self.position.tp1) * 0.5
                            self.position.tp1 = reduced_tp1
                            logger.warning("[FOCUS] Emergency Tier1: BTC %.1f%% → TP1 tightened to %.2f", btc_change_pct, reduced_tp1)
                        # Tier 2: BTC -5% → 즉시 청산
                        if btc_change_pct < -5.0:
                            return self._execute_exit(f"BTC_CRASH:{btc_change_pct:.1f}%", is_sl=True)
            except Exception as exc:
                logger.warning("[FOCUS] emergency tier check failed: %s", exc)

        pnl_pct = ((price / self.position.entry_price) - 1) * 100
        if self.position.direction == "SHORT":
            pnl_pct = -pnl_pct

        return {
            "state": "POSITIONED",
            "market": self.position.market,
            "direction": self.position.direction,
            "entry": self.position.entry_price,
            "current": price,
            "pnl_pct": round(pnl_pct, 2),
            "tp1": self.position.tp1,
            "sl": self.position.sl,
        }

    def _handle_trailing(self, now: float, btc_price: float) -> Dict:
        """LEGACY — tick()에서 직접 호출되지 않음. _manage_all_positions이 대체."""
        if not self.position:
            self.state = FocusState.DORMANT
            self._save_config()
            return {"state": "POSITIONED", "error": "no_position"}

        price = self._get_current_price(self.position.market)
        if not price or price <= 0:
            return {"state": "POSITIONED", "price": "unavailable"}

        # Update trailing watermark
        if self.position.direction == "LONG":
            if price > self.position.trailing_high:
                self.position.trailing_high = price
        else:
            if self.position.trailing_low <= 0 or price < self.position.trailing_low:
                self.position.trailing_low = price

        from app.strategy.greenpen.cycle_tp import CycleTargets, should_full_exit

        targets = CycleTargets(
            tp1=self.position.tp1, tp2=self.position.tp2,
            sl=self.position.sl, rr_ratio=0,
            atr_used=self.position.atr_used, direction=self.position.direction,
        )

        exit_reason = should_full_exit(
            price, self.position.entry_price, self.position.direction, targets,
            trailing_high=self.position.trailing_high,
            trailing_low=self.position.trailing_low,
            trailing_pct=self.config.trailing_pct,
        )
        if exit_reason:
            return self._execute_exit(exit_reason, is_sl="SL hit" in exit_reason)

        return {"state": "POSITIONED", "market": self.position.market, "price": price}

    def _handle_cooldown(self, now: float) -> Dict:
        # ── 플립 기회: LONG 청산 조건 = SHORT 기회 (반대도 동일) ──
        # BB+MACD 기반 청산 시 방향 전환 기회 → 쿨다운 30초로 단축
        if self._pending_flip:
            flip_cooldown = 30.0  # 기회를 놓치지 않기 위해 30초만
            elapsed = now - self.cooldown_start_ts
            if elapsed >= flip_cooldown:
                flip_dir = self._pending_flip
                self._pending_flip = ""
                # v2: 플립이 같은 방향이면 재진입 차단 체크
                price = self._get_current_price(self._last_exit_market or self.config.lock_market or "BTCUSDT") or 0
                if flip_dir == self._last_exit_direction and price > 0:
                    if not self._check_reentry_allowed(flip_dir, self._last_exit_market, price):
                        logger.info("[FOCUS] Flip %s blocked by reentry filter → DORMANT", flip_dir)
                        self.state = FocusState.DORMANT
                        self._save_config()
                        return {"state": "DORMANT", "flip_blocked": flip_dir}
                self.selected_direction = flip_dir
                self.state = FocusState.HUNT
                self.last_scan_ts = 0  # 즉시 재스캔
                self._save_config()
                logger.info("[FOCUS] FLIP COOLDOWN → HUNT (direction=%s)", flip_dir)
                return {"state": "HUNT", "flip": flip_dir}
            return {"state": "COOLDOWN", "remaining_sec": round(flip_cooldown - elapsed), "pending_flip": self._pending_flip}

        # ── 일반 Adaptive Cooldown: 연패 시 쿨다운 증가 ──
        base_cooldown = self.config.cooldown_sec
        if self.config.adaptive_cooldown and self.daily_sl_count >= 2:
            cd_mult = min(2.5, 1.0 + (self.daily_sl_count - 2) * 0.5)
            base_cooldown *= cd_mult

        elapsed = now - self.cooldown_start_ts
        remaining = max(0, base_cooldown - elapsed)
        if remaining <= 0:
            self._pending_flip = ""
            self.state = FocusState.DORMANT
            self._save_config()
            logger.info("[FOCUS] COOLDOWN → DORMANT")
            return {"state": "DORMANT"}
        return {"state": "COOLDOWN", "remaining_sec": round(remaining)}

    # ── Execution ───────────────────────────────────────────

    def _get_effective_budget(self, market: str) -> float:
        """Budget=0이면 기존 시스템 예산 배정 로직 활용, >0이면 고정 예산.
        어떤 경우든 최소 $5 보장."""
        MIN_BUDGET = 5.0
        if self.config.budget_usdt > 0:
            return max(MIN_BUDGET, self.config.budget_usdt)

        # Budget=0: 기존 slot 예산 시스템에서 배정받기
        try:
            system = self.system
            if system:
                # 1) OMA에 budget_usdt가 이미 배정되어 있으면 사용
                oma_budget = None
                try:
                    oma_budget = system.oma_registry.get_budget_usdt(market)
                except Exception as exc:
                    logger.debug("[FOCUS] oma_budget failed: %s", exc)
                if oma_budget and float(oma_budget) > 0:
                    return max(MIN_BUDGET, float(oma_budget))

                # 2) equity / active 슬롯 수로 균등 분배
                equity = float(getattr(system, '_last_equity_usdt', 0) or 0)
                # ★ Nunnaya 배치 자본 차감 (이중 지출 방지)
                try:
                    from app.core.cross_strategy_guard import get_total_deployed_usdt
                    _, _nunnaya_deployed = get_total_deployed_usdt(system)
                    if _nunnaya_deployed > 0:
                        equity = max(0.0, equity - _nunnaya_deployed)
                except Exception as exc:
                    logger.debug("[FOCUS] import get_total_deployed_usdt failed: %s", exc)
                deploy_ratio = float(getattr(system, 'deploy_ratio', 0.5) or 0.5)
                active_count = max(1, len(system.oma_registry.list_active()) + 1)
                auto_budget = (equity * deploy_ratio) / active_count
                if auto_budget > 0:
                    auto_budget = max(MIN_BUDGET, auto_budget)
                    logger.info("[FOCUS] Budget=0 → auto budget: $%.2f (equity=%.0f × %.0f%% / %d slots)",
                                auto_budget, equity, deploy_ratio * 100, active_count)
                    return auto_budget
        except Exception as exc:
            logger.warning("[FOCUS] auto budget calc failed: %s", exc)

        # 최종 fallback — 최소 $5 (Q.min_order) 보장
        return max(MIN_BUDGET, 10.0)

    def _check_portfolio_sl_rate_pause(self) -> tuple:
        """#2A — 최근 N분 SL hit M건 이상이면 신규 진입 차단 (동시 SL 방어).

        4-26 형 검수: 6슬롯 풀가동 시 BTC 급변 동반 SL 시나리오 대응.
        부모님 인내 정신 충돌 X — "한 번 맞아도 그 다음 추가 손실 방어".
        Returns: (paused: bool, reason: str)
        """
        if not getattr(self.config, "portfolio_sl_rate_enabled", True):
            return False, ""
        now = time.time()
        # pause 활성 중이면 그대로 유지
        until = getattr(self, "_portfolio_sl_pause_until", 0.0)
        if until > now:
            return True, f"portfolio_sl_pause: {(until - now)/60:.1f}min remaining"
        # 최근 SL hit 카운트
        window_min = float(getattr(self.config, "portfolio_sl_rate_window_min", 5))
        threshold = int(getattr(self.config, "portfolio_sl_rate_threshold", 3))
        cutoff = now - window_min * 60
        sl_ts_list = getattr(self, "_recent_sl_ts", []) or []
        recent = [t for t in sl_ts_list if t >= cutoff]
        self._recent_sl_ts = recent  # 윈도우 밖 정리
        if len(recent) >= threshold:
            pause_min = float(getattr(self.config, "portfolio_sl_rate_pause_min", 15))
            self._portfolio_sl_pause_until = now + pause_min * 60.0
            logger.warning("[FOCUS] ★ PORTFOLIO SL PAUSE: %d SL hits in %.0fmin → pause %.0fmin (동시 SL 방어)",
                           len(recent), window_min, pause_min)
            return True, f"portfolio_sl_pause: {len(recent)} SL/{window_min:.0f}min"
        return False, ""

    def _record_sl_hit(self, market: str = ""):
        """#2A SL hit 기록 — _close_position / SERVER_SL EXIT 시 호출."""
        if not hasattr(self, "_recent_sl_ts"):
            self._recent_sl_ts = []
        self._recent_sl_ts.append(time.time())
        # 30분 이상 오래된 것 정리
        cutoff = time.time() - 1800
        self._recent_sl_ts = [t for t in self._recent_sl_ts if t >= cutoff]

    def _check_regime_reversal_pause(self) -> tuple:
        """#7 — BTC EMA gap 수렴 + ADX 약화 동시 = 전환점 → 신규 진입 일시 중단.

        부모님 메모리: "전환점 = 학비 가장 비싼 구간, 기다림이 가장 비싼 투자"
        Returns: (paused: bool, reason: str)
        """
        if not getattr(self.config, "regime_reversal_pause_enabled", True):
            return False, ""
        now = time.time()
        # 기존 pause 가 활성이면 그대로 유지
        until = getattr(self, "_regime_pause_until", 0.0)
        if until > now:
            return True, f"regime_reversal_pause: {(until - now)/60:.1f}min remaining"
        # 트리거 조건 검사
        gap_th = float(getattr(self.config, "regime_reversal_ema_gap_threshold_pct", 0.3))
        adx_th = float(getattr(self.config, "regime_reversal_adx_threshold", 20.0))
        btc_gap = getattr(self, "_btc_ema_gap_pct", None)
        btc_adx = getattr(self, "_btc_adx_value", 0)  # ★ BTC 전용 (2026-06-04 bug fix: _last_adx_value → 임의 코인 ADX 참조 문제)
        if btc_gap is None or btc_adx <= 0:
            return False, ""
        if btc_gap < gap_th and btc_adx < adx_th:
            pause_min = float(getattr(self.config, "regime_reversal_pause_min", 15.0))
            self._regime_pause_until = now + pause_min * 60.0
            logger.info("[FOCUS] ★ REGIME REVERSAL PAUSE: gap=%.3f%% adx=%.1f → pause %.0fmin (전환점 학비 회피)",
                        btc_gap, btc_adx, pause_min)
            return True, f"regime_reversal_pause: gap={btc_gap:.3f}% adx={btc_adx:.1f}"
        return False, ""

    def _btc_trend_conv_bonus(self, direction: str) -> int:
        """#4 — BTC UPTREND 시 LONG +N / DOWNTREND 시 SHORT +N conviction 보너스."""
        if not getattr(self.config, "btc_trend_conv_bonus_enabled", True):
            return 0
        bonus = int(getattr(self.config, "btc_trend_conv_bonus", 2))
        regime = getattr(self, "_b11_regime_state", ("", 0.0))
        regime_label = (regime[0] if regime and len(regime) > 0 else "").upper()
        d = (direction or "").upper()
        if regime_label in ("BULL", "UPTREND") and d == "LONG":
            return bonus
        if regime_label in ("BEAR", "DOWNTREND") and d == "SHORT":
            return bonus
        return 0

    def _conv_sizing_multiplier(self, conviction: float) -> float:
        """[2026-05-17 100점 ×10] Conviction 가중 budget multiplier.
        low≤50: 0.5x / mid: 1.0x / high≥80: 1.5x (옛 5/9 → 50/80)"""
        if not getattr(self.config, "conv_sizing_enabled", True):
            return 1.0
        low = float(getattr(self.config, "conv_sizing_low_threshold", 50.0))    # [100점 ×10] 5→50
        high = float(getattr(self.config, "conv_sizing_high_threshold", 90.0))  # [100점 ×10] 9→90
        if conviction <= low:
            return 0.5
        if conviction >= high:
            return 1.5
        return 1.0

    def _conv_risk_factor(self, conviction: float) -> float:
        """[진입점수=확신, 2026-06-13 부모] guard 점수 → risk 배수. 진입임계(guard_score_threshold) anchor + 역U자.
        임계=1.0x(확신 기준선) → peak_conv 까지 선형↑(peak_mult) → 끝물(≥chop_conv)=chop_mult 컷.
        budget×conv 는 cap이 먹어버려 → risk_pct 에 곱해 qty에 직접 닿게. default OFF → 1.0."""
        if not getattr(self.config, "conv_risk_scale_enabled", False):
            return 1.0
        try:
            thr = float(getattr(self.config, "guard_score_threshold", 50.0))   # ★ 동적 anchor (50 못박음 X)
            peak_c = float(getattr(self.config, "conv_risk_peak_conv", 65.0))
            peak_m = float(getattr(self.config, "conv_risk_peak_mult", 1.5))
            chop_c = float(getattr(self.config, "conv_risk_chop_conv", 80.0))
            chop_m = float(getattr(self.config, "conv_risk_chop_mult", 0.6))
            floor_m = float(getattr(self.config, "conv_risk_floor_mult", 0.5))
            max_m = float(getattr(self.config, "conv_risk_max_mult", 2.0))
            c = float(conviction)
            if c < thr:
                f = floor_m                       # 임계 미만(이례) — 안전하게 작게
            elif c >= chop_c:
                f = chop_m                        # 끝물 컷 (80+ = 후행)
            elif c >= peak_c:
                f = peak_m                        # sweet spot 정점 (65~80)
            else:
                span = max(1e-9, peak_c - thr)    # 임계(1.0) → peak_conv(peak_m) 선형
                f = 1.0 + (c - thr) / span * (peak_m - 1.0)
            return max(0.1, min(max_m, f))
        except Exception:
            return 1.0

    def _multi_be_lock_target(self, peak_pct: float, pos: Optional["FocusPosition"] = None) -> float:
        """#6 — 다단 BE Lock. peak 도달 단계별 lock 강화.

        [2026-05-21 부모] ATR 적응 모드 추가.
          ON 모드 (default): stage trigger = ATR% × stage_atr_mult
            - 변동성 큰 코인은 더 멀리 가야 BE — 일찍 컷 방지
            - 예: BTC ATR ~1% → stage1=0.3, HYPE ATR ~3% → stage1=0.9
            - lock 값도 비례 (stage2 lock = stage1 trigger, stage3 lock = stage2 trigger, etc.)
          OFF 모드: 기존 고정 % (stage1=0.4, stage2=1.0, stage3=2.0, stage4=3.0)

        [2026-05-16 부모] stage1 이 0.0 (price-BE) 이면 fee 0.11% 그대로 손실.
        SUI 사례: peak +0.64% → SL=entry → fee 컷 -$0.78. fee_cushion 으로 진짜 BE.
        """
        cfg = self.config
        if not getattr(cfg, "multi_be_lock_enabled", True):
            return 0.0

        fee_cushion = float(getattr(cfg, "multi_be_lock_fee_cushion_pct", 0.15))
        adaptive = getattr(cfg, "multi_be_lock_atr_adaptive_enabled", True)
        atr_pct = 0.0

        if adaptive and pos is not None:
            try:
                market = getattr(pos, "market", "") or ""
                if market:
                    tf = str(getattr(cfg, "multi_be_lock_atr_tf", "60") or "60")
                    period = int(getattr(cfg, "multi_be_lock_atr_period", 14))
                    raw = self._get_mtf_kline(market, tf, limit=period + 5)
                    if raw and len(raw) >= period + 2:
                        ordered = list(raw)
                        trs = []
                        for i in range(1, len(ordered)):
                            h = float(ordered[i][2])
                            l = float(ordered[i][3])
                            pc = float(ordered[i - 1][4])
                            tr = max(h - l, abs(h - pc), abs(l - pc))
                            trs.append(tr)
                        if len(trs) >= period:
                            atr = sum(trs[-period:]) / period
                            last_close = float(ordered[-1][4])
                            if last_close > 0 and atr > 0:
                                atr_pct = atr / last_close * 100.0
            except Exception as exc:
                logger.debug("[FOCUS] multi_be_lock ATR 계산 실패 (고정 모드 fallback): %s", exc)

        if adaptive and atr_pct > 0:
            # ATR 적응 모드 — trigger = ATR% × mult, lock = 이전 stage trigger 비례
            s1 = atr_pct * float(getattr(cfg, "multi_be_lock_stage1_atr_mult", 0.3))
            s2 = atr_pct * float(getattr(cfg, "multi_be_lock_stage2_atr_mult", 0.7))
            s3 = atr_pct * float(getattr(cfg, "multi_be_lock_stage3_atr_mult", 1.4))
            s4 = atr_pct * float(getattr(cfg, "multi_be_lock_stage4_atr_mult", 2.2))
            # [2026-05-29 부모 5→6번째 fix] stage1 trigger 하한선 — 저변동 코인 노이즈 컷 보호
            # HYPE peak 0.094% 사고: ATR 작아서 trigger 0.05% 정도 → 진입 직후 BE lock 발동 → 노이즈 컷
            min_s1 = float(getattr(cfg, "multi_be_lock_atr_min_stage1_trigger_pct", 0.3))
            if s1 < min_s1:
                s1 = min_s1
            # ★ [2026-06-13 부모] stage1 trigger 상한 — extreme ATR 코인도 +N%엔 BE 락 (무방비 give-back 차단)
            max_s1 = float(getattr(cfg, "multi_be_lock_atr_max_stage1_trigger_pct", 3.0))
            if max_s1 > 0 and s1 > max_s1:
                s1 = max_s1
            lock_s4 = s3   # peak ≥ s4 도달 시 SL=entry+s3
            lock_s3 = s2
            lock_s2 = s1
        else:
            # 고정 % 모드 (기존)
            s1 = float(getattr(cfg, "multi_be_lock_stage1_pct", 0.4))
            s2 = float(getattr(cfg, "multi_be_lock_stage2_pct", 1.0))
            s3 = float(getattr(cfg, "multi_be_lock_stage3_pct", 2.0))
            s4 = float(getattr(cfg, "multi_be_lock_stage4_pct", 3.0))
            lock_s4 = 2.0
            lock_s3 = 1.0
            lock_s2 = 0.3

        if peak_pct >= s4: return lock_s4
        if peak_pct >= s3: return lock_s3
        if peak_pct >= s2: return lock_s2
        if peak_pct >= s1: return max(0.0, fee_cushion)
        return -999.0  # 아직 BE 미도달

    def _effective_coin_loss_cap(self) -> float:
        """Equity-scaled coin loss cap (4-26 부모님 결정 — $1000/$2000/$5000 자동 대응).

        기준: coin_loss_cap_amount 가 equity $1000 기준 절대값.
        실제 cap = amount × (equity / 1000). equity 늘면 cap 도 비례 증가.
        """
        base_amount = float(getattr(self.config, "coin_loss_cap_amount", 200.0))
        try:
            equity = float(getattr(self.system, '_last_equity_usdt', 0) or 0)
            if equity > 0:
                return base_amount * (equity / 1000.0)
        except Exception:
            pass
        return base_amount

    def _get_available_margin(self) -> float:
        """Bybit Unified Account의 실제 사용 가능 마진 조회.

        [2026-05-25 부모] paper/dry 모드 시 가상 잔고 반환 (실제 Bybit API 우회).
        _get_client() wrapper 와 별개로 직접 requests 호출하므로 여기도 paper 분기 필요.
        """
        _live = (os.getenv("TRADING_MODE", "PAPER").upper() == "LIVE"
                 and os.getenv("AUTOBOT_LIVE", "0") == "1")
        if not _live:
            return float(os.getenv("DRY_INITIAL_USDT", "1000") or "1000")
        try:
            import requests as _req, time as _t, hashlib, hmac
            key = os.environ.get('BYBIT_API_KEY', '')
            secret = os.environ.get('BYBIT_API_SECRET', '')
            ts = str(int(_t.time() * 1000))
            recv = '5000'
            params = 'accountType=UNIFIED'
            sign_str = ts + key + recv + params
            sig = hmac.new(secret.encode(), sign_str.encode(), hashlib.sha256).hexdigest()
            headers = {'X-BAPI-API-KEY': key, 'X-BAPI-TIMESTAMP': ts,
                       'X-BAPI-RECV-WINDOW': recv, 'X-BAPI-SIGN': sig}
            r = _req.get('https://api.bybit.com/v5/account/wallet-balance',
                         params={'accountType': 'UNIFIED'}, headers=headers, timeout=5)
            d = r.json()
            avail = float(d.get('result', {}).get('list', [{}])[0].get('totalAvailableBalance', 0) or 0)
            return avail
        except Exception as exc:
            logger.debug("[FOCUS] available margin check failed: %s", exc)
            return 0.0

    def _execute_entry(self, entry: Dict) -> Dict:
        """Place market order to enter position."""
        market = entry.get("market") or self.selected_market
        if not market:
            logger.error("[FOCUS] _execute_entry: no market specified!")
            return {"state": "DORMANT", "error": "no_market"}

        # [2026-04-18] direction 조기 추출 — coin_loss_cap 검사보다 먼저 필요
        #   BUG FIX: Phase 2-2 (direction-split coin_loss_cap) 도입 후
        #            direction 사용 시점이 추출 시점보다 앞이라 UnboundLocalError 발생
        #            RAVE 진입 실패 5시간 지속된 진짜 원인
        direction = entry.get("direction")
        if not direction or direction not in ("LONG", "SHORT"):
            logger.error("[FOCUS] _execute_entry: no valid direction (%s) — rejected", direction)
            return {"state": "HUNT", "error": "no_direction"}

        # ★ [2026-05-16 부모] 5m Microtiming Gate — BLOCK 아닌 WAIT/DEFER
        # conviction 통과한 후보를 5m RSI/MACD/BB 변곡 3종으로 검사. 점수 부족 시 defer.
        # 호출자(scanner)는 state != POSITIONED 이면 다음 후보로 자연 진행 — BLOCK 카운트 안 쌓임.
        # Phase K (regime transition) 진입은 옵션에 따라 면제 (시장 전환 포착 우선).
        # ★ [2026-05-16] _manual=True (수동 진입) 시 마이크로 타이밍 게이트 우회.
        _is_manual = bool(entry.get("_manual"))
        if _is_manual:
            logger.warning("[FOCUS] ★ MANUAL ENTRY — bypass microtiming/EE/MTF gates: %s %s", market, direction)
        # ── [2026-05-16 부모 비전 #4] Coin State Machine — 진입 시점 상태 분류 + entry dict 박기 ──
        if not _is_manual and getattr(self.config, "coin_state_machine_enabled", True):
            try:
                _cs_label, _cs_adj = self._classify_coin_state(market, direction)
                if _cs_label:
                    entry["_coin_state"] = _cs_label
                    entry["_coin_state_conv_adj"] = _cs_adj
                    logger.info("[FOCUS] 🎭 coin_state %s = %s (conv_adj=%+d)", market, _cs_label, _cs_adj)
                    # conviction 보정 적용 (default OFF — 검증 후 ON)
                    if getattr(self.config, "coin_state_apply_conv_adjust", False) and _cs_adj != 0:
                        _orig_conv = float(entry.get("conviction_score", 0) or 0)  # [2026-05-17 100점]
                        _new_conv = max(0.0, _orig_conv + float(_cs_adj))
                        entry["conviction_score"] = _new_conv
                        logger.info("[FOCUS] 🎭 coin_state conv 조정: %d → %d (state=%s, adj=%+d)",
                                    _orig_conv, _new_conv, _cs_label, _cs_adj)
            except Exception as exc:
                logger.debug("[FOCUS] coin_state classification failed: %s", exc)
        # ── [2026-05-27 부모] ★ Phase 6 점수 통합 — 가드를 conv 가산/감점으로 평가 ──
        #   부모님 통찰: "롱/숏 무관 점수에 따라 진입. 모든 가드 *제대로 평가*되어야".
        #   활성 시: 모든 진입 가드 우회 → 점수 평가 → 임계 통과 시 진입 직행.
        #   비활성 시: 기존 가드 직렬 차단 흐름.
        #   안전망 (이미 위에서 검사한 drawdown / hard_roe_cap / btc_emergency / portfolio_sl_rate) 은 변경 X.
        if not _is_manual and self._guard_score_mode_active():
            _gs_total, _gs_breakdown = self._compute_guard_score_modifiers(market, direction, entry)
            _base_conv = float(entry.get("conviction_score", 0) or 0)
            _final_conv = _base_conv + _gs_total
            # ★ [패치 v1] 끝물 상한 post-guards — 강등된 끝물이 가산점으로 부활하는 구멍 차단
            if (getattr(self.config, "conviction_ceiling_enabled", False)
                    and getattr(self.config, "conviction_ceiling_post_guards", False)):
                _pcc_start = float(getattr(self.config, "conviction_ceiling_start", 65.0))
                if _final_conv >= _pcc_start:
                    _pcc_target = float(getattr(self.config, "conviction_ceiling_target", 50.0))
                    _pcc_exempt = float(getattr(self.config, "conviction_ceiling_adx_exempt", 30.0))
                    _pcc_adx = float(getattr(self, "_conv_adx_cache", {}).get((market or "").upper(), 0.0) or 0.0)
                    if _pcc_exempt > 0 and _pcc_adx >= _pcc_exempt:
                        logger.info("[FOCUS] ②' 끝물 면제(벽타기, post): %s %s conv=%.0f ADX=%.0f≥%.0f",
                                    market, direction, _final_conv, _pcc_adx, _pcc_exempt)
                    else:
                        logger.info("[FOCUS] ②' 끝물 상한 (post-guards): %s %s conv %.0f→%.0f (ADX=%.0f<%.0f)",
                                    market, direction, _final_conv, min(_final_conv, _pcc_target), _pcc_adx, _pcc_exempt)
                        _final_conv = min(_final_conv, _pcc_target)
            _gs_threshold = float(getattr(self.config, "guard_score_threshold", 80.0))
            logger.info("[FOCUS] 🎯 GuardScore %s %s: base=%.1f + guards=%+.1f = %.1f (임계 %.0f)",
                        market, direction, _base_conv, _gs_total, _final_conv, _gs_threshold)
            logger.info("[FOCUS]   breakdown: %s", _gs_breakdown)
            # ★ [2026-05-28] 가드 점수 캐시 (scan-list API 가 분리 컬럼 표시) — 통과/실패 모두 저장
            _disp_total = 0.0 if abs(_final_conv) < 0.05 else _final_conv  # -0 표시 방지
            _bd_short = _gs_breakdown.replace(" | ", ",").replace("++", "+")
            self._last_guard_score[market.upper()] = {
                "base": _base_conv,
                "deduction": _gs_total,
                "total": _disp_total,
                "threshold": _gs_threshold,
                "breakdown": _bd_short,
            }
            # ── [2026-06-07 부모] 가드 정확도 측정 로그 (읽기전용·동작 무영향) ──
            #   부모님 "가드가 정확한지 어떻게 아냐" → 진입평가마다 1줄 append. 통과/실패 모두.
            #   scripts/guard_accuracy.py 가 이 로그 + 저널 EXIT 를 조인해 가드별 적중률 산출.
            try:
                from app.manager.trade_journal import JOURNAL_PATH as _JP
                _ge_path = os.path.join(os.path.dirname(_JP), "guard_eval.jsonl")
                _ge_rec = {
                    "ts": round(time.time(), 1), "market": market.upper(), "direction": direction,
                    "base": round(_base_conv, 1), "guards": round(_gs_total, 1),
                    "final": round(_final_conv, 1), "threshold": _gs_threshold,
                    "passed": bool(_final_conv >= _gs_threshold), "breakdown": _gs_breakdown,
                }
                with open(_ge_path, "a", encoding="utf-8") as _gf:
                    _gf.write(json.dumps(_ge_rec, ensure_ascii=False) + "\n")
            except Exception as _ge_exc:
                logger.debug("[FOCUS] guard_eval log failed: %s", _ge_exc)
            if _final_conv < _gs_threshold:
                try:
                    from app.manager.trade_journal import journal as _jnl
                    _jnl.record_blocked("FOCUS", market, direction,
                                        reason="guard_score_below_threshold",
                                        detail=("final=%.1f<%.0f | %s" % (_final_conv, _gs_threshold, _gs_breakdown))[:300])
                except Exception as exc:
                    logger.debug("[FOCUS] guard_score journal failed: %s", exc)
                # status text = breakdown 만 (score 식은 분리 컬럼에 표시됨)
                return {"state": "HUNT", "error": _bd_short}
            # ── [2026-05-28 부모] 진입 직전 마지막 가드 — "이것만으로 충분" ──
            #   ★ [2026-05-28 저녁 부모 "단 하나" 룰] D1 정렬 필수 검증 (가장 먼저)
            #   "Day 캔들만 거슬리지 않으면 어떻게든 이윤. 72h 안에 풀림."
            #   D1=DOWN vs LONG / D1=UP vs SHORT = 진입 차단.
            _fd1_blocked, _fd1_reason = self._final_d1_alignment_check(market, direction)
            if _fd1_blocked:
                # ★ [2026-06-09 부모] D1 점수흡수 — D1 게이트는 옛 장기물림(72h) 전제 유산.
                #   지금 🐢/BE/reverse_drift/빠른회전으로 장기물림 방지됨 → 명분 퇴색(데이터: D1차단 59%기회손실).
                #   conviction 충분히 높으면 D1 역행 통과(강신호만, 출구가드가 받침). regime_opposed(거시)는 흡수 제외.
                _fd1_byp = float(getattr(self.config, "final_d1_bypass_conviction", 0.0) or 0.0)
                _fd1_regime = "regime_opposed" in (_fd1_reason or "")
                _fd1_cmp = _base_conv if getattr(self.config, "final_bypass_use_base", False) else _final_conv  # ★ [패치 v1]
                if _fd1_byp > 0 and _fd1_cmp >= _fd1_byp and not _fd1_regime:
                    logger.info("[FOCUS] 🎯 final_d1 점수흡수 BYPASS (conv %.0f≥%.0f): %s %s — %s → 진입 허용 (D1 퇴색·출구가드 받침)",
                                _fd1_cmp, _fd1_byp, market, direction, _fd1_reason)
                else:
                    logger.warning("[FOCUS] 🎯 GuardScore PASS but D1 ALIGNMENT BLOCK: %s %s — %s",
                                   market, direction, _fd1_reason)
                    try:
                        from app.manager.trade_journal import journal as _jnl
                        _jnl.record_blocked("FOCUS", market, direction, reason="final_d1_alignment", detail=_fd1_reason)
                    except Exception:
                        pass
                    self._record_near_miss(market, direction, _final_conv, "final_d1: " + _fd1_reason)
                    return {"state": "HUNT", "error": "PASS but D1(%s)" % _fd1_reason}
            #   (1) 30M+15M 방향 재확인 (2) 5M RSI/MACD/BB 동조
            _f30_blocked, _f30_reason = self._final_30m15m_check(market, direction)
            if _f30_blocked:
                # ★ [2026-06-09 부모] 점수 흡수 — conviction 충분히 높으면 통과 (30M/15M 역행 이중처벌 해소).
                #   regime_opposed(거시역행=떨어지는칼)는 흡수 제외 = 진짜 위험. 단순 상위TF lag 만 흡수.
                _f30_byp = float(getattr(self.config, "final_30m15m_bypass_conviction", 0.0) or 0.0)
                _f30_regime = "regime_opposed" in (_f30_reason or "")
                #   ★ [2026-06-09 부모] 거시역행 포함 토글 — True 면 거시역행도 점수로 우회 허용.
                _f30_inc_regime = bool(getattr(self.config, "final_30m15m_bypass_include_regime", False))
                _f30_cmp = _base_conv if getattr(self.config, "final_bypass_use_base", False) else _final_conv  # ★ [패치 v1]
                if _f30_byp > 0 and _f30_cmp >= _f30_byp and (not _f30_regime or _f30_inc_regime):
                    logger.info("[FOCUS] 🎯 final_30m15m 점수흡수 BYPASS (conv %.0f≥%.0f): %s %s — %s → 진입 허용",
                                _f30_cmp, _f30_byp, market, direction, _f30_reason)
                else:
                    logger.info("[FOCUS] 🎯 GuardScore PASS but FINAL 30M+15M BLOCK: %s %s — %s",
                                market, direction, _f30_reason)
                    try:
                        from app.manager.trade_journal import journal as _jnl
                        _jnl.record_blocked("FOCUS", market, direction, reason="final_30m15m", detail=_f30_reason)
                    except Exception:
                        pass
                    self._record_near_miss(market, direction, _final_conv, "final_30m15m: " + _f30_reason)
                    return {"state": "HUNT", "error": "PASS but final_30m15m(%s)" % _f30_reason}
            _f5_blocked, _f5_reason = self._final_5m_simple_check(market, direction)
            if _f5_blocked:
                logger.info("[FOCUS] 🎯 GuardScore PASS but FINAL 5M BLOCK: %s %s — %s",
                            market, direction, _f5_reason)
                try:
                    from app.manager.trade_journal import journal as _jnl
                    _jnl.record_blocked("FOCUS", market, direction, reason="final_5m_simple", detail=_f5_reason)
                except Exception:
                    pass
                self._record_near_miss(market, direction, _final_conv, "final_5m: " + _f5_reason)
                return {"state": "HUNT", "error": "PASS but final_5m(%s)" % _f5_reason}
            # ── [2026-06-06 부모] Peer Brief = 하드 차단 ❌ → 소프트 참고 ⭕ ──
            #   부모님 정정: "옆은 자체 로직 진입 전 한 번 더 생각하는 참고 차원."
            #   - 옆 보유 중 = 차단 사유 아님 (두 서버 같은 자리 보유 OK)
            #   - 옆 같은 코인+방향 최근 SL = guard_score 소프트 감점(PeerSL, _compute 단계)
            #   - SL 이어도 본체 지표 반등이면 점수가 감점 넘어 진입 → "반등 가점" 자연 처리
            #   하드 차단(return)은 폐기. peer 신호는 점수에만 반영(PeerWin/PeerSL).
            # 통과 — 모든 가드 우회 마킹 (각 가드는 _guard_score_pass 확인하고 skip)
            entry["_guard_score_pass"] = True
            entry["_guard_score"] = _final_conv
            entry["_guard_breakdown"] = _gs_breakdown
            logger.info("[FOCUS] 🎯 GuardScore PASS %s %s — 점수 %.1f ≥ %.0f | %s | %s",
                        market, direction, _final_conv, _gs_threshold,
                        _f30_reason or "30M15M_ok", _f5_reason or "5M_ok")
        # ── [2026-05-16 부모] Same-coin Flip Cooldown — TAO 양방향 사례 차단 ──
        if not _is_manual and not entry.get("_guard_score_pass"):
            _flip_blocked, _flip_reason = self._check_same_coin_flip_cooldown(market, direction)
            if _flip_blocked:
                logger.info("[FOCUS] %s — %s %s", _flip_reason, market, direction)
                try:
                    from app.manager.trade_journal import journal as _jnl
                    _jnl.record_blocked("FOCUS", market, direction, reason="same_coin_flip_cooldown", detail=_flip_reason)
                except Exception as exc:
                    logger.debug("[FOCUS] same_coin_flip_cooldown journal failed: %s", exc)
                return {"state": "HUNT", "error": "same_coin_flip_cooldown"}
        # ── [2026-05-16 부모 통찰] 5m Raw Body Guard — BILL 매수 에너지 자리 SHORT 차단 ──
        if not _is_manual and not entry.get("_guard_score_pass"):
            _raw_blocked, _raw_reason = self._check_raw_body_guard(market, direction)
            if _raw_blocked:
                logger.info("[FOCUS] %s — %s %s", _raw_reason, market, direction)
                try:
                    from app.manager.trade_journal import journal as _jnl
                    _jnl.record_blocked("FOCUS", market, direction, reason="raw_body_guard", detail=_raw_reason)
                except Exception as exc:
                    logger.debug("[FOCUS] raw_body_guard journal failed: %s", exc)
                return {"state": "HUNT", "error": "raw_body_guard"}
        # ── [2026-05-26 부모] Frame Guard — 교재 "프레임(S/R)" 강제 (레인지 위치) ──
        #   BTC SHORT @ $76,616 (24h 저점 근처) 같은 바닥잡기/고점잡기 차단.
        # ── [2026-05-27 부모] Frame Guard cooldown — 차단 후 같은 자리 반복 시도 silent skip ──
        #   RENDER SHORT 13:16~13:20 12회 반복 차단 패턴 제거. cooldown 동안 frame_guard 계산도 생략.
        if not _is_manual and not entry.get("_guard_score_pass"):
            _fg_cd_enabled = bool(getattr(self.config, "frame_guard_cooldown_enabled", True))
            _fg_key = (market.upper(), direction)
            if _fg_cd_enabled:
                _cd_until = self._frame_guard_cooldown.get(_fg_key, 0.0)
                _now_ts = time.time()
                if _cd_until > _now_ts:
                    _remain = int(_cd_until - _now_ts)
                    logger.debug("[FOCUS] frame_guard_cooldown active: %s %s remain=%ds (silent)", market, direction, _remain)
                    return {"state": "HUNT", "error": "frame_guard_cooldown(%ds)" % _remain}
            _fg_blocked, _fg_reason = self._check_frame_guard(market, direction)
            if _fg_blocked:
                logger.info("[FOCUS] %s — %s %s", _fg_reason, market, direction)
                # cooldown 갱신 — 같은 자리 반복 차단 회피
                if _fg_cd_enabled:
                    _cd_sec = float(getattr(self.config, "frame_guard_cooldown_sec", 90.0))
                    self._frame_guard_cooldown[_fg_key] = time.time() + _cd_sec
                try:
                    from app.manager.trade_journal import journal as _jnl
                    _jnl.record_blocked("FOCUS", market, direction, reason="frame_guard", detail=_fg_reason)
                except Exception as exc:
                    logger.debug("[FOCUS] frame_guard journal failed: %s", exc)
                return {"state": "HUNT", "error": "frame_guard"}
            # 통과 시 cooldown clear (가격이 좋은 자리로 이동했으면 즉시 풀림)
            elif _fg_cd_enabled and _fg_key in self._frame_guard_cooldown:
                del self._frame_guard_cooldown[_fg_key]
        # ── [2026-05-27 부모] Day Box Guard — 9시 박스 핑퐁 시 박스 안 진입 차단 ──
        #   "D1 시작 후 1~4h 핑퐁 = 하루 종일 상하한선" 부모님 직관 + 교재 กรอบวัน.
        #   per-market 박스 추적, lock 시 상한 근처 SHORT / 하한 근처 LONG / 박스 안 양방 차단.
        if not _is_manual and not entry.get("_guard_score_pass") and self._day_box_guard_active():
            _box_price = 0.0
            try:
                _box_price = float(entry.get("price", 0) or 0)
            except Exception:
                _box_price = 0.0
            if _box_price <= 0:
                try:
                    _box_price = float(self._get_client()._linear_last_price(market) or 0)
                except Exception:
                    _box_price = 0.0
            if _box_price > 0:
                self._update_day_box(market, _box_price)
                _box_blocked, _box_reason = self._check_day_box_guard(market, direction, _box_price)
                if _box_blocked:
                    logger.info("[FOCUS] %s — %s %s", _box_reason, market, direction)
                    try:
                        from app.manager.trade_journal import journal as _jnl
                        _jnl.record_blocked("FOCUS", market, direction, reason="day_box", detail=_box_reason)
                    except Exception as exc:
                        logger.debug("[FOCUS] day_box journal failed: %s", exc)
                    return {"state": "HUNT", "error": "day_box"}
        # ── [2026-05-26 부모] H4 Close Pulse Only — H4 마감 직후 창에서만 진입 ──
        # ── [2026-05-27 부모] H1 PA Pulse OR — H1 PA 인식 시 진입 추가 허용 ──
        #   교재 "H4 PA 직후 진입" 타이밍 강제 + "SIG는 H1 이상 라운드 인정" 정통.
        #   H4 펄스 OR H1 PA 펄스 = 둘 중 하나 통과면 OK. H1 PA 는 PA 트리거(시간창 X).
        if not _is_manual and not entry.get("_guard_score_pass") and self._h4_pulse_only_active():
            _pulse_ok, _pulse_reason = self._in_h4_pulse_window()
            if _pulse_ok:
                # H4 펄스 통과 — 어느 펄스로 들어왔는지 마킹 + H1 겹침 정보
                entry["_pulse_via"] = "h4"
                _h1_also = ""
                if self._h1_pa_pulse_active():
                    _h1_ok2, _h1_info2 = self._h1_pa_detected(market, direction)
                    if _h1_ok2:
                        _h1_also = " (+ h1_pa 겹침)"
                logger.info("[FOCUS] ⏰ Pulse OK %s %s via h4 %s%s",
                            market, direction, _pulse_reason, _h1_also)
            else:
                # H1 PA 펄스 OR — H1 PA 인식 + day_direction 정렬 시 H4 차단 우회
                _h1_ok, _h1_info = (False, "")
                if self._h1_pa_pulse_active():
                    _h1_ok, _h1_info = self._h1_pa_detected(market, direction)
                if _h1_ok:
                    entry["_pulse_via"] = "h1_pa"
                    logger.info("[FOCUS] ⏰ Pulse OK %s %s via h1_pa — H4 차단 우회 (%s)",
                                market, direction, _h1_info)
                    # 통과 — 다음 가드로
                else:
                    _block_detail = _pulse_reason
                    if _h1_info:
                        _block_detail += " | " + _h1_info
                    logger.info("[FOCUS] %s — %s %s 차단", _block_detail, market, direction)
                    try:
                        from app.manager.trade_journal import journal as _jnl
                        _jnl.record_blocked("FOCUS", market, direction, reason="h4_pulse_only", detail=_block_detail)
                    except Exception as exc:
                        logger.debug("[FOCUS] h4_pulse journal failed: %s", exc)
                    return {"state": "HUNT", "error": "h4_pulse_only"}
        # ── [2026-05-27 부모] PA Completion Guard — Sig + ไส้หลัง 마감 검증 (H4 OR H1) ──
        #   교재 XAUUSD 88 / GreenPen "Pat 1/2/3 외 모든 캔들 진입 불가" 정신.
        #   부모님 정정 (2026-05-27): "H4 든 H1 이든 위 표 캔들이면 다 진입이 맞는 표현".
        #   → H4 OR H1 둘 중 *어느 TF 든* PA Pat 1/2/3 완성이면 통과.
        #   → 둘 다 실패해야만 차단.
        #   봇 결함 (오늘 18:35 BTC SHORT): Sig 인식 즉시 진입 → ไส้หลัง 안 기다림 → 손실.
        if not _is_manual and not entry.get("_guard_score_pass") and self._pa_completion_active():
            # H4 우선 검사
            _h4_pa_ok, _h4_pa_reason = self._check_pa_completion(market, direction, "240")
            _h1_pa_ok, _h1_pa_reason = (False, "")
            # H4 실패 시 H1 도 시도 (OR)
            if not _h4_pa_ok:
                _h1_pa_ok, _h1_pa_reason = self._check_pa_completion(market, direction, "60")
            if _h4_pa_ok:
                entry["_pa_via"] = "h4"
                logger.info("[FOCUS] 🐟 PA OK %s %s via H4 — %s", market, direction, _h4_pa_reason)
            elif _h1_pa_ok:
                entry["_pa_via"] = "h1"
                logger.info("[FOCUS] 🐟 PA OK %s %s via H1 (H4 실패: %s) — %s",
                            market, direction, _h4_pa_reason, _h1_pa_reason)
            else:
                _pa_block_detail = "H4: %s | H1: %s" % (_h4_pa_reason, _h1_pa_reason)
                logger.info("[FOCUS] 🐟 PA 미완성 (H4+H1 둘다 X) — %s %s | %s",
                            market, direction, _pa_block_detail)
                try:
                    from app.manager.trade_journal import journal as _jnl
                    _jnl.record_blocked("FOCUS", market, direction,
                                        reason="pa_completion", detail=_pa_block_detail[:300])
                except Exception as exc:
                    logger.debug("[FOCUS] pa_completion journal failed: %s", exc)
                return {"state": "HUNT", "error": "pa_completion"}
        # ── [2026-05-16 부모 비전] Momentum Derivative Guard — RSI/MACD 변화율 가드 ──
        if not _is_manual and not entry.get("_guard_score_pass"):
            _md_blocked, _md_reason = self._check_momentum_derivative_guard(market, direction)
            if _md_blocked:
                # ★ CFID 우회 — 변곡점 임박 자리는 momentum_deriv 의 "현재 흐름 반대" 보다 우선
                _cfid_bypass = False
                if getattr(self.config, "cfid_bypass_momentum_deriv", True):
                    _cfid_dir, _cfid_str = self._detect_coin_flip_imminent(market)
                    if ((direction.upper() == "LONG" and _cfid_dir == "BULL_IMMINENT") or
                        (direction.upper() == "SHORT" and _cfid_dir == "BEAR_IMMINENT")):
                        _cfid_bypass = True
                        logger.info("[FOCUS] 🚀 CFID %s (strength=%.1f) → momentum_deriv 우회 %s %s",
                                    _cfid_dir, _cfid_str, market, direction)
                if not _cfid_bypass:
                    logger.info("[FOCUS] %s — %s %s", _md_reason, market, direction)
                    try:
                        from app.manager.trade_journal import journal as _jnl
                        _jnl.record_blocked("FOCUS", market, direction, reason="momentum_deriv_guard", detail=_md_reason)
                    except Exception as exc:
                        logger.debug("[FOCUS] momentum_deriv_guard journal failed: %s", exc)
                    return {"state": "HUNT", "error": "momentum_deriv_guard"}
        # ── [2026-05-16 부모 비전 #2] MTF Momentum Alignment — TF 들 흐름 일관성 ──
        if not _is_manual and not entry.get("_guard_score_pass"):
            _mtf_blocked, _mtf_reason = self._check_mtf_momentum_alignment(market, direction)
            if _mtf_blocked:
                # ★ CFID 우회 — 변곡점 임박 자리는 mtf_align BLOCK 보다 우선
                _cfid_bypass2 = False
                if getattr(self.config, "cfid_bypass_mtf_align", True):
                    _cfid_dir2, _cfid_str2 = self._detect_coin_flip_imminent(market)
                    if ((direction.upper() == "LONG" and _cfid_dir2 == "BULL_IMMINENT") or
                        (direction.upper() == "SHORT" and _cfid_dir2 == "BEAR_IMMINENT")):
                        _cfid_bypass2 = True
                        logger.info("[FOCUS] 🚀 CFID %s (strength=%.1f) → mtf_align 우회 %s %s",
                                    _cfid_dir2, _cfid_str2, market, direction)
                if not _cfid_bypass2:
                    logger.info("[FOCUS] %s — %s %s", _mtf_reason, market, direction)
                    try:
                        from app.manager.trade_journal import journal as _jnl
                        _jnl.record_blocked("FOCUS", market, direction, reason="mtf_momentum_align", detail=_mtf_reason[:300])
                    except Exception as exc:
                        logger.debug("[FOCUS] mtf_momentum_align journal failed: %s", exc)
                    return {"state": "HUNT", "error": "mtf_momentum_align"}
        # ── [2026-05-27 부모] Anchor Proximity Fast-Track — anchor 근처면 microtiming 우회 ──
        #   "5m 보다 더 중요한 것 발견했으면 무시가 답" — 부모님 2026-05-27.
        #   H4 pulse 직후 anchor 근접 자리 = 사이클 시작점 = 즉시 진입이 정답.
        #   microtiming 의 5M 트리거 대기(최대 30분)는 anchor 에서 멀어진 자리에서만 의미 (2차 리테스트).
        if not _is_manual and not entry.get("_guard_score_pass") and self._anchor_fasttrack_active():
            _ft_ok, _ft_prox, _ft_info = self._check_anchor_fasttrack(market, direction)
            if _ft_ok:
                entry["_bypass_microtiming"] = True
                entry["_anchor_fasttrack"] = True
                logger.info("[FOCUS] ⚡ ANCHOR FAST-TRACK %s %s: %s → microtiming 우회", market, direction, _ft_info)
        if getattr(self.config, "microtiming_5m_enabled", False) and not _is_manual and not entry.get("_guard_score_pass"):
            _mt_phase_k_exempt = bool(getattr(self.config, "microtiming_5m_phase_k_exempt", True))
            _is_phase_k = bool(entry.get("_phase_k"))
            # ★ [2026-05-18] Leading Entry bypass — CFID/PATTERN 모드에서 microtiming 우회
            # ★ [2026-05-27] Anchor fast-track bypass — _anchor_fasttrack 도 같은 _bypass_microtiming 마킹 활용
            _is_leading_bypass = bool(entry.get("_bypass_microtiming") and
                                     (entry.get("_leading_entry") or entry.get("_anchor_fasttrack")))
            if _is_leading_bypass:
                if entry.get("_anchor_fasttrack"):
                    logger.info("[FOCUS] microtiming_5m BYPASS: %s %s (ANCHOR_FASTTRACK)", market, direction)
                else:
                    _leading_mode = entry.get("_leading_mode", "?")
                    logger.info("[FOCUS] microtiming_5m BYPASS: %s %s (%s_LEAD)", market, direction, _leading_mode)
            elif not (_mt_phase_k_exempt and _is_phase_k):
                _now_ts = time.time()
                _defer_map = getattr(self, "_microtiming_defer", {})
                _key = (market.upper(), direction)
                _defer_state = _defer_map.get(_key)
                # 1) 아직 defer 시간 내 → 조용히 통과 거부
                if _defer_state and _defer_state[0] > _now_ts:
                    _remain = int(_defer_state[0] - _now_ts)
                    logger.debug("[FOCUS] microtiming_5m DEFER active: %s %s remain=%ds (defers=%d)",
                                 market, direction, _remain, _defer_state[1])
                    # ★ state=HUNT 강제 — POSITIONED 인 채로 반환되면 호출자(scanner)가 ENTERED 로 오인.
                    # microtiming_deferred 플래그도 추가 — scanner 가 명시적으로 인식하도록.
                    return {"state": "HUNT", "error": f"microtiming_5m_defer_active({_remain}s)", "microtiming_deferred": True}
                # 2) 검사 — 점수 산출
                _mt_ok, _mt_label, _mt_score = self._check_microtiming_5m(market, direction)
                if _mt_ok:
                    # GO — defer 기록 정리
                    if _key in _defer_map:
                        del _defer_map[_key]
                    logger.info("[FOCUS] microtiming_5m PASS: %s %s %s", market, direction, _mt_label)
                else:
                    # 점수 부족 → defer (단, max 초과 시 자연 만료 = 다음 진입 즉시 통과)
                    _max_defers = int(getattr(self.config, "microtiming_5m_max_defers", 3))
                    _defer_sec = float(getattr(self.config, "microtiming_5m_defer_sec", 600.0))
                    _prev_defers = _defer_state[1] if _defer_state else 0
                    _new_defers = _prev_defers + 1
                    if _new_defers > _max_defers:
                        # 자연 만료 — 기록 삭제, 그래도 이번엔 통과시키지 않고 한 번만 더 defer 후 다음 진입 통과
                        # (안전: 자연 만료라도 미충족 = 진입 안 함. 다음 _scan tick 에 재평가)
                        if _key in _defer_map:
                            del _defer_map[_key]
                        logger.info("[FOCUS] microtiming_5m EXPIRED: %s %s %s defers=%d → 자연 만료",
                                    market, direction, _mt_label, _prev_defers)
                        return {"state": "HUNT", "error": f"microtiming_5m_expired({_mt_label})", "microtiming_deferred": True}
                    _defer_map[_key] = (_now_ts + _defer_sec, _new_defers)
                    self._microtiming_defer = _defer_map
                    logger.info("[FOCUS] microtiming_5m DEFER %ds: %s %s %s defers=%d/%d",
                                int(_defer_sec), market, direction, _mt_label, _new_defers, _max_defers)
                    return {"state": "HUNT", "error": f"microtiming_5m_defer({_mt_label})", "microtiming_deferred": True}

        # ★ [2026-06-05 부모] 1M 마이크로 체크 — "지금 이 순간" 타이밍 검증
        # 5M microtiming 통과 후 1M 레벨 최종 확인 (역방향 봉/거래량 소진/RSI 과열)
        if not _is_manual and getattr(self.config, "micro_1m_check_enabled", True):
            try:
                _1m_ok, _1m_reason = self._check_micro_1m(market, direction)
                if not _1m_ok:
                    logger.info("[FOCUS] ⛔ 1M 마이크로: %s %s → %s", direction, market, _1m_reason)
                    try:
                        from app.manager.trade_journal import journal
                        journal.record_blocked("FOCUS", market, direction,
                                               reason="micro_1m", detail=_1m_reason)
                    except Exception:
                        pass
                    return {"state": "HUNT", "skip": f"micro_1m:{_1m_reason}"}
            except Exception as _1m_exc:
                logger.debug("[FOCUS] micro_1m failed (fail-open): %s", _1m_exc)

        # ★ [2026-04-19] REENTRY FINAL GATE — scan/execute race 방어
        # Scanner의 _check_reentry_allowed 는 candidate 필터링 시점에만 호출됨.
        # 그 이후 execute 까지 수 초~수십 초 간격 중에 기존 포지션이 exit 되면
        # B9 Post-Trade Pause / B8 Direction Exhaustion / coin_repeat_brake 가 전부 우회됨.
        # 실례: 2026-04-19 AAVE SHORT EXIT(1776567899) → ENTRY(1776567916) = 17초 재진입.
        # 해결: execute 직전에 _check_reentry_allowed 를 한번 더. 중복 비용 ms 단위.
        # ★ [2026-05-16 부모] _manual=True 시 reentry guard 우회 — 부모님이 차트 보고 의도적 재진입할 때 막지 않음.
        _exec_price = float(entry.get("entry_price") or entry.get("price") or 0.0)
        if not _is_manual and not self._check_reentry_allowed(direction, market, _exec_price):
            logger.warning(
                "[FOCUS] ★ ENTRY BLOCKED at execute (scan/execute race guard): %s %s",
                market, direction)
            return {"state": self.state.value, "error": "reentry_blocked_at_execute"}

        # ★ ANTI-GAMBLER FINAL GATE: coin_loss_cap을 진입 직전에 한 번 더 확인
        # _check_reentry_allowed 우회 가능성 차단 (모든 진입 경로에서 반드시 실행)
        # [2026-04-18] 방향별 분리 — entry direction 기반 누적 손실만 확인
        if self.config.coin_loss_cap_enabled and market:
            _loss = self._get_coin_loss_total(market, direction)
            _cap = self._effective_coin_loss_cap()
            logger.debug("[FOCUS] Coin Loss Cap CHECK: %s %s total_loss=$%.2f cap=$%.2f enabled=%s",
                         market, direction, _loss, _cap, self.config.coin_loss_cap_enabled)
            if _loss < 0 and abs(_loss) >= _cap:
                logger.warning(
                    "[FOCUS] ★ ANTI-GAMBLER FINAL GATE: %s %s 24h loss $%.2f >= cap $%.2f — ENTRY DENIED",
                    market, direction, _loss, _cap)
                return {"state": self.state.value, "error": f"coin_loss_cap_final_{market}"}

        # ★ Cross-strategy guard: 주문 직전 최종 확인 (scan→execute race 방어)
        try:
            from app.core.cross_strategy_guard import is_market_owned_by_other
            _other = is_market_owned_by_other(self.system, market, "FOCUS")
            if _other:
                logger.warning("[FOCUS] ENTRY BLOCKED at execute: %s held by %s (qty=%.4f)",
                               market, _other.owner, _other.qty)
                return {"state": self.state.value, "error": "cross_strategy_conflict_at_execute"}
        except Exception as exc:
            logger.debug("[FOCUS] cross_strategy_guard execute check: %s", exc)

        # ★ 자기 포지션 중복 진입 차단 (최종 안전망)
        if any(p.market.upper() == market.upper() for p in self.positions):
            logger.warning("[FOCUS] ENTRY BLOCKED: %s already in self.positions", market)
            return {"state": self.state.value, "error": "already_held_self"}

        # ★ [2026-04-18] Bybit 직접 조회 — internal state와 Bybit 실잔고 불일치 시 중복 진입 방지
        #   오늘 SOL 2중 진입(-$21), ORDI 2중 진입(-$14) 사건 재발 방지
        #   internal positions는 비어있는데 Bybit에 실제 포지션 있는 케이스 차단
        try:
            # ★ [2026-05-25 부모] paper/dry 모드: 실거래소 조회 skip — 실계좌에 남은 포지션이
            #   가상 진입을 DUPLICATE 로 오탐해 차단하는 것 방지. paper 중복은 아래 self.positions 가드가 담당.
            if not self._is_live_mode():
                _bybit_pos = []
            else:
                from app.integrations.bybit_trade import BybitTradeClient
                _sync_client = BybitTradeClient(category="linear")
                _bybit_pos = _sync_client.get_positions()
            for _bp in (_bybit_pos or []):
                _bp_market = (_bp.get("symbol") or _bp.get("market") or "").upper()
                _bp_size = abs(float(_bp.get("size", 0) or 0))
                if _bp_market == market.upper() and _bp_size > 0:
                    logger.warning(
                        "[FOCUS] ★ DUPLICATE ENTRY BLOCKED: %s already open on Bybit (qty=%.4f) — internal state desync",
                        market, _bp_size)
                    # Bybit 포지션이 있지만 internal에 없음 → internal에 복원
                    try:
                        _bp_dir = "LONG" if (_bp.get("side") or "").lower() == "buy" else "SHORT"
                        _bp_entry = float(_bp.get("avgPrice", 0) or _bp.get("entry_price", 0) or 0)
                        if _bp_entry > 0 and not any(p.market.upper() == market.upper() for p in self.positions):
                            logger.warning("[FOCUS] Bybit pos detected, restoring to internal: %s %s qty=%.4f @ $%.4f",
                                           market, _bp_dir, _bp_size, _bp_entry)
                            # 참고만 하고 진입은 차단 — SYNC가 다음 tick에서 복원
                    except Exception as exc:
                        logger.debug("[FOCUS] Bybit pos restore hint failed: %s", exc)
                    return {"state": self.state.value, "error": f"bybit_duplicate_{market}"}
        except Exception as exc:
            logger.debug("[FOCUS] Bybit duplicate check failed (safe to skip): %s", exc)

        # ★ HARPOON 충돌 방어: 진입 전 HARPOON 포지션 강제 청산
        try:
            hm = getattr(self.system, 'harpoon_manager', None) if self.system else None
            if hm and hm.current_scalp:
                logger.warning("[FOCUS] Closing HARPOON scalp before entry — leverage conflict prevention")
                hp = hm._get_current_price(hm.current_scalp.market) or 0
                hm._execute_scalp_exit("FOCUS_ENTRY_PREEMPT", hp)
        except Exception as exc:
            logger.debug("[FOCUS] HARPOON preempt check failed (safe to ignore): %s", exc)

        # ★ lock_market 강제: 다른 코인 진입 차단 (scanner / manual 예외)
        is_scanner_entry = entry.get("_scanner_entry", False)
        _lock_is_manual = bool(entry.get("_manual"))
        if self.config.lock_market and market.upper() != self.config.lock_market.upper():
            if not (is_scanner_entry and self.config.scanner_entry) and not _lock_is_manual:
                logger.warning("[FOCUS] BLOCKED: %s != locked %s — skipping entry", market, self.config.lock_market)
                return {"state": self.state.value, "error": f"locked_to_{self.config.lock_market}"}
            if _lock_is_manual and market.upper() != self.config.lock_market.upper():
                logger.warning("[FOCUS] ★ MANUAL ENTRY bypassing lock_market=%s for %s", self.config.lock_market, market)
        # [2026-04-18] 방향 분산 최종 가드 — Primary/Scanner 모든 경로에서 적용
        # 기존: Scanner에만 있던 max_same_direction 검사가 Primary 경로에 없어
        #       5슬롯 전부 LONG 가능 (편향 원인 #2)
        # [2026-04-19 Option B] 원방향만 saturated → MTF FLIP 기회 살리기 위해 통과.
        #   _mtf_gate 안에서 dir_limit 을 한 조건으로 포함 → 자연스럽게 opposite 시도
        #   로 흘러간다. 양방향 모두 saturated 만 하드차단.
        _same_dir = sum(1 for p in self.positions if p.direction == direction)
        _opp_tmp = "SHORT" if direction == "LONG" else "LONG"
        _opp_dir_count = sum(1 for p in self.positions if p.direction == _opp_tmp)
        _same_cap_final = self._effective_dir_cap(direction)
        _opp_cap_final = self._effective_dir_cap(_opp_tmp)
        if _same_dir >= _same_cap_final and _opp_dir_count >= _opp_cap_final:
            logger.info("[FOCUS] direction limit: both saturated (%s=%d/%d, %s=%d/%d) — entry blocked",
                        direction, _same_dir, _same_cap_final, _opp_tmp, _opp_dir_count, _opp_cap_final)
            try:
                from app.manager.trade_journal import journal
                journal.record_blocked("FOCUS", market, direction,
                                       reason="direction_limit_both",
                                       detail=f"{direction}={_same_dir}/{_same_cap_final},{_opp_tmp}={_opp_dir_count}/{_opp_cap_final}")
            except Exception as exc:
                logger.debug("[FOCUS] record_blocked failed: %s", exc)
            return {"state": "HUNT", "skip": "direction_limit_both"}
        # 원방향만 full 이면 로그 남기고 계속 — MTF 게이트가 처리
        if _same_dir >= _same_cap_final:
            logger.info("[FOCUS] direction %s saturated (%d/%d) — deferring to MTF FLIP (opposite %s=%d/%d)",
                        direction, _same_dir, _same_cap_final,
                        _opp_tmp, _opp_dir_count, _opp_cap_final)

        price = entry.get("price", 0)

        if not price or price <= 0:
            price = self._get_current_price(market) or 0
        if price <= 0:
            return {"state": "HUNT", "error": "no_price"}

        # ── ★ [2026-04-18 저녁] MTF 필터 + 방향 자동 전환 ──
        #   user 지적: "무조건 차단이 답이 아니야. 1시간/30분/15분 유동에 따라 롱 아니면
        #             숏을 쳐야지. 다 차단하면 언제 기회가 오냐"
        #
        #   1. 원 방향(entry의 direction)으로 Anti-Knife + H4 Context 검사
        #   2. 둘 다 통과 → 원 방향으로 진입
        #   3. 하나라도 실패 → 반대 방향으로 재검사
        #        - 반대 방향 둘 다 통과 → FLIP (방향 전환 후 진입)
        #        - 반대 방향도 실패 → 그제서야 진짜 skip
        #
        #   예: ETH BUY 신호 왔는데 H4 5봉 하락 → SHORT 재검사 → 통과 → SHORT 진입
        #       양방향 모두 애매하면 → skip (기회 없음 = 안 들어감)
        def _mtf_gate(_dir):
            # [2026-04-19 Option B] dir_limit 을 MTF 게이트 한 조건으로 포함.
            #   원방향이 saturated 면 자연스럽게 fail → opposite 시도로 흘러간다.
            # [2026-04-20] 방향별 상한(_effective_dir_cap)으로 교체 — LONG/SHORT 분리 제어
            _dir_cnt = sum(1 for p in self.positions if p.direction == _dir)
            _dir_cap = self._effective_dir_cap(_dir)
            if _dir_cnt >= _dir_cap:
                return False, f"dir_full({_dir_cnt}/{_dir_cap})"
            # ★ [2026-05-20 부모 결정] 수동 진입 100% 우회 — knife/primary 가드 skip.
            #   부모님 명시: "수동진입시 같은방향이든 역방향이든 운영자가 하자고 하는대로 10000000% 할것".
            #   슬롯 cap (dir_full) 만 자본 보호용으로 유지. 시장 신호 가드는 부모님 의도 존중 우회.
            if _is_manual:
                logger.warning("[FOCUS] ★ MANUAL ENTRY %s %s — _mtf_gate bypass (knife/primary 가드 skip, 부모님 100%% 의도 존중)",
                               market, _dir)
                return True, "manual_bypass"
            k_ok, k_r = self._anti_falling_knife_check(market, _dir)
            if not k_ok:
                return False, f"knife:{k_r}"
            h_ok, h_r = self._primary_context_filter(market, _dir)
            if not h_ok:
                return False, f"primary:{h_r}"
            return True, ""

        _pass, _fail_reason = _mtf_gate(direction)
        if not _pass:
            # ★ [2026-05-20 부모 의도 보호] 수동 진입은 절대 direction 변환 X
            # 부모님 L (LONG) 클릭 → MTF 실패 → 봇이 자동 SHORT FLIP → SHORT 진입 사고 (HYPE/ETH 케이스).
            # 수동 의도가 명확하므로 _original direction 실패 = 그대로 fail 반환. FLIP 절대 발동 X.
            if _is_manual:
                logger.warning("[FOCUS] ★ MANUAL ENTRY %s %s MTF fail (%s) — FLIP 차단, 원의도 그대로 fail",
                               market, direction, _fail_reason)
                try:
                    from app.manager.trade_journal import journal
                    journal.record_blocked("FOCUS", market, direction,
                                           reason="manual_mtf_fail",
                                           detail=f"manual {direction} mtf fail: {_fail_reason} (FLIP blocked)")
                except Exception as exc:
                    logger.debug("[FOCUS] record_blocked manual_mtf failed: %s", exc)
                return {"state": "HUNT", "skip": f"manual_mtf_fail:{_fail_reason}"}
            # ★ [2026-05-28 부모 ICP 사고] 자동 진입도 FLIP 차단 ──
            # ICPUSDT 사고: 봇 자동 LONG 평가 → MTF 실패 → SHORT FLIP → SHORT 진입.
            # 부모님 의도: 봇 자동 진입도 원 방향 실패 = 그대로 fail. 반대 자동 진입 X.
            # `_is_manual` 차단 (5-20 fix) 의 자동 진입판 확장.
            if not bool(getattr(self.config, "entry_auto_flip_enabled", False)):
                logger.warning("[FOCUS] ★ AUTO FLIP DISABLED %s %s mtf fail (%s) — FLIP blocked, return fail",
                               market, direction, _fail_reason)
                try:
                    from app.manager.trade_journal import journal
                    journal.record_blocked("FOCUS", market, direction,
                                           reason="auto_flip_disabled",
                                           detail=f"auto {direction} mtf fail: {_fail_reason}; FLIP off (ICP 사고 fix)")
                except Exception as exc:
                    logger.debug("[FOCUS] record_blocked auto_flip failed: %s", exc)
                return {"state": "HUNT", "skip": f"auto_flip_disabled:{_fail_reason}"}
            _opp = "SHORT" if direction == "LONG" else "LONG"
            # 반대 방향도 방향별 상한에 걸리면 flip 무의미
            _opp_same = sum(1 for p in self.positions if p.direction == _opp)
            _opp_cap_mtf = self._effective_dir_cap(_opp)
            if _opp_same >= _opp_cap_mtf:
                logger.info("[FOCUS] MTF fail (%s: %s) + opposite %s saturated (%d/%d) → skip",
                            direction, _fail_reason, _opp, _opp_same, _opp_cap_mtf)
                try:
                    from app.manager.trade_journal import journal
                    journal.record_blocked("FOCUS", market, direction,
                                           reason="mtf_both_blocked",
                                           detail=f"orig={_fail_reason};opp_saturated")
                except Exception as exc:
                    logger.debug("[FOCUS] record_blocked mtf_both failed: %s", exc)
                return {"state": "HUNT", "skip": f"mtf_fail_{_fail_reason}"}

            _opp_pass, _opp_fail = _mtf_gate(_opp)
            if _opp_pass:
                # coin_loss_cap도 반대 방향으로 재확인
                if self.config.coin_loss_cap_enabled:
                    _opp_loss = self._get_coin_loss_total(market, _opp)
                    _opp_cap = self._effective_coin_loss_cap()
                    if _opp_loss < 0 and abs(_opp_loss) >= _opp_cap:
                        logger.info("[FOCUS] MTF flip blocked: %s %s opp_loss $%.2f >= cap $%.2f",
                                    market, _opp, _opp_loss, _opp_cap)
                        return {"state": "HUNT", "skip": "flip_coin_loss_cap"}

                # ★ Phase D-1 (2026-04-20): MTF FLIP 후 reentry/regime 재검증
                # 형 Claude 진단 (07:05 AAVE 사건): FLIP 시 새 방향에 대해 B11(regime) 재검증 안 됨
                # → BULL regime + LONG fail → SHORT 우회 진입 (대패 원인). _check_reentry_allowed 안에 B6/B7/B9/B10/B11 모두 포함됨.
                if not self._check_reentry_allowed(_opp, market, price):
                    logger.info("[FOCUS] MTF flip blocked by reentry/regime gate: %s %s (was %s)",
                                market, _opp, direction)
                    try:
                        from app.manager.trade_journal import journal
                        journal.record_blocked("FOCUS", market, _opp,
                                               reason="flip_blocked",
                                               detail=f"flip {direction}->{_opp} denied by reentry/regime gate")
                    except Exception as exc:
                        logger.debug("[FOCUS] record_blocked flip failed: %s", exc)
                    return {"state": "HUNT", "skip": f"flip_blocked_{_opp}"}

                # ── ★ FLIP Alignment Gate (2026-05-15 부모) ──
                # DOGE 패턴: 스캐너 LONG → Anti-Knife 차단 → SHORT flip. H1+30M 둘 다 UPTR이면 counter-trend → 차단.
                # "_mtf_gate 통과"는 Anti-Knife + primary_context 만 보는 약한 게이트라 상위 TF 정렬엔 무관심.
                # 여기서 H1+30M 동시 역행만 잡고, 한쪽만 반대면 통과 (FLIP 의의 보존).
                if getattr(self.config, "entry_flip_require_alignment", False):
                    try:
                        from app.strategy.greenpen.market_structure import analyze_structure as _fl_az
                        from app.strategy.greenpen.pa_detector import OHLCV as _fl_O
                        def _fl_trend(_interval):
                            _r = self._get_mtf_kline(market, _interval)
                            if not _r or len(_r) < 10:
                                return "?"
                            _cs = [_fl_O(float(rr[1]), float(rr[2]), float(rr[3]), float(rr[4]))
                                   for rr in _r if len(rr) >= 5]
                            if len(_cs) < 10:
                                return "?"
                            _st = _fl_az(_cs)
                            return _st.trend.value if hasattr(_st.trend, 'value') else str(_st.trend)
                        _fl_h1 = _fl_trend("60")
                        _fl_m30 = _fl_trend("30")
                        _both_against = (
                            (_opp == "SHORT" and _fl_h1 == "UPTREND" and _fl_m30 == "UPTREND") or
                            (_opp == "LONG" and _fl_h1 == "DOWNTREND" and _fl_m30 == "DOWNTREND")
                        )
                        # ★ [2026-05-16] _manual=True (수동 진입) 시 FLIP alignment 우회
                        if _both_against and not _is_manual:
                            logger.info("[FOCUS] ⛔ FLIP alignment block: %s %s→%s but H1=%s 30M=%s (counter-trend)",
                                        market, direction, _opp, _fl_h1, _fl_m30)
                            try:
                                from app.manager.trade_journal import journal
                                journal.record_blocked("FOCUS", market, _opp,
                                                       reason="flip_alignment_blocked",
                                                       detail=f"flip {direction}->{_opp} blocked: H1={_fl_h1} 30M={_fl_m30}")
                            except Exception as exc:
                                logger.debug("[FOCUS] record_blocked flip_alignment failed: %s", exc)
                            return {"state": "HUNT", "skip": f"flip_align:{_opp}_vs_H1{_fl_h1[:4]}_30M{_fl_m30[:4]}"}
                    except Exception as _fl_exc:
                        logger.debug("[FOCUS] FLIP alignment check error: %s", _fl_exc)

                logger.info("[FOCUS] ★ DIRECTION FLIPPED: %s %s → %s (original failed: %s, opposite passed MTF + reentry/regime)",
                            market, direction, _opp, _fail_reason)
                direction = _opp
                entry["direction"] = _opp  # 다운스트림 로직 일관성
            else:
                logger.info("[FOCUS] MTF fail both directions — true skip: %s (orig=%s, opp=%s)",
                            market, _fail_reason, _opp_fail)
                try:
                    from app.manager.trade_journal import journal
                    journal.record_blocked("FOCUS", market, direction,
                                           reason="mtf_both_blocked",
                                           detail=f"orig={_fail_reason};opp={_opp_fail}")
                except Exception as exc:
                    logger.debug("[FOCUS] record_blocked mtf_both failed: %s", exc)
                return {"state": "HUNT", "skip": f"mtf_both_{_fail_reason}"}

        # ── Entry Quality Filter (M5 마이크로타이밍) ──
        # [2026-04-18] SW_UPPER_BB/SW_LOWER_BB 면제 — Entry Quality는 추세 지속성 검사
        #   (m5_momentum, nbar_trend) 기반이라 mean reversion 신호와 구조적 충돌
        #   H4 counter_trend/Peak Fade/H1 penalty와 같은 패턴으로 SW 면제
        _entry_is_sw = entry.get("_is_sw_bb", False)
        if self.config.entry_quality_enabled and not _entry_is_sw:
            eq_ok, eq_reason = self._entry_quality_check(market, direction, price)
            if not eq_ok:
                logger.info("[FOCUS] Entry Quality BLOCKED: %s %s @ %.4f — %s",
                            direction, market, price, eq_reason)
                try:
                    from app.manager.trade_journal import journal
                    journal.record_blocked("FOCUS", market, direction,
                                           reason="entry_quality", detail=eq_reason)
                except Exception as exc:
                    logger.debug("[FOCUS] import journal failed: %s", exc)
                return {"state": "HUNT", "skip": f"entry_quality({eq_reason})"}
        elif _entry_is_sw:
            logger.info("[FOCUS] Entry Quality EXEMPT (SW mean reversion): %s %s", direction, market)

        # ★ 가격 sanity check: Bybit API로 이중 확인
        try:
            verified_price = self._get_client()._linear_last_price(market)
            if verified_price and verified_price > 0:
                # 가격이 50% 이상 차이나면 신뢰할 수 없음 → API 가격 사용
                ratio = price / verified_price if verified_price > 0 else 0
                if ratio < 0.5 or ratio > 2.0:
                    logger.warning("[FOCUS] Price sanity FAIL: price=%.6f vs API=%.6f (ratio=%.2f) → using API price",
                                   price, verified_price, ratio)
                    price = verified_price
                elif abs(ratio - 1.0) > 0.05:
                    logger.info("[FOCUS] Price drift: price=%.6f vs API=%.6f → using API price", price, verified_price)
                    price = verified_price
        except Exception as exc:
            logger.debug("[FOCUS] price verification failed: %s", exc)

        # Budget 결정: 0이면 기존 시스템, >0이면 고정
        effective_budget = self._get_effective_budget(market)

        # Compute position size (Green Pen 3M)
        from app.strategy.greenpen.cycle_tp import compute_cycle_targets, compute_position_size

        # ★ ATR: Primary = H4 ATR (primary_sig), Scanner = 코인별 개별 ATR (entry)
        #    Scanner 진입 시 primary_sig는 다른 코인(primary)의 ATR이므로 사용 금지
        atr = 0
        if entry.get("_scanner_entry") and entry.get("atr", 0) > 0:
            atr = entry["atr"]  # Scanner: 코인 자체 ATR (primary_sig는 primary 코인용)
        elif self.primary_sig and self.primary_sig.get("atr", 0) > 0:
            atr = self.primary_sig["atr"]  # Primary: H4 전략 ATR
        if atr <= 0:
            atr = entry.get("atr", price * 0.02)

        # ATR sanity check + cap
        if price > 0 and atr > 0:
            atr_pct = atr / price * 100
            MAX_ATR_PCT = float(getattr(self.config, "max_atr_pct", 5.0))  # [2026-04-26] config 노출
            if atr_pct > MAX_ATR_PCT:
                old_atr = atr
                atr = price * (MAX_ATR_PCT / 100.0)
                logger.warning("[FOCUS] ATR capped: %.4f (%.1f%%) → %.4f (%.1f%%) for %s",
                               old_atr, atr_pct, atr, MAX_ATR_PCT, market)
            elif atr_pct < 0.1:
                atr = price * 0.015
                logger.warning("[FOCUS] ATR too small → 1.5%% fallback: %.4f for %s", atr, market)

        # ★ Phase K (2026-04-21): regime_transition 태그 진입은 tp/sl 승수 교체
        _k_tp_mult = float(entry.get("_phase_k_tp_mult", 0) or 0)
        _k_sl_mult = float(entry.get("_phase_k_sl_mult", 0) or 0)
        if entry.get("_phase_k") and _k_tp_mult > 0 and _k_sl_mult > 0:
            _tp1 = self.config.cycle_tp1_mult * _k_tp_mult
            _tp2 = self.config.cycle_tp2_mult * _k_tp_mult
            _sl = self.config.cycle_sl_mult * _k_sl_mult
            logger.info("[FOCUS] Phase K TP/SL mults: tp1=%.2f→%.2f sl=%.2f→%.2f",
                        self.config.cycle_tp1_mult, _tp1, self.config.cycle_sl_mult, _sl)
        else:
            _tp1 = self.config.cycle_tp1_mult
            _tp2 = self.config.cycle_tp2_mult
            _sl = self.config.cycle_sl_mult

        # ★ [2026-05-15] min TP fee-guard: 진입가 옆 TP 방지 (저변동 코인 보호)
        _min_tp_pct = float(getattr(self.config, "min_tp_distance_pct", 0.30)) \
            if getattr(self.config, "min_tp_distance_enabled", False) else 0.0
        targets = compute_cycle_targets(
            price, direction, atr,
            tp1_mult=_tp1,
            tp2_mult=_tp2,
            sl_mult=_sl,
            min_rr=float(getattr(self.config, "cycle_min_rr", 1.0)),  # ★ [2026-04-26] config 노출
            min_tp_distance_pct=_min_tp_pct,
        )

        # ★ 레짐 TP/SL 스케일링 + 수수료 인식 (기존 인프라 재활용)
        targets = self._apply_regime_scaling(market, price, targets)

        # ── ★ Entry Expectation (2026-05-14 부모 — 진입 기대치 메커니즘) ──
        # H4 S/R 구조로 reward_target/risk_invalidation 산정 → 거래소 TP/SL 일원화.
        # 산정 불가(S/R·swing 미발견)면 위에서 계산한 ATR targets 를 그대로 유지(fallback).
        _exp_reward_target = 0.0
        _exp_risk_invalidation = 0.0
        _exp_rr_ratio = 0.0
        _exp_source = ""
        if getattr(self.config, "entry_expectation_enabled", False):
            try:
                from app.manager.entry_expectation import compute_entry_expectation, atr_from_ohlcv
                from app.strategy.greenpen.pa_detector import OHLCV as _EE_OHLCV
                _ee_client = self._get_client()
                _raw_primary = _ee_client.get_kline(market, interval=self.config.primary_tf, limit=60)
                _primary_candles = [_EE_OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4]))
                               for r in _raw_primary if len(r) >= 5]
                _raw_m15 = _ee_client.get_kline(market, interval="15", limit=60)
                _m15_candles = [_EE_OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4]))
                                for r in _raw_m15 if len(r) >= 5]
                _m15_atr = atr_from_ohlcv(_m15_candles)
                _exp = compute_entry_expectation(
                    direction, price, _primary_candles, atr,
                    m15_candles=_m15_candles, m15_atr=_m15_atr,
                )
                if _exp.is_valid:
                    _exp_reward_target = _exp.reward_target
                    _exp_risk_invalidation = _exp.risk_invalidation
                    _exp_rr_ratio = _exp.rr_ratio
                    _exp_source = f"{_exp.reward_source}/{_exp.risk_source}"
                    # ★ [2026-05-16 부모 SUI 사고] EE 가 cycle_tp 보다 불리한 방향이면 cycle_tp 유지.
                    # 사례: SUI 1m 떨어지는 중 → EE 가 H1 stale zone $1.099 로 TP 덮어씀 → reward 0.06% / RR 0.01 → 차단.
                    # 그러나 cycle_tp TP $1.064 (-2.9%) = 진짜 자리. EE 가 좁히기만 함.
                    # 해결: EE.TP 가 cycle_tp.TP 보다 reward 작으면 cycle_tp.TP 유지 (개선용으로만, 좁히기 금지).
                    #       EE.SL 도 cycle_tp.SL 보다 risk 크면 cycle_tp.SL 유지 (안전 우선).
                    _ee_tp_better = False
                    _ee_sl_better = False
                    if direction == "LONG":
                        # LONG: TP 는 위 (높을수록 reward 큼) / SL 은 아래 (낮을수록 risk 큼, 가까울수록 안전)
                        _ee_tp_better = _exp_reward_target > targets.tp2  # EE TP 가 더 위
                        _ee_sl_better = _exp_risk_invalidation > targets.sl  # EE SL 이 더 위 (가까움 = 안전)
                    elif direction == "SHORT":
                        # SHORT: TP 는 아래 (낮을수록 reward 큼) / SL 은 위 (낮을수록 가까움 = 안전)
                        _ee_tp_better = _exp_reward_target < targets.tp2  # EE TP 가 더 아래
                        _ee_sl_better = _exp_risk_invalidation < targets.sl  # EE SL 이 더 아래 (가까움 = 안전)
                    # 목표 일원화 — EE 가 더 좋은 쪽만 채택. 더 나쁜 쪽이면 cycle_tp 유지.
                    _orig_tp2 = targets.tp2
                    _orig_sl = targets.sl
                    if _ee_tp_better:
                        targets.tp2 = _exp_reward_target
                    if _ee_sl_better:
                        targets.sl = _exp_risk_invalidation
                    # EE 가 둘 다 안 채택되면 RR 재계산 (cycle_tp 기준)
                    if not (_ee_tp_better and _ee_sl_better):
                        try:
                            if direction == "LONG":
                                _new_reward = (targets.tp2 - price) / price * 100.0
                                _new_risk = (price - targets.sl) / price * 100.0
                            else:
                                _new_reward = (price - targets.tp2) / price * 100.0
                                _new_risk = (targets.sl - price) / price * 100.0
                            _new_risk = max(_new_risk, 0.001)
                            _exp_rr_ratio = _new_reward / _new_risk
                            _exp_source += f"|cycle_tp_kept(tp={_ee_tp_better},sl={_ee_sl_better})"
                            logger.info(
                                "[FOCUS] EE/cycle_tp blend: TP %s SL %s → reward=%.2f%% risk=%.2f%% RR=%.2f",
                                "EE" if _ee_tp_better else f"cycle($%.4g)" % _orig_tp2,
                                "EE" if _ee_sl_better else f"cycle($%.4g)" % _orig_sl,
                                _new_reward, _new_risk, _exp_rr_ratio,
                            )
                            # _exp 객체의 rr_ratio 도 갱신 (EE Gate 비교용)
                            _exp.rr_ratio = _exp_rr_ratio
                            _exp.reward_pct = _new_reward
                            _exp.risk_pct = _new_risk
                        except Exception as _blend_exc:
                            logger.debug("[FOCUS] EE/cycle_tp blend recalc failed: %s", _blend_exc)
                    # TP1(partial exit) 이 TP2 를 넘으면 목표 절반 지점으로 재설정
                    if direction == "LONG" and targets.tp1 >= targets.tp2:
                        targets.tp1 = price + (targets.tp2 - price) * 0.5
                    elif direction == "SHORT" and targets.tp1 <= targets.tp2:
                        targets.tp1 = price - (price - targets.tp2) * 0.5
                    logger.info(
                        "[FOCUS] ★ Entry Expectation: %s %s reward=%.2f%% risk=%.2f%% RR=%.2f (%s) → TP2=$%.6g SL=$%.6g",
                        direction, market, _exp.reward_pct, _exp.risk_pct, _exp.rr_ratio,
                        _exp_source, targets.tp2, targets.sl,
                    )
                    # ── ★ Entry Expectation Gate (2026-05-15 부모 — RR/risk 임계 차단) ──
                    # SIREN RR=0.18 같은 명백한 쓰레기 진입 차단. 산정 불가시는 fail-open(이 블록 안 도달).
                    # ★ [2026-05-16] _manual=True (수동 진입) 시 EE Gate 우회
                    if (getattr(self.config, "entry_expectation_gate_enabled", False) and not _is_manual
                            and not entry.get("_guard_score_pass")
                            and self._is_yellow_guard_active("entry")):  # [2026-05-28 부모 저녁] yellow 마스터 토글
                        _min_rr = float(getattr(self.config, "entry_expectation_min_rr", 1.0))
                        _max_risk = float(getattr(self.config, "entry_expectation_max_risk_pct", 6.0))
                        _min_reward = float(getattr(self.config, "entry_expectation_min_reward_pct", 0.8))
                        if _exp.rr_ratio < _min_rr:
                            logger.info("[FOCUS] ⛔ EE Gate: %s %s RR=%.2f < %.2f → SKIP entry",
                                        direction, market, _exp.rr_ratio, _min_rr)
                            try:
                                from app.manager.trade_journal import journal
                                journal.record_blocked("FOCUS", market, direction,
                                                       reason="ee_gate_rr_low",
                                                       detail=f"RR={_exp.rr_ratio:.2f}<{_min_rr:.2f}")
                            except Exception as exc:
                                logger.debug("[FOCUS] record_blocked ee_gate_rr failed: %s", exc)
                            return {"state": "HUNT", "skip": f"ee_gate_rr_low:{_exp.rr_ratio:.2f}"}
                        # [2026-05-20 5-14 설계도 Phase 2] reward < min_reward 차단 — "이 자리에서 갈 곳이 있는가"
                        if _exp.reward_pct < _min_reward:
                            logger.info("[FOCUS] ⛔ EE Gate: %s %s reward=%.2f%% < %.2f%% → SKIP entry",
                                        direction, market, _exp.reward_pct, _min_reward)
                            try:
                                from app.manager.trade_journal import journal
                                journal.record_blocked("FOCUS", market, direction,
                                                       reason="ee_gate_reward_low",
                                                       detail=f"reward={_exp.reward_pct:.2f}%<{_min_reward:.2f}%")
                            except Exception as exc:
                                logger.debug("[FOCUS] record_blocked ee_gate_reward failed: %s", exc)
                            return {"state": "HUNT", "skip": f"ee_gate_reward_low:{_exp.reward_pct:.2f}%"}
                        if _exp.risk_pct > _max_risk:
                            logger.info("[FOCUS] ⛔ EE Gate: %s %s risk=%.2f%% > %.2f%% → SKIP entry",
                                        direction, market, _exp.risk_pct, _max_risk)
                            try:
                                from app.manager.trade_journal import journal
                                journal.record_blocked("FOCUS", market, direction,
                                                       reason="ee_gate_risk_high",
                                                       detail=f"risk={_exp.risk_pct:.2f}%>{_max_risk:.2f}%")
                            except Exception as exc:
                                logger.debug("[FOCUS] record_blocked ee_gate_risk failed: %s", exc)
                            return {"state": "HUNT", "skip": f"ee_gate_risk_high:{_exp.risk_pct:.2f}%"}

                    # ── ★ 갭 체크 게이트 (2026-06-03 부모님 "충분한 갭을 갖지 못하면 진입의 의미가 없다") ──
                    # 선택 TF(5/15/30/60M) × N봉 고가(LONG)/저가(SHORT) 까지 거리 < min_pct → 진입 거부.
                    if (not _is_manual
                            and getattr(self.config, "gap_check_enabled", True)
                            and float(getattr(self.config, "gap_check_min_pct", 0.0)) > 0
                            and price > 0):
                        try:
                            _gc_tf   = str(getattr(self.config, "gap_check_tf", "15"))
                            _gc_bars = int(getattr(self.config, "gap_check_lookback_bars", 12))
                            _gc_min  = float(getattr(self.config, "gap_check_min_pct", 0.0))
                            _gc_raw  = self._get_mtf_kline(market, _gc_tf, limit=_gc_bars + 2, ttl=60.0)
                            if _gc_raw and len(_gc_raw) >= _gc_bars:
                                _gc_recent = _gc_raw[-_gc_bars:]
                                if direction == "LONG":
                                    _gc_wall = max(float(r[2]) for r in _gc_recent if len(r) >= 5)
                                    _gc_gap  = (_gc_wall - price) / price * 100.0
                                else:
                                    _gc_wall = min(float(r[3]) for r in _gc_recent if len(r) >= 5)
                                    _gc_gap  = (price - _gc_wall) / price * 100.0
                                # ★ ATR 적응 — 등락폭 큰 코인은 필요 갭 ↑ (꼭대기 추격 차단, 2026-06-07 부모)
                                _gc_eff = _gc_min
                                if (getattr(self.config, "gap_check_atr_adaptive_enabled", True)
                                        and price > 0 and atr > 0):
                                    _gc_atrp = atr / price * 100.0
                                    _gc_need = _gc_atrp * float(getattr(self.config, "gap_check_atr_mult", 0.7))
                                    _gc_cap  = float(getattr(self.config, "gap_check_atr_cap_pct", 1.5))
                                    _gc_eff  = max(_gc_min, min(_gc_need, _gc_cap))
                                if _gc_gap < _gc_eff:
                                    logger.info(
                                        "[FOCUS] ⛔ 갭Gate: %s %s %sM×%d봉 gap=%.2f%%<%.2f%%(ATR적응) (wall=%.4f) → SKIP",
                                        direction, market, _gc_tf, _gc_bars, _gc_gap, _gc_eff, _gc_wall,
                                    )
                                    try:
                                        from app.manager.trade_journal import journal
                                        journal.record_blocked(
                                            "FOCUS", market, direction,
                                            reason="gap_check",
                                            detail=f"gap={_gc_gap:.2f}%<{_gc_eff:.2f}%(min{_gc_min:.2f}/ATR적응,{_gc_tf}M×{_gc_bars}봉,wall={_gc_wall:.4f})",
                                        )
                                    except Exception:
                                        pass
                                    return {"state": "HUNT", "skip": f"gap_check:{_gc_tf}M={_gc_gap:.2f}%<{_gc_eff:.2f}%"}
                        except Exception as _gc_exc:
                            logger.debug("[FOCUS] gap_check failed (fail-open): %s", _gc_exc)

                    # ── ★ 변동성 도달가능성 게이트 (2026-05-23 부모님 "충분한 등락폭으로 TP 갈 수 있나") ──
                    # reward 거리(저항선)는 멀어도 변동성이 죽어있으면 거기 못 감 (나쁜 진입 29%, peak=0 → 4h 인내 → 손실).
                    # 최근 N봉 실제 등락폭(고저 range)이 reward 거리의 min_reach_ratio 이상이어야 진입.
                    if (getattr(self.config, "entry_volatility_gate_enabled", True)
                            and not _is_manual and _exp.reward_pct > 0
                            and not entry.get("_guard_score_pass")
                            and self._is_yellow_guard_active("entry")):  # [2026-05-28 부모 저녁] yellow 마스터 토글
                        try:
                            _vol_tf = str(getattr(self.config, "entry_volatility_lookback_tf", "5"))
                            _vol_bars = int(getattr(self.config, "entry_volatility_lookback_bars", 12))
                            _vol_min_ratio = float(getattr(self.config, "entry_volatility_min_reach_ratio", 0.6))
                            _raw_vol = self._get_mtf_kline(market, _vol_tf, limit=_vol_bars + 2, ttl=30.0)
                            if _raw_vol and len(_raw_vol) >= _vol_bars and price > 0:
                                _recent_vol = _raw_vol[-_vol_bars:]
                                _vol_highs = [float(r[2]) for r in _recent_vol if len(r) >= 5]
                                _vol_lows = [float(r[3]) for r in _recent_vol if len(r) >= 5]
                                if _vol_highs and _vol_lows:
                                    _recent_range_pct = (max(_vol_highs) - min(_vol_lows)) / price * 100.0
                                    _reach_ratio = _recent_range_pct / _exp.reward_pct if _exp.reward_pct > 0 else 0.0
                                    if _reach_ratio < _vol_min_ratio:
                                        logger.info(
                                            "[FOCUS] ⛔ 변동성 Gate: %s %s 최근%d봉 등락=%.2f%% / reward=%.2f%% = reach %.2f < %.2f → SKIP (횡보 죽은 자리)",
                                            direction, market, _vol_bars, _recent_range_pct, _exp.reward_pct, _reach_ratio, _vol_min_ratio,
                                        )
                                        try:
                                            from app.manager.trade_journal import journal
                                            journal.record_blocked(
                                                "FOCUS", market, direction,
                                                reason="volatility_gate",
                                                detail=f"reach={_reach_ratio:.2f}<{_vol_min_ratio:.2f}(range={_recent_range_pct:.2f}%/rw={_exp.reward_pct:.2f}%)",
                                            )
                                        except Exception as exc:
                                            logger.debug("[FOCUS] record_blocked volatility_gate failed: %s", exc)
                                        return {"state": "HUNT", "skip": f"volatility_gate:reach{_reach_ratio:.2f}"}
                        except Exception as _vol_exc:
                            logger.debug("[FOCUS] volatility gate failed (fail-open): %s", _vol_exc)
                else:
                    logger.info("[FOCUS] Entry Expectation: %s %s 산정 불가 — ATR targets 유지 (%s)",
                                direction, market, _exp.note)
            except Exception as _exp_exc:
                logger.warning("[FOCUS] Entry Expectation failed (ATR targets 유지): %s", _exp_exc)

        sl_distance = abs(price - targets.sl)

        # ★★★ SL distance 최소값: config 노출 (default 0.5%) ★★★
        # [2026-04-26 부모 fix] 0.1% → 0.5% — 작은 가격 코인 round 후 entry==sl 즉사 방지
        MIN_SL_PCT = float(getattr(self.config, "min_sl_pct", 0.005))
        min_sl_distance = price * MIN_SL_PCT
        if sl_distance < min_sl_distance:
            logger.warning("[FOCUS] SL distance too small: %.4f (%.4f%%) → floor %.4f (%.2f%%) for %s",
                           sl_distance, sl_distance / price * 100 if price > 0 else 0,
                           min_sl_distance, MIN_SL_PCT * 100, market)
            sl_distance = min_sl_distance
            # ★ 실제 SL 가격도 함께 수정 — Bybit에 보내는 SL이 너무 좁으면 즉사!
            if direction == "LONG":
                targets.sl = price - min_sl_distance
            else:
                targets.sl = price + min_sl_distance
            logger.info("[FOCUS] SL price adjusted → $%.4f (%.2f%% floor from $%.4f)", targets.sl, MIN_SL_PCT * 100, price)

        # ★★★ Sanity check — entry == sl 즉사 절대 방지 (4-26 부모 명령) ★★★
        if direction == "LONG":
                if targets.sl >= price * 0.999:  # SL 이 entry 의 99.9% 이상이면 위험
                    targets.sl = price * 0.99  # 강제 1% 아래로
                    sl_distance = price - targets.sl
                    logger.warning("[FOCUS] ⚠ SANITY: LONG sl too close to entry — forced 1%% below ($%.4f)", targets.sl)
        else:
                if targets.sl <= price * 1.001:  # SL 이 entry 의 100.1% 이하면 위험
                    targets.sl = price * 1.01  # 강제 1% 위로
                    sl_distance = targets.sl - price
                    logger.warning("[FOCUS] ⚠ SANITY: SHORT sl too close to entry — forced 1%% above ($%.4f)", targets.sl)

        # ★★★★★ [2026-04-26 부모 절대 명령] PARENT ROE GUARD ★★★★★
        # "어떤 일이 있어도 -31% 까지는 청산하는 일 있으면 안된다"
        # SL 거리를 ROE -31% 지점으로 강제 — SL 거리 = entry × (31% / leverage)
        # leverage 5 → SL 거리 6.2% / leverage 7 → 4.43%
        if getattr(self.config, "parent_roe_guard_enabled", True):
            parent_roe_cap = float(getattr(self.config, "parent_max_roe_loss_pct", 31.0))
            lev = max(1, int(getattr(self.config, "leverage", 5)))
            parent_min_pct = parent_roe_cap / lev
            parent_min_distance = price * (parent_min_pct / 100.0)
            current_sl_pct = (sl_distance / price * 100) if price > 0 else 0
            if sl_distance < parent_min_distance:
                logger.warning("[FOCUS] ★★ PARENT ROE GUARD: SL %.2f%% → %.2f%% (ROE -31%% 견딤 보장, lev=%d, %s)",
                               current_sl_pct, parent_min_pct, lev, market)
                sl_distance = parent_min_distance
                if direction == "LONG":
                    targets.sl = price - parent_min_distance
                else:
                    targets.sl = price + parent_min_distance

        # ★★★ SL distance 절대 상한: config 노출 (default 99.0%, 부모님 "이윤 못내면 못나가") ★★★
        # ★ Override Slot (2026-05-10): override 자격 진입 시 가까운 SL (5%) 적용 (배신 대비)
        if bool(entry.get("_is_override", False)):
            MAX_SL_DISTANCE_PCT = float(getattr(self.config, "override_max_sl_distance_pct", 5.0))
        else:
            MAX_SL_DISTANCE_PCT = float(getattr(self.config, "max_sl_distance_pct", 99.0))
        sl_distance_pct = abs(price - targets.sl) / price * 100 if price > 0 else 0
        if sl_distance_pct > MAX_SL_DISTANCE_PCT:
            logger.warning("[FOCUS] SL distance %.2f%% capped to %.1f%% for %s",
                           sl_distance_pct, MAX_SL_DISTANCE_PCT, market)
            if direction == "LONG":
                targets.sl = price * (1 - MAX_SL_DISTANCE_PCT / 100)
            else:
                targets.sl = price * (1 + MAX_SL_DISTANCE_PCT / 100)
            sl_distance = abs(price - targets.sl)
            logger.info("[FOCUS] SL capped → $%.4f (%.1f%% ceiling from $%.4f)", targets.sl, MAX_SL_DISTANCE_PCT, price)

        # ── 🌋 [2026-06-11 부모] 변동성 각성 SL 적응 — 각성+Day순행 시 SL 넓게(size 자동↓ 리스크 고정) ──
        #   여기(SL 확정 후·TP R:R·예산 전)서 sl_distance 키우면 → 아래 TP R:R·compute_position_size 가
        #   새 sl_distance 로 자동 반영(TP 동반 확장 + size 축소). default OFF.
        if getattr(self.config, "awaken_sl_enabled", False):
            try:
                _aw_dist, _aw_sl, _aw_lbl = self._volatility_awakening_sl(
                    market, price, atr, direction, sl_distance)
                if _aw_sl is not None and _aw_dist > sl_distance:
                    targets.sl = _aw_sl
                    sl_distance = _aw_dist
                    logger.info("[FOCUS] 🌋 변동성 각성 SL 적응: %s", _aw_lbl)
            except Exception as _aw_exc:
                logger.debug("[FOCUS] awaken sl apply error: %s", _aw_exc)

        # ★ TP도 최소 보장: SL보다 작으면 안 됨 (R:R 최소 1:1)
        tp1_dist = abs(targets.tp1 - price)
        if tp1_dist < sl_distance:
            if direction == "LONG":
                targets.tp1 = price + sl_distance
            else:
                targets.tp1 = price - sl_distance
            logger.info("[FOCUS] TP1 adjusted for min R:R 1:1 → $%.2f", targets.tp1)

        # ── v2: Conviction 기반 예산 (DCA/Scout/Anti-Martingale/TimeVolatility 제거) ──
        conviction_score = float(entry.get("conviction_score", 0))  # [2026-05-17 100점] int 절삭 제거
        conviction_budget = float(entry.get("conviction_budget", 0))
        if conviction_budget > 0:
            effective_budget = conviction_budget
        # conviction이 없으면 기존 effective_budget 유지 (fallback)

        # ★ [2026-04-25 부모 신규] Dynamic Leverage — ATR% 기반 코인별 차등
        # 저변동 코인 (ETH 같은) → lev 낮춤 / 고변동 → lev 높임
        _atr_pct_for_lev = (atr / price * 100) if (price > 0 and atr > 0) else 2.0
        _dyn_lev = self._compute_dynamic_leverage(_atr_pct_for_lev, market=market)
        # Bybit 에 per-symbol leverage 설정 (실패해도 진행 — fallback 은 Bybit 기본)
        try:
            client = self._get_client()
            if client and hasattr(client, "set_leverage"):
                client.set_leverage(market, _dyn_lev)
                logger.debug("[FOCUS] Bybit set_leverage %s → %dx OK", market, _dyn_lev)
        except Exception as _lev_exc:
            logger.warning("[FOCUS] set_leverage failed %s lev=%d: %s (fallback Bybit 기본 leverage)",
                           market, _dyn_lev, _lev_exc)

        # ★★★ Per-Coin Size Cap (2026-05-08 부모님 결정) ★★★
        # 4-26 풀가동 후 1건 -$202 사고 원인 해소.
        # "안 팔리면 언젠가는 올라온다" 정수 (95%) 와 충돌 X — 안 팔지만 사이즈 작게.
        # ★ Override Slot (2026-05-10): override 자격 진입 시 별도 cap (8%) 적용 (배신 대비)
        _is_override_entry = bool(entry.get("_is_override", False))
        if _is_override_entry:
            _cap_pct = float(getattr(self.config, "override_size_cap_pct", 8.0))
        elif getattr(self.config, "per_coin_size_cap_enabled", False):
            _cap_pct = float(getattr(self.config, "per_coin_size_cap_pct", 20.0))
        else:
            _cap_pct = 0.0
        if _cap_pct > 0:
            _equity_for_cap = float(getattr(self.system, '_last_equity_usdt', 0) or 0)
            if _equity_for_cap > 0:
                _max_size_usd = _equity_for_cap * (_cap_pct / 100.0)
                if effective_budget > _max_size_usd:
                    _label = "Override size cap" if _is_override_entry else "Per-coin size cap"
                    logger.warning(
                        "[FOCUS] %s %s: $%.2f → $%.2f (%.1f%% of equity $%.2f)",
                        _label, market, effective_budget, _max_size_usd, _cap_pct, _equity_for_cap
                    )
                    effective_budget = _max_size_usd

        # [2026-05-29 부모] Slot Auto Expand 사이즈 축소 — 자본 보호 (default 50%)
        if entry.get("_slot_expand", False):
            _se_ratio = float(getattr(self.config, "slot_auto_expand_size_ratio", 0.5))
            _orig_budget = effective_budget
            effective_budget = effective_budget * _se_ratio
            logger.warning(
                "[FOCUS] ★ Slot Auto Expand size: $%.2f → $%.2f (×%.2f, 자본 보호) %s",
                _orig_budget, effective_budget, _se_ratio, market,
            )

        logger.info("[FOCUS] Sizing inputs: budget=$%.2f conviction=%d sl_dist=%.8f price=%.6f lev=%d(dyn) market=%s",
                    effective_budget, conviction_score, sl_distance, price, _dyn_lev, market)

        # ★ [진입점수=확신] guard 점수 기준 risk 스케일 (역U자) — cap 안 막히고 qty에 직접 닿음
        _anchor_conv = float(entry.get("_guard_score", conviction_score) or conviction_score or 0)
        _crf = self._conv_risk_factor(_anchor_conv)
        _eff_risk_pct = self.config.risk_pct * _crf
        if _crf != 1.0:
            logger.info("[FOCUS] conv-risk 스케일: %s guardconv=%.0f risk %.2f%%→%.2f%% (×%.2f, 진입점수=확신)",
                        market, _anchor_conv, self.config.risk_pct, _eff_risk_pct, _crf)

        sizing = compute_position_size(
            effective_budget, _eff_risk_pct,
            sl_distance, price,
            leverage=_dyn_lev,
            max_daily_plans=self.config.max_daily_plans,
        )

        if sizing.leverage_qty <= 0:
            return {"state": "HUNT", "error": "qty_zero"}

        # ★ Phase L (2026-04-22) — S3 Fee-Aware net_ev Gate ★
        # 검수 기준 #3: 모든 방어 (B11/B10/B8/B9/J v2/Morning Shield 등) 이후
        # 검수 기준 #5: paper_mode=True 면 진입 허용 + 가상 카운터만
        # 검수 기준 #10: default OFF + paper_mode=True 2중 안전망 (Phase K 패턴)
        # ★ 형 letter PASS (2026-04-22 21:05) MED 1건 수정:
        #   기존 `tp_mult = cycle_tp1_mult * _tp1` 이중 곱셈 (_tp1 이미 cycle_tp1_mult 포함)
        #   → gross_ev 가 cycle_tp1_mult 배 부풀려져 Gate 가 느슨해지는 버그
        #   수정: `tp_mult = _tp1` (이미 full multiplier)
        try:
            _l3_pa_double = bool(entry.get("_pa_double_confirmed", False))
            _s3_allow, _s3_reason, _s3_stats = self._check_s3_fee_gate(
                market=market,
                direction=direction,
                price=price,
                atr=atr,
                size_usdt=effective_budget,
                leverage=int(_dyn_lev),   # ★ [2026-04-25] dynamic leverage (ATR tier)
                tp_mult=float(_tp1),   # ★ FIX: _tp1 이 이미 cycle_tp1_mult (+ Phase K mult) 포함
                sl_mult=float(_sl),    # ★ FIX: _sl 이 이미 cycle_sl_mult (+ Phase K mult) 포함
                pa_double_confirmed=_l3_pa_double,
            )
            # 검수 기준 #4 + #8: stats 영속화 (paper/live 무관 항상 기록)
            if _s3_stats:
                self._persist_s3_gate_stats(_s3_stats)
            # live 모드에서만 차단
            if not _s3_allow:
                return {"state": "HUNT", "error": "s3_fee_gate_blocked", "reason": _s3_reason}
        except Exception as _s3_exc:
            # 엣지: S3 Gate 자체 예외 시 진입 차단 X (안전 fallback) — 형 letter #11 의 "신중 접근"
            logger.warning("[S3_GATE] check exception (fallback PASS): %s", _s3_exc, exc_info=True)

        # Switch to one-way mode + set leverage
        client = self._get_client()
        try:
            client.switch_position_mode(market, mode="MergedSingle")
        except Exception as exc:
            err_str = str(exc)
            # retCode=110025 "Position mode is not modified" = 이미 MergedSingle → 성공과 동일
            if "110025" in err_str or "not modified" in err_str.lower():
                logger.debug("[FOCUS] position mode already MergedSingle — OK")
            elif "position" in err_str.lower() and ("exist" in err_str.lower() or "mode" in err_str.lower()):
                # ★ 진짜 Hedge Mode 충돌 (열린 포지션 있어서 전환 불가 등)
                logger.error("[FOCUS] ABORT ENTRY: position mode switch failed (hedge mode conflict): %s", exc)
                return {"state": self.state.value, "error": f"position_mode_conflict: {exc}"}
            else:
                logger.warning("[FOCUS] switch_position_mode: %s (assuming one-way)", exc)
        try:
            client.set_leverage(market, self.config.leverage)
        except Exception as exc:
            logger.debug("[FOCUS] set_leverage: %s (may already be set)", exc)

        # ★★★ QTY 폭발 방지: notional value 상한 체크 ★★★
        order_qty = sizing.leverage_qty
        # ★ [패치 v2-A] Pre-Close 선행 진입 = 마감 확인 전 → 절반 사이즈 (이후 lot/margin 클램프 통과)
        if entry.get("preclose"):
            _pc_ratio = max(0.05, min(1.0, float(getattr(self.config, "preclose_size_ratio", 0.5))))
            if _pc_ratio < 1.0:
                order_qty = order_qty * _pc_ratio
                entry["_preclose_ratio"] = _pc_ratio  # ★ [v2-A2] 마감확인 증액 시 나머지 반 계산용
                logger.info("[FOCUS] ⏩ Pre-Close 선행 진입: %s %s — 사이즈 ×%.2f (%s)",
                            market, direction, _pc_ratio, entry.get("_preclose_rsn", ""))
        notional_value = order_qty * price
        max_notional = effective_budget * self.config.leverage * 2  # 예산×레버리지×2 이내 (5→2 축소: SL 좁을 때 과잉 진입 방지)
        if max_notional < 100:
            max_notional = 100  # 최소 $100
        if notional_value > max_notional:
            logger.error("[FOCUS] QTY EXPLOSION BLOCKED: qty=%.0f notional=$%.0f > max=$%.0f for %s "
                         "(budget=$%.2f sl_dist=%.8f price=%.6f)",
                         order_qty, notional_value, max_notional, market,
                         effective_budget, sl_distance, price)
            # 안전한 qty로 재계산
            safe_qty = (effective_budget * self.config.leverage) / price
            order_qty = safe_qty
            logger.info("[FOCUS] Safe qty fallback: %.4f (notional=$%.2f)", order_qty, order_qty * price)

        # Adjust qty precision for Bybit linear — fetch instrument info directly
        try:
            from app.core.constants import BYBIT_MARKET_INSTRUMENTS
            resp = client._request("GET", BYBIT_MARKET_INSTRUMENTS,
                                   params={"category": "linear", "symbol": market})
            inst_list = resp.get("list", []) if isinstance(resp, dict) else []
            if inst_list:
                lot_filter = inst_list[0].get("lotSizeFilter", {})
                qty_step = float(lot_filter.get("qtyStep", 0.01) or 0.01)
                min_qty = float(lot_filter.get("minOrderQty", 0.01) or 0.01)
                max_order_qty = float(lot_filter.get("maxOrderQty", 0) or 0)
                # Round down to qtyStep
                import math
                if qty_step > 0:
                    order_qty = math.floor(order_qty / qty_step) * qty_step
                    order_qty = round(order_qty, 8)
                # ★ maxOrderQty 체크 — qty가 Bybit 한도 초과 시 블록
                if max_order_qty > 0 and order_qty > max_order_qty:
                    logger.error("[FOCUS] QTY BLOCKED: %.0f > maxOrderQty %.0f for %s — blacklisting coin",
                                 order_qty, max_order_qty, market)
                    tbl = getattr(self, '_temp_blacklist', {})
                    tbl[market] = time.time() + 600  # 10분 블랙리스트
                    self._temp_blacklist = tbl
                    self.selected_market = ""
                    self.state = FocusState.DORMANT
                    self._save_config()
                    return {"state": "DORMANT", "error": f"qty>{max_order_qty:.0f}"}
                if order_qty < min_qty:
                    logger.warning("[FOCUS] qty %.8f < minOrderQty %.8f for %s — skipping", order_qty, min_qty, market)
                    return {"state": "HUNT", "error": f"qty_below_min({order_qty}<{min_qty})"}
                logger.info("[FOCUS] qty adjusted: %.8f (step=%.4f min=%.4f max=%.0f)", order_qty, qty_step, min_qty, max_order_qty)
        except Exception as exc:
            logger.warning("[FOCUS] instrument info fetch failed: %s — using raw qty %.8f", exc, order_qty)

        # ★ Margin cap — notional/leverage가 available balance 초과 시 qty 축소
        _avail = self._get_available_margin()  # Bybit API (정확)
        if _avail <= 0:
            # API 실패 시 내부 추정치 fallback
            _equity = float(getattr(self.system, '_last_equity_usdt', 0) or 0)
            _used = sum(abs(p.qty) * p.entry_price / max(1, self.config.leverage) for p in self.positions)
            _avail = max(0.0, _equity - _used)
        if _avail > 0:
            margin_needed = (order_qty * price) / max(1, self.config.leverage)
            margin_limit = _avail * 0.95  # 5% 여유
            if margin_needed > margin_limit:
                old_qty = order_qty
                order_qty = (margin_limit * self.config.leverage) / price
                # qty_step 재적용
                try:
                    _qs = qty_step
                    if _qs > 0:
                        import math
                        order_qty = math.floor(order_qty / _qs) * _qs
                        order_qty = round(order_qty, 8)
                except NameError:
                    pass
                logger.warning("[FOCUS] Margin cap: qty %.4f → %.4f (margin $%.0f > avail $%.0f × 95%%)",
                               old_qty, order_qty, margin_needed, _avail)
                if order_qty <= 0 or (order_qty * price) < 5:
                    logger.warning("[FOCUS] Margin insufficient: avail=$%.2f, need=$%.2f — skip %s",
                                   _avail, margin_needed, market)
                    return {"state": "HUNT", "error": f"margin_insufficient(avail=${_avail:.0f})"}

        # ── 🪙 ★ Orderbook 깊이 사이즈 적응 (2026-06-09 부모 "잔돈 없는 환전소") ──
        # 얇은 호가가 못 받는 큰 주문 = 미체결 폭탄. 수용량으로 clamp / 너무 얇으면 skip.
        if getattr(self.config, "orderbook_depth_sizing_enabled", False):
            try:
                from app.core.hyper_price_store import orderbook_store
                _ob = orderbook_store.get(market)
                _units = (_ob or {}).get("units") or []
                if _units and price > 0:
                    _ob_slip = float(getattr(self.config, "orderbook_depth_max_slippage_pct", 0.3))
                    _ob_min_ratio = float(getattr(self.config, "orderbook_depth_min_fill_ratio", 0.5))
                    _avail_qty = 0.0
                    if direction == "LONG":
                        _lim = price * (1 + _ob_slip / 100.0)
                        for _u in _units:
                            _ap = float(_u.get("ask_price", 0) or 0); _asz = float(_u.get("ask_size", 0) or 0)
                            if 0 < _ap <= _lim:
                                _avail_qty += _asz
                    else:
                        _lim = price * (1 - _ob_slip / 100.0)
                        for _u in _units:
                            _bp = float(_u.get("bid_price", 0) or 0); _bsz = float(_u.get("bid_size", 0) or 0)
                            if _bp >= _lim and _bp > 0:
                                _avail_qty += _bsz
                    if _avail_qty > 0 and order_qty > _avail_qty:
                        _fill_ratio = _avail_qty / order_qty
                        if _fill_ratio < _ob_min_ratio:
                            logger.warning(
                                "[FOCUS] 🪙 Orderbook 얕음 SKIP: %s %s 의도=%.4f > 수용=%.4f (%.0f%%<min%.0f%%, slip%.2f%%, %d호가) — 잔돈 없는 환전소",
                                direction, market, order_qty, _avail_qty, _fill_ratio * 100, _ob_min_ratio * 100, _ob_slip, len(_units),
                            )
                            return {"state": "HUNT", "error": f"orderbook_too_thin({_fill_ratio*100:.0f}%<{_ob_min_ratio*100:.0f}%)"}
                        _old_q = order_qty
                        order_qty = _avail_qty
                        try:  # lot step 재적용 (qty_step 스코프에 있으면)
                            if qty_step and qty_step > 0:
                                order_qty = round(math.floor(order_qty / qty_step) * qty_step, 8)
                        except NameError:
                            pass
                        logger.info(
                            "[FOCUS] 🪙 Orderbook 사이즈 적응: %s %s qty %.4f→%.4f (호가 수용량, slip%.2f%%) — 미체결 방지",
                            direction, market, _old_q, order_qty, _ob_slip,
                        )
            except Exception as _ob_exc:
                logger.debug("[FOCUS] orderbook depth sizing skip (fail-open): %s", _ob_exc)

        logger.info("[FOCUS] Attempting entry: %s %s qty=%.8f (raw=%.8f) price=%.2f",
                     "Buy" if direction == "LONG" else "Sell", market, order_qty, sizing.leverage_qty, price)

        # Place order
        try:
            side = "Buy" if direction == "LONG" else "Sell"
            order = client.place_order(
                market=market, side=side, ord_type="market",
                volume=order_qty,
            )
            # ★ [2026-06-11] cowork ①② — 실제 체결가/체결량 추출 (best-effort).
            #   미체결 최종 판정은 아래 verify 블록(0.5s 안정 후 실제 포지션 조회)이 담당.
            #   여기서 raise 시 시장가 지연체결이 추적불가 포지션 되는 위험 → 권위 조회로 미룸.
            _fill_price, _filled_qty, _ostate, _is_filled = self._extract_fill(
                order, fallback_price=price, fallback_qty=order_qty)
            _entry_price_actual = _fill_price if _fill_price > 0 else price
            _entry_qty_actual = _filled_qty if _filled_qty > 0 else order_qty
            logger.info("[FOCUS] Entry order placed: %s %s qty=%.8f @ $%.4f (intended $%.4f, state=%s)",
                        side, market, _entry_qty_actual, _entry_price_actual, price, _ostate)
            # ★ [2026-06-11] cowork ③ — 서버 SL/TP 를 진입 직후 즉시 설정 (기존엔 방향검증+sleep 후 ~2.5s 공백).
            #   여기서 1차 보호. 방향 보정(아래)·실패 시 하단 블록이 재설정/재시도.
            try:
                client.set_trading_stop(market, take_profit=targets.tp2, stop_loss=targets.sl)
                logger.info("[FOCUS] ⚡ 진입 직후 SL/TP 즉시 설정: SL=$%.4f TP=$%.4f", targets.sl, targets.tp2)
            except Exception as _esl:
                logger.warning("[FOCUS] 진입 직후 SL 즉시설정 실패 (하단 재시도 예정): %s", _esl)
            # ★ [2026-06-11] 장부 기록(record_entry)은 아래 verify(미체결 판정) 통과 후로 이동 —
            #   미체결 abort 시 유령 장부가 남지 않도록.
        except Exception as exc:
            err_msg = str(exc)
            # ★ 마진 부족 OR qty 초과 OR 기타 Bybit 거부 → 재시도 무의미
            is_fatal = (
                "ab not enough" in err_msg or "110007" in err_msg
                or "exceeds maximum" in err_msg or "10001" in err_msg
                or "max_qty" in err_msg
                or "110125" in err_msg or "Trading Terms" in err_msg
            )
            if is_fatal:
                logger.warning("[FOCUS] ORDER REJECTED for %s: %s — blacklisting coin, re-selecting", market, err_msg[:120])
                # ★ Bybit 약관 미동의(110125) 등 → 영구 블랙리스트에 자동 추가
                if ("110125" in err_msg or "Trading Terms" in err_msg) and market not in self.config.scanner_blacklist:
                    self.config.scanner_blacklist.append(market)
                    logger.warning("[FOCUS] %s → PERMANENT scanner blacklist (Bybit terms required)", market)
                # ★ 이 코인을 일시 블랙리스트 (같은 코인 반복 진입 방지)
                bl = getattr(self, '_temp_blacklist', {})
                bl[market] = time.time() + 600  # 10분간 이 코인 건너뜀
                self._temp_blacklist = bl
                self._entry_fail_count = 0
                self.selected_market = ""
                self.state = FocusState.DORMANT
                self.last_scan_ts = time.time() + 60  # 1분 후 다른 코인으로 재스캔
                self._save_config()
                return {"state": "DORMANT", "reason": f"order_rejected_reselect: {err_msg[:80]}"}

            logger.error("[FOCUS] Entry order FAILED: %s", exc, exc_info=True)
            fail_count = getattr(self, '_entry_fail_count', 0) + 1
            self._entry_fail_count = fail_count
            if fail_count >= 3:
                logger.warning("[FOCUS] 3 entry failures on %s — re-selecting coin", market)
                self._entry_fail_count = 0
                self.selected_market = ""
                self.state = FocusState.DORMANT
                self._save_config()
                return {"state": "DORMANT", "reason": f"entry_failed_3x_reselect: {exc}"}
            return {"state": "HUNT", "error": f"order_failed({fail_count}/3): {exc}"}

        # ★ 진입 직후 Bybit 실제 포지션 방향 검증 — 방향 불일치 즉시 감지
        # ★ [2026-05-25 부모] paper/dry 모드: 실거래소 조회 skip — 가상 진입은 실제 Bybit 에
        #   없으므로, 실계좌에 우연히 남은 동일 코인 포지션에 paper 방향이 끌려가는 오류 방지.
        _actual_leverage = None  # ★ [2026-06-11] cowork ④ — 거래소 실제 leverage
        _verified_size = None     # ★ [2026-06-11] cowork ② — 거래소 실제 체결 size
        _position_found = False   # ★ [2026-06-11] cowork ② — 진입 후 실제 포지션 존재 확인(미체결 판정)
        _verify_ok = False        # 조회 자체가 성공했는지 (실패 시 미체결 단정 금지)
        try:
            if self._is_live_mode():
                import time as _vt; _vt.sleep(0.5)  # 체결 반영 대기
                from app.core.constants import BYBIT_POSITION_LIST
                pos_resp = client._request("GET", BYBIT_POSITION_LIST,
                                            params={"category": "linear", "symbol": market})
                _verify_ok = True
                pos_list = pos_resp.get("list", []) if isinstance(pos_resp, dict) else []
                for bp in pos_list:
                    if float(bp.get("size", 0)) > 0:
                        _position_found = True
                        _verified_size = float(bp.get("size", 0))
                        bybit_side = bp.get("side", "")
                        bybit_dir = "LONG" if bybit_side == "Buy" else "SHORT"
                        # ★ [2026-06-11] cowork ④ — 실제 leverage 검증. 의도와 불일치 시 경보(노출액/청산가 어긋남).
                        try:
                            _actual_leverage = float(bp.get("leverage", 0) or 0)
                            if _actual_leverage > 0 and abs(_actual_leverage - _dyn_lev) >= 0.5:
                                logger.error("[FOCUS] ⚠ LEVERAGE MISMATCH %s: 의도 %dx ≠ 거래소 %.0fx "
                                             "— set_leverage 실패 의심, 노출액/청산가 어긋남",
                                             market, _dyn_lev, _actual_leverage)
                        except (TypeError, ValueError):
                            _actual_leverage = None
                        # ★ [2026-06-11] cowork ⑤ — 방향 불일치는 Bybit 진실로 흡수하되 원인 경보(직전 잔여/이중체결).
                        if bybit_dir != direction:
                            logger.error("[FOCUS] ⚠ DIRECTION MISMATCH after entry! Intended=%s but Bybit=%s(%s) size=%.8f "
                                         "— 직전 포지션 잔여/이중체결 의심. Bybit 방향으로 보정",
                                         direction, bybit_dir, bybit_side, _verified_size)
                            direction = bybit_dir  # Bybit이 최종 진실
                        # ★ [2026-06-11] cowork ② — size 검증: 의도 수량과 5%+ 차이 시 경보(부분/이중 체결).
                        if order_qty > 0 and abs(_verified_size - order_qty) / order_qty > 0.05:
                            logger.warning("[FOCUS] ⚠ SIZE MISMATCH %s: 의도 qty=%.8f ≠ 거래소 size=%.8f (부분/이중 체결 의심)",
                                           market, order_qty, _verified_size)
                        break
        except Exception as vexc:
            logger.debug("[FOCUS] Post-entry position verify failed (non-critical): %s", vexc)
        # ★ [2026-06-11] cowork ② — 조회 성공했는데 포지션이 없으면 미체결 확정 → 유령 방지로 포지션 미생성.
        #   (조회 실패 _verify_ok=False 시엔 단정 금지 — 기존대로 진행, 다음 tick SYNC 가 정리.)
        if self._is_live_mode() and _verify_ok and not _position_found:
            logger.error("[FOCUS] ⚠ 진입 후 거래소에 포지션 없음 %s — 미체결 확정, 포지션 미생성(유령 방지)", market)
            fail_count = getattr(self, '_entry_fail_count', 0) + 1
            self._entry_fail_count = fail_count
            if fail_count >= 3:
                self._entry_fail_count = 0
                self.selected_market = ""
                self.state = FocusState.DORMANT
                self._save_config()
                return {"state": "DORMANT", "reason": "entry_unconfirmed_3x_reselect"}
            return {"state": "HUNT", "error": f"entry_unconfirmed_no_position({fail_count}/3)"}
        # ★ [2026-06-11] 거래소 검증값으로 포지션 기록 보정 (live 에서 size/leverage 가 진실)
        if _verified_size and _verified_size > 0:
            _entry_qty_actual = _verified_size
        _pos_leverage = int(round(_actual_leverage)) if (_actual_leverage and _actual_leverage > 0) else _dyn_lev

        # ★ 방향 보정 후 TP/SL 재계산 (Bybit 실제 방향과 targets 방향이 다를 수 있음)
        if direction != entry.get("direction", direction):
            # direction이 Bybit 검증에서 바뀌었음 → targets 재계산 필수
            from app.strategy.greenpen.cycle_tp import compute_cycle_targets
            _min_tp_pct_2 = float(getattr(self.config, "min_tp_distance_pct", 0.30)) \
                if getattr(self.config, "min_tp_distance_enabled", False) else 0.0
            targets = compute_cycle_targets(
                price, direction, atr,
                tp1_mult=self.config.cycle_tp1_mult,
                tp2_mult=self.config.cycle_tp2_mult,
                sl_mult=self.config.cycle_sl_mult,
                min_tp_distance_pct=_min_tp_pct_2,
            )
            # ★ Entry Expectation 무효화 — _exp_* 는 옛 방향 기준이라 신뢰 불가.
            #   0 으로 비우면 진행률 청산이 자동 비활성 → 기존 LHT 가 fallback.
            _exp_reward_target = 0.0
            _exp_risk_invalidation = 0.0
            _exp_rr_ratio = 0.0
            _exp_source = ""
            logger.warning("[FOCUS] TP/SL recalculated for corrected direction %s: TP1=$%.2f TP2=$%.2f SL=$%.2f (Entry Expectation 무효화)",
                           direction, targets.tp1, targets.tp2, targets.sl)

        # ★ [2026-05-26 부모] TF 라운드 앵커 TP/SL 오버라이드 (교재 충실, 기본 OFF)
        #   ON 시: cycle_tp/EE/regime 결과를 버리고 거래TF 라운드(ATR×배수)+앵커(직전 H4 최고점)로 대체.
        #   ★ [2026-05-27 부모] entry["_pa_via"] 따라 TF 분리 (H4 PA→H4 anchor / H1 PA→H1 anchor).
        if self._tf_round_active():
            try:
                _pa_via = entry.get("_pa_via", "")
                _tf_override = "60" if _pa_via == "h1" else "240"  # h4 또는 기본 = 240
                _rnd = self._compute_tf_round_targets(market, direction, tf_override=_tf_override)
                if _rnd:
                    _tn_tp1, _tn_tp2, _tn_sl, _rnd_atr = _rnd
                    # ★ [2026-05-28 부모] SL 안전망 — anchor 진입가 반대편 OR SL 거리 너무 짧음 → fallback
                    #   부모님 정신 (내부메모/GreenPen): TP1 ATR×1, TP2 ATR×2, SL=TP1×⅓ (RR 1:3) — H1 도 동일 비율.
                    #   forming 캔들 짧을 때 anchor low/high 가 진입가 가까워 SL 즉시 hit 위험 → 최소 거리 보장.
                    _min_sl_chk = float(getattr(self.config, "min_sl_pct", 0.005)) or 0.005
                    _sl_wrong = False
                    _wrong_reason = ""
                    # 조건 1: SL 방향 잘못 (LONG SL ≥ price 또는 SHORT SL ≤ price)
                    if direction == "LONG" and _tn_sl >= price * (1 - _min_sl_chk):
                        _sl_wrong = True; _wrong_reason = "SL≥entry(LONG)"
                    elif direction == "SHORT" and _tn_sl <= price * (1 + _min_sl_chk):
                        _sl_wrong = True; _wrong_reason = "SL≤entry(SHORT)"
                    # 조건 2: SL 거리 너무 짧음 (min_sl_pct 미만)
                    _sl_dist_pct = abs(_tn_sl - price) / price if price > 0 else 0
                    if not _sl_wrong and _sl_dist_pct < _min_sl_chk:
                        _sl_wrong = True; _wrong_reason = f"SL_dist<{_min_sl_chk*100:.2f}%"
                    # ★ [2026-05-28 부모] 조건 3: TP 방향 잘못 — XLM 사례 (진입가 0.178 / TP2 0.151)
                    #   LONG TP ≤ entry 또는 SHORT TP ≥ entry → anchor 가 옛 가격대라 TP가 진입가 반대편.
                    #   진입 즉시 TP hit = 의미 없는 청산. anchor=price 재계산 필수.
                    if not _sl_wrong:
                        if direction == "LONG" and (_tn_tp1 <= price or _tn_tp2 <= price):
                            _sl_wrong = True
                            _wrong_reason = "TP≤entry(LONG, anchor 옛가격)"
                        elif direction == "SHORT" and (_tn_tp1 >= price or _tn_tp2 >= price):
                            _sl_wrong = True
                            _wrong_reason = "TP≥entry(SHORT, anchor 옛가격)"
                    if _sl_wrong and _rnd_atr and _rnd_atr > 0:
                        # anchor=price 강제 + ATR 비율 유지 + SL 거리 min_sl_pct 보장
                        _tp_mult_f = float(getattr(self.config, "tf_round_tp_atr_mult", 1.0))
                        _tp2_mult_f = float(getattr(self.config, "tf_round_tp2_atr_mult", 2.0))
                        _sl_ratio_f = float(getattr(self.config, "tf_round_sl_ratio", 0.333)) or 0.333
                        _round1_f = _rnd_atr * _tp_mult_f
                        _round2_f = _rnd_atr * _tp2_mult_f
                        _sl_dist_atr = _round1_f * _sl_ratio_f
                        # SL 거리 = max(ATR×⅓, price×min_sl_pct) — 0.5% 최소 보장 (정상 시장 변동 흡수)
                        _sl_dist_min = price * _min_sl_chk
                        _sl_dist_f = max(_sl_dist_atr, _sl_dist_min)
                        if direction == "LONG":
                            _new_tp1 = price + _round1_f
                            _new_tp2 = price + _round2_f
                            _new_sl  = price - _sl_dist_f
                        else:
                            _new_tp1 = price - _round1_f
                            _new_tp2 = price - _round2_f
                            _new_sl  = price + _sl_dist_f
                        logger.warning("[FOCUS] ⛔ TF-round anchor 부적합 [%s] (%s entry=$%.4f orig: TP1=$%.4f TP2=$%.4f SL=$%.4f dist=%.3f%%) → anchor=price 재계산 (ATR=%.4f, SL_dist=$%.4f=max(ATR×⅓,price×%.3f%%)) → TP1=$%.4f TP2=$%.4f SL=$%.4f",
                                       _wrong_reason, direction, price, _tn_tp1, _tn_tp2, _tn_sl, _sl_dist_pct * 100, _rnd_atr, _sl_dist_f, _min_sl_chk * 100, _new_tp1, _new_tp2, _new_sl)
                        _tn_tp1, _tn_tp2, _tn_sl = _new_tp1, _new_tp2, _new_sl
                    targets.tp1, targets.tp2, targets.sl = _tn_tp1, _tn_tp2, _tn_sl
                    atr = _rnd_atr  # atr_used 기록 일치
                    logger.warning("[FOCUS] ★ TF-round TP/SL applied %s %s: TP1=$%.4f TP2=$%.4f SL=$%.4f",
                                   market, direction, targets.tp1, targets.tp2, targets.sl)
                else:
                    logger.warning("[FOCUS] TF-round TP/SL 계산 실패 → cycle_tp fallback (%s)", market)
            except Exception as _rexc:
                logger.warning("[FOCUS] TF-round TP/SL error → cycle_tp fallback: %s", _rexc)

        # ★★★ [2026-06-13 부모 "지금 고치자"] PARENT ROE GUARD 최종 floor 재적용 (거래소 전송 직전) ★★★
        #   버그: TF-round recompute(anchor부적합 시 SL=0.5% 최소, L17088)가 위 parent_roe_guard(L16582)가 넓힌
        #   SL을 *덮어씀* → INJ home 31초 churn(server-a은 anchor정상이라 미발동 = 같은 버그 다른 발현).
        #   "어떤 일 있어도 -31%까진 청산 안 됨" 절대 명령을 *마지막에* 보장. 좁을 때만 넓힘(넓은 SL은 보존).
        #   override 슬롯은 타이트 의도 → max_sl_cap 내로 제한해 회귀 방지.
        if getattr(self.config, "parent_roe_guard_enabled", True) and price > 0:
            try:
                _prf_cap = float(getattr(self.config, "parent_max_roe_loss_pct", 31.0))
                _prf_lev = max(1, int(getattr(self.config, "leverage", 5)))
                _prf_min_dist = price * (_prf_cap / _prf_lev / 100.0)
                _prf_max_pct = (float(getattr(self.config, "override_max_sl_distance_pct", 5.0))
                                if entry.get("_is_override", False)
                                else float(getattr(self.config, "max_sl_distance_pct", 99.0)))
                _prf_min_dist = min(_prf_min_dist, price * (_prf_max_pct / 100.0))   # cap 초과 금지
                _prf_cur = abs(price - targets.sl)
                if _prf_cur < _prf_min_dist - 1e-9:   # 너무 좁을 때만 floor 로 넓힘
                    _prf_old = targets.sl
                    targets.sl = (price - _prf_min_dist) if direction == "LONG" else (price + _prf_min_dist)
                    logger.warning("[FOCUS] ★★ PARENT ROE GUARD 최종 floor 재적용 (TF-round 덮어쓰기 방지): %s %s SL $%.4f→$%.4f (%.2f%%→%.2f%%)",
                                   market, direction, _prf_old, targets.sl, _prf_cur / price * 100, _prf_min_dist / price * 100)
            except Exception as _prfexc:
                logger.debug("[FOCUS] parent_roe 최종 floor error: %s", _prfexc)

        # Set server-side TP/SL safety net (3회 시도, 실패해도 포지션 유지 → tick에서 재시도)
        _tp_sl_set = False
        for _tp_attempt in range(3):
            try:
                client.set_trading_stop(market, take_profit=targets.tp2, stop_loss=targets.sl)
                logger.info("[FOCUS] TP/SL set on Bybit: TP=$%.2f SL=$%.2f (dir=%s)", targets.tp2, targets.sl, direction)
                _tp_sl_set = True
                break
            except Exception as exc:
                logger.warning("[FOCUS] set_trading_stop attempt %d/3 failed: %s", _tp_attempt + 1, exc)
                if _tp_attempt < 2:
                    import time as _sl_t; _sl_t.sleep(1)
        if not _tp_sl_set:
            # ★ TP/SL 실패해도 포지션 유지 — FOCUS 자체 SL 감시가 1차 안전망
            # 다음 tick의 _manage_all_positions에서 SL 체크 + _update_bybit_sl에서 재시도
            logger.warning("[FOCUS] TP/SL FAILED 3x for %s — position KEPT, will retry on next tick", market)
            self._notify(f"⚠️ {market} TP/SL 설정 실패 — FOCUS SL 감시로 보호 중, 다음 tick 재시도")

        # ── 장부 기록 (★ [2026-06-11] 체결 확인 후로 이동 — 실제 체결가/량/방향/leverage 반영) ──
        try:
            from app.manager.trade_journal import journal
            _modifiers = entry.get("_conviction_modifiers", "")
            _phase = f"conviction={conviction_score}"
            if _modifiers:
                _phase += f",{_modifiers}"
            if entry.get("preclose"):  # ★ [패치 v2-A] 성과 분리 측정의 생명선 — 태그 누락 금지
                _phase += ",preclose=1"
            # ★ Phase K (2026-04-21): regime_transition 태그 — EXIT 시 승률 분석용
            if entry.get("_phase_k"):
                _phase += f",phase_k={entry.get('_phase_k_reason','')}"
            # ★ [2026-05-27 부모] H4 / H1 어느 펄스로 통과했는지 — 빈도↑ 효과 검증용
            _pulse_via = entry.get("_pulse_via", "")
            if _pulse_via:
                _phase += f",pulse={_pulse_via}"
            # ★ [2026-05-27 부모] PA Completion: H4 OR H1 어느 TF 의 Pat 1/2/3 로 통과했는지
            _pa_via = entry.get("_pa_via", "")
            if _pa_via:
                _phase += f",pa={_pa_via}"
            # ★ [2026-05-27 부모] Phase 6 점수 통합 — guard_score 진입 여부 + 점수
            if entry.get("_guard_score_pass"):
                _gs = entry.get("_guard_score", 0)
                _phase += f",guard_score={_gs:.0f}"
            # ★ Anchor Fast-Track 도 같이 마킹 (microtiming 우회 진입 식별)
            if entry.get("_anchor_fasttrack"):
                _phase += ",fasttrack=1"
            journal.record_entry(
                strategy="FOCUS", market=market, direction=direction,
                price=_entry_price_actual, qty=_entry_qty_actual,  # ★ 실제 체결가/량 (주문전 추정 price/order_qty 대체)
                leverage=_pos_leverage,   # ★ [2026-06-11] 거래소 실제 leverage
                phase=_phase,
            )
        except Exception as exc:
            logger.debug("[FOCUS] journal.record_entry failed: %s", exc)

        # ★ [해결안 B] GateLedger — 진입 성사 = ENTRY pass (관측만, 진입 불침) — UI 토글
        if getattr(self, "_gate_ledger", None) is not None and self.config.gate_ledger_enabled:
            try:
                self._gate_ledger.record(market, "ENTRY", passed=True, direction=direction)
            except Exception:  # noqa: BLE001
                pass

        # Record position → multi-position list
        new_pos = FocusPosition(
            market=market,
            direction=direction,
            entry_price=_entry_price_actual,  # ★ [2026-06-11] 실제 체결가 (slippage 반영 → PnL/BE/SL 정확)
            qty=_entry_qty_actual,            # ★ [2026-06-11] 실제 체결량 (거래소 검증 size)
            leverage=_pos_leverage,           # ★ [2026-06-11] 거래소 실제 leverage (불일치 시 보정)
            tp1=targets.tp1,
            tp2=targets.tp2,
            sl=targets.sl,
            atr_used=atr,
            entry_ts=time.time(),
            conviction_score=conviction_score,
        )
        new_pos.entry_source = "scanner" if entry.get("_scanner_entry", False) else "primary"
        new_pos.original_sl = targets.sl      # Decay 원본 기준 (진입 시 고정)
        new_pos.original_tp1 = targets.tp1    # Decay 원본 기준 (진입 시 고정)
        # ★ Entry Expectation 결과 저장 (진행률 청산 기준 — 0 이면 미산정/비활성)
        # [2026-05-16 부모 BTC 사고 근본 fix] EE 가 좁은 H1 zone 잡으면 _exp_reward_target 좁음
        # → progress 계산 과장 (BTC -113% 사례). blend 후 최종 targets.tp2 (cycle_tp 큰 쪽 채택된
        # 값) 를 reward_target 으로 저장 = 진행률 계산이 진짜 목표 기준.
        # EE 가 산정 안 됐으면 (_exp_reward_target=0) cycle_tp targets.tp2 그대로 저장.
        new_pos.reward_target = targets.tp2 if targets.tp2 > 0 else _exp_reward_target
        new_pos.risk_invalidation = _exp_risk_invalidation
        new_pos.rr_ratio = _exp_rr_ratio
        new_pos.expectation_source = _exp_source
        # ★ Override Slot 마커 (2026-05-10): Hard ROE -10% 컷 발동 / 별도 룰 적용
        new_pos.is_override = bool(entry.get("_is_override", False))
        # [2026-05-29 부모] Slot Auto Expand 마커 전파 (청산까지 임시 슬롯 점유 표시)
        new_pos.is_slot_expand = bool(entry.get("_slot_expand", False))
        # ★ [패치 v2-A2] Pre-Close 마감 확인 증액 대기 마킹 (반 진입 → H4 마감 후 확인되면 나머지 반)
        new_pos.preclose_pending_topup = False
        new_pos.preclose_topup_qty = 0.0
        new_pos.preclose_entry_ts = 0.0
        if entry.get("preclose") and getattr(self.config, "preclose_topup_enabled", False):
            try:
                _pcr = float(entry.get("_preclose_ratio", 0.5) or 0.5)
                if 0.0 < _pcr < 1.0:
                    import time as _t_pc
                    new_pos.preclose_topup_qty = float(new_pos.qty) * (1.0 / _pcr - 1.0)
                    new_pos.preclose_entry_ts = _t_pc.time()
                    new_pos.preclose_pending_topup = new_pos.preclose_topup_qty > 0
                    logger.info("[FOCUS] ⏩ Pre-Close 증액 대기 등록: %s %s — 마감 확인 시 +qty=%.4f",
                                market, direction, new_pos.preclose_topup_qty)
            except Exception as _pcexc:
                logger.debug("[FOCUS] preclose topup 등록 error: %s", _pcexc)
        # ★ [2026-05-28 부모] guard_score 100점 체계 진입 OR 수동 진입 = 옛 EXIT 우회
        # 수동 진입 누락 사고 (5-28 DOGE 297s pre_be_stall):
        #   수동 진입은 entry["_guard_score_pass"] 가 set 안 됨 → 옛 EXIT 작동 → 4분 만에 컷.
        #   부모님 수동 진입 = 부모님 직감/판단 = 옛 시간기반 가드가 끼어들면 안 됨.
        _entry_is_manual = bool(entry.get("_manual"))
        new_pos.guard_score_entry = (
            bool(entry.get("_guard_score_pass", False)) or _entry_is_manual
        )
        if new_pos.guard_score_entry:
            _reason = "MANUAL" if _entry_is_manual else "GUARD_SCORE"
            logger.info(
                "[FOCUS] ★ %s ENTRY: %s %s — 옛 EXIT 가드(fast_reject/reverse_drift/"
                "pre_be_stall/long_hold/trend_reversal/quick_tp/bb_macd_sw/thesis_invalidation) 모두 우회",
                _reason, market, direction,
            )
        if new_pos.is_override:
            logger.warning(
                "[FOCUS] ★ OVERRIDE SLOT entered: %s %s conviction=%d adx=%.1f size=$%.2f sl=$%.4f",
                market, direction, conviction_score, float(entry.get("adx", 0) or 0),
                effective_budget, targets.sl,
            )
        # ── ★ [2026-05-21 Phase 6 Stage 8 재재설계] 진입 시점 baseline 저장 ──
        # 부모님 진짜 룰: "이윤 + 점수 회복 기미 → 소액 청산". 기존 가드 그대로.
        try:
            new_pos.entry_baseline_conv = float(self._last_scan_conviction.get(market, 0.0) or 0.0)
            _hist_b = self._confidence_history.get(market)
            if _hist_b and len(_hist_b) > 0:
                new_pos.entry_baseline_trend = str(_hist_b[-1][1])
            logger.info("[FOCUS] Stage 8 baseline %s %s: conv=%.1f trend=%s (점수 회복 청산 기준)",
                        market, direction, new_pos.entry_baseline_conv, new_pos.entry_baseline_trend or "(unknown)")
        except Exception as exc:
            logger.debug("[FOCUS] Stage 8 baseline save error %s: %s", market, exc)

        self.positions.append(new_pos)
        self.position = new_pos  # legacy 호환
        self.daily_plans_used += 1
        if entry.get("preclose"):  # ★ [패치 v2-A] 선행 진입 일일 카운터 (체결 시 증가)
            self.preclose_used_today = getattr(self, "preclose_used_today", 0) + 1
        self._entry_fail_count = 0
        self.state = FocusState.POSITIONED
        self._save_config()

        # Phase C-2 (2026-04-20): WebSocket push — UI 실시간 갱신. fire-and-forget, 거래 path 무영향.
        try:
            from app.api.websocket_router import state_broadcast_safe
            state_broadcast_safe("POSITION_OPEN", {
                "market": market, "direction": direction,
                "entry_price": price, "qty": order_qty,
                "conviction": conviction_score,
            })
        except Exception:
            pass

        logger.info("[FOCUS] POSITIONED %s %s @ %.2f | TP1=%.2f TP2=%.2f SL=%.2f [%d/%d slots]",
                     direction, market, price, targets.tp1, targets.tp2, targets.sl,
                     len(self.positions), self.config.max_positions)
        try:
            self.system.ledger.append(
                "FOCUS_ENTRY", market=market,
                direction=direction, qty=order_qty, entry_price=price,
                tp1=targets.tp1, tp2=targets.tp2, sl=targets.sl,
                leverage=_dyn_lev, conviction=conviction_score,   # ★ [2026-04-25] dynamic lev
                budget_usdt=effective_budget,
            )
        except Exception as exc:
            logger.debug("[FOCUS] self.system.ledger.append failed: %s", exc)
        self._notify(f"🟢 ENTRY {direction} {market}\n@ ${price:.2f} qty={order_qty}\nTP1=${targets.tp1:.2f} SL=${targets.sl:.2f}\nConviction: {conviction_score:.1f}/100 Budget: ${effective_budget:.0f}")
        return {"state": "POSITIONED", "market": market, "direction": direction, "entry": price,
                "positions": len(self.positions)}

    def _execute_partial(self, partial, price: float) -> Dict:
        """Execute TP1 partial exit."""
        pos = self.position
        close_qty = pos.qty * (partial.exit_pct / 100.0)

        client = self._get_client()
        try:
            side = "Sell" if pos.direction == "LONG" else "Buy"
            client.place_order(market=pos.market, side=side, ord_type="market", volume=close_qty)
            logger.info("[FOCUS] Partial exit %.0f%% @ %.2f", partial.exit_pct, price)
            try:
                self.system.ledger.append(
                    "FOCUS_PARTIAL", market=pos.market,
                    direction=pos.direction, qty=close_qty,
                    exit_pct=partial.exit_pct, price=price,
                    entry_price=pos.entry_price,
                    conviction=pos.conviction_score,
                )
            except Exception as exc:
                logger.debug("[FOCUS] self.system.ledger.append failed: %s", exc)
        except Exception as exc:
            logger.error("[FOCUS] Partial exit FAILED: %s", exc, exc_info=True)
            return {"state": "POSITIONED", "error": f"partial_failed: {exc}"}

        # Update position
        pos.partial_done = True
        pos.qty -= close_qty
        pos.sl = partial.new_sl  # Move SL to breakeven
        if pos.direction == "LONG":
            pos.trailing_high = price
        else:
            pos.trailing_low = price

        # Update server TP/SL
        try:
            client.set_trading_stop(pos.market, take_profit=pos.tp2, stop_loss=pos.sl)
        except Exception as exc:
            logger.warning("[FOCUS] update trading_stop after partial: %s", exc)

        # v2: TRAILING 상태 제거 — POSITIONED가 DT를 담당
        self._save_config()
        logger.info("[FOCUS] TP1 partial done — DT handles trailing (SL breakeven %.2f)", pos.sl)
        return {"state": "POSITIONED", "partial_pct": partial.exit_pct}

    def _execute_exit(self, reason: str, is_sl: bool = False) -> Dict:
        """Close remaining position(s) fully.
        ★ H8 FIX: multi-position 대응 — 모든 열린 포지션 순회 청산."""
        # multi-position: 모든 포지션 수집
        targets = list(self.positions) if self.positions else []
        if not targets and self.position:
            targets = [self.position]
        if not targets:
            self.state = FocusState.COOLDOWN
            self.cooldown_start_ts = time.time()
            self._save_config()
            return {"state": "COOLDOWN", "reason": reason}

        client = self._get_client()
        _failed = []  # ★ [2026-06-11] cowork ② — 청산 실패 포지션은 보존(다음 tick 재시도, 유령 방지)
        for pos in targets:
            try:
                side = "Sell" if pos.direction == "LONG" else "Buy"
                # ★ [2026-06-11] reduce_only=True — 청산 의도가 반대 신규진입 되는 사고 방지(_close_position 과 일관)
                order = client.place_order(market=pos.market, side=side, ord_type="market",
                                           volume=pos.qty, reduce_only=True)
                # ★ [2026-06-11] cowork ① — 실제 체결 확인. 미체결이면 성공으로 간주하지 않음.
                _fp, _fq, _ost, _isf = self._extract_fill(order, fallback_price=pos.entry_price, fallback_qty=pos.qty)
                if self._is_live_mode() and not _isf:
                    logger.error("[FOCUS] Full exit 미체결 %s (state=%s qty=%s) — 포지션 보존", pos.market, _ost, _fq)
                    _failed.append(pos)
                    continue
                logger.info("[FOCUS] Full exit %s %s %.6f: %s (state=%s)", pos.direction, pos.market, pos.qty, reason, _ost)
                try:
                    self.system.ledger.append(
                        "FOCUS_EXIT", market=pos.market,
                        direction=pos.direction, qty=pos.qty,
                        entry_price=pos.entry_price, reason=reason,
                        is_sl=is_sl, conviction=pos.conviction_score,
                    )
                except Exception as exc:
                    logger.debug("[FOCUS] self.system.ledger.append failed: %s", exc)
            except Exception as exc:
                exc_str = str(exc)
                # ★ 110017 = position is zero → 서버에서 이미 청산됨 = 성공 (보존 X)
                if "110017" in exc_str or "position is zero" in exc_str.lower():
                    logger.info("[FOCUS] Full exit %s: 서버에서 이미 청산됨(110017) — 성공 처리", pos.market)
                else:
                    logger.error("[FOCUS] Full exit FAILED %s: %s — 포지션 보존, 다음 tick 재시도", pos.market, exc, exc_info=True)
                    _failed.append(pos)

        if is_sl:
            self.daily_sl_count += 1
            logger.info("[FOCUS] SL count: %d/%d", self.daily_sl_count, self.config.max_daily_sl)

        # ★ [2026-06-11] cowork ② — 청산 실패분이 있으면 보존하고 COOLDOWN 진입 안 함(유령 desync 방지).
        if _failed:
            self.positions = _failed
            self.position = _failed[0]
            logger.critical("[FOCUS] _execute_exit: %d/%d 청산 실패 — 보존, POSITIONED 유지(다음 tick 재시도)",
                            len(_failed), len(targets))
            self._save_config()
            return {"state": "POSITIONED", "reason": reason, "is_sl": is_sl,
                    "closed": len(targets) - len(_failed), "exit_failed": len(_failed)}

        # 전부 정리 (모두 성공)
        self.positions.clear()
        self.position = None
        self.selected_market = ""
        self.selected_direction = ""
        self.primary_sig = None
        self.cooldown_start_ts = time.time()
        self.state = FocusState.COOLDOWN
        self._save_config()

        return {"state": "COOLDOWN", "reason": reason, "is_sl": is_sl, "closed": len(targets)}

    # ── Regime Scaling (기존 인프라 재활용) ──────────────────

    def _apply_regime_scaling(self, market: str, price: float, targets) -> object:
        """레짐 배율 + 수수료 인식으로 TP/SL 조정.

        strategy_tp_sl_policy.json의 regime_tp/sl_multiplier 사용.
        기존 엔진(hyper_nunnaya_engine.py:600-642)과 동일 로직.
        """
        try:
            import json as _json

            # 1. 정책 파일 로드 (캐시)
            policy = getattr(self, "_tp_sl_policy_cache", None)
            if policy is None:
                with open("runtime/strategy_tp_sl_policy.json", "r", encoding="utf-8") as f:
                    policy = _json.load(f)
                self._tp_sl_policy_cache = policy

            if not policy.get("enabled"):
                return targets

            # 2. 레짐 감지
            from app.core.market_regime import RegimeDetector
            det = getattr(self, "_regime_detector", None)
            if det is None:
                det = RegimeDetector()
                self._regime_detector = det

            regime_result = det.detect("BTCUSDT")
            regime = str(getattr(regime_result, "regime", "SIDEWAYS")).upper()
            # enum에서 값 추출
            if "." in regime:
                regime = regime.split(".")[-1]

            # 3. 레짐 배율 적용
            tp_mults = policy.get("regime_tp_multiplier", {})
            sl_mults = policy.get("regime_sl_multiplier", {})
            tp_mult = float(tp_mults.get(regime, 1.0))
            sl_mult = float(sl_mults.get(regime, 1.0))

            direction = targets.direction
            old_tp1, old_tp2, old_sl = targets.tp1, targets.tp2, targets.sl

            if direction == "LONG":
                tp1_dist = (targets.tp1 - price) * tp_mult
                tp2_dist = (targets.tp2 - price) * tp_mult
                sl_dist = (price - targets.sl) * sl_mult
                targets.tp1 = round(price + tp1_dist, 8)
                targets.tp2 = round(price + tp2_dist, 8)
                targets.sl = round(price - sl_dist, 8)
            else:  # SHORT
                tp1_dist = (price - targets.tp1) * tp_mult
                tp2_dist = (price - targets.tp2) * tp_mult
                sl_dist = (targets.sl - price) * sl_mult
                targets.tp1 = round(price - tp1_dist, 8)
                targets.tp2 = round(price - tp2_dist, 8)
                targets.sl = round(price + sl_dist, 8)

            # 4. 수수료 인식: TP가 왕복 수수료보다 낮으면 방지
            if policy.get("fee_aware_tp"):
                fee_rate = float(policy.get("fee_rate", 0.00055))
                spread_bps = 0.0
                try:
                    from app.core.hyper_price_store import orderbook_store
                    ob = orderbook_store.get(market)
                    if ob:
                        bid = float(ob.get("best_bid", 0) or 0)
                        ask = float(ob.get("best_ask", 0) or 0)
                        if bid > 0 and ask > 0:
                            spread_bps = (ask - bid) / bid * 10000
                except Exception as exc:
                    logger.debug("[FOCUS] import orderbook_store failed: %s", exc)
                fee_cost_pct = (fee_rate * 2 + spread_bps / 10000) * 100
                min_tp_dist = price * fee_cost_pct * 1.2 / 100
                if direction == "LONG" and (targets.tp1 - price) < min_tp_dist:
                    targets.tp1 = round(price + min_tp_dist, 8)
                elif direction == "SHORT" and (price - targets.tp1) < min_tp_dist:
                    targets.tp1 = round(price - min_tp_dist, 8)

            if tp_mult != 1.0 or sl_mult != 1.0:
                logger.info("[FOCUS] Regime %s: TP×%.1f SL×%.1f | TP1: %.4f→%.4f TP2: %.4f→%.4f SL: %.4f→%.4f",
                            regime, tp_mult, sl_mult,
                            old_tp1, targets.tp1, old_tp2, targets.tp2, old_sl, targets.sl)

        except Exception as exc:
            logger.debug("[FOCUS] regime scaling skipped: %s", exc)

        return targets

    def _notify(self, message: str):
        """텔레그램 알림 (비차단)."""
        try:
            from app.notify.telegram import send_telegram
            send_telegram(f"[FOCUS] {message}")
        except Exception as exc:
            logger.debug("[FOCUS] import send_telegram failed: %s", exc)

    def _get_price_history(self, market: str, count: int = 60) -> list:
        """M5 kline close 가격 히스토리."""
        try:
            raw = self._get_client().get_kline(market, interval="5", limit=count)
            return [float(r[4]) for r in raw if len(r) >= 5]
        except Exception as exc:
            logger.debug("[FOCUS] raw failed (fallback): %s", exc)
            return []

    # ── Helpers ─────────────────────────────────────────────

    def _get_current_price(self, market: str) -> Optional[float]:
        """Get current price from price_store or API.
        price_store 캐시가 60초 이상 오래됐으면 stale로 간주, API fallback 사용.
        """
        try:
            from app.core.hyper_price_store import price_store
            p = price_store.get_price(market, max_age_sec=60.0)
            if p and p > 0:
                return float(p)
        except Exception as exc:
            logger.debug("[FOCUS] price_store.get_price(%s) failed: %s", market, exc)
        # Fallback: Bybit API
        try:
            p = self._get_client()._linear_last_price(market)
            if p and p > 0:
                return float(p)
        except Exception as exc:
            logger.warning("[FOCUS] _linear_last_price(%s) failed: %s", market, exc)
        return None

    def _maybe_reset_daily_counters(self):
        """Reset daily plan/SL counters at 07:00 KST (22:00 UTC)."""
        import datetime
        # ★ H11 FIX: utcnow() deprecated → now(UTC) 사용
        now_utc = datetime.datetime.now(datetime.timezone.utc)
        # KST = UTC+9, so 07:00 KST = 22:00 UTC previous day
        reset_hour_utc = 22
        today_reset = now_utc.replace(hour=reset_hour_utc, minute=0, second=0, microsecond=0)
        if now_utc.hour < reset_hour_utc:
            today_reset -= datetime.timedelta(days=1)

        reset_ts = today_reset.timestamp()
        if self.daily_reset_ts < reset_ts:
            # ★ 리셋 전에 어제 스냅샷 저장
            try:
                from app.manager.focus_daily_snapshot import build_snapshot, save_snapshot
                from app.manager.trade_journal import JOURNAL_PATH
                import json as _json2
                prev_reset = today_reset - datetime.timedelta(days=1)
                exits = []
                if os.path.exists(JOURNAL_PATH):
                    with open(JOURNAL_PATH, "r", encoding="utf-8") as _f:
                        for _line in _f:
                            _line = _line.strip()
                            if not _line:
                                continue
                            try:
                                _rec = _json2.loads(_line)
                                if _rec.get("event") == "EXIT":
                                    exits.append(_rec)
                            except _json2.JSONDecodeError:
                                continue
                # Bybit 잔고 조회 (ROI% 계산용)
                _equity = self._get_available_margin() or 0
                snap = build_snapshot(exits, prev_reset.timestamp(), reset_ts, asdict(self.config), equity_start=_equity)
                if snap.get("total_trades", 0) > 0:
                    save_snapshot(snap)
            except Exception as exc:
                logger.warning("[FOCUS] Daily snapshot save failed: %s", exc)

            self.daily_plans_used = 0
            self.daily_sl_count = 0
            self.preclose_used_today = 0   # ★ [패치 v2-A] 선행 진입 카운터 일일 리셋
            self.daily_reset_ts = reset_ts
            logger.info("[FOCUS] Daily counters reset")

            # ★ Phase G (2026-04-20 형 Claude 진단): DrawdownShield daily_peak_pnl 고착 버그 수정
            # reset_daily()가 정의되어 있으나 호출부 누락 → daily_peak_pnl이 영원히 안 풀림
            # → 시장 좋아져도 -3 페널티 깔려 scanner 침묵 (오늘 실제 PnL +$2 인데 dd $182 CRISIS)
            try:
                from app.manager.drawdown_shield import drawdown_shield
                drawdown_shield.reset_daily()
            except Exception as _dse:
                logger.warning("[FOCUS] drawdown_shield.reset_daily failed: %s", _dse)

            # ★ Daily reset 시 Coin Report Card 자동 갱신
            try:
                from app.manager.coin_report_card import CoinReportCard
                _crc = CoinReportCard()
                _crc.refresh()
                self._last_coin_grade_refresh_ts = time.time()
                logger.info("[FOCUS] Coin Report Card refreshed at daily reset")
            except Exception as _cre:
                logger.warning("[FOCUS] Coin Report Card refresh failed: %s", _cre)

    # ── Today PnL ────────────────────────────────────────────

    def _calc_today_pnl(self) -> float:
        """오늘 07:00 KST 이후 실현 PnL 합산. 캐시 30초."""
        now = time.time()
        if hasattr(self, '_today_pnl_cache') and now - self._today_pnl_cache_ts < 30:
            return self._today_pnl_cache
        try:
            from app.manager.trade_journal import journal
            import datetime as _dt
            now_utc = _dt.datetime.now(_dt.timezone.utc)
            reset_hour_utc = 22  # 07:00 KST = 22:00 UTC (prev day)
            today_reset = now_utc.replace(hour=reset_hour_utc, minute=0, second=0, microsecond=0)
            if now_utc.hour < reset_hour_utc:
                today_reset -= _dt.timedelta(days=1)
            reset_ts = today_reset.timestamp()

            # ★ [2026-06-05] dashboard freeze fix — 47MB 저널 풀파싱 → 인메모리 캐시(write-through)
            #   순회로 교체 (b12 와 동일 패턴, feedback_journal_cache_leak_fix). 30초 result 캐시는 유지.
            total = 0.0
            journal._ensure_cache()
            for rec in journal._cache:
                try:
                    if rec.get("event") != "EXIT":
                        continue
                    if rec.get("ts", 0) < reset_ts:
                        continue
                    total += rec.get("pnl_net", 0) or 0
                except (KeyError, TypeError, ValueError):
                    continue
            self._today_pnl_cache = total
            self._today_pnl_cache_ts = now
            return total
        except Exception as exc:
            logger.debug("[FOCUS] rec failed (fallback): %s", exc)
            return 0.0

    # ── Persistence ─────────────────────────────────────────

    def _save_config(self):
        """Save config + state to runtime/focus_config.json."""
        data = {
            "config": asdict(self.config),
            "state": {
                "focus_state": self.state.value,
                "selected_market": self.selected_market,
                "selected_direction": self.selected_direction,
                "position": asdict(self.position) if self.position else None,
                "positions": [asdict(p) for p in self.positions],
                "zones": self.zones,
                "primary_sig": self.primary_sig,
                "daily_plans_used": self.daily_plans_used,
                "daily_sl_count": self.daily_sl_count,
                "daily_reset_ts": self.daily_reset_ts,
                "last_scan_ts": self.last_scan_ts,
                "cooldown_start_ts": self.cooldown_start_ts,
                # v2: 재진입 차단 상태
                "last_exit_direction": self._last_exit_direction,
                "last_exit_price": self._last_exit_price,
                "last_exit_ts": self._last_exit_ts,
                "last_exit_market": self._last_exit_market,
                # v2: ADX 캐시 (재시작 후에도 유지)
                "last_adx_value": round(self._last_adx_value, 2),
                "last_adx_ts": self._last_adx_ts,
                # ★ 수동 퇴장 페널티 (재시작 생존)
                "manual_exit_penalties": {k: v for k, v in self._manual_exit_penalties.items() if v > time.time()},
                # ★ [2026-05-11 부모님 사고 수정 — 자녀 2번째 누락] AMNESTY 시각 재시작 생존
                #   _save_config 가 amnesty_ts 저장 안 했음 → 재시작 시 _amnesty_ts=0 → consec_pause 재발동
                "amnesty_ts": self._amnesty_ts,
            },
        }
        # ★ 2026-05-10 부모님 옵션 B: WinError 5 race 일시 실패 → 3회 retry + 점진 sleep 자동 회복
        # 5-10 측정 결과 시간당 10회 발생 — race 자체는 지속, retry 로 대부분 회복 기대
        try:
            from app.core.io_utils import safe_write_json
        except ImportError as exc:
            logger.error("[FOCUS] safe_write_json import failed: %s", exc)
            return
        _last_exc = None
        _MAX_RETRY = 5   # 2026-06-06: 3→5. WinError 5 race 가 3회로 못 잡은 잔여(server-a 관측) 보강.
        for _attempt in range(_MAX_RETRY):
            try:
                safe_write_json(CONFIG_PATH, data)
                if _attempt > 0:
                    logger.debug("[FOCUS] save config recovered on retry #%d", _attempt + 1)
                return
            except OSError as exc:
                _last_exc = exc
                if _attempt < _MAX_RETRY - 1:
                    time.sleep(0.05 * (_attempt + 1))   # 50→100→150→200ms 점진 백오프
            except Exception as exc:
                logger.warning("[FOCUS] save config unexpected exception: %s", exc)
                return
        logger.warning("[FOCUS] save config failed (%d retries): %s", _MAX_RETRY, _last_exc)

    def _load_config(self):
        """Load config + state from runtime/focus_config.json."""
        if not os.path.exists(CONFIG_PATH):
            return
        try:
            with open(CONFIG_PATH, "r", encoding="utf-8") as f:
                data = json.load(f)

            # Config — ★ M19 FIX: bool 필드 특별 처리 (bool("false")==True 방지)
            cfg = data.get("config", {})
            for k, v in cfg.items():
                if hasattr(self.config, k):
                    cur = getattr(self.config, k)
                    if isinstance(cur, bool):
                        setattr(self.config, k, v if isinstance(v, bool) else str(v).lower() in ("true", "1", "yes"))
                    else:
                        try:
                            setattr(self.config, k, type(cur)(v))
                        except (TypeError, ValueError):
                            pass

            # [2026-05-17 100점 체계 — 부모님 정정: "호환 X, 교체"]
            # 호환 로직 제거. 옛 config 자체 무효 — 부모님이 운영 전 runtime/focus_config.json
            # *수동 삭제* 후 봇 시작 → dataclass default (처음부터 100점 단위) 자동 적용.
            # 이후 dashboard 에서 원하는 값 직접 입력.

            # ── config_version 마이그레이션 (2026-06-20 신설, spot 패턴 미러) ──
            #   옛 runtime 엔 config_version 없음(=0). 각 버전서 *새로 바뀐 기본값만* 1회 강제 적용 후 버전 올림.
            #   → 새 안전 기본값이 재시작 시 자동 적용되되, 이후 부모님이 UI 로 바꾼 값은 보존(재발동 안 함).
            #   ★ 부모님 요구(2026-06-20): "재시작 시 기본 동작 + 변경값은 저장·유지 + 기본값설정=내 기본값".
            _loaded_ver = int(cfg.get("config_version", 0) or 0)
            _cur_ver = FocusConfig().config_version
            if _loaded_ver < _cur_ver:
                _d = FocusConfig()
                _bump: list = []
                if _loaded_ver < 1:   # v1 (2026-06-20): 청산 누수 fix 안전 기본값
                    _bump += ["sl_decay_enabled", "charge_exit_enabled", "be_lock_smart_defer_giveback_pct"]
                for _k in _bump:
                    setattr(self.config, _k, getattr(_d, _k))
                self.config.config_version = _cur_ver
                self._config_dirty = True   # 첫 tick flush(L4255~) 에서 영속 → 버전 박혀 재발동 방지
                logger.info("[FOCUS] config v%d→v%d 마이그레이션 — 새 기본값 1회 강제: %s",
                            _loaded_ver, _cur_ver, ", ".join(_bump) or "(none)")

            # State — v2: 마이그레이션 맵 적용
            st = data.get("state", {})
            raw_state = st.get("focus_state", "DORMANT")
            migrated_state = _STATE_MIGRATION.get(raw_state, raw_state)
            try:
                self.state = FocusState(migrated_state)
            except ValueError:
                logger.warning("[FOCUS] Unknown state '%s' → DORMANT", migrated_state)
                self.state = FocusState.DORMANT
            if raw_state != migrated_state:
                logger.info("[FOCUS] State migrated: %s → %s", raw_state, migrated_state)
            self.selected_market = st.get("selected_market", "")
            self.selected_direction = st.get("selected_direction", "")
            self.zones = st.get("zones", [])
            self.primary_sig = st.get("primary_sig") or st.get("h4_sig")  # [2026-05-15] 구 state 호환
            self.daily_plans_used = int(st.get("daily_plans_used", 0))
            self.daily_sl_count = int(st.get("daily_sl_count", 0))
            self.daily_reset_ts = float(st.get("daily_reset_ts", 0))
            self.last_scan_ts = 0  # [2026-04-09] 재시작 후 즉시 첫 스캔
            self.cooldown_start_ts = float(st.get("cooldown_start_ts", 0))
            # v2: 재진입 차단 상태 복원
            self._last_exit_direction = st.get("last_exit_direction", "")
            self._last_exit_price = float(st.get("last_exit_price", 0))
            self._last_exit_ts = float(st.get("last_exit_ts", 0))
            self._last_exit_market = st.get("last_exit_market", "")
            # ★ [2026-05-11 부모님 AMNESTY 영속화 누락 수정] 재시작 시 _amnesty_ts 복원
            #   미복원 시 재시작 후 사면 효과 사라짐 (consecutive_loss_pause 다시 적용 등)
            self._amnesty_ts = float(st.get("amnesty_ts", 0) or 0)
            # v2: ADX 캐시 복원 — 값이 없거나 10분 이상 지나면 즉시 재계산
            self._last_adx_value = float(st.get("last_adx_value") or 0)
            self._last_adx_ts = float(st.get("last_adx_ts") or 0)
            if self._last_adx_value <= 0 or (time.time() - self._last_adx_ts > 600):
                # 캐시 만료 → 첫 tick에서 즉시 fetch되도록 ts 초기화
                self._last_adx_ts = 0
            # ★ Phase D-2 (2026-04-20): B11 regime state 복원 — 재시작 후 freeze 유지
            try:
                if os.path.exists(B11_STATE_PATH):
                    with open(B11_STATE_PATH, "r", encoding="utf-8") as bf:
                        b11_data = json.load(bf)
                    regime_loaded = b11_data.get("regime", "")
                    ts_loaded = float(b11_data.get("change_ts", 0))
                    if regime_loaded:
                        self._b11_regime_state = (regime_loaded, ts_loaded)
                        elapsed_min = (time.time() - ts_loaded) / 60
                        logger.info("[FOCUS] B11 regime state restored: %s (last change %.1fm ago)", regime_loaded, elapsed_min)
            except Exception as exc:
                logger.warning("[FOCUS] B11 state load failed: %s", exc)

            # ★ 수동 퇴장 페널티 복원 (만료된 것 자동 제거)
            now = time.time()
            raw_penalties = st.get("manual_exit_penalties", {})
            # ★ Phase H (형 letter#3 A-7): per-item try/except — 잘못된 1건이 전체 차단 막지 않도록
            self._manual_exit_penalties = {}
            for k, v in raw_penalties.items():
                try:
                    _exp = float(v)
                    if _exp > now:
                        self._manual_exit_penalties[k] = _exp
                except (TypeError, ValueError) as _mpe:
                    logger.warning("[FOCUS] manual_exit_penalty bad value %s=%r — skipping: %s", k, v, _mpe)
            if self._manual_exit_penalties:
                for mk, exp in self._manual_exit_penalties.items():
                    logger.info("[FOCUS] Manual penalty restored: %s (%.1fh remaining)", mk, (exp - now) / 3600)

            # Position
            # Restore positions (multi)
            self.positions = []
            positions_data = st.get("positions", [])
            for pd in (positions_data or []):
                if isinstance(pd, dict) and pd.get("market"):
                    _restored_pos = FocusPosition(**{
                        k: v for k, v in pd.items() if k in FocusPosition.__dataclass_fields__
                    })
                    # ★ [2026-05-28 부모] OFF→ON 청산 사고 fix:
                    #   옛 state 에 guard_score_entry 필드 없으면 True 로 보장
                    #   (재시작 시 옛 EXIT 가드가 묶여있던 포지션 강제청산 막음).
                    if "guard_score_entry" not in pd:
                        _restored_pos.guard_score_entry = True
                    self.positions.append(_restored_pos)

            # Legacy single position fallback
            pos_data = st.get("position")
            if pos_data and isinstance(pos_data, dict) and pos_data.get("market"):
                legacy = FocusPosition(**{
                    k: v for k, v in pos_data.items() if k in FocusPosition.__dataclass_fields__
                })
                # ★ [2026-05-28 부모] 같은 fix — legacy 도 보호
                if "guard_score_entry" not in pos_data:
                    legacy.guard_score_entry = True
                if not any(p.market == legacy.market for p in self.positions):
                    self.positions.append(legacy)
            self.position = self.positions[0] if self.positions else None

            # ★ TP/SL 건전성 검증 — 깨진 SL이 재시작 후에도 유지되는 것 방지
            # ★ breakeven_locked 또는 partial_done 시 SL=진입가는 정상
            for pos in self.positions:
                sl_at_or_past_entry = False
                if pos.direction == "LONG" and pos.sl >= pos.entry_price:
                    sl_at_or_past_entry = True
                elif pos.direction == "SHORT" and pos.sl <= pos.entry_price:
                    sl_at_or_past_entry = True

                if sl_at_or_past_entry:
                    if pos.breakeven_locked or pos.partial_done:
                        # Dynamic trailing 또는 TP1 부분청산으로 SL이 진입가 이상 → 정상
                        logger.info("[FOCUS] SL at/past entry OK (breakeven_locked=%s partial=%s): %s %s SL=$%.2f entry=$%.2f",
                                    pos.breakeven_locked, pos.partial_done, pos.direction, pos.market, pos.sl, pos.entry_price)
                    else:
                        logger.error("[FOCUS] INVALID SL on load: %s %s entry=$%.2f SL=$%.2f → recalc",
                                     pos.direction, pos.market, pos.entry_price, pos.sl)
                        if pos.direction == "LONG":
                            pos.sl = pos.entry_price * 0.99
                        else:
                            pos.sl = pos.entry_price * 1.01

            logger.info("[FOCUS] Config loaded: state=%s market=%s positions=%d enabled=%s",
                       self.state.value, self.selected_market, len(self.positions), self.config.enabled)
        except (OSError, json.JSONDecodeError, ValueError) as exc:
            logger.warning("[FOCUS] load config failed: %s", exc)

    def _live_sync_positions(self):
        """★ 운영 중 60초마다 Bybit 실잔고 확인 — 고스트 제거 + 역방향 복구."""
        # ★ [2026-05-25 부모] paper/dry 모드: 실거래소 동기화 불필요 — 가상 포지션을
        #   ghost 로 오인해 제거하는 사고 방지. paper 청산은 _manage_all_positions 가 담당.
        if not self._is_live_mode():
            return
        try:
            client = self._get_client()
            from app.core.constants import BYBIT_POSITION_LIST
            resp = client._request("GET", BYBIT_POSITION_LIST,
                                   params={"category": "linear", "settleCoin": "USDT"})
            bybit_list = resp.get("list", []) if isinstance(resp, dict) else []
            # Bybit에 실제 포지션 있는 심볼 셋
            bybit_alive = set()
            for bp in bybit_list:
                if float(bp.get("size", 0)) > 0:
                    bybit_alive.add(bp.get("symbol", "").upper())

            # 로컬에 있지만 Bybit에 없는 = 고스트
            # ★ DOUBLE-LOG FIX: _close_position 진행 중인 마켓은 제외 (레이스 시 0.3s 창에서 고스트 오판 방지).
            ghosts = [
                p for p in self.positions
                if p.market.upper() not in bybit_alive
                and p.market.upper() not in self._closing_markets
            ]
            for ghost in ghosts:
                logger.warning("[FOCUS] LIVE SYNC: %s gone from Bybit — server-side SL/TP fired", ghost.market)
                # 장부 기록
                try:
                    from app.manager.trade_journal import journal
                    _price = self._get_current_price(ghost.market) or ghost.entry_price
                    _hold = (time.time() - ghost.entry_ts) if ghost.entry_ts > 0 else 0
                    # SL/TP 판별
                    _reason = "SERVER_SIDE_CLOSED"
                    if ghost.sl and _price > 0:
                        if ghost.direction == "LONG" and _price <= ghost.sl * 1.005:
                            _reason = "SERVER_SL"
                        elif ghost.direction == "SHORT" and _price >= ghost.sl * 0.995:
                            _reason = "SERVER_SL"
                    if ghost.tp1 and _price > 0:
                        if ghost.direction == "LONG" and _price >= ghost.tp1 * 0.995:
                            _reason = "SERVER_TP"
                        elif ghost.direction == "SHORT" and _price <= ghost.tp1 * 1.005:
                            _reason = "SERVER_TP"
                    is_sl = "SL" in _reason
                    if is_sl:
                        self.daily_sl_count += 1
                    journal.record_exit(
                        strategy="FOCUS", market=ghost.market, direction=ghost.direction,
                        entry_price=ghost.entry_price, exit_price=_price, qty=ghost.qty,
                        reason=_reason, leverage=ghost.leverage, hold_sec=_hold,
                        phase=f"conviction={ghost.conviction_score}",
                        dynamic_trailing=self.config.dynamic_trailing,
                        breakeven_locked=ghost.breakeven_locked,
                    )
                except Exception as exc:
                    logger.warning("[FOCUS] journal.record_exit failed (ghost %s): %s", ghost.market, exc)
                self._last_exit_direction = ghost.direction
                self._last_exit_price = self._get_current_price(ghost.market) or ghost.entry_price
                self._last_exit_ts = time.time()
                self._last_exit_market = ghost.market
                self._notify(f"👻 GHOST DETECTED: {ghost.market} {ghost.direction}\nBybit SL/TP fired — removed from tracking\nreason={_reason}")

            if ghosts:
                self.positions = [p for p in self.positions if p.market.upper() in bybit_alive]
                self.position = self.positions[0] if self.positions else None
                if not self.positions and self.state in (FocusState.POSITIONED, FocusState.CAUTION):
                    self.cooldown_start_ts = time.time()
                    self.state = FocusState.COOLDOWN
                self._save_config()
                logger.info("[FOCUS] LIVE SYNC: %d ghost(s) removed, %d remaining", len(ghosts), len(self.positions))

            # ★ 역방향 복구: Bybit에 있지만 로컬에 없는 포지션 복원
            local_markets = {p.market.upper() for p in self.positions}
            for bp in bybit_list:
                sym = bp.get("symbol", "").upper()
                sz = float(bp.get("size", 0))
                if sz > 0 and sym not in local_markets:
                    # ★ cross-strategy guard: 다른 전략(SNIPER 등) 소유면 복원 금지
                    try:
                        from app.core.cross_strategy_guard import is_market_owned_by_other
                        _other = is_market_owned_by_other(self.system, sym, "FOCUS")
                        if _other:
                            logger.info("[FOCUS] LIVE SYNC SKIP: %s owned by %s — not restoring", sym, _other.owner)
                            continue
                    except Exception as exc:
                        logger.debug("[FOCUS] import is_market_owned_by_other failed: %s", exc)
                    direction = "LONG" if bp.get("side") == "Buy" else "SHORT"
                    entry_price = float(bp.get("avgPrice", 0) or 0)
                    atr = entry_price * 0.015  # 추정치
                    try:
                        from app.strategy.greenpen.cycle_tp import compute_cycle_targets
                        _min_tp_pct_3 = float(getattr(self.config, "min_tp_distance_pct", 0.30)) \
                            if getattr(self.config, "min_tp_distance_enabled", False) else 0.0
                        targets = compute_cycle_targets(
                            entry_price, direction, atr,
                            tp1_mult=self.config.cycle_tp1_mult,
                            tp2_mult=self.config.cycle_tp2_mult,
                            sl_mult=self.config.cycle_sl_mult,
                            min_tp_distance_pct=_min_tp_pct_3,
                        )
                        tp1, tp2, sl = targets.tp1, targets.tp2, targets.sl
                    except Exception as exc:
                        logger.debug("[FOCUS] import compute_cycle_targets failed (fallback): %s", exc)
                        tp1 = tp2 = sl = 0.0
                    restored = FocusPosition(
                        market=sym, direction=direction, entry_price=entry_price,
                        qty=sz, leverage=self.config.leverage,
                        tp1=tp1, tp2=tp2, sl=sl, atr_used=atr,
                        entry_ts=time.time(), entry_source="restored",
                    )
                    restored.original_sl = sl      # Decay 원본 기준
                    restored.original_tp1 = tp1    # Decay 원본 기준
                    # ★ [2026-05-28 부모] FOCUS OFF→ON 청산 사고 fix:
                    #   Bybit 잔고에 있는 포지션 = 이미 운영 중인 자리 (수동/봇 무관).
                    #   복원된 포지션은 옛 EXIT 가드 우회 처리 = 봇이 함부로 청산 안 함.
                    #   부모님: "Day 캔들 역방향 아니면 손실 보지 말고 묶여야".
                    restored.guard_score_entry = True
                    self.positions.append(restored)
                    local_markets.add(sym)
                    logger.warning("[FOCUS] LIVE SYNC RESTORE: %s %s qty=%.4f entry=$%.2f — recovered from Bybit",
                                   sym, direction, sz, entry_price)
            if self.positions and self.state in (FocusState.DORMANT, FocusState.ALERT, FocusState.COOLDOWN):
                self.position = self.positions[0]
                self.state = FocusState.POSITIONED
                self._save_config()
                logger.info("[FOCUS] LIVE SYNC: state → POSITIONED (%d positions)", len(self.positions))
        except Exception as exc:
            logger.debug("[FOCUS] live sync failed: %s", exc)

    def _sync_with_bybit(self):
        """★ 부팅 시 Bybit 실잔고로 포지션 동기화. state 파일은 힌트, Bybit이 최종.
        ★ RACE FIX: Lock + 최소 5초 간격으로 동시/연속 실행 차단."""
        if not self.config.enabled or not self.positions:
            return
        # ★ [2026-05-25 부모] paper/dry 모드: 실거래소에 포지션이 없음 → 실제 Bybit 조회 시
        #   가상 포지션을 phantom 으로 오인 → 즉시 강제청산 사고 (6연패 정지 유발).
        #   paper 는 self.positions 가 진실, 청산은 _manage_all_positions(가격 vs TP/SL)가 담당.
        if not self._is_live_mode():
            return
        # ★ 최소 간격 가드: 5초 미만이면 건너뜀
        now = time.time()
        if now - self._last_sync_ts < 5.0:
            logger.debug("[FOCUS] SYNC: skipped (%.1fs since last sync)", now - self._last_sync_ts)
            return
        # ★ 동시 실행 차단: non-blocking acquire
        if not self._sync_lock.acquire(blocking=False):
            logger.debug("[FOCUS] SYNC: already in progress, skipping")
            return
        self._last_sync_ts = now
        try:
            self._sync_with_bybit_inner()
        finally:
            self._sync_lock.release()

    def _sync_with_bybit_inner(self):
        """실제 Bybit 동기화 로직 (Lock 내부에서만 호출)."""
        try:
            import os, hashlib, hmac, time as _t, requests as _req
            key = os.environ.get('BYBIT_API_KEY', '')
            secret = os.environ.get('BYBIT_API_SECRET', '')
            if not key or not secret:
                return
            ts = str(int(_t.time() * 1000))
            recv = '5000'
            params = 'category=linear&settleCoin=USDT'
            sign_str = ts + key + recv + params
            sig = hmac.new(secret.encode(), sign_str.encode(), hashlib.sha256).hexdigest()
            headers = {'X-BAPI-API-KEY': key, 'X-BAPI-TIMESTAMP': ts,
                       'X-BAPI-RECV-WINDOW': recv, 'X-BAPI-SIGN': sig}
            r = _req.get('https://api.bybit.com/v5/position/list',
                         params={'category': 'linear', 'settleCoin': 'USDT'},
                         headers=headers, timeout=10)
            bybit_positions = r.json().get('result', {}).get('list', [])
            # Bybit 실잔고 맵 구축
            bybit_map = {}
            for bp in bybit_positions:
                sz = float(bp.get('size', 0))
                if sz > 0:
                    sym = bp.get('symbol', '')
                    bybit_map[sym] = {
                        'size': sz,
                        'side': bp.get('side', ''),
                        'avgPrice': float(bp.get('avgPrice', 0) or 0),
                        'unrealisedPnl': float(bp.get('unrealisedPnl', 0) or 0),
                        'stopLoss': float(bp.get('stopLoss', 0) or 0),  # 서버 SL read-verify(Fix ①)
                    }

            # 로컬 포지션 vs Bybit 실잔고 대조
            synced = []
            for pos in self.positions:
                mkt = pos.market.upper()
                if mkt in bybit_map:
                    bp = bybit_map[mkt]
                    old_qty = pos.qty
                    pos.qty = bp['size']  # Bybit 실잔고가 최종
                    if bp['avgPrice'] > 0:
                        pos.entry_price = bp['avgPrice']
                    if abs(old_qty - pos.qty) > 0.0001:
                        logger.warning("[FOCUS] SYNC: %s qty %.4f → %.4f (Bybit actual)", mkt, old_qty, pos.qty)

                    # ★★ 서버 SL read-verify (Fix ①) — 거래소 실제 stopLoss 가 pos.sl 과 맞는지 *읽어* 확인.
                    #   write-only 갭: 한 번 _tp_sl_confirmed=True 면 영원 신뢰하던 것 → 실제 없으면/다르면 재배치.
                    if getattr(self.config, "server_sl_verify_enabled", True) and pos.sl > 0:
                        _srv_sl = float(bp.get('stopLoss', 0.0) or 0.0)
                        _sl_missing = _srv_sl <= 0
                        _sl_mismatch = (_srv_sl > 0 and abs(_srv_sl - pos.sl) / pos.sl > 0.001)  # 0.1% 허용
                        if _sl_missing or _sl_mismatch:
                            logger.warning("[FOCUS] 🚨 SYNC SL VERIFY: %s 거래소 SL %s (server=$%.4f vs pos=$%.4f) → 재배치",
                                           mkt, "없음" if _sl_missing else "불일치", _srv_sl, pos.sl)
                            pos._tp_sl_confirmed = False   # 매니지 복구 + naked 가드 활성화
                            try:
                                self._update_bybit_sl(pos)   # 즉시 재배치 시도
                                pos._tp_sl_confirmed = True
                            except Exception:
                                pass  # 실패해도 다음 tick 복구 + naked 가드가 받음

                    # ★ 방향 동기화: Bybit side가 최종 진실 (Buy=LONG, Sell=SHORT)
                    bybit_dir = "LONG" if bp['side'] == "Buy" else "SHORT"
                    if pos.direction != bybit_dir:
                        logger.warning("[FOCUS] SYNC: %s direction %s → %s (Bybit actual)", mkt, pos.direction, bybit_dir)
                        pos.direction = bybit_dir
                        # 방향이 바뀌면 TP/SL도 재계산해야 함
                        try:
                            atr = pos.atr_used if pos.atr_used > 0 else pos.entry_price * 0.015
                            from app.strategy.greenpen.cycle_tp import compute_cycle_targets
                            _min_tp_pct_4 = float(getattr(self.config, "min_tp_distance_pct", 0.30)) \
                                if getattr(self.config, "min_tp_distance_enabled", False) else 0.0
                            new_targets = compute_cycle_targets(
                                pos.entry_price, bybit_dir, atr,
                                tp1_mult=self.config.cycle_tp1_mult,
                                tp2_mult=self.config.cycle_tp2_mult,
                                sl_mult=self.config.cycle_sl_mult,
                                min_tp_distance_pct=_min_tp_pct_4,
                            )
                            pos.tp1 = new_targets.tp1
                            pos.tp2 = new_targets.tp2
                            pos.sl = new_targets.sl
                            logger.warning("[FOCUS] SYNC: TP/SL recalculated for %s: TP1=$%.2f TP2=$%.2f SL=$%.2f",
                                           mkt, pos.tp1, pos.tp2, pos.sl)
                            # Bybit 서버에도 TP/SL 재설정
                            try:
                                from app.integrations.bybit_trade import BybitTradeClient
                                sync_client = BybitTradeClient(category="linear")
                                sync_client.set_trading_stop(mkt, take_profit=pos.tp2, stop_loss=pos.sl)
                                logger.info("[FOCUS] SYNC: TP/SL set on Bybit for corrected direction")
                            except Exception as ts_exc:
                                logger.warning("[FOCUS] SYNC: set_trading_stop after direction fix failed: %s", ts_exc)
                        except Exception as tp_exc:
                            logger.warning("[FOCUS] SYNC: TP/SL recalc failed after direction fix: %s", tp_exc)

                    synced.append(pos)
                    del bybit_map[mkt]
                else:
                    # state에 있지만 Bybit에 없음 → Bybit 서버사이드 SL/TP로 청산됨
                    # ★ EXIT 기록 필수 (journal + ledger + 카운터)
                    # ★ DOUBLE-LOG FIX (2026-04-19): _close_position 이 이미 이 마켓을 처리 중이면
                    #   그 쪽이 journal 을 쓰고 있으니 SYNC 경로에서 중복 기록하지 않고 로컬 제거만.
                    if mkt in self._closing_markets:
                        logger.info("[FOCUS] SYNC: %s phantom SKIP — _close_position in progress", mkt)
                        # synced 에 넣지 않고 루프 종료 → self.positions = synced 로 자연 제거
                        continue
                    logger.warning("[FOCUS] SYNC: %s phantom detected — recording EXIT", mkt)
                    try:
                        _exit_price = self._get_current_price(pos.market) or pos.entry_price
                        _hold = (time.time() - pos.entry_ts) if pos.entry_ts > 0 else 0

                        # TP/SL 판별: SL 근처면 SL, TP 근처면 TP
                        _is_sl = False
                        _exit_reason = "SERVER_SIDE_CLOSED"
                        if pos.sl and pos.sl > 0 and _exit_price > 0:
                            if pos.direction == "LONG" and _exit_price <= pos.sl * 1.002:
                                _exit_reason = "SERVER_SL"
                                _exit_price = pos.sl  # SL 가격이 실제 체결가에 가까움
                                _is_sl = True
                            elif pos.direction == "SHORT" and _exit_price >= pos.sl * 0.998:
                                _exit_reason = "SERVER_SL"
                                _exit_price = pos.sl
                                _is_sl = True
                        if not _is_sl and pos.tp2 and pos.tp2 > 0:
                            if pos.direction == "LONG" and _exit_price >= pos.tp2 * 0.998:
                                _exit_reason = "SERVER_TP"
                                _exit_price = pos.tp2
                            elif pos.direction == "SHORT" and _exit_price <= pos.tp2 * 1.002:
                                _exit_reason = "SERVER_TP"
                                _exit_price = pos.tp2

                        # peak profit
                        _peak = 0.0
                        if pos.peak_profit_price > 0 and pos.entry_price > 0:
                            if pos.direction == "LONG":
                                _peak = (pos.peak_profit_price / pos.entry_price - 1) * 100
                            else:
                                _peak = (1 - pos.peak_profit_price / pos.entry_price) * 100

                        from app.manager.trade_journal import journal
                        journal.record_exit(
                            strategy="FOCUS", market=pos.market, direction=pos.direction,
                            entry_price=pos.entry_price, exit_price=_exit_price, qty=pos.qty,
                            reason=_exit_reason, leverage=pos.leverage, hold_sec=_hold,
                            phase=f"conviction={pos.conviction_score}",
                            dynamic_trailing=self.config.dynamic_trailing,
                            breakeven_locked=pos.breakeven_locked,
                            peak_profit_pct=_peak,
                        )

                        # 퇴장 정보 기록
                        self._last_exit_direction = pos.direction
                        self._last_exit_price = _exit_price
                        self._last_exit_ts = time.time()
                        self._last_exit_market = pos.market

                        # SL 카운터
                        if _is_sl:
                            self.daily_sl_count += 1

                        logger.warning("[FOCUS] SYNC: %s EXIT RECORDED — %s @ $%.2f (entry=$%.2f, hold=%.0fs)",
                                       mkt, _exit_reason, _exit_price, pos.entry_price, _hold)
                        # 🔔 텔레그램 청산 알림 — 서버사이드 TP/SL 청산 (부모님 "FOCUS 침묵" 갭: 진입·수동청산은 이미 알림, 이 자동청산 경로만 빠졌었음)
                        try:
                            _pnl_pct = ((_exit_price / pos.entry_price - 1.0) * 100.0) if pos.direction == "LONG" else ((1.0 - _exit_price / pos.entry_price) * 100.0) if pos.entry_price else 0.0
                            _emoji = "🔴" if _is_sl else ("🟢" if _exit_reason == "SERVER_TP" else "⚪")
                            self._notify(f"{_emoji} EXIT {pos.direction} {pos.market} ({_exit_reason})\n진입 ${pos.entry_price:.2f} → 청산 ${_exit_price:.2f}\n{_pnl_pct:+.2f}% | hold {_hold:.0f}s")
                        except Exception:
                            pass
                    except Exception as exc:
                        logger.error("[FOCUS] SYNC: %s phantom EXIT record failed: %s", mkt, exc)

            self.positions = synced
            self.position = self.positions[0] if self.positions else None

            # ★ 재시작 후 모든 포지션 Bybit TP/SL 재설정 (증발 방지)
            if self.positions:
                try:
                    from app.integrations.bybit_trade import BybitTradeClient
                    _sync_client = BybitTradeClient(category="linear")
                    for pos in self.positions:
                        tp = pos.tp2 if pos.partial_done else pos.tp1
                        try:
                            _sync_client.set_trading_stop(pos.market, take_profit=tp, stop_loss=pos.sl)
                            pos._tp_sl_confirmed = True  # ★ 부팅 시에도 플래그 세팅
                            logger.info("[FOCUS] SYNC: TP/SL OK on Bybit — %s TP=$%.4f SL=$%.4f",
                                        pos.market, tp, pos.sl)
                        except Exception as _ts_err:
                            logger.warning("[FOCUS] SYNC: set_trading_stop failed %s: %s", pos.market, _ts_err)
                except Exception as _client_err:
                    logger.warning("[FOCUS] SYNC: BybitTradeClient init failed for TP/SL restore: %s", _client_err)

            # Bybit에 있지만 state에 없는 포지션 → 경고만 (다른 전략 소유일 수 있음)
            for sym, bp in bybit_map.items():
                logger.info("[FOCUS] SYNC: %s found on Bybit (size=%.4f) but not in FOCUS state — may belong to other strategy",
                           sym, bp['size'])

            # 포지션 없으면 IDLE로
            if not self.positions and self.state == FocusState.POSITIONED:
                self.state = FocusState.DORMANT
                logger.info("[FOCUS] SYNC: No positions on Bybit → IDLE")

            self._save_config()
            logger.info("[FOCUS] SYNC complete: %d positions verified against Bybit", len(self.positions))

        except (ConnectionError, OSError) as exc:
            # ★ H13 FIX: 재귀 제거 → 단순 1회 재시도
            logger.warning("[FOCUS] Bybit sync connection error, retrying once: %s", exc)
            try:
                import time as _t2; _t2.sleep(3)
                from app.core.constants import BYBIT_POSITION_LIST
                client = self._get_client()
                resp = client._request("GET", BYBIT_POSITION_LIST,
                                       params={"category": "linear", "settleCoin": "USDT"})
                pos_list = resp.get("list", []) if isinstance(resp, dict) else []
                # 간이 동기화: 포지션이 없으면 IDLE로
                has_position = any(float(p.get('size', 0)) > 0 for p in pos_list)
                if not has_position and self.positions:
                    logger.warning("[FOCUS] Retry sync: no positions on Bybit — clearing local state")
                    self.positions.clear()
                    self.position = None
                    if self.state in (FocusState.POSITIONED, FocusState.CAUTION):
                        self.state = FocusState.DORMANT
                    self._save_config()
                logger.info("[FOCUS] Retry sync succeeded")
            except Exception as exc:
                logger.debug("[FOCUS] import time as _t2; _t2.sleep(3) failed (fallback): %s", exc)
                logger.warning("[FOCUS] Bybit sync retry also failed — using state file")
        except Exception as exc:
            logger.warning("[FOCUS] Bybit sync failed (will use state file): %s", exc)

    def _get_whale_alerts(self) -> Dict:
        """WhaleRadar 활성 알림 조회 (대시보드용)."""
        try:
            from app.core.whale_radar import whale_radar
            return whale_radar.get_active_alerts()
        except Exception as exc:
            logger.debug("[FOCUS] import whale_radar failed (fallback): %s", exc)
            return {}

    # ── Status API ──────────────────────────────────────────

    def get_status(self) -> Dict[str, Any]:
        """Return full status for API/Dashboard.

        [2026-05-15 hotfix] self._lock 제거 — 무거운 tick(16코인 MTF 스캔)이 락 잡으면
        dashboard status 폴링 전부 대기 → 큐 폭주 → 화면 멈춤.
        get_status 는 읽기 전용(positions/state → dict)이라 GIL 하에서 lock-free 안전.
        tick mid-mutation 시 약간의 불일치 가능하지만 화면 표시용이라 무해.
        """
        if True:  # ★ no lock — dashboard freeze 방지 (update_config 와 동일한 분리 패턴)
            # ★ 포지션별 현재가 + PnL 계산 (Dashboard 실시간 표시용)
            enriched_positions = []
            total_pnl = 0.0
            for p in self.positions:
                pd = asdict(p)
                cur_price = self._get_current_price(p.market)
                if cur_price and p.entry_price > 0:
                    pd["current_price"] = cur_price
                    if p.direction == "LONG":
                        pnl = (cur_price - p.entry_price) * p.qty
                        pnl_pct = (cur_price / p.entry_price - 1) * 100
                    else:
                        pnl = (p.entry_price - cur_price) * p.qty
                        pnl_pct = (1 - cur_price / p.entry_price) * 100
                    pd["unrealized_pnl"] = round(pnl, 4)
                    pd["pnl_pct"] = round(pnl_pct, 2)
                    total_pnl += pnl
                else:
                    pd["current_price"] = 0
                    pd["unrealized_pnl"] = 0
                    pd["pnl_pct"] = 0
                # 보유 시간 (시간 단위)
                pd["hold_hours"] = round((time.time() - p.entry_ts) / 3600, 1) if p.entry_ts > 0 else 0
                enriched_positions.append(pd)

            # ★ Today PnL (07:00 KST 리셋 기준) — daily_reset_ts 재활용
            today_pnl_realized = self._calc_today_pnl()

            return {
                "enabled": self.config.enabled,
                "state": self.state.value,
                "selected_market": self.selected_market,
                "selected_direction": self.selected_direction,
                "position": enriched_positions[0] if enriched_positions else None,
                "positions": enriched_positions,
                "positions_count": len(self.positions),
                "max_positions": self.config.max_positions,
                "total_pnl": round(total_pnl, 4),
                "today_pnl": round(today_pnl_realized, 2),
                "today_pnl_unrealized": round(today_pnl_realized + total_pnl, 2),
                "zones_count": len(self.zones),
                "primary_sig": self.primary_sig,
                # ★ [2026-04-24] Recent Skips — 부모 지시 가시화
                # 최신 skip 사유 N건 (시간 역순). dashboard 노출용.
                "recent_skips": list(reversed(self.recent_skips[-20:])),  # 최근 20건만 dashboard 전송
                # ★ [2026-06-15 해결안 B] GateLedger — "오늘 왜 침묵했나"(게이트별 pass/reject). ON 일 때만.
                "gate_stats": (self._gate_ledger.snapshot() if (self._gate_ledger is not None and self.config.gate_ledger_enabled) else None),
                "daily_plans_used": self.daily_plans_used,
                "daily_plans_max": self.config.max_daily_plans,
                "daily_sl_count": self.daily_sl_count,
                "daily_sl_max": self.config.max_daily_sl,
                "config": asdict(self.config),
                # v2: ADX / Conviction / Reentry
                "last_adx": round(self._last_adx_value, 1),
                "last_exit_direction": self._last_exit_direction,
                "last_exit_market": self._last_exit_market,
                # ★ Phase E (2026-04-20): cooldown 카운트다운용 — dashboard JS가 클라이언트 계산
                "last_exit_ts": self._last_exit_ts,
                "cooldown_start_ts": self.cooldown_start_ts,
                # ★ 수동 퇴장 페널티 현황
                "manual_penalties": {
                    mk: {"expires_in_h": round((exp - time.time()) / 3600, 1), "expires_at": time.strftime("%H:%M", time.localtime(exp))}
                    for mk, exp in self._manual_exit_penalties.items() if exp > time.time()
                },
                # ★ WhaleRadar 활성 알림
                "whale_alerts": self._get_whale_alerts(),
                # ★ B12 Scanner Breadth — 실시간 투표 상태 (UI 표시용, 2026-04-23)
                "b12_vote": self._get_b12_breadth_vote(),
                # ★ 대사면 (General Amnesty) — UI 표시용 (2026-04-23)
                "amnesty_ts": self._amnesty_ts,
                # ★ [2026-06-06 부모] 거시 레짐 나침반 — 급락/회복 전환 표시 (진입 0영향, Phase 1 표시전용)
                "macro_compass": self._macro_compass(),
                # ★ [2026-06-08 부모] Event Shield — 헤더 이벤트 카운트다운용 (자동 fetch + 수동)
                "event_shield": self._event_shield_status(),
            }

    def update_config(self, patch: Dict) -> Dict:
        """Update config from API/Dashboard.

        [2026-05-15 Tick 락 분리] self._lock(무거운 tick 공유) → self._config_lock 전용.
        ① 패치는 _config_lock 만으로 메모리에 즉시 반영.
        ② 파일 저장: _lock 을 timeout 0.5s 로 시도 → tick 이 idle(5초 간격 중 대부분)이면 즉시 저장,
           무거운 tick 진행 중이면 _config_dirty 플래그만 남기고 다음 tick 시작 시 flush.
        → 옛 동작(무거운 tick 1회 통째 대기, 체감 30~60초)을 최대 0.5초로 단축.
        락 순서는 항상 _lock → _config_lock (tick flush 와 동일) — 데드락 없음.
        """
        with self._config_lock:
            for k, v in patch.items():
                if hasattr(self.config, k):
                    try:
                        cur = getattr(self.config, k)
                        # ★ M19 FIX: bool 필드 특별 처리 (bool("false")==True 방지)
                        if isinstance(cur, bool):
                            new_val = v if isinstance(v, bool) else str(v).lower() in ("true", "1", "yes")
                            setattr(self.config, k, new_val)
                        else:
                            setattr(self.config, k, type(cur)(v))
                        # ★ enabled 변경 추적 (미스터리 비활성화 디버깅)
                        if k == "enabled":
                            import traceback
                            caller = ''.join(traceback.format_stack()[-4:-1]).strip()
                            logger.warning("[FOCUS] ⚠️ enabled CHANGED → %s (caller: %s)", v, caller[:200])
                    except (TypeError, ValueError) as exc:
                        logger.warning("[FOCUS] config update failed for %s=%s: %s", k, v, exc)
            self._config_dirty = True
            result = asdict(self.config)
        # ② 즉시 저장 시도 — _config_lock 해제 후 _lock 획득 (락 순서 _lock→_config_lock 유지).
        #    tick 이 무거운 스캔 중이면 0.5초 후 포기 → dirty 플래그로 다음 tick 에 위임.
        if self._lock.acquire(timeout=0.5):
            try:
                with self._config_lock:
                    if self._config_dirty:
                        self._config_dirty = False
                        self._save_config()
            except Exception as _cfexc:
                logger.warning("[FOCUS] update_config immediate save failed: %s", _cfexc)
            finally:
                self._lock.release()
        # Phase C-2 (2026-04-20): WebSocket push — config 변경 즉시 dashboard 반영. fire-and-forget.
        try:
            from app.api.websocket_router import state_broadcast_safe
            state_broadcast_safe("CONFIG_CHANGED", {"changed_keys": list(patch.keys())})
        except Exception:
            pass
        return result

    def force_select(self, market: str, direction: str = "LONG") -> Dict:
        """Manually override coin selection → HUNT."""
        with self._lock:
            self.selected_market = market.upper()
            self.selected_direction = direction.upper()
            self.state = FocusState.HUNT
            self.last_scan_ts = 0  # 즉시 스캔
            self._save_config()
            logger.info("[FOCUS] Force-selected %s %s → HUNT", market, direction)
            return {"market": market, "direction": direction, "state": "HUNT"}

    def manual_entry(self, market: str, direction: str, wait_for_signal: bool = False, timeout_sec: Optional[float] = None) -> Dict:
        """[2026-05-16 부모] 수동 강제 진입.

        사용 의도: 시스템이 자동으로 못 잡는 자리를 부모님이 차트 보고 직접 진입.
        게이트 우회: microtiming_5m, EE Gate, MTF FLIP block, BB gate, conviction 임계.
        안전 가드는 유지: reentry / Bybit dup / cross-strategy / qty/margin / 자기 dup.

        [2026-05-29 부모] wait_for_signal=True 시 *즉시 X*. 큐 등록 후 부모님 방향 신호
        확인될 때까지 대기 → 매칭 시점에 자동 실행 (default timeout 1시간).

        Returns: dict with state / market / direction / error (if any)
        """
        market = (market or "").upper()
        direction = (direction or "").upper()
        if direction not in ("LONG", "SHORT"):
            return {"state": "ERROR", "error": f"invalid_direction:{direction}"}

        # ── [2026-05-29 부모] Smart Manual Entry — 신호 확인 후 진입 큐 등록 ──
        if wait_for_signal:
            # 부모님 OFF 시 즉시 reject (운영자 판단이 더 빠른 경우)
            if not getattr(self.config, "smart_manual_entry_enabled", True):
                return {"state": "SMART_DISABLED",
                        "error": "Smart Manual Entry 비활성화 — 즉시 진입 (L/S) 사용",
                        "market": market, "direction": direction}
            _to_sec = float(timeout_sec) if timeout_sec else float(
                getattr(self.config, "smart_manual_entry_default_timeout_sec", 3600.0)
            )
            # 중복 체크 — 같은 market+direction 이미 대기 중이면 추가 X
            for _q in self._pending_manual_entries:
                if _q.get("market") == market and _q.get("direction") == direction:
                    return {"state": "PENDING_DUP", "market": market, "direction": direction,
                            "elapsed_sec": time.time() - _q.get("requested_ts", time.time())}
            self._pending_manual_entries.append({
                "market": market,
                "direction": direction,
                "requested_ts": time.time(),
                "timeout_sec": _to_sec,
            })
            logger.warning("[FOCUS] ★ Smart Manual Entry PENDING: %s %s (timeout %.0fs)",
                           market, direction, _to_sec)
            return {"state": "PENDING", "market": market, "direction": direction,
                    "timeout_sec": _to_sec, "queue_len": len(self._pending_manual_entries)}
        # 가격 조회 — entry payload에 필요
        try:
            raw = self._get_client().get_kline(market, interval="5", limit=2)
            if not raw or len(raw) < 1:
                return {"state": "ERROR", "error": "price_fetch_failed"}
            price = float(raw[-1][4])
            # ATR 근사 (5m 최근봉 high-low)
            atr_approx = abs(float(raw[-1][2]) - float(raw[-1][3]))
        except Exception as exc:
            return {"state": "ERROR", "error": f"price_fetch_exception:{exc}"}

        logger.warning("[FOCUS] ★ MANUAL ENTRY 요청: %s %s @ $%.6f", market, direction, price)

        # ── [2026-05-20 Phase 6 Stage 5] 수동 진입 B층 (combo F) 검증 ──
        #   default OFF (부모님 의도 100% 존중). ON 시 봉 흐름 미달 자리에서 손실 방지.
        #   DOGE -$11.62 교훈: MTF 회복 추세 + M5 양봉 연속 자리에서 SHORT 수동 진입 = 손실 직행.
        if getattr(self.config, "manual_entry_require_combo_f_pass", False):
            try:
                _f_min = int(getattr(self.config, "manual_entry_combo_f_min", 20))
                _f_total = 0
                _f_parts = []
                _f_mtf_partial = int(getattr(self.config, 'phase6_combo_f_mtf_partial_bonus', 10))
                _f_mtf_full = int(getattr(self.config, 'phase6_combo_f_mtf_full_bonus', 20))
                _f_m5_dir_bonus = int(getattr(self.config, 'phase6_combo_f_m5_dir_bonus', 15))
                _f_m5_body_bonus = int(getattr(self.config, 'phase6_combo_f_m5_body_bonus', 15))
                _f_m5_body_threshold = float(getattr(self.config, 'phase6_combo_f_m5_body_threshold', 0.3))
                # F1: MTF
                try:
                    mtf_s_m, _ = self._compute_mtf_alignment_matrix(market, direction, None)
                    if mtf_s_m >= 2:
                        _f_total += _f_mtf_full
                        _f_parts.append(f"MTF_full+{_f_mtf_full}")
                    elif mtf_s_m >= 1:
                        _f_total += _f_mtf_partial
                        _f_parts.append(f"MTF_partial+{_f_mtf_partial}")
                except Exception as exc:
                    logger.debug("[FOCUS] manual combo F MTF error: %s", exc)
                # F2/F3: M5 패턴
                _m5p = self._get_m5_candle_pattern(market, n=5)
                if _m5p:
                    _expected_dir = 'BULL' if direction == "LONG" else 'BEAR'
                    if _m5p.get('dominant_dir') == _expected_dir:
                        _f_total += _f_m5_dir_bonus
                        _f_parts.append(f"M5_{_m5p['dominant_dir']}+{_f_m5_dir_bonus}")
                    if _m5p.get('avg_body_pct', 0.0) >= _f_m5_body_threshold:
                        _f_total += _f_m5_body_bonus
                        _f_parts.append(f"M5_body{_m5p['avg_body_pct']:.2f}%+{_f_m5_body_bonus}")
                logger.info("[FOCUS] ★ MANUAL combo F %s %s: %s = %d (min=%d)",
                            market, direction, "|".join(_f_parts) if _f_parts else "X",
                            _f_total, _f_min)
                if _f_total < _f_min:
                    try:
                        from app.manager.trade_journal import journal
                        journal.record_blocked("FOCUS", market, direction,
                                               reason="manual_combo_f_fail",
                                               detail=f"manual {direction} combo F {_f_total}<{_f_min}: {'|'.join(_f_parts) if _f_parts else 'X'}")
                    except Exception as exc:
                        logger.debug("[FOCUS] record_blocked manual_combo_f failed: %s", exc)
                    return {"state": "BLOCKED",
                            "error": f"combo_f_fail:{_f_total}<{_f_min}",
                            "market": market, "direction": direction,
                            "combo_f_score": _f_total,
                            "combo_f_parts": _f_parts}
            except Exception as exc:
                logger.warning("[FOCUS] manual combo F check error %s: %s", market, exc)

        # entry payload — _manual=True 플래그로 게이트들 우회
        entry = {
            "market": market,
            "direction": direction,
            "price": price,
            "atr": atr_approx,
            "reason": "MANUAL_ENTRY",
            "conviction_score": 80,  # [2026-05-21 부모 — 100점 체계 마이그 누락 fix] 옛 7/10 → 새 80/100. conv_sizing low≤50 0.5x 잘못 적용 → "꼬딱지 size" 사고. 80 = mid range (50<x<90) → conv_mult 1.0x 정상 size.
            "conviction_budget": 0,  # 0 = 시스템 자동 배분
            "_manual": True,         # ★ 게이트 우회 플래그
            "_scanner_entry": False,
            "_is_sw_bb": False,
            "_conviction_modifiers": "manual",
        }
        with self._lock:
            result = self._execute_entry(entry)
        return result
